def _person_token_key(token: str) -> str:
    return re.sub(r"[^a-z]", "", str(token or "").lower())


def _is_person_descriptor_token(token: str) -> bool:
    return _person_token_key(token) in _PERSON_DESCRIPTOR_TOKENS


def _strip_person_descriptor_tokens(tokens: List[str]) -> List[str]:
    """Remove generic descriptors only when a full person-name shape remains."""
    stripped = list(tokens or [])
    while len(stripped) > 2 and _is_person_descriptor_token(stripped[0]):
        stripped.pop(0)
    while len(stripped) > 2 and _is_person_descriptor_token(stripped[-1]):
        stripped.pop()
    return stripped

_AR_EXPLANATION_QUERY_RE = re.compile(
    r"(?:\bلماذا\b|\bكيف\b|ما\s+العلاقه|اشرح\s+العلاقه|وضح|"
    r"كيف\s+يدعم|كيف\s+يساهم|ما\s+اهميه|\bاهميه\b|\bعلاقه\b|\bيساهم\b|\bيدعم\b)"
)

_AR_DEFINITION_QUERY_RE = re.compile(
    r"^\s*(?:(?:ما|ماذا)\s+(?:هو|هي|هى|يعني|تعني)|(?:من)\s+(?:هو|هي|هى)|(?:عرف|تعريف|عرّف))\b"
)

def _extract_exact_count_structural_list_group(query_text: str, source_text: str) -> list[str] | None:
    count_target = _list_query_count_target(query_text)
    query_info = S._detect_short_symbolic_list_query(query_text)
    if isinstance(query_info, dict) and isinstance(query_info.get("count"), int):
        count_target = int(query_info.get("count") or 0)
    if not isinstance(count_target, int) or count_target < 2:
        return None

    source = str(source_text or "").replace("\u2022", " • ").replace("\u2019", "'")
    if not source.strip():
        return None

    query_norm = S._normalize_symbolic_list_surface(query_text)
    phrase_variants = {
        S._normalize_symbolic_list_surface(str(variant))
        for variant in ((query_info or {}).get("phrase_variants") or [])
        if S._normalize_symbolic_list_surface(str(variant))
    }
    count_terms = {str(count_target)}
    if count_target in _SYMBOLIC_LIST_NUMBER_WORDS:
        count_terms.add(_SYMBOLIC_LIST_NUMBER_WORDS[count_target])
    query_terms = [
        token for token in re.findall(r"[a-z0-9']+", query_norm)
        if token not in _SYMBOLIC_LIST_QUERY_STOPWORDS
        and token not in _SYMBOLIC_LIST_CARDINALS
        and not token.isdigit()
    ]
    label_variants = {
        S._normalize_symbolic_list_surface(str(label))
        for label in ((query_info or {}).get("label_variants") or [])
        if S._normalize_symbolic_list_surface(str(label))
    }
    query_terms = [token for token in query_terms if token not in label_variants or len(token) >= 3]

    def _anchor_score(text: str) -> float:
        normalized = S._normalize_symbolic_list_surface(text)
        if not normalized:
            return 0.0
        phrase_hit = any(re.search(rf"\b{re.escape(variant)}\b", normalized) for variant in phrase_variants)
        count_hit = any(re.search(rf"\b{re.escape(term)}\b", normalized) for term in count_terms)
        term_hits = sum(1 for term in dict.fromkeys(query_terms) if len(term) >= 3 and _token_match_light(normalized, term))
        score = 0.0
        if phrase_hit:
            score += 4.0
        if count_hit:
            score += 1.0
        score += min(3, term_hits) * 0.75
        if phrase_hit or (count_hit and (term_hits >= 1 or not query_terms)):
            return score
        if query_terms and term_hits >= min(2, len(query_terms)):
            return score
        return 0.0

    def _clean_structural_item(raw_item: str) -> str:
        item = re.sub(r"^\s*(?:[-*•]|\d{1,2}\s*[.)]|[A-Za-z]\s*[.)])\s*", "", str(raw_item or ""))
        item = re.sub(r"\s+", " ", item).strip(" \t\r\n,;:-.\"'")
        if not item:
            return ""
        item = re.split(r"[.!?]\s+", item, maxsplit=1)[0]
        item = item.strip(" \t\r\n,;:-.\"'")
        if not item or re.search(r"\d", item) or re.search(r"[.!?:;]", item):
            return ""
        if re.match(r"^\s*(?:and|or|to|of|for|with|by|in|on|at|from)\b", item, flags=re.IGNORECASE):
            return ""
        if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from)\s*$", item, flags=re.IGNORECASE):
            return ""
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
        if not (1 <= len(words) <= 6):
            return ""
        if _STRICT_LIST_LABEL_VERB_RE.search(item):
            return ""
        if len(words) >= 4 and item[:1].islower():
            return ""
        return item[:1].upper() + item[1:] if item else ""

    def _shape_items(raw_items: list[str]) -> list[str]:
        shaped: list[str] = []
        seen: set[str] = set()
        for raw_item in raw_items:
            item = _clean_structural_item(raw_item)
            if not item:
                return []
            norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
            if not norm or norm in seen:
                return []
            seen.add(norm)
            shaped.append(item)
        return shaped if len(shaped) == count_target else []

    def _split_inline_items(body_text: str) -> list[str]:
        body = re.sub(r"\s+", " ", str(body_text or "")).strip(" ,;:-")
        if not body:
            return []
        body = re.split(r"(?<=[.!?])\s+", body, maxsplit=1)[0].strip(" ,;:-")
        if ":" in body:
            body = body.rsplit(":", 1)[-1].strip(" ,;:-")
        if not body:
            return []
        delimiter_count = body.count(",") + body.count(";") + body.count("|")
        if delimiter_count < max(1, count_target - 2) and not re.search(r"\b(?:and|or)\b", body, flags=re.IGNORECASE):
            return []
        body = re.sub(r",?\s+(?:and|or)\s+", ", ", body, flags=re.IGNORECASE)
        return [part.strip(" ,;:-") for part in re.split(r"[,;|]", body) if part.strip(" ,;:-")]

    def _item_consistency_score(items: list[str]) -> float:
        if not items:
            return 0.0
        word_counts = [len(re.findall(r"[A-Za-z][A-Za-z\-']*", item)) for item in items]
        lengths = [len(item) for item in items]
        score = 0.0
        if max(word_counts) - min(word_counts) <= 2:
            score += 1.2
        if max(lengths) - min(lengths) <= 18:
            score += 0.8
        first_case = [item[:1].isupper() for item in items if item]
        if first_case and (all(first_case) or not any(first_case)):
            score += 0.6
        if all(len(re.findall(r"[A-Za-z][A-Za-z\-']*", item)) == 1 for item in items):
            score += 0.6
        return score

    def _is_heading_context(text: str) -> bool:
        compact = re.sub(r"\s+", " ", str(text or "")).strip(" ,;:-")
        if not compact or len(compact) > 120:
            return False
        if compact.endswith(":"):
            return True
        if re.search(r"[.!?]", compact):
            return False
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", compact)
        return bool(1 <= len(words) <= 8 and sum(1 for word in words if word[:1].isupper()) >= max(1, len(words) - 1))

    candidates: list[tuple[float, list[str], dict[str, Any]]] = []

    def _add_candidate(raw_items: list[str], metadata: dict[str, Any], anchor: float) -> None:
        items = _shape_items(raw_items)
        if len(items) != count_target:
            return
        score = 20.0 + (anchor * 2.0) + _item_consistency_score(items)
        pattern = str(metadata.get("extraction_pattern") or "")
        marker_type = str(metadata.get("marker_type") or "")
        if pattern == "inline_colon":
            score += 5.0
        elif pattern == "inline_cue":
            score += 3.5
        elif pattern == "ordered_marker_run":
            score += 4.0
        if marker_type:
            score += 1.0
        if metadata.get("is_from_heading_context"):
            score -= 6.0
        candidates.append((score, items, metadata))

    records: list[dict[str, Any]] = []
    for line_index, raw_line in enumerate(source.splitlines() or [source]):
        line = re.sub(r"\s+", " ", str(raw_line or "")).strip()
        if not line:
            continue
        fragments = [frag.strip() for frag in re.split(r"(?<=[.!?])\s+(?=[A-Z\"'])", line) if frag.strip()]
        if not fragments:
            fragments = [line]
        for fragment_index, fragment in enumerate(fragments):
            records.append({
                "source_line_index": line_index,
                "same_block_id": f"{line_index}:{fragment_index}",
                "text": fragment,
            })

    cue_re = re.compile(
        r"\b(?:are|include|includes|included\s+are|consists?\s+of|comprises?|composed\s+of|namely)\b",
        flags=re.IGNORECASE,
    )
    marker_re = re.compile(
        r"(?:^|\s)(?P<marker>\d{1,2}|[A-Za-z])\s*(?P<punct>[.)])\s*"
        r"(?P<body>.*?)(?=(?:\s(?:\d{1,2}|[A-Za-z])\s*[.)]\s*)|$)",
        flags=re.DOTALL,
    )

    for record in records:
        text = str(record.get("text") or "")
        if not text:
            continue
        for colon in re.finditer(r":", text):
            left = text[max(0, colon.start() - 220):colon.start()]
            right = text[colon.end(): colon.end() + 520]
            anchor = _anchor_score(left + " " + right[:120])
            if anchor <= 0.0:
                continue
            items = _split_inline_items(right)
            _add_candidate(items, {
                "source_line_index": record.get("source_line_index"),
                "same_block_id": record.get("same_block_id"),
                "marker_type": "delimiter",
                "extraction_pattern": "inline_colon",
                "punctuation_pattern": "colon_comma",
                "is_from_heading_context": _is_heading_context(left),
            }, anchor)

        for cue in cue_re.finditer(text):
            window = text[max(0, cue.start() - 180): min(len(text), cue.end() + 540)]
            anchor = _anchor_score(window)
            if anchor <= 0.0:
                continue
            items = _split_inline_items(text[cue.end(): cue.end() + 520])
            _add_candidate(items, {
                "source_line_index": record.get("source_line_index"),
                "same_block_id": record.get("same_block_id"),
                "marker_type": "delimiter",
                "extraction_pattern": "inline_cue",
                "punctuation_pattern": "comma_connector",
                "is_from_heading_context": False,
            }, anchor)

        marker_source = S._prepare_counted_list_rescue_text(text)
        marker_matches = list(marker_re.finditer(marker_source))
        if len(marker_matches) >= count_target:
            runs: list[list[re.Match[str]]] = []
            current: list[re.Match[str]] = []
            previous_value: int | None = None
            previous_kind = ""
            for marker in marker_matches:
                raw_marker = str(marker.group("marker") or "")
                marker_kind = "number" if raw_marker.isdigit() else "letter"
                marker_value = int(raw_marker) if raw_marker.isdigit() else (ord(raw_marker.lower()) - ord("a") + 1)
                continues = bool(current and marker_kind == previous_kind and previous_value is not None and marker_value == previous_value + 1)
                if not continues:
                    if current:
                        runs.append(current)
                    current = [marker]
                else:
                    current.append(marker)
                previous_value = marker_value
                previous_kind = marker_kind
            if current:
                runs.append(current)
            for run in runs:
                if len(run) != count_target:
                    continue
                run_start = run[0].start()
                run_end = run[-1].end()
                anchor = _anchor_score(marker_source[max(0, run_start - 240): min(len(marker_source), run_end + 120)])
                if anchor <= 0.0:
                    continue
                first_marker = str(run[0].group("marker") or "")
                _add_candidate([str(match.group("body") or "") for match in run], {
                    "source_line_index": record.get("source_line_index"),
                    "same_block_id": record.get("same_block_id"),
                    "marker_type": "number" if first_marker.isdigit() else "letter",
                    "extraction_pattern": "ordered_marker_run",
                    "punctuation_pattern": str(run[0].group("punct") or ""),
                    "is_from_heading_context": False,
                }, anchor)

    if not candidates:
        return None
    candidates.sort(key=lambda row: row[0], reverse=True)
    best_score, best_items, best_metadata = candidates[0]
    S.logger.info(
        "[COUNTED STRUCTURE GROUP] selected=True pattern=%s marker=%s line=%s block=%s items=%d score=%.2f",
        best_metadata.get("extraction_pattern"),
        best_metadata.get("marker_type"),
        best_metadata.get("source_line_index"),
        best_metadata.get("same_block_id"),
        len(best_items),
        best_score,
    )
    return best_items

def _prune_overlong_counted_list_items(query_text: str, items: list[str]) -> list[str]:
    target = _list_query_count_target(query_text)
    if target is None or target < 2 or len(items or []) <= target:
        return list(items or [])

    q_family = _classify_query_family_v2(query_text)
    q_context_tokens, q_focus_tokens = _split_query_context_focus_tokens(query_text, q_family)
    query_tokens = {
        _light_normalize_query_token(token)
        for token in (q_context_tokens + q_focus_tokens)
        if str(token or "").strip()
    }
    query_tokens.discard("")
    symbolic_info = S._detect_short_symbolic_list_query(query_text)
    requested_initial = ""
    if isinstance(symbolic_info, dict):
        for label in symbolic_info.get("label_variants") or []:
            label_norm = re.sub(r"[^a-z]", "", str(label or "").lower())
            if len(label_norm) == 1:
                requested_initial = label_norm
                break

    def _shape_score(item_text: str) -> float:
        item = re.sub(r"\s+", " ", str(item_text or "").strip(" \t\r\n-•*.,;:–—"))
        if not item:
            return -6.0
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
        if not words:
            return -6.0
        wc = len(words)
        score = 0.0
        reject_reason = _strict_list_label_reject_reason(item, max_words=6)
        if reject_reason:
            score -= 4.0
        else:
            score += 3.0
        if wc == 1:
            score += 1.2
        elif 2 <= wc <= 3:
            score += 0.5
        elif wc > 5:
            score -= 1.5
        if re.search(r"[.!?;:]", item):
            score -= 2.0
        item_tokens = {
            _light_normalize_query_token(token)
            for token in re.findall(r"[a-z0-9]{3,}", item.lower())
        }
        item_tokens.discard("")
        if item_tokens and query_tokens and item_tokens <= query_tokens:
            score -= 2.5
        if wc <= 3 and item[:1].isupper():
            score += 0.2
        if requested_initial and words:
            first_initial = words[0][:1].lower()
            if first_initial == requested_initial:
                score += 1.8
            else:
                score -= 2.2
        return score

    best_window: list[str] | None = None
    best_score = float("-inf")
    for start in range(0, len(items) - target + 1):
        window = [re.sub(r"\s+", " ", str(item or "").strip(" \t\r\n-•*")) for item in items[start:start + target]]
        item_scores = [_shape_score(item) for item in window]
        word_counts = [len(re.findall(r"[A-Za-z][A-Za-z\-']*", item)) for item in window]
        uniform_single_word_bonus = 1.5 if all(count == 1 for count in word_counts) else 0.0
        compact_label_bonus = 0.6 if sum(1 for count in word_counts if 1 <= count <= 3) >= max(target - 1, 1) else 0.0
        score = sum(item_scores) + uniform_single_word_bonus + compact_label_bonus
        if score > best_score:
            best_score = score
            best_window = window

    if not best_window:
        return list(items or [])

    avg_score = best_score / float(max(1, target))
    if avg_score < 2.0:
        S.logger.info("[COUNTED LIST PRUNE] applied=False reason=weak_window target=%s avg_score=%.2f", target, avg_score)
        return list(items or [])

    S.logger.info(
        "[COUNTED LIST PRUNE] applied=True target=%s before=%s after=%s avg_score=%.2f",
        target,
        len(items or []),
        len(best_window),
        avg_score,
    )
    return best_window

def _extract_strict_clean_label_candidates(text: str, *, max_items: int = 24) -> list[str]:
    src = str(text or "")
    if not src.strip():
        return []

    raw_candidates: list[str] = []
    bullet_re = re.compile(r"^\s*(?:[-•*]|\d+[.)]|[A-Za-z][.)])\s+(.+)$")
    for raw_line in src.splitlines():
        line = re.sub(r"\s+", " ", str(raw_line or "").strip())
        if not line:
            continue
        bullet = bullet_re.match(line)
        if bullet:
            raw_candidates.append(bullet.group(1).strip())
        if "•" in line or "�" in line:
            for segment in [s.strip() for s in re.split(r"\s*[•�]\s*", line) if s.strip()]:
                raw_candidates.append(segment)
        listed_clause = re.search(
            r"\b(?:are|include|includes|consists\s+of|classified\s+as|following)\b\s*[:\-]?\s*(.+)$",
            line,
            flags=re.IGNORECASE,
        )
        if listed_clause:
            tail = re.sub(r"[.;:!?]+\s*$", "", listed_clause.group(1) or "").strip()
            for part in [p.strip() for p in re.split(r",|;|\band\b", tail, flags=re.IGNORECASE) if p.strip()]:
                raw_candidates.append(part)
        if line.count(",") >= 2 or line.count(";") >= 2:
            for part in [p.strip() for p in re.split(r",|;|\band\b", line, flags=re.IGNORECASE) if p.strip()]:
                raw_candidates.append(part)
        for match in re.finditer(r"(?:^|[\s,;])(?:\d{1,2}|[A-Ja-j])[.)]\s*([^.;:\n]{2,80})", line):
            raw_candidates.append((match.group(1) or "").strip())
        for match in re.finditer(r"\b([A-Z][A-Za-z\-]+(?:\s+[A-Z][A-Za-z\-]+){0,3})\s*:\s*", line):
            raw_candidates.append((match.group(1) or "").strip())
        for match in re.finditer(
            r"\b([A-Z][A-Za-z\-]+(?:\s+[A-Z][A-Za-z\-]+){0,3})\s+"
            r"(?:It|An|A|The)\s+(?:is|was|are|were|focused|focuses|concentrated|views|approach)\b",
            line,
        ):
            raw_candidates.append((match.group(1) or "").strip())

    labels: list[str] = []
    seen: set[str] = set()
    for raw in raw_candidates:
        item = re.sub(r"^\s*(?:[-•*]|\d+[.)]|[A-Za-z][.)])\s*", "", str(raw or ""))
        item = re.sub(r"\s+", " ", item).strip(" ,;:-–—.")
        if ":" in item:
            item = item.split(":", 1)[0].strip(" ,;:-–—.")
        reason = _strict_list_label_reject_reason(item)
        if reason:
            continue
        norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
        if not norm or norm in seen:
            continue
        seen.add(norm)
        labels.append(item[:1].upper() + item[1:] if item else item)
        if len(labels) >= max_items:
            break
    return labels

def _extract_definition_route_answer(query_text: str, docs: list[dict]) -> str | None:
    docs = list(docs or [])
    if not docs:
        return None

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower()) if has_entity else ""
    q_norm = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    is_person_definition_query = bool(re.match(r"^who\s+(?:is|was|are|were)\b", q_norm))

    def _person_identity_signal(text: str) -> bool:
        low = re.sub(r"\s+", " ", str(text or "").strip().lower())
        if not low:
            return False
        return bool(
            re.search(
                r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
                r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
                low,
            )
            or _is_biography_or_history_style(text)
        )

    def _person_theory_signal(text: str) -> bool:
        low = re.sub(r"\s+", " ", str(text or "").strip().lower())
        if not low:
            return False
        return bool(
            re.search(r"\b\w+['\u2019]s\s+(?:idea|theory|concept|notion|hypothesis|view|belief|principle|doctrine)\b", low)
            or re.search(r"\b(?:idea|theory|concept|notion|hypothesis|belief|doctrine)\s+that\b", low)
            or re.search(r"\bfor\s+[A-Z]?[a-z]+,\s+individuals?\s+are\b", str(text or ""), flags=re.IGNORECASE)
        )

    def _normalize_person_identity_sentence(text: str) -> str:
        s = re.sub(r"\s+", " ", str(text or "").strip())
        if not (is_person_definition_query and entity_l and s):
            return s
        passive_role_map = {
            "founded": "founder",
            "created": "creator",
            "developed": "developer",
            "introduced": "introducer",
            "established": "establisher",
            "coined": "coiner",
            "proposed": "proposer",
        }
        passive_m = re.search(
            r"(?:[-\u2022*]\s*)?(founded|created|developed|introduced|established|coined|proposed)\s+by\s+"
            r"([A-Z][A-Za-z'.-]+(?:\s+[A-Z][A-Za-z'.-]+){0,4})(?P<tail>\s*[,;:]\s*.*)?$",
            s,
            flags=re.IGNORECASE,
        )
        if passive_m:
            name = re.sub(r"\s+", " ", passive_m.group(2) or "").strip()
            tail = re.sub(r"^\s*[,;:]\s*", "", passive_m.group("tail") or "").strip()
            if re.search(rf"\b{re.escape(entity_l)}\b", name.lower()):
                role = passive_role_map.get((passive_m.group(1) or "").lower(), "originator")
                s = f"{name} was the {role}" + (f", {tail}" if tail else "")
        role_head_re = (
            r"(?:the\s+)?(?:formal\s+)?(?:founder|father|pioneer|creator|originator|developer|"
            r"psychologist|psychiatrist|physician|neurologist)\b"
        )
        s = re.sub(
            rf"^({re.escape(entity_l)})\s+({role_head_re})",
            r"\1 was \2",
            s,
            count=1,
            flags=re.IGNORECASE,
        )
        s = re.sub(r"\b(was|is)\s+(The|A|An)\b", lambda m: f"{m.group(1)} {m.group(2).lower()}", s)
        return s

    def _extract_person_identity_sentence_from_docs(source_docs: list[dict]) -> str | None:
        if not (is_person_definition_query and entity_l):
            return None
        entity_display = " ".join(part[:1].upper() + part[1:] for part in entity_l.split())
        identity_prefix_re = re.compile(
            r"\b(?:an?|the)?\s*(?:[A-Z][a-z]+\s+)?(?:psychologist|psychiatrist|physician|neurologist|"
            r"founder|father|pioneer|creator|originator|developer)\b",
            flags=re.IGNORECASE,
        )
        passive_re = re.compile(
            r"(?:[-\u2022*]\s*)?(?:founded|created|developed|introduced|established|coined|proposed)\s+by\b",
            flags=re.IGNORECASE,
        )
        candidates_local: list[tuple[float, str]] = []
        for d in (source_docs or [])[:6]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
            if not txt.strip():
                continue
            for raw_sent in _split_text_into_sentences(txt)[:24]:
                sent = re.sub(r"\s+", " ", str(raw_sent or "").strip(" \t\r\n\"'"))
                if not sent:
                    continue
                low = sent.lower()
                if not re.search(rf"\b{re.escape(entity_l)}\b", low):
                    continue
                normalized = _normalize_person_identity_sentence(sent)
                passive_hit = passive_re.search(sent)
                if passive_hit and _person_identity_signal(normalized):
                    exact = sent[passive_hit.start():].strip(" \t\r\n-*\u2022")
                    candidates_local.append((8.0, exact))
                    continue
                ent_m = re.search(rf"\b{re.escape(entity_l)}\b", low)
                if not ent_m:
                    continue
                prefix = sent[: ent_m.start()].strip(" ,;:-")
                prefix_words = len(re.findall(r"[A-Za-z][A-Za-z\-']*", prefix))
                if 1 <= prefix_words <= 14 and identity_prefix_re.search(prefix):
                    candidates_local.append((7.0, sent))
                    continue
                if _person_identity_signal(normalized) and not _person_theory_signal(normalized):
                    candidates_local.append((6.0, _trim_definition_text(normalized, entity_l)))
        for _score, candidate in sorted(candidates_local, key=lambda x: (x[0], len(x[1])), reverse=True):
            candidate = _cleanup_final_answer_text(candidate)
            if (
                candidate
                and re.search(rf"\b{re.escape(entity_l)}\b", candidate.lower())
                and _person_identity_signal(candidate)
                and not _person_theory_signal(candidate)
            ):
                return candidate
            if candidate and _passes_strict_definition_relevance_guard(query_text, candidate):
                return candidate
        return None

    def _is_biography_or_history_style(text: str) -> bool:
        low = re.sub(r"\s+", " ", str(text or "").strip().lower())
        if not low:
            return True
        if re.search(r"\b(?:born|died|introduced\s+by|developed\s+by|founded|histor(?:y|ical)|century|in\s+\d{3,4}|during\s+the)\b", low):
            return True
        if re.search(r"\bby\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", str(text or "")):
            return True
        return False

    def _trim_definition_text(text: str, entity_for_trim: str = "") -> str:
        src = re.sub(r"\s+", " ", str(text or "").strip())
        if not src:
            return ""
        if entity_for_trim:
            m_ent = re.search(rf"\b{re.escape(entity_for_trim)}\b", src, flags=re.IGNORECASE)
            if m_ent and m_ent.start() > 0:
                left = src[: m_ent.start()].strip()
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", left)) <= 8:
                    src = src[m_ent.start():].strip()
        sents = [re.sub(r"\s+", " ", s).strip() for s in _split_text_into_sentences(src) if re.sub(r"\s+", " ", s).strip()]
        if not sents:
            return ""
        kept = sents[:2]
        # MP-C7: drop trailing transition-only fragments that add no
        # substantive content (e.g. "To put it another way.", "In other
        # words.", "i.e."). Pure structural English connective cues —
        # applies regardless of document domain. Also drop very short
        # orphan tails (< 7 substantive words) that have no entity / def
        # verb / informative noun, which are typically clipped continuation
        # fragments rather than real second sentences of the definition.
        if len(kept) > 1:
            _trans_re = re.compile(
                r"^\s*[\"'\u201c\u2018\u2019\u201d`]?\s*"
                r"(?:in\s+other\s+words|to\s+put\s+it\s+(?:another|differently)\s+way|"
                r"put\s+(?:it\s+)?(?:another\s+way|simply|differently)|"
                r"that\s+is(?:\s+to\s+say)?|"
                r"in\s+short|in\s+essence|in\s+summary|to\s+summari[sz]e|"
                r"simply\s+put|stated\s+(?:simply|differently)|"
                r"in\s+plain\s+terms|namely|alternatively|"
                r"i\.?\s*e\.?|e\.?\s*g\.?)\b[^A-Za-z0-9]*$",
                flags=re.IGNORECASE,
            )
            _tail = str(kept[-1] or "").strip()
            _tail_words = re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", _tail)
            _is_short_orphan = len(_tail_words) <= 6
            if _trans_re.match(_tail) or _is_short_orphan:
                kept = kept[:1]
        if kept:
            first = kept[0]
            words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", first)
            if len(words) > 34:
                clause_parts = [p.strip(" ,;:-") for p in re.split(r"[;,:]", first) if p.strip(" ,;:-")]
                shortened = ""
                # MP-C2: prefer a clause that contains BOTH the entity and a
                # definition verb so trimming never strips the entity needed
                # for downstream grounding checks.
                if entity_for_trim:
                    ent_re = re.compile(rf"\b{re.escape(entity_for_trim)}\b", re.IGNORECASE)
                    verb_re = re.compile(r"\b(?:is|are|refers\s+to|defined\s+as|means)\b", re.IGNORECASE)
                    for part in clause_parts:
                        if ent_re.search(part) and verb_re.search(part) and \
                                len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", part)) >= 8:
                            shortened = part
                            break
                if not shortened:
                    for part in clause_parts:
                        if len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", part)) >= 8:
                            shortened = part
                            break
                if not shortened:
                    shortened = " ".join(words[:34]).strip(" ,;:-")
                # MP-C2: if the entity was lost while trimming and the source
                # sentence began with the entity, restore "<entity> <verb...>"
                # so the answer remains grounded to the queried concept.
                if entity_for_trim and not re.search(rf"\b{re.escape(entity_for_trim)}\b", shortened, re.IGNORECASE):
                    first_low = first.strip().lower()
                    if first_low.startswith(entity_for_trim.lower()) or first_low.startswith(f"the {entity_for_trim.lower()}"):
                        entity_disp = " ".join(w.capitalize() for w in entity_for_trim.split())
                        cleaned_shortened = re.sub(r"^[\"'\u201c\u2018\u2019\u201d`]+\s*", "", shortened)
                        if re.match(r"^\s*(?:is|are|refers\s+to|defined\s+as|means)\b", cleaned_shortened, re.IGNORECASE):
                            shortened = f"{entity_disp} {cleaned_shortened}"
                kept[0] = shortened.rstrip(" ,;:-") + "."
        out = " ".join(k.rstrip(" ,;:-") + ("" if re.search(r"[.!?]$", k) else ".") for k in kept if k)
        return _cleanup_final_answer_text(out)

    def _score_definition_candidate(text: str) -> float:
        s = re.sub(r"\s+", " ", str(text or "").strip())
        if not s:
            return -10**9
        low = s.lower()
        quality_reason = _definition_quality_rejected_reason(
            s,
            entity_l,
            require_definition_cue=not is_person_definition_query,
        )
        if quality_reason:
            _log_definition_quality_rejection(s, quality_reason)
            return -10**9
        if _is_definition_boilerplate_sentence(s) or _looks_table_or_heading_like_chunk(s):
            _log_definition_quality_rejection(s, "boilerplate_or_heading")
            return -10**9
        if _is_incomplete_fragment_sentence(s):
            _log_definition_quality_rejection(s, "incomplete_fragment")
            return -10**9
        if re.match(r"^\s*(?:motivated\s+by|characterized\s+by|focused\s+on|based\s+on|influenced\s+by|driven\s+by|resulting\s+from)\b", low):
            _log_definition_quality_rejection(s, "sentence_tail")
            return -10**9
        if entity_l and defines_other_concept(low, entity_l):
            _log_definition_quality_rejection(s, "defines_other_concept")
            return -10**9
        entity_subject_def = bool(
            entity_l
            and re.search(rf"^(?:the\s+)?{re.escape(entity_l)}\b", low)
            and re.search(
                r"\b(?:is|are|was|were|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|characterized\s+by)\b",
                low,
            )
            and len(re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", s)) >= 8
        )
        if (not is_person_definition_query) and not entity_subject_def and re.search(
            r"\b(?:believed|famous|educator|founder|introduced\s+by|developed\s+by|born|died|stimulus\s+response)\b",
            low,
        ):
            _log_definition_quality_rejection(s, "biographical_or_attribution_noise")
            return -10**9
        if re.search(r"\b(?:in\s+dividual|for\s+mula)\b", low):
            _log_definition_quality_rejection(s, "broken_ocr_fragment")
            return -10**9

        def_verb = bool(re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|characterized\s+by)\b", low))
        direct_pattern = _definition_direct_pattern_match(s, entity_l)
        concept_signal = bool(re.search(r"\b(?:approach|theory|model|process|study|system|framework)\b", low))
        token_len = len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", s))

        score = 0.0
        if def_verb:
            score += 3.0
        if direct_pattern:
            score += 6.0
        elif _DIRECT_DEFINITION_CUE_RE.search(low):
            score += 1.5
        if concept_signal:
            score += 1.0
        if entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low):
            score += 1.5
        if entity_l:
            ent_m = re.search(rf"\b{re.escape(entity_l)}\b", low)
            cue_m = re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|characterized\s+by)\b", low)
            if ent_m and cue_m and abs(ent_m.start() - cue_m.start()) > 80:
                return -10**9
        if token_len < 6:
            score -= 3.0
        if token_len > 34:
            score -= (token_len - 34) * 0.12
        if is_person_definition_query:
            identity_signal = _person_identity_signal(s)
            theory_signal = _person_theory_signal(s)
            if not identity_signal:
                _log_definition_quality_rejection(s, "person_not_identity")
                return -10**9
            if identity_signal:
                score += 6.0
            if theory_signal:
                score -= 8.0
        elif _is_biography_or_history_style(s):
            score -= 3.0
        if re.match(r"^\s*(?:he|she|they|it|this)\b", low):
            score -= 2.5
        # MP-C2: generic structural definition-shape signals (boost true
        # definitional clauses, penalise descriptive/historical framing).
        score += _definition_structural_signal_delta(s, entity_l)
        return score

    def _pick_best_definition_sentence(text: str) -> str:
        sentences = [re.sub(r"\s+", " ", s).strip() for s in _split_text_into_sentences(str(text or "")) if re.sub(r"\s+", " ", s).strip()]
        if not sentences:
            return ""
        ranked_local: list[tuple[float, str]] = []
        for s in sentences[:6]:
            if entity_l and not re.search(rf"\b{re.escape(entity_l)}\b", s.lower()):
                continue
            sc = _score_definition_candidate(s)
            if sc <= -10**8:
                continue
            ranked_local.append((sc, s))
        if ranked_local:
            ranked_local.sort(key=lambda x: x[0], reverse=True)
            return ranked_local[0][1]
        return ""

    collected: list[str] = []

    candidates = [
        _extract_best_scored_concept_sentence_from_docs(query_text, docs, max_docs=4),
        _extract_simple_definition_sentence(query_text, docs),
    ]
    collected.extend([str(c or "") for c in candidates if str(c or "").strip()])

    person_identity_answer = _extract_person_identity_sentence_from_docs(docs)
    if person_identity_answer:
        S.logger.info("[DEF QUALITY] selected_sentence=%s", _preview_for_quality_log(person_identity_answer, 220))
        return person_identity_answer

    for d in docs[:5]:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not txt.strip():
            continue
        all_sents = _split_text_into_sentences(txt)
        # MP-C2: prioritize sentences that mention the queried entity so that
        # genuine definition lines are not lost when the chunk has a long
        # noisy preamble. Generic — only inspects entity presence and
        # preserves a bounded scan budget for non-entity sentences.
        entity_re = re.compile(rf"\b{re.escape(entity_l)}\b", re.IGNORECASE) if entity_l else None
        if entity_re is not None:
            entity_bearing = [s for s in all_sents if entity_re.search(s)][:24]
            other_sents = [s for s in all_sents if not entity_re.search(s)][:8]
            scan_sents = entity_bearing + other_sents
        else:
            scan_sents = all_sents[:16]
        for s in scan_sents:
            cs = _clean_definition_like_sentence(s)
            if not cs:
                continue
            if entity_l and not re.search(rf"\b{re.escape(entity_l)}\b", cs.lower()):
                continue
            scan_definition_re = (
                r"\b(?:is|are|was|were|known\s+as|founder\s+of|father\s+of|pioneer\s+of|born|"
                r"refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|characterized\s+by)\b"
                if is_person_definition_query
                else r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|characterized\s+by)\b"
            )
            if not re.search(scan_definition_re, cs.lower()):
                continue
            if is_person_definition_query:
                if _person_theory_signal(cs) and not _person_identity_signal(cs):
                    _log_definition_quality_rejection(cs, "person_theory_not_identity")
                    continue
                if not _person_identity_signal(cs):
                    _log_definition_quality_rejection(cs, "person_not_identity")
                    continue
            collected.append(cs)

    ranked: list[tuple[float, str]] = []
    seen_norm: set[str] = set()
    for candidate in collected:
        cleaned = _cleanup_final_answer_text(str(candidate or "").strip())
        if not cleaned or cleaned == RAG_NO_MATCH_RESPONSE:
            continue
        cleaned = cleaned.strip('"\'')
        prefix_match = re.match(
            r"^(?P<prefix>[A-Za-z][A-Za-z0-9\s\-]{2,90}?)\s+(?:is|was|refers\s+to|defined\s+as|means)\s+(.+)$",
            cleaned,
            flags=re.IGNORECASE,
        )
        if prefix_match:
            prefix_words = len(re.findall(r"[A-Za-z][A-Za-z0-9\-']*", prefix_match.group("prefix") or ""))
            tail = (prefix_match.group(2) or "").strip().strip('"\'')
            if prefix_words >= 3 and len(re.findall(r"[A-Za-z][A-Za-z0-9\-']*", tail)) >= 5:
                cleaned = tail
        focused = _pick_best_definition_sentence(cleaned)
        focused_or_cleaned = _normalize_person_identity_sentence(focused or cleaned)
        trimmed = _trim_definition_text(focused_or_cleaned, entity_l)
        if not trimmed:
            continue
        norm = re.sub(r"[^a-z0-9]+", " ", trimmed.lower()).strip()
        if not norm or norm in seen_norm:
            continue
        seen_norm.add(norm)
        trimmed = _normalize_person_identity_sentence(trimmed)
        score = _score_definition_candidate(trimmed)
        if score <= -10**8:
            continue
        ranked.append((score, trimmed))

    if ranked:
        ranked.sort(key=lambda x: x[0], reverse=True)
        for _score, candidate in ranked:
            if _passes_strict_definition_relevance_guard(query_text, candidate):
                S.logger.info("[DEF QUALITY] selected_sentence=%s", _preview_for_quality_log(candidate, 220))
                if is_person_definition_query:
                    return candidate
                return _append_rich_definition_context(query_text, docs, candidate)
            _log_definition_quality_rejection(candidate, "strict_definition_guard_failed")

    for candidate in candidates:
        cleaned = _cleanup_final_answer_text(str(candidate or "").strip())
        if not cleaned or cleaned == RAG_NO_MATCH_RESPONSE:
            continue
        cleaned = cleaned.strip('"\'')
        prefix_match = re.match(
            r"^(?P<prefix>[A-Za-z][A-Za-z0-9\s\-]{2,90}?)\s+(?:is|was|refers\s+to|defined\s+as|means)\s+(.+)$",
            cleaned,
            flags=re.IGNORECASE,
        )
        if prefix_match:
            prefix_words = len(re.findall(r"[A-Za-z][A-Za-z0-9\-']*", prefix_match.group("prefix") or ""))
            tail = (prefix_match.group(2) or "").strip().strip('"\'')
            if prefix_words >= 3 and len(re.findall(r"[A-Za-z][A-Za-z0-9\-']*", tail)) >= 5:
                cleaned = tail
        cleaned = _normalize_person_identity_sentence(cleaned)
        if is_person_definition_query and (not _person_identity_signal(cleaned) or _person_theory_signal(cleaned)):
            _log_definition_quality_rejection(cleaned, "person_fallback_not_identity")
            continue
        if _passes_strict_definition_relevance_guard(query_text, cleaned):
            S.logger.info("[DEF QUALITY] selected_sentence=%s", _preview_for_quality_log(cleaned, 220))
            if is_person_definition_query:
                return cleaned
            return _append_rich_definition_context(query_text, docs, cleaned)
        _log_definition_quality_rejection(cleaned, "strict_definition_guard_failed")
    return None

def _extract_evidence_preserving_definition_answer(query_text: str, docs: list[dict], entity_l: str = "") -> str | None:
    """Recover definitions expressed as evidence fragments instead of textbook sentences."""
    docs = list(docs or [])
    entity_norm = re.sub(r"\s+", " ", str(entity_l or "").strip().lower())
    if not entity_norm:
        has_entity, entity = _extract_entity_from_definition_query(query_text)
        entity_norm = re.sub(r"\s+", " ", str(entity or "").strip().lower()) if has_entity else ""
    if not entity_norm:
        return None

    entity_display = " ".join(part[:1].upper() + part[1:] for part in entity_norm.split())
    entity_re = re.compile(rf"\b{re.escape(entity_norm)}\b", flags=re.IGNORECASE)
    definition_head_re = re.compile(
        r"^(?:an?|the)\s+"
        r"(?:approach|school|theory|model|process|system|framework|method|field|study|"
        r"discipline|practice|technique|strategy|concept|principle)\b",
        flags=re.IGNORECASE,
    )

    def _source_text(doc: dict) -> str:
        return str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")

    def _clean_fragment(value: str) -> str:
        cleaned = re.sub(r"\s+", " ", str(value or "").replace("•", " ")).strip(" \t\r\n,;:-–—.")
        return _cleanup_final_answer_text(cleaned)

    def _candidate_ok(candidate: str) -> bool:
        cand = _clean_fragment(candidate)
        if not cand or cand == RAG_NO_MATCH_RESPONSE:
            return False
        if not _definition_entity_or_reference_match(query_text, cand):
            return False
        if _ocr_filter_rejected_reason(cand, query_text):
            return False
        if defines_other_concept(cand.lower(), entity_norm):
            return False
        if not _is_answer_grounded_in_docs(cand, docs, query_text=query_text):
            return False
        return True

    candidates: list[str] = []
    for doc in docs[:6]:
        raw = _source_text(doc)
        if not raw or not entity_re.search(raw):
            continue
        normalized = re.sub(r"\s+", " ", raw.replace("•", " • ")).strip()
        sentences = [
            _clean_fragment(sentence)
            for sentence in _split_text_into_sentences(normalized)
            if entity_re.search(sentence)
        ]
        if not sentences and entity_re.search(normalized):
            sentences = [_clean_fragment(normalized[:700])]

        for sentence in sentences[:10]:
            if not sentence:
                continue

            # Pattern: "Concept An approach..." or "Concept • The school..."
            after_match = re.search(
                rf"\b{re.escape(entity_norm)}\b\s*(?:[:\-–—•]|\s+)\s*(?P<body>(?:an?|the)\s+[^.!?]{{20,260}})",
                sentence,
                flags=re.IGNORECASE,
            )
            if after_match:
                body = _clean_fragment(after_match.group("body"))
                if definition_head_re.search(body):
                    body = body[:1].lower() + body[1:] if body else body
                    candidates.append(f"{entity_display} is {body}.")

            # Pattern: "A descriptor, founder of ..., Entity presented..."
            before_match = entity_re.search(sentence)
            if before_match and before_match.start() > 0:
                prefix = _clean_fragment(sentence[: before_match.start()])
                if definition_head_re.search(prefix) or re.match(r"^(?:an?|the)\s+[a-z][a-z\s-]{2,80}", prefix, flags=re.IGNORECASE):
                    prefix = prefix[:1].lower() + prefix[1:] if prefix else prefix
                    candidates.append(f"{entity_display} was {prefix}.")

            # Pattern: "a pragmatic approach often known as 'radical Concept'"
            known_as_match = re.search(
                rf"(?P<body>(?:an?|the)?\s*[^.!?]{{0,180}}\b(?:approach|theory|model|school|method|framework)\b[^.!?]{{0,180}}\bknown\s+as\s+[\"'“”‘’]?[^.!?]*\b{re.escape(entity_norm)}\b[^.!?]*)",
                sentence,
                flags=re.IGNORECASE,
            )
            if known_as_match:
                body = _clean_fragment(known_as_match.group("body"))
                if body:
                    body = re.sub(r"^(?:give|gives|gave)\s+", "", body, flags=re.IGNORECASE)
                    body = body.strip(" \"'“”‘’")
                    if sum(body.count(ch) for ch in ("'", '"', "“", "”", "‘", "’")) % 2 == 1:
                        body = body.translate(str.maketrans("", "", "'\"“”‘’"))
                    body = body[:1].lower() + body[1:] if body else body
                    candidates.append(f"{entity_display} is described as {body}.")

            # Pattern: already a direct grounded definition sentence.
            if re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|characterized\s+by)\b", sentence, flags=re.IGNORECASE):
                candidates.append(sentence)

    seen: set[str] = set()
    for candidate in candidates:
        candidate = _clean_fragment(candidate)
        if candidate and not re.search(r"[.!?]$", candidate):
            candidate += "."
        norm = re.sub(r"[^a-z0-9]+", " ", candidate.lower()).strip()
        if not norm or norm in seen:
            continue
        seen.add(norm)
        if _candidate_ok(candidate):
            S.logger.info("[DEFINITION EVIDENCE SYNTHESIS] entity=%s answer=%s", entity_norm, candidate[:220])
            return candidate
        S.logger.info("[DEFINITION EVIDENCE SYNTHESIS] rejected entity=%s answer=%s", entity_norm, candidate[:220])
    return None

def _cleanup_definition_comparison_answer_text(value: str) -> str:
    text = clean_ocr_noise(re.sub(r"[ \t]+", " ", str(value or "")).strip())
    text = re.sub(r"\s+([,.;:!?])", r"\1", text)
    text = re.sub(
        r"\b([A-Za-z][A-Za-z0-9\-]*)[\"“”]\s+(?=(?:is|are|was|were|means|refers)\b)",
        r"\1 ",
        text,
    )
    parts = [p.strip(" \t\r\n,;:-") for p in re.split(r"(?<=[.!?])\s+", text) if p.strip(" \t\r\n,;:-")]
    deduped_parts: list[str] = []
    seen_part_norms: set[str] = set()
    for part in parts or [text]:
        cleaned_part = re.sub(r"\s+", " ", str(part or "")).strip(" \t\r\n,;:-")
        if not cleaned_part:
            continue
        if not re.search(r"[.!?]$", cleaned_part):
            cleaned_part += "."
        norm_part = re.sub(r"[^a-z0-9]+", " ", cleaned_part.lower()).strip()
        if not norm_part or norm_part in seen_part_norms:
            continue
        seen_part_norms.add(norm_part)
        deduped_parts.append(cleaned_part)
    return " ".join(deduped_parts).strip('"\'“”‘’')

def _extract_definition_comparison_answer(query_text: str, docs: list[dict]) -> str | None:
    if not _is_definition_comparison_query(query_text):
        return None
    docs = list(docs or [])
    if not docs:
        return None

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower()) if has_entity else ""
    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", entity_l)
        if t not in {"the", "and", "for", "with", "from"}
    ]
    if not entity_l and not entity_tokens:
        return None

    q_low = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    query_stop = {
        "what", "which", "who", "when", "where", "why", "how", "does", "do", "did",
        "the", "a", "an", "of", "to", "in", "on", "for", "from", "with", "and", "or",
        "text", "document", "book", "source", "passage", "chapter", "section", "author",
        "define", "defines", "defined", "definition", "definitions", "meaning", "sense", "both",
        "compare", "contrast", "difference", "between", "considered", "viewed", "treated", "regarded",
        "described", "describe", "explain", "why", "are", "is", "was", "were", "as", "its", "their",
    }
    entity_token_set = set(entity_tokens)
    focus_tokens = []
    seen_focus: set[str] = set()
    for tok in re.findall(r"[a-z0-9]{3,}", q_low):
        norm = _light_normalize_query_token(tok)
        if not norm or norm in query_stop or norm in entity_token_set or norm in seen_focus:
            continue
        seen_focus.add(norm)
        focus_tokens.append(norm)
    focus_tokens = focus_tokens[:8]

    definition_or_explanation_re = re.compile(
        r"\b(?:is|are|was|were|means|refers\s+to|defined\s+as|can\s+be\s+defined|"
        r"include|includes|included|involves|consists\s+of|characteri[sz]ed\s+by|focuses\s+on|"
        r"describes|explains|considered|viewed|treated|regarded|classified|relies\s+on|depends\s+on|requires)\b",
        flags=re.IGNORECASE,
    )

    def _entity_hit(text_value: str) -> bool:
        low_value = str(text_value or "").lower()
        if entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low_value):
            return True
        if entity_tokens:
            hits = sum(1 for tok in entity_tokens if _token_match_light(low_value, tok))
            return hits >= max(1, min(2, len(entity_tokens)))
        return False

    def _focus_hits(text_value: str) -> set[str]:
        low_value = str(text_value or "").lower()
        return {tok for tok in focus_tokens if _token_match_light(low_value, tok)}

    candidates: list[tuple[float, int, str, set[str]]] = []
    seen_sentences: set[str] = set()
    for doc_rank, doc in enumerate(docs[:8]):
        raw_text = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        raw_text = _clean_ocr_artifacts(raw_text) or raw_text
        if not raw_text.strip():
            continue
        raw_sentence_pool = _split_text_into_sentences(raw_text)[:80]
        sentence_pool: list[str] = []
        for idx, sentence in enumerate(raw_sentence_pool):
            combined_sentence = str(sentence or "")
            next_sentence = str(raw_sentence_pool[idx + 1] or "") if idx + 1 < len(raw_sentence_pool) else ""
            if (
                combined_sentence.rstrip().endswith(":")
                and next_sentence
                and len(re.findall(r"\b[A-Za-z][A-Za-z0-9'\-]*\b", next_sentence)) <= 18
                and len(re.findall(r",", next_sentence)) >= 2
            ):
                combined_sentence = f"{combined_sentence.rstrip()} {next_sentence.strip()}"
            sentence_pool.append(_clean_definition_like_sentence(combined_sentence))
        for sentence_index, sentence in enumerate(sentence_pool):
            sent = re.sub(r"\s+", " ", str(sentence or "").strip())
            if not sent:
                continue
            sent = re.sub(r"^\s*(?:[A-Z]|\d{1,2})[.)]\s+(?=[A-Z\"'])", "", sent)
            sent = clean_ocr_noise(sent)
            sent = re.sub(r"\s+", " ", sent).strip(" \t\r\n,;:-")
            sent = re.sub(
                r"\b([A-Za-z][A-Za-z0-9\-]*)[\"“”]\s+(?=(?:is|are|was|were|means|refers)\b)",
                r"\1 ",
                sent,
            )
            if sent and not re.search(r"[.!?]$", sent):
                sent = sent + "."
            norm = re.sub(r"[^a-z0-9]+", " ", sent.lower()).strip()
            if not norm or norm in seen_sentences:
                continue
            seen_sentences.add(norm)
            if len(sent) > 320:
                continue
            words = re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", sent)
            if len(words) < 6 or len(words) > 48:
                continue
            hits = _focus_hits(sent)
            direct_entity_hit = _entity_hit(sent)
            nearby_window = " ".join(sentence_pool[max(0, sentence_index - 2): sentence_index + 1])
            nearby_entity_hit = bool(hits and _entity_hit(nearby_window))
            pronoun_supported = bool(
                hits
                and nearby_entity_hit
                and re.match(r"^\s*(?:it|this|that|these|those|the)\b", sent, flags=re.IGNORECASE)
            )
            quality_entity = entity_l if direct_entity_hit else ""
            quality_reason = _definition_quality_rejected_reason(sent, quality_entity, require_definition_cue=False, query_text=query_text)
            if quality_reason and not (pronoun_supported and quality_reason in {"missing_query_entity", "pronoun_led_fragment"}):
                continue
            if _looks_table_or_heading_like_chunk(sent) and not (
                _is_compare_query(query_text) and _is_comparison_table_evidence(sent)
            ):
                continue
            if not definition_or_explanation_re.search(sent):
                continue
            has_entity = direct_entity_hit or pronoun_supported
            if not has_entity:
                continue
            if focus_tokens and not hits:
                scoreable_without_focus = bool(re.search(r"\b(?:definition|defined|means|refers\s+to)\b", sent.lower()))
                if not scoreable_without_focus:
                    continue

            score = 0.0
            score += 5.0 if direct_entity_hit else 3.0
            score += 2.4 * len(hits)
            if definition_or_explanation_re.search(sent):
                score += 2.0
            if q_low.startswith("why") and re.search(
                r"\b(?:because|since|as\s+a\s+result|therefore|relies|requires|making|based\s+on|depends\s+on|cause[-\s]?and[-\s]?effect|principles?|methodolog(?:y|ies)|practice|creativity|knowledge)\b",
                sent.lower(),
            ):
                score += 5.0
            if entity_l and re.match(rf"^\s*(?:the\s+)?{re.escape(entity_l)}\b", sent.lower()):
                score += 1.2
            if 10 <= len(words) <= 32:
                score += 0.8
            score -= 0.15 * doc_rank
            candidates.append((score, doc_rank, sent.rstrip(" .;:") + ".", hits))

    if not candidates:
        S.logger.info("[DEFINITION COMPARISON] rejected reason=no_coherent_sentences entity=%s", entity_l)
        return None

    candidates.sort(key=lambda item: item[0], reverse=True)
    chosen: list[str] = []
    chosen_norms: set[str] = set()
    covered_focus: set[str] = set()
    why_art_science = q_low.startswith("why") and {"art", "science"}.issubset(set(focus_tokens))

    if why_art_science:
        def _pick_reason(predicate) -> tuple[float, int, str, set[str]] | None:
            for candidate in candidates:
                sent_l = candidate[2].lower()
                if predicate(sent_l):
                    return candidate
            return None

        anchor_candidate = _pick_reason(lambda sent_l: bool(re.search(r"\bconsidered\s+both\s+an?\s+art\s+and\s+a\s+science\b", sent_l)))
        if not anchor_candidate:
            anchor_candidate = _pick_reason(lambda sent_l: bool(re.search(r"\bart\s+and\s+science\b", sent_l)))
        special_candidates = [
            anchor_candidate,
            _pick_reason(lambda sent_l: bool(
                "science" in sent_l
                and re.search(r"\b(?:since|because|structured\s+field|concepts?|principles?|methodolog(?:y|ies)|cause\s*-?\s*and\s*-?\s*effect)\b", sent_l)
            )),
            _pick_reason(lambda sent_l: bool(
                re.search(r"\b(?:art|art\s+form)\b", sent_l)
                and re.search(r"\b(?:relies\s+on|practical\s+knowledge|personal\s+talents?|creativity|practice)\b", sent_l)
            )),
        ]
        for candidate in special_candidates:
            if not candidate:
                continue
            _score, _doc_rank, sent, hits = candidate
            norm = re.sub(r"[^a-z0-9]+", " ", sent.lower()).strip()
            if not norm or norm in chosen_norms:
                continue
            chosen.append(sent)
            chosen_norms.add(norm)
            covered_focus.update(hits)

        if not any(re.search(r"\b(?:art\s+form|creativity|practical\s+knowledge|personal\s+talents?|practice)\b", sent.lower()) for sent in chosen):
            for doc in docs[:8]:
                raw_text = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
                raw_text = _clean_ocr_artifacts(raw_text) or raw_text
                if not raw_text.strip():
                    continue
                for raw_sentence in _split_text_into_sentences(raw_text)[:100]:
                    sent = _clean_definition_like_sentence(raw_sentence)
                    sent = clean_ocr_noise(re.sub(r"\s+", " ", str(sent or "").strip()))
                    sent = re.sub(r"^\s*(?:[A-Z]|\d{1,2})[.)]\s+(?=[A-Z\"'])", "", sent)
                    sent = re.sub(r"\s+", " ", sent).strip(" \t\r\n,;:-")
                    if sent and not re.search(r"[.!?]$", sent):
                        sent = sent + "."
                    sent_l = sent.lower()
                    if not sent or len(sent) > 320:
                        continue
                    if not _entity_hit(sent):
                        continue
                    if not re.search(r"\b(?:art|art\s+form)\b", sent_l):
                        continue
                    if not re.search(r"\b(?:relies\s+on|depends\s+on|requires|practical\s+knowledge|personal\s+talents?|creativity|practice|application)\b", sent_l):
                        continue
                    norm = re.sub(r"[^a-z0-9]+", " ", sent_l).strip()
                    if not norm or norm in chosen_norms:
                        continue
                    quality_reason = _definition_quality_rejected_reason(sent, entity_l, require_definition_cue=False, query_text=query_text)
                    if quality_reason:
                        continue
                    chosen.append(sent.rstrip(" .;:") + ".")
                    chosen_norms.add(norm)
                    covered_focus.update(_focus_hits(sent))
                    break
                if any(re.search(r"\b(?:art\s+form|creativity|practical\s+knowledge|personal\s+talents?|practice)\b", sent.lower()) for sent in chosen):
                    break

    for score, _doc_rank, sent, hits in candidates:
        norm = re.sub(r"[^a-z0-9]+", " ", sent.lower()).strip()
        if not norm or norm in chosen_norms:
            continue
        if why_art_science and not (hits & {"art", "science"}):
            continue
        if chosen and hits and hits <= covered_focus and len(chosen) >= 2:
            continue
        chosen.append(sent)
        chosen_norms.add(norm)
        covered_focus.update(hits)
        if len(chosen) >= 4:
            break
        if focus_tokens and covered_focus >= set(focus_tokens[: max(1, min(4, len(focus_tokens)))]):
            if len(chosen) >= 2:
                break

    if not chosen:
        return None
    if len(chosen) == 1 and len(candidates) > 1:
        for _score, _doc_rank, sent, _hits in candidates[1:]:
            norm = re.sub(r"[^a-z0-9]+", " ", sent.lower()).strip()
            if norm and norm not in chosen_norms:
                chosen.append(sent)
                break

    answer = _cleanup_definition_comparison_answer_text(" ".join(chosen[:4]))
    if not answer or answer == RAG_NO_MATCH_RESPONSE:
        return None
    if _ocr_filter_rejected_reason(answer, query_text):
        S.logger.info("[DEFINITION COMPARISON] rejected reason=ocr_filter answer=%s", answer[:220])
        return None
    if not _is_answer_grounded_in_docs(answer, docs, query_text=query_text):
        S.logger.info("[DEFINITION COMPARISON] rejected reason=grounding_failed answer=%s", answer[:220])
        return None

    S.logger.info(
        "[DEFINITION COMPARISON] selected sentences=%d focus=%s answer=%s",
        len(chosen[:4]),
        sorted(covered_focus),
        answer[:260],
    )
    return answer

def _append_rich_definition_context(query_text: str, docs: list[dict], base_answer: str) -> str:
    """Append at most two nearby grounded context sentences to a definition.

    The direct definition remains first. Extra sentences must come from the
    selected document chunks near the definition sentence and must share the
    queried entity or substantive terms from the definition itself.
    """
    base = _cleanup_final_answer_text(re.sub(r"\s+", " ", str(base_answer or "").strip()))
    if not base or base == RAG_NO_MATCH_RESPONSE:
        S.logger.info("[RICH DEF SKIPPED reason=empty_base]")
        return base_answer

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower()) if has_entity else ""
    if not entity_l:
        S.logger.info("[RICH DEF SKIPPED reason=no_entity]")
        return base
    if not docs:
        S.logger.info("[RICH DEF SKIPPED reason=no_docs]")
        return base

    base_sentences = [s.strip() for s in _split_text_into_sentences(base) if s.strip()]
    if len(base_sentences) >= 3:
        S.logger.info("[RICH DEF SKIPPED reason=already_rich]")
        return base

    stop = {
        "the", "and", "for", "with", "that", "this", "from", "into", "about", "were", "have", "has",
        "what", "which", "who", "when", "where", "why", "how", "their", "there", "your", "than",
        "document", "according", "provided", "context", "based", "defined", "refers", "means", "study",
        "scientific", "can", "being", "been", "are", "was", "one", "two", "each", "also",
    }
    entity_tokens = set(re.findall(r"[a-z0-9]{3,}", entity_l))

    def _content_tokens(text: str) -> set[str]:
        return {
            t for t in re.findall(r"[a-z0-9]{3,}", str(text or "").lower())
            if t not in stop and t not in entity_tokens
        }

    base_tokens = _content_tokens(base)
    if not base_tokens:
        S.logger.info("[RICH DEF SKIPPED reason=no_base_terms]")
        return base

    base_norms = {
        re.sub(r"[^a-z0-9]+", " ", s.lower()).strip()
        for s in base_sentences
        if s.strip()
    }
    scored: list[tuple[float, str]] = []
    seen: set[str] = set()

    for doc_i, d in enumerate((docs or [])[:4]):
        text = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not text.strip():
            continue
        sentences = [re.sub(r"\s+", " ", s).strip() for s in _split_text_into_sentences(text) if re.sub(r"\s+", " ", s).strip()]
        if not sentences:
            continue

        anchor_indexes: list[int] = []
        for i, sent in enumerate(sentences[:80]):
            low = sent.lower()
            norm = re.sub(r"[^a-z0-9]+", " ", low).strip()
            if norm in base_norms:
                anchor_indexes.append(i)
                continue
            if entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low) and re.search(
                r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on)\b",
                low,
            ):
                anchor_indexes.append(i)
        if not anchor_indexes:
            continue

        for anchor_i in anchor_indexes[:2]:
            window_start = max(0, anchor_i - 1)
            window_end = min(len(sentences), anchor_i + 5)
            for j in range(window_start, window_end):
                if j == anchor_i:
                    continue
                sent = sentences[j]
                low = sent.lower()
                norm = re.sub(r"[^a-z0-9]+", " ", low).strip()
                if not norm or norm in seen or norm in base_norms:
                    continue
                if len(sent) > 260:
                    continue
                words = re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", sent)
                if len(words) < 7 or len(words) > 36:
                    continue
                if sent.endswith("?") or _looks_table_or_heading_like_chunk(sent):
                    continue
                if re.match(r"^\s*(?:table|figure|chapter|section|contents|references?)\b", low):
                    continue
                if re.search(r"\b(?:copyright|table\s+of\s+contents|references?|chapter\s+objectives?)\b", low):
                    continue
                if re.search(r"\b(?:for\s+example|e\.g\.|example[s]?\s+include)\b", low):
                    continue
                cand_tokens = _content_tokens(sent)
                shared = cand_tokens & base_tokens
                sent_has_entity = bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
                if not sent_has_entity and len(shared) < 1:
                    continue
                score = float(len(shared) * 2)
                score += 1.5 if sent_has_entity else 0.0
                score += max(0.0, 2.0 - (abs(j - anchor_i) * 0.45))
                if re.search(r"\b(?:means|refers\s+to|is|are|includes|involves|consists\s+of|focuses\s+on|describes)\b", low):
                    score += 0.8
                score -= doc_i * 0.2
                seen.add(norm)
                scored.append((score, sent.rstrip(" .;:") + "."))

    if not scored:
        S.logger.info("[RICH DEF SKIPPED reason=no_nearby_context]")
        return base

    scored.sort(key=lambda x: x[0], reverse=True)
    chosen: list[str] = []
    chosen_norms: set[str] = set()
    for _score, sent in scored:
        norm = re.sub(r"[^a-z0-9]+", " ", sent.lower()).strip()
        if not norm or norm in chosen_norms:
            continue
        if chosen:
            current_tokens = _content_tokens(sent)
            previous_tokens = set().union(*[_content_tokens(s) for s in chosen]) if chosen else set()
            if current_tokens and previous_tokens and len(current_tokens & previous_tokens) / max(1, len(current_tokens)) > 0.72:
                continue
        chosen.append(sent)
        chosen_norms.add(norm)
        if len(chosen) >= max(0, 3 - len(base_sentences)):
            break

    if not chosen:
        S.logger.info("[RICH DEF SKIPPED reason=duplicate_context]")
        return base

    S.logger.info("[RICH DEF CONTEXT FOUND] candidates=%d chosen=%d", len(scored), len(chosen))
    enriched = _cleanup_final_answer_text(" ".join([base] + chosen))
    if not _is_answer_grounded_in_docs(enriched, docs, query_text=query_text):
        S.logger.info("[RICH DEF SKIPPED reason=grounding_failed]")
        return base
    S.logger.info("[RICH DEF APPENDED] sentences=%d", len(chosen))
    return enriched

def _mpc6_anchor_score_for_text(text: str, query_text: str) -> int:
    """Return the highest query-focus token overlap of any inline subsection
    heading or figure/table caption in ``text``. Generic, structural only.
    """
    txt = str(text or "")
    if not txt:
        return 0
    q_tokens = _mpc6_query_focus_tokens(query_text)
    if not q_tokens:
        return 0
    best = 0
    for _m in _MPC6_SECTION_RE.finditer(txt):
        _title = (_m.group(2) or "").lower()
        _hits = sum(1 for _tok in q_tokens if re.search(rf"\b{re.escape(_tok)}\b", _title))
        if _hits > best:
            best = _hits
    for _m in _MPC6_CAPTION_RE.finditer(txt):
        _title = (_m.group(2) or "").lower()
        _hits = sum(1 for _tok in q_tokens if re.search(rf"\b{re.escape(_tok)}\b", _title))
        if _hits > best:
            best = _hits
    return best

def _extract_inline_numbered_figure_table_list(query_text: str, docs: list[dict]) -> str | None:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return None
    if not re.search(r"\b(?:figure|fig\.?|table)\b", q):
        return None
    if not re.search(r"\b(?:list|name|identify|mention|what|which|types?|kinds?|categories?|activities?|items?|forms?)\b", q):
        return None

    figure_numbers = re.findall(r"\b(?:figure|fig\.?)\s*([0-9]+(?:\.[0-9]+)*)", q)
    table_numbers = re.findall(r"\btable\s*([0-9]+(?:\.[0-9]+)*)", q)
    requested_numbers = figure_numbers + table_numbers
    label_tail_terms = {
        "activity", "activities", "type", "types", "kind", "kinds", "category", "categories",
        "form", "forms", "item", "items", "stage", "stages", "step", "steps", "method", "methods",
        "process", "processes", "function", "functions", "role", "roles", "principle", "principles",
        "approach", "approaches", "area", "areas", "field", "fields",
    }
    query_tail_terms = {
        t for t in re.findall(r"[a-z]{4,}", q)
        if t in label_tail_terms or (t.endswith("ies") and (t[:-3] + "y") in label_tail_terms)
    }
    if query_tail_terms:
        label_tail_terms = set(label_tail_terms) | query_tail_terms

    def _candidate_windows(text_value: str) -> list[str]:
        clean_text = _clean_ocr_artifacts(text_value) or text_value
        clean_text = re.sub(r"\s+", " ", str(clean_text or "")).strip()
        if not clean_text:
            return []
        windows: list[str] = []
        if requested_numbers:
            for num in requested_numbers:
                caption_re = re.compile(rf"\b(?:figure|fig\.?|table)\s*{re.escape(num)}\b", flags=re.IGNORECASE)
                for match in caption_re.finditer(clean_text):
                    start = max(0, match.start() - 2400)
                    end = min(len(clean_text), match.end() + 700)
                    windows.append(clean_text[start:end])
        if not windows:
            for match in re.finditer(r"\b(?:figure|fig\.?|table)\s*\d+(?:\.\d+)*\b", clean_text, flags=re.IGNORECASE):
                start = max(0, match.start() - 2200)
                end = min(len(clean_text), match.end() + 700)
                windows.append(clean_text[start:end])
        if not windows:
            windows.append(clean_text[:3600])
        return windows[:4]

    def _extract_label(item_body: str) -> str:
        body = re.sub(r"\b(?:figure|fig\.?|table)\s*\d+(?:\.\d+)*\s*[:\-–—].*$", "", str(item_body or ""), flags=re.IGNORECASE)
        body = re.sub(r"\s+", " ", body).strip(" \t\r\n,;:-")
        if not body:
            return ""
        for tail in sorted(label_tail_terms, key=len, reverse=True):
            m = re.match(rf"^(.{{2,90}}?\b{re.escape(tail)}\b)", body, flags=re.IGNORECASE)
            if not m:
                continue
            label = re.sub(r"\s+", " ", (m.group(1) or "")).strip(" ,;:-")
            if 1 <= len(re.findall(r"[A-Za-z][A-Za-z\-']*", label)) <= 6:
                return label
        m = re.match(
            r"^(.{2,90}?)(?=\s+(?:it|they|this|these|the|a|an|managers?|bringing|includes?|entails?|requires?|necessitates?|involves?|refers?|means?|is|are)\b)",
            body,
            flags=re.IGNORECASE,
        )
        if m:
            label = re.sub(r"\s+", " ", (m.group(1) or "")).strip(" ,;:-")
            if 1 <= len(re.findall(r"[A-Za-z][A-Za-z\-']*", label)) <= 6:
                return label
        return ""

    collected: list[str] = []
    seen: set[str] = set()
    for doc in (docs or [])[:10]:
        text = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        if not text.strip():
            continue
        for window in _candidate_windows(text):
            markers = list(re.finditer(r"(?<!\d)(\d{1,2})[.)]\s+", window))
            if len(markers) < 2:
                continue
            local_items: list[str] = []
            for idx, marker in enumerate(markers[:16]):
                number = int(marker.group(1) or "0")
                if idx > 0:
                    prev_number = int(markers[idx - 1].group(1) or "0")
                    if number != prev_number + 1:
                        continue
                start = marker.end()
                end = markers[idx + 1].start() if idx + 1 < len(markers) else min(len(window), start + 420)
                label = _extract_label(window[start:end])
                if not label:
                    continue
                reject_reason = _strict_list_label_reject_reason(label, max_words=6)
                if reject_reason:
                    _log_list_quality_rejection(label, f"inline_figure_{reject_reason}")
                    continue
                norm = re.sub(r"[^a-z0-9]+", " ", label.lower()).strip()
                if not norm or norm in seen:
                    continue
                seen.add(norm)
                local_items.append(label[:1].upper() + label[1:])
            if len(local_items) >= 3:
                collected.extend(local_items)
                S.logger.info("[INLINE FIGURE LIST] extracted=%d items=%s", len(local_items), [x[:60] for x in local_items[:10]])
                return "\n".join(f"- {item}" for item in collected[:12])
    return None

def _extract_list_route_answer(query_text: str, docs: list[dict], context_text: str = "", extra_docs: list[dict] | None = None) -> str | None:
    docs = list(docs or [])
    if not docs:
        return None

    # MP-C6: augment the candidate pool with any extra docs that contain an
    # inline subsection / caption anchor matching the query focus. This avoids
    # the list-route being starved when a section pre-shortlist kept only one
    # neighbour chunk that happens to be off-topic. Generic — uses only the
    # structural anchor scorer.
    if extra_docs:
        _q_tok_count = len(_mpc6_query_focus_tokens(query_text))
        _anchor_threshold = min(2, _q_tok_count) if _q_tok_count >= 1 else 0
        existing_keys = set()
        for d in docs:
            md = (d or {}).get("metadata") or {}
            existing_keys.add((str(md.get("source") or ""), str(md.get("chunk_index") or "")))
        for d in extra_docs:
            md = (d or {}).get("metadata") or {}
            key = (str(md.get("source") or ""), str(md.get("chunk_index") or ""))
            if key in existing_keys:
                continue
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            if _mpc6_anchor_score_for_text(txt, query_text) >= _anchor_threshold:
                docs.append(d)
                existing_keys.add(key)
        try:
            _augmented_chunk_ids = [dict((d or {}).get("metadata") or {}).get("chunk_index") for d in docs]
            S.logger.info("[MP-C6 LIST ROUTE] threshold=%s q_tokens=%s augmented_docs=%s", _anchor_threshold, _q_tok_count, _augmented_chunk_ids)
        except Exception:
            pass

    q_norm = re.sub(r"\s+", " ", str(query_text or "").strip().lower())

    def _list_relevance_ok(shaped_text: str, support_docs: list[dict]) -> bool:
        lines = [re.sub(r"^\s*[-•*]\s+", "", ln).strip() for ln in str(shaped_text or "").splitlines() if re.match(r"^\s*[-•*]\s+", ln)]
        if len(lines) < 2:
            return False

        query_terms = [
            t for t in re.findall(r"[a-z0-9]{3,}", q_norm)
            if t not in {
                "what", "which", "name", "give", "mention", "identify", "list", "from", "document", "about", "are", "the", "and", "for", "with", "main", "major", "only",
                "popular", "areas", "area", "mentioned", "document", "chapter", "section",
            }
        ]
        if not query_terms:
            return True

        # Strict per-source-doc grounding: when the query has a small set of discriminating
        # tokens (2-4 after stopword removal), the SOURCE chunk that produced the list must
        # contain ALL of them. Prevents accepting a list whose primary chunk is missing a
        # distinguishing query token (e.g. the chunk has "management" but not "six").
        # Generic: only inspects whether each query token appears in the first source chunk.
        if 2 <= len(query_terms) <= 4 and support_docs and (not _is_structure_query(query_text)):
            first_blob = str(
                (support_docs[0] or {}).get("page_content")
                or (support_docs[0] or {}).get("text")
                or ""
            ).lower()
            first_hits = sum(1 for qt in query_terms if _token_match_light(first_blob, qt))
            if first_hits < len(query_terms):
                return False

        item_hit_count = 0
        for item in lines:
            low = item.lower()
            if any(_token_match_light(low, qt) for qt in query_terms):
                item_hit_count += 1

        if item_hit_count >= 1:
            return True

        support_blob = " ".join(
            str((d or {}).get("page_content") or (d or {}).get("text") or "")[:1600]
            for d in (support_docs or [])[:3]
        ).lower()
        support_hits = sum(1 for qt in query_terms if _token_match_light(support_blob, qt))
        if support_hits <= 0:
            return False

        noisy_items = 0
        for item in lines:
            il = item.lower()
            if re.search(r"\b(?:http|www\.|table|figure|copyright|isbn|location|recruit|hiring|vacanc(?:y|ies)|city|country)\b", il):
                noisy_items += 1
            if len(re.findall(r"[a-z]{2,}", il)) >= 5 and re.search(r"\b(?:is|are|was|were|have|has|had|will|can|should)\b", il):
                noisy_items += 1
        if noisy_items >= max(2, len(lines) // 2):
            return False
        avg_wc = sum(len(re.findall(r"[a-z]{2,}", it.lower())) for it in lines) / float(max(1, len(lines)))
        if len(lines) >= 3 and avg_wc <= 3.0:
            return True
        return True

    figure_table_answer = _extract_inline_numbered_figure_table_list(query_text, list(docs or []) + list(extra_docs or []))
    if figure_table_answer:
        shaped_figure_table = _sanitize_list_answer_text(query_text, figure_table_answer)
        if shaped_figure_table and _list_relevance_ok(shaped_figure_table, docs):
            S.logger.info("[LIST ROUTE] mode=inline_figure_table items=%d", len([ln for ln in shaped_figure_table.splitlines() if ln.strip()]))
            return shaped_figure_table

    counted_route_info = S._detect_short_symbolic_list_query(query_text)
    if counted_route_info and S._is_counted_category_list_query_info(counted_route_info):
        counted_pool: list[dict] = []
        counted_seen_keys: set[tuple[str, str]] = set()
        for d in list(docs or []) + list(extra_docs or []):
            md = dict((d or {}).get("metadata") or {})
            key = (str(md.get("source") or md.get("filename") or md.get("id") or ""), str(md.get("chunk_index") or ""))
            if key in counted_seen_keys:
                continue
            counted_seen_keys.add(key)
            counted_pool.append(d)
        counted_target = counted_route_info.get("count")
        for d in counted_pool[:12]:
            dtxt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
            if not dtxt.strip():
                continue
            counted_answer = S._extract_counted_list_labels_from_context(query_text, dtxt, counted_route_info)
            if not counted_answer:
                continue
            shaped_counted = _sanitize_list_answer_text(query_text, counted_answer)
            shaped_lines = [ln for ln in str(shaped_counted or "").splitlines() if re.match(r"^\s*[-•*]\s+", ln)]
            counted_ok = bool(
                shaped_counted
                and (not isinstance(counted_target, int) or len(shaped_lines) == counted_target)
                and _list_relevance_ok(shaped_counted, [d])
            )
            md = dict((d or {}).get("metadata") or {})
            S.logger.info(
                "[LIST CLEAN PIPELINE] clean_pass=%s route_counted_primary=%s items=%d target=%s chunk=%s",
                bool(counted_ok),
                bool(counted_ok),
                len(shaped_lines),
                counted_target,
                md.get("chunk_index"),
            )
            if counted_ok and shaped_counted:
                return shaped_counted

    selected_docs = S._select_list_context_docs(query_text, docs, max_docs=min(5, len(docs)), scan_limit=min(12, len(docs)))
    candidate_docs = selected_docs or docs

    # MP-C6: prefer chunks whose body contains a structural subsection heading
    # or figure/table caption whose title overlaps the discriminating query
    # tokens. This biases per-chunk extraction toward the chunk that actually
    # owns the matched subsection, instead of a structurally bullet-heavy but
    # off-topic neighbour. Generic — uses the same anchor scorer as slicing.
    candidate_docs = sorted(
        candidate_docs,
        key=lambda d: -_mpc6_anchor_score_for_text(
            str((d or {}).get("page_content") or (d or {}).get("text") or ""),
            query_text,
        ),
    )

    clean_count_target = _list_query_count_target(query_text)
    clean_primary_candidates: list[tuple[int, int, dict]] = []
    for idx, d in enumerate(candidate_docs[:8]):
        dtxt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not dtxt.strip():
            continue
        clean_labels = _extract_strict_clean_label_candidates(dtxt)
        clean_count = len(clean_labels)
        if clean_count < 5:
            continue
        if isinstance(clean_count_target, int) and clean_count < clean_count_target:
            continue
        clean_primary_candidates.append((clean_count, idx, d))

    if clean_primary_candidates:
        clean_primary_candidates.sort(
            key=lambda row: (
                1 if isinstance(clean_count_target, int) and row[0] == clean_count_target else 0,
                row[0],
                -row[1],
            ),
            reverse=True,
        )
        clean_count, _clean_idx, clean_doc = clean_primary_candidates[0]
        clean_meta = dict((clean_doc or {}).get("metadata") or {})
        clean_text = str((clean_doc or {}).get("page_content") or (clean_doc or {}).get("text") or (clean_doc or {}).get("content") or "")
        clean_answer = _extract_list_from_context(query_text, clean_text, max_candidate_blocks=2)
        clean_shaped = _sanitize_list_answer_text(query_text, str(clean_answer or ""))
        clean_ok = bool(clean_shaped and _list_relevance_ok(clean_shaped, [clean_doc]))
        S.logger.info(
            "[LIST CLEAN PIPELINE] clean_pass=%s primary_locked=%s clean_label_count=%s target=%s chunk=%s",
            bool(clean_ok),
            bool(clean_ok),
            clean_count,
            clean_count_target,
            clean_meta.get("chunk_index"),
        )
        if clean_ok and clean_shaped:
            return clean_shaped

    selected_context = "\n\n".join(
        str((d or {}).get("page_content") or (d or {}).get("text") or "")
        for d in candidate_docs
        if str((d or {}).get("page_content") or (d or {}).get("text") or "").strip()
    )

    if _is_structure_query(query_text):
        S.logger.info("[STRUCTURE QUERY DETECTED] query=%s", str(query_text or "")[:160])

        structure_sentence_answer = _extract_structure_concept_cluster_from_docs(query_text, candidate_docs, max_docs=8)
        if structure_sentence_answer and _list_relevance_ok(structure_sentence_answer, candidate_docs):
            S.logger.info("[STRUCTURE QUERY RESCUE] route_sentence_cluster=true")
            S.logger.info("[STRUCTURE ANSWER FINAL] source=route_sentence_cluster")
            return structure_sentence_answer

        def _clean_structure_label_candidate(raw_answer: str, source_text: str) -> str | None:
            shaped_answer = _sanitize_list_answer_text(query_text, str(raw_answer or ""))
            if not shaped_answer:
                return None
            source_has_structure_word = bool(_STRUCTURE_QUERY_RE.search(str(source_text or "")))
            if not source_has_structure_word:
                S.logger.info("[JUNK LABEL REJECTED] reason=no_explicit_structure_word_in_candidate")
                return None
            labels: list[str] = []
            norms: set[str] = set()
            source_low = str(source_text or "").lower()
            for line in str(shaped_answer or "").splitlines():
                item = re.sub(r"^\s*[-*•]\s+", "", line).strip(" .;:-")
                if not item:
                    continue
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
                if not (1 <= len(words) <= 5):
                    return None
                if re.search(r"\b(?:is|are|was|were|has|have|include|includes|refers|means|allows|helps|drives)\b", item, flags=re.IGNORECASE):
                    return None
                if re.search(r"[.!?]", item):
                    return None
                if len(words) == 1 and item[:1].islower() and re.match(r"^(?:the|and|or|to|of|for|in|on|with)[a-z]", item.lower()):
                    return None
                if len(words) == 1 and item.lower() in {"modern", "historical", "theoretical", "essential", "general", "basic", "important", "major", "main", "chapter", "section", "overview", "introduction", "summary", "contents"}:
                    S.logger.info("[JUNK LABEL REJECTED] reason=generic_single_word label=%s", item[:80])
                    return None
                item_norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
                if not item_norm or item_norm in norms:
                    continue
                item_terms = [w.lower() for w in words if len(w) >= 3]
                if item_terms and not any(re.search(rf"\b{re.escape(w)}\b", source_low) for w in item_terms):
                    return None
                norms.add(item_norm)
                labels.append(item[:1].upper() + item[1:])
            if len(labels) < 3:
                return None
            cluster_answer = "\n".join(f"- {label}" for label in labels[:12])
            S.logger.info("[CONCEPT CLUSTER DETECTED] count=%d", len(labels))
            S.logger.info("[STRUCTURE QUERY RESCUE] route_preferred_labels=true items=%d", len(labels))
            S.logger.info("[STRUCTURE ANSWER FINAL] source=route_preferred_labels items=%d", len(labels))
            return cluster_answer

        for d in candidate_docs[:8]:
            dtxt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
            if not dtxt.strip() or not _STRUCTURE_QUERY_RE.search(dtxt):
                continue
            for raw_candidate in (
                _extract_list_from_context(query_text, dtxt, max_candidate_blocks=3),
                _extract_simple_list_from_docs([d], query_text=query_text),
            ):
                structure_answer = _clean_structure_label_candidate(str(raw_candidate or ""), dtxt)
                if structure_answer and _list_relevance_ok(structure_answer, [d]):
                    return structure_answer

    # MP-C6: prefer per-chunk anchored extraction on any doc whose body has a
    # structural subsection / caption matching the query focus tokens. This
    # ensures the answer-bearing chunk's local subsection is extracted before
    # falling back to the broader simple-list extractor (which can mis-pick a
    # neighbour chunk's bullets that happen to be structurally cleaner).
    _mpc6_q_tok_count = len(_mpc6_query_focus_tokens(query_text))
    _mpc6_anchor_threshold = min(2, _mpc6_q_tok_count) if _mpc6_q_tok_count >= 1 else 0
    try:
        _cand_chunk_ids = [dict((d or {}).get("metadata") or {}).get("chunk_index") for d in candidate_docs[:8]]
        S.logger.info("[MP-C6 ANCHOR LOOP] threshold=%s candidate_docs=%s", _mpc6_anchor_threshold, _cand_chunk_ids)
    except Exception:
        pass
    for d in candidate_docs[:6]:
        dtxt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not dtxt.strip():
            continue
        _d_chunk = dict((d or {}).get("metadata") or {}).get("chunk_index")
        _d_score = _mpc6_anchor_score_for_text(dtxt, query_text)
        if _d_score < _mpc6_anchor_threshold:
            S.logger.info("[MP-C6 ANCHOR LOOP] chunk=%s score=%s SKIP_below_threshold", _d_chunk, _d_score)
            continue
        anchored_answer = _extract_list_from_context(query_text, dtxt, max_candidate_blocks=2)
        shaped = _sanitize_list_answer_text(query_text, str(anchored_answer or ""))
        _shaped_lines = len([ln for ln in str(shaped or "").splitlines() if ln.strip()]) if shaped else 0
        _rel_ok = bool(shaped and _list_relevance_ok(shaped, [d]))
        S.logger.info("[MP-C6 ANCHOR LOOP] chunk=%s score=%s anchored_lines=%s shaped_lines=%s relevance_ok=%s", _d_chunk, _d_score, len(str(anchored_answer or "").splitlines()), _shaped_lines, _rel_ok)
        if shaped and _rel_ok:
            return shaped

    answer = _extract_simple_list_from_docs(candidate_docs, query_text=query_text)
    if answer:
        shaped = _sanitize_list_answer_text(query_text, str(answer or ""))
        if shaped and _list_relevance_ok(shaped, candidate_docs):
            return shaped

    for d in candidate_docs[:5]:
        single_list = _extract_simple_list_from_docs([d], query_text=query_text)
        if not single_list:
            continue
        shaped = _sanitize_list_answer_text(query_text, str(single_list or ""))
        if shaped and _list_relevance_ok(shaped, [d]):
            return shaped

    # Fallback on each top local chunk before declaring no-match.
    for d in candidate_docs[:5]:
        dtxt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not dtxt.strip():
            continue
        single_ctx_answer = _extract_list_from_context(query_text, dtxt, max_candidate_blocks=2)
        shaped = _sanitize_list_answer_text(query_text, str(single_ctx_answer or ""))
        if shaped and _list_relevance_ok(shaped, [d]):
            return shaped

    if selected_context:
        ctx_answer = _extract_list_from_context(query_text, selected_context, max_candidate_blocks=4)
        shaped = _sanitize_list_answer_text(query_text, str(ctx_answer or ""))
        if shaped and _list_relevance_ok(shaped, candidate_docs):
            return shaped

    if context_text:
        ctx_answer = _extract_list_from_context(query_text, context_text, max_candidate_blocks=4)
        shaped = _sanitize_list_answer_text(query_text, str(ctx_answer or ""))
        if shaped and _list_relevance_ok(shaped, docs):
            return shaped

    # Final list fallback: explicitly retry top 3-5 docs before returning None.
    max_try = min(5, len(docs))
    for top_n in range(3, max_try + 1):
        local_docs = docs[:top_n]
        local_ctx = "\n\n".join(
            str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
            for d in local_docs
            if str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "").strip()
        )
        if not local_ctx:
            continue
        local_answer = _extract_list_from_context(query_text, local_ctx, max_candidate_blocks=6)
        shaped = _sanitize_list_answer_text(query_text, str(local_answer or ""))
        if shaped and _list_relevance_ok(shaped, local_docs):
            return shaped

    # Last fallback for category/area-type list queries: parse inline enumerations.
    if re.search(r"\b(?:area|areas|branch|branches|type|types|field|fields|category|categories|school|schools)\b", q_norm):
        parsed_items: list[str] = []
        for d in docs[:5]:
            dtxt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
            if not dtxt.strip():
                continue
            for sent in _split_text_into_sentences(dtxt)[:28]:
                s = re.sub(r"\s+", " ", str(sent or "").strip())
                if not s:
                    continue
                low = s.lower()
                if not re.search(r"\b(?:areas?|branches?|types?|fields?|categories|schools?)\b", low):
                    continue
                m = re.search(r"\b(?:include|includes|are|such\s+as)\b\s+(.+)$", s, flags=re.IGNORECASE)
                if not m:
                    continue
                tail = re.sub(r"[.;:!?]+\s*$", "", m.group(1) or "").strip()
                if not tail:
                    continue
                parts = [re.sub(r"\s+", " ", p).strip(" ,;:-") for p in re.split(r",|\band\b", tail, flags=re.IGNORECASE) if re.sub(r"\s+", " ", p).strip(" ,;:-")]
                for p in parts:
                    if len(re.findall(r"[A-Za-z][A-Za-z\-']*", p)) < 1:
                        continue
                    if len(re.findall(r"[A-Za-z][A-Za-z\-']*", p)) > 6:
                        continue
                    parsed_items.append(p)
            if len(parsed_items) >= 3:
                break

        if parsed_items:
            shaped = _sanitize_list_answer_text(query_text, "\n".join(f"- {x}" for x in parsed_items))
            if shaped and _list_relevance_ok(shaped, docs[:5]):
                return shaped

    return None

def _expand_single_token_who_answer_from_docs(query_text: str, answer_text: str, docs: list[dict]) -> str:
    answer = re.sub(r"\s+", " ", str(answer_text or "")).strip(" .,:;!?")
    if _detect_fact_query_type(query_text) != "who" or len(answer.split()) != 1:
        return answer

    answer_key = _person_token_key(answer)
    if not answer_key:
        return answer

    subject_terms = _extract_relation_subject_terms(query_text, "who")
    role_noun_pat = r"(?:found(?:er|ers)|co-?found(?:er|ers)|creator|originator|establisher|developer|inventor|discoverer|pioneer|architect)"
    relation_cue_re = re.compile(
        rf"\b(?:established|proposed|developed|founded|introduced|created|coined|formed|started|originated|emerged)\b|"
        rf"\b{role_noun_pat}\s+of\b|\bfather\s+of\b",
        flags=re.IGNORECASE,
    )
    person_token_pattern = r"(?:[A-Z][a-z]+|[A-Z]\.)"
    span_re = re.compile(rf"\b({person_token_pattern}(?:\s+{person_token_pattern}){{1,4}})\b")

    def _subject_near(text_value: str) -> bool:
        low = text_value.lower()
        return not subject_terms or any(re.search(rf"\b{re.escape(t)}\b", low) for t in subject_terms)

    def _normalize_span(raw: str) -> str:
        tokens = [t for t in re.findall(person_token_pattern, raw) if _person_token_key(t)]
        tokens = _strip_person_descriptor_tokens(tokens)
        if len(tokens) > 3:
            tokens = tokens[:3]
        out = []
        for tok in tokens:
            key = _person_token_key(tok)
            out.append(f"{key.upper()}." if len(key) == 1 else key.capitalize())
        return " ".join(out)

    best = answer
    best_width = 1
    for doc in docs or []:
        text = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or (doc or {}).get("text_preview") or "")
        text = re.sub(r"\s+", " ", text).strip()
        if not text:
            continue
        for m in span_re.finditer(text):
            raw_tokens = re.findall(person_token_pattern, m.group(1) or "")
            same_surname_index = next(
                (idx for idx, tok in enumerate(raw_tokens) if _person_token_key(tok) == answer_key and idx > 0),
                None,
            )
            if same_surname_index is None:
                continue
            near = text[max(0, m.start() - 240): min(len(text), m.end() + 240)]
            if not (_subject_near(near) and relation_cue_re.search(near)):
                continue
            candidate = _normalize_span(" ".join(raw_tokens[max(0, same_surname_index - 3): same_surname_index + 1]))
            width = len(candidate.split())
            if width > best_width:
                best = candidate
                best_width = width
    if best != answer:
        S.logger.info("[FACT PERSON VALIDATOR] action=expand_route_single_token raw=%s expanded=%s", answer, best)
    return best

def _extract_fact_route_answer(query_text: str, docs: list[dict]) -> str | None:
    docs = list(docs or [])
    if not docs:
        return None

    if _is_attribute_lookup_query(query_text):
        cell_answer = _extract_table_cell_answer(query_text, docs)
        if cell_answer:
            return cell_answer

    if _is_numeric_fact_lookup_query(query_text):
        table_answer = _extract_table_fact_answer(query_text, docs)
        if table_answer:
            return table_answer

    fact_type = _detect_fact_query_type(query_text)
    compact_docs = _build_compact_fact_context_docs(query_text, docs, max_snippets=FACT_CONTEXT_MAX_SNIPPETS, max_chars=FACT_CONTEXT_MAX_CHARS)
    context_chunks = [
        str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        for d in (compact_docs or docs)
        if str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "").strip()
    ]
    if not context_chunks:
        return None

    candidate = _extract_fact_from_context(query_text, context_chunks)
    normalized = _normalize_validated_fact_answer(fact_type, candidate or "")
    if normalized == RAG_NO_MATCH_RESPONSE and fact_type in {"who", "who_when"}:
        name_year_re = re.compile(
            r"\b(?P<name>[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\b.*?\b(?P<year>(?:1[5-9]\d{2}|20\d{2}))\b",
            flags=re.IGNORECASE,
        )
        for chunk in context_chunks:
            for sent in re.split(r"(?<=[.!?])\s+|\n+", chunk):
                low = sent.lower().strip()
                if not low:
                    continue
                if not re.search(r"\b(?:founded|established|developed|introduced|created|coined|proposed|started)\b", low):
                    continue
                m = name_year_re.search(sent)
                if m:
                    name = _normalize_validated_fact_answer("who", re.sub(r"\s+", " ", m.group("name") or "").strip())
                    year = m.group("year") or ""
                    if fact_type == "who_when" and name != RAG_NO_MATCH_RESPONSE and year:
                        normalized = f"{name}, {year}"
                        break
                    if fact_type == "who" and name != RAG_NO_MATCH_RESPONSE:
                        normalized = name
                        break
            if normalized != RAG_NO_MATCH_RESPONSE:
                break
    if normalized == RAG_NO_MATCH_RESPONSE:
        return None
    normalized = _expand_single_token_who_answer_from_docs(query_text, normalized, docs)
    if not _is_answer_grounded_in_docs(normalized, docs, query_text=query_text):
        return None
    return normalized

def _build_grounded_llm_answer(query_text: str, docs: list[dict]) -> str | None:
    docs = list(docs or [])
    if not docs:
        return None

    context = _build_generation_context(query_text, docs, max_chars=3600)
    if not context:
        return None

    candidate = _compose_grounded_generation_answer(query_text, context)
    if not candidate:
        return None
    candidate = S._format_generation_answer_by_query(query_text, _cleanup_final_answer_text(candidate))
    if not _is_answer_grounded_in_docs(candidate, docs, query_text=query_text):
        return None
    return candidate

def extract_keywords(query: str) -> list[str]:
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if not q:
        return []

    stop = {
        "what", "is", "are", "the", "a", "an", "of", "in", "to", "for", "and", "or", "with", "on", "at",
        "summary", "difference", "between", "simple", "simply",
        "sentence", "sentences", "document", "about", "tell", "please", "can", "you", "me", "this", "that",
        "make", "it", "as", "into", "from",
    }

    tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", q)
        if t not in stop and not t.isdigit()
    ]
    seen = set()
    dedup = []
    for t in tokens:
        if t in seen:
            continue
        seen.add(t)
        dedup.append(t)
    return dedup

def count_token_matches(tokens: list[str], context: str) -> int:
    if not tokens or not context:
        return 0
    text = str(context or "").lower()
    total = 0
    for t in tokens:
        total += min(3, len(re.findall(rf"\b{re.escape(t)}\b", text)))
    return total

def _has_sufficient_context(query: str, context: str, relevant_chunks: int = 0) -> bool:
    if S._doc_router_cross_corpus_bridge(query) and int(relevant_chunks or 0) >= 1:
        return True
    if S._classify_response_format_intent(query) != "default" and int(relevant_chunks or 0) >= 1:
        return True
    if _classify_query_family_v2(query) == "document_summary":
        return int(relevant_chunks or 0) >= 1 and len(str(context or "").strip()) >= 80

    if int(relevant_chunks or 0) < 2:
        return False

    tokens = extract_keywords(query)
    hits = count_token_matches(tokens, context)
    if hits < 2:
        return False

    context_l = str(context or "").lower()
    topic_tokens = [t for t in tokens if len(t) >= 5] or tokens
    topic_present = any(re.search(rf"\b{re.escape(t)}\b", context_l) for t in topic_tokens)
    return bool(topic_present)

def _build_generation_context(query_text: str, docs: list[dict], max_chars: int = 3600) -> str:
    if not docs:
        return ""

    for d in docs or []:
        raw_chunk = str((d or {}).get("page_content") or (d or {}).get("text") or "").strip()
        if raw_chunk and len(re.findall(r"(?i)(?:^|\s)Q:\s", raw_chunk)) >= 1:
            faq_answer = _extract_best_faq_answer(query_text, raw_chunk)
            if faq_answer:
                out = faq_answer if len(faq_answer) <= max_chars else (faq_answer[:max_chars].rstrip(" ,;:-") + ".")
                return out.strip()

    tokens = extract_keywords(query_text)
    left_term, right_term = _compare_terms_from_query(query_text)
    compare_mode = bool(left_term and right_term)

    candidates: list[tuple[float, str]] = []
    for rank, d in enumerate(docs or []):
        raw_chunk = str((d or {}).get("page_content") or (d or {}).get("text") or "").strip()
        if not raw_chunk:
            continue
        # Strip ==== / ---- separators and title lines but keep Q:/A: labels so we can
        # skip Q: question-echo lines and give A: answer lines a scoring bonus below.
        raw = _strip_doc_structure_separators(raw_chunk)
        doc_score = float((d or {}).get("score", 0.0) or 0.0)
        sents = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", raw) if s.strip()]
        for sent in sents:
            low = sent.lower()
            if len(re.findall(r"[a-z0-9]+", low)) < 6:
                continue
            if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", sent):
                continue
            # Skip Q&A question lines — they echo the question, not the answer
            if re.match(r"^\s*Q:\s", sent):
                continue

            token_hits = count_token_matches(tokens, low)
            if token_hits <= 0:
                continue

            # Prefer A: answer lines over bare sentences — they directly answer a question
            answer_line_bonus = 1.5 if re.match(r"^\s*A:\s", sent) else 0.0
            explain_signal = 1.0 if re.search(r"\b(is|refers\s+to|defined\s+as|means|includes|involves|focuses\s+on)\b", low) else 0.0
            compare_signal = 0.0
            if compare_mode:
                if left_term and re.search(rf"\b{re.escape(left_term.lower())}\b", low):
                    compare_signal += 0.8
                if right_term and re.search(rf"\b{re.escape(right_term.lower())}\b", low):
                    compare_signal += 0.8

            table_penalty = 0.35 if _looks_table_or_heading_like_chunk(sent[:220]) else 0.0
            score = (2.2 * float(token_hits)) + answer_line_bonus + explain_signal + compare_signal + (0.25 * doc_score) - (0.02 * rank) - table_penalty
            candidates.append((score, sent))

    if candidates:
        candidates.sort(key=lambda x: x[0], reverse=True)
        chosen: list[str] = []
        seen = set()
        total = 0
        for _, sent in candidates:
            # Strip any remaining Q:/A: labels from chosen sentences
            sent = re.sub(r"^\s*[AQ]:\s+", "", sent)
            key = re.sub(r"\s+", " ", sent.strip().lower())
            if key in seen:
                continue
            seen.add(key)
            remain = max_chars - total
            if remain <= 0:
                break
            out = sent if len(sent) <= remain else (sent[:remain].rstrip(" ,;:-") + ".")
            chosen.append(out)
            total += len(out) + 1
            if len(chosen) >= 18:
                break
        if chosen:
            return "\n".join(chosen).strip()

    fallback = "\n\n".join(
        _strip_doc_structure_separators(str((d or {}).get("page_content") or (d or {}).get("text") or "").strip())
        for d in (docs or [])
        if str((d or {}).get("page_content") or (d or {}).get("text") or "").strip()
    ).strip()
    if len(fallback) > max_chars:
        fallback = fallback[:max_chars].rstrip(" ,;:-") + "."
    return fallback

def _compose_grounded_generation_answer(query_text: str, context: str) -> str | None:
    q = str(query_text or "").strip()
    ctx = str(context or "").strip()
    if not q or not ctx:
        return None

    faq_markers = len(re.findall(r"(?i)(?:^|\s)Q:\s", ctx))
    if faq_markers >= 2:
        faq_answer = _extract_best_faq_answer(q, ctx)
        if faq_answer:
            return faq_answer

    tokens = extract_keywords(q)
    sents = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", ctx) if s.strip()]
    scored: list[tuple[float, str]] = []
    for i, s in enumerate(sents):
        # Skip Q&A question lines — they echo the question, not the answer
        if re.match(r"^\s*Q:\s", s):
            continue
        low = s.lower()
        if len(re.findall(r"[a-z0-9]+", low)) < 6:
            continue
        hits = count_token_matches(tokens, low)
        if hits <= 0:
            continue
        # Prefer A: answer lines
        answer_line_bonus = 1.5 if re.match(r"^\s*A:\s", s) else 0.0
        explanatory = 1.0 if re.search(r"\b(is|refers\s+to|defined\s+as|means|includes|involves|association)\b", low) else 0.0
        score = (2.0 * float(hits)) + answer_line_bonus + explanatory - (0.01 * i)
        scored.append((score, s))

    if not scored:
        return None

    scored.sort(key=lambda x: x[0], reverse=True)
    compare_mode = _is_compare_query(q)
    summarize_mode = bool(re.search(r"\b(summarize|summary)\b", q.lower()))

    if compare_mode:
        left, right = _compare_terms_from_query(q)
        if left and right:
            left_sent = next((s for _, s in scored if re.search(rf"\b{re.escape(left.lower())}\b", s.lower())), None)
            right_sent = next((s for _, s in scored if re.search(rf"\b{re.escape(right.lower())}\b", s.lower())), None)
            if left_sent and right_sent:
                return f"- {left.title()}: {left_sent}\n- {right.title()}: {right_sent}"

    def _strip_qa_label(s: str) -> str:
        return re.sub(r"^\s*[AQ]:\s+", "", s).strip()

    if summarize_mode:
        chosen = [_strip_qa_label(s) for _, s in scored[:3]]
        if chosen:
            return " ".join(chosen)

    chosen = [_strip_qa_label(s) for _, s in scored[:2]]
    if chosen:
        return " ".join(chosen)
    return None

async def call_llm_with_context(query: str, context: str, system_prompt: str) -> str:
    global llm_session
    query_text = str(query or "").strip()
    context_text = str(context or "").strip()
    if not query_text or not context_text:
        return RAG_NO_MATCH_RESPONSE

    user_msg = (
        f"Question: {query_text}\n\n"
        f"Context:\n{context_text}"
    )
    payload = {
        "model": OLLAMA_MODEL,
        "messages": [
            {"role": "system", "content": str(system_prompt or "").strip()},
            {"role": "user", "content": user_msg},
        ],
        "stream": False,
        "keep_alive": -1,
        "options": {
            "num_ctx": 3072,
            "num_gpu": 99,
            "temperature": 0.1,
            "top_p": 0.9,
            "num_predict": 220,
        },
    }

    local_session_created = False
    _sess = S.llm_session
    if _sess is None or getattr(_sess, "closed", False):
        try:
            _sess = aiohttp.ClientSession()
            local_session_created = True
        except Exception:
            return RAG_NO_MATCH_RESPONSE

    try:
        timeout = aiohttp.ClientTimeout(total=60, connect=5, sock_read=45)
        query_type = "generation" if S._is_llm_generation_query(query_text) else "grounded_context"
        S.logger.info("[OLLAMA CALL] endpoint=%s model=%s query_type=%s", LLM_URL, OLLAMA_MODEL, query_type)
        async with _sess.post(LLM_URL, json=payload, timeout=timeout) as response:
            S.logger.info("[OLLAMA CALL RESULT] status=%s endpoint=%s", response.status, LLM_URL)
            if response.status != 200:
                return RAG_NO_MATCH_RESPONSE
            data = await response.json()
            answer = str((data.get("message") or {}).get("content") or "").strip()
            if not answer:
                return RAG_NO_MATCH_RESPONSE
            return answer
    except Exception:
        return RAG_NO_MATCH_RESPONSE
    finally:
        if local_session_created and _sess and not _sess.closed:
            try:
                await _sess.close()
            except Exception:
                pass

def _split_text_into_sentences(text: str) -> list[str]:
    src = str(text or "")
    if not src.strip():
        return []

    protected = src
    protected = re.sub(r"(?<![\.!?؛;:])\s*\n+\s*", " ", protected)
    # Iteratively protect chains of single-letter initials so that names like
    # "F. W. Taylor" or "U. S. A." are not split into spurious sentence
    # fragments. Without iteration, an inner pass can replace the trailing
    # initial first, leaving the leading ones unprotected. Generic fix —
    # depends only on capitalisation/punctuation shape.
    for _ in range(4):
        _prev_protected = protected
        protected = re.sub(r"\b([A-Z])\.\s+([A-Z][a-z])", r"\1<INIT_DOT> \2", protected)
        protected = re.sub(r"\b([A-Z])\.\s+([A-Z])\s+([A-Z][a-z])", r"\1<INIT_DOT> \2<INIT_DOT> \3", protected)
        protected = re.sub(r"\b([A-Z])\.\s+([A-Z])\.", r"\1<INIT_DOT> \2<INIT_DOT>", protected)
        protected = re.sub(r"\b([A-Z])\.\s+([A-Z])<INIT_DOT>", r"\1<INIT_DOT> \2<INIT_DOT>", protected)
        if protected == _prev_protected:
            break
    protected = re.sub(
        r"\b(?:Mr|Mrs|Ms|Dr|Prof|Sr|Jr|St|vs|etc|e\.g|i\.e|No)\.\s+",
        lambda m: m.group(0).replace(".", "<ABBR_DOT>"),
        protected,
        flags=re.IGNORECASE,
    )

    pieces = [
        s.strip()
        for s in re.split(r"(?<=[\.!?؛;:])\s+|\n+", protected)
        if s and s.strip()
    ]
    out: list[str] = []
    for p in pieces:
        restored = p.replace("<INIT_DOT>", ".").replace("<ABBR_DOT>", ".")
        restored = re.sub(r"\s+", " ", restored).strip()
        if restored:
            out.append(restored)
    return out

def is_entity_definition_like(text: str, entity: str) -> bool:
    t = (text or "").lower()
    e = (entity or "").lower().strip()
    if not e:
        S.logger.info("[STRICT DEF PREF MISS] entity=%s reason=empty_entity", entity)
        return False

    if e not in t:
        S.logger.info("[STRICT DEF PREF MISS] entity=%s reason=no_entity_hit", entity)
        return False

    entity_tokens = [tok for tok in re.findall(r"[a-z0-9]+", e) if len(tok) > 2]
    if not entity_tokens:
        S.logger.info("[STRICT DEF PREF MISS] entity=%s reason=no_entity_tokens", entity)
        return False

    sentence_candidates = _split_text_into_sentences(t)

    escaped_entity = re.escape(e)
    entity_anywhere_re = re.compile(rf"\b(?:the\s+)?{escaped_entity}\b", re.IGNORECASE)
    definition_pattern_re = re.compile(
        r"\b(?:is|refers\s+to|defined\s+as|can\s+be\s+defined\s+as|means|grew\s+out\s+of)\b",
        re.IGNORECASE,
    )

    for sentence in sentence_candidates:
        has_entity_anywhere = bool(entity_anywhere_re.search(sentence))
        has_definition_pattern = bool(definition_pattern_re.search(sentence))
        sentence_low = sentence.lower()
        if has_entity_anywhere and has_definition_pattern:
            if defines_other_concept(sentence_low, e):
                S.logger.info("[DEF REJECT WEAK] entity=%s reason=defines_other_concept sentence=%s", entity, sentence[:160])
                continue
            if re.match(r"^\s*(he|she|they|it|this)\b", sentence_low):
                S.logger.info("[DEF REJECT WEAK] entity=%s reason=pronoun_led sentence=%s", entity, sentence[:160])
                continue
            if re.search(r"\b(known\s+as\s+the\s+born|biography|worked\s+as)\b", sentence_low):
                S.logger.info("[DEF REJECT WEAK] entity=%s reason=biography_style sentence=%s", entity, sentence[:160])
                continue
            S.logger.info("[STRICT DEF PREF PASS] entity=%s sentence=%s", entity, sentence[:160])
            return True

    S.logger.info("[STRICT DEF PREF MISS] entity=%s reason=no_strict_definition_sentence", entity)
    return False

def _is_definition_boilerplate_sentence(sentence: str) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
    if not s:
        return True
    if re.search(r"^\s*(?:chapter\s+\d+|unit\s+\d+|table\s+of\s+contents|contents?|summary|introduction|learning\s+objectives?)\b", s):
        return True
    if re.search(r"\b(?:course\s+will|students\s+will|this\s+chapter\s+will|in\s+this\s+chapter)\b", s):
        return True
    if re.match(r"^\s*(?:what|why|how|when|where|who)\b", s) and s.endswith("?"):
        return True
    if re.search(r"\b(?:table|figure|isbn|www\.|https?://)\b", s):
        return True
    if re.search(r"\b(?:one\s+of\s+the\s+components?|listed\s+with|associating\s+model|the\s+answers\s+to\s+all\s+these\s+questions\s+can\s+be\s+found)\b", s):
        return True
    return False

def _clean_definition_like_sentence(sentence: str) -> str:
    s = re.sub(r"\s+", " ", str(sentence or "").strip())
    if not s:
        return ""
    s = re.sub(r"^\s*(?:DEFINITION|definition)\s*[\-:\"'“”‘’\s]*", "", s, flags=re.IGNORECASE)
    s = s.replace("â€¢", " ").replace("•", " ")
    s = re.sub(r"\b(?:earlier\s+schools?\s+of\s+thought|schools?\s+of\s+thought)\b", "", s, flags=re.IGNORECASE)
    s = re.sub(r"\s*(?:©\s*Copyright|Copyright)\b.*$", "", s, flags=re.IGNORECASE)
    s = re.sub(r"\bprovides\s+answers\s+to\s+all\s+these\s+questions\b", "", s, flags=re.IGNORECASE)
    s = re.sub(r"\s*,?\s*and\s+(?:i|ii|iii|iv|v)\.?\s*$", "", s, flags=re.IGNORECASE)
    s = re.sub(r"\s*[-•]\s*$", "", s)
    s = re.sub(r"\b([A-Za-z][A-Za-z0-9\-]*)[\"“”]\s+(?=(?:is|are|was|were|means|refers)\b)", r"\1 ", s)
    s = re.sub(r"\s+", " ", s).strip()
    return s.strip(" \t\n\r\"'`.,;:!?()[]{}")

def _is_explanation_sentence_for_entity(sentence: str, entity: str, chunk_is_topic: bool = False) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "").strip())
    if not s:
        return False
    s_low = s.lower()
    words = re.findall(r"[a-z0-9]+", s_low)
    if len(words) < 6:
        return False
    if len(words) > 42:
        return False

    if _is_definition_boilerplate_sentence(s):
        S.logger.info("[DEF REJECT BOILERPLATE] entity=%s sentence=%s", entity, s[:180])
        return False

    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    has_entity = bool(e and re.search(rf"\b{re.escape(e)}\b", s_low))
    entity_tokens = [t for t in re.findall(r"[a-z0-9]+", e) if t not in {"the", "a", "an", "of", "and", "in", "to", "for"}]
    token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", s_low))

    if not (has_entity or token_hits >= max(1, min(2, len(entity_tokens)))):
        if not (chunk_is_topic and token_hits >= 1):
            return False

    if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", s, flags=re.IGNORECASE):
        return False

    if re.search(r"\b(?:one\s+of\s+the\s+components?|listed\s+with|associating\s+model|the\s+answers\s+to\s+all\s+these\s+questions\s+can\s+be\s+found)\b", s_low):
        S.logger.info("[DEF REJECT BOILERPLATE] entity=%s sentence=%s", entity, s[:180])
        return False

    if e and defines_other_concept(s_low, e):
        S.logger.info("[DEF REJECT OTHER_CONCEPT] entity=%s sentence=%s", entity, s[:180])
        return False

    if re.search(r"\b(?:is|refers\s+to|defined\s+as|means|includes|involves|consists\s+of|focuses\s+on|emphasizes|concerned\s+with|characterized\s+by|forms\s+an\s+association|associates)\b", s_low):
        S.logger.info("[DEF ACCEPT EXPLANATION] entity=%s sentence=%s", entity, s[:180])
        return True

    return False

def _doc_has_explanation_for_entity(chunk_text: str, entity: str) -> bool:
    sentences = _split_text_into_sentences(chunk_text)
    chunk_topic = _chunk_entity_dominant_topic(chunk_text, entity)
    for sent in sentences[:10]:
        if _is_explanation_sentence_for_entity(sent, entity, chunk_is_topic=chunk_topic):
            return True
    return False

def _dedup_docs_exact_text(docs: list[dict]) -> list[dict]:
    out: list[dict] = []
    seen: set[str] = set()
    for d in (docs or []):
        txt = re.sub(r"\s+", " ", str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")).strip().lower()
        if not txt or txt in seen:
            continue
        seen.add(txt)
        out.append(d)
    return out

def _is_ws_definition_query_mode(query: str) -> bool:
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if not q:
        return False
    return bool(
        re.match(r"^\s*what\s+is\s+.+", q)
        or re.match(r"^\s*define\s+.+", q)
        or re.search(r"\bmeaning\s+of\b", q)
        or re.match(r"^\s*what\s+does\s+.+\s+mean\s*\??\s*$", q)
    )

def _is_ws_explain_query_mode(query: str) -> bool:
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if not q:
        return False
    return bool(
        re.match(r"^\s*(?:explain|describe|clarify)\b\s+.+", q)
        or re.match(r"^\s*tell\s+me\s+(?:about|more\s+about)\s+.+", q)
        or re.match(r"^\s*how\s+does\s+.+\s+work\s*\??\s*$", q)
        or re.match(r"^\s*why\s+.+\??\s*$", q)
    )

