def _explanation_doc_text(doc: dict) -> str:
    if not isinstance(doc, dict):
        return ""
    return str(
        doc.get("page_content")
        or doc.get("text")
        or doc.get("content")
        or ""
    )

def _explanation_doc_metadata_text(doc: dict) -> str:
    if not isinstance(doc, dict):
        return ""
    metadata = dict(doc.get("metadata") or {})
    return " ".join(
        str(metadata.get(key) or "")
        for key in ("source", "filename", "title", "chapter", "section", "heading", "page")
    )

def _explanation_content_tokens(value: str, keep_short: bool = False) -> list[str]:
    raw_tokens = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", str(value or "").lower())
    tokens: list[str] = []
    for token in raw_tokens:
        token = token.strip("'-")
        if not token or token in _EXPLANATION_QUERY_STOP:
            continue
        if len(token) >= 3 or (keep_short and len(token) >= 2):
            tokens.append(token)
    return tokens

def _normalize_support_query_surface(query: str) -> str:
    """Strip conversational/STT prefixes so support procedural detection still matches."""
    q = re.sub(r"\s+", " ", str(query or "").strip())
    q = re.sub(r"^(?:so|okay|ok|well|um|uh)[,.\s]+", "", q, flags=re.IGNORECASE)
    q = re.sub(
        r"^(?:please\s+)?(?:(?:can|could)\s+you\s+)?(?:tell\s+me|explain\s+to\s+me)\s+",
        "",
        q,
        flags=re.IGNORECASE,
    )
    return q.strip(" ?.!,;:")

def _is_support_procedural_query(query: str) -> bool:
    """Support-KB style questions (returns, password, shipping) — not relationship essays."""
    q = _normalize_support_query_surface(query).lower()
    if not q:
        return False
    patterns = (
        r"^\s*how\s+(?:do|can|to)\s+i\s+",
        r"^\s*(?:how\s+to|how\s+do\s+i|how\s+can\s+i)\s+",
        r"^\s*(?:tell\s+me\s+)?how\s+(?:do|can|to)\s+i\s+",
        r"^\s*(?:tell\s+me\s+)?how\s+to\s+",
        r"^\s*how\s+(?:many|long|much)\b",
        r"^\s*when\s+(?:is|are|will)\b",
        r"^\s*when\s+do\s+i\s+(?:receive|get)\b",
        r"^\s*what\s+payment\b",
        # Tightened: only treat "what are your/the ..." as a support FAQ when
        # it targets a support-domain topic, so document essay questions like
        # "what are the steps in the planning process?" are NOT misrouted.
        r"^\s*what\s+are\s+(?:your|the)\s+(?:return|refund|exchange|shipping|"
        r"delivery|payment|support|business|opening|store|warrant|"
        r"cancellation|contact)\b",
        r"support\s+hours\b",
        r".\breset\b.*\bpassword\b",
        r".\bpassword\b.*\breset\b",
        # ---- Common support-FAQ intents (e-commerce style) ----
        # These are support questions that were previously blocked by the
        # generic/low-confidence guard even though the matching support
        # chunk was retrieved. The answer-permission gate still requires a
        # retrieved doc, so off-topic queries remain gated downstream.
        r"\breturn\b.*\bpolic",
        r"\brefund\b",
        r"\bexchange\b",
        r"\bwarrant(?:y|ies)\b",
        r"\bguarantee\b",
        r"\bcancel(?:lation|led|ling)?\b",
        r"\b(?:forgot|lost|recover|change|update)\b.*\bpassword\b",
        r"\bpassword\b.*\b(?:forgot|lost|recover|change|update)\b",
        r"\btrack(?:ing)?\b",
        r"\bwhere\s+is\s+my\b",
        r"\b(?:ship|shipping|shipped|deliver|delivery)\b",
        r"\bpayment\b",
        r"\b(?:create|delete|update|make)\b.*\baccount\b",
        r"\bcontact\b.*\b(?:hours|support|us)\b",
        r"\btransfer\b.*\bownership\b",
        r"\bownership\b.*\btransfer\b",
        r"\badd\b.*\bteammate\b",
        r"\binvite\b.*\b(?:teammate|member|user)\b",
        r"\bsso\b",
        r"^\s*can\s+i\s+",
        # ---- Support scenario / outcome questions (banking support) ----
        # "What happens if I report fraud?", "I lost my card. What should I do?",
        # "My account was hacked." — these are support-handling questions whose
        # answer is in the KB; without this they fall to the explanatory family
        # and get blocked by the low-confidence-generic guard.
        r"^\s*what\s+happens\s+(?:if|when|after)\b",
        r"\bwhat\s+should\s+i\s+do\b",
        r"\b(?:report|reporting|reported)\b.*\bfraud\b",
        r"\bfraud\b",
        r"\bdispute\b",
        r"\b(?:lost|stolen|missing|hacked|compromised)\b.*\b(?:card|account)\b",
        r"\b(?:card|account)\b.*\b(?:lost|stolen|missing|hacked|compromised)\b",
        r"\bunauthorized\b",
        # ---- Operational / policy FAQ (cloud billing, onboarding, compliance) ----
        r"\bdo\s+i\s+pay\b",
        r"\bhow\s+is\b.*\bbilled\b",
        r"\bhow\s+quickly\b",
        r"\bhow\s+long\s+does\b.*\btake\b",
        r"\bhow\s+does\b.*\bwork\b",
        r"\bare\b.*\bavailable\b",
        r"\bwhat\s+refund\b",
        r"\brefund\s+options\b",
        r"\bprepaid\b",
        r"\bcredits?\b.*\bvalid\b",
        r"\begress\b",
        r"\bingress\b",
        r"\bonboarding\b",
        r"\blaunch\b.*\bvm\b",
        r"\bsetup\s+take\b",
        r"\bcompliance\s+setup\b",
        r"\busage\s+discount\b",
        r"\bwho\s+is\s+the\s+account\s+owner\b",
        r"\bhow\s+long\b.*\binvitation\b.*\bvalid\b",
        r"\binvitation\b.*\bvalid\b",
        # Transfer / payment option questions (same-day send, fees, limits)
        r"\b(?:send|transfer|wire)\b.*\b(?:today|cost|fee|option|bank)\b",
        r"\breplace\b.*\bcard\b",
        r"\b(?:requirements|eligibility)\b",
        r"\b(?:basic|personal)\b.*\b(?:requirements|account)\b",
    )
    return any(re.search(p, q) for p in patterns)

_FAQ_PROCEDURAL_SHELL = frozenset({
    "how", "do", "can", "what", "where", "when", "why", "who",
    "i", "my", "me", "the", "you", "your", "a", "an", "is", "are", "to", "of", "for",
})

def _faq_content_tokens(text: str) -> list[str]:
    norm = re.sub(r"\s+", " ", str(text or "").strip().lower())
    return [t for t in extract_keywords(norm) if t not in _FAQ_PROCEDURAL_SHELL]

_FAQ_PAIR_BLOCK_RE = re.compile(
    r"(?:^|\s)Q:\s*(.*?)\s*A:\s*(.*?)(?=(?:\sQ:\s)|$)",
    re.IGNORECASE | re.DOTALL,
)

def _parse_faq_pairs(text: str) -> list[tuple[str, str]]:
    """Parse structural Q:/A: pairs from a chunk (inline or multiline)."""
    src = str(text or "").strip()
    if not src:
        return []
    pairs: list[tuple[str, str]] = []
    for match in _FAQ_PAIR_BLOCK_RE.finditer(src):
        question = re.sub(r"\s+", " ", match.group(1) or "").strip(" .?!,;:")
        answer = re.sub(r"\s+", " ", match.group(2) or "").strip(" .?!,;:")
        if question and answer and len(answer) >= 8:
            pairs.append((question, answer))
    if pairs:
        return pairs
    # Multiline fallback: Q: on its own line
    blocks = re.split(r"(?im)(?:^|\n)\s*Q:\s*", src)
    for block in blocks:
        block = block.strip()
        if not block:
            continue
        parts = re.split(r"(?im)\s*A:\s*", block, maxsplit=1)
        if len(parts) != 2:
            continue
        question = re.sub(r"\s+", " ", parts[0]).strip(" .?!,;:")
        answer = re.sub(r"\s+", " ", parts[1]).strip(" .?!,;:")
        answer = re.split(r"(?im)(?:^|\n)\s*Q:\s*", answer, maxsplit=1)[0].strip(" .?!,;:")
        if question and answer and len(answer) >= 8:
            pairs.append((question, answer))
    return pairs

def _score_faq_pair(query: str, question: str, answer: str) -> float:
    q_norm = re.sub(r"\s+", " ", str(query or "").strip().lower())
    question_norm = re.sub(r"\s+", " ", str(question or "").strip().lower())
    answer_norm = re.sub(r"\s+", " ", str(answer or "").strip().lower())
    if not q_norm or not question_norm or not answer_norm:
        return -1000.0
    content_query = _faq_content_tokens(q_norm)
    content_overlap = count_token_matches(content_query, question_norm) if content_query else 0
    _faq_topic_groups = (
        frozenset({"policy", "options", "available", "terms", "conditions"}),
        frozenset({"refund", "return", "cancellation", "cancel", "exchange"}),
    )
    for group in _faq_topic_groups:
        q_in = any(tok in group for tok in content_query)
        faq_in = any(tok in group for tok in _faq_content_tokens(question_norm))
        if q_in and faq_in:
            shared = sum(1 for tok in content_query if tok in group)
            content_overlap += max(1, shared)
    if content_query and content_overlap <= 0:
        return -1000.0
    if len(content_query) >= 2 and content_overlap < 2:
        if (content_overlap / float(len(content_query))) < 0.5:
            return -1000.0
    query_tokens = extract_keywords(q_norm)
    question_tokens = extract_keywords(question_norm)
    question_overlap = count_token_matches(query_tokens, question_norm)
    if question_overlap <= 0 and content_overlap <= 0:
        return -1000.0
    overlap = max(question_overlap, content_overlap)
    overlap += 0.35 * count_token_matches(query_tokens, answer_norm)
    overlap += 0.25 * count_token_matches(question_tokens, q_norm)
    overlap += 1.5 * float(content_overlap)
    q_words = q_norm.split()
    for idx in range(len(q_words) - 1):
        bigram = f"{q_words[idx]} {q_words[idx + 1]}"
        if bigram in question_norm:
            overlap += 1.5
    procedural_bonus = 0.0
    if content_query and content_overlap >= 2:
        procedural_bonus += 0.4
    score = (3.0 * float(max(question_overlap, content_overlap))) + float(overlap) + procedural_bonus
    if len(answer_norm) < 20:
        score -= 0.5
    return score

def _extract_best_faq_answer(query: str, text: str) -> str | None:
    pairs = _parse_faq_pairs(text)
    if not pairs:
        return None
    scored = [
        (_score_faq_pair(query, question, answer), answer)
        for question, answer in pairs
    ]
    scored.sort(key=lambda item: item[0], reverse=True)
    best_score, best_answer = scored[0]
    ambiguity_margin = 1.0 if best_score >= 3.0 else 1.5
    if len(scored) >= 2 and (best_score - scored[1][0]) < ambiguity_margin:
        return None
    if best_score <= 0:
        return None
    try:
        S.logger.info(
            "[FAQ PAIR SELECT] pairs=%s selected_score=%.2f chars=%s",
            len(pairs),
            best_score,
            len(best_answer),
        )
    except Exception:
        pass
    return re.sub(r"^\s*A:\s+", "", best_answer, flags=re.IGNORECASE).strip()

def _extract_best_faq_answer_from_docs(query: str, docs: list[dict], max_docs: int = 8) -> str | None:
    all_scored: list[tuple[float, str]] = []
    for doc in (docs or [])[:max_docs]:
        raw = str((doc or {}).get("page_content") or (doc or {}).get("text") or "").strip()
        if not raw:
            continue
        for question, answer in _parse_faq_pairs(raw):
            score = _score_faq_pair(query, question, answer)
            if score > -1000.0:
                all_scored.append((score, answer))
    if not all_scored:
        return None
    all_scored.sort(key=lambda item: item[0], reverse=True)
    best_score, best_answer = all_scored[0]
    ambiguity_margin = 1.0 if best_score >= 3.0 else 1.5
    if len(all_scored) >= 2 and (best_score - all_scored[1][0]) < ambiguity_margin:
        return None
    if best_score <= 0:
        return None
    try:
        S.logger.info("[FAQ PAIR SELECT] cross_doc pairs=%s selected_score=%.2f", len(all_scored), best_score)
    except Exception:
        pass
    return re.sub(r"^\s*A:\s+", "", best_answer, flags=re.IGNORECASE).strip()

def _extract_operational_faq_answer(query: str, docs: list[dict]) -> str | None:
    faq_answer = _extract_best_faq_answer_from_docs(query, docs)
    if faq_answer and _valid_procedural_rescue_answer(query, faq_answer):
        return faq_answer
    process_answer = _extract_process_sentence_answer(query, docs)
    if process_answer and _valid_procedural_rescue_answer(query, process_answer):
        return process_answer
    query_tokens = _faq_content_tokens(query)
    if not query_tokens:
        return None
    q_low = re.sub(r"\s+", " ", str(query or "").strip().lower())
    is_how_work = bool(re.search(r"\bhow\s+does\b", q_low) and re.search(r"\bwork\b", q_low))
    best_sentence = ""
    best_score = 0.0
    for doc in (docs or [])[:12]:
        raw = _doc_retrieval_text(doc).strip()
        if not raw:
            continue
        for sent in re.split(r"(?<=[.!?])\s+|\n+", raw):
            s = re.sub(r"\s+", " ", str(sent or "").strip())
            if len(s) < 20 or re.match(r"^\s*Q:\s", s, flags=re.IGNORECASE):
                continue
            sl = s.lower()
            hits = count_token_matches(query_tokens, sl)
            if hits <= 0:
                sibling_hits = 0
                if "policy" in query_tokens:
                    sibling_hits = count_token_matches(["refund", "return", "options", "available", "credit"], sl)
                elif "refund" in query_tokens or "return" in query_tokens:
                    sibling_hits = count_token_matches(["policy", "options", "available", "credit"], sl)
                if sibling_hits <= 0:
                    continue
                hits = sibling_hits
            score = float(hits) + (0.5 if re.match(r"^\s*A:\s", s, flags=re.IGNORECASE) else 0.0)
            if is_how_work and re.search(r"\b(?:work|process|step|onboard|setup)\b", sl):
                score += 0.75
            if re.search(r"\bfraud\b", q_low):
                if re.search(r"\b(?:lock|restrict|dispute|unauthorized|report|verify|suspected)\b", sl):
                    score += 2.5
                if re.search(r"\bcash back\b|\brewards credit card\b|\bdebit\b.*\bincluded\b", sl):
                    score -= 3.0
            if re.search(r"\bwhat happens\b", q_low):
                if re.search(r"\b(?:declin|coverage|optional|exceed)\b", sl):
                    score += 2.0
                elif re.search(r"\boverdraft fees\b", sl):
                    score -= 2.0
            if re.search(r"\bhow long\b", q_low) and re.search(r"\bdispute\b", q_low):
                if re.search(r"\b(?:business day|investigation|acknowledge|provisional)\b", sl):
                    score += 2.5
            if score > best_score:
                best_score = score
                best_sentence = re.sub(r"^\s*A:\s+", "", s, flags=re.IGNORECASE).strip()
    if best_sentence and best_score >= 1.0 and _valid_procedural_rescue_answer(query, best_sentence):
        return best_sentence
    return None

def _extract_process_sentence_answer(query: str, docs: list[dict]) -> str | None:
    """Generic process/workflow sentence extraction for how-does-X-work style queries."""
    query_tokens = _faq_content_tokens(query)
    if not query_tokens:
        return None
    q_low = re.sub(r"\s+", " ", str(query or "").strip().lower())
    is_how_work = bool(re.search(r"\bhow\s+does\b", q_low) and re.search(r"\bwork\b", q_low))
    query_mentions_password = bool(re.search(r"\b(?:password|forgot|reset)\b", q_low))
    process_cues = ("step", "phase", "stage", "process", "workflow", "onboard", "setup")
    best_sentence = ""
    best_score = 0.0
    for doc in (docs or [])[:8]:
        raw = _doc_retrieval_text(doc).strip()
        if not raw:
            continue
        low_doc = raw.lower()
        password_reset = (
            ("password" in low_doc and ("reset" in low_doc or "change" in low_doc or "forgot" in low_doc))
        )
        if password_reset and not query_mentions_password:
            continue
        for sent in re.split(r"(?<=[.!?])\s+|\n+", raw):
            s = re.sub(r"\s+", " ", str(sent or "").strip())
            if len(s) < 20 or re.match(r"^\s*Q:\s", s, flags=re.IGNORECASE):
                continue
            sl = s.lower()
            if ("password" in sl or "forgot" in sl) and not query_mentions_password:
                continue
            hits = count_token_matches(query_tokens, sl)
            if hits <= 0:
                continue
            score = float(hits)
            if any(cue in sl for cue in process_cues):
                score += 1.5
            if is_how_work and any(cue in sl for cue in process_cues):
                score += 1.0
            if score > best_score:
                best_score = score
                best_sentence = re.sub(r"^\s*A:\s+", "", s, flags=re.IGNORECASE).strip()
    if best_sentence and best_score >= 1.5:
        return best_sentence
    return None


def _decontaminate_faq_answer(query: str, answer: str) -> str:
    raw = str(answer or "").strip()
    if len(re.findall(r"(?i)(?:^|\s)Q:\s", raw)) < 2:
        return raw
    faq_answer = _extract_best_faq_answer(query, raw)
    return faq_answer or raw

def _tenant_scoped_process_doc_candidates(docs: list[dict], query: str, *, limit: int = 12) -> list[dict]:
    """Tenant collection prose fallback when route docs omit a matching process chunk."""
    tenant_id = _resolve_enrichment_tenant_id(docs)
    if tenant_id is None:
        return []
    query_tokens = _faq_content_tokens(query)
    if not query_tokens:
        return []
    candidates: list[dict] = []
    try:
        from backend.knowledge_base import get_or_create_collection

        col = get_or_create_collection(allow_empty=True, tenant_id=tenant_id)
        if col is None:
            return []
        payload = col.get(include=["documents"]) or {}
        for raw in payload.get("documents") or []:
            text = str(raw or "").strip()
            if len(text) < 20 or "|" in text:
                continue
            low = text.lower()
            if not any(tok in low for tok in query_tokens):
                continue
            candidates.append(
                {"page_content": text, "text": text, "metadata": {"tenant_id": tenant_id}}
            )
            if len(candidates) >= limit:
                break
    except Exception:
        return []
    return candidates


def _valid_procedural_rescue_answer(query: str, answer: str) -> bool:
    cleaned = re.sub(r"\s+", " ", str(answer or "")).strip()
    if len(cleaned) < 20:
        return False
    return not _is_evidence_fragment_answer(query, cleaned)


def _rescue_support_procedural_from_docs(query: str, retrieved_docs: list[dict]) -> str:
    """When retrieval clearly has a support how-to chunk, return it instead of not-found."""
    if not _is_support_procedural_query(query):
        return ""
    if not retrieved_docs:
        retrieved_docs = []

    faq_answer = _extract_best_faq_answer_from_docs(query, retrieved_docs, max_docs=15)
    if faq_answer:
        cleaned = re.sub(r"\s+", " ", faq_answer).strip()
        if _valid_procedural_rescue_answer(query, cleaned):
            try:
                S.logger.info(
                    "[SUPPORT PROCEDURAL RESCUE] query=%s source=faq_cross_doc chars=%s",
                    str(query or "")[:240],
                    len(cleaned),
                )
            except Exception:
                pass
            return cleaned

    op_answer = _extract_operational_faq_answer(query, retrieved_docs)
    if op_answer:
        cleaned = re.sub(r"\s+", " ", op_answer).strip()
        if _valid_procedural_rescue_answer(query, cleaned):
            try:
                S.logger.info(
                    "[SUPPORT PROCEDURAL RESCUE] query=%s source=operational_faq chars=%s",
                    str(query or "")[:240],
                    len(cleaned),
                )
            except Exception:
                pass
            return cleaned

    process_answer = _extract_process_sentence_answer(query, retrieved_docs)
    if not process_answer:
        collection_docs = _tenant_scoped_process_doc_candidates(retrieved_docs, query)
        if collection_docs:
            process_answer = _extract_process_sentence_answer(query, collection_docs)
    if process_answer:
        cleaned = re.sub(r"\s+", " ", process_answer).strip()
        if _valid_procedural_rescue_answer(query, cleaned):
            try:
                S.logger.info(
                    "[SUPPORT PROCEDURAL RESCUE] query=%s source=process_sentence chars=%s",
                    str(query or "")[:240],
                    len(cleaned),
                )
            except Exception:
                pass
            return cleaned

    procedural_markers = (
        "follow these steps",
        "forgot password",
        "reset link",
        "log in with your new",
    )
    for doc in retrieved_docs[:4]:
        meta = dict((doc or {}).get("metadata") or {})
        doc_id = str(meta.get("id") or meta.get("doc_id") or "").lower()
        text = str((doc or {}).get("page_content") or (doc or {}).get("text") or "").strip()
        if not text:
            continue
        low = text.lower()
        password_reset = (
            ("password" in low and ("reset" in low or "change" in low or "forgot" in low))
            or doc_id == "password_reset"
        )
        if not password_reset and not any(m in low for m in procedural_markers):
            continue
        faq_answer = _extract_best_faq_answer(query, text)
        if faq_answer:
            cleaned = re.sub(r"\s+", " ", faq_answer).strip()
        else:
            cleaned = re.sub(r"\s+", " ", text).strip()
        min_chars = 20 if faq_answer else 40
        if len(cleaned) >= min_chars and _valid_procedural_rescue_answer(query, cleaned):
            try:
                S.logger.info(
                    "[SUPPORT PROCEDURAL RESCUE] query=%s source=%s chars=%s faq_pair=%s",
                    str(query or "")[:240],
                    doc_id or "support_chunk",
                    len(cleaned),
                    bool(faq_answer),
                )
            except Exception:
                pass
            return cleaned
    return ""

def _is_explanation_intent_query(query: str) -> bool:
    q = str(query or "").strip()
    if not q:
        return False
    if _is_support_procedural_query(q):
        return False
    if _EXPLANATION_INTENT_RE_EN.search(q):
        return True
    if _EXPLANATION_INTENT_RE_AR.search(q):
        return True
    return False

def _is_simple_fact_definition_or_list_query(query: str) -> bool:
    q_raw = str(query or "").strip()
    if not q_raw:
        return False
    if _is_memory_rewrite_query(q_raw):
        return False
    if _is_definition_comparison_query(q_raw):
        return True
    if _is_compare_query(q_raw):
        return False
    if _is_arabic_text(q_raw):
        normalized_ar = S._normalize_arabic_query_surface(q_raw)
        if S._looks_like_arabic_list_query(q_raw) or _AR_DEFINITION_QUERY_RE.search(normalized_ar):
            return True
    if _is_targeted_list_question(q_raw):
        return True
    if _is_support_procedural_query(q_raw):
        return True
    if _detect_fact_query_type(q_raw):
        return True
    if not _is_definition_style_query(q_raw):
        return False
    if _explanation_relationship_concept_groups(q_raw):
        return False
    q = re.sub(r"\s+", " ", q_raw.lower())
    if re.match(r"^\s*why\b", q):
        return False
    if re.match(
        r"^\s*how\s+(?:does|do|can|could)\s+.+\s+"
        r"(?:support|supports|help|helps|contribute|contributes|relate|relates|"
        r"connect|connects|affect|affects|influence|influences|link|links)\b",
        q,
    ):
        return False
    return True

def _is_relationship_or_explanation_query(query: str) -> bool:
    q_raw = str(query or "").strip()
    if not q_raw:
        return False
    if _is_simple_fact_definition_or_list_query(q_raw):
        return False
    if _is_arabic_text(q_raw):
        normalized_ar = S._normalize_arabic_query_surface(q_raw)
        if _AR_EXPLANATION_QUERY_RE.search(normalized_ar):
            return True
    if _explanation_relationship_concept_groups(q_raw):
        return True
    query_features = set(_explanation_query_features(q_raw))
    if query_features.intersection({"importance", "reason", "relationship", "support", "role"}):
        return True
    return _is_explanation_intent_query(q_raw)

def _classify_simple_recovery_query_type(
    query_text: str,
    original_query_text: str = "",
    original_arabic_text: str = "",
) -> str:
    surfaces: list[str] = []
    for value in (original_arabic_text, original_query_text, query_text):
        cleaned = re.sub(r"\s+", " ", str(value or "").strip())
        if cleaned and cleaned not in surfaces:
            surfaces.append(cleaned)
    if any(_is_memory_rewrite_query(value) for value in surfaces):
        return "followup_memory"
    if any(_is_definition_comparison_query(value) for value in surfaces):
        return "definition_comparison"
    if any(_is_simple_fact_definition_or_list_query(value) for value in surfaces):
        return "simple_fact_definition"
    if any(_is_relationship_or_explanation_query(value) for value in surfaces):
        return "relationship_explanation"
    return "direct_grounded"

def _explanation_query_features(query_text: str) -> list[str]:
    query_value = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not query_value:
        return []
    features: list[str] = []
    for feature_name, patterns in _EXPLANATION_FEATURE_QUERY_PATTERNS.items():
        if any(re.search(pattern, query_value, flags=re.IGNORECASE) for pattern in patterns):
            features.append(feature_name)
    if "reason" in features and "importance" in features:
        features = [feature for feature in features if feature != "reason"] + ["reason"]
    return features

def _explanation_feature_hits(text_value: str, query_features: list[str] | set[str] | tuple[str, ...]) -> set[str]:
    haystack = str(text_value or "").lower()
    hits: set[str] = set()
    for feature_name in query_features or []:
        patterns = _EXPLANATION_FEATURE_EVIDENCE_PATTERNS.get(str(feature_name), ())
        if any(re.search(pattern, haystack, flags=re.IGNORECASE) for pattern in patterns):
            hits.add(str(feature_name))
    return hits

def _explanation_token_match(haystack: str, token: str) -> bool:
    if _token_match_light(haystack, token):
        return True
    base = _light_normalize_query_token(token)
    if len(base) < 5:
        return False
    forms = {base + "ing", base + "ed", base + "s", base + "es"}
    if base.endswith("e") and len(base) > 5:
        forms.add(base[:-1] + "ing")
    if re.search(r"[aeiou][bcdfghjklmnpqrstvwxyz]$", base):
        forms.add(base + base[-1] + "ing")
        forms.add(base + base[-1] + "ed")
    low = str(haystack or "").lower()
    return any(re.search(rf"\b{re.escape(form)}\b", low) for form in forms if form)

def _explanation_section_feature_hits(text_value: str, query_features: list[str] | set[str] | tuple[str, ...]) -> set[str]:
    head = str(text_value or "")[:900]
    hits = set(_explanation_feature_hits(head, query_features))
    if _EXPLANATION_SECTION_MARKER_RE.search(head):
        hits.add("section_marker")
    return hits

def _explanation_focus_tokens(query_text: str) -> list[str]:
    """Return generic content tokens of the query, excluding intent words.

    Reuses the existing `_query_section_tokens` helper (no new lexicon)."""
    try:
        base = _query_section_tokens(query_text, "explanatory_compare")
    except Exception:
        base = []
    filtered = [t for t in base if t not in _EXPLANATION_QUERY_STOP]
    extras = _explanation_content_tokens(query_text, keep_short=True)
    merged: list[str] = []
    for token in list(filtered or []) + extras:
        if token and token not in merged:
            merged.append(token)
    return merged or filtered or base

def _clean_explanation_concept_phrase(value: str) -> str:
    cleaned = re.sub(r"\s+", " ", str(value or "").strip().lower())
    cleaned = re.sub(r"^[\s\"'`.,;:!?()\[\]{}-]+|[\s\"'`.,;:!?()\[\]{}-]+$", "", cleaned)
    cleaned = re.sub(r"^(?:the|a|an|this|that|these|those|its|their|his|her|our)\s+", "", cleaned)
    cleaned = re.sub(r"\s+", " ", cleaned).strip()
    return cleaned

def _explanation_tokens_for_phrase(value: str) -> list[str]:
    tokens: list[str] = []
    for token in _explanation_content_tokens(_clean_explanation_concept_phrase(value), keep_short=True):
        normalized = _light_normalize_query_token(token)
        if normalized and normalized not in tokens:
            tokens.append(normalized)
    return tokens[:5]

def _explanation_relationship_concept_groups(query_text: str) -> list[list[str]]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return []

    left = right = ""
    try:
        left, right = _compare_terms_from_query(q)
    except Exception:
        left = right = ""
    if left and right:
        groups = [_explanation_tokens_for_phrase(left), _explanation_tokens_for_phrase(right)]
        return [group for group in groups if group]

    relation_patterns = [
        r"\bhow\s+(?:does|do|can|could)\s+(.+?)\s+(?:support|supports|help|helps|contribute|contributes|relate|relates|connect|connects|affect|affects|influence|influences|link|links)\s+(?:to\s+|with\s+)?(.+?)(?:[?.!]|$)",
        r"\bhow\s+(?:is|are)\s+(.+?)\s+(?:related|connected|linked)\s+(?:to|with)\s+(.+?)(?:[?.!]|$)",
        r"\b(?:relationship|relation|connection|link)\s+between\s+(.+?)\s+and\s+(.+?)(?:[?.!]|$)",
    ]
    for pattern in relation_patterns:
        match = re.search(pattern, q)
        if not match:
            continue
        groups = [
            _explanation_tokens_for_phrase(match.group(1)),
            _explanation_tokens_for_phrase(match.group(2)),
        ]
        groups = [group for group in groups if group]
        if len(groups) >= 2:
            return groups[:2]
    return []

def _explanation_primary_concept_group(query_text: str, query_focus: list[str]) -> list[str]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return []
    primary_patterns = [
        r"\bwhy\s+(?:is|are|was|were|does|do|did)?\s*(.+?)\s+(?:important|necessary|needed|useful|significant|valuable|beneficial)\b",
        r"\b(?:importance|benefits?|purpose|role|function)\s+of\s+(.+?)(?:\s+(?:in|for|to|within|about|regarding|concerning)\b|[?.!]|$)",
        r"\bhow\s+(?:does|do|can|could)\s+(.+?)\s+(?:work|operate|function)\b",
    ]
    for pattern in primary_patterns:
        match = re.search(pattern, q)
        if not match:
            continue
        tokens = _explanation_tokens_for_phrase(match.group(1))
        if tokens:
            return tokens
    return [_light_normalize_query_token(query_focus[0])] if query_focus else []

def _explanation_hit_group_indices(text_value: str, concept_groups: list[list[str]]) -> set[int]:
    low = str(text_value or "").lower()
    hit_indices: set[int] = set()
    for idx, group in enumerate(concept_groups or []):
        group_tokens = [token for token in group if token]
        if not group_tokens:
            continue
        hits = sum(1 for token in group_tokens if _explanation_token_match(low, token))
        required = max(1, min(2, len(group_tokens)))
        if hits >= required:
            hit_indices.add(idx)
    return hit_indices

def _explanation_group_has_hit(text_value: str, group: list[str]) -> bool:
    if not group:
        return False
    return bool(_explanation_hit_group_indices(text_value, [group]))

def _split_explanation_leading_label(sentence: str) -> tuple[str, str]:
    value = re.sub(r"\s+", " ", str(sentence or "").strip())
    if ":" not in value[:120]:
        return "", value
    label, body = value.split(":", 1)
    label = label.strip(" -\t\r\n.,;:")
    body = body.strip()
    label_words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", label)
    if not (1 <= len(label_words) <= 9):
        return "", value
    if re.search(r"[.!?]", label):
        return "", value
    return label, body

def _explanation_primary_appears_early(sentence: str, primary_group: list[str], max_words: int = 12) -> bool:
    if not primary_group:
        return True
    label, body = _split_explanation_leading_label(sentence)
    prefix_source = f"{label} " if label and _explanation_group_has_hit(label, primary_group) else ""
    prefix_source += " ".join(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", body or sentence)[:max_words])
    return _explanation_group_has_hit(prefix_source, primary_group)

def _explanation_starts_as_fragment(sentence: str, primary_group: list[str] | None = None) -> bool:
    value = re.sub(r"\s+", " ", str(sentence or "").strip())
    if not value:
        return True
    if _EXPLANATION_LEADING_FRAGMENT_RE.match(value):
        return True
    first_word_match = re.match(r"^\s*([A-Za-z][A-Za-z'\-]*)", value)
    if not first_word_match:
        return False
    first_word = first_word_match.group(1)
    if first_word[:1].islower():
        allowed_lower_starts = {"it", "this", "these", "those", "they", "the", "a", "an", "one", "another", "each"}
        if first_word.lower() not in allowed_lower_starts and not _explanation_primary_appears_early(value, primary_group or [], max_words=8):
            return True
    return False

def _explanation_line_fingerprint(sentence: str) -> set[str]:
    return {
        _light_normalize_query_token(token)
        for token in _explanation_content_tokens(sentence, keep_short=False)
        if _light_normalize_query_token(token)
    }

def _explanation_lines_too_similar(left: str, right: str) -> bool:
    a = _explanation_line_fingerprint(left)
    b = _explanation_line_fingerprint(right)
    if not a or not b:
        return False
    overlap = len(a & b) / float(max(1, len(a | b)))
    return overlap >= 0.72 or (len(a & b) >= 8 and min(len(a), len(b)) <= len(a & b) + 2)

def _filter_docs_for_explanation(docs: list[dict], query_text: str) -> list[dict]:
    """Contamination guard: keep only chunks that share at least one
    query-content token with the explanation question. If no chunk matches,
    return an empty list so the caller can strict-fallback.
    Order is preserved (already ranked by retrieval / reranker upstream)."""
    if not docs:
        return docs
    focus = _explanation_focus_tokens(query_text)
    if not focus:
        return docs
    matched: list[dict] = []
    for d in docs:
        try:
            blob = (_explanation_doc_text(d) + " " + _explanation_doc_metadata_text(d)).lower()
        except Exception:
            blob = ""
        if not blob:
            continue
        try:
            hit = any(_token_match_light(blob, tok) for tok in focus)
        except Exception:
            hit = False
        if hit:
            matched.append(d)
    if not matched:
        S.logger.info("[EXPLANATION MODE] focus_tokens=%s kept=0/%d", focus, len(docs))
        return []
    try:
        S.logger.info(
            "[EXPLANATION MODE] focus_tokens=%s kept=%d/%d",
            focus, len(matched), len(docs),
        )
    except Exception:
        pass
    return matched

def _explanation_mode_instructions(language: str = "en") -> str:
    """Strict prompt suffix forcing grounded, short, single-topic answers."""
    if (language or "").strip().lower() == "ar":
        return (
            "\nEXPLANATION MODE (\u0648\u0636\u0639 \u0627\u0644\u0634\u0631\u062d):\n"
            "- \u064a\u062c\u0628 \u0623\u0646 \u062a\u0623\u062a\u064a \u0627\u0644\u0625\u062c\u0627\u0628\u0629 \u0641\u0642\u0637 \u0645\u0646 \u0642\u0627\u0639\u062f\u0629 \u0627\u0644\u0645\u0639\u0631\u0641\u0629 \u0623\u0639\u0644\u0627\u0647.\n"
            "- \u0627\u062c\u0639\u0644 \u0627\u0644\u0625\u062c\u0627\u0628\u0629 \u0645\u0646 2 \u0625\u0644\u0649 5 \u0623\u0633\u0637\u0631 \u0642\u0635\u064a\u0631\u0629.\n"
            "- \u0631\u0643\u0651\u0632 \u0639\u0644\u0649 \u0645\u0648\u0636\u0648\u0639 \u0648\u0627\u062d\u062f \u0641\u0642\u0637\u061b \u0644\u0627 \u062a\u062e\u0644\u0637 \u0645\u0648\u0627\u0636\u064a\u0639 \u0645\u062e\u062a\u0644\u0641\u0629.\n"
            "- \u0625\u0630\u0627 \u0644\u0645 \u064a\u0643\u0646 \u0627\u0644\u062f\u0644\u064a\u0644 \u0648\u0627\u0636\u062d\u0627\u064b \u0623\u062c\u0628 \u062a\u0645\u0627\u0645\u0627\u064b: Not found in the document.\n"
        )
    return (
        "\nEXPLANATION MODE:\n"
        "- Use only the KNOWLEDGE BASE CONTEXT above.\n"
        "- Answer in 2 to 5 short lines.\n"
        "- Use one consistent topic group only; do not merge unrelated chunks.\n"
        "- If support is weak, fragmented, conflicting, or unclear, answer exactly: Not found in the document.\n"
    )

def _clean_explanation_sentence(sentence: str) -> str:
    cleaned = re.sub(r"\s+", " ", str(sentence or "").strip())
    try:
        cleaned = _clean_ocr_artifacts(cleaned)
    except Exception:
        pass
    cleaned = re.sub(
        r"^\s*(?:(?:[A-Z][A-Za-z0-9'\-/]*|of|and|the|for|in|to|on)(?:\s*/\s*|\s+)+){3,}\d{1,4}\s+(?=(?:[A-Z][.)]\s+)?[A-Z][A-Za-z])",
        "",
        cleaned,
    )
    cleaned = re.sub(
        r"^\s*(?:(?:[A-Z][A-Za-z0-9'\-/]*|of|and|the|for|in|to|on)(?:\s*/\s*|\s+)+){5,}(?=[A-Z][.)]\s+[A-Z][A-Za-z])",
        "",
        cleaned,
    )
    cleaned = re.sub(r"^\s*(?:[-*\u2022]|\d+[.)]|[A-Za-z][.)])\s+", "", cleaned)
    cleaned = re.sub(r"^\s*\d+(?:\.\d+)*\s+[A-Za-z][^:]{0,90}:\s*", "", cleaned)
    cleaned = cleaned.strip(" \t\r\n\"'`.,;:()[]{}")
    cleaned = _cleanup_final_answer_text(cleaned)
    if cleaned and not re.search(r"[.!?\u061f]$", cleaned):
        cleaned += "."
    return cleaned

def _is_usable_explanation_sentence(
    sentence: str,
    query_focus: list[str],
    needs_direct_cue: bool = True,
    concept_groups: list[list[str]] | None = None,
    relationship_mode: bool = False,
    primary_group: list[str] | None = None,
) -> bool:
    sentence_text = re.sub(r"\s+", " ", str(sentence or "").strip())
    if not sentence_text:
        return False
    if _EXPLANATION_NOISE_RE.search(sentence_text):
        return False
    if _explanation_starts_as_fragment(sentence_text, primary_group or []):
        return False
    if sentence_text.count('"') % 2 == 1:
        return False
    if sentence_text.count("\u201c") != sentence_text.count("\u201d"):
        return False
    words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", sentence_text)
    if len(words) < 5 or len(words) > 42:
        return False
    if len(sentence_text) < 24 or len(sentence_text) > 320:
        return False
    lower_sentence = sentence_text.lower()
    if re.match(r"^\s*(?:chapter|unit|section|figure|table)\s+\d+\b", lower_sentence):
        return False
    if re.search(r"\b(?:diagram\s+illustrates|figure\s+illustrates)\b", lower_sentence):
        return False
    if re.search(r"\bthe\s+next\s+function\b", lower_sentence):
        return False
    if len(re.findall(r"\b[A-Za-z]{2,7}\s+(?:ves|tion|sion|ment|ness|ance|ence|ing|ed)\b", sentence_text)) >= 3:
        return False
    if len(re.findall(r"\b[A-Za-z]{1,2}\s+[A-Za-z]{1,2}\s+[A-Za-z]{1,2}\b", sentence_text)) >= 1:
        return False
    direct_cue = bool(_EXPLANATION_DIRECT_CUE_RE.search(lower_sentence))
    if needs_direct_cue and not direct_cue:
        return False
    if query_focus:
        focus_hits = sum(1 for token in query_focus if _token_match_light(lower_sentence, token))
        if focus_hits <= 0:
            return False
        groups = list(concept_groups or [])
        hit_indices = _explanation_hit_group_indices(lower_sentence, groups)
        if groups:
            if relationship_mode:
                if not hit_indices:
                    return False
            elif primary_group and not _explanation_group_has_hit(lower_sentence, primary_group):
                return False
        if (not relationship_mode) and primary_group:
            label, body = _split_explanation_leading_label(sentence_text)
            if label and not _explanation_group_has_hit(label, primary_group):
                if not _explanation_primary_appears_early(body or sentence_text, primary_group, max_words=12):
                    return False
        if len(query_focus) >= 2 and focus_hits < 2 and not direct_cue and not groups:
            return False
    return True

def _split_explanation_candidates(text: str) -> list[str]:
    source_text = re.sub(r"[\t\r\f\v]+", " ", str(text or ""))
    source_text = re.sub(
        r"(?<=[.!?\"\u201d])\s+(?=[A-Z]\.\s+[A-Z][A-Za-z]{3,}\b)",
        "\n",
        source_text,
    )
    source_text = re.sub(r"(?m)^\s*(?:[-*\u2022]|\d+[.)]|[A-Za-z][.)])\s+", "", source_text)
    protected = source_text
    for _ in range(4):
        previous = protected
        protected = re.sub(r"\b([A-Z])\.\s+([A-Z][a-z])", r"\1<INIT_DOT> \2", protected)
        protected = re.sub(r"\b([A-Z])\.\s+([A-Z])\s+([A-Z][a-z])", r"\1<INIT_DOT> \2<INIT_DOT> \3", protected)
        if protected == previous:
            break
    protected = re.sub(r"([.!?][\"\u201d]?)\s+", r"\1\n", protected)
    candidates = [
        part.replace("<INIT_DOT>", ".").strip()
        for part in re.split(r"\n+", protected)
        if part and part.strip()
    ]
    expanded: list[str] = []
    for candidate in candidates:
        candidate_text = re.sub(r"\s+", " ", str(candidate or "").strip())
        if not candidate_text:
            continue
        if len(candidate_text) > 260:
            parts = [part.strip() for part in re.split(r"\s*;\s+|\s+--\s+|\s+\u2013\s+|\s+\u2014\s+", candidate_text) if part.strip()]
            expanded.extend(parts if len(parts) > 1 else [candidate_text])
        else:
            expanded.append(candidate_text)
    return expanded

def _score_explanation_sentence(
    sentence: str,
    query_focus: list[str],
    doc_rank: int,
    concept_groups: list[list[str]] | None = None,
    relationship_mode: bool = False,
    primary_group: list[str] | None = None,
    query_features: list[str] | None = None,
) -> float:
    lower_sentence = str(sentence or "").lower()
    focus_hits = sum(1 for token in query_focus if _token_match_light(lower_sentence, token)) if query_focus else 0
    cue_bonus = 1.5 if _EXPLANATION_CUE_RE.search(lower_sentence) else 0.0
    predicate_bonus = 0.8 if re.search(r"\b(?:is|are|was|were|means?|includes?|involves?|consists?|provides?|ensures?|supports?|helps?|uses?)\b", lower_sentence) else 0.0
    length_words = len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", lower_sentence))
    length_bonus = 0.4 if 8 <= length_words <= 32 else 0.0
    groups = list(concept_groups or [])
    hit_indices = _explanation_hit_group_indices(lower_sentence, groups)
    group_bonus = 0.0
    if groups:
        if relationship_mode and len(groups) >= 2:
            if len(hit_indices) >= len(groups):
                group_bonus += 4.0
            elif hit_indices:
                group_bonus += 0.8
                if _EXPLANATION_RELATION_VERB_RE.search(lower_sentence):
                    group_bonus += 0.7
        elif primary_group and _explanation_group_has_hit(lower_sentence, primary_group):
            group_bonus += 2.4
            if _explanation_primary_appears_early(sentence, primary_group, max_words=12):
                group_bonus += 0.9
    features = list(query_features or [])
    feature_hits = _explanation_feature_hits(lower_sentence, features)
    feature_bonus = 0.0
    if feature_hits:
        feature_bonus += min(2.4, 1.05 * len(feature_hits))
        if "relationship" in feature_hits and relationship_mode:
            feature_bonus += 0.8
        if "importance" in feature_hits and (not relationship_mode):
            feature_bonus += 0.7
    feature_missing_penalty = 0.0
    if features and not feature_hits:
        feature_missing_penalty = 0.9 if not relationship_mode else 0.35
    label_penalty = 0.0
    label_quality_bonus = 0.0
    if (not relationship_mode) and primary_group:
        label, body = _split_explanation_leading_label(sentence)
        label_low = label.lower()
        if label and re.search(
            r"\b(?:facilitates?|fundamental|important|importance|significance|significant|purpose|benefits?|helps?|supports?|enables?|ensures?|leads?\s+to|contributes?)\b",
            label_low,
        ):
            label_quality_bonus += 0.5
        if label and not _explanation_group_has_hit(label, primary_group) and not _explanation_primary_appears_early(body or sentence, primary_group, max_words=12):
            label_penalty += 3.0
        elif label and not _explanation_group_has_hit(label, primary_group):
            label_penalty += 0.65
        elif label and not _explanation_group_has_hit(label, primary_group) and not label_quality_bonus:
            label_penalty += 0.8
    fragment_penalty = 2.5 if _explanation_starts_as_fragment(sentence, primary_group or []) else 0.0
    ocr_penalty = 1.5 if re.search(r"\b[A-Za-z]{2,7}\s+(?:ves|tion|sion|ment|ness|ance|ence|ing|ed)\b", sentence) else 0.0
    density = focus_hits / max(1, length_words)
    density_bonus = min(1.0, density * 10.0) if focus_hits else 0.0
    return (1.8 * focus_hits) + group_bonus + feature_bonus + cue_bonus + predicate_bonus + length_bonus + density_bonus + label_quality_bonus - label_penalty - feature_missing_penalty - fragment_penalty - ocr_penalty - (0.05 * doc_rank)

def _doc_explanation_focus_hits(doc: dict, query_focus: list[str]) -> set[str]:
    haystack = (
        _explanation_doc_text(doc)
        + " "
        + _explanation_doc_metadata_text(doc)
    ).lower()
    return {token for token in query_focus if _token_match_light(haystack, token)}

def _select_explanation_topic_group(docs: list[dict], query_text: str) -> list[dict]:
    filtered_docs = _filter_docs_for_explanation(docs or [], query_text)
    if not filtered_docs:
        return []
    query_focus = _explanation_focus_tokens(query_text)
    query_features = _explanation_query_features(query_text)
    relationship_groups = _explanation_relationship_concept_groups(query_text)
    relationship_mode = bool(len(relationship_groups) >= 2)
    primary_group = relationship_groups[0] if relationship_mode else _explanation_primary_concept_group(query_text, query_focus)
    concept_groups = relationship_groups if relationship_mode else ([primary_group] if primary_group else [])
    scored_docs: list[tuple[float, int, dict, set[str], tuple[str, str, str]]] = []
    token_document_frequency: dict[str, int] = {}
    doc_hits_by_id: dict[int, set[str]] = {}
    for doc_rank, doc_candidate in enumerate(filtered_docs):
        hits = _doc_explanation_focus_hits(doc_candidate, query_focus)
        if not hits:
            continue
        doc_hits_by_id[id(doc_candidate)] = hits
        for token in hits:
            token_document_frequency[token] = token_document_frequency.get(token, 0) + 1

    rare_tokens = {
        token for token, frequency in token_document_frequency.items()
        if frequency <= max(1, len(filtered_docs) // 2)
    }
    for doc_rank, doc_candidate in enumerate(filtered_docs):
        hits = doc_hits_by_id.get(id(doc_candidate), set())
        if not hits:
            continue
        doc_text = _explanation_doc_text(doc_candidate)
        usable_sentence_scores: list[float] = []
        for sentence_text in _split_explanation_candidates(doc_text)[:24]:
            cleaned_sentence = _clean_explanation_sentence(sentence_text)
            if not _is_usable_explanation_sentence(
                cleaned_sentence,
                query_focus,
                needs_direct_cue=True,
                concept_groups=concept_groups,
                relationship_mode=relationship_mode,
                primary_group=primary_group,
            ):
                continue
            usable_sentence_scores.append(_score_explanation_sentence(
                cleaned_sentence,
                query_focus,
                doc_rank,
                concept_groups=concept_groups,
                relationship_mode=relationship_mode,
                primary_group=primary_group,
                query_features=query_features,
            ))
        if not usable_sentence_scores:
            continue
        best_sentence_score = max(usable_sentence_scores)
        if best_sentence_score < 3.0:
            continue
        metadata = dict((doc_candidate or {}).get("metadata") or {})
        key = (
            str(metadata.get("source") or metadata.get("filename") or "").strip().lower(),
            str(metadata.get("chapter") or "").strip().lower(),
            str(metadata.get("section") or metadata.get("title") or metadata.get("heading") or "").strip().lower(),
        )
        rare_hit_bonus = 1.2 * len(hits.intersection(rare_tokens))
        cue_bonus = 0.6 if _EXPLANATION_CUE_RE.search(doc_text[:1800]) else 0.0
        coverage = len(hits) / max(1, len(query_focus))
        group_hits = len(_explanation_hit_group_indices(doc_text, concept_groups)) if concept_groups else 0
        group_bonus = 0.9 * group_hits
        if relationship_mode and concept_groups and group_hits >= len(concept_groups):
            group_bonus += 2.0
        sentence_bonus = min(4.0, best_sentence_score * 0.45) + min(1.0, 0.25 * len(usable_sentence_scores))
        score = (1.55 * len(hits)) + rare_hit_bonus + coverage + cue_bonus + group_bonus + sentence_bonus - (0.08 * doc_rank)
        scored_docs.append((score, doc_rank, doc_candidate, hits, key))
    if not scored_docs:
        return []
    scored_docs.sort(key=lambda item: (-item[0], item[1]))
    best_score, _best_rank, best_doc, best_hits, best_key = scored_docs[0]
    if best_score < 1.0:
        return []

    selected: list[dict] = [best_doc]
    selected_ids = {id(best_doc)}
    selected_hits = set(best_hits)
    for score, _doc_rank, doc_candidate, hits, key in scored_docs[1:]:
        if len(selected) >= 4:
            break
        same_topic_key = bool(best_key[0] and key[0] == best_key[0] and (key[1:] == best_key[1:] or key[1] == best_key[1] or key[2] == best_key[2]))
        shares_rare = bool(hits.intersection(rare_tokens) and (best_hits.intersection(rare_tokens) or same_topic_key))
        enough_overlap = bool(hits.intersection(selected_hits) and (len(hits) >= 2 or len(best_hits) <= 1))
        complementary_same_topic = bool(same_topic_key and hits and len(selected_hits.union(hits)) > len(selected_hits))
        complementary_relationship = bool(relationship_mode and hits and len(selected_hits.union(hits)) > len(selected_hits))
        if shares_rare or enough_overlap or complementary_same_topic or complementary_relationship:
            selected.append(doc_candidate)
            selected_ids.add(id(doc_candidate))
            selected_hits.update(hits)

    if query_focus and len(selected_hits) < min(2, len(query_focus)):
        only_hit = next(iter(selected_hits), "")
        if len(query_focus) > 1 and only_hit not in rare_tokens:
            return []
    return selected

def _append_symbolic_explanation_rescue_doc(query_text: str, docs: list[dict]) -> tuple[list[dict], dict[str, Any]]:
    if not _is_explanation_intent_query(query_text):
        return list(docs or []), {"detected": False, "reason": "not_explanation_intent"}
    query_info = S._detect_short_symbolic_list_query(query_text)
    if not isinstance(query_info, dict):
        return list(docs or []), {"detected": False, "reason": "not_symbolic_query"}

    rescue_doc, rescue_meta = S._lexical_rescue_symbolic_list_chunk(query_text, docs)
    rescue_meta = dict(rescue_meta or {})
    signals = dict(rescue_meta.get("signals") or {})
    if not rescue_doc or rescue_meta.get("reason") != "candidate_selected" or float(signals.get("phrase_hits") or 0.0) <= 0.0:
        rescue_meta.setdefault("reason", "no_phrase_anchor_rescue")
        return list(docs or []), rescue_meta

    rescued_docs = list(docs or [])
    rescue_metadata = dict((rescue_doc or {}).get("metadata") or {})
    rescue_key = (
        str(rescue_metadata.get("source") or rescue_metadata.get("filename") or rescue_metadata.get("id") or ""),
        str(rescue_metadata.get("chunk_index") or ""),
    )
    for existing_doc in rescued_docs:
        existing_metadata = dict((existing_doc or {}).get("metadata") or {})
        existing_key = (
            str(existing_metadata.get("source") or existing_metadata.get("filename") or existing_metadata.get("id") or ""),
            str(existing_metadata.get("chunk_index") or ""),
        )
        if existing_key == rescue_key:
            return rescued_docs, rescue_meta
    rescued_docs.append(rescue_doc)
    S.logger.info(
        "[EXPLANATION MODE] symbolic_rescue_appended chunk=%s score=%.2f",
        rescue_metadata.get("chunk_index"),
        float(rescue_meta.get("score") or 0.0),
    )
    return rescued_docs, rescue_meta

def _symbolic_anchor_phrase_hit(sentence_text: str, query_info: dict[str, Any], required_anchor_tokens: list[str]) -> bool:
    normalized_sentence = S._normalize_symbolic_list_surface(sentence_text)
    phrase_variants = [
        S._normalize_symbolic_list_surface(str(variant))
        for variant in (query_info.get("phrase_variants") or [])
        if S._normalize_symbolic_list_surface(str(variant))
    ]
    if any(re.search(rf"\b{re.escape(variant)}\b", normalized_sentence) for variant in phrase_variants):
        return True
    sentence_low = str(sentence_text or "").lower()
    return bool(required_anchor_tokens and all(_token_match_light(sentence_low, token) for token in required_anchor_tokens))

def _is_symbolic_explanation_line(sentence_text: str) -> bool:
    sentence = re.sub(r"\s+", " ", str(sentence_text or "").strip())
    if not sentence or _EXPLANATION_NOISE_RE.search(sentence):
        return False
    words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", sentence)
    if len(words) < 5 or len(words) > 46:
        return False
    if len(sentence) < 24 or len(sentence) > 340:
        return False
    if re.match(r"^\s*(?:chapter|unit|section|figure|table)\s+\d+\b", sentence.lower()):
        return False
    return True

def _is_symbolic_support_line(sentence_text: str, query_focus: list[str]) -> bool:
    sentence = re.sub(r"\s+", " ", str(sentence_text or "").strip())
    if not _is_symbolic_explanation_line(sentence):
        return False
    sentence_low = sentence.lower()
    has_cue = bool(_EXPLANATION_DIRECT_CUE_RE.search(sentence_low) or _EXPLANATION_CUE_RE.search(sentence_low))
    has_bridge = bool(re.search(
        r"\b(?:these|this|those|assets?|resources?|elements?|factors?|components?|items?|"
        r"parts?|uses?|used|utili[sz]es?|goals?|objectives?|purpose|accomplish(?:es|ing)?|achiev(?:e|es|ing))\b",
        sentence_low,
    ))
    if not (has_cue and has_bridge):
        return False
    if query_focus:
        focus_hits = sum(1 for token in query_focus if _token_match_light(sentence_low, token))
        if focus_hits <= 0 and not re.search(r"\b(?:goals?|objectives?|achiev(?:e|es|ing)|accomplish(?:es|ing)?)\b", sentence_low):
            return False
    return True

def _build_symbolic_anchor_explanation_answer(
    query_text: str,
    docs: list[dict],
    query_focus: list[str],
    required_anchor_tokens: list[str],
) -> str:
    query_info = S._detect_short_symbolic_list_query(query_text)
    if not isinstance(query_info, dict) or not required_anchor_tokens:
        return ""
    query_features = _explanation_query_features(query_text)

    best_answer_lines: list[str] = []
    best_score = float("-inf")
    for doc_rank, doc_candidate in enumerate(docs or []):
        cleaned_candidates = [
            _clean_explanation_sentence(candidate)
            for candidate in _split_explanation_candidates(_explanation_doc_text(doc_candidate))
        ]
        cleaned_candidates = [candidate for candidate in cleaned_candidates if candidate]
        for sentence_index, anchor_sentence in enumerate(cleaned_candidates):
            if not _is_symbolic_explanation_line(anchor_sentence):
                continue
            if not _symbolic_anchor_phrase_hit(anchor_sentence, query_info, required_anchor_tokens):
                continue

            support_candidates: list[tuple[float, int, str]] = []
            for offset in (1, 2, -1):
                support_index = sentence_index + offset
                if support_index < 0 or support_index >= len(cleaned_candidates):
                    continue
                support_sentence = cleaned_candidates[support_index]
                if not _is_symbolic_support_line(support_sentence, query_focus):
                    continue
                support_score = _score_explanation_sentence(support_sentence, query_focus, doc_rank)
                if query_features and _explanation_feature_hits(support_sentence, query_features):
                    support_score += 0.8
                if offset == 1:
                    support_score += 2.0
                elif offset == 2:
                    support_score += 0.8
                support_candidates.append((support_score, abs(offset), support_sentence))
            if not support_candidates:
                continue

            support_candidates.sort(key=lambda row: (-row[0], row[1]))
            selected_lines = [anchor_sentence, support_candidates[0][2]]
            normalized_lines = {re.sub(r"\W+", " ", line.lower()).strip() for line in selected_lines}
            if len(normalized_lines) < 2:
                continue
            anchor_bonus = 3.0 + sum(1 for token in required_anchor_tokens if _token_match_light(anchor_sentence.lower(), token))
            total_score = anchor_bonus + support_candidates[0][0] - (0.05 * doc_rank)
            if total_score > best_score:
                best_score = total_score
                best_answer_lines = selected_lines

    if len(best_answer_lines) < 2:
        return ""
    S.logger.info(
        "[EXPLANATION MODE] accepted_symbolic_anchor lines=%d focus=%s score=%.2f",
        len(best_answer_lines),
        query_focus,
        best_score,
    )
    return "\n".join(f"- {line}" for line in best_answer_lines[:3]).strip()

def _expand_explanation_docs_with_local_windows(query_text: str, docs: list[dict]) -> list[dict]:
    """Prefer focused local spans from already-selected chunks.

    This does not change chunking or retrieval. It only adds short, query-focused
    views of the same evidence so the sentence selector is less likely to start
    from a section boundary or a mid-chunk OCR fragment.
    """
    expanded: list[dict] = []
    seen: set[str] = set()
    focus_tokens = _explanation_focus_tokens(query_text)

    def _append(doc_value: dict, text_value: str, local_flag: bool = False) -> None:
        text_clean = re.sub(r"\s+", " ", str(text_value or "").strip())
        if not text_clean:
            return
        if focus_tokens and not any(_token_match_light(text_clean.lower(), token) for token in focus_tokens):
            return
        fingerprint = text_clean.lower()[:700]
        if fingerprint in seen:
            return
        seen.add(fingerprint)
        doc_new = dict(doc_value or {})
        metadata_new = dict((doc_new.get("metadata") or {}))
        if local_flag:
            metadata_new["_explanation_local_window"] = True
        doc_new["metadata"] = metadata_new
        doc_new["page_content"] = text_value
        doc_new["text"] = text_value
        expanded.append(doc_new)

    for doc in docs or []:
        raw_text = _explanation_doc_text(doc)
        if not raw_text.strip():
            continue
        metadata = dict((doc or {}).get("metadata") or {})
        local_text = str(metadata.get("_single_local_window_text") or "").strip()
        if local_text:
            _append(doc, local_text, local_flag=True)
        if len(raw_text) > 1400:
            try:
                focused_text = S._focus_doc_to_query_window(query_text, raw_text, window=1000)
            except Exception:
                focused_text = ""
            if focused_text and len(focused_text) < int(len(raw_text) * 0.92):
                _append(doc, focused_text, local_flag=True)
        _append(doc, raw_text, local_flag=False)
    return expanded or list(docs or [])

def _explanation_fragment_marker_count(text_value: str) -> int:
    lines = [re.sub(r"\s+", " ", line).strip() for line in str(text_value or "").splitlines() if str(line or "").strip()]
    count = 0
    for line in lines[:80]:
        words = re.findall(r"[A-Za-z][A-Za-z'\-]*", line)
        if not (2 <= len(words) <= 11):
            continue
        if re.match(r"^\s*(?:[-*\u2022]|\d+[.)]|[A-Za-z][.)])\s+", line) or line.endswith(":"):
            count += 1
            continue
        title_words = sum(1 for word in words if word[:1].isupper())
        if title_words >= max(2, len(words) // 2) and not re.search(r"[.!?]$", line):
            count += 1
    return count

def _rank_explanation_docs_for_query(query_text: str, docs: list[dict], max_docs: int = 3) -> list[dict]:
    source_docs = list(docs or [])
    if not source_docs:
        return []

    query_focus = _explanation_focus_tokens(query_text)
    query_features = _explanation_query_features(query_text)
    S.logger.info("[EXPLAIN QUERY FEATURES] features=%s", query_features)
    relationship_groups = _explanation_relationship_concept_groups(query_text)
    relationship_mode = bool(len(relationship_groups) >= 2 or "relationship" in query_features)
    primary_group = relationship_groups[0] if len(relationship_groups) >= 2 else _explanation_primary_concept_group(query_text, query_focus)
    concept_groups = relationship_groups if len(relationship_groups) >= 2 else ([primary_group] if primary_group else [])

    scored_rows: list[tuple[float, float, float, int, dict, set[int], set[str], int, str]] = []
    for doc_rank, doc_candidate in enumerate(source_docs):
        doc_text = _explanation_doc_text(doc_candidate)
        if not doc_text.strip():
            continue
        lower_text = doc_text.lower()
        metadata = dict((doc_candidate or {}).get("metadata") or {})
        base_raw = float(
            (doc_candidate or {}).get(
                "similarity",
                (doc_candidate or {}).get("score", metadata.get("_score", 0.0)),
            )
            or 0.0
        )
        base_component = max(-1.4, min(1.4, base_raw * 0.20))
        words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", lower_text)
        focus_hits = sum(1 for token in query_focus if _token_match_light(lower_text, token)) if query_focus else 0
        focus_coverage = focus_hits / max(1, len(query_focus)) if query_focus else 0.0
        focus_density = focus_hits / max(1, len(words))
        group_hits = _explanation_hit_group_indices(lower_text, concept_groups)
        feature_hits = _explanation_feature_hits(lower_text, query_features)
        section_blob = "\n".join([
            _explanation_doc_metadata_text(doc_candidate),
            "\n".join(str(doc_text or "").splitlines()[:8]),
        ])
        section_hits = _explanation_section_feature_hits(section_blob, query_features)

        usable_sentence_scores: list[float] = []
        starts_fragment = False
        example_sentences = 0
        for sentence_text in _split_explanation_candidates(doc_text)[:28]:
            cleaned_sentence = _clean_explanation_sentence(sentence_text)
            if not cleaned_sentence:
                continue
            if _explanation_starts_as_fragment(cleaned_sentence, primary_group):
                starts_fragment = True
            if _EXPLANATION_EXAMPLE_DOMINANT_RE.search(cleaned_sentence):
                example_sentences += 1
            if not _is_usable_explanation_sentence(
                cleaned_sentence,
                query_focus,
                needs_direct_cue=True,
                concept_groups=concept_groups,
                relationship_mode=relationship_mode,
                primary_group=primary_group,
            ):
                continue
            usable_sentence_scores.append(_score_explanation_sentence(
                cleaned_sentence,
                query_focus,
                doc_rank,
                concept_groups=concept_groups,
                relationship_mode=relationship_mode,
                primary_group=primary_group,
                query_features=query_features,
            ))

        best_sentence_score = max(usable_sentence_scores) if usable_sentence_scores else 0.0
        coherent_count = len(usable_sentence_scores)
        relationship_both_sides = bool(concept_groups and len(group_hits) >= len(concept_groups))
        boost = 0.0
        boost += min(3.0, 2.2 * focus_coverage)
        boost += min(1.4, focus_hits * 0.35)
        boost += min(1.2, focus_density * 70.0) if focus_hits else 0.0
        boost += min(3.2, 1.15 * len(feature_hits))
        boost += min(1.4, 0.55 * len(section_hits))
        boost += min(3.4, best_sentence_score * 0.42)
        boost += min(1.0, coherent_count * 0.25)
        if concept_groups:
            boost += min(2.0, 0.8 * len(group_hits))
        if relationship_mode and relationship_both_sides:
            boost += 2.8

        penalty = 0.0
        reasons: list[str] = []
        if query_focus and focus_hits <= 0:
            penalty += 4.0
            reasons.append("no_concept_hit")
        elif query_focus and focus_coverage < 0.45:
            penalty += 1.35
            reasons.append("low_concept_coverage")
        if focus_hits and focus_density < 0.006:
            penalty += 0.9
            reasons.append("low_concept_density")
        if query_features and not feature_hits and coherent_count <= 1:
            penalty += 1.35
            reasons.append("missing_feature_terms")
        if relationship_mode and concept_groups and not relationship_both_sides:
            penalty += 1.4
            reasons.append("single_relationship_side")
        if starts_fragment:
            penalty += 0.7
            reasons.append("fragment_start")
        if _looks_table_or_heading_like_chunk(doc_text[:1800]):
            penalty += 1.5
            reasons.append("heading_table_like")
        fragment_markers = _explanation_fragment_marker_count(doc_text[:1800])
        if fragment_markers >= 4:
            penalty += min(1.4, 0.25 * fragment_markers)
            reasons.append("many_heading_fragments")
        lines = [line for line in str(doc_text or "").splitlines() if line.strip()]
        bullet_lines = [line for line in lines if re.match(r"^\s*(?:[-*\u2022]|\d+[.)]|[A-Za-z][.)])\s+", line)]
        if lines and (len(bullet_lines) / max(1, len(lines))) >= 0.35:
            penalty += 1.1
            reasons.append("list_fragment")
        if example_sentences >= max(2, coherent_count + 1):
            penalty += 0.8
            reasons.append("example_dominant")
        if coherent_count <= 0:
            penalty += 2.6
            reasons.append("no_coherent_sentence")

        final_score = base_component + boost - penalty - (0.035 * doc_rank)
        if not reasons:
            reasons.append("matched")

        doc_ranked = dict(doc_candidate or {})
        ranked_metadata = dict(metadata)
        ranked_metadata["_explanation_rank_score"] = float(final_score)
        ranked_metadata["_explanation_rank_features"] = sorted(feature_hits)
        doc_ranked["metadata"] = ranked_metadata
        S.logger.info(
            "[EXPLAIN RANK] chunk_index=%s base=%.3f boost=%.3f penalty=%.3f final=%.3f reason=%s",
            metadata.get("chunk_index"),
            base_raw,
            boost,
            penalty,
            final_score,
            ",".join(reasons[:4]),
        )
        scored_rows.append((final_score, boost, penalty, doc_rank, doc_ranked, group_hits, feature_hits, coherent_count, ",".join(reasons[:4])))

    if not scored_rows:
        return []
    scored_rows.sort(key=lambda row: (-row[0], row[3]))
    minimum_score = 4.2 if relationship_mode else 3.3
    strong_rows = [row for row in scored_rows if row[0] >= minimum_score and row[7] > 0]
    S.logger.info(
        "[EXPLAIN FILTER TRACE] relationship_mode=%s threshold=%.2f candidates=%d strong=%d best=%.3f",
        bool(relationship_mode),
        minimum_score,
        len(scored_rows),
        len(strong_rows),
        float(scored_rows[0][0]),
    )
    if not strong_rows:
        S.logger.info("[EXPLANATION MODE] fallback=weak_explanation_rank best=%.2f threshold=%.2f", scored_rows[0][0], minimum_score)
        return []

    if relationship_mode and concept_groups:
        required_groups = set(range(len(concept_groups)))
        both_side_rows = [row for row in strong_rows if required_groups.issubset(row[5])]
        selected_rows: list[tuple[float, float, float, int, dict, set[int], set[str], int, str]] = []
        covered_groups: set[int] = set()
        if both_side_rows:
            selected_rows.append(both_side_rows[0])
            covered_groups.update(both_side_rows[0][5])
        for row in strong_rows:
            if len(selected_rows) >= max_docs:
                break
            if any(row[4] is selected[4] for selected in selected_rows):
                continue
            if not row[5].difference(covered_groups) and selected_rows:
                continue
            selected_rows.append(row)
            covered_groups.update(row[5])
        if not required_groups.issubset(covered_groups):
            S.logger.info(
                "[EXPLANATION MODE] fallback=weak_relationship_rank required=%s covered=%s",
                sorted(required_groups),
                sorted(covered_groups),
            )
            return []
        return [row[4] for row in selected_rows[:max_docs]]

    return [row[4] for row in strong_rows[:max_docs]]

def _build_controlled_explanation_answer_en(query_text: str, docs: list[dict]) -> str:
    query_focus = _explanation_focus_tokens(query_text)
    query_features = _explanation_query_features(query_text)
    S.logger.info("[EXPLAIN QUERY FEATURES] features=%s", query_features)
    relationship_groups = _explanation_relationship_concept_groups(query_text)
    relationship_mode = bool(len(relationship_groups) >= 2)
    primary_group = relationship_groups[0] if relationship_mode else _explanation_primary_concept_group(query_text, query_focus)
    concept_groups = relationship_groups if relationship_mode else ([primary_group] if primary_group else [])
    candidate_docs = _expand_explanation_docs_with_local_windows(query_text, docs or [])
    topic_docs = _select_explanation_topic_group(candidate_docs, query_text)
    if not topic_docs:
        rescued_docs, rescue_meta = _append_symbolic_explanation_rescue_doc(query_text, docs or [])
        if rescue_meta.get("reason") == "candidate_selected" and len(rescued_docs) > len(docs or []):
            topic_docs = _select_explanation_topic_group(_expand_explanation_docs_with_local_windows(query_text, rescued_docs), query_text)
    if not topic_docs:
        S.logger.info("[EXPLANATION MODE] fallback=no_consistent_topic_group")
        return RAG_NO_MATCH_RESPONSE

    combined_topic_text = " ".join(_explanation_doc_text(doc) for doc in topic_docs).lower()
    required_anchor_tokens = [token for token in query_focus if len(token) <= 3 or any(ch.isdigit() for ch in token)]
    missing_anchor_tokens = [
        token for token in required_anchor_tokens
        if not _token_match_light(combined_topic_text, token)
    ]
    if missing_anchor_tokens:
        rescued_docs, rescue_meta = _append_symbolic_explanation_rescue_doc(query_text, docs or [])
        if rescue_meta.get("reason") == "candidate_selected" and len(rescued_docs) > len(docs or []):
            rescued_topic_docs = _select_explanation_topic_group(_expand_explanation_docs_with_local_windows(query_text, rescued_docs), query_text)
            rescued_combined_text = " ".join(_explanation_doc_text(doc) for doc in rescued_topic_docs).lower()
            rescued_missing_anchors = [
                token for token in required_anchor_tokens
                if not _token_match_light(rescued_combined_text, token)
            ]
            if rescued_topic_docs and not rescued_missing_anchors:
                topic_docs = rescued_topic_docs
                combined_topic_text = rescued_combined_text
                missing_anchor_tokens = []
        if missing_anchor_tokens:
            S.logger.info("[EXPLANATION MODE] fallback=missing_required_anchors anchors=%s", missing_anchor_tokens)
            return RAG_NO_MATCH_RESPONSE

    symbolic_answer = _build_symbolic_anchor_explanation_answer(
        query_text,
        topic_docs,
        query_focus,
        required_anchor_tokens,
    )
    if symbolic_answer:
        return symbolic_answer

    scored_sentences: list[tuple[float, int, str, set[int]]] = []
    needs_direct_cue = bool(_is_explanation_intent_query(query_text))
    for doc_rank, doc_candidate in enumerate(topic_docs):
        doc_text = _explanation_doc_text(doc_candidate)
        for sentence_index, sentence_text in enumerate(_split_explanation_candidates(doc_text)):
            cleaned_sentence = _clean_explanation_sentence(sentence_text)
            if not _is_usable_explanation_sentence(
                cleaned_sentence,
                query_focus,
                needs_direct_cue=needs_direct_cue,
                concept_groups=concept_groups,
                relationship_mode=relationship_mode,
                primary_group=primary_group,
            ):
                continue
            score = _score_explanation_sentence(
                cleaned_sentence,
                query_focus,
                doc_rank,
                concept_groups=concept_groups,
                relationship_mode=relationship_mode,
                primary_group=primary_group,
                query_features=query_features,
            )
            if score < 3.0:
                continue
            hit_indices = _explanation_hit_group_indices(cleaned_sentence, concept_groups)
            scored_sentences.append((score, sentence_index + (doc_rank * 1000), cleaned_sentence, hit_indices))
    if not scored_sentences:
        S.logger.info("[EXPLANATION MODE] fallback=no_relevant_sentences")
        return RAG_NO_MATCH_RESPONSE

    scored_sentences.sort(key=lambda item: (-item[0], item[1]))
    selected_lines: list[str] = []
    seen_lines: set[str] = set()
    selected_group_indices: set[int] = set()
    selected_has_direct_relationship = False

    direct_relationship_rows = [
        row for row in scored_sentences
        if relationship_mode and concept_groups and len(row[3]) >= len(concept_groups)
    ]
    ordered_rows = direct_relationship_rows + [row for row in scored_sentences if row not in direct_relationship_rows]

    for score, _sentence_order, sentence_text, hit_indices in ordered_rows:
        normalized_sentence = re.sub(r"\W+", " ", sentence_text.lower()).strip()
        if not normalized_sentence or normalized_sentence in seen_lines:
            continue
        if any(_explanation_lines_too_similar(sentence_text, existing) for existing in selected_lines):
            continue
        if relationship_mode and selected_lines and hit_indices and hit_indices.issubset(selected_group_indices) and len(selected_lines) >= 2:
            continue
        seen_lines.add(normalized_sentence)
        selected_lines.append(sentence_text)
        selected_group_indices.update(hit_indices)
        if relationship_mode and concept_groups and len(hit_indices) >= len(concept_groups):
            selected_has_direct_relationship = True
        if len(selected_lines) >= 3:
            break

    if not selected_lines:
        S.logger.info("[EXPLANATION MODE] fallback=empty_after_dedupe")
        return RAG_NO_MATCH_RESPONSE
    if relationship_mode and len(concept_groups) >= 2:
        required_groups = set(range(len(concept_groups)))
        if not required_groups.issubset(selected_group_indices):
            S.logger.info(
                "[EXPLANATION MODE] fallback=missing_relationship_side groups=%s selected=%s",
                len(concept_groups),
                sorted(selected_group_indices),
            )
            return RAG_NO_MATCH_RESPONSE
        if (not selected_has_direct_relationship) and len(selected_lines) < 2:
            S.logger.info("[EXPLANATION MODE] fallback=relationship_needs_two_grounded_sides")
            return RAG_NO_MATCH_RESPONSE
    if len(selected_lines) < 2:
        if relationship_mode and selected_has_direct_relationship:
            S.logger.info("[EXPLANATION MODE] accepted_single_direct_relationship")
        else:
            S.logger.info("[EXPLANATION MODE] fallback=too_few_lines count=%d", len(selected_lines))
            return RAG_NO_MATCH_RESPONSE

    answer = "\n".join(f"- {line}" for line in selected_lines[:3]).strip()
    S.logger.info(
        "[EXPLANATION MODE] accepted docs=%d lines=%d focus=%s",
        len(topic_docs), len(selected_lines[:3]), query_focus,
    )
    return answer or RAG_NO_MATCH_RESPONSE

def _format_translated_explanation_lines(text: str, max_lines: int = 3) -> str:
    cleaned = re.sub(r"\s+", " ", str(text or "").strip())
    if not cleaned:
        return ""
    parts = [part.strip() for part in re.split(r"(?<=[.!?\u061f])\s+|\n+", cleaned) if part.strip()]
    if len(parts) <= 1:
        parts = [part.strip() for part in re.split(r"\s*[;\u061b]\s+", cleaned) if part.strip()]
    lines: list[str] = []
    for part in parts:
        if not part:
            continue
        lines.append(part)
        if len(lines) >= max_lines:
            break
    return "\n".join(lines or [cleaned])

async def _translate_controlled_explanation_answer_ar(answer_en: str) -> str:
    async def _translate_line_external(line_text: str) -> str:
        source_text = str(line_text or "").strip()
        if not source_text:
            return ""
        try:
            translator_cls = __import__("deep_translator", fromlist=["GoogleTranslator"]).GoogleTranslator
            translated = await asyncio.get_event_loop().run_in_executor(
                None,
                lambda: translator_cls(source="en", target="ar").translate(source_text),
            )
            return str(translated or "").strip()
        except Exception:
            return ""

    def _clean_ar_controlled_line(candidate: str) -> str:
        cleaned = _sanitize_arabic_text(str(candidate or "").strip())
        cleaned = re.sub(r"\s+", " ", cleaned).strip(" \t\r\n-\u2022،,.;:")
        return cleaned

    def _valid_ar_controlled_line(candidate: str) -> bool:
        if not candidate:
            return False
        if re.search(r"[A-Za-z\u0400-\u04FF\u3040-\u30FF\u3400-\u4DBF\u4E00-\u9FFF\uAC00-\uD7AF]", candidate):
            return False
        if S._has_arabic_latin_token_mix(candidate):
            return False
        return sum(1 for char in candidate if "\u0600" <= char <= "\u06FF") >= 3

    lines = []
    for raw_line in str(answer_en or "").splitlines():
        line = re.sub(r"^\s*(?:[-*\u2022]|\d+[.)])\s+", "", raw_line).strip()
        if line:
            lines.append(line)
    if len(lines) < 2:
        return ""

    translated_lines: list[str] = []
    for line in lines[:3]:
        cached = _ar_item_translation_cache_get(line, "ar", "controlled_explanation")
        if cached:
            translated_lines.append(cached)
            continue
        candidate = await _translate_line_external(line)
        if _valid_ar_controlled_line(candidate):
            S.logger.info("[AR ITEM TRANSLATION] provider=external branch=controlled_explanation item_len=%s", len(line))
        else:
            try:
                candidate = await translate_with_llm(line, "en", "ar")
            except Exception:
                candidate = ""
        candidate = _clean_ar_controlled_line(candidate)
        if not _valid_ar_controlled_line(candidate):
            candidate = _clean_ar_controlled_line(await _translate_line_external(line))
            if _valid_ar_controlled_line(candidate):
                S.logger.info("[AR ITEM TRANSLATION] provider=external branch=controlled_explanation item_len=%s", len(line))
        if not _valid_ar_controlled_line(candidate):
            return ""
        if len(candidate) > 280:
            candidate = re.sub(r"(?<=[.!?\u061f])\s+", "\n", candidate).split("\n", 1)[0].strip()
            if len(candidate) > 280:
                return ""
        _ar_item_translation_cache_put(line, candidate, "ar", "controlled_explanation")
        translated_lines.append(candidate)

    if len(translated_lines) < 2:
        return ""
    return "\n".join(f"- {line}" for line in translated_lines)

async def _build_controlled_explanation_answer(
    query_text: str,
    docs: list[dict],
    language: str = "en",
    original_query_text: str = "",
) -> str:
    answer_en = _build_controlled_explanation_answer_en(query_text, docs or [])
    if answer_en == RAG_NO_MATCH_RESPONSE:
        return RAG_NO_MATCH_RESPONSE
    if (language or "").strip().lower() == "ar":
        translated = await _translate_controlled_explanation_answer_ar(answer_en)
        if translated:
            return translated
    return answer_en

def _safe_grounded_concise_explanation_extraction(query_text: str, docs: list[dict], max_lines: int = 2) -> str:
    source_docs = _dedup_docs_exact_text(list(docs or []))
    if not source_docs:
        return RAG_NO_MATCH_RESPONSE
    query_focus = _explanation_focus_tokens(query_text)
    if not query_focus:
        return RAG_NO_MATCH_RESPONSE
    query_features = _explanation_query_features(query_text)
    relationship_groups = _explanation_relationship_concept_groups(query_text)
    relationship_mode = bool(len(relationship_groups) >= 2)
    primary_group = relationship_groups[0] if relationship_mode else _explanation_primary_concept_group(query_text, query_focus)
    concept_groups = relationship_groups if relationship_mode else ([primary_group] if primary_group else [])
    filtered_docs = _filter_docs_for_explanation(source_docs[:8], query_text)
    if not filtered_docs:
        return RAG_NO_MATCH_RESPONSE

    scored_rows: list[tuple[float, int, str, set[int]]] = []
    for doc_rank, doc_candidate in enumerate(filtered_docs[:8]):
        doc_text = _explanation_doc_text(doc_candidate)
        for sentence_index, sentence_text in enumerate(_split_explanation_candidates(doc_text)[:30]):
            cleaned_sentence = _clean_explanation_sentence(sentence_text)
            if not _is_usable_explanation_sentence(
                cleaned_sentence,
                query_focus,
                needs_direct_cue=True,
                concept_groups=concept_groups,
                relationship_mode=relationship_mode,
                primary_group=primary_group,
            ):
                continue
            score = _score_explanation_sentence(
                cleaned_sentence,
                query_focus,
                doc_rank,
                concept_groups=concept_groups,
                relationship_mode=relationship_mode,
                primary_group=primary_group,
                query_features=query_features,
            )
            if score < (2.7 if relationship_mode else 2.9):
                continue
            scored_rows.append((score, sentence_index + (doc_rank * 1000), cleaned_sentence, _explanation_hit_group_indices(cleaned_sentence, concept_groups)))

    if not scored_rows:
        return RAG_NO_MATCH_RESPONSE
    scored_rows.sort(key=lambda row: (-row[0], row[1]))
    selected_lines: list[str] = []
    selected_groups: set[int] = set()
    direct_relationship = False
    for _score, _order, sentence_text, hit_groups in scored_rows:
        if any(_explanation_lines_too_similar(sentence_text, existing) for existing in selected_lines):
            continue
        selected_lines.append(sentence_text)
        selected_groups.update(hit_groups)
        if relationship_mode and concept_groups and len(hit_groups) >= len(concept_groups):
            direct_relationship = True
        if len(selected_lines) >= max(1, max_lines):
            break

    if not selected_lines:
        return RAG_NO_MATCH_RESPONSE
    if relationship_mode and len(concept_groups) >= 2:
        required_groups = set(range(len(concept_groups)))
        if not required_groups.issubset(selected_groups) and not direct_relationship:
            return RAG_NO_MATCH_RESPONSE
        if len(selected_lines) < 2 and not direct_relationship:
            return RAG_NO_MATCH_RESPONSE

    S.logger.info(
        "[EXPLANATION MODE] safe_concise_extraction accepted lines=%d relationship=%s focus=%s",
        len(selected_lines),
        bool(relationship_mode),
        query_focus,
    )
    return "\n".join(f"- {line}" for line in selected_lines[:max_lines]).strip() or RAG_NO_MATCH_RESPONSE

def _definition_explanation_fallback(query_text: str, docs: list[dict], entity: str = "") -> Optional[str]:
    ent = re.sub(r"\s+", " ", str(entity or "").strip())
    if not ent:
        _has_ent, extracted = _extract_entity_from_definition_query(query_text)
        ent = extracted if _has_ent else ""
    if not ent or not docs:
        return None

    try:
        recovered, _debug = _extract_structure_aware_definition(query_text, docs or [], ent)
        recovered = _clean_definition_like_sentence(recovered or "")
        if recovered and _passes_strict_definition_relevance_guard(query_text, recovered):
            return recovered
    except Exception:
        S.logger.debug("[DEFINITION FALLBACK] structure recovery failed", exc_info=True)

    for doc in docs or []:
        text = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        if not text:
            continue
        chunk_topic = _chunk_entity_dominant_topic(text, ent)
        for sent in _split_text_into_sentences(text)[:18]:
            cleaned = _clean_definition_like_sentence(sent)
            if not cleaned:
                continue
            if not _is_explanation_sentence_for_entity(cleaned, ent, chunk_is_topic=chunk_topic):
                continue
            if _passes_strict_definition_relevance_guard(query_text, cleaned):
                return cleaned
    return None

_MPC15_DEF_CUE_RE = re.compile(
    r"\b(?:is|are|refers\s+to|defined\s+as|means|"
    r"characteri[sz]ed\s+by|consists?\s+of|involves|includes|"
    r"emphasi[sz]e[sd]?|focus(?:es|ed)?\s+on|aims?\s+at|"
    r"can\s+be\s+(?:defined|described|viewed)|"
    r"is\s+a\s+type\s+of)\b",
    re.IGNORECASE,
)

_MPC15_BIO_REJECT_RE = re.compile(
    r"\b(?:born|died|coined\s+the\s+term|"
    r"\d{4}\s*[\-–—]\s*\d{4}|"
    r"contributed\s+by|proposed\s+by|developed\s+by|"
    r"introduced\s+by|founded\s+by|written\s+by|"
    r"author\s+of|sociologist|engineer|entrepreneur|"
    r"attended|graduated|quit\s+school|professional\s+journey|"
    r"father\s+of|claimed\s+that|thought\s+that)\b",
    re.IGNORECASE,
)

_MPC15_ALIAS_ONLY_RE = re.compile(
    r"^\s*(?:these\s+(?:ideas|concepts|principles|theories)\s+are\s+"
    r"(?:also\s+|alternatively\s+)?(?:referred\s+to\s+as|known\s+as|called)|"
    r"(?:also|alternatively)\s+(?:referred\s+to\s+as|known\s+as|called))\b",
    re.IGNORECASE,
)

_MPC15_GENERIC_CONCEPT_SUFFIX = {
    "theory", "model", "approach", "system",
    "method", "framework", "science", "process", "concept",
    "organization", "organisation",
}

_MPC15_BAD_ANCHOR_PREFIX_RE = re.compile(
    r"\b(?:criticism|critique|critic|limitations?|drawbacks?|"
    r"advantages?|disadvantages?|benefits?|merits?|demerits?|"
    r"applications?|examples?|impact|effects?|history|origins?|"
    r"importance|significance|features?\s+and\s+limitations?|"
    r"strengths?|weakness(?:es)?|comparison)\b",
    re.IGNORECASE,
)

_MPC15_NEXT_HEADING_RE = re.compile(
    r"\n\s*(?:[A-Z]\.\s+[A-Z][A-Za-z][^\n:]{2,80}:|"
    r"\d+\.\d+(?:\.\d+)?\s+[A-Z][^\n]{2,80}|"
    r"[A-Z][A-Za-z][A-Za-z\s]{2,40}\s+(?:Approach|Theory|Model|Method|System|Framework|Process)\s*:)"
)

def _mpc15_load_full_corpus_chunks() -> list[dict]:
    try:
        vs = getattr(S.live_rag, "vs", None)
        coll = getattr(vs, "collection", None) if vs is not None else None
        if coll is None:
            return []
        version_key = (getattr(coll, "name", ""), int(coll.count() or 0))
        cached = S._MPC15_CORPUS_CACHE.get("chunks")
        if cached is not None and S._MPC15_CORPUS_CACHE.get("version") == version_key:
            return cached
        data = coll.get(include=["documents", "metadatas"]) or {}
        docs_text = data.get("documents") or []
        metas = data.get("metadatas") or [{} for _ in docs_text]
        out: list[dict] = []
        for txt, meta in zip(docs_text, metas):
            if not txt:
                continue
            md = dict(meta or {})
            out.append({
                "page_content": str(txt),
                "text": str(txt),
                "source": md.get("source") or md.get("file") or "",
                "metadata": md,
            })
        S._MPC15_CORPUS_CACHE["chunks"] = out
        S._MPC15_CORPUS_CACHE["version"] = version_key
        S.logger.info("[STRUCT-AWARE DEF] corpus_cache_loaded count=%s", len(out))
        return out
    except Exception as e:
        S.logger.warning("[STRUCT-AWARE DEF] corpus_cache_failed: %s", e)
        return []

def _mpc15_corpus_filter_by_entity(entity: str, allowed_sources: set[str] | None = None, limit: int = 12) -> list[dict]:
    """Return chunks from the full corpus whose text mentions the entity
    stem or an entity-anchored heading, restricted to ``allowed_sources``
    when provided."""
    chunks = _mpc15_load_full_corpus_chunks()
    if not chunks:
        return []
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not e:
        return []
    e_tokens_all = [t for t in re.findall(r"[a-z0-9]+", e) if t not in {"the", "a", "an", "of", "and", "in", "to", "for"}]
    e_tokens = [t for t in e_tokens_all if t not in _MPC15_GENERIC_CONCEPT_SUFFIX] or e_tokens_all
    if not e_tokens:
        return []
    e_root = e_tokens[0]
    e_stem = e_root[:6] if len(e_root) >= 7 else e_root
    stem_re = re.compile(rf"\b{re.escape(e_stem)}[a-z]*\b", re.IGNORECASE)
    heading_re = re.compile(
        rf"(?:^|\n|\.\s)(?:elements?|principles?|characteristics?|features?|components?|nature|definition|introduction)\s+(?:of|to)\s+(?:the\s+)?{re.escape(e_stem)}[a-z]*",
        re.IGNORECASE,
    )
    # Score: heading hits ×3, stem hits ×1, all-token presence ×2.
    scored: list[tuple[float, dict]] = []
    for c in chunks:
        txt = str(c.get("page_content") or c.get("text") or "")
        if not txt:
            continue
        src = str(c.get("source") or (c.get("metadata") or {}).get("source") or "")
        if allowed_sources and src and src not in allowed_sources:
            # also try basename match — sources may be path vs basename
            import os as _os
            if _os.path.basename(src) not in {_os.path.basename(s) for s in allowed_sources}:
                continue
        stem_hits = len(stem_re.findall(txt))
        if stem_hits == 0:
            continue
        heading_hits = len(heading_re.findall(txt))
        all_tokens_present = all(re.search(rf"\b{re.escape(t)}", txt, re.IGNORECASE) for t in e_tokens)
        score = heading_hits * 3.0 + stem_hits * 1.0 + (2.0 if all_tokens_present else 0.0)
        scored.append((score, c))
    scored.sort(key=lambda x: x[0], reverse=True)
    return [c for _, c in scored[:limit]]

def _extract_structure_aware_definition(
    query_text: str, docs: list[dict], entity: str
) -> tuple[str | None, dict]:
    """Generic structure-aware definition recovery.

    Returns ``(sentence_or_None, debug_info)``. Debug info exposes the
    structural anchor that fired, the focused window preview, the
    candidate definition sentences considered, and the candidate list
    items collected from the same window. No domain-specific terms; the
    function only relies on heading shape, label colon, lettered/numbered
    list rows, and shared sentence validators.
    """
    debug: dict = {
        "structure_recovery_mode": None,
        "anchor_preview": "",
        "focused_window_preview": "",
        "candidate_definition_sentences": [],
        "candidate_definition_list_items": [],
        "final_recovery_reason": "",
    }
    docs = list(docs or [])
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not e or not docs:
        debug["final_recovery_reason"] = "no_entity_or_docs"
        return None, debug

    e_tokens_all = [t for t in re.findall(r"[a-z0-9]+", e) if t not in {"the", "a", "an", "of", "and", "in", "to", "for"}]
    e_tokens = [t for t in e_tokens_all if t not in _MPC15_GENERIC_CONCEPT_SUFFIX]
    if not e_tokens:
        e_tokens = e_tokens_all
    if not e_tokens:
        debug["final_recovery_reason"] = "empty_entity_tokens"
        return None, debug

    e_root = e_tokens[0]
    e_stem = e_root[:6] if len(e_root) >= 7 else e_root
    stem_chunk = (
        rf"{re.escape(e_stem)}[a-z]*"
        + "".join(rf"(?:\s+{re.escape(t)}[a-z]*)?" for t in e_tokens[1:3])
        + r"(?:\s+(?:model|theory|approach|system|method|framework|process|organization|organisation))?"
    )
    heading_patterns: list[tuple[str, str]] = [
        ("lettered_label", rf"(?:(?:^|\n)\s*|[\.!?•]\s+)(?:[A-Z]\.|\d+\.)\s*{stem_chunk}\s*[:\-–—]"),
        ("label_line", rf"(?:(?:^|\n)\s*|[\.!?•]\s+){stem_chunk}\s*[:\-–—](?!\s*$)"),
        ("inline_label", rf"(?<![A-Za-z0-9]){stem_chunk}\s*[:\-–—](?!\s*$)"),
        ("elements_of", rf"(?:^|\n|\.\s)(?:elements?|principles?|characteristics?|features?|components?|nature)\s+of\s+(?:the\s+)?{stem_chunk}\s*[:\-–—]"),
    ]

    def _score(s: str, sl: str) -> float:
        score = 0.0
        if re.search(r"\b(?:defined\s+as|is\s+a\s+type\s+of|characteri[sz]ed\s+by|consists?\s+of)\b", sl):
            score += 4.0
        if re.search(r"\b(?:emphasi[sz]e[sd]?|focus(?:es|ed)?\s+on|involves|includes|aims?\s+at)\b", sl):
            score += 2.0
        if re.search(rf"\b{re.escape(e)}\b", sl):
            score += 2.0
        if re.search(rf"\b{re.escape(e_stem)}[a-z]*\b", sl):
            score += 1.0
        if re.match(r"^\s*(?:it|its|this|these|the)\b", sl):
            score += 0.5
        words = re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", s)
        n = len(words)
        if 12 <= n <= 30:
            score += 1.0
        elif n > 40:
            score -= (n - 40) * 0.05
        return score

    best_overall: tuple[float, str, str] | None = None
    for d in docs[:24]:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not txt:
            continue
        # Find every anchor in the doc; pick the EARLIEST that survives the
        # bad-prefix filter so we don't skip the real concept heading just
        # because an "Elements of X:" / "Criticism of X:" appears later.
        anchor_matches: list[tuple[int, int, str, str]] = []
        for mode_name, pat in heading_patterns:
            for m in re.finditer(pat, txt, flags=re.IGNORECASE):
                pre = txt[max(0, m.start() - 40): m.start() + len(m.group(0))]
                if _MPC15_BAD_ANCHOR_PREFIX_RE.search(pre):
                    continue
                anchor_matches.append((m.start(), m.end(), m.group(0).strip(), mode_name))
        if not anchor_matches:
            continue
        anchor_matches.sort(key=lambda x: x[0])
        # Try anchors in document order; first one that yields a passing
        # candidate wins for this doc.
        for a_start, a_end, a_text, a_mode in anchor_matches[:3]:
            raw_window = txt[a_end:a_end + 1500]
            cut = _MPC15_NEXT_HEADING_RE.search(raw_window)
            window = raw_window[: cut.start()] if cut else raw_window

            sents = [
                re.sub(r"\s+", " ", s).strip()
                for s in re.split(r"(?<=[.!?])\s+|\n+", window)
                if s and s.strip()
            ][:14]
            # Defining-element list extraction. Only collect list items
            # when the anchor is of an "Elements/Features/Characteristics
            # of X" shape — those windows are the only ones where
            # following labels are semantically the entity's defining
            # parts. For other anchor modes (label_line / lettered_label
            # / inline_label), the following lines may be biographical
            # captions ("Max Weber : ...") that must NOT be treated as
            # defining elements.
            list_items: list[str] = []
            if a_mode == "elements_of":
                # True bullet markers — works whether bullets are at line
                # start or inline.
                list_items = re.findall(
                    r"(?:^|\n|\s)[•\u2022\*]\s+([^•\u2022\*\n]{8,200})",
                    window[:1500],
                )
                # Heading-like labels: short capitalised label followed
                # by ":" then descriptive prose. Anchored to start-of-
                # line OR a bullet character to avoid pulling biographical
                # name labels like "Max Weber :" out of running prose.
                for hm in re.finditer(
                    r"(?:^|\n|[•\u2022\*])\s*([A-Z][A-Za-z][A-Za-z \-/&]{2,40}?)\s*:\s+(?=[A-Z])",
                    window[:1500],
                ):
                    _label = re.sub(r"\s+", " ", hm.group(1)).strip()
                    if 1 <= len(_label.split()) <= 5 and _label.lower() != a_text.strip(" :.-\u2013\u2014").lower():
                        list_items.append(_label)
            if not debug["structure_recovery_mode"]:
                debug["structure_recovery_mode"] = a_mode
                debug["anchor_preview"] = a_text[:160]
                debug["focused_window_preview"] = re.sub(r"\s+", " ", window).strip()[:280]
            # Always merge list items from every anchor we explore — the
            # entity-defining bullets often live under an "Elements of X:"
            # anchor while the first-matched anchor (e.g. "X Model:")
            # contains only narrative prose.
            if list_items:
                _existing = debug.get("candidate_definition_list_items") or []
                _seen_li = {str(li).lower() for li in _existing}
                for li in list_items[:6]:
                    _li_clean = li.strip()[:140]
                    if _li_clean.lower() not in _seen_li:
                        _seen_li.add(_li_clean.lower())
                        _existing.append(_li_clean)
                debug["candidate_definition_list_items"] = _existing

            pronoun_led_allowed = a_mode in {"lettered_label", "label_line", "inline_label"}

            def _rank_window(_window: str) -> list[tuple[float, str]]:
                _ranked: list[tuple[float, str]] = []
                _sents = [
                    re.sub(r"\s+", " ", s).strip()
                    for s in re.split(r"(?<=[.!?])\s+|\n+", _window)
                    if s and s.strip()
                ][:24]
                for idx, s in enumerate(_sents):
                    sl = s.lower()
                    words = re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", s)
                    if len(words) < 8:
                        continue
                    if _MPC15_BIO_REJECT_RE.search(sl):
                        continue
                    if _MPC15_ALIAS_ONLY_RE.search(sl):
                        continue
                    try:
                        if _is_table_or_classification_sentence(s):
                            continue
                    except Exception:
                        pass
                    if not _MPC15_DEF_CUE_RE.search(sl):
                        continue
                    if defines_other_concept(sl, e):
                        continue
                    entity_present = bool(re.search(rf"\b{re.escape(e)}\b", sl))
                    stem_present = bool(re.search(rf"\b{re.escape(e_stem)}[a-z]*\b", sl))
                    pronoun_led = bool(re.match(r"^\s*(?:it|its|this|these|the|he|she|they)\b", sl))
                    if entity_present or stem_present:
                        pass
                    elif pronoun_led and pronoun_led_allowed and idx < 6:
                        pass
                    else:
                        continue
                    sc = _score(s, sl)
                    _ranked.append((sc, s))
                    debug["candidate_definition_sentences"].append(f"score={sc:.2f} :: {s[:200]}")
                return _ranked

            ranked = _rank_window(window)

            # Cross-chunk window extension + sub-list scan: always do
            # this for letter/label anchors so that (a) weak ranked
            # candidates can be improved with adjacent-chunk context and
            # (b) defining-element lists in the next chunk are surfaced
            # for the assembly fallback. Generic — uses chunk_index
            # adjacency only.
            do_extend = a_mode in {"lettered_label", "label_line", "inline_label", "elements_of"}
            extended = window
            if do_extend:
                meta = (d or {}).get("metadata") or {}
                src_n = str(meta.get("source") or (d or {}).get("source") or "")
                ci = meta.get("chunk_index")
                try:
                    ci = int(ci or 0) if ci is not None else None
                except Exception:
                    ci = None
                if src_n and ci is not None:
                    extended = window
                    for _adj_n in (1, 2):
                        for _cc in _mpc15_load_full_corpus_chunks():
                            _cm = (_cc or {}).get("metadata") or {}
                            if str(_cm.get("source") or "") != src_n:
                                continue
                            try:
                                if int(_cm.get("chunk_index") or -1) == ci + _adj_n:
                                    extended = extended + "\n" + str(_cc.get("page_content") or _cc.get("text") or "")
                                    break
                            except Exception:
                                continue
                    if extended != window:
                        # cap at 3500 chars; cut at next heading.
                        extended = extended[:3500]
                        _cut2 = _MPC15_NEXT_HEADING_RE.search(extended[len(window):])
                        if _cut2:
                            extended = window + "\n" + extended[len(window):][: _cut2.start()]
                        # Re-rank only if we previously had no ranked
                        # candidate; otherwise keep the in-chunk ranking.
                        if not ranked:
                            ranked = _rank_window(extended)
                            if ranked:
                                debug["focused_window_preview"] = (debug.get("focused_window_preview") or "") + " [+adjacent]"
                    # Sub-list detection on the (extended) window.
                    for sm in re.finditer(
                        rf"(?:elements?|principles?|functions?|characteristics?|components?)\s+of\s+"
                        rf"(?:the\s+)?{stem_chunk}(?:\s*[:\-\u2013\u2014]|(?=\s+\d+\s*\.))",
                        extended,
                        flags=re.IGNORECASE,
                    ):
                        sub_window = extended[sm.end(): sm.end() + 800]
                        sub_items = re.findall(
                            r"(?:^|\n|\.\s|\s|•|\u2022|\*)(?:\d+\s*\.|[a-z]\s*\.)\s+"
                            r"([A-Z][A-Za-z][A-Za-z \-,/&()]{2,80}?)\s*[\.\n]",
                            sub_window,
                        )
                        for li in sub_items[:8]:
                            _li_clean = re.sub(r"\s+", " ", li).strip(" .;,")
                            if 1 <= len(_li_clean.split()) <= 6 and len(_li_clean) >= 4:
                                _existing = debug.get("candidate_definition_list_items") or []
                                if _li_clean.lower() not in {x.lower() for x in _existing}:
                                    _existing.append(_li_clean)
                                    debug["candidate_definition_list_items"] = _existing

            if ranked:
                ranked.sort(key=lambda x: x[0], reverse=True)
                top_sc, top_s = ranked[0]
                cleaned = _cleanup_final_answer_text(re.sub(r"\s+", " ", top_s).strip())
                if cleaned and not re.search(r"[.!?]$", cleaned):
                    cleaned += "."
                if best_overall is None or top_sc > best_overall[0]:
                    best_overall = (top_sc, cleaned, a_mode)
                break  # next doc (we accepted from this doc's first viable anchor)

    # Determine assembly availability up front so we can prefer it over
    # weak ranked candidates (e.g. a low-score pronoun-led sentence that
    # would not survive the grounding check downstream).
    _list_items_now = debug.get("candidate_definition_list_items") or []
    _assembly_labels: list[str] = []
    for li in _list_items_now:
        li_clean = re.sub(r"\s+", " ", str(li or "")).strip()
        head = re.split(r"\s*[:\-\u2013\u2014]\s+", li_clean, maxsplit=1)[0].strip(" .;,•")
        if 1 <= len(head.split()) <= 6 and re.search(r"[A-Za-z]", head) and len(head) >= 4:
            _assembly_labels.append(head)
    _assembly_labels_dedup: list[str] = []
    _seen_a: set[str] = set()
    for h in _assembly_labels:
        k = h.lower()
        if k in _seen_a:
            continue
        _seen_a.add(k)
        _assembly_labels_dedup.append(h)
    _assembly_available = len(_assembly_labels_dedup) >= 3 and debug.get("structure_recovery_mode") in {
        "elements_of", "label_line", "lettered_label", "inline_label",
    }

    if best_overall is not None and not (best_overall[0] < 3.0 and _assembly_available):
        debug["final_recovery_reason"] = f"accepted_via_{best_overall[2]}"
        return best_overall[1], debug

    # Fallback C — concept + defining-list assembly.
    # Some documents don't put a defining sentence near the concept
    # heading; instead they give a heading then a bulleted list of the
    # concept's defining characteristics ("Elements of X:", "Features of
    # X:"). When the structural pass located such a list, synthesise a
    # short grounded answer by enumerating those bullet labels. This is
    # NOT generation — every label comes verbatim from the chunk.
    list_items = debug.get("candidate_definition_list_items") or []
    if list_items and debug.get("structure_recovery_mode") in {"elements_of", "label_line", "lettered_label", "inline_label"}:
        # Pull the head label of each bullet (text before ":" / "—" / "-").
        labels: list[str] = []
        for li in list_items:
            li_clean = re.sub(r"\s+", " ", str(li or "")).strip()
            head = re.split(r"\s*[:\-\u2013\u2014]\s+", li_clean, maxsplit=1)[0].strip(" .;,•")
            if 1 <= len(head.split()) <= 6 and re.search(r"[A-Za-z]", head) and len(head) >= 4:
                labels.append(head)
        # Dedupe preserving order.
        seen_l: set[str] = set()
        deduped = []
        for h in labels:
            k = h.lower()
            if k in seen_l:
                continue
            seen_l.add(k)
            deduped.append(h)
        if len(deduped) >= 3:
            # Cap to first 6 items to keep the assembled sentence focused
            # and to avoid concatenating items from sibling sub-lists
            # picked up in the extended window (which would dilute the
            # answer's groundedness).
            deduped = deduped[:6]
            entity_disp = " ".join(w.capitalize() for w in e.split())
            joined = ", ".join(deduped[:-1]) + ", and " + deduped[-1] if len(deduped) >= 2 else deduped[0]
            assembled = f"{entity_disp} is described in the document by the following defining elements: {joined}."
            debug["final_recovery_reason"] = f"accepted_via_{debug['structure_recovery_mode']}_list_assembly"
            return assembled, debug

    if not debug["structure_recovery_mode"]:
        debug["final_recovery_reason"] = "no_anchor_in_any_doc"
    else:
        debug["final_recovery_reason"] = f"anchor_{debug['structure_recovery_mode']}_no_definition"
    return None, debug

def _is_valid_definition_sentence(sentence: str, entity: str) -> bool:
    """STRICT generic validator for "what is X?" answers.

    Precision-over-recall gate: an answer is accepted only when it actually
    DEFINES the entity, not merely mentions it or attributes it to someone.
    Generic — no domain-specific terms.

    Rules:
      1. Must contain the entity (or its tokens) — surface or lemma-level.
      2. Must contain a definition cue: is / are / refers to / can be defined / means.
      3. Must NOT be attribution-only ("contributed by", "proposed by",
         "developed by", "introduced by", "founded by", "given by").
      4. Must NOT be pronoun-led ("he said", "they believed", ...).
      5. Must have at least 6 substantive word tokens.
      6. Must NOT look like a table or list fragment.
    """
    s = re.sub(r"\s+", " ", str(sentence or "").strip())
    if not s:
        return False
    sl = s.lower()
    ocr_reason = _ocr_filter_rejected_reason(s)
    if ocr_reason:
        _log_ocr_filter_rejection(s, ocr_reason)
        return False

    # 5. Length gate.
    words = re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", s)
    if len(words) < 6:
        return False

    # 6. Table / list fragment.
    try:
        if _is_table_or_classification_sentence(s):
            return False
    except Exception:
        pass

    # 1. Entity presence (surface or substantive tokens).
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if e:
        if not re.search(rf"\b{re.escape(e)}\b", sl):
            etoks = [
                t for t in re.findall(r"[a-z0-9]+", e)
                if t not in {"the", "a", "an", "of", "and", "in", "to", "for"}
            ]
            if not etoks:
                return False
            hits = sum(1 for t in etoks if re.search(rf"\b{re.escape(t)}\b", sl))
            if hits < max(1, len(etoks) - 1):
                return False

    # 2. Definition cue (incl. descriptive predicates for product definitions
    #    like "Everyday Checking has no overdraft fees").
    if not re.search(
        r"\b(?:is|are|has|have|had|refers\s+to|can\s+be\s+defined|defined\s+as|means|covers|cover|insured|insures|"
        r"include|includes|provides|provide|protects|guarantees|offers|offer|charges|charge|bills|"
        r"lets|let|allows|allow|comes\s+with|gives|give|earns|earn|pays|pay|equals|up\s+to|at\s+least|minimum|maximum)\b",
        sl,
    ):
        return False

    # 4. Pronoun-led narrative.
    if re.match(
        r"^\s*(?:he|she|they|it|we|i|you|his|her|their|its|our|my|your)\b",
        sl,
    ):
        return False

    # 3. Attribution-only patterns: "X is contributed/proposed/... by Y".
    # Reject when the predicate after "is/are" is *only* attribution and the
    # sentence contains no further descriptive content.
    attribution_pred = (
        r"\b(?:is|are|was|were)\s+(?:first\s+|originally\s+|mainly\s+)?"
        r"(?:contributed|proposed|developed|introduced|founded|given|"
        r"presented|formulated|created|written|authored|established)\s+by\b"
    )
    entity_subject = bool(e and re.search(rf"^(?:the\s+)?{re.escape(e)}\b", sl))
    if re.search(attribution_pred, sl):
        # Check whether the sentence has substantive content beyond the
        # attribution clause (e.g. "X is proposed by Y and focuses on Z").
        m = re.search(attribution_pred, sl)
        tail = sl[m.end():] if m else ""
        tail_words = re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", tail)
        # If only a person/short phrase follows the "by", treat as attribution-only.
        descriptive_cue = re.search(
            r"\b(?:and|which|that|to|for|in\s+order|focuses?\s+on|involves|includes|deals\s+with|describes|emphasi[sz]es|aims?\s+to)\b",
            tail,
        )
        if entity_subject and re.search(
            r"\b(?:method|approach|therapy|school|theory|model|process|system|framework|field|study|discipline|practice|technique|clinical|focused)\b",
            sl,
        ):
            pass
        elif not descriptive_cue or len(tail_words) < 3:
            return False
    elif entity_subject and re.search(r",\s*(?:developed|created|introduced|founded|established|proposed)\s+by\b", sl):
        pre_attr = re.split(r",\s*(?:developed|created|introduced|founded|established|proposed)\s+by\b", sl, maxsplit=1)[0]
        if len(re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", pre_attr)) < 6:
            return False

    return True

def _ws_fix_explanation_answer(query: str, answer: str, docs: list[dict]) -> str:
    raw_answer = re.sub(r"\s+", " ", str(answer or "").strip())
    not_found = "Not found in the document."
    if raw_answer and raw_answer.lower() != not_found.lower():
        if _is_attribute_lookup_query(query):
            if not _is_compact_table_answer(raw_answer):
                collapsed = _collapse_attribute_table_answer(query, raw_answer, docs)
                if collapsed:
                    return collapsed
            return raw_answer
        if _is_support_procedural_query(query) and len(raw_answer) >= 20:
            return raw_answer
    is_definition_comparison_mode = _is_definition_comparison_query(query)
    if S._doc_router_implies_comparison(query) and not is_definition_comparison_mode:
        return _cleanup_final_answer_text(str(answer or "").strip())
    raw_answer = re.sub(r"\s+", " ", str(answer or "").strip())
    if is_definition_comparison_mode:
        ans = _cleanup_definition_comparison_answer_text(raw_answer)
    else:
        ans = _cleanup_final_answer_text(raw_answer)
    is_explain_mode = _is_ws_explain_query_mode(query)
    is_definition_mode = _is_ws_definition_query_mode(query)
    if not (is_explain_mode or is_definition_mode):
        return ans

    has_entity, entity = _extract_entity_from_definition_query(query)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower()) if has_entity else ""

    # MP-C7: drop trailing transition-only fragments and tiny orphan tails
    # that survived upstream extraction (e.g. "To put it another way.",
    # "In other words.", "i.e."). Pure structural English connective cues
    # plus a short-orphan rule — applies regardless of document domain.
    def _mpc7_polish_definition_tail(text: str) -> str:
        s = str(text or "").strip()
        if not s:
            return s
        # Quote-aware sentence split: split on .!? optionally followed by a
        # closing quote, then whitespace, then a capital letter. The shared
        # `_split_text_into_sentences` does NOT split on `."` (period inside
        # closing quote) which is exactly the shape that lets transition
        # tails like "...way." To put it another way." survive upstream.
        _split_re = re.compile(r"(?<=[.!?])[\"'\u201c\u2018\u2019\u201d`]?\s+(?=[A-Z])")
        sents = [p.strip() for p in _split_re.split(s) if p and p.strip()]
        if len(sents) <= 1:
            return s
        _trans_re = re.compile(
            r"^\s*[\"'\u201c\u2018\u2019\u201d`]?\s*"
            r"(?:in\s+other\s+words|to\s+put\s+it\s+(?:another|differently)\s+way|"
            r"put\s+(?:it\s+)?(?:another\s+way|simply|differently)|"
            r"that\s+is(?:\s+to\s+say)?|"
            r"in\s+short|in\s+essence|in\s+summary|to\s+summari[sz]e|"
            r"simply\s+put|stated\s+(?:simply|differently)|"
            r"in\s+plain\s+terms|namely|alternatively|"
            r"i\.?\s*e\.?|e\.?\s*g\.?)\b[^A-Za-z0-9]*$",
            flags=re.IGNORECASE,
        )
        # Iteratively drop trailing transition-only sentences AND short
        # orphan tails (≤6 substantive words) that lack the queried entity.
        while len(sents) > 1:
            tail = sents[-1].strip()
            tail_words = re.findall(r"[A-Za-z][A-Za-z0-9'\-]*", tail)
            tail_low = tail.lower()
            short_orphan = len(tail_words) <= 6
            entity_in_tail = bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", tail_low))
            if _trans_re.match(tail) or (short_orphan and not entity_in_tail):
                sents.pop()
                continue
            break
        out = " ".join(
            (k.rstrip(" ,;:-") + ("" if re.search(r"[.!?]$", k) else "."))
            for k in sents if k
        )
        return _cleanup_final_answer_text(out)

    if ans and ans.lower() != not_found.lower() and not is_definition_comparison_mode:
        _polished = _mpc7_polish_definition_tail(ans)
        if _polished:
            ans = _polished

    if not entity_l:
        if ans and ans.lower() != not_found.lower() and _is_answer_grounded_in_docs(ans, docs or [], query_text=query) and _passes_strict_definition_relevance_guard(query, ans):
            S.logger.info("[WS FIXED ANSWER] mode=preserve_validated_no_entity answer=%s", ans[:220])
            return ans
        return not_found

    def _entity_grounded_in_text(text_l: str) -> bool:
        if not entity_l:
            return True
        if re.search(rf"\b{re.escape(entity_l)}\b", text_l):
            return True
        etoks = [t for t in re.findall(r"[a-z0-9]{2,}", entity_l) if t not in {"the", "a", "an", "of", "and", "in", "to"}]
        generic_entity_tokens = {"approach", "theory", "method", "model", "system", "concept", "perspective", "school", "view"}
        match_tokens = [t for t in etoks if t not in generic_entity_tokens] or etoks
        token_hits = sum(1 for t in match_tokens if re.search(rf"\b{re.escape(t)}\b", text_l))
        return token_hits >= 1

    if is_definition_comparison_mode:
        if (
            ans
            and ans.lower() != not_found.lower()
            and _entity_grounded_in_text(ans.lower())
            and _is_answer_grounded_in_docs(ans, docs or [], query_text=query)
            and not _ocr_filter_rejected_reason(ans, query)
        ):
            S.logger.info("[WS FIXED ANSWER] mode=preserve_definition_comparison answer=%s", ans[:220])
            return ans
        comparison_answer = _extract_definition_comparison_answer(query, docs or [])
        if comparison_answer:
            S.logger.info("[WS FIXED ANSWER] mode=definition_comparison_route answer=%s", comparison_answer[:220])
            return comparison_answer
        return not_found

    if is_definition_mode and ans and ans.lower() != not_found.lower():
        ans_l = ans.lower()
        # MP-C15: structure-recovery assembled answers have a fixed
        # signature ("X is described in the document by the following
        # defining elements: ...") and were already grounded against
        # the wider corpus pool by the structure-aware route. Trust
        # them here so the strict definition-sentence validator does
        # not wipe a properly-recovered list-assembly answer.
        if re.search(r"\bis\s+described\s+in\s+the\s+document\s+by\s+the\s+following\s+defining\s+elements\s*:", ans_l):
            S.logger.info("[WS FIXED ANSWER] mode=preserve_structure_recovery answer=%s", ans[:220])
            return ans
        if (
            _entity_grounded_in_text(ans_l)
            and _is_answer_grounded_in_docs(ans, docs or [], query_text=query)
            and _passes_strict_definition_relevance_guard(query, ans)
            and _is_valid_definition_sentence(ans, entity_l)
        ):
            S.logger.info("[WS FIXED ANSWER] mode=preserve_validated answer=%s", ans[:220])
            return ans
        if entity_l:
            S.logger.info("[DEF QUALITY REJECT] mode=preserve_validated entity=%s preview=%s", entity_l, ans[:160])

    def _finalize_definition_output(text: str) -> str:
        s = _cleanup_final_answer_text(re.sub(r"\s+", " ", str(text or "").strip()))
        if not s:
            return not_found
        s = re.sub(r"^\s*(?:earlier\s+schools?\s+of\s+thought|schools?\s+of\s+thought|important\s+terminology)\s*[:\-–—]*\s*", "", s, flags=re.IGNORECASE)
        if entity_l:
            m = re.search(rf"\b{re.escape(entity_l)}\b", s, flags=re.IGNORECASE)
            if m and m.start() > 0:
                left = s[: m.start()].strip()
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", left)) <= 8:
                    s = s[m.start():].strip()

        sents = [re.sub(r"\s+", " ", x).strip() for x in _split_text_into_sentences(s) if re.sub(r"\s+", " ", x).strip()]
        if not sents:
            return not_found

        def _is_complete_sentence(sent: str, require_entity: bool = True) -> bool:
            ss = re.sub(r"\s+", " ", str(sent or "").strip())
            if not ss:
                return False
            if _is_incomplete_fragment_sentence(ss):
                return False
            if re.match(r"^\s*(?:motivated\s+by|characterized\s+by|focused\s+on|based\s+on|influenced\s+by|driven\s+by|resulting\s+from|because\s+of|as\s+a\s+result\s+of)\b", ss, flags=re.IGNORECASE):
                return False
            words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", ss)
            if len(words) < 8:
                return False
            if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from|because|however|therefore|thus|then)\b\s*$", ss.lower()):
                return False
            if not re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|describes|explains|studies)\b", ss.lower()):
                return False
            if require_entity and entity_l and not re.search(rf"\b{re.escape(entity_l)}\b", ss, flags=re.IGNORECASE):
                return False
            return True

        def _repair_telegraphic_definition(sent: str) -> str:
            s2 = re.sub(r"\s+", " ", str(sent or "").strip())
            if not s2:
                return s2
            if not entity_l:
                return s2
            if re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on)\b", s2, flags=re.IGNORECASE):
                return s2
            ent = re.escape(entity_l)
            if re.match(rf"^\s*(?:the\s+)?{ent}\s*[:\-]?\s+the\b", s2, flags=re.IGNORECASE):
                s2 = re.sub(rf"^\s*((?:the\s+)?{ent})\s*[:\-]?\s+", r"\1 is ", s2, flags=re.IGNORECASE)
            elif re.match(rf"^\s*(?:the\s+)?{ent}\s+[A-Za-z]", s2, flags=re.IGNORECASE):
                s2 = re.sub(rf"^\s*((?:the\s+)?{ent})\s+", r"\1 is ", s2, flags=re.IGNORECASE)
            s2 = re.sub(r"\bis\s+The\b", "is the", s2)
            return s2

        def _enforce_one_sentence_25_35(seed: str, pool: list[str]) -> str:
            min_words = 25
            max_words = 35
            seed_words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", seed)
            if len(seed_words) >= min_words:
                clipped = " ".join(seed_words[:max_words]).strip(" ,;:-")
                return clipped.rstrip(" ,;:-") + "."

            base = re.sub(r"[.!?]+\s*$", "", seed).strip(" ,;:-")
            additions: list[str] = []
            current_words = list(seed_words)
            for cand in pool:
                c = re.sub(r"\s+", " ", str(cand or "").strip())
                if not c or c.lower() == seed.lower():
                    continue
                if not _is_complete_sentence(c, require_entity=False):
                    continue
                c = re.sub(r"^[A-Za-z][A-Za-z0-9'\-]*\s+(?:is|are|refers\s+to|defined\s+as|means)\s+", "", c, flags=re.IGNORECASE)
                c = re.sub(r"^[Tt]his\s+(?:approach|theory|model|process)\s+", "", c)
                c = re.sub(r"^[Ii]t\s+", "", c)
                c = re.sub(r"[.!?]+\s*$", "", c).strip(" ,;:-")
                c_words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", c)
                if len(c_words) < 5:
                    continue
                if len(current_words) + len(c_words) > max_words:
                    remaining = max_words - len(current_words)
                    if remaining >= 5:
                        c_words = c_words[:remaining]
                        c = " ".join(c_words)
                    else:
                        continue
                additions.append(c)
                current_words.extend(c_words)
                if len(current_words) >= min_words:
                    break

            sentence = base
            if additions:
                sentence = base + ", " + ", ".join(additions)
            out_words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", sentence)
            if len(out_words) > max_words:
                sentence = " ".join(out_words[:max_words]).strip(" ,;:-")
            if not re.search(r"[.!?]$", sentence):
                sentence = sentence.rstrip(" ,;:-") + "."
            return sentence

        def _sent_score(sent: str) -> float:
            sent = _repair_telegraphic_definition(sent)
            low = sent.lower()
            if _is_incomplete_fragment_sentence(sent):
                return -10**9
            if not _is_complete_sentence(sent):
                return -10**9
            if re.match(r"^\s*(?:motivated\s+by|characterized\s+by|focused\s+on|based\s+on|influenced\s+by|driven\s+by)\b", low):
                return -10**9
            score = 0.0
            if entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low):
                score += 2.0
            if re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|characterized\s+by)\b", low):
                score += 2.2
            if re.search(r"\b(?:approach|theory|model|process|study|system|framework)\b", low):
                score += 0.8
            if re.search(r"\b(?:born|died|introduced\s+by|developed\s+by|founded|histor(?:y|ical)|century|in\s+\d{3,4})\b", low):
                score -= 2.0
            if re.search(r"\b(?:believed|famous|educator|founder|stimulus\s+response)\b", low):
                return -10**9
            if re.search(r"\bby\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", sent):
                score -= 1.5
            if re.search(r"\b(?:in\s+dividual|for\s+mula)\b", low):
                score -= 1.6
            if entity_l:
                ent_m = re.search(rf"\b{re.escape(entity_l)}\b", low)
                cue_m = re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on)\b", low)
                if ent_m and cue_m:
                    if abs(ent_m.start() - cue_m.start()) > 80:
                        return -10**9
            words = len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", sent))
            if words > 34:
                score -= min(2.0, (words - 34) * 0.1)
            return score

        ranked_local = sorted([(float(_sent_score(ss)), _repair_telegraphic_definition(ss)) for ss in sents[:5]], key=lambda x: x[0], reverse=True)
        best_score_local, best = ranked_local[0]

        if best_score_local < 1.6:
            rescue_pool: list[tuple[float, str]] = []
            for d in (docs or [])[:5]:
                txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
                if not txt.strip():
                    continue
                for rs in _split_text_into_sentences(txt)[:24]:
                    rs_clean = _clean_definition_like_sentence(rs)
                    if not rs_clean:
                        continue
                    rs_low = rs_clean.lower()
                    if entity_l and not re.search(rf"\b{re.escape(entity_l)}\b", rs_low):
                        continue
                    if not re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|characterized\s+by)\b", rs_low):
                        continue
                    rs_clean = _repair_telegraphic_definition(rs_clean)
                    sc = _sent_score(rs_clean)
                    if sc <= -10**8:
                        continue
                    rescue_pool.append((sc, rs_clean))
            if rescue_pool:
                rescue_pool.sort(key=lambda x: x[0], reverse=True)
                best = rescue_pool[0][1]

        support_pool: list[str] = [x for x in sents[:6] if x]
        for d in (docs or [])[:4]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
            if not txt.strip():
                continue
            for rs in _split_text_into_sentences(txt)[:18]:
                rs_clean = _clean_definition_like_sentence(rs)
                if rs_clean:
                    support_pool.append(rs_clean)

        best = _repair_telegraphic_definition(best)
        best = _enforce_one_sentence_25_35(best, support_pool)
        best = _cleanup_final_answer_text(best)
        if not _is_complete_sentence(best):
            return not_found
        return best

    if is_definition_mode:
        doc_rescue = _extract_best_scored_concept_sentence_from_docs(query, docs or [], max_docs=3)
        if not doc_rescue:
            doc_rescue = _extract_simple_definition_sentence(query, docs or [])
        if (not doc_rescue) and entity_l:
            for d in (docs or [])[:3]:
                txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
                if not txt.strip():
                    continue
                for rs in _split_text_into_sentences(txt)[:24]:
                    rs_clean = _clean_definition_like_sentence(rs)
                    if not rs_clean:
                        continue
                    rs_low = rs_clean.lower()
                    if not re.search(rf"\b{re.escape(entity_l)}\b", rs_low):
                        continue
                    if _looks_table_or_heading_like_chunk(rs_clean):
                        continue
                    if len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", rs_clean)) < 8:
                        continue
                    doc_rescue = rs_clean
                    break
                if doc_rescue:
                    break
        doc_rescue = _cleanup_final_answer_text(re.sub(r"\s+", " ", str(doc_rescue or "")).strip())

        # MP-C12 — Reject doc_rescue extractions that look like a TOC/heading
        # row (e.g. "Introduction Concepts ... Criticism of X Theory") with no
        # verb predicate. Such fragments only contain the entity surface form
        # but no definition cue; downstream grounding/strict-guard let them
        # through, then the validator nullifies them. Falls through to the
        # indirect-evidence rescue below. Generic — no domain words.
        def _looks_like_structural_fragment(text: str) -> bool:
            t = re.sub(r"\s+", " ", str(text or "").strip())
            if not t:
                return True
            tl = t.lower()
            has_def_cue = bool(re.search(
                r"\b(?:is|are|was|were|refers\s+to|defined\s+as|means|involves|"
                r"includes|focuses\s+on|consists\s+of|comprises|describes|"
                r"characterized\s+by|known\s+as|deals\s+with|works|operates?)\b",
                tl,
            ))
            if has_def_cue:
                return False
            if _is_table_or_classification_sentence(t):
                return True
            # Heuristic: many capitalised tokens with no verb suggests a
            # heading/index row stitched by OCR.
            cap_tokens = len(re.findall(r"\b[A-Z][A-Za-z]+\b", t))
            total_tokens = len(re.findall(r"[A-Za-z]+", t))
            if total_tokens >= 6 and cap_tokens >= max(4, int(total_tokens * 0.4)):
                return True
            return False

        if doc_rescue and _looks_like_structural_fragment(doc_rescue):
            S.logger.info("[DOC RESCUE REJECT STRUCTURAL] preview=%s", doc_rescue[:160])
            doc_rescue = ""

        if doc_rescue and _is_answer_grounded_in_docs(doc_rescue, docs or [], query_text=query) and _passes_strict_definition_relevance_guard(query, doc_rescue) and _is_valid_definition_sentence(doc_rescue, entity_l):
            S.logger.info("[WS FIXED ANSWER] mode=doc_rescue extracted=%s", doc_rescue[:220])
            return _finalize_definition_output(doc_rescue)
        if doc_rescue and entity_l:
            S.logger.info("[DEF QUALITY REJECT] mode=doc_rescue entity=%s preview=%s", entity_l, doc_rescue[:160])

        # MP-C13 — Definition queries are deterministic-or-fail. The previous
        # indirect-evidence rescue (MP-C12) was relaxed to surface narrative
        # prose like "He claimed that ..." which is mention, not definition.
        # Per task: we accept missing answers rather than wrong answers.
        # When no sentence passes _is_valid_definition_sentence, fall through
        # to not_found below.
        if entity_l and is_definition_mode:
            return not_found

    routed_answer = _extract_definition_route_answer(query, docs)
    if routed_answer:
        S.logger.info("[WS FIXED ANSWER] mode=route extracted=%s", routed_answer[:220])
        return _finalize_definition_output(routed_answer) if is_definition_mode else routed_answer

    generic_answer = _build_grounded_llm_answer(query, docs)
    if generic_answer:
        _family_v2_for_generic = _classify_query_family_v2(query)
        if _family_v2_for_generic not in {"definition_entity", "definition_comparison", "list_entity", "explanatory_compare", "fact_entity"} and not _should_allow_generic_answer(query, docs or [], _family_v2_for_generic, "ws_fix_generic_extracted"):
            S.logger.info("[ANSWER BLOCKED] reason=low_confidence_generic")
            return not_found
        S.logger.info("[WS FIXED ANSWER] mode=generic extracted=%s", generic_answer[:220])
        return _finalize_definition_output(generic_answer) if is_definition_mode else generic_answer

    def _final_clean(text: str) -> str:
        out = clean_ocr_noise(re.sub(r"\s+", " ", str(text or "").strip()))
        out = re.sub(r"\s+([,.;:!?])", r"\1", out)
        out = re.sub(r"\b(\w+)\s+\1\b", r"\1", out, flags=re.IGNORECASE)
        if out and not re.search(r"[.!?]\s*$", out):
            out = out.rstrip(" ,;:-") + "."
        return out

    def _entity_hit(sentence: str) -> bool:
        sl = str(sentence or "").lower()
        return bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", sl))

    def _has_definition_signal(sentence: str) -> bool:
        sl = str(sentence or "").lower()
        return bool(re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|involves|includes|focuses\s+on|works|operates?)\b", sl))

    def _has_explain_signal(sentence: str) -> bool:
        sl = str(sentence or "").lower()
        return bool(re.search(r"\b(?:works?|operates?|process|mechanism|involves|includes|causes|results?\s+in|leads?\s+to)\b", sl))

    heading_like_re = re.compile(
        r"\b(?:important\s+terminology|terminology|introduction|overview|summary|contents?|table\s+of\s+contents|chapter\s+\d+|unit\s+\d+|lesson\s+\d+)\b",
        flags=re.IGNORECASE,
    )

    def _looks_heading_like(sentence: str) -> bool:
        s = re.sub(r"\s+", " ", str(sentence or "")).strip()
        if not s:
            return True
        if heading_like_re.search(s):
            return True
        if re.match(r"^\s*[A-Z][A-Za-z0-9\s\-,:]{3,120}\s*$", s) and not re.search(r"[.!?]$", s):
            return True
        return False

    def _is_fragmentary_garbage(sentence: str) -> bool:
        s = str(sentence or "").strip()
        if not s:
            return True
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
        if len(words) < 5:
            return True
        if re.search(r"(?:\b[A-Za-z]\s+){4,}\b", s):
            return True
        if re.search(r"\b(?:www\.|https?://|isbn|copyright|table\s*\d+|figure\s*\d+)\b", s, flags=re.IGNORECASE):
            return True
        return False

    def _is_incomplete_definition_fragment(sentence: str) -> bool:
        s = re.sub(r"\s+", " ", str(sentence or "").strip())
        if not s:
            return True
        if _is_incomplete_fragment_sentence(s):
            return True
        low = s.lower()
        if re.match(r"^\s*(?:motivated\s+by|characterized\s+by|focused\s+on|based\s+on|influenced\s+by|driven\s+by|resulting\s+from|because\s+of|as\s+a\s+result\s+of)\b", low):
            return True
        return False

    def _entity_hit_in_local_window(sentences: list[str], idx: int) -> bool:
        for j in range(max(0, idx - 1), min(len(sentences), idx + 2)):
            if _entity_hit(sentences[j]):
                return True
        return False

    def _entity_definition_cue_local(sentence: str) -> bool:
        sl = str(sentence or "").lower()
        if not _entity_hit(sentence):
            return False
        cue_m = re.search(r"\b(?:is|are|refers\s+to|defined\s+as|means|is\s+the\s+study\s+of)\b", sl)
        ent_m = re.search(rf"\b{re.escape(entity_l)}\b", sl) if entity_l else None
        if not cue_m or not ent_m:
            return False
        return abs(cue_m.start() - ent_m.start()) <= 80

    strict_answer_lock = False
    if is_definition_mode and ans and ans.lower() != not_found.lower():
        if (
            _entity_hit(ans)
            and _has_definition_signal(ans)
            and _entity_definition_cue_local(ans)
            and (not _looks_heading_like(ans))
            and (not _is_fragmentary_garbage(ans))
            and (not _is_incomplete_definition_fragment(ans))
            and (not re.search(r"\b(?:believed|famous|educator|founder|introduced\s+by|developed\s+by|born|died|stimulus\s+response)\b", ans, flags=re.IGNORECASE))
            and (not re.search(r"\b(?:in\s+dividual|for\s+mula)\b", ans, flags=re.IGNORECASE))
            and _passes_strict_definition_relevance_guard(query, ans)
        ):
            strict_answer_lock = True
            S.logger.info("[STRICT DEFINITION WINNER CHOSEN] source=current_answer answer=%s", str(ans)[:220])

    ranked_docs = sorted(list(docs or []), key=lambda x: float((x or {}).get("score", 0.0) or 0.0), reverse=True)
    candidates: list[tuple[float, str, int, int]] = []

    for doc_rank, d in enumerate(ranked_docs[:5]):
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not txt.strip():
            continue
        base_score = float((d or {}).get("score", 0.0) or 0.0)
        sents = [_clean_definition_like_sentence(s) for s in _split_text_into_sentences(txt)[:28]]
        sents = [re.sub(r"\s+", " ", str(s or "").strip()) for s in sents if str(s or "").strip()]

        for sent_idx, s in enumerate(sents):
            if not _entity_hit_in_local_window(sents, sent_idx):
                continue
            if len(re.findall(r"[a-zA-Z0-9][a-zA-Z0-9'\-]*", s)) < 5:
                continue
            if _looks_heading_like(s):
                continue
            if _is_fragmentary_garbage(s):
                continue
            if _is_incomplete_definition_fragment(s):
                continue

            if is_definition_mode and not _has_definition_signal(s):
                continue
            if is_explain_mode and not (_has_definition_signal(s) or _has_explain_signal(s)):
                continue

            score = base_score + 2.0 + (0.4 if _has_definition_signal(s) else 0.0) + (0.3 if _has_explain_signal(s) else 0.0) - (0.01 * sent_idx) - (0.001 * doc_rank)
            if is_definition_mode:
                if _entity_definition_cue_local(s):
                    score += 1.3
                else:
                    score -= 0.8
                if re.search(r"\b(?:born|died|introduced\s+by|developed\s+by|founded|histor(?:y|ical)|century|in\s+\d{3,4})\b", s, flags=re.IGNORECASE):
                    score -= 1.4
                if re.search(r"\bby\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", s):
                    score -= 1.2
                wc = len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", s))
                if wc > 34:
                    score -= min(2.0, (wc - 34) * 0.08)
            candidates.append((score, s, doc_rank, sent_idx))

    if candidates:
        candidates.sort(key=lambda x: x[0], reverse=True)
        best_score, best_sent, best_doc_rank, best_sent_idx = candidates[0]
        out_parts = [best_sent]

        if is_explain_mode:
            txt = str((ranked_docs[best_doc_rank] or {}).get("page_content") or (ranked_docs[best_doc_rank] or {}).get("text") or (ranked_docs[best_doc_rank] or {}).get("content") or "")
            sents = [_clean_definition_like_sentence(s) for s in _split_text_into_sentences(txt)[:28]]
            sents = [re.sub(r"\s+", " ", str(s or "").strip()) for s in sents if str(s or "").strip()]
            for nxt in sents[best_sent_idx + 1: best_sent_idx + 3]:
                if re.match(r"^\s*(it|this|these|they|the\s+concept)\b", nxt.lower()) and (_has_definition_signal(nxt) or _has_explain_signal(nxt)):
                    out_parts.append(nxt)
                    break

        final_out = _final_clean(" ".join(out_parts[:2]))
        if strict_answer_lock and final_out and re.sub(r"\s+", " ", final_out).strip().lower() != re.sub(r"\s+", " ", ans).strip().lower():
            S.logger.info("[LATE OVERRIDE BLOCKED] reason=strict_definition_priority kept=%s blocked=%s", str(ans)[:180], str(final_out)[:180])
            locked = _cleanup_final_answer_text(_final_clean(ans))
            return _finalize_definition_output(locked) if is_definition_mode else locked
        S.logger.info("[FINAL GROUNDED ANSWER] mode=%s entity=%s score=%.3f answer=%s", "definition" if is_definition_mode else "explain", entity_l, best_score, final_out[:220])
        out = _cleanup_final_answer_text(final_out)
        return _finalize_definition_output(out) if is_definition_mode else out

    if ans and ans.lower() != not_found.lower() and _entity_hit(ans):
        if (is_definition_mode and _has_definition_signal(ans)) or (is_explain_mode and (_has_definition_signal(ans) or _has_explain_signal(ans))):
            out = _cleanup_final_answer_text(_final_clean(ans))
            return _finalize_definition_output(out) if is_definition_mode else out

    return not_found

def _best_term_explanation_from_docs(term: str, docs: list[dict]) -> tuple[str, dict] | tuple[None, None]:
    t = re.sub(r"\s+", " ", str(term or "").strip().lower())
    if not t or not docs:
        return None, None
    ttoks = [x for x in re.findall(r"[a-z0-9]{3,}", t) if x not in {"the", "and", "of"}]
    best: tuple[float, str, dict] | None = None
    for d in (docs or [])[:5]:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        md = dict((d or {}).get("metadata") or {})
        if not txt.strip():
            continue
        for sent in _split_text_into_sentences(txt)[:14]:
            s = _clean_definition_like_sentence(sent)
            sl = s.lower()
            if _is_definition_boilerplate_sentence(s):
                continue
            if len(s) > 200:
                continue
            if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", s, flags=re.IGNORECASE):
                continue
            if s.count("•") >= 1 or re.search(r"\btable\b|\bfigure\b", sl):
                continue
            if re.search(r"\b(?:one\s+of\s+the\s+components?|listed\s+with|associating\s+model|the\s+answers\s+to\s+all\s+these\s+questions\s+can\s+be\s+found|answers\s+to\s+all\s+these\s+questions)\b", sl):
                continue
            token_hits = sum(1 for tok in ttoks if re.search(rf"\b{re.escape(tok)}\b", sl))
            if token_hits < max(1, min(2, len(ttoks))):
                continue
            if not re.search(r"\b(?:is|refers\s+to|means|involves|focuses\s+on|includes|characterized\s+by|uses|forms\s+an\s+association|associates)\b", sl):
                continue
            score = float(token_hits) + (1.0 if re.search(r"\b(is|refers\s+to|means)\b", sl) else 0.0)
            if best is None or score > best[0]:
                best = (score, s, md)
    if best is None:
        for d in (docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            md = dict((d or {}).get("metadata") or {})
            if not txt.strip():
                continue
            for sent in _split_text_into_sentences(txt)[:18]:
                s = _clean_definition_like_sentence(sent)
                sl = s.lower()
                if len(s) < 30 or len(s) > 220:
                    continue
                if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", s, flags=re.IGNORECASE):
                    continue
                if re.search(r"\b(?:one\s+of\s+the\s+components?|listed\s+with|associating\s+model|the\s+answers\s+to\s+all\s+these\s+questions\s+can\s+be\s+found|answers\s+to\s+all\s+these\s+questions)\b", sl):
                    continue
                token_hits = sum(1 for tok in ttoks if re.search(rf"\b{re.escape(tok)}\b", sl))
                if token_hits < max(1, min(2, len(ttoks))):
                    continue
                return s, md
        return None, None
    return best[1], best[2]

def _is_comparison_table_evidence(text: str, metadata: dict | None = None) -> bool:
    raw = str(text or "")
    meta = dict(metadata or {})
    if "[TABLE DATA]" in raw:
        return True
    if str(meta.get("chunk_role") or "").lower() == "table":
        return True
    if raw.count("|") >= 5:
        return True
    pipe_lines = [
        ln.strip()
        for ln in raw.splitlines()
        if "|" in ln and ln.count("|") >= 2 and len(ln.strip()) >= 8
    ]
    return len(pipe_lines) >= 2

def _entity_row_match_score(entity: str, row_text: str) -> float:
    entity_tokens = [
        token
        for token in re.findall(r"[a-z0-9]{2,}", str(entity or "").lower())
        if token not in {"the", "and", "of", "for", "with", "from"}
    ]
    if not entity_tokens:
        return -1000.0
    low = str(row_text or "").lower()
    hits = sum(1 for token in entity_tokens if re.search(rf"\b{re.escape(token)}\b", low))
    phrase = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    phrase_bonus = 2.0 if phrase and re.search(rf"\b{re.escape(phrase)}\b", low) else 0.0
    return phrase_bonus + (2.0 * hits / max(1, len(entity_tokens)))

def _extract_comparison_table_rows(docs: list[dict], entities: list[str]) -> dict[str, str]:
    best_rows: dict[str, tuple[float, str]] = {}
    for doc in docs or []:
        meta = dict((doc or {}).get("metadata") or {})
        text = str((doc or {}).get("page_content") or (doc or {}).get("text") or "").strip()
        if not text or not _is_comparison_table_evidence(text, meta):
            continue
        for line in text.splitlines():
            line = line.strip()
            if "|" not in line or line.count("|") < 2:
                continue
            for entity in entities:
                score = _entity_row_match_score(entity, line)
                if score <= 0:
                    continue
                prev = best_rows.get(entity)
                if prev is None or score > prev[0]:
                    best_rows[entity] = (score, re.sub(r"\s+", " ", line).strip())
    return {entity: value[1] for entity, value in best_rows.items()}

def _compare_answer_from_docs_strict(query: str, docs: list[dict]) -> str | None:
    docs = _enrich_docs_with_collection_pipe_tables(_anchor_compare_docs_to_table_source(list(docs or [])))
    entities = _compare_entities_from_query(query)
    compare_all_tokens = _compare_all_class_tokens(query)
    if len(entities) < 2 and compare_all_tokens:
        entities = _discover_compare_entities_from_tables(docs, compare_all_tokens)
        if len(entities) >= 2:
            try:
                S.logger.info("[COMPARE ENTITIES] entities=%s source=table_discovery", entities[:6])
            except Exception:
                pass
    if len(entities) < 2:
        return None
    left, right = entities[0], entities[1]

    structured = _format_structured_table_comparison(docs, entities)
    if structured:
        S.logger.info("[COMPARE TABLE EVIDENCE] entities=%s rows=structured", entities)
        return structured

    table_rows = _extract_comparison_table_rows(docs, entities)
    if len(table_rows) >= min(2, len(entities)):
        structured_fallback = _format_structured_table_comparison(docs, entities)
        if structured_fallback:
            S.logger.info("[COMPARE TABLE EVIDENCE] entities=%s rows=%s", entities, len(table_rows))
            return structured_fallback

    if _collect_pipe_table_texts(docs):
        enriched_docs = _enrich_docs_with_collection_pipe_tables(docs)
        structured_retry = _format_structured_table_comparison(enriched_docs, entities)
        if structured_retry:
            S.logger.info("[COMPARE TABLE EVIDENCE] entities=%s rows=structured_retry", entities)
            return structured_retry
        S.logger.info("[COMPARE] table_evidence_present synthesis_suppressed entities=%s", entities[:6])
        return None

    S.logger.info("[COMPARE ENTITIES] left=%s right=%s source=query", left, right)
    S.logger.info("[SYNTHESIS MODE] active=True entities=%s", entities)

    def _entity_tokens(entity: str) -> list[str]:
        return [
            token
            for token in re.findall(r"[a-z0-9]{2,}", str(entity or "").lower())
            if token not in {"the", "and", "of", "for", "with", "from"}
        ]

    def _has_entity_phrase(text_value: str, entity: str) -> bool:
        entity_phrase = re.sub(r"\s+", " ", str(entity or "").strip().lower())
        if not entity_phrase:
            return False
        return bool(re.search(rf"\b{re.escape(entity_phrase)}\b", str(text_value or "").lower()))

    def _token_hits(text_value: str, tokens: list[str]) -> int:
        low_text = str(text_value or "").lower()
        return sum(1 for token in tokens if re.search(rf"\b{re.escape(token)}\b", low_text))

    def _doc_source_label(doc: dict | None) -> str:
        metadata = dict((doc or {}).get("metadata") or {}) if isinstance(doc, dict) else {}
        source = (
            metadata.get("display_source")
            or metadata.get("source_file")
            or metadata.get("source")
            or metadata.get("file_name")
            or metadata.get("filename")
            or "unknown"
        )
        page = metadata.get("page") or metadata.get("page_number")
        chunk = metadata.get("chunk_index") or metadata.get("chunk_id")
        pieces = [str(source)]
        if page not in (None, ""):
            pieces.append(f"p={page}")
        if chunk not in (None, ""):
            pieces.append(f"chunk={chunk}")
        return " ".join(pieces)

    def _dedupe_compare_docs(source_docs: list[dict]) -> list[dict]:
        output: list[dict] = []
        seen: set[str] = set()
        for source_doc in source_docs or []:
            text_value = str(
                (source_doc or {}).get("page_content")
                or (source_doc or {}).get("text")
                or (source_doc or {}).get("content")
                or ""
            )
            fingerprint = re.sub(r"\s+", " ", text_value).strip().lower()[:500]
            if not fingerprint or fingerprint in seen:
                continue
            seen.add(fingerprint)
            output.append(source_doc)
        return output

    def _score_entity_doc(doc: dict, entity: str, other_entity: str) -> float:
        text_value = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        entity_token_list = _entity_tokens(entity)
        other_token_list = _entity_tokens(other_entity)
        if not text_value.strip() or not entity_token_list:
            return -1000.0
        score = 0.0
        entity_hits = _token_hits(text_value, entity_token_list)
        other_hits = _token_hits(text_value, other_token_list)
        if _has_entity_phrase(text_value, entity):
            score += 4.0
        if entity_token_list:
            score += 2.4 * (entity_hits / max(1, len(entity_token_list)))
        if _doc_has_explanation_for_entity(text_value, entity):
            score += 4.0
        try:
            if _chunk_entity_dominant_topic(text_value, entity):
                score += 1.5
        except Exception:
            pass
        try:
            if _is_wrong_concept_definition_chunk(text_value, entity):
                score -= 8.0
        except Exception:
            pass
        if other_hits > entity_hits and not _has_entity_phrase(text_value, entity):
            score -= 3.0
        return score

    def _prepare_entity_compare_docs(entity: str, other_entity: str) -> list[dict]:
        definition_query = f"what is {entity}"
        retrieved_raw = _search_fast_definition_minimal(definition_query)
        if not retrieved_raw:
            retrieved_raw = _search_fast_minimal(definition_query, top_k=6)
        retrieved_docs = _prepare_rag_doc_dicts_shared(retrieved_raw or [], definition_query)

        entity_token_list = _entity_tokens(entity)
        candidate_docs: list[dict] = []
        for candidate_doc in (docs or [])[:8]:
            candidate_text = str(
                (candidate_doc or {}).get("page_content")
                or (candidate_doc or {}).get("text")
                or (candidate_doc or {}).get("content")
                or ""
            )
            if _has_entity_phrase(candidate_text, entity) or _token_hits(candidate_text, entity_token_list) >= max(1, min(2, len(entity_token_list))):
                candidate_docs.append(candidate_doc)

        combined_docs = _dedupe_compare_docs(retrieved_docs + _prepare_rag_doc_dicts_shared(candidate_docs, definition_query))
        filtered_docs = _apply_concept_filter_to_docs(combined_docs, entity)
        guarded_docs = _enforce_definition_doc_contamination_guard(filtered_docs, entity)
        ranked_docs = sorted(
            guarded_docs or [],
            key=lambda compare_doc: _score_entity_doc(compare_doc, entity, other_entity),
            reverse=True,
        )
        best_doc = ranked_docs[0] if ranked_docs else None
        best_score = _score_entity_doc(best_doc, entity, other_entity) if best_doc else -1000.0
        accepted = bool(best_doc and best_score >= 2.0)
        reason = "entity_supported" if accepted else ("no_docs" if not ranked_docs else "weak_entity_support")
        S.logger.info(
            "[COMPARE ENTITY RETRIEVAL] entity=%s docs=%d top_source=%s accepted=%s reason=%s",
            entity,
            len(ranked_docs or []),
            _doc_source_label(best_doc),
            accepted,
            reason,
        )
        return ranked_docs[:6] if accepted else []

    def _sentence_alignment_reason(sentence: str, entity: str, other_entity: str) -> tuple[bool, str, float]:
        cleaned_sentence = re.sub(r"\s+", " ", str(sentence or "").strip())
        normalized_sentence = cleaned_sentence.lower()
        entity_token_list = _entity_tokens(entity)
        other_token_list = _entity_tokens(other_entity)
        if not cleaned_sentence:
            return False, "empty_sentence", -1000.0
        if len(re.findall(r"[a-z0-9]+", normalized_sentence)) < 5:
            return False, "too_short", -1000.0
        if len(re.findall(r"[a-z0-9]+", normalized_sentence)) > 48:
            return False, "too_long", -1000.0
        if _is_definition_boilerplate_sentence(cleaned_sentence):
            return False, "boilerplate", -1000.0
        if re.search(r"(?:copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", cleaned_sentence, flags=re.IGNORECASE):
            return False, "ocr_or_header_noise", -1000.0
        other_phrase = re.sub(r"\s+", " ", str(other_entity or "").strip().lower())
        if other_phrase and re.match(
            rf"^\s*(?:the\s+)?{re.escape(other_phrase)}\b\s+(?:is|are|was|were|refers\s+to|means|can\s+be\s+defined\s+as|is\s+defined\s+as)\b",
            normalized_sentence,
        ):
            return False, "other_entity_subject", -1000.0
        try:
            if defines_other_concept(normalized_sentence, entity):
                return False, "defines_other_concept", -1000.0
        except Exception:
            pass

        entity_hits = _token_hits(normalized_sentence, entity_token_list)
        other_hits = _token_hits(normalized_sentence, other_token_list)
        required_hits = max(1, min(2, len(entity_token_list)))
        if entity_hits < required_hits and not _has_entity_phrase(normalized_sentence, entity):
            return False, "entity_missing", -1000.0
        unique_tokens = [token for token in entity_token_list if token not in set(other_token_list)]
        if unique_tokens and not any(re.search(rf"\b{re.escape(token)}\b", normalized_sentence) for token in unique_tokens):
            return False, "unique_entity_token_missing", -1000.0
        if other_hits > entity_hits and not _has_entity_phrase(normalized_sentence, entity):
            return False, "dominated_by_other_entity", -1000.0
        has_core_explanation = bool(
            re.search(
                r"\b(?:is|are|was|were|refers\s+to|defined\s+as|means|involves|focuses\s+on|concerned\s+with|consists\s+of|includes|emphasizes|characterized\s+by|forms\s+an\s+association|associates|uses|use|goes|distributed|provides|designed|intended)\b",
                normalized_sentence,
            )
        )
        if not has_core_explanation:
            try:
                from backend.rag_chunk_heuristics import _is_colon_led_definition_prose

                if _is_colon_led_definition_prose(sentence):
                    has_core_explanation = True
            except Exception:
                pass
        if not has_core_explanation:
            return False, "no_core_explanation_signal", -1000.0

        score = float(entity_hits) + (3.0 if _has_entity_phrase(normalized_sentence, entity) else 0.0)
        score += 2.0 if has_core_explanation else 0.0
        entity_phrase = re.sub(r"\s+", " ", str(entity or "").strip().lower())
        if entity_phrase and re.match(rf"^\s*(?:the\s+)?{re.escape(entity_phrase)}\b", normalized_sentence):
            score += 2.0
        if re.match(r"^\s*(?:it|this|these|they)\b", normalized_sentence):
            score -= 1.5
        return True, "aligned", score

    def _extract_aligned_entity_sentence(entity: str, other_entity: str, entity_docs: list[dict]) -> tuple[str | None, dict | None, str]:
        best: tuple[float, str, dict, str] | None = None
        last_reason = "no_candidate_sentences"
        for entity_doc in (entity_docs or [])[:6]:
            doc_text = str((entity_doc or {}).get("page_content") or (entity_doc or {}).get("text") or (entity_doc or {}).get("content") or "")
            if not doc_text.strip():
                continue
            raw_sentences = _split_text_into_sentences(doc_text)[:18]
            skip_next = False
            for idx, raw_sentence in enumerate(raw_sentences):
                if skip_next:
                    skip_next = False
                    continue
                sentence = _clean_definition_like_sentence(raw_sentence)
                if str(raw_sentence or "").strip().endswith(":") and idx + 1 < len(raw_sentences):
                    next_part = _clean_definition_like_sentence(raw_sentences[idx + 1])
                    if next_part:
                        sentence = f"{sentence.rstrip(':').strip()}: {next_part}".strip()
                        skip_next = True
                accepted, reason, score = _sentence_alignment_reason(sentence, entity, other_entity)
                last_reason = reason
                if not accepted:
                    continue
                if best is None or score > best[0]:
                    best = (score, re.sub(r"\s+", " ", sentence).strip(), entity_doc, reason)
        if best is not None:
            S.logger.info("[COMPARE ALIGNMENT] entity=%s accepted=%s reason=%s", entity, True, best[3])
            return best[1], best[2], best[3]

        rescue_sentence, rescue_meta = _best_term_explanation_from_docs(entity, entity_docs)
        if rescue_sentence:
            accepted, reason, _score = _sentence_alignment_reason(rescue_sentence, entity, other_entity)
            if accepted:
                S.logger.info("[COMPARE ALIGNMENT] entity=%s accepted=%s reason=%s", entity, True, "rescue_aligned")
                return re.sub(r"\s+", " ", str(rescue_sentence)).strip(), {"metadata": rescue_meta or {}}, "rescue_aligned"
            last_reason = reason
        S.logger.info("[COMPARE ALIGNMENT] entity=%s accepted=%s reason=%s", entity, False, last_reason)
        return None, None, last_reason

    def _display_entity(entity: str) -> str:
        return " ".join(part.upper() if part.isupper() else part.capitalize() for part in str(entity or "").split())

    def _ensure_sentence_period(sentence: str) -> str:
        value = re.sub(r"[\ufffd\u2026\u00a6\u20ac\u00a2\u00a7\u00a4]+", "", str(sentence or ""))
        value = re.sub(r"\s+", " ", value.strip()).rstrip(" ,;:-")
        if value and not re.search(r"[.!?]$", value):
            value += "."
        return value

    synthesis_fallback = "The documents define them separately and do not provide enough information for a direct comparison."

    def _synthesis_content_tokens(text_value: str) -> set[str]:
        stop_words = {
            "about", "after", "also", "although", "and", "another", "any", "are", "because", "been", "being",
            "between", "both", "but", "can", "could", "defined", "does", "each", "for", "from", "had", "has",
            "have", "into", "its", "may", "more", "most", "not", "only", "other", "over", "same", "some", "such",
            "that", "the", "their", "them", "then", "there", "these", "they", "this", "those", "through", "under",
            "was", "were", "what", "when", "where", "which", "while", "with", "would",
        }
        return {
            token
            for token in re.findall(r"[a-z0-9]{4,}", str(text_value or "").lower())
            if token not in stop_words
        }

    def _synthesis_clause(sentence: str) -> str:
        clause = _ensure_sentence_period(sentence)
        clause = re.sub(r"[\r\n]+", " ", clause)
        clause = re.sub(r"\s+", " ", clause).strip().rstrip(".!?")
        return clause.strip(" ,;:-")

    def _side_is_clearly_defined(entity: str, other_entity: str, sentence: str) -> tuple[bool, str]:
        accepted, reason, _score = _sentence_alignment_reason(sentence, entity, other_entity)
        if not accepted:
            return False, reason
        normalized_sentence = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
        if not re.search(
            r"\b(?:is|are|was|were|refers\s+to|defined\s+as|means|involves|focuses\s+on|concerned\s+with|consists\s+of|includes|emphasizes|characterized\s+by|forms\s+an\s+association|associates)\b",
            normalized_sentence,
        ):
            return False, "not_clearly_defined"
        if len(_synthesis_content_tokens(normalized_sentence)) < 3:
            return False, "too_little_content"
        return True, "ok"

    def _synthesis_sentence_passes_guard(synthesis_sentence: str, left_evidence: str, right_evidence: str) -> tuple[bool, str]:
        synthesis_text = re.sub(r"\s+", " ", str(synthesis_sentence or "").strip())
        if not synthesis_text:
            return False, "empty_synthesis"
        if len(re.findall(r"[a-z0-9]+", synthesis_text.lower())) > 90:
            return False, "synthesis_too_long"
        sentence_count = len([part for part in re.split(r"(?<=[.!?])\s+", synthesis_text) if part.strip()])
        if sentence_count > 1:
            return False, "multiple_synthesis_sentences"

        evidence_tokens = _synthesis_content_tokens(f"{left_evidence} {right_evidence} {left} {right}")
        synthesis_tokens = _synthesis_content_tokens(synthesis_text)
        allowed_bridge_tokens = {"while"}
        unsupported_tokens = sorted(token for token in synthesis_tokens if token not in evidence_tokens and token not in allowed_bridge_tokens)
        if unsupported_tokens:
            return False, "unsupported_tokens=" + ",".join(unsupported_tokens[:6])

        inferred_relation_tokens = {
            "causes", "caused", "therefore", "depends", "results", "resulting", "leads", "leading",
            "supports", "opposes", "proves", "creates", "requires",
        }
        unsupported_relations = sorted(token for token in inferred_relation_tokens if token in synthesis_tokens and token not in evidence_tokens)
        if unsupported_relations:
            return False, "unsupported_relation=" + ",".join(unsupported_relations[:4])
        return True, "grounded_join_of_side_evidence"

    def _build_grounded_synthesis_sentence(left_evidence: str, right_evidence: str) -> tuple[str | None, str]:
        left_clear, left_clear_reason = _side_is_clearly_defined(left, right, left_evidence)
        right_clear, right_clear_reason = _side_is_clearly_defined(right, left, right_evidence)
        if not left_clear or not right_clear:
            return None, f"side_not_clearly_defined left={left_clear_reason} right={right_clear_reason}"

        left_clause = _synthesis_clause(left_evidence)
        right_clause = _synthesis_clause(right_evidence)
        if not left_clause or not right_clause:
            return None, "empty_side_clause"
        if left_clause.lower() == right_clause.lower():
            return None, "identical_side_clause"
        synthesis_sentence = f"{left_clause}, while {right_clause}."
        guard_passed, guard_reason = _synthesis_sentence_passes_guard(synthesis_sentence, left_evidence, right_evidence)
        if not guard_passed:
            return None, guard_reason
        return synthesis_sentence, guard_reason

    def _direct_difference_sentence(all_docs: list[dict]) -> str:
        left_tokens = _entity_tokens(left)
        right_tokens = _entity_tokens(right)
        compare_marker_re = re.compile(r"\b(?:different|difference|differs?|whereas|while|unlike|compared\s+with|compared\s+to|contrast|contrasts)\b", re.IGNORECASE)
        for compare_doc in _dedupe_compare_docs(all_docs or [])[:12]:
            compare_text = str((compare_doc or {}).get("page_content") or (compare_doc or {}).get("text") or (compare_doc or {}).get("content") or "")
            for raw_sentence in _split_text_into_sentences(compare_text)[:20]:
                sentence = _ensure_sentence_period(_clean_definition_like_sentence(raw_sentence))
                sentence_low = sentence.lower()
                if not compare_marker_re.search(sentence_low):
                    continue
                if _token_hits(sentence_low, left_tokens) >= max(1, min(2, len(left_tokens))) and _token_hits(sentence_low, right_tokens) >= max(1, min(2, len(right_tokens))):
                    if len(sentence) <= 240:
                        return sentence
        return "The documents define them separately, but do not provide a direct comparison."

    def _compare_output_passes_contamination_guard(answer_text: str) -> tuple[bool, str]:
        lines = [line.strip() for line in str(answer_text or "").splitlines() if line.strip()]
        if len(lines) < 3:
            return False, "missing_compare_lines"
        side_pairs = [(left, right), (right, left)]
        for entity, other_entity in side_pairs:
            label = _display_entity(entity)
            matching_lines = [line for line in lines if line.lower().startswith(label.lower() + ":")]
            if not matching_lines:
                return False, f"missing_label_{label}"
            content = matching_lines[0].split(":", 1)[1].strip().lower()
            other_phrase = re.sub(r"\s+", " ", str(other_entity or "").strip().lower())
            if other_phrase and re.match(
                rf"^(?:the\s+)?{re.escape(other_phrase)}\b\s+(?:is|are|was|were|refers\s+to|means|can\s+be\s+defined\s+as|is\s+defined\s+as)\b",
                content,
            ):
                return False, f"{label}_line_starts_with_other_entity"
        left_line = next((line for line in lines if line.lower().startswith(_display_entity(left).lower() + ":")), "")
        right_line = next((line for line in lines if line.lower().startswith(_display_entity(right).lower() + ":")), "")
        if left_line and right_line and left_line.split(":", 1)[-1].strip().lower() == right_line.split(":", 1)[-1].strip().lower():
            return False, "identical_side_evidence"
        return True, "ok"

    if len(entities) > 2:
        multi_lines: list[str] = []
        multi_clauses: list[str] = []
        for entity in entities:
            other_entity = next((other for other in entities if other != entity), "")
            entity_docs = _prepare_entity_compare_docs(entity, other_entity)
            sentence, _, reason = _extract_aligned_entity_sentence(entity, other_entity, entity_docs)
            if not sentence:
                S.logger.info(
                    "[COMPARE MULTI] entity=%s failed reason=%s",
                    entity,
                    reason,
                )
                return RAG_NO_MATCH_RESPONSE
            sentence = _ensure_sentence_period(sentence)
            multi_lines.append(f"{_display_entity(entity)}: {sentence}")
            clause = _synthesis_clause(sentence)
            if clause:
                multi_clauses.append(clause)
        synthesis_output = (
            "; ".join(multi_clauses) + "."
            if len(multi_clauses) >= 2
            else synthesis_fallback
        )
        answer = "\n".join(multi_lines + ["SYNTHESIS:", f"- {synthesis_output}"])
        answer = "\n".join(re.sub(r"[ \t]+", " ", line).strip() for line in answer.splitlines() if line.strip())
        S.logger.info("[COMPARE FINAL ANSWER] multi entities=%s", entities)
        return answer

    left_tokens = _entity_tokens(left)
    right_tokens = _entity_tokens(right)
    for shared_doc in docs or []:
        shared_text = str(
            (shared_doc or {}).get("page_content")
            or (shared_doc or {}).get("text")
            or (shared_doc or {}).get("content")
            or ""
        )
        if not shared_text.strip():
            continue
        if _token_hits(shared_text, left_tokens) < max(1, min(2, len(left_tokens))):
            continue
        if _token_hits(shared_text, right_tokens) < max(1, min(2, len(right_tokens))):
            continue
        shared_prepared = _prepare_rag_doc_dicts_shared([shared_doc], query)
        if not shared_prepared:
            continue
        shared_doc_dict = shared_prepared[0]
        left_sentence, _, _ = _extract_aligned_entity_sentence(left, right, [shared_doc_dict])
        right_sentence, _, _ = _extract_aligned_entity_sentence(right, left, [shared_doc_dict])
        if left_sentence and right_sentence and left_sentence.lower() != right_sentence.lower():
            left_sentence = _ensure_sentence_period(left_sentence)
            right_sentence = _ensure_sentence_period(right_sentence)
            synthesis_sentence, _ = _build_grounded_synthesis_sentence(left_sentence, right_sentence)
            synthesis_output = synthesis_sentence or synthesis_fallback
            shared_answer = "\n".join(
                [
                    f"{_display_entity(left)}: {left_sentence}",
                    f"{_display_entity(right)}: {right_sentence}",
                    "SYNTHESIS:",
                    f"- {synthesis_output}",
                ]
            )
            shared_answer = "\n".join(
                re.sub(r"[ \t]+", " ", line).strip() for line in shared_answer.splitlines() if line.strip()
            )
            passed, reason = _compare_output_passes_contamination_guard(shared_answer)
            if passed:
                S.logger.info("[COMPARE SHARED CHUNK] accepted reason=%s", reason)
                return shared_answer
            S.logger.info("[COMPARE SHARED CHUNK] rejected reason=%s", reason)

    left_docs = _prepare_entity_compare_docs(left, right)
    right_docs = _prepare_entity_compare_docs(right, left)
    if not left_docs or not right_docs:
        S.logger.info("[COMPARE CONTAMINATION GUARD] passed=%s reason=%s", False, "missing_entity_grounding")
        return RAG_NO_MATCH_RESPONSE

    left_sentence, _left_doc, left_reason = _extract_aligned_entity_sentence(left, right, left_docs)
    right_sentence, _right_doc, right_reason = _extract_aligned_entity_sentence(right, left, right_docs)
    if not left_sentence or not right_sentence:
        S.logger.info(
            "[COMPARE CONTAMINATION GUARD] passed=%s reason=%s",
            False,
            f"alignment_failed left={left_reason} right={right_reason}",
        )
        return RAG_NO_MATCH_RESPONSE
    if left_sentence.lower() == right_sentence.lower():
        S.logger.info("[COMPARE CONTAMINATION GUARD] passed=%s reason=%s", False, "identical_side_evidence")
        return RAG_NO_MATCH_RESPONSE

    left_sentence = _ensure_sentence_period(left_sentence)
    right_sentence = _ensure_sentence_period(right_sentence)
    S.logger.info("[SYNTHESIS BUILD] using grounded evidence only")
    synthesis_sentence, synthesis_reason = _build_grounded_synthesis_sentence(left_sentence, right_sentence)
    synthesis_passed = bool(synthesis_sentence)
    S.logger.info("[SYNTHESIS GUARD] passed=%s reason=%s", synthesis_passed, synthesis_reason)
    synthesis_output = synthesis_sentence if synthesis_sentence else synthesis_fallback
    answer = "\n".join(
        [
            f"{_display_entity(left)}: {left_sentence}",
            f"{_display_entity(right)}: {right_sentence}",
            "SYNTHESIS:",
            f"- {synthesis_output}",
        ]
    )
    answer = "\n".join(re.sub(r"[ \t]+", " ", line).strip() for line in answer.splitlines() if line.strip())
    passed, reason = _compare_output_passes_contamination_guard(answer)
    S.logger.info("[COMPARE CONTAMINATION GUARD] passed=%s reason=%s", passed, reason)
    if not passed:
        return RAG_NO_MATCH_RESPONSE
    S.logger.info("[COMPARE FINAL ANSWER] %s", answer[:280].replace("\n", " | "))
    return answer

def _compare_answer_from_docs(query: str, docs: list[dict]) -> str | None:
    strict_compare_answer = _compare_answer_from_docs_strict(query, docs)
    if strict_compare_answer is not None:
        return strict_compare_answer

    left, right = _compare_terms_from_query(query)
    if not left or not right:
        return None
    S.logger.info("[COMPARE MODE] entities=(%s, %s)", left, right)

    candidate_docs = (docs or [])[:8]
    left_retrieved = _search_fast_minimal(f"what is {left}", top_k=6)
    right_retrieved = _search_fast_minimal(f"what is {right}", top_k=6)

    left_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", left.lower()) if t not in {"the", "and", "of"}]
    right_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", right.lower()) if t not in {"the", "and", "of"}]

    left_docs: list[dict] = []
    right_docs: list[dict] = []
    for d in candidate_docs:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        tl = txt.lower()
        if left_tokens and any(re.search(rf"\b{re.escape(tok)}\b", tl) for tok in left_tokens):
            left_docs.append(d)
        if right_tokens and any(re.search(rf"\b{re.escape(tok)}\b", tl) for tok in right_tokens):
            right_docs.append(d)

    left_pool = left_docs or left_retrieved or candidate_docs
    right_pool = right_docs or right_retrieved or candidate_docs

    def _extract_best_compare_sentence(term: str, other_term: str, pool_docs: list[dict]) -> tuple[str | None, dict | None, int]:
        term_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", term.lower()) if t not in {"the", "and", "of"}]
        other_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", str(other_term or "").lower()) if t not in {"the", "and", "of"}]
        unique_term_tokens = [t for t in term_tokens if t not in set(other_tokens)]
        term_phrase = re.sub(r"\s+", " ", str(term or "").strip().lower())
        other_phrase = re.sub(r"\s+", " ", str(other_term or "").strip().lower())
        best_sentence: str | None = None
        best_meta: dict | None = None
        best_score = -10**9

        for d in (pool_docs or [])[:4]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            md = dict((d or {}).get("metadata") or {})
            if not txt.strip():
                continue

            sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if (s or "").strip()]
            for raw in sentences:
                s = _clean_definition_like_sentence(raw)
                if not s:
                    continue

                s = re.sub(r"\s+", " ", s).strip()
                sl = s.lower()
                words = re.findall(r"[a-z0-9]+", sl)
                word_count = len(words)

                if word_count < 6 or word_count > 36:
                    continue
                if _is_definition_boilerplate_sentence(s):
                    continue
                if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", s, flags=re.IGNORECASE):
                    continue
                if s.count("•") >= 1 or re.search(r"\btable\b|\bfigure\b", sl):
                    if not (_is_comparison_table_evidence(s) and _entity_row_match_score(term, s) > 0):
                        continue

                token_hits = sum(1 for tok in term_tokens if re.search(rf"\b{re.escape(tok)}\b", sl))
                required_hits = max(1, min(2, len(term_tokens)))
                has_term = token_hits >= required_hits
                if not has_term:
                    continue
                if unique_term_tokens and not any(re.search(rf"\b{re.escape(tok)}\b", sl) for tok in unique_term_tokens):
                    continue
                if other_phrase and other_phrase in sl and term_phrase and term_phrase not in sl:
                    continue

                has_def_marker = bool(re.search(r"\b(?:is|refers\s+to|defined\s+as|means|forms\s+an\s+association|associates)\b", sl))
                starts_pronoun = bool(re.match(r"^\s*(?:it|this|they|he|she)\b", sl))
                score = 0
                if has_def_marker:
                    score += 2
                if has_term:
                    score += 2
                if starts_pronoun:
                    score -= 2
                if word_count < 8:
                    score -= 2

                caps_count = len(re.findall(r"\b[A-Z][a-z]+\b", s))
                if caps_count >= 6 and not re.search(r"[,;:]", s) and len(s) > 90:
                    score -= 3

                if score > best_score:
                    best_score = score
                    best_sentence = s
                    best_meta = md

        if not best_sentence:
            for d in (pool_docs or [])[:4]:
                txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
                md = dict((d or {}).get("metadata") or {})
                if not txt.strip():
                    continue
                sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if (s or "").strip()]
                for raw in sentences:
                    s = _clean_definition_like_sentence(raw)
                    if not s:
                        continue
                    s = re.sub(r"\s+", " ", s).strip()
                    sl = s.lower()
                    word_count = len(re.findall(r"[a-z0-9]+", sl))
                    if word_count < 8 or word_count > 34:
                        continue
                    if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", s, flags=re.IGNORECASE):
                        continue
                    if s.count("•") >= 1 or re.search(r"\btable\b|\bfigure\b", sl):
                        continue
                    token_hits = sum(1 for tok in term_tokens if re.search(rf"\b{re.escape(tok)}\b", sl))
                    required_hits = max(1, min(2, len(term_tokens)))
                    if token_hits < required_hits:
                        continue
                    if unique_term_tokens and not any(re.search(rf"\b{re.escape(tok)}\b", sl) for tok in unique_term_tokens):
                        continue
                    if other_phrase and other_phrase in sl and term_phrase and term_phrase not in sl:
                        continue
                    if not re.search(r"\b(?:is|refers\s+to|defined\s+as|means|forms\s+an\s+association|associates)\b", sl):
                        continue
                    caps_count = len(re.findall(r"\b[A-Z][a-z]+\b", s))
                    if caps_count >= 6 and not re.search(r"[,;:]", s) and len(s) > 90:
                        continue
                    best_sentence = s
                    best_meta = md
                    best_score = max(best_score, 1)
                    break
                if best_sentence:
                    break

        if not best_sentence:
            return None, None, best_score
        return best_sentence, best_meta, best_score

    left_sent, left_md, left_score = _extract_best_compare_sentence(left, right, left_pool)
    right_sent, right_md, right_score = _extract_best_compare_sentence(right, left, right_pool)
    S.logger.info(
        "[COMPARE CHUNKS] left_chunk=%s right_chunk=%s left_score=%s right_score=%s",
        (left_md or {}).get("chunk_index") if isinstance(left_md, dict) else None,
        (right_md or {}).get("chunk_index") if isinstance(right_md, dict) else None,
        left_score,
        right_score,
    )

    left_rescue, left_rescue_md = _best_term_explanation_from_docs(left, left_pool)
    right_rescue, right_rescue_md = _best_term_explanation_from_docs(right, right_pool)
    if not left_sent and left_rescue:
        left_sent, left_md = left_rescue, left_rescue_md
    if not right_sent and right_rescue:
        right_sent, right_md = right_rescue, right_rescue_md

    if left_sent and right_sent and left_sent.lower() == right_sent.lower():
        if left_rescue and right_rescue and left_rescue.lower() != right_rescue.lower():
            left_sent, left_md = left_rescue, left_rescue_md
            right_sent, right_md = right_rescue, right_rescue_md
        elif left_rescue and left_rescue.lower() != right_sent.lower():
            left_sent, left_md = left_rescue, left_rescue_md
        elif right_rescue and right_rescue.lower() != left_sent.lower():
            right_sent, right_md = right_rescue, right_rescue_md

    def _is_fragment_like_compare_sentence(term: str, s: str) -> bool:
        if not s:
            return True
        sl = s.lower()
        if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", s, flags=re.IGNORECASE):
            return True
        if re.search(r"\b(?:is|refers\s+to|defined\s+as|means|forms\s+an\s+association|associates)\b", sl):
            return False
        caps_run = bool(re.search(r"(?:\b[A-Z][a-z]+\b\s+){3,}", s))
        term_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", term.lower()) if t not in {"the", "and", "of"}]
        token_hits = sum(1 for tok in term_tokens if re.search(rf"\b{re.escape(tok)}\b", sl))
        if caps_run and token_hits <= 1:
            return True
        if len(re.findall(r"\b[A-Z][a-z]+\b", s)) >= 6 and not re.search(r"[,;:]", s) and len(s) > 80:
            return True
        return False

    if _is_fragment_like_compare_sentence(left, str(left_sent or "")):
        if left_rescue and not _is_fragment_like_compare_sentence(left, left_rescue):
            left_sent, left_md = left_rescue, left_rescue_md

    if _is_fragment_like_compare_sentence(right, str(right_sent or "")):
        if right_rescue and not _is_fragment_like_compare_sentence(right, right_rescue):
            right_sent, right_md = right_rescue, right_rescue_md

    if not left_sent or not right_sent:
        return None

    left_sent = re.sub(r"\s+", " ", str(left_sent or "")).strip().rstrip(" ,;:-")
    right_sent = re.sub(r"\s+", " ", str(right_sent or "")).strip().rstrip(" ,;:-")
    if not re.search(r"[.!?]$", left_sent):
        left_sent += "."
    if not re.search(r"[.!?]$", right_sent):
        right_sent += "."

    S.logger.info("[COMPARE SIDE PASS] side=left term=%s sentence=%s", left, left_sent[:220])
    S.logger.info("[COMPARE SIDE PASS] side=right term=%s sentence=%s", right, right_sent[:220])
    if left_sent and right_sent and left_sent.lower() == right_sent.lower():
        return None

    left_sent = left_sent[:220].rstrip(" ,;:-.!?")
    right_sent = right_sent[:220].rstrip(" ,;:-.!?")
    answer = f"{left.title()}: {left_sent}; {right.title()}: {right_sent}."
    answer = re.sub(r"\s*[•\-]\s*", " ", answer)
    answer = re.sub(r"[ \t]+", " ", answer).strip()
    if len(answer) > 500:
        answer = answer[:500].rstrip(" ,;:-") + "."
    S.logger.info("[COMPARE FINAL ANSWER] %s", answer[:280])
    S.logger.info("[COMPARE ANSWER] %s", answer[:280])
    return answer

def defines_other_concept(sentence: str, entity: str) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not s or not e or e not in s:
        return False

    entity_subject_re = re.compile(rf"^(?:the\s+)?{re.escape(e)}\b")
    if entity_subject_re.search(s):
        return False

    other_subject_definition_re = re.compile(
        r"^\s*(?:the\s+)?([a-z][a-z0-9/&\-\s]{2,100}?)\s+(?:is|refers\s+to|is\s+defined\s+as|can\s+be\s+defined\s+as)\b"
    )
    m = other_subject_definition_re.search(s)
    if not m:
        label_style_re = re.compile(
            r"^\s*([a-z][a-z0-9/&\-\s]{2,100}?)\s*:\s*this\s+approach\s+(?:is|refers\s+to|is\s+defined\s+as|can\s+be\s+defined\s+as)\b"
        )
        lm = label_style_re.search(s)
        if not lm:
            return False
        label_subject = re.sub(r"\s+", " ", (lm.group(1) or "").strip())
        if not label_subject:
            return False
        if label_subject == e or e in label_subject:
            return False
        return True

    other_subject = re.sub(r"\s+", " ", (m.group(1) or "").strip())
    if not other_subject:
        return False

    if other_subject == e:
        return False

    if e in other_subject:
        return False

    return True

def is_indirect_entity_explanation(sentence: str, entity: str) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "").strip())
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not s or not e:
        return False

    s_l = s.lower()
    entity_full_re = re.compile(rf"\b(?:the\s+)?{re.escape(e)}\b", re.IGNORECASE)
    has_full_entity = bool(entity_full_re.search(s_l))

    entity_tokens = [
        tok for tok in re.findall(r"[a-z0-9]+", e)
        if tok not in {"the", "a", "an", "of", "and", "in", "to", "for"}
    ]
    matched_tokens = [tok for tok in entity_tokens if re.search(rf"\b{re.escape(tok)}\b", s_l)]
    has_strong_direct_mention = bool(entity_tokens) and (len(matched_tokens) >= max(1, len(entity_tokens) - 1))
    if not (has_full_entity or has_strong_direct_mention):
        return False

    if defines_other_concept(s_l, e):
        return False

    descriptive_cues = [
        r"\bfocused\s+on\b",
        r"\bfocuses\s+on\b",
        r"\bpart\s+of\b",
        r"\bassociated\s+with\b",
        r"\bideas?\s+put\s+forward\s+by\b",
        r"\bgrew\s+out\s+of\b",
        r"\bperiod\b",
        r"\bera\b",
        r"\bincludes\b",
        r"\bconsists\s+of\b",
        r"\bimprovement\s+over\b",
        r"\bimprovements\s+over\b",
        r"\bdefined\s+as\b",
        r"\brefers\s+to\b",
        r"\bmeans\b",
        r"\binvolves?\b",
        r"\buses?\b",
        r"\baims?\s+to\b",
        r"\bused\s+to\b",
        r"\bpurposes?\b",
        r"\bfunctions?\b",
        r"\broles?\b",
    ]
    descriptive_re = re.compile("|".join(descriptive_cues), re.IGNORECASE)
    if not descriptive_re.search(s_l):
        return False

    # DISABLED_CHEATING_LOGIC: Domain-specific generic-management rejection.
    # unrelated_general_re = re.compile(
    #     r"\b(?:management\s+is\s+the\s+process|management\s+in\s+general|general\s+principles\s+of\s+management)\b",
    #     re.IGNORECASE,
    # )
    # if unrelated_general_re.search(s_l) and not has_full_entity:
    #     return False

    return True

def _is_table_or_classification_sentence(sentence: str) -> bool:
    s = str(sentence or "")
    if not s:
        return False
    list_or_table_like_re = re.compile(r"^\s*(?:[-•*]|\d+[.)]|\|)|\t|\s{3,}")
    table_or_classification_re = re.compile(
        r"\b(?:table|classification|major\s+classification|categories?)\b",
        re.IGNORECASE,
    )
    return bool(list_or_table_like_re.search(s) or table_or_classification_re.search(s))

def _is_classification_only_chunk(text: str) -> bool:
    src = str(text or "")
    if not src.strip():
        return True
    low = src.lower()
    classification_terms = len(re.findall(r"\b(?:classification|classifications|categories?|major\s+classification|contributors?)\b", low))
    sentence_count = len(_split_text_into_sentences(src))
    if classification_terms >= 3 and sentence_count <= 4:
        return True
    if _looks_table_or_heading_like_chunk(src) and sentence_count <= 3:
        return True
    return False

def _has_paragraph_prose_shape(text: str) -> bool:
    src = re.sub(r"\s+", " ", str(text or "")).strip()
    if not src:
        return False
    words = re.findall(r"[A-Za-z0-9][A-Za-z0-9\-']*", src)
    if len(words) < 18:
        return False
    sentence_like = len(re.findall(r"[.!?]", src))
    alpha_ratio = len(re.findall(r"[A-Za-z]", src)) / max(1, len(src))
    if sentence_like < 1:
        return False
    if alpha_ratio < 0.45:
        return False
    return True

def pick_best_safe_prose_fallback(doc_dicts, entity):
    docs = list(doc_dicts or [])
    if not docs:
        return None, False

    e = re.sub(r"\s+", " ", str(entity or "")).strip().lower()
    entity_tokens = [
        tok for tok in re.findall(r"[a-z0-9]+", e)
        if tok not in {"the", "a", "an", "of", "and", "in", "to", "for"}
    ]

    ranked_docs = sorted(
        docs,
        key=lambda d: float((d or {}).get("score", ((d or {}).get("metadata") or {}).get("_score", 0.0)) or 0.0),
        reverse=True,
    )

    best_doc = None
    best_rank = float("-inf")
    for d in ranked_docs:
        text = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not text.strip():
            continue
        if _looks_table_or_heading_like_chunk(text):
            continue
        if _is_classification_only_chunk(text):
            continue
        if not _has_paragraph_prose_shape(text):
            continue

        low = text.lower()
        has_full = bool(e and re.search(rf"\b{re.escape(e)}\b", low))
        entity_token_hits = sum(1 for tok in entity_tokens if re.search(rf"\b{re.escape(tok)}\b", low))
        if not has_full and entity_token_hits < 2:
            continue

        early_text = low[:int(len(low) * 0.3)]
        if entity_tokens and not any(tok in early_text for tok in entity_tokens):
            continue

        S.logger.info(
            "[FALLBACK CANDIDATE] entity_hits=%d has_full=%s preview=%s",
            entity_token_hits,
            has_full,
            text[:120],
        )

        doc_score = float((d or {}).get("score", ((d or {}).get("metadata") or {}).get("_score", 0.0)) or 0.0)
        prose_bonus = min(1.8, len(re.findall(r"[A-Za-z0-9][A-Za-z0-9\-']*", text)) / 120.0)
        entity_bonus = 2.0 if has_full else float(entity_token_hits) * 0.5
        rank_score = doc_score + prose_bonus + entity_bonus
        if rank_score > best_rank:
            best_rank = rank_score
            best_doc = d

    if best_doc is not None:
        return best_doc, False

    return None, False

def _extract_heading_preview(text: str, max_lines: int = 10) -> str:
    t = str(text or "")
    if not t.strip():
        return ""
    lines = [ln.strip() for ln in t.splitlines() if ln.strip()]
    if not lines:
        return ""
    heading_like_lines = []
    for ln in lines[: max(6, max_lines)]:
        if re.search(r"^\s*(?:\d+(?:\.\d+)*\s+|[A-Z]\.)", ln):
            heading_like_lines.append(ln)
        elif len(ln) <= 120 and not ln.endswith("."):
            heading_like_lines.append(ln)
    if not heading_like_lines:
        heading_like_lines = lines[:3]
    return " ".join(heading_like_lines[:max_lines])

def _chunk_has_entity_heading(text: str, entity: str) -> bool:
    t = str(text or "")
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not t.strip() or not e:
        return False
    entity_tokens = [tok for tok in re.findall(r"[a-z0-9]+", e) if tok not in {"the", "a", "an", "of", "and", "in", "to", "for"}]
    if not entity_tokens:
        return False
    head_lines = [ln.strip().lower() for ln in t.splitlines()[:12] if ln.strip()]
    for ln in head_lines:
        heading_shape = bool(re.search(r"^(?:\d+(?:\.\d+)*\s+|[a-z]\.|[ivxlcdm]+\.)", ln, flags=re.IGNORECASE)) or (len(ln) <= 140 and not ln.endswith("."))
        if not heading_shape:
            continue
        token_hits = sum(1 for tok in entity_tokens if re.search(rf"\b{re.escape(tok)}\b", ln))
        if token_hits >= max(1, len(entity_tokens) - 1):
            return True
    return False

def _sentence_subject_is_target_entity(sentence: str, entity: str) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not s or not e:
        return False
    if re.search(rf"^\s*(?:the\s+)?{re.escape(e)}\b", s):
        return True
    if re.search(rf"\b(?:the\s+)?{re.escape(e)}\s+(?:is|was|are|were|focuses|focused|aims|uses|emphasizes|includes|consists|grew)\b", s):
        return True
    return False

def _choose_top_complementary_indirect_sentences(entity: str, candidates: list[tuple[float, bool, str]], max_pick: int = 2) -> list[str]:
    if not candidates:
        return []
    prose_candidates = [c for c in candidates if not c[1]]
    source = prose_candidates if prose_candidates else candidates
    chosen: list[str] = []
    seen = set()
    for _score, _is_table, sentence in sorted(source, key=lambda x: x[0], reverse=True):
        s = re.sub(r"\s+", " ", str(sentence or "").strip())
        if not s:
            continue
        key = s.lower()
        if key in seen:
            continue
        if chosen:
            existing_tokens = set(re.findall(r"[a-z0-9]{4,}", chosen[0].lower()))
            current_tokens = set(re.findall(r"[a-z0-9]{4,}", key))
            overlap = len(existing_tokens & current_tokens)
            if current_tokens and (overlap / max(1, len(current_tokens))) > 0.72:
                continue
        seen.add(key)
        chosen.append(s)
        if len(chosen) >= max_pick:
            break
    return chosen

def _build_indirect_definition_answer(entity: str, evidence_lines: list[str]) -> tuple[str, list[str]]:
    e = re.sub(r"\s+", " ", str(entity or "").strip())
    normalized = [re.sub(r"\s+", " ", str(s or "").strip()) for s in (evidence_lines or []) if str(s or "").strip()]
    dedup = []
    seen = set()
    for s in normalized:
        key = s.lower()
        if key in seen:
            continue
        seen.add(key)
        dedup.append(s)
    chosen = _choose_top_complementary_indirect_sentences(e.lower(), [(1.0, _is_table_or_classification_sentence(s), s) for s in dedup], max_pick=2)
    if not chosen:
        return "", []

    first = chosen[0].rstrip(" .;:")
    answer = first
    if e and not re.search(rf"\b{re.escape(e.lower())}\b", first.lower()):
        first_lc = first[:1].lower() + first[1:] if first else first
        answer = f"The document describes {e.lower()} as {first_lc}"
    if len(chosen) > 1:
        second = chosen[1].rstrip(" .;:")
        if second:
            answer = f"{answer}. {second}"
    answer = re.sub(r"\s+", " ", answer).strip()
    if answer and not answer.endswith("."):
        answer += "."
    return answer, chosen

def _definition_entity_tokens(entity: str) -> list[str]:
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not e:
        return []
    return [
        tok for tok in re.findall(r"[a-z0-9]+", e)
        if tok not in {"the", "a", "an", "of", "and", "in", "to", "for"}
    ]

def _mentions_other_approach(text: str, entity: str) -> bool:
    s = re.sub(r"\s+", " ", str(text or "").strip().lower())
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not s:
        return False
    if e and re.search(rf"\b{re.escape(e)}\b", s):
        return False
    concept_suffix_re = re.compile(
        r"\b[a-z][a-z0-9\-]*(?:\s+[a-z][a-z0-9\-]*){0,3}\s+"
        r"(?:approach|theory|model|system|method|framework|school|perspective)\b"
    )
    candidates = {
        re.sub(r"\s+", " ", m.group(0)).strip()
        for m in concept_suffix_re.finditer(s)
    }
    if not candidates:
        return False
    if not e:
        return True
    e_tokens = set(_definition_entity_tokens(e))
    for candidate in candidates:
        if candidate == e:
            continue
        cand_tokens = set(_definition_entity_tokens(candidate))
        if cand_tokens and e_tokens and len(cand_tokens & e_tokens) >= max(1, min(2, len(e_tokens))):
            continue
        return True
    return False

def _chunk_passes_concept_consistency(chunk_text: str, entity: str) -> bool:
    t = re.sub(r"\s+", " ", str(chunk_text or "").strip().lower())
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not t or not e:
        return True
    full_entity = bool(re.search(rf"\b{re.escape(e)}\b", t))
    tokens = _definition_entity_tokens(e)
    main_tokens = tokens[:2]
    has_main_tokens = bool(main_tokens) and all(re.search(rf"\b{re.escape(tok)}\b", t) for tok in main_tokens)
    if not (full_entity or has_main_tokens):
        return False
    if _mentions_other_approach(t, e):
        return False
    return True

def _chunk_entity_dominant_topic(chunk_text: str, entity: str) -> bool:
    t = re.sub(r"\s+", " ", str(chunk_text or "").strip().lower())
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not t or not e:
        return False
    full_hits = len(re.findall(rf"\b{re.escape(e)}\b", t)) if e else 0
    token_hits = sum(1 for tok in _definition_entity_tokens(e) if re.search(rf"\b{re.escape(tok)}\b", t))
    other_hit = 1 if _mentions_other_approach(t, e) else 0
    return bool((full_hits >= 1 or token_hits >= 2) and (full_hits + token_hits) > other_hit)

def _sentence_is_generic_weak(sentence: str) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
    if not s:
        return False
    return bool(
        re.search(r"^\s*this\s+approach\s+focuses\s+on\b", s)
        or re.search(r"^\s*this\s+method\s+helps\b", s)
    )

def _sentence_passes_same_concept_filter(sentence: str, entity: str, chunk_is_entity_dominant: bool) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "").strip())
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not s or not e:
        return False

    s_l = s.lower()
    has_full_entity = bool(re.search(rf"\b{re.escape(e)}\b", s_l))
    if not (has_full_entity or chunk_is_entity_dominant):
        return False

    if re.search(r"^\s*this\s+approach\b", s_l) and not has_full_entity:
        return False

    if _mentions_other_approach(s_l, e):
        return False

    if _sentence_is_generic_weak(s_l) and not has_full_entity:
        return False

    return True

def _apply_concept_filter_to_docs(docs: list[dict], entity: str) -> list[dict]:
    source_docs = list(docs or [])
    if not source_docs:
        return []
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not e:
        return source_docs
    filtered: list[dict] = []
    for d in source_docs:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if _chunk_passes_concept_consistency(txt, e):
            filtered.append(d)
    if filtered:
        S.logger.info("[CONCEPT FILTER] entity=%s docs=%d kept=%d", entity, len(source_docs), len(filtered))
        return filtered
    S.logger.info("[CONCEPT FILTER] entity=%s docs=%d kept=0 fallback=original", entity, len(source_docs))
    return source_docs

def _select_safe_indirect_from_pool(pool: list[dict], max_pick: int = 2) -> tuple[list[str], str]:
    if not pool:
        return [], ""
    ranked = sorted(pool, key=lambda x: float(x.get("score", 0.0)), reverse=True)
    anchor = ranked[0]
    anchor_chunk_id = str(anchor.get("chunk_id") or anchor.get("chunk_index") or "")
    same_chunk = [p for p in ranked if str(p.get("chunk_id") or p.get("chunk_index") or "") == anchor_chunk_id]
    picked: list[str] = []
    seen = set()
    for item in same_chunk:
        sentence = re.sub(r"\s+", " ", str(item.get("sentence") or "").strip())
        if not sentence:
            continue
        key = sentence.lower()
        if key in seen:
            continue
        seen.add(key)
        picked.append(sentence)
        if len(picked) >= max_pick:
            break
    S.logger.info("[INDIRECT SAFE] using_chunk_id=%s", anchor_chunk_id)
    return picked, anchor_chunk_id

def _enforce_definition_doc_contamination_guard(docs: list[dict], entity: str) -> list[dict]:
    source_docs = list(docs or [])
    if not source_docs:
        return []
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not e:
        return source_docs[:5]
    guarded: list[dict] = []
    for d in source_docs:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not _chunk_passes_concept_consistency(txt, e):
            continue
        if _is_wrong_concept_definition_chunk(txt, e):
            continue
        guarded.append(d)
    if guarded:
        S.logger.info("[CONTAMINATION GUARD] entity=%s docs=%d kept=%d", entity, len(source_docs), len(guarded))
        return guarded[:5]
    S.logger.info("[CONTAMINATION GUARD] entity=%s docs=%d kept=0 fallback=top5", entity, len(source_docs))
    return source_docs[:5]

def collect_indirect_entity_evidence(text: str, entity: str, return_scored: bool = False) -> list[str] | list[tuple[float, bool, str]]:
    t = str(text or "")
    e = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not t.strip() or not e:
        return []

    sentences = _split_text_into_sentences(t)

    chunk_heading_preview = _extract_heading_preview(t)
    chunk_has_entity_heading = _chunk_has_entity_heading(t, e)
    chunk_is_entity_dominant = _chunk_entity_dominant_topic(t, e)
    scored: list[tuple[float, bool, str]] = []
    seen = set()
    for sentence in sentences:
        s_norm = re.sub(r"\s+", " ", sentence).strip()
        s_l = s_norm.lower()
        if len(s_norm) < 30:
            continue
        if not _sentence_passes_same_concept_filter(s_norm, e, chunk_is_entity_dominant):
            S.logger.info("[REJECT CROSS CONCEPT] preview=%s", s_norm[:180])
            continue
        if defines_other_concept(s_l, e):
            S.logger.info("[INDIRECT DEF REJECT] reason=defines_other_concept sentence=%s", s_norm[:180])
            continue
        if not is_indirect_entity_explanation(s_norm, e):
            continue
        if s_l in seen:
            continue
        seen.add(s_l)

        is_table_like = _is_table_or_classification_sentence(s_norm)
        starts_with_entity = 1.8 if re.search(rf"^\s*(?:the\s+)?{re.escape(e)}\b", s_l) else 0.0
        starts_with_heading_mention = 0.8 if chunk_heading_preview and re.search(rf"^\s*(?:\d+(?:\.\d+)*\s+|[A-Z]\.\s+)?(?:the\s+)?{re.escape(e)}\b", s_l, flags=re.IGNORECASE) else 0.0
        heading_context_boost = 1.4 if (chunk_has_entity_heading and not is_table_like) else (0.6 if chunk_has_entity_heading else 0.0)
        heading_preview_hit = 0.9 if (chunk_heading_preview and re.search(rf"\b{re.escape(e)}\b", chunk_heading_preview.lower())) else 0.0

        explanatory_cues = [
            r"\bfocused\s+on\b",
            r"\bmain\s+goals?\b",
            r"\bgrew\s+out\s+of\b",
            r"\bprinciples?\b",
            r"\bmethods?\b",
            r"\bpurposes?\b",
            r"\bfunctions?\b",
            r"\broles?\b",
            r"\binvolves?\b",
            r"\bincludes?\b",
            r"\baims?\s+to\b",
            r"\bused\s+to\b",
            r"\bconsists?\s+of\b",
        ]
        explanatory_hits = sum(1 for pat in explanatory_cues if re.search(pat, s_l, flags=re.IGNORECASE))
        explanatory_boost = min(3.2, 0.95 * explanatory_hits)

        strong_explanatory_phrase_boost = 0.0
        if re.search(r"\b(?:defined\s+as|refers\s+to|means|is\s+used\s+to|aims?\s+to|focus(?:es|ed)\s+on)\b", s_l, flags=re.IGNORECASE):
            strong_explanatory_phrase_boost += 1.8
        # DISABLED_CHEATING_LOGIC: Domain-specific principles+scientific boost.
        # if re.search(r"\b(?:principles?|methods?)\b", s_l, flags=re.IGNORECASE) and re.search(r"\bscientific\b", s_l, flags=re.IGNORECASE):
        #     strong_explanatory_phrase_boost += 1.2

        prose_bonus = 1.6 if not is_table_like else 0.0
        long_coherent_bonus = 0.0
        if len(s_norm) >= 110 and not is_table_like:
            long_coherent_bonus += min(1.8, (len(s_norm) - 90) / 140.0)
        if len(re.findall(r"[a-z0-9]+", s_l)) >= 16 and not is_table_like:
            long_coherent_bonus += 0.6

        table_penalty = 3.4 if is_table_like else 0.0
        label_penalty = 1.6 if re.search(r"^\s*(?:table|figure|classification|categories?)\b", s_l, flags=re.IGNORECASE) else 0.0

        comparison_re = re.compile(r"\b(?:improvement\s+over|improvements\s+over|unlike|compared\s+to)\b", re.IGNORECASE)
        comparison_penalty = 0.0
        if comparison_re.search(s_l) and not _sentence_subject_is_target_entity(s_norm, e):
            comparison_penalty = 3.6

        # P5: Removed hard-coded management-specific vague-phrase blacklist
        # ("global situation", "management in general", "all managers"). Off-target
        # subjects are still penalised generically by off_target_define_penalty below.
        vague_penalty = 0.0

        off_target_define_penalty = 0.0
        if defines_other_concept(s_l, e):
            off_target_define_penalty = 6.0

        historical_context_penalty = 0.0
        if re.search(r"\b(?:come\s+to\s+mind\s+whenever|changed\s+over\s+time|histor(?:y|ical)|era|you\s+can\s+also\s+call\s+it)\b", s_l, flags=re.IGNORECASE):
            if not re.search(r"\b(?:is|refers\s+to|means|defined\s+as|includes?|involves?|focus(?:es|ed)\s+on|aims?\s+to)\b", s_l, flags=re.IGNORECASE):
                historical_context_penalty = 4.4

        broken_fragment_penalty = 0.0
        if re.search(r"\b[A-Za-z]\.\s*$", s_norm) or re.search(r"\bby\s+[A-Za-z]\.\s*$", s_l):
            broken_fragment_penalty = 8.0

        preamble_penalty = 0.0
        if re.search(r"\b(?:before\s+we\s+can\s+study|we\s+need\s+to\s+look\s+at|there\s+are\s+\w+\s+parts\s+to)\b", s_l, flags=re.IGNORECASE):
            preamble_penalty = 3.8

        entity_token_completeness_boost = 0.0
        entity_tokens = [tok for tok in re.findall(r"[a-z0-9]+", e) if tok not in {"the", "a", "an", "of", "and", "in", "to", "for"}]
        if entity_tokens:
            token_hits = sum(1 for tok in entity_tokens if re.search(rf"\b{re.escape(tok)}\b", s_l))
            if token_hits >= max(1, len(entity_tokens) - 1):
                entity_token_completeness_boost += 1.1

        score = (
            starts_with_entity
            + starts_with_heading_mention
            + heading_context_boost
            + heading_preview_hit
            + explanatory_boost
            + strong_explanatory_phrase_boost
            + entity_token_completeness_boost
            + prose_bonus
            + long_coherent_bonus
            - table_penalty
            - label_penalty
            - comparison_penalty
            - vague_penalty
            - off_target_define_penalty
            - historical_context_penalty
            - broken_fragment_penalty
            - preamble_penalty
        )
        S.logger.info("[INDIRECT SCORE] score=%.3f sentence=%s", float(score), s_norm[:220])
        if score <= 0.4:
            continue
        scored.append((score, is_table_like, s_norm))

    scored.sort(key=lambda x: (x[0], not x[1], len(x[2])), reverse=True)
    if return_scored:
        return scored[:4]
    prose = [s for _score, is_table_like, s in scored if not is_table_like]
    table_fallback = [s for _score, is_table_like, s in scored if is_table_like]
    picked = (prose[:3] if prose else table_fallback[:3])
    return picked

def _is_wrong_concept_definition_chunk(text: str, query_entity: str) -> bool:
    t = re.sub(r"\s+", " ", str(text or "").strip().lower())
    e = re.sub(r"\s+", " ", str(query_entity or "").strip().lower())
    if not t or not e:
        return False
    has_entity_phrase = bool(re.search(rf"\b{re.escape(e)}\b", t))
    if has_entity_phrase:
        return False
    entity_tokens = _definition_entity_tokens(e)
    token_hits = sum(1 for tok in entity_tokens if re.search(rf"\b{re.escape(tok)}\b", t))
    wrong_concept = bool(defines_other_concept(t, e) or (_mentions_other_approach(t, e) and token_hits < max(1, min(2, len(entity_tokens)))))
    if wrong_concept:
        S.logger.info("[WRONG CONCEPT CHECK] entity=%s result=true preview=%s", query_entity, str(text or "")[:180].replace("\n", " "))
        return True
    return False

def _extract_relation_subject_terms(query_text: str, fact_type: str | None) -> list[str]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return []

    relation_noise = {
        "what", "which", "who", "whom", "whose", "when", "where", "why", "how",
        "is", "are", "was", "were", "did", "do", "does", "the", "a", "an", "of",
        "in", "on", "at", "to", "for", "from", "and", "or", "by", "it", "its", "be",
        "this", "that", "these", "those", "year", "date", "time", "first", "considered",
        "proposed", "developed", "introduced", "established", "founded", "created", "coined",
        "model",
        "emerge", "emerged", "began", "started", "originated", "happened", "occurred",
    }

    tokens = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in relation_noise]
    if fact_type == "when":
        tokens = [
            t for t in tokens
            if t not in {"year", "date", "time", "establish", "established", "founded", "founded", "began", "started"}
        ]
    return tokens

def _has_likely_person_name_for_fact_relation(text: str) -> bool:
    person_noise_tokens = {
        "model", "models", "theory", "approach",
        "introduction", "chapter", "division", "university",
        "science", "scientific", "learning",
    }
    for m in re.findall(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", str(text or "")):
        toks = [t.lower() for t in re.findall(r"[A-Za-z]+", m)]
        if len(toks) < 2:
            continue
        if all(t in person_noise_tokens for t in toks):
            continue
        if sum(1 for t in toks if t not in person_noise_tokens) >= 2:
            return True
    return False

def _chunk_satisfies_fact_relation_rule(chunk_text: str, query_text: str, fact_type: str | None) -> bool:
    raw = str(chunk_text or "")
    ql = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not raw.strip():
        return False

    subject_terms = _extract_relation_subject_terms(query_text, fact_type)
    required_subject_hits = 1 if len(subject_terms) <= 1 else min(2, len(subject_terms))
    sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", raw) if str(s or "").strip()]
    if not sentences:
        sentences = [raw]

    for sent in sentences:
        sl = sent.lower()
        subject_hits = sum(1 for tok in subject_terms if re.search(rf"\b{re.escape(tok)}\b", sl))
        has_subject = bool(subject_terms) and (subject_hits >= required_subject_hits)

        if fact_type == "who":
            has_person_name = _has_likely_person_name_for_fact_relation(sent)
            has_action_verb = bool(
                re.search(
                    r"\b(?:proposed|developed|introduced|established|founded|created|coined|considered)\b",
                    sl,
                )
            )
            has_noun_relation = bool(
                re.search(
                    r"\b(?:founder|co-?founder|creator|developer|originator|inventor|author|discoverer|pioneer|father|architect|proposer|initiator)\s+of\b",
                    sl,
                )
            )
            if has_person_name and (has_action_verb or has_noun_relation) and has_subject:
                return True

        elif fact_type == "when":
            has_event_word = bool(
                re.search(
                    r"\b(?:emerge|emerged|emergence|began|started|originated|origin)\b",
                    sl,
                )
            )
            has_valid_year = bool(re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", sl))
            if has_subject and has_event_word and has_valid_year:
                return True
        else:
            return True

    return False

def _prefilter_fact_docs_by_relation(query_text: str, docs: list[dict], fact_type: str | None) -> list[dict]:
    if fact_type not in {"who", "when"}:
        return list(docs or [])

    valid_docs: list[dict] = []
    for doc in (docs or []):
        txt = str((doc or {}).get("text") or (doc or {}).get("page_content") or (doc or {}).get("content") or "")
        if _chunk_satisfies_fact_relation_rule(txt, query_text, fact_type):
            valid_docs.append(doc)

    if valid_docs or fact_type != "who":
        return valid_docs

    ql = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if "model" not in ql:
        return valid_docs

    subject_terms = _extract_relation_subject_terms(query_text, fact_type)
    if not subject_terms:
        return valid_docs

    def _source_key(d: dict) -> str:
        md = dict((d or {}).get("metadata") or {})
        return str(md.get("source") or md.get("file_name") or md.get("filename") or md.get("doc_id") or "").strip().lower()

    def _chunk_index(d: dict) -> int | None:
        md = dict((d or {}).get("metadata") or {})
        raw_idx = md.get("chunk_index")
        if raw_idx is None:
            return None
        try:
            return int(raw_idx)
        except Exception:
            return None

    subject_positions: dict[str, list[int]] = {}
    for doc in (docs or []):
        txt = str((doc or {}).get("text") or (doc or {}).get("page_content") or (doc or {}).get("content") or "")
        sl = txt.lower()
        subject_hits = sum(1 for tok in subject_terms if re.search(rf"\b{re.escape(tok)}\b", sl))
        if subject_hits <= 0:
            continue
        sk = _source_key(doc)
        ci = _chunk_index(doc)
        if not sk or ci is None:
            continue
        subject_positions.setdefault(sk, []).append(ci)

    if not subject_positions:
        return valid_docs

    neighbor_valid: list[dict] = []
    for doc in (docs or []):
        txt = str((doc or {}).get("text") or (doc or {}).get("page_content") or (doc or {}).get("content") or "")
        sk = _source_key(doc)
        ci = _chunk_index(doc)
        if not sk or ci is None or sk not in subject_positions:
            continue

        close_to_subject = any(abs(ci - subj_idx) <= 12 for subj_idx in subject_positions.get(sk, []))
        if not close_to_subject:
            continue

        has_person_name = _has_likely_person_name_for_fact_relation(txt)
        has_action_verb = bool(
            re.search(
                r"\b(?:proposed|developed|introduced|established|founded|created|coined|considered)\b",
                txt.lower(),
            )
        )
        if has_person_name and has_action_verb:
            neighbor_valid.append(doc)

    return neighbor_valid

def _build_relation_rescue_query(query_text: str, fact_type: str | None) -> str:
    q = re.sub(r"\s+", " ", str(query_text or "").strip())
    subject_terms = _extract_relation_subject_terms(q, fact_type)
    subject_part = " ".join(subject_terms[:4]).strip()

    if subject_part and subject_part.lower() not in q.lower():
        return f"{q} {subject_part}".strip()
    return q

def _with_fact_context_mode(docs: list[dict], mode: str) -> list[dict]:
    tagged: list[dict] = []
    for d in (docs or []):
        d2 = dict(d or {})
        d2["_fact_context_mode"] = mode
        tagged.append(d2)
    return tagged

def _select_multichunk_fact_fallback_docs(
    query_text: str,
    docs: list[dict],
    fact_type: str | None,
    top_n: int = 20,
    max_select: int = 6,
) -> list[dict]:
    if fact_type not in {"who", "when"}:
        return []

    q_raw = re.sub(r"\s+", " ", str(query_text or "").strip())
    subject_terms = _extract_relation_subject_terms(q_raw, fact_type)
    if not docs:
        return []

    person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b")
    year_re = re.compile(r"\b(1[5-9]\d{2}|20\d{2})\b")
    who_action_re = re.compile(
        r"\b(?:proposed|developed|introduced|established|founded|created|coined|considered)\b",
        flags=re.IGNORECASE,
    )
    when_event_re = re.compile(
        r"\b(?:emerge|emerged|emergence|began|started|originated|origin)\b",
        flags=re.IGNORECASE,
    )

    q_low = q_raw.lower()
    query_has_origin_event = bool(re.search(r"\b(?:emerg|origin|began|started|first|establish|founded)\b", q_low))
    scored: list[tuple[int, int, dict, dict]] = []
    for idx, doc in enumerate((docs or [])[: max(1, int(top_n or 20))]):
        txt = str((doc or {}).get("text") or (doc or {}).get("page_content") or (doc or {}).get("content") or "")
        if not txt.strip():
            continue
        low = txt.lower()
        subject_hits = sum(
            1
            for tok in subject_terms
            if re.search(rf"\b{re.escape(tok)}\b", low)
        )
        has_subject = subject_hits > 0
        has_person = bool(person_name_re.search(txt))
        has_year = bool(year_re.search(txt))
        has_who_action = bool(who_action_re.search(low))
        has_when_event = bool(when_event_re.search(low))
        has_father_phrase = bool(re.search(r"\bfather\s+of\b", low))
        person_action = bool(has_person and has_who_action)

        score = 0
        if has_subject:
            score += 4 + min(2, subject_hits)
        if fact_type == "who":
            if has_person:
                score += 3
            if has_who_action:
                score += 2
        if fact_type == "when":
            if has_year:
                score += 3
            if has_when_event:
                score += 4
            elif query_has_origin_event:
                score -= 2

        qualifies = False
        if fact_type == "who":
            qualifies = bool(has_subject or person_action)
        elif fact_type == "when":
            qualifies = bool(has_subject and has_year)
        if (score <= 0) or (not qualifies):
            continue
        scored.append(
            (
                score,
                idx,
                doc,
                {
                    "subject": has_subject,
                    "person": has_person,
                    "person_action": person_action,
                    "year": has_year,
                    "who_action": has_who_action,
                    "when_event": has_when_event,
                    "father_phrase": has_father_phrase,
                },
            )
        )

    if not scored:
        return []

    scored.sort(key=lambda x: (x[0], -x[1]), reverse=True)
    if fact_type == "who":
        required = {"subject", "person_action"}
    else:
        required = {"subject", "year"}
    selected: list[dict] = []
    seen_ids: set[int] = set()
    covered: set[str] = set()

    for _score, _idx, doc, flags in scored:
        doc_id = id(doc)
        if doc_id in seen_ids:
            continue
        adds_required = any(flags.get(k, False) and k not in covered for k in required)
        should_take = adds_required or len(selected) < min(2, max_select)
        if not should_take and len(selected) < max_select:
            should_take = _score >= 5
        if not should_take:
            continue

        selected.append(doc)
        seen_ids.add(doc_id)
        for key in ("subject", "person", "person_action", "year"):
            if flags.get(key, False):
                covered.add(key)
        if len(selected) >= max_select:
            break

    if not required.issubset(covered):
        S.logger.info(
            "[FACT MULTI-CHUNK] type=%s action=reject_incomplete_signals covered=%s required=%s",
            fact_type,
            sorted(list(covered)),
            sorted(list(required)),
        )
        return []

    S.logger.info(
        "[FACT MULTI-CHUNK] type=%s pool=%s candidates=%s selected=%s covered=%s",
        fact_type,
        len((docs or [])[: max(1, int(top_n or 20))]),
        len(scored),
        len(selected),
        sorted(list(covered)),
    )
    return selected

def _select_fact_anchor_docs(query_text: str, docs: list[dict], top_k: int = 5, scan_limit: int = 20) -> list[dict]:
    if not query_text or not docs:
        return docs

    family_v2 = _classify_query_family_v2(query_text)
    if family_v2 != "fact_entity":
        return docs

    q_raw = str(query_text or "").strip()
    q = q_raw.lower()
    fact_type = _detect_fact_query_type(q_raw)
    if fact_type == "who_when":
        S.logger.info("[FACT RELATION FILTER] type=who_when action=map_to_who_for_retrieval")
        fact_type = "who"

    stop = {
        "what", "which", "who", "whom", "whose", "when", "where", "why", "how",
        "is", "are", "was", "were", "did", "do", "does", "the", "a", "an", "of",
        "in", "on", "at", "to", "for", "from", "and", "or", "by", "it", "its", "be",
        "consider", "called",
    }
    q_terms = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in stop]
    if not q_terms:
        q_terms = [t for t in re.findall(r"[a-z0-9]{3,}", q)]

    ignore_entity_words = {
        "what", "which", "who", "when", "where", "why", "how", "in", "on", "at", "did",
        "was", "were", "is", "are", "the", "a", "an", "of", "for", "to", "by", "it",
        "this", "that", "first", "year", "model",
    }

    query_entities = [
        re.sub(r"\s+", " ", m.strip()).lower()
        for m in re.findall(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\b", q_raw)
    ]
    filtered_entities = []
    for ent in query_entities:
        tokens = [t for t in re.findall(r"[a-z]{2,}", ent) if t not in ignore_entity_words]
        if len(tokens) >= 2:
            filtered_entities.append(" ".join(tokens))
        elif len(tokens) == 1 and len(tokens[0]) >= 5:
            filtered_entities.append(tokens[0])
    query_entities = filtered_entities
    query_acronyms = [m.upper() for m in re.findall(r"\b[A-Z]{2,}\b", q_raw)]
    query_years = set(re.findall(r"\b(1[5-9]\d{2}|20\d{2})\b", q_raw))
    temporal_origin_query = bool(re.search(r"\b(?:emerg|origin|began|started|first|establish|founded|introduced|proposed)\b", q))
    query_actions = [
        a for a in (
            "established", "founded", "proposed", "introduced", "considered",  "developed", "emerged", "started",
        )
        if a in q
    ]
    query_focus_terms = [
        t for t in q_terms
        if t not in {"who", "what", "when", "where", "is", "are", "was", "were", "did", "year", "it"}
    ]
    ambiguous_when_subject = bool(fact_type == "when" and len([t for t in query_focus_terms if t not in {"established", "founded", "first"}]) == 0)
    query_domain_terms = query_focus_terms

    scored_rows: list[tuple[float, bool, dict, dict]] = []
    pool = list(docs[: max(1, min(int(scan_limit or 20), len(docs)))])
    tail = list(docs[len(pool):])
    relation_filter_applied = False
    fact_context_mode = "strict_relation"

    relation_filtered_pool = _prefilter_fact_docs_by_relation(q_raw, pool, fact_type)
    if fact_type in {"who", "when"}:
        is_model_style_query = bool(re.search(r"\bmodel\b", q_raw.lower()))
        has_query_acronym = bool(re.search(r"\b[A-Z]{2,}\b", q_raw))
        is_when_origin_query = bool(
            fact_type == "when"
            and re.search(r"\b(?:emerg|origin|began|started|first|establish|founded)\b", q_raw.lower())
        )
        enable_multi_chunk_fallback = bool(
            (fact_type == "who" and (is_model_style_query or has_query_acronym))
            or is_when_origin_query
        )
        if relation_filtered_pool:
            relation_filter_applied = True
            S.logger.info(
                "[FACT RELATION FILTER] type=%s total=%s valid=%s action=relation_only_before_scoring",
                fact_type,
                len(pool),
                len(relation_filtered_pool),
            )
            pool = relation_filtered_pool
            tail = []
        else:
            rescue_query = _build_relation_rescue_query(q_raw, fact_type)
            rescue_docs = []
            try:
                rescue_top_k = min(FACT_MAX_TOP_K, max(8, int(scan_limit or 20)))
                S.logger.info("[FACT TOPK] stage=_select_fact_anchor_docs.relation_rescue requested=%s used=%s", int(scan_limit or 20), rescue_top_k)
                rescue_docs = _search_fast_minimal(rescue_query, top_k=rescue_top_k) or []
            except Exception:
                rescue_docs = []
            rescue_valid = _prefilter_fact_docs_by_relation(q_raw, rescue_docs, fact_type)
            if rescue_valid:
                if enable_multi_chunk_fallback:
                    multi_source_pool = list((pool or []) + (tail or []) + (rescue_docs or []))
                    multi_docs = _select_multichunk_fact_fallback_docs(
                        q_raw,
                        multi_source_pool,
                        fact_type,
                        top_n=max(10, min(20, len(multi_source_pool))),
                        max_select=6,
                    )
                    if multi_docs:
                        relation_filter_applied = True
                        fact_context_mode = "multi_chunk"
                        S.logger.info(
                            "[FACT RELATION FILTER] type=%s total=%s valid=0 rescue_valid=%s action=multi_chunk_over_rescue selected=%s",
                            fact_type,
                            len(pool),
                            len(rescue_valid),
                            len(multi_docs),
                        )
                        pool = multi_docs
                        tail = []
                    else:
                        relation_filter_applied = True
                        S.logger.info(
                            "[FACT RELATION FILTER] type=%s total=%s valid=0 rescue_valid=%s action=relation_rescue_before_scoring",
                            fact_type,
                            len(pool),
                            len(rescue_valid),
                        )
                        pool = rescue_valid
                        tail = []
                else:
                    relation_filter_applied = True
                    S.logger.info(
                        "[FACT RELATION FILTER] type=%s total=%s valid=0 rescue_valid=%s action=relation_rescue_before_scoring",
                        fact_type,
                        len(pool),
                        len(rescue_valid),
                    )
                    pool = rescue_valid
                    tail = []
            else:
                if enable_multi_chunk_fallback:
                    multi_source_pool = list((pool or []) + (tail or []))
                    multi_docs = _select_multichunk_fact_fallback_docs(
                        q_raw,
                        multi_source_pool,
                        fact_type,
                        top_n=max(10, min(20, len(multi_source_pool))),
                        max_select=6,
                    )
                    if multi_docs:
                        relation_filter_applied = True
                        fact_context_mode = "multi_chunk"
                        S.logger.info(
                            "[FACT RELATION FILTER] type=%s total=%s valid=0 action=multi_chunk_fallback selected=%s",
                            fact_type,
                            len(pool),
                            len(multi_docs),
                        )
                        pool = multi_docs
                        tail = []
                    else:
                        S.logger.info(
                            "[FACT RELATION FILTER] type=%s total=%s valid=0 action=fallback_original_pipeline",
                            fact_type,
                            len(pool),
                        )
                else:
                    S.logger.info(
                        "[FACT RELATION FILTER] type=%s total=%s valid=0 action=fallback_original_pipeline",
                        fact_type,
                        len(pool),
                    )

    term_doc_freq: dict[str, int] = {}
    for t in q_terms:
        try:
            term_doc_freq[t] = sum(
                1
                for d in pool
                if re.search(
                    rf"\b{re.escape(t)}\b",
                    str((d or {}).get("text") or (d or {}).get("page_content") or (d or {}).get("content") or "").lower(),
                )
            )
        except Exception:
            term_doc_freq[t] = len(pool)

    non_discriminative_terms = {
        "year", "years", "model", "first", "established", "establish", "founded",
        "proposed", "introduced", "considered",  "emerged", "emerge", "started", "start",
    }
    rarity_threshold = max(2, int(max(1, len(pool)) * 0.25))
    rare_terms = {
        t for t in q_terms
        if t not in non_discriminative_terms and term_doc_freq.get(t, len(pool)) <= rarity_threshold
    }
    critical_terms = set(rare_terms)
    if "laboratory" in q_terms:
        critical_terms.add("laboratory")
    if "father" in q_terms:
        critical_terms.add("father")
    for ac in query_acronyms:
        critical_terms.add(ac.lower())

    person_name_counts: dict[str, int] = {}
    if fact_type == "who" and "father" in q_terms:
        person_noise = {"Introduction", "Chapter", "Unit", "Table", "Figure", "Theory", "Model", "Approach"}
        for d in pool:
            raw = str((d or {}).get("text") or (d or {}).get("page_content") or (d or {}).get("content") or "")
            for nm in re.findall(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", raw):
                tokens_nm = [t for t in str(nm).split() if t not in person_noise]
                if len(tokens_nm) < 2:
                    continue
                norm_nm = " ".join(tokens_nm).strip().lower()
                if not norm_nm:
                    continue
                person_name_counts[norm_nm] = person_name_counts.get(norm_nm, 0) + 1

    for idx, doc in enumerate(pool):
        txt_raw = str((doc or {}).get("text") or (doc or {}).get("page_content") or (doc or {}).get("content") or "")
        txt = txt_raw.lower()
        md = dict((doc or {}).get("metadata") or {})
        tokens = re.findall(r"[a-z0-9]{2,}", txt)
        token_count = len(tokens)
        if token_count == 0:
            continue

        term_hits = [t for t in q_terms if re.search(rf"\b{re.escape(t)}\b", txt)]
        critical_hits = [t for t in critical_terms if re.search(rf"\b{re.escape(t)}\b", txt)]
        overlap = (len(term_hits) / max(1, len(q_terms)))
        critical_coverage = (len(critical_hits) / max(1, len(critical_terms))) if critical_terms else 0.0

        entity_match_bonus = 0.0
        for ent in query_entities:
            if re.search(rf"\b{re.escape(ent)}\b", txt):
                entity_match_bonus += 0.8
        for ac in query_acronyms:
            if re.search(rf"\b{re.escape(ac.lower())}\b", txt):
                entity_match_bonus += 1.25 if fact_type == "who" else 0.75
        if fact_type == "when":
            entity_match_bonus = min(entity_match_bonus, 0.25)

        chunk_years = set(re.findall(r"\b(1[5-9]\d{2}|20\d{2})\b", txt))
        person_name_for_meta = bool(re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", txt_raw))
        sent_with_year_for_behavior = [
            s for s in re.split(r"(?<=[.!?])\s+|\n+", txt_raw)
            if re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", str(s or ""))
        ]
        number_match_bonus = 0.0
        year_age_bonus = 0.0
        if ambiguous_when_subject and chunk_years:
            try:
                earliest_year = min(int(y) for y in chunk_years)
                year_age_bonus = max(0.0, (2100.0 - float(earliest_year)) / 450.0)
            except Exception:
                year_age_bonus = 0.0
        temporal_origin_hit = False
        temporal_bio_penalty = 0.0
        if fact_type == "when" and chunk_years:
            subject_terms = [t for t in q_terms if t not in {"when", "year", "did", "was", "were", "is", "are"}]
            sent_with_year = [
                s for s in re.split(r"(?<=[.!?])\s+|\n+", txt_raw)
                if re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", str(s or ""))
            ]
            best_support = -0.6
            for s_raw in sent_with_year:
                s = str(s_raw or "").lower()
                support = 0.0
                subj_hits = sum(1 for t in subject_terms if re.search(rf"\b{re.escape(t)}\b", s))
                if subj_hits > 0:
                    support += min(0.7, 0.35 * subj_hits)
                has_origin_word = bool(re.search(r"\b(?:emerg(?:ed|ence)?|origin(?:s|ated)?|began|started|first|establish(?:ed)?|founded|introduced|proposed)\b", s))
                if has_origin_word:
                    support += 0.95
                if re.search(r"\b(?:born|died|aged?|years?\s+old|founder\s+of)\b", s):
                    support -= 0.75
                if re.search(r"\(\s*(1[5-9]\d{2}|20\d{2})\s*[-–]\s*(1[5-9]\d{2}|20\d{2})\s*\)", s):
                    support -= 0.65
                if re.search(r"\(\s*(1[5-9]\d{2}|20\d{2})\s*\)\s*[:\-]", s) and re.search(r"\bfounder\b", s):
                    support -= 0.55
                if support > best_support:
                    best_support = support
                if has_origin_word and subj_hits > 0:
                    temporal_origin_hit = True
            temporal_bio_penalty = max(0.0, -best_support) * 0.6
            number_match_bonus = 0.55 + best_support + year_age_bonus
        if query_years:
            number_match_bonus += 0.9 if (query_years & chunk_years) else -0.25
        elif fact_type == "when" and not chunk_years:
            number_match_bonus += -0.35

        positions = []
        for t in term_hits:
            try:
                positions.extend(i for i, tok in enumerate(tokens) if tok == t)
            except Exception:
                pass
        proximity = 0.0
        if len(positions) >= 2:
            span = max(positions) - min(positions) + 1
            proximity = max(0.0, 1.0 - ((span - 2) / 30.0))
        elif len(positions) == 1:
            proximity = 0.25

        chunk_entities = re.findall(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\b", txt_raw)
        direct_fact_bonus = 0.0
        if fact_type == "who":
            has_action = bool(query_actions and any(re.search(rf"\b{re.escape(a)}\b", txt) for a in query_actions))
            if not has_action:
                has_action = bool(re.search(r"\b(?:established|founded|proposed|introduced|considered|known\s+as|developed)\b", txt))
            focus_hits = sum(1 for t in query_focus_terms if re.search(rf"\b{re.escape(t)}\b", txt))
            if chunk_entities and has_action and (focus_hits >= 1):
                direct_fact_bonus += 0.85
            if "father" in query_actions and re.search(r"\bfather\s+of\b", txt):
                direct_fact_bonus += 0.5
                direct_fact_bonus += 2.2
                direct_fact_bonus += 1.25
            if query_acronyms and any(re.search(rf"\b{re.escape(a.lower())}\b", txt) for a in query_acronyms):
                direct_fact_bonus += 0.95
                direct_fact_bonus += 1.3
                direct_fact_bonus += 1.0
                direct_fact_bonus += 1.6
        elif fact_type == "when":
            if chunk_years and re.search(r"\b(?:in|during|year|emerged|established|introduced|proposed|first)\b", txt):
                direct_fact_bonus += 0.9
            if temporal_origin_query and temporal_origin_hit:
                direct_fact_bonus += 0.7
            elif temporal_origin_query and chunk_years:
                direct_fact_bonus -= 0.35
        else:
            if re.search(r"\b(?:is|was|introduced|proposed|established|known\s+as)\b", txt):
                direct_fact_bonus += 0.35

        if _is_metric_fact_query(q_raw):
            # Generic, evidence-driven boost: reward chunks that mention the
            # question's concept terms AND carry a number of the shape the
            # question asks for (currency, percent, ratio…). No specific value
            # is referenced, so this works for any document's metrics.
            txt_low = txt_raw.lower()
            metric_concepts = _evidence_concept_tokens(q_raw)
            concept_hits = sum(1 for tok in metric_concepts if tok in txt_low)
            has_metric_value = any(
                _EVIDENCE_VALUE_PATTERNS[t].search(txt_raw)
                for t in _evidence_value_types_for_query(q_raw)
                if t in _EVIDENCE_VALUE_PATTERNS
            )
            if concept_hits and has_metric_value:
                direct_fact_bonus += min(4.0, 1.5 + float(concept_hits))

        generic_penalty = 0.0
        if fact_type == "who" and critical_terms and not critical_hits:
            generic_penalty += 1.1
        if "laboratory" in q_terms and not re.search(r"\blaborator(?:y|ies)\b", txt):
            generic_penalty += 1.1
            generic_penalty += 0.85
            generic_penalty += 1.5
        if query_acronyms and not any(re.search(rf"\b{re.escape(a.lower())}\b", txt) for a in query_acronyms):
            generic_penalty += 0.95
            generic_penalty += 1.4
            generic_penalty += 1.6
            generic_penalty += 0.9
        if fact_type == "who" and query_acronyms and not person_name_for_meta:
            generic_penalty += 1.35
            generic_penalty += 1.35
            generic_penalty += 0.85
        if fact_type == "when" and temporal_origin_query and not re.search(r"\b(?:emerg(?:ed|ence)?|origin(?:s|ated)?|began|started|first|establish(?:ed)?|founded|introduced|proposed)\b", txt):
            generic_penalty += 0.55
        if _looks_table_or_heading_like_chunk(txt_raw[:1800]):
            generic_penalty += 0.9
        lines = [ln.strip() for ln in txt_raw.splitlines() if ln.strip()]
        bullet_lines = [ln for ln in lines if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", ln)]
        if lines and (len(bullet_lines) / max(1, len(lines))) >= 0.4:
            generic_penalty += 0.35
        if token_count > 130 and overlap < 0.45 and not chunk_years and not chunk_entities:
            generic_penalty += 0.55
        if _is_metric_fact_query(q_raw) and re.search(r"\bdss assignment\b", txt) and not re.search(r"\d+\.\d+\s*%", txt_raw):
            generic_penalty += 2.5

        base_score = float((doc or {}).get("score", (doc or {}).get("similarity", ((doc or {}).get("metadata") or {}).get("_score", 0.0))) or 0.0)
        final_score = (
            overlap
            + (1.25 * critical_coverage)
            + entity_match_bonus
            + number_match_bonus
            + (0.65 * proximity)
            + direct_fact_bonus
            + (0.15 * base_score)
            - generic_penalty
            - temporal_bio_penalty
        )

        if fact_type == "when" and temporal_origin_query:
            has_direct_anchor = bool(
                chunk_years
                and (
                    temporal_origin_hit
                    or bool(critical_hits)
                )
                and overlap >= 0.2
            )
        elif fact_type == "who":
            person_name_hit = bool(re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", txt_raw))
            focus_hits = sum(1 for t in query_focus_terms if re.search(rf"\b{re.escape(t)}\b", txt))
            has_direct_anchor = bool(
                person_name_hit
                and direct_fact_bonus >= 0.75
                and (
                    bool(critical_hits)
                    or focus_hits >= 2
                    or overlap >= 0.5
                )
            )
        else:
            has_direct_anchor = bool(
                overlap >= 0.45
                and (
                    entity_match_bonus >= 0.55
                    or number_match_bonus >= 0.5
                    or direct_fact_bonus >= 0.75
                )
            )

        S.logger.info(
            "[FACT ANCHOR SCORE] idx=%s chunk=%s score=%.3f overlap=%.2f crit=%.2f ent=%.2f num=%.2f prox=%.2f direct=%.2f penalty=%.2f temporal_pen=%.2f",
            idx,
            md.get("chunk_index"),
            float(final_score),
            float(overlap),
            float(critical_coverage),
            float(entity_match_bonus),
            float(number_match_bonus),
            float(proximity),
            float(direct_fact_bonus),
            float(generic_penalty),
            float(temporal_bio_penalty),
        )

        person_name_for_meta = bool(re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", txt_raw))
        acronym_hit_for_meta = bool(query_acronyms and any(re.search(rf"\b{re.escape(a.lower())}\b", txt) for a in query_acronyms))
        person_action_hit_for_meta = bool(
            person_name_for_meta
            and re.search(r"\b(?:developed|proposed|introduced|established|founded|considered|known\s+as)\b", txt)
        )
        father_domain_hit_for_meta = False
        abc_model_hit_for_meta = False
        abc_person_hit_for_meta = False

        scored_rows.append((final_score, has_direct_anchor, doc, {
            "chunk_index": md.get("chunk_index"),
            "page": md.get("page"),
            "preview": re.sub(r"\s+", " ", txt_raw).strip()[:180],
            "acronym_hit": acronym_hit_for_meta,
            "person_action_hit": person_action_hit_for_meta,
            "father_domain_hit": father_domain_hit_for_meta,
            "abc_model_hit": abc_model_hit_for_meta,
            "abc_person_hit": abc_person_hit_for_meta,
            "has_year": bool(chunk_years),
            "earliest_year": (min(int(y) for y in chunk_years) if chunk_years else None),
        }))

    if not scored_rows:
        return docs

    scored_rows.sort(key=lambda x: (x[0], x[1]), reverse=True)

    pinned_docs: list[dict] = []
    pinned_ids: set[int] = set()

    def _pin_row(row: tuple[float, bool, dict, dict]) -> None:
        d = row[2]
        did = id(d)
        if did in pinned_ids:
            return
        pinned_ids.add(did)
        pinned_docs.append(d)

    if fact_type == "who" and query_acronyms:
        abc_person_row = next((r for r in scored_rows if r[3].get("abc_person_hit")), None)
        abc_model_row = next((r for r in scored_rows if r[3].get("abc_model_hit")), None)
        acronym_row = next((r for r in scored_rows if r[3].get("acronym_hit")), None)
        person_action_row = next((r for r in scored_rows if r[3].get("person_action_hit")), None)
        if abc_person_row is not None:
            _pin_row(abc_person_row)
        if abc_model_row is not None:
            _pin_row(abc_model_row)
        if acronym_row is not None:
            _pin_row(acronym_row)
        if person_action_row is not None:
            _pin_row(person_action_row)

    if fact_type == "who" and "father" in q_terms:
        father_row = next((r for r in scored_rows if r[3].get("father_domain_hit")), None)
        if father_row is not None:
            _pin_row(father_row)

    anchors = [row for row in scored_rows if row[1]]
    min_anchor_docs = 2 if len(scored_rows) >= 4 else 1
    for row in anchors[:min_anchor_docs]:
        _pin_row(row)

    for row in scored_rows:
        _pin_row(row)

    if top_k and top_k > 0:
        top_k = int(top_k)
    else:
        top_k = len(pinned_docs)

    selected_preview = []
    for i, row in enumerate(scored_rows[: max(1, min(top_k, 5))]):
        selected_preview.append({
            "rank": i,
            "score": round(float(row[0]), 4),
            "anchor": bool(row[1]),
            "chunk_index": row[3].get("chunk_index"),
            "page": row[3].get("page"),
            "preview": row[3].get("preview"),
        })
    S.logger.info("[FACT CHUNK SELECTION] query=%s selected=%s", q_raw[:140], selected_preview)

    ordered_pool = pinned_docs + [d for d in pool if id(d) not in pinned_ids]
    selected_docs = ordered_pool if relation_filter_applied else (ordered_pool + tail)
    return _with_fact_context_mode(selected_docs, fact_context_mode)

def _rerank_docs_for_query_intent(query_text: str, retrieved_docs: list[dict]) -> list[dict]:
    if not query_text or not retrieved_docs:
        return retrieved_docs

    q_raw = (query_text or "").strip()
    q = q_raw.lower()
    family_v2 = _classify_query_family_v2(q_raw)
    is_fact_q = family_v2 == "fact_entity"
    # P1: Use word-boundary detection instead of substring "in" checks so
    # benign tokens (e.g. "punctual", "discontent") don't trigger structure intent.
    if re.search(r"\b(?:unit|chapter)s?\b", q):
        retrieval_intent = "chapter"
    elif _is_list_query(q_raw) or re.search(r"\b(?:section|sections|table of contents|contents|topics)\b", q):
        retrieval_intent = "structure"
    else:
        retrieval_intent = "general"
    # P1: Reuse the centralized definition / list classifiers instead of fragile
    # startswith / "in" substring tests. Keep person-vs-concept distinction by
    # checking for an explicit interrogative on a real person-pattern phrasing
    # (word-boundary "who is/was/introduced/considered" — never matches "who is not"
    # because the negation is captured separately and de-prioritized via family).
    is_definition_q = (not is_fact_q) and _is_definition_style_query(q_raw)
    is_person_definition_q = bool(
        is_definition_q
        and re.match(r"^\s*who\s+(?:is|was|introduced|founded|considered)\b", q)
        and not re.match(r"^\s*who\s+(?:is|was)\s+(?:not|this|that|it)\b", q)
    )
    is_concept_definition_q = is_definition_q and not is_person_definition_q
    is_entity_definition_q = is_definition_q
    # P1: drop "'only' in q" — too FP-prone (matches "the only thing", etc.).
    is_list_q = _is_list_query(q_raw)
    is_structure_q = retrieval_intent in {"chapter", "structure"}
    is_overview_q = bool(
        re.search(r"\b(?:overview|summary|summarize|main\s+ideas?)\b", q)
        or "what is this document about" in q
    )
    hard_noise_patterns = (
        r"\bcommentary\b",
        r"\bfurther\s+reading\b",
        r"\breferences?\b",
        r"\bbibliograph(?:y|ies)\b",
        r"\bworks\s+cited\b",
        r"\bconnections?\s+see\s+the\b",
    )
    publisher_noise_patterns = (
        r"\bself[-\s]*published\b",
        r"\bcreatespace\b",
        r"\bisbn\b",
        r"\bopenstax\b",
        r"\bindex\b",
    )
    stop = {
        "what", "is", "are", "the", "a", "an", "in", "of", "to", "and", "or", "who", "when", "where",
        "different", "define", "only", "list", "please", "tell", "about", "from", "document",
    }
    q_tokens = [t for t in re.findall(r"[a-zA-Z]{3,}", q) if t not in stop]
    named_entities = {e.lower() for e in re.findall(r"\b[A-Z][a-z]{2,}\b", q_raw)}
    _, definition_entity = _extract_entity_from_definition_query(q_raw)
    definition_entity_l = definition_entity.lower()
    normalized_phrase = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", definition_entity_l)).strip()
    definition_reject_re = re.compile(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", re.IGNORECASE)
    definition_heading_intro_re = re.compile(
        r"(?im)^\s*(?:introduction|overview|summary|contents?|table of contents|chapter\s+\d+|unit\s+\d+|learning objectives?|key terms?)\s*[:\-–—]?\s*$"
    )
    concept_def_verb_re = re.compile(r"\b(?:is|refers to|defined as|known as)\b", re.IGNORECASE)
    attribution_verb_re = re.compile(r"\b(?:is|was|known as|introduced)\b", re.IGNORECASE)
    person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b")

    explain_verbs_re = re.compile(
        r"\b(?:is|refers\s+to|means|focuses\s+on|involves|developed|emerged|consists\s+of|includes)\b",
        re.IGNORECASE,
    )
    comparison_re = re.compile(r"\b(?:better\s+than|worse\s+than|compared\s+to|in\s+contrast\s+to|unlike)\b", re.IGNORECASE)
    list_like_re = re.compile(r"(?m)^\s*(?:[-•*]|\d+[.)])\s+")
    table_or_classification_re = re.compile(r"\b(?:table|classification|major\s+classification|contributors?)\b", re.IGNORECASE)

    def _generic_mixed_topic_fragment_count(text_value: str) -> int:
        lines_local = [re.sub(r"\s+", " ", ln).strip() for ln in str(text_value or "").splitlines() if str(ln or "").strip()]
        count = 0
        for line_value in lines_local[:80]:
            words_local = re.findall(r"[A-Za-z][A-Za-z'\-]*", line_value)
            if not (2 <= len(words_local) <= 10):
                continue
            if list_like_re.match(line_value) or line_value.endswith(":"):
                count += 1
                continue
            title_words = sum(1 for word in words_local if word[:1].isupper())
            if title_words >= max(2, len(words_local) // 2) and not re.search(r"[.!?]$", line_value):
                count += 1
        return count

    query_entity = ""
    try:
        _ok, _ent = _extract_entity_from_definition_query(q_raw)
        if _ok:
            query_entity = (_ent or "").strip().lower()
    except Exception:
        query_entity = ""

    query_tokens_for_explain = _explanation_focus_tokens(q_raw)
    if not query_tokens_for_explain:
        query_tokens_for_explain = [t for t in re.findall(r"[a-z0-9]{3,}", q)]

    def _doc_text(doc: dict) -> str:
        return str((doc or {}).get("text") or (doc or {}).get("page_content") or "")

    def _is_explanatory_chunk(text: str, query: str) -> bool:
        txt_raw = str(text or "")
        txt = txt_raw.lower()
        if len(txt_raw.strip()) < 200:
            return False
        if _looks_table_or_heading_like_chunk(txt_raw[:1800]):
            return False
        if table_or_classification_re.search(txt[:1200]):
            return False

        lines = [ln.strip() for ln in txt_raw.splitlines() if ln.strip()]
        bullet_lines = [ln for ln in lines if list_like_re.match(ln)]
        bullet_ratio = (len(bullet_lines) / max(1, len(lines))) if lines else 0.0
        if bullet_ratio >= 0.35:
            return False

        qtoks = [t for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower()) if t not in stop]
        if not qtoks:
            qtoks = [t for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower())]
        if qtoks:
            token_hits = sum(1 for t in qtoks if re.search(rf"\b{re.escape(t)}\b", txt))
            coverage = token_hits / max(1, len(qtoks))
            if coverage < 0.5:
                return False

        has_explain_verb = bool(explain_verbs_re.search(txt))
        long_sentence = any(
            len(re.findall(r"[a-z0-9]{2,}", s.lower())) >= 16
            for s in re.split(r"(?<=[.!?])\s+|\n+", txt_raw)
            if s and s.strip()
        )
        return bool(has_explain_verb or long_sentence)

    def _hard_explain_reject_reason(doc: dict) -> str | None:
        txt_raw = _doc_text(doc)
        txt = txt_raw.lower()
        if not txt.strip():
            return "empty"

        lines = [ln.strip() for ln in txt_raw.splitlines() if ln.strip()]
        bullet_lines = [ln for ln in lines if list_like_re.match(ln)]
        bullet_ratio = (len(bullet_lines) / max(1, len(lines))) if lines else 0.0
        if _looks_table_or_heading_like_chunk(txt_raw[:1800]) or table_or_classification_re.search(txt[:1400]) or bullet_ratio >= 0.45:
            return "table_or_classification"

        token_hits = sum(1 for t in query_tokens_for_explain if re.search(rf"\b{re.escape(t)}\b", txt))
        density = token_hits / max(1, len(re.findall(r"[a-z0-9]{2,}", txt)))
        coverage = (token_hits / max(1, len(query_tokens_for_explain))) if query_tokens_for_explain else 0.0
        if coverage < 0.4 or density < 0.008:
            return "incidental_mention_low_density"

        if comparison_re.search(txt):
            return "comparison_fragment"

        if query_entity and (query_entity not in txt):
            if _generic_mixed_topic_fragment_count(txt_raw[:1800]) >= 3:
                return "different_concept_focus"

        return None

    def _is_hard_noise(doc: dict) -> bool:
        md = (doc or {}).get("metadata") or {}
        txt = str((doc or {}).get("text") or "")[:1200]
        txt_l = txt.lower()
        sec_l = str(md.get("section") or "").lower()
        title_l = str(md.get("title") or "").lower()
        chap_l = str(md.get("chapter") or "").lower()
        hay = f"{sec_l}\n{chap_l}\n{txt_l}"
        is_toc_like = ("table of contents" in hay or "contents" in hay)
        has_structure = bool(re.search(r"\bchapter\s+\d+\b", hay)) or bool(re.search(r"\b\d+\.\d+\b", hay))
        if retrieval_intent in {"chapter", "structure"} and is_toc_like:
            if re.search(r"(?im)^\s*(references?|review questions?|further reading)\b", txt_l):
                return True
            return False
        if any(re.search(pat, txt_l, flags=re.IGNORECASE) for pat in hard_noise_patterns):
            if retrieval_intent in {"chapter", "structure"} and is_toc_like and has_structure:
                if re.search(r"(?im)^\s*(references?|review questions?|further reading)\b", txt_l):
                    return True
                return False
            return True
        if any(re.search(pat, title_l, flags=re.IGNORECASE) for pat in hard_noise_patterns):
            if len(txt_l.split()) < 120:
                return True
        if any(re.search(pat, hay, flags=re.IGNORECASE) for pat in publisher_noise_patterns):
            if retrieval_intent in {"chapter", "structure"} and has_structure:
                return False
            if len(txt_l.split()) < 45 and len(re.findall(r"\([12][0-9]{3}\)|\[[0-9]{1,3}\]|https?://", hay)) >= 4:
                return True
        return False

    cleaned_docs = [doc for doc in retrieved_docs if not _is_hard_noise(doc)]
    if cleaned_docs:
        retrieved_docs = cleaned_docs

    if (not is_fact_q) and (not is_list_q) and (not is_structure_q):
        explain_prefiltered_docs = []
        for doc in retrieved_docs:
            reject_reason = _hard_explain_reject_reason(doc)
            if reject_reason:
                md = (doc or {}).get("metadata") or {}
                S.logger.info(
                    "[EXPLAIN FILTER] rejected chunk_index=%s reason=%s",
                    md.get("chunk_index"),
                    reject_reason,
                )
                continue
            explain_prefiltered_docs.append(doc)

        if explain_prefiltered_docs:
            retrieved_docs = explain_prefiltered_docs
        elif retrieved_docs:
            fallback_doc = max(
                retrieved_docs,
                key=lambda d: (
                    len(_doc_text(d))
                    + int(
                        50
                        * float(
                            d.get(
                                "similarity",
                                d.get("score", ((d.get("metadata") or {}).get("_score", 0.0))),
                            )
                            or 0.0
                        )
                    )
                ),
            )
            S.logger.info(
                "[EXPLAIN MODE] fallback_to_explanation chunk_index=%s",
                ((fallback_doc or {}).get("metadata") or {}).get("chunk_index"),
            )
            retrieved_docs = [fallback_doc] + [d for d in retrieved_docs if d is not fallback_doc]

    def _boost(doc: dict) -> float:
        txt_raw = _doc_text(doc)
        txt = txt_raw.lower()
        txt_normalized = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", txt)).strip()
        md = (doc or {}).get("metadata") or {}
        chunk_role = str(md.get("chunk_role") or "").lower().strip()

        if is_definition_q:
            head_window = txt_raw[:1200]
            if definition_reject_re.search(head_window):
                return -1_000_000.0
            head_lines = [ln.strip() for ln in head_window.splitlines() if ln.strip()][:8]
            heading_like_intro = any(definition_heading_intro_re.search(ln) for ln in head_lines)
            starts_with_heading_intro = bool(definition_heading_intro_re.search((head_lines[0] if head_lines else "")))
            if chunk_role in {"chapter_heading", "section_heading", "chapter_intro", "summary", "introduction", "toc"}:
                if not re.search(r"[.!?]", head_window[:260]):
                    return -1_000_000.0
            if heading_like_intro and starts_with_heading_intro and not re.search(r"[.!?]", head_window[:260]):
                return -1_000_000.0

        overlap = sum(1 for tok in q_tokens if re.search(rf"\b{re.escape(tok)}\b", txt))
        bonus = 0.08 * overlap
        def_boost_before = float(bonus)
        retrieval_boost_applied = False

        if is_definition_q and definition_entity_l:
            has_entity_phrase = bool(re.search(rf"\b{re.escape(definition_entity_l)}\b", txt))
            classical_alias_phrase_hit = bool(
                False
                and re.search(r"\b(?:classical\s+management\s+theory|classical\s+method|classical\s+management)\b", txt)
            )
            classical_contrastive_mention = bool(
                False
                and re.search(r"\b(?:improvement\s+over\s+the\s+classical\s+approach|classical\s+approach\s+which\s+focused\s+on)\b", txt)
            )
            has_def_pattern = any(pat in txt for pat in (
                " is ",
                " refers to ",
                " defined as ",
                " can be defined as ",
                " means ",
            ))
            if has_entity_phrase and has_def_pattern:
                bonus += 0.25
                retrieval_boost_applied = True

            if classical_alias_phrase_hit:
                bonus += 0.35
                retrieval_boost_applied = True

            if classical_contrastive_mention:
                bonus -= 0.90
                retrieval_boost_applied = True

            if has_entity_phrase:
                first_window = txt[: max(1, int(len(txt) * 0.30))]
                if re.search(rf"\b{re.escape(definition_entity_l)}\b", first_window):
                    bonus += 0.15
                    retrieval_boost_applied = True

            if _looks_table_or_heading_like_chunk(txt_raw[:1800]) or table_or_classification_re.search(txt[:1400]) or list_like_re.search(txt_raw):
                bonus -= 0.20
                retrieval_boost_applied = True

            if retrieval_boost_applied:
                S.logger.info("[DEF BOOST] before=%.3f after=%.3f", def_boost_before, float(bonus))
                S.logger.info("[RETRIEVAL BOOST APPLIED] chunk_index=%s", md.get("chunk_index"))

        if normalized_phrase and normalized_phrase in txt_normalized:
            bonus += 1.25
            sentence_hits = 0
            for sent in re.split(r"(?<=[.!?])\s+|\n+", txt):
                sl = sent.strip().lower()
                if not sl:
                    continue
                sl_norm = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", sl)).strip()
                if normalized_phrase in sl_norm and re.search(r"\b(is|was|refers to|defined as|means|known as|introduced|born|considered)\b", sl):
                    if len(re.findall(r"[a-z0-9]{2,}", sl)) >= 6:
                        sentence_hits += 1
                        break
            if sentence_hits:
                bonus += 1.05

        if is_concept_definition_q and re.search(r"\b(is|are|defined as|refers to|means|is the process of)\b", txt):
            bonus += 0.35

        if is_concept_definition_q and normalized_phrase:
            concept_def_sentence_hits = 0
            for sent in re.split(r"(?<=[.!?])\s+|\n+", txt_raw):
                sl = (sent or "").strip()
                if not sl:
                    continue
                sl_norm = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", sl.lower())).strip()
                has_concept = normalized_phrase in sl_norm
                if has_concept and concept_def_verb_re.search(sl):
                    concept_def_sentence_hits += 1
                    break
            if concept_def_sentence_hits:
                bonus += 1.3
            else:
                bonus -= 1.0

        if is_concept_definition_q:
            bio_hits = len(re.findall(r"\b(he|she|born|birth|died|biography)\b", txt))
            bonus -= min(1.8, 0.22 * bio_hits)

        if is_entity_definition_q and definition_entity_l:
            ent_tokens = [t for t in re.findall(r"[a-z0-9]{2,}", definition_entity_l) if t not in {"the", "a", "an", "of", "and", "in", "to"}]
            ent_hits = 0
            if re.search(rf"\b{re.escape(definition_entity_l)}\b", txt):
                ent_hits = max(ent_hits, 2)
            if ent_tokens:
                ent_hits = max(ent_hits, sum(1 for t in ent_tokens if re.search(rf"\b{re.escape(t)}\b", txt)))
            has_entity = ent_hits >= max(1, min(2, len(ent_tokens) if ent_tokens else 1))
            has_descriptive = has_entity and bool(re.search(r"\b(is|was|refers to|defined as|known as|introduced|born|developed|called|means|is the process of|considered)\b", txt))

            entity_sentences = []
            for sent in re.split(r"(?<=[.!?])\s+|\n+", txt):
                sl = (sent or "").strip().lower()
                if not sl:
                    continue
                has_entity_in_sentence = False
                if definition_entity_l and re.search(rf"\b{re.escape(definition_entity_l)}\b", sl):
                    has_entity_in_sentence = True
                elif ent_tokens:
                    token_hits_in_sentence = sum(1 for t in ent_tokens if re.search(rf"\b{re.escape(t)}\b", sl))
                    has_entity_in_sentence = token_hits_in_sentence >= max(1, min(2, len(ent_tokens)))
                if has_entity_in_sentence:
                    entity_sentences.append(sl)

            has_entity_definition_sentence = any(
                re.search(r"\b(is|was|refers to|defined as|means|known as|introduced|considered|called)\b", s)
                and len(re.findall(r"[a-z0-9]{2,}", s)) >= 6
                for s in entity_sentences
            )

            short_entity_lines = sum(
                1
                for s in entity_sentences
                if len(re.findall(r"[a-z0-9]{2,}", s)) <= 6 and not re.search(r"[.!?]", s)
            )

            if has_entity:
                bonus += 0.55
            if has_descriptive:
                bonus += 0.85
            if has_entity_definition_sentence:
                bonus += 1.15
            elif entity_sentences:
                bonus -= 1.0
            if short_entity_lines >= 1 and not has_entity_definition_sentence:
                bonus -= 1.2

            if is_concept_definition_q:
                if re.search(r"\b(is|refers to|defined as|means|is the process of)\b", txt):
                    bonus += 0.45
                if re.search(r"\b(he|she|born|birth|died|biography)\b", txt):
                    bonus -= 0.9

            if is_person_definition_q:
                attribution_sentence_found = False
                ent_token_need = max(1, min(2, len(ent_tokens))) if ent_tokens else 1
                for sent in re.split(r"(?<=[.!?])\s+|\n+", txt_raw):
                    s_raw = (sent or "").strip()
                    if not s_raw:
                        continue
                    s = s_raw.lower()
                    if not attribution_verb_re.search(s):
                        continue
                    has_entity_anchor = False
                    if normalized_phrase:
                        s_norm = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", s)).strip()
                        has_entity_anchor = normalized_phrase in s_norm
                    if not has_entity_anchor and ent_tokens:
                        token_hits = sum(1 for t in ent_tokens if re.search(rf"\b{re.escape(t)}\b", s))
                        has_entity_anchor = token_hits >= ent_token_need
                    has_person_name = bool(person_name_re.search(s_raw))
                    if has_entity_anchor and (has_person_name or attribution_verb_re.search(s)):
                        attribution_sentence_found = True
                        break

                if attribution_sentence_found:
                    bonus += 1.45
                else:
                    bonus -= 2.35

            looks_like_bad_entity_page = any(m in txt[:1400] for m in (
                "table of contents", "major classification", "classification", "contributors", "roster"
            ))
            short_lines = [ln.strip() for ln in txt.splitlines() if ln.strip()][:80]
            short_named_items = 0
            for ln in short_lines:
                words = re.findall(r"[a-z][a-z\-']*", ln)
                if 1 <= len(words) <= 5 and bool(re.match(r"^(?:[-•*]|\d+[.)])\s+", ln)):
                    short_named_items += 1
            no_sentence = not bool(re.search(r"[.!?]", txt))
            if looks_like_bad_entity_page and not has_descriptive:
                bonus -= 1.25
            if short_named_items >= 5 and no_sentence and not has_descriptive:
                bonus -= 1.05
            if is_person_definition_q:
                if "major classification" in txt[:1600] or "contributors" in txt[:1600]:
                    bonus -= 2.4
                if looks_like_bad_entity_page and not has_descriptive:
                    bonus -= 1.4
            if normalized_phrase and normalized_phrase in txt_normalized and not has_descriptive:
                if no_sentence or short_named_items >= 4:
                    bonus -= 1.1

        if is_list_q and (re.search(r"(?:^|\n)\s*(?:[-•*]|\d+[.)])\s+", txt) or txt.count(",") >= 2):
            bonus += 0.2

        if retrieval_intent == "chapter":
            chapter_match = re.search(r"\b(?:chapter|unit)\s+(\d+)\b", q)
            if chapter_match:
                target_num = chapter_match.group(1)
                if re.search(rf"\b(?:chapter|unit)\s+{target_num}\b", txt):
                    bonus += 0.45
                if re.search(rf"\b{target_num}\.\d+\b", txt):
                    bonus += 0.26
                if any(marker in txt for marker in ("table of contents", "contents")):
                    bonus -= 0.18
            if chunk_role in {"chapter_heading", "section_heading", "chapter_intro", "summary", "introduction"}:
                bonus += 0.24
        elif retrieval_intent == "structure":
            if re.search(r"\b(?:chapter|unit)\s+\d+\b", txt):
                bonus += 0.22
            if re.search(r"\b\d+(?:\.\d+){1,3}\b", txt):
                bonus += 0.12
            if any(marker in txt for marker in ("table of contents", "contents", "key terms")):
                bonus += 0.16
            if chunk_role in {"toc", "chapter_heading", "section_heading"}:
                bonus += 0.22
        else:
            if any(marker in txt[:400] for marker in ("table of contents", "contents", "index")):
                bonus -= 0.35
            if chunk_role == "toc":
                bonus -= 0.32

        if is_overview_q:
            if any(marker in txt[:500] for marker in ("introduction", "summary", "key terms", "key concepts")):
                bonus += 0.10
            page_val = (doc.get("metadata") or {}).get("page")
            try:
                if page_val is not None and 0 < int(page_val) <= 8:
                    bonus += 0.08
            except Exception:
                pass

        if named_entities:
            entity_hits = sum(1 for ent in named_entities if re.search(rf"\b{re.escape(ent)}\b", txt))
            if entity_hits > 0:
                bonus += 0.35 * entity_hits # Increased bonus for matching named entities found in both query and context
            
            # 2. DIRECT BOOK ASSOCIATION BOOST:
            # We want to favor "Peter Drucker wrote X" over a list of books.
            is_singular_book_q = bool(re.search(r"\b(name|what|which)\b.*?\bbook\b", q)) or \
                                 bool(re.search(r"\bbook\b.*?\b(by|of|written)\b", q))
            
            if is_singular_book_q:
                # Direct link: "Drucker ... his book" or "Drucker ... published"
                for ent in named_entities:
                    if re.search(rf"\b{re.escape(ent)}\b.*?\bbook\b", txt, re.DOTALL):
                        bonus += 0.55
                    if re.search(rf"\b{re.escape(ent)}\b.*?\bpublished\b", txt, re.DOTALL):
                        bonus += 0.35
                if re.search(r"\bhis book\b.*?\bpublished\b", txt, re.DOTALL):
                    bonus += 0.4
                
                # Penalty for BIBLIOGRAPHY/LIST noise (Title + Number pattern like "Management 42")
                if re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\s+\d{1,3}\b", txt):
                    bonus -= 0.7
                
                # Penalty for "Index/List" density (many TitleCase words, few periods)
                title_words = re.findall(r"\b[A-Z][a-z]{3,}\b", txt)
                if len(title_words) > 10 and txt.count('.') < 2:
                    bonus -= 0.6
                
                # General bibliography pattern penalty
                if any(re.search(pat, txt, flags=re.IGNORECASE) for pat in hard_noise_patterns):
                    bonus -= 0.85

        if any(marker in txt[:350] for marker in ("table of contents", "contents", "index", "how this book is organized")):
            if is_structure_q or is_overview_q:
                bonus += 0.16
            else:
                bonus -= 0.3

        if _is_hard_noise(doc):
            bonus -= 1.0

        words = txt.split()
        if len(words) > 60:
            bonus += min(0.06, (len(words) - 60) / 1500.0)

        base = float(
            doc.get("similarity", doc.get("score", (md or {}).get("_score", 0.0))) or 0.0
        )
        return base + bonus

    explain_scored_docs = []
    for i, doc in enumerate(retrieved_docs):
        txt_raw = _doc_text(doc)
        txt = txt_raw.lower()
        md = (doc or {}).get("metadata") or {}
        semantic_score = float(doc.get("similarity", doc.get("score", (md or {}).get("_score", 0.0))) or 0.0)
        token_hits = sum(1 for tok in query_tokens_for_explain if re.search(rf"\b{re.escape(tok)}\b", txt))
        keyword_overlap = (token_hits / max(1, len(query_tokens_for_explain))) * 1.8

        explanation_flag = _is_explanatory_chunk(txt_raw, q_raw)
        explanation_bonus = 0.0
        if not is_fact_q:
            if explanation_flag:
                explanation_bonus += 1.6
            if explain_verbs_re.search(txt):
                explanation_bonus += 0.7
        heading_l = f"{(md.get('section') or '')} {(md.get('title') or '')} {(md.get('chapter') or '')}".lower()
        if query_entity and query_entity in heading_l:
            explanation_bonus += 0.5

        penalties = 0.0
        table_like = _looks_table_or_heading_like_chunk(txt_raw[:1800])
        classification_heavy = bool(table_or_classification_re.search(txt[:1400]))
        if table_like:
            penalties += 1.4
        if classification_heavy:
            penalties += 1.2
        mixed_topic_hits = _generic_mixed_topic_fragment_count(txt_raw[:1800])
        if mixed_topic_hits >= 3 and (not query_entity or query_entity not in txt):
            penalties += 0.9 + (0.2 * min(4, mixed_topic_hits))

        legacy_score = _boost(doc)
        explain_score = semantic_score + keyword_overlap + explanation_bonus - penalties
        final_score = legacy_score + explain_score

        if is_fact_q:
            final_score = legacy_score + (0.35 * explain_score)

        if any(x in txt for x in ["classification", "table", "figure"]) or _looks_table_or_heading_like_chunk(txt_raw[:1600]):
            final_score -= 0.20
        if (not is_fact_q) and any(x in txt for x in ["is defined as", "refers to", "is a", "means"]):
            final_score += 2.0

        S.logger.info("[EXPLAIN SCORE] idx=%d score=%.3f preview=%s", i, float(final_score), txt_raw[:120])

        S.logger.info(
            "[EXPLAIN SCORE] chunk_index=%s score=%.3f explanation=%s",
            md.get("chunk_index"),
            float(final_score),
            bool(explanation_flag),
        )

        explain_scored_docs.append((final_score, explain_score, explanation_flag, doc))

    explain_scored_docs.sort(key=lambda x: (x[0], x[1]), reverse=True)
    scored_docs = [x[3] for x in explain_scored_docs]

    if scored_docs:
        definition_like_query = (not is_fact_q) and bool(is_definition_q or ("what is" in q) or ("define" in q) or ("explain" in q))
        if definition_like_query:
            def _doc0_eligible_explain(item) -> bool:
                _final_score, _explain_score, _explain_flag, _doc = item
                _txt = _doc_text(_doc)
                _low = _txt.lower()
                _table = _looks_table_or_heading_like_chunk(_txt[:1800])
                _classif = bool(table_or_classification_re.search(_low[:1400]))
                _short = len(_txt.strip()) < 160
                _unrelated = _generic_mixed_topic_fragment_count(_txt[:1800]) >= 3 and (not query_entity or query_entity not in _low)
                _lines = [ln.strip() for ln in _txt.splitlines() if ln.strip()]
                _bullet_lines = [ln for ln in _lines if list_like_re.match(ln)]
                _bullet_ratio = (len(_bullet_lines) / max(1, len(_lines))) if _lines else 0.0
                _listish = _bullet_ratio >= 0.35
                return bool((not _table) and (not _classif) and (not _short) and (not _unrelated) and (not _listish) and (_explain_flag or bool(explain_verbs_re.search(_low))))

            best_idx = -1
            for idx, item in enumerate(explain_scored_docs):
                if _doc0_eligible_explain(item):
                    best_idx = idx
                    break

            if best_idx >= 0:
                chosen_doc = explain_scored_docs[best_idx][3]
                scored_docs = [chosen_doc] + [d for d in scored_docs if d is not chosen_doc]
                S.logger.info("[EXPLAIN SELECT] doc0 chosen idx=%d", best_idx)
            elif explain_scored_docs:
                fallback_pool = [item for item in explain_scored_docs if not _looks_table_or_heading_like_chunk(_doc_text(item[3])[:1800])]
                if not fallback_pool:
                    fallback_pool = explain_scored_docs
                fallback = max(fallback_pool, key=lambda x: (x[1], x[0]))
                fallback_doc = fallback[3]
                scored_docs = [fallback_doc] + [d for d in scored_docs if d is not fallback_doc]
                S.logger.info("[EXPLAIN SELECT] doc0 chosen idx=%d", explain_scored_docs.index(fallback))

    if is_fact_q and scored_docs:
        scored_docs = _select_fact_anchor_docs(
            q_raw,
            scored_docs,
            top_k=min(5, len(scored_docs)),
            scan_limit=min(20, len(scored_docs)),
        )

    # CRITICAL: Hard Filtering for Singular Book Queries (Final precision layer)
    # Detect intent: "What book of Peter Drucker..."
    is_singular_book_q = (bool(re.search(r"\b(name|what|which)\b.*?\bbook\b", q)) or 
                          bool(re.search(r"\bbook\b.*?\b(by|of|written)\b", q))) and named_entities

    if is_singular_book_q:
        hard_filtered = []
        for doc in scored_docs:
            txt = _doc_text(doc).lower()
            # 1. Must contain the queried entity name
            has_ent = any(re.search(rf"\b{re.escape(ent)}\b", txt) for ent in named_entities)
            # 2. Must contain a direct book association keyword or pattern
            has_assoc = any(marker in txt for marker in ["book", "published", "wrote", "author", "authored"])
            # 3. Must not look like a bibliography list (Title + Number pattern e.g. "Management 42")
            is_list_noise = bool(re.search(r"\b[a-z]{3,}\s+\d{1,3}\b", txt)) and txt.count('.') < 3
            
            if has_ent and has_assoc and not is_list_noise:
                hard_filtered.append(doc)
        
        if hard_filtered:
            S.logger.info("RAG: Singular book query hard-filtered %d -> %d docs", len(scored_docs), len(hard_filtered))
            # Pass only the narrowed set (top 2-3 are usually enough for a specific book answer)
            return hard_filtered[:3]
        else:
            S.logger.info("RAG: Singular book query hard-filter yielded 0 results, keeping all.")

    # P9: surface top-of-rerank context-quality decisions so we can trace
    # why a particular chunk was chosen for a query without enabling debug
    # logging across the whole pipeline.
    try:
        _top_preview = []
        for _d in (scored_docs or [])[:3]:
            _src = str(((_d or {}).get("metadata") or {}).get("source") or (_d or {}).get("source") or "")
            _scr = float((_d or {}).get("score", 0.0) or 0.0)
            _txt = _doc_text(_d)
            _top_preview.append({
                "source": _src[-80:],
                "score": round(_scr, 4),
                "preview": re.sub(r"\s+", " ", _txt[:120]).strip(),
            })
        S.logger.info("[CONTEXT QUALITY] family=%s intent=%s selected_chunks=%s",
                    family_v2, retrieval_intent, _top_preview)
    except Exception:
        pass

    return scored_docs

def _expand_query(query: str) -> List[str]:
    q_raw = re.sub(r"\s+", " ", str(query or "")).strip()
    if not q_raw:
        return []

    q = q_raw.strip(" ?.!")
    q_low = q.lower()

    variants: List[str] = [q]

    def _add(v: str):
        v2 = re.sub(r"\s+", " ", str(v or "")).strip(" ?.!")
        if not v2:
            return
        if len(v2) < 2 or len(v2) > 140:
            return
        variants.append(v2)

    base_term = re.sub(
        r"^(?:what\s+is|what\s+are|define|who\s+is|who\s+was|who\s+introduced|who\s+is\s+considered\s+the\s+father\s+of)\s+",
        "",
        q,
        flags=re.IGNORECASE,
    ).strip(" ?.!")

    is_definition = bool(re.match(r"^(?:what\s+is|define|who\s+is|who\s+was|who\s+introduced)", q_low))
    is_person = bool(re.match(r"^(?:who\s+is|who\s+was|who\s+introduced)", q_low))
    is_compare = "difference between" in q_low or "compare" in q_low
    chapter_m = re.search(r"\b(?:chapter|unit)\s+\d+\b", q_low)

    if base_term:
        _add(base_term)

    if is_definition and base_term:
        _add(f"{base_term} definition")
        _add(f"{base_term} meaning")

    if is_person and base_term:
        _add(base_term)
        _add(f"{base_term} biography")
        _add(f"{base_term} contribution")

    if is_definition and not is_person and base_term:
        _add(base_term)
        _add(f"{base_term} model")
        _add(f"{base_term} theory")

    if chapter_m:
        chap = chapter_m.group(0)
        _add(chap)
        _add(f"{chap} topics")
        _add(f"{chap} sections")

    if is_compare:
        m = re.search(r"difference\s+between\s+(.+?)\s+and\s+(.+?)(?:\?|$)", q_low)
        if m:
            left = m.group(1).strip(" ?.!")
            right = m.group(2).strip(" ?.!")
            _add(left)
            _add(right)
            _add(f"difference between {left} and {right}")

    if _is_targeted_list_question(q_low):
        if base_term:
            _add(f"{base_term} list")
            _add(f"{base_term} items")
            _add(f"{base_term} points")
            _add(base_term)

    # de-duplicate while preserving order
    ordered: List[str] = []
    seen = set()
    for v in variants:
        key = v.lower()
        if key in seen:
            continue
        seen.add(key)
        ordered.append(v)
    return ordered[:10]

def _search_with_query_expansion(query_text: str, top_k: int, distance_threshold: float, return_dicts: bool = True, enable_rerank: bool = True) -> list[dict]:
    expanded = _expand_query(query_text)
    if not expanded:
        return []

    requested_top_k = int(top_k or 1)
    per_query_k = max(3, requested_top_k)
    if _classify_query_family_v2(query_text) == "fact_entity":
        capped_k = min(per_query_k, FACT_MAX_TOP_K)
        S.logger.info("[FACT TOPK] stage=_search_with_query_expansion requested=%s used=%s capped=%s", per_query_k, capped_k, capped_k != per_query_k)
        per_query_k = capped_k
    enable_rerank = True
    S.logger.info("[RERANK ACTIVE]")
    S.logger.info("[TOPK TRACE] requested=%s actual=%s function=_search_with_query_expansion", requested_top_k, per_query_k)
    all_results: List[dict] = []

    for q in expanded:
        try:
            found = S._active_rag().search(
                q,
                top_k=per_query_k,
                distance_threshold=distance_threshold,
                return_dicts=return_dicts,
                enable_rerank=enable_rerank,
            )
        except Exception:
            found = []
        if found:
            all_results.extend(found)
        S.logger.info("[DOC COUNT TRACE] stage=_search_with_query_expansion.live_rag.search count=%s", len(found or []))

    if not all_results:
        S.logger.info("[DOC COUNT TRACE] stage=_search_with_query_expansion.aggregate count=0")
        return []

    # Deduplicate by content fingerprint + metadata id/page hints.
    dedup: List[dict] = []
    seen = set()
    for d in all_results:
        md = (d or {}).get("metadata") or {}
        txt = str((d or {}).get("text") or (d or {}).get("page_content") or "")
        fp = re.sub(r"\s+", " ", txt).strip().lower()[:300]
        key = (
            str(md.get("id") or md.get("doc_id") or ""),
            str(md.get("page") or ""),
            fp,
        )
        if key in seen:
            continue
        seen.add(key)
        dedup.append(d)

    q_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower()) if t not in {"what", "who", "define", "the", "and", "for", "with", "from", "about", "between", "difference", "chapter", "unit"}]
    entity_phrase = re.sub(
        r"^(?:what\s+is|what\s+are|define|who\s+is|who\s+was|who\s+introduced|who\s+is\s+considered\s+the\s+father\s+of)\s+",
        "",
        (query_text or "").strip(" ?.!"),
        flags=re.IGNORECASE,
    ).lower()

    def _base(d: dict) -> float:
        for k in ("final_score", "similarity", "score"):
            try:
                if k in d:
                    return float(d.get(k) or 0.0)
            except Exception:
                pass
        return 0.0

    def _rank_score(d: dict) -> float:
        txt = str((d or {}).get("text") or (d or {}).get("page_content") or "")
        low = txt.lower()
        score = _base(d)

        if entity_phrase and len(entity_phrase) >= 3 and entity_phrase in low:
            score += 0.9

        token_hits = sum(1 for t in q_tokens if re.search(rf"\b{re.escape(t)}\b", low))
        score += 0.12 * token_hits

        if any(sig in f" {low} " for sig in (" is ", " was ", " refers to ", " defined as ", " known as ", " born ", " introduced ")):
            score += 0.35

        return score

    ranked = sorted(dedup, key=_rank_score, reverse=True)
    out = ranked[:requested_top_k]
    S.logger.info("[DOC COUNT TRACE] stage=_search_with_query_expansion.aggregate count=%s", len(all_results))
    S.logger.info("[DOC COUNT TRACE] stage=_search_with_query_expansion.dedup count=%s", len(dedup))
    S.logger.info("[DOC COUNT TRACE] stage=_search_with_query_expansion.return count=%s", len(out))
    return out

def _search_fast_minimal(query_text: str, top_k: int) -> list[dict]:
    _t_sfm0 = time.perf_counter()
    requested_top_k = int(top_k or 1)
    actual_top_k = max(1, requested_top_k)
    if _classify_query_family_v2(query_text) == "fact_entity":
        capped_k = min(actual_top_k, FACT_MAX_TOP_K)
        S.logger.info("[FACT TOPK] stage=_search_fast_minimal requested=%s used=%s capped=%s", requested_top_k, capped_k, capped_k != actual_top_k)
        actual_top_k = capped_k
    S.logger.info("[TOPK TRACE] requested=%s actual=%s function=_search_fast_minimal", requested_top_k, actual_top_k)
    try:
        _rag = S._active_rag()
        out = _rag.search(
            query_text,
            top_k=actual_top_k,
            distance_threshold=_distance_threshold_for_query(query_text),
            return_dicts=True,
            enable_rerank=True,
        ) or []
        # #region agent log
        try:
            _col = getattr(getattr(_rag, "vs", None), "collection", None)
            S._dbg7d3bbb("assistify_rag_server.py:_search_fast_minimal", "retrieval done", {
                "tenant_id": current_tenant_id(),
                "collection": getattr(_col, "name", None),
                "collection_count": (_col.count() if _col is not None else None),
                "returned": len(out),
                "distance_threshold": _distance_threshold_for_query(query_text),
                "query": str(query_text or "")[:120],
            }, "H-A")
        except Exception as _e:
            S._dbg7d3bbb("assistify_rag_server.py:_search_fast_minimal", "retrieval log error",
                       {"err": str(_e), "returned": len(out), "query": str(query_text or "")[:120]}, "H-A")
        # #endregion
        S.logger.info("[RERANK ACTIVE]")
        S.logger.info("[DOC COUNT TRACE] stage=_search_fast_minimal.return count=%s", len(out))
        _sfm_ms = (time.perf_counter() - _t_sfm0) * 1000
        S.logger.info("[RETRIEVAL TIMING] _search_fast_minimal total=%.0f ms top_k=%d docs_returned=%d", _sfm_ms, actual_top_k, len(out))
        return out
    except Exception:
        _sfm_ms = (time.perf_counter() - _t_sfm0) * 1000
        S.logger.info("[DOC COUNT TRACE] stage=_search_fast_minimal.return count=0")
        S.logger.info("[RETRIEVAL TIMING] _search_fast_minimal total=%.0f ms top_k=%d docs_returned=0 (exception)", _sfm_ms, actual_top_k)
        return []

async def _search_fast_minimal_async(query_text: str, top_k: int) -> list[dict]:
    """Offload blocking Chroma/embed/rerank work from the asyncio event loop."""
    return await asyncio.to_thread(_search_fast_minimal, query_text, top_k)

async def _search_fast_definition_minimal_async(query_text: str) -> list[dict]:
    return await asyncio.to_thread(_search_fast_definition_minimal, query_text)

async def _active_rag_search_async(**kwargs) -> list:
    def _run() -> list:
        return S._active_rag().search(**kwargs) or []

    return await asyncio.to_thread(_run)

def _search_fast_definition_minimal(query_text: str) -> list[dict]:
    _t_sfdm0 = time.perf_counter()
    has_entity, entity = _extract_entity_from_definition_query(query_text)
    q_low = (query_text or "").strip().lower()
    is_concept_query = q_low.startswith("what is") or q_low.startswith("define")

    probes: List[str] = []
    concept_text = (entity or "").strip()
    is_person_query = (
        q_low.startswith("who is")
        or q_low.startswith("who was")
        or q_low.startswith("who introduced")
        or bool(re.match(r"^who\s+is\s+considered\s+the\s+father\s+of\b", q_low))
    )
    definition_top_k = 8 if (is_concept_query or is_person_query) else 6
    S.logger.info("[TOPK TRACE] requested=%s actual=%s function=_search_fast_definition_minimal", definition_top_k, definition_top_k)
    if is_concept_query and concept_text:
        probes.extend([
            (query_text or "").strip(),
            f"definition of {concept_text}",
        ])
    else:
        if has_entity and concept_text:
            probes.append(concept_text)
        probes.append((query_text or "").strip())
        if is_person_query and concept_text:
            probes.extend([
                f"{concept_text} founder",
                f"{concept_text} known as",
                f"{concept_text} born",
            ])

    best: list[dict] = []
    entity_l = (entity or "").strip().lower()
    entity_tokens = [t for t in re.findall(r"[a-z0-9]{2,}", entity_l) if t not in {"the", "a", "an", "of", "and", "in", "to"}]
    reject_marker_re = re.compile(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", re.IGNORECASE)
    intro_heading_re = re.compile(r"(?im)^\s*(?:introduction|overview|summary|contents?|table of contents|chapter\s+\d+|unit\s+\d+|learning objectives?|key terms?)\s*[:\-–—]?\s*$")
    heading_like_intro_re = re.compile(r"^\s*[A-Z][A-Za-z0-9\s\-]{3,90}\s*:\s*(?:[-•*]|\d+[.)])\s+", re.IGNORECASE)
    definition_verb_re = re.compile(r"\b(?:is|refers\s+to|defined\s+as|means)\b", re.IGNORECASE)
    attribution_verb_re = re.compile(r"\b(?:is|was|known as|introduced)\b", re.IGNORECASE)
    person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b")
    person_identity_re = None
    if is_person_query and len(entity_tokens) >= 2:
        parts = [re.escape(t) for t in entity_tokens]
        if len(parts) == 2:
            person_identity_re = re.compile(
                rf"\b{parts[0]}(?:\s+[a-z]{{2,}}){{0,3}}\s+{parts[1]}\b",
                flags=re.IGNORECASE,
            )
        else:
            middle = ""
            for p in parts[1:-1]:
                middle += rf"(?:\s+[a-z]{{2,}}){{0,2}}\s+{p}"
            person_identity_re = re.compile(
                rf"\b{parts[0]}{middle}(?:\s+[a-z]{{2,}}){{0,3}}\s+{parts[-1]}\b",
                flags=re.IGNORECASE,
            )

    def _score_definition_doc(d: dict) -> float:
        txt_raw = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        txt = txt_raw.lower()
        score = 0.0

        head_window = txt_raw[:1200]
        if reject_marker_re.search(head_window):
            return -1_000_000.0
        head_lines = [ln.strip() for ln in head_window.splitlines() if ln.strip()][:8]
        if head_lines:
            if intro_heading_re.search(head_lines[0]) and not re.search(r"[.!?]", head_window[:260]):
                return -1_000_000.0
            if heading_like_intro_re.search(head_lines[0]):
                return -1_000_000.0

        if entity_l and re.search(rf"\b{re.escape(entity_l)}\b", txt):
            score += 3.0

        token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", txt))
        token_overlap_ratio = (token_hits / max(1, len(entity_tokens))) if entity_tokens else 0.0
        score += 2.4 * token_overlap_ratio
        if len(entity_tokens) >= 2 and token_overlap_ratio < 0.34:
            score -= 1.8

        sents = [s.strip().lower() for s in re.split(r"(?<=[.!?])\s+|\n+", txt_raw) if s.strip()][:12]
        has_definitional = any(
            definition_verb_re.search(s)
            and len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) >= 7
            for s in sents
        )
        if has_definitional:
            score += 2.0

        table_like_head = bool(re.search(r"\b(table\s*\d+|table\s+of\s+contents|contents?|figure\s*\d+|fig\.?\s*\d+|caption)\b", txt[:1400]))
        noisy_symbols = len(re.findall(r"[�¦€¢§¤]", head_window))
        alpha_count = len(re.findall(r"[A-Za-z]", head_window))
        if (len(head_window) >= 280 and alpha_count <= 60) or noisy_symbols >= 8:
            return -1_000_000.0

        local_support = False
        strong_local_support = False
        best_local_support = 0.0
        for s_raw in re.split(r"(?<=[.!?])\s+|\n+", txt_raw):
            s = (s_raw or "").strip()
            if not s:
                continue
            sl = s.lower()
            wc = len(re.findall(r"[A-Za-z][A-Za-z\-']*", s))
            if wc < 6:
                continue
            sent_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", sl))
            sent_ratio = (sent_hits / max(1, len(entity_tokens))) if entity_tokens else 0.0
            has_entity_phrase = bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", sl))
            has_def_verb = bool(definition_verb_re.search(sl))
            if has_def_verb and sent_ratio >= 0.5:
                local_support = True
            if has_def_verb and has_entity_phrase:
                strong_local_support = True
            local_score = (1.6 * sent_ratio) + (1.2 if has_def_verb else 0.0) + (1.4 if (has_def_verb and has_entity_phrase) else 0.0)
            if local_score > best_local_support:
                best_local_support = local_score

        score += min(4.2, best_local_support)
        if not local_support:
            score -= 2.8

        if is_concept_query and table_like_head:
            if strong_local_support:
                score -= 0.8
            else:
                score -= 3.2

        if is_concept_query and entity_l:
            concept_def_hit = False
            concept_exact_def_hit = False
            for s_raw in re.split(r"(?<=[.!?])\s+|\n+", txt_raw):
                s = (s_raw or "").strip()
                if not s:
                    continue
                s_norm = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", s.lower())).strip()
                if entity_l in s_norm and definition_verb_re.search(s):
                    concept_def_hit = True
                    if definition_verb_re.search(s):
                        concept_exact_def_hit = True
                    break
            if concept_exact_def_hit:
                score += 3.0
            elif concept_def_hit:
                score += 1.0
            else:
                score -= 2.8

        if is_person_query:
            ent_need = max(1, min(2, len(entity_tokens))) if entity_tokens else 1
            attribution_ok = False
            for s_raw in re.split(r"(?<=[.!?])\s+|\n+", txt_raw):
                sentence = (s_raw or "").strip()
                if not sentence:
                    continue
                sl = sentence.lower()
                if not attribution_verb_re.search(sl):
                    continue
                entity_grounded = False
                if entity_l:
                    s_norm = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", sl)).strip()
                    entity_grounded = entity_l in s_norm
                if not entity_grounded and entity_tokens:
                    token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", sl))
                    entity_grounded = token_hits >= ent_need
                if entity_grounded and (person_name_re.search(sentence) is not None):
                    attribution_ok = True
                    break
            if attribution_ok:
                score += 1.6
            else:
                score -= 2.3
            if person_identity_re and person_identity_re.search(txt):
                score += 3.2

        long_prose = sum(1 for s in sents if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) >= 8)
        score += min(1.2, 0.2 * long_prose)

        if re.search(r"\b(table\s*\d+|contributors?|classification)\b", txt[:1200]):
            score -= 2.4
        if is_person_query and table_like_head and person_identity_re and person_identity_re.search(txt):
            score += 1.8

        lines = [ln.strip() for ln in txt_raw.splitlines() if ln.strip()][:40]
        bullet_lines = sum(1 for ln in lines if re.match(r"^(?:[-•*]|\d+[.)])\s+", ln))
        if lines and (bullet_lines / max(1, len(lines))) >= 0.25:
            score -= 1.0

        return score

    def _pick_best_definition_docs(cands: list[dict]) -> list[dict]:
        if not cands:
            return []
        scored = [(_score_definition_doc(d), d) for d in cands[:max(4, definition_top_k)]]
        ranked = [d for s, d in sorted(scored, key=lambda x: x[0], reverse=True) if s > -100000.0]
        return ranked[:definition_top_k]

    collected: List[dict] = []
    seen_ids: set[str] = set()
    _second_probe_used = False
    _probes_run = 0

    for _probe_idx, q in enumerate(probes[:3]):
        _t_probe0 = time.perf_counter()
        docs = _search_fast_minimal(q, top_k=definition_top_k)
        _probe_ms = (time.perf_counter() - _t_probe0) * 1000
        _probes_run += 1
        if _probe_idx >= 1:
            _second_probe_used = True
        S.logger.info(
            "[RETRIEVAL TIMING] definition_probe #%d query=%r top_k=%d raw_docs=%d time=%.0f ms",
            _probe_idx + 1, q[:80], definition_top_k, len(docs), _probe_ms,
        )
        S.logger.info("[DOC COUNT TRACE] stage=_search_fast_definition_minimal.probe_raw count=%s", len(docs))
        if not docs:
            continue
        ranked_docs = _pick_best_definition_docs(docs)
        S.logger.info("[DOC COUNT TRACE] stage=_search_fast_definition_minimal.probe_ranked count=%s", len(ranked_docs))
        if not ranked_docs:
            continue
        for d in ranked_docs[:max(5, definition_top_k)]:
            did = str((d or {}).get("id") or "")
            key = did or str(id(d))
            if key in seen_ids:
                continue
            seen_ids.add(key)
            collected.append(d)

        # Early-stop: after probe #1, if we already have at least 2 strong
        # definition candidates, skip remaining probes. Strong = score from
        # _score_definition_doc >= 3.0 (entity match + definitional verb).
        if _probe_idx == 0 and len(probes) > 1 and not is_person_query:
            _strong = 0
            for _d in collected:
                try:
                    if _score_definition_doc(_d) >= 3.0:
                        _strong += 1
                        if _strong >= 2:
                            break
                except Exception:
                    continue
            if _strong >= 2:
                S.logger.info("[DEF PROBE EARLY STOP] reason=strong_definition_found docs=%d", _strong)
                break

    if not collected:
        S.logger.info("[DOC COUNT TRACE] stage=_search_fast_definition_minimal.collected count=0")
        _sfdm_ms = (time.perf_counter() - _t_sfdm0) * 1000
        S.logger.info("[RETRIEVAL TIMING] _search_fast_definition_minimal total=%.0f ms probes=%d collected=0 returned=0", _sfdm_ms, _probes_run)
        return best

    def _combined_rank(d: dict) -> float:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "").lower()
        score = _score_definition_doc(d)
        if entity_l and re.search(rf"\b{re.escape(entity_l)}\b", txt):
            score += 0.8
        token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", txt))
        score += min(0.8, 0.3 * token_hits)
        return score

    scored_final = [(_combined_rank(d), d) for d in collected]
    final_ranked = [d for s, d in sorted(scored_final, key=lambda x: x[0], reverse=True) if s > -100000.0]
    out = final_ranked[:definition_top_k]
    S.logger.info("[DOC COUNT TRACE] stage=_search_fast_definition_minimal.collected count=%s", len(collected))
    S.logger.info("[DOC COUNT TRACE] stage=_search_fast_definition_minimal.return count=%s", len(out))
    _sfdm_ms = (time.perf_counter() - _t_sfdm0) * 1000
    S.logger.info(
        "[RETRIEVAL TIMING] _search_fast_definition_minimal total=%.0f ms probes=%d collected=%d returned=%d second_probe_used=%s",
        _sfdm_ms, _probes_run, len(collected), len(out), _second_probe_used,
    )
    return out

def _build_definition_entity_rescue_queries(query_text: str, entity: str) -> list[str]:
    e = _normalize_definition_entity(re.sub(r"\s+", " ", str(entity or "")).strip())
    if not e:
        return []

    queries = [
        e,
        f"definition of {e}",
        f"{e} is",
        f"what is {e}",
        f"what is meant by {e}",
        f"explain {e}",
        f"{e} theory",
        f"{e} explained",
        f"{e} principles methods",
    ]

    if re.search(r"\bapproach\b", e, flags=re.IGNORECASE):
        queries.append(f"{e} explanation")

    out: list[str] = []
    seen: set[str] = set()
    for cand in queries:
        c = re.sub(r"\s+", " ", str(cand or "")).strip()
        if not c:
            continue
        key = c.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(c)
    return out

def _build_fact_rescue_queries(query_text: str, history: list[dict] | None = None) -> list[str]:
    q = re.sub(r"\s+", " ", str(query_text or "")).strip()
    q_low = q.lower()

    queries: list[str] = [q] if q else []
    fact_type = _detect_fact_query_type(q)
    subject_terms = _extract_relation_subject_terms(q, fact_type)
    subject_part = " ".join(subject_terms[:4]).strip()

    if _is_metric_fact_query(q):
        # Build the metric rescue query from the question's own concept tokens
        # plus its subject, so retrieval is steered toward the relevant figures
        # in *any* corpus rather than one document's known KPIs.
        metric_terms = " ".join(_evidence_concept_tokens(q)[:6]).strip()
        for extra in (metric_terms, subject_part):
            extra = (extra or "").strip()
            if extra and extra not in queries:
                queries.append(extra)

    has_pronoun = bool(re.search(r"\b(it|this|that|they|he|she)\b", q_low))
    if has_pronoun and history:
        last_user = ""
        for item in reversed(history):
            if str((item or {}).get("role") or "").lower() != "user":
                continue
            content = re.sub(r"\s+", " ", str((item or {}).get("content") or "")).strip()
            if not content:
                continue
            if content.lower() == q_low:
                continue
            last_user = content
            break
        if last_user:
            queries.append(last_user)
            queries.append(f"{q} {last_user}".strip())

    out: list[str] = []
    seen: set[str] = set()
    for cand in queries:
        c = re.sub(r"\s+", " ", str(cand or "")).strip()
        if not c:
            continue
        key = c.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(c)
    return out

def _normalize_rescue_doc_dict(query_text: str, doc: dict) -> dict:
    raw_page = str(
        (doc or {}).get("page_content")
        or (doc or {}).get("text")
        or (doc or {}).get("content")
        or (doc or {}).get("raw_text")
        or ""
    )
    cleaned = _clean_ocr_artifacts(raw_page)
    if not cleaned or not cleaned.strip():
        cleaned = raw_page
    normalized = _normalize_context_entities(query_text, cleaned)
    final = normalized or cleaned or ""

    metadata = dict((doc or {}).get("metadata") or {})
    score_val = 0.0
    for score_key in ("final_score", "score", "similarity"):
        if score_key in (doc or {}):
            try:
                score_val = float((doc or {}).get(score_key) or 0.0)
            except Exception:
                score_val = 0.0
            break
    metadata["_score"] = float(score_val)

    return {
        "page_content": final,
        "text": final,
        "content": final,
        "metadata": metadata,
        "score": float(score_val),
    }

def _merge_rescue_docs_and_rerank(query_text: str, base_doc_dicts: list[dict], rescue_docs: list[dict], top_k: int = 12) -> list[dict]:
    base = list(base_doc_dicts or [])
    extra = [_normalize_rescue_doc_dict(query_text, d) for d in (rescue_docs or []) if isinstance(d, dict)]

    merged: list[dict] = []
    seen_keys: set[str] = set()
    for d in (base + extra):
        md = dict((d or {}).get("metadata") or {})
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        chunk_idx = md.get("chunk_index")
        page_no = md.get("page")
        fp = re.sub(r"\s+", " ", txt).strip().lower()[:400]
        key = f"{chunk_idx}|{page_no}|{fp}"
        if key in seen_keys:
            continue
        seen_keys.add(key)
        merged.append(d)

    reranked = _rerank_docs_for_query_intent(query_text, merged)
    if top_k and top_k > 0:
        return reranked[: int(top_k)]
    return reranked

def _indirect_evidence_pool_is_weak(indirect_evidence_pool: list[tuple[float, bool, str]] | list[dict]) -> bool:
    if not indirect_evidence_pool:
        return True
    try:
        first_item = indirect_evidence_pool[0]
        if isinstance(first_item, dict):
            best_score = max(float((d.get("score", 0.0) or 0.0) if isinstance(d, dict) else 0.0) for d in indirect_evidence_pool)
        else:
            best_score = max(float(item[0]) for item in indirect_evidence_pool)  # type: ignore[index]
    except Exception:
        return True
    return best_score < 0.85

def _prepare_rag_doc_dicts_shared(retrieved_docs: list[dict], query_text: str) -> list[dict]:
    if not retrieved_docs:
        return []

    seen = set()
    out: list[dict] = []
    for doc in retrieved_docs:
        raw_page = (
            (doc or {}).get("page_content")
            or (doc or {}).get("text")
            or (doc or {}).get("content")
            or (doc or {}).get("raw_text")
            or (doc or {}).get("text_preview")
            or ""
        )
        cleaned = _clean_ocr_artifacts(raw_page)
        if not cleaned or not cleaned.strip():
            cleaned = raw_page or ""
        normalized = _normalize_context_entities(query_text, cleaned)
        final = normalized or cleaned or ""

        fp = re.sub(r"\s+", " ", str(final)).strip().lower()[:400]
        if fp in seen:
            continue
        seen.add(fp)

        meta = dict((doc or {}).get("metadata") or {})
        score_val = 0.0
        for score_key in ("final_score", "score", "similarity"):
            if score_key in (doc or {}):
                try:
                    score_val = float((doc or {}).get(score_key) or 0.0)
                except Exception:
                    score_val = 0.0
                break
        meta["_score"] = float(score_val)

        out.append({
            "page_content": str(final),
            "text": str(final),
            "content": str(final),
            "metadata": meta,
            "score": float(score_val),
        })

    if not out:
        for doc in retrieved_docs:
            raw_text = (
                (doc or {}).get("page_content")
                or (doc or {}).get("text")
                or (doc or {}).get("content")
                or (doc or {}).get("raw_text")
                or ""
            )
            meta = dict((doc or {}).get("metadata") or {})
            score_val = 0.0
            for score_key in ("final_score", "score", "similarity"):
                if score_key in (doc or {}):
                    try:
                        score_val = float((doc or {}).get(score_key) or 0.0)
                    except Exception:
                        score_val = 0.0
                    break
            meta["_score"] = float(score_val)
            out.append({
                "page_content": str(raw_text or "(no content)"),
                "text": str(raw_text or "(no content)"),
                "content": str(raw_text or "(no content)"),
                "metadata": meta,
                "score": float(score_val),
            })
    return out

def _log_selected_doc_markers(doc_dicts: list[dict]) -> None:
    ids: list[str] = []
    chunk_indexes: list[str] = []
    for d in (doc_dicts or []):
        md = dict((d or {}).get("metadata") or {})
        ids.append(str(md.get("id") or md.get("doc_id") or md.get("source") or "unknown"))
        chunk_indexes.append(str(md.get("chunk_index")))
    S.logger.info("[SELECTED DOC IDS] %s", ids)
    S.logger.info("[SELECTED CHUNK INDEXES] %s", chunk_indexes)

def _log_answer_mode_markers(query_text: str, doc_dicts: list[dict], answer_text: str, source_mode: str) -> None:
    family = _classify_query_family(query_text)
    family_v2 = _classify_query_family_v2(query_text)
    list_mode_active = (family_v2 == "list_entity") or (family == "list_structure")

    resolved_source_mode = source_mode
    if source_mode in {"extractor", "llm"}:
        if family_v2 in {"definition_entity", "definition_comparison"}:
            resolved_source_mode = "definition"
        elif family_v2 == "fact_entity":
            resolved_source_mode = "fact"
        elif family_v2 == "list_entity":
            resolved_source_mode = "list"
        elif family_v2 in {"sequence_lookup"}:
            resolved_source_mode = "toc"
        elif family_v2 == "lesson_lookup":
            resolved_source_mode = "lesson_lookup"
        elif str(answer_text or "").strip().lower() == str(RAG_NO_MATCH_RESPONSE).strip().lower():
            resolved_source_mode = "not_found_guard"
        else:
            resolved_source_mode = "prose"

    S.logger.info("[ANSWER SOURCE MODE] %s", resolved_source_mode)
    S.logger.info("[QUERY FAMILY] legacy=%s v2=%s", family, family_v2)
    S.logger.info("[LIST MODE ACTIVE] %s", bool(list_mode_active))

    top_text = ""
    if doc_dicts:
        top_text = str((doc_dicts[0] or {}).get("page_content") or (doc_dicts[0] or {}).get("text") or "")
    table_mode = bool(top_text and (_looks_table_or_heading_like_chunk(top_text[:1800]) or _is_classification_only_chunk(top_text)))
    prose_mode = bool(top_text and (not table_mode) and _has_paragraph_prose_shape(top_text))
    S.logger.info("[TABLE ANSWER MODE] %s", table_mode)
    S.logger.info("[PROSE ANSWER MODE] %s", prose_mode)
    S.logger.info("[POSTPROCESS FINAL ANSWER] %s", str(answer_text or "")[:280])

_BM25_DEF_CACHE: Dict[str, Any] = {
    "collection": "",
    "count": -1,
    "entries": [],
    "idf": {},
    "avgdl": 0.0,
}

def _bm25_tokenize_text(text: str) -> List[str]:
    stop = {
        "the", "a", "an", "of", "and", "in", "to", "for", "with", "on", "at", "by",
        "what", "who", "is", "was", "are", "were", "define", "this", "that",
    }
    return [
        t for t in re.findall(r"[a-z0-9]{2,}", (text or "").lower())
        if t not in stop
    ]

def _ensure_bm25_definition_cache() -> Dict[str, Any]:
    cache = _BM25_DEF_CACHE
    try:
        collection = getattr(getattr(S.live_rag, "vs", None), "collection", None)
        if collection is None:
            return cache

        collection_name = str(getattr(collection, "name", "") or "")
        try:
            chunk_count = int(collection.count())
        except Exception:
            chunk_count = -1

        if (
            cache.get("entries")
            and cache.get("collection") == collection_name
            and int(cache.get("count", -2)) == chunk_count
        ):
            return cache

        data = collection.get(include=["documents", "metadatas"]) or {}
        docs = data.get("documents") or []
        metas = data.get("metadatas") or []

        entries: List[Dict[str, Any]] = []
        doc_freq: Counter = Counter()
        total_len = 0

        for i, txt in enumerate(docs):
            text = str(txt or "")
            if not text.strip():
                continue
            tokens = _bm25_tokenize_text(text)
            if not tokens:
                continue
            tf = Counter(tokens)
            dl = len(tokens)
            total_len += dl
            md = metas[i] if i < len(metas) and isinstance(metas[i], dict) else {}
            entries.append({
                "text": text,
                "metadata": md,
                "tf": tf,
                "dl": dl,
            })
            for tok in tf.keys():
                doc_freq[tok] += 1

        n_docs = len(entries)
        avgdl = (total_len / n_docs) if n_docs else 0.0
        idf: Dict[str, float] = {}
        for tok, df in doc_freq.items():
            idf[tok] = float(__import__("math").log(1.0 + ((n_docs - df + 0.5) / (df + 0.5)))) if n_docs else 0.0

        cache.update({
            "collection": collection_name,
            "count": chunk_count,
            "entries": entries,
            "idf": idf,
            "avgdl": avgdl,
        })
    except Exception:
        pass
    return cache

def _search_bm25_definition_fallback(query_text: str, top_k: int = 2) -> tuple[list[dict], float]:
    started = time.perf_counter()
    try:
        q_tokens = _bm25_tokenize_text(query_text)
        if not q_tokens:
            return [], (time.perf_counter() - started) * 1000.0

        cache = _ensure_bm25_definition_cache()
        entries = cache.get("entries") or []
        idf = cache.get("idf") or {}
        avgdl = float(cache.get("avgdl") or 0.0)
        if not entries or avgdl <= 0.0:
            return [], (time.perf_counter() - started) * 1000.0

        k1 = 1.2
        b = 0.75
        q_unique = list(dict.fromkeys(q_tokens))

        scored: List[Tuple[float, Dict[str, Any]]] = []
        for entry in entries:
            tf: Counter = entry.get("tf") or Counter()
            dl = max(1, int(entry.get("dl") or 1))
            score = 0.0
            for tok in q_unique:
                f = float(tf.get(tok, 0))
                if f <= 0.0:
                    continue
                tok_idf = float(idf.get(tok, 0.0))
                denom = f + k1 * (1.0 - b + b * (dl / avgdl))
                score += tok_idf * ((f * (k1 + 1.0)) / max(1e-9, denom))
            if score > 0.0:
                scored.append((score, entry))

        scored.sort(key=lambda x: x[0], reverse=True)
        out: List[dict] = []
        for score, entry in scored[: max(1, min(2, int(top_k)) )]:
            out.append({
                "text": entry.get("text") or "",
                "page_content": entry.get("text") or "",
                "metadata": entry.get("metadata") or {},
                "bm25_score": float(score),
            })

        elapsed_ms = (time.perf_counter() - started) * 1000.0
        return out, elapsed_ms
    except Exception:
        return [], (time.perf_counter() - started) * 1000.0

def _extract_document_headings(retrieved_docs: list[dict]) -> List[Dict[str, Any]]:
    headings: List[Dict[str, Any]] = []
    if not retrieved_docs:
        return headings

    for idx, doc in enumerate(retrieved_docs):
        md = (doc or {}).get("metadata") or {}
        txt = str((doc or {}).get("text") or (doc or {}).get("page_content") or "")

        for key in ("unit", "chapter", "section", "title"):
            value = re.sub(r"\s+", " ", str(md.get(key) or "")).strip()
            if value and 3 <= len(value) <= 120:
                headings.append({"heading": value, "doc_idx": idx, "source": f"metadata:{key}"})

        line_count = 0
        for raw in txt.splitlines():
            if line_count >= 30:
                break
            line = re.sub(r"\s+", " ", raw).strip(" \t-•*:")
            if not line:
                continue
            line_count += 1
            if len(line) < 4 or len(line) > 110:
                continue
            if re.search(r"[.!?]$", line):
                continue
            if re.search(r"\b(?:chapter|unit|section)\s+\d+\b", line, flags=re.IGNORECASE):
                headings.append({"heading": line, "doc_idx": idx, "source": "text:chapter_like"})
                continue
            if re.search(r"^\d+(?:\.\d+){1,4}\s+[A-Za-z]", line):
                headings.append({"heading": line, "doc_idx": idx, "source": "text:numbered_heading"})
                continue
            words = line.split()
            title_case = sum(1 for w in words if re.match(r"^[A-Z][a-zA-Z\-]{2,}$", w))
            if len(words) <= 10 and title_case >= max(2, len(words) // 2):
                headings.append({"heading": line, "doc_idx": idx, "source": "text:title_like"})

    deduped: List[Dict[str, Any]] = []
    seen = set()
    for h in headings:
        norm = re.sub(r"\s+", " ", h["heading"]).strip().lower()
        if not norm or norm in seen:
            continue
        seen.add(norm)
        deduped.append(h)
    return deduped

def _match_query_to_headings(query_text: str, headings: List[Dict[str, Any]]) -> Dict[str, Any]:
    q = (query_text or "").strip().lower()
    if not q or not headings:
        return {"primary": [], "secondary": [], "compare_terms": []}

    stop = {
        "what", "which", "who", "when", "where", "why", "how", "the", "this", "that", "these", "those",
        "is", "are", "was", "were", "be", "to", "of", "in", "on", "for", "and", "or", "with", "from",
        "a", "an", "do", "does", "did", "can", "could", "should", "would", "about", "main", "only",
        "list", "explain", "define", "tell", "me", "document", "topics", "covered", "difference", "between",
        "chapter", "section", "unit", "discussed", "talk", "compare",
    }

    q_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in stop]

    chapter_phrase = ""
    chapter_m = re.search(r"\b(?:chapter|unit)\s+\d+\b", q)
    if chapter_m:
        chapter_phrase = chapter_m.group(0)

    compare_terms: List[str] = []
    cm = re.search(r"difference\s+between\s+(.+?)\s+and\s+(.+?)(?:\?|$)", q)
    if not cm:
        cm = re.search(r"compare\s+(.+?)\s+and\s+(.+?)(?:\?|$)", q)
    if cm:
        compare_terms = [cm.group(1).strip(), cm.group(2).strip()]

    def _score_heading(h: str, tokens: List[str], chapter_hint: str = "") -> float:
        low = h.lower()
        hits = sum(1 for t in tokens if re.search(rf"\b{re.escape(t)}\b", low))
        score = float(hits)
        if chapter_hint and chapter_hint in low:
            score += 3.0
        if any(k in low for k in ("table of contents", "contents", "chapter", "unit", "summary", "introduction")):
            score += 0.8
        return score

    ranked = []
    for h in headings:
        score = _score_heading(h["heading"], q_tokens, chapter_phrase)
        if score > 0:
            ranked.append((score, h))
    ranked.sort(key=lambda x: x[0], reverse=True)

    primary = [h for _, h in ranked[:6]]
    secondary: List[Dict[str, Any]] = []

    if compare_terms:
        for term in compare_terms:
            term_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", term.lower()) if t not in stop]
            term_ranked = []
            for h in headings:
                score = _score_heading(h["heading"], term_tokens)
                if score > 0:
                    term_ranked.append((score, h))
            term_ranked.sort(key=lambda x: x[0], reverse=True)
            secondary.extend([h for _, h in term_ranked[:3]])

    sec_dedup: List[Dict[str, Any]] = []
    seen = set()
    for h in secondary:
        norm = h["heading"].strip().lower()
        if norm in seen:
            continue
        seen.add(norm)
        sec_dedup.append(h)

    return {"primary": primary, "secondary": sec_dedup, "compare_terms": compare_terms}

def _extract_section_block(text: str, heading: str) -> str:
    if not text or not heading:
        return ""

    raw_text = str(text).replace("\r\n", "\n").replace("\r", "\n")
    normalized_heading = re.sub(r"\s+", " ", str(heading)).strip()
    if not normalized_heading:
        return ""

    # 1) Find heading position (prefer line-start heading match)
    start_idx = -1
    line_heading_pattern = re.compile(
        rf"(?im)^\s*{re.escape(normalized_heading)}\s*[:\-–—]?\s*$"
    )
    m = line_heading_pattern.search(raw_text)
    if m:
        start_idx = m.start()
    else:
        heading_compact = re.sub(r"\s+", " ", normalized_heading).lower()
        text_compact = re.sub(r"\s+", " ", raw_text).lower()
        p = text_compact.find(heading_compact)
        if p >= 0:
            # map compact position back to original conservatively
            probe = re.search(re.escape(normalized_heading), raw_text, flags=re.IGNORECASE)
            if probe:
                start_idx = probe.start()

    if start_idx < 0:
        return ""

    # 2) Slice from heading and stop at next heading / section marker / large break
    tail = raw_text[start_idx:]
    lines = tail.split("\n")
    if not lines:
        return ""

    kept: List[str] = []
    blank_streak = 0

    next_heading_re = re.compile(
        r"^\s*(?:chapter\s+\d+|unit\s+\d+|section\s+\d+|\d+(?:\.\d+){1,4}\s+.+|[A-Z]\.\s+.+|[IVXLC]+\.\s+.+)\s*$",
        flags=re.IGNORECASE,
    )
    caps_heading_re = re.compile(r"^\s*[A-Z][A-Za-z0-9 ,&'\-()]{3,90}\s*$")

    for idx, ln in enumerate(lines):
        s = ln.rstrip()
        stripped = s.strip()

        if stripped == "":
            blank_streak += 1
            if blank_streak >= 2 and len(kept) >= 3:
                break
            kept.append(s)
            continue

        blank_streak = 0

        # after we have some content, stop at next heading-like marker
        if idx > 0 and len(kept) >= 2:
            if next_heading_re.match(stripped):
                break
            if caps_heading_re.match(stripped) and not re.search(r"[.!?]$", stripped):
                break

        kept.append(s)

        # safety cap to prevent very large noisy blocks
        if sum(len(x) for x in kept) >= 2200:
            break

    block = "\n".join(kept).strip()
    if len(block) < 80:
        return ""
    return block

def _retrieve_with_section_bias(query_text: str, retrieved_docs: list[dict], top_k: int = 10) -> list[dict]:
    if not query_text or not retrieved_docs:
        return retrieved_docs

    family = _classify_query_family(query_text)
    if family == "out_of_scope_candidate":
        return retrieved_docs

    enriched_docs = list(retrieved_docs)
    heading_candidates = _extract_document_headings(enriched_docs)
    matched = _match_query_to_headings(query_text, heading_candidates)

    # Compare queries: retrieve both sides and merge into candidate pool before biasing.
    if family == "overview_chapter_compare" and matched.get("compare_terms"):
        for term in matched.get("compare_terms", []):
            try:
                extra = S._active_rag().search(
                    term,
                    top_k=3,
                    distance_threshold=max(_distance_threshold_for_query(query_text), 1.25),
                    return_dicts=True,
                    enable_rerank=True,
                )
                S.logger.info("[RERANK ACTIVE]")
            except Exception:
                extra = []
            if not extra:
                continue
            for d in extra:
                txt = str((d or {}).get("text") or (d or {}).get("page_content") or "")
                if not txt.strip():
                    continue
                dup = False
                fp = re.sub(r"\s+", " ", txt).strip().lower()[:280]
                for ex in enriched_docs:
                    ex_txt = str((ex or {}).get("text") or (ex or {}).get("page_content") or "")
                    ex_fp = re.sub(r"\s+", " ", ex_txt).strip().lower()[:280]
                    if ex_fp and ex_fp == fp:
                        dup = True
                        break
                if not dup:
                    enriched_docs.append(d)

        heading_candidates = _extract_document_headings(enriched_docs)
        matched = _match_query_to_headings(query_text, heading_candidates)

    primary_heads = [h["heading"].lower() for h in matched.get("primary", [])]
    secondary_heads = [h["heading"].lower() for h in matched.get("secondary", [])]

    ql = (query_text or "").lower()
    list_or_section_query = bool(
        family in {"list_structure", "overview_chapter_compare"}
        or _is_targeted_list_question(ql)
        or re.match(r"^\s*(?:what|which)\s+are\b", ql)
    )

    q_stop = {
        "what", "which", "are", "the", "and", "for", "with", "from", "list", "name", "give", "mention", "identify",
        "of", "in", "on", "at", "to", "a", "an", "is", "was", "were", "be", "being", "been",
    }
    query_focus_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", ql) if t not in q_stop][:12]

    def _has_query_token(haystack: str, token: str) -> bool:
        t = str(token or "").strip().lower()
        if not t:
            return False
        if re.search(rf"\b{re.escape(t)}\b", haystack):
            return True
        if len(t) >= 6:
            stem = t[:5]
            if re.search(rf"\b{re.escape(stem)}[a-z]*\b", haystack):
                return True
        return False

    def _heading_like(line: str) -> bool:
        s = str(line or "").strip()
        if not s or len(s) > 140:
            return False
        if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
            return False
        if s.endswith(":"):
            return True
        if re.match(r"^[A-Z][A-Za-z0-9\- ,()]{3,80}$", s):
            return True
        return False

    def _marker_density(lines_block: list[str]) -> float:
        if not lines_block:
            return 0.0
        marker_lines = 0
        for ln in lines_block:
            if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", ln):
                marker_lines += 1
            elif re.match(r"^\s*[a-zA-Z][.)]\s+", ln):
                marker_lines += 1
            elif len(re.findall(r"\b[a-zA-Z][.)]\s+", ln)) >= 2:
                marker_lines += 1
            elif (ln.count(",") >= 2 and len(ln) <= 240) or (";" in ln and len(ln) <= 260):
                marker_lines += 1
        return marker_lines / max(1, len([ln for ln in lines_block if ln.strip()]))

    def _topic_drift(lines_block: list[str]) -> float:
        token_sets: list[set[str]] = []
        for ln in lines_block:
            toks = {t for t in re.findall(r"[a-z0-9]{3,}", ln.lower()) if t not in q_stop}
            if toks:
                token_sets.append(toks)
        if len(token_sets) < 2:
            return 0.0
        drifts = 0
        for i in range(len(token_sets) - 1):
            inter = len(token_sets[i] & token_sets[i + 1])
            union = len(token_sets[i] | token_sets[i + 1]) or 1
            if (inter / union) < 0.08:
                drifts += 1
        return drifts / max(1, len(token_sets) - 1)

    def _best_local_window(raw_text: str, metadata: dict[str, Any] | None = None) -> tuple[float, str, str, dict[str, Any]]:
        lines_raw = [str(ln or "") for ln in str(raw_text or "").splitlines()]
        if not lines_raw:
            return (0.0, "", "", {"focus_hits": 0.0, "heading_hits": 0.0, "marker_density": 0.0, "compactness": 0.0, "drift": 1.0})

        course_code_re = re.compile(r"\b[A-Za-z]{2,8}\s*[-–—]?\s*\d{2,4}[A-Za-z]?\b", re.IGNORECASE)
        broad_title_re = re.compile(r"\b(?:introduction|intro\s*duction|fundamentals|principles|basics|overview)\s+to\b", re.IGNORECASE)
        doc_header_term_re = re.compile(r"\b(?:course|syllabus|textbook|edition|semester|module|manual)\b", re.IGNORECASE)

        def _is_document_title_heading(cand: str, idx: int) -> bool:
            c = re.sub(r"\s+", " ", str(cand or "")).strip()
            if not c:
                return True
            lower = c.lower()
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", c)
            title_case_words = sum(1 for w in words if re.match(r"^[A-Z][a-zA-Z\-']+$", w))
            title_ratio = (float(title_case_words) / float(max(1, len(words)))) if words else 0.0
            has_course_code = bool(course_code_re.search(c))
            has_local_marker = bool(
                c.endswith(":")
                or re.match(r"^\s*\d+(?:\.\d+)*\s+[A-Za-z]", c)
                or re.search(r"\b(?:section|part|topic|subsection)\s+\d+\b", lower)
            )
            if has_course_code and not has_local_marker:
                return True
            if re.search(r"[-–—]\s*[A-Za-z]{2,8}\s*\d{2,4}", c, flags=re.IGNORECASE) and not has_local_marker:
                return True
            if broad_title_re.search(c) and not has_local_marker:
                return True
            if doc_header_term_re.search(c) and title_ratio >= 0.5 and not has_local_marker:
                return True

            norm = re.sub(r"[^a-z0-9]+", " ", lower).strip()
            repeated_head = 0
            if norm:
                for probe in lines_raw[max(0, idx - 80): min(len(lines_raw), idx + 80)]:
                    p = re.sub(r"[^a-z0-9]+", " ", str(probe or "").lower()).strip()
                    if p == norm:
                        repeated_head += 1
            if repeated_head >= 2 and title_ratio >= 0.55 and not has_local_marker:
                return True
            return False

        heading_candidates: list[tuple[float, int, str]] = []
        raw_candidates: list[str] = []
        metadata_candidates: list[str] = []
        for key in ("title", "section", "chapter"):
            value = re.sub(r"\s+", " ", str((metadata or {}).get(key) or "").strip())
            if not value or value.lower() in {"document", "page"}:
                continue
            if _is_placeholder_heading_text(value):
                S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', value[:120])
                continue
            if value.lower() not in {v.lower() for v in metadata_candidates}:
                metadata_candidates.append(value)
        if metadata_candidates:
            raw_candidates.extend(metadata_candidates)
            anchor_heading = metadata_candidates[0]
            S.logger.info("[HEADING SOURCE DEBUG] raw_candidates=%s", raw_candidates[:8])
            S.logger.info('[HEADING SOURCE DEBUG] chosen_heading="%s"', anchor_heading[:120])
            S.logger.info("[HEADING SOURCE DEBUG] chosen_from=metadata")
            return (
                1.0,
                str(raw_text or "").strip(),
                anchor_heading,
                {"focus_hits": 0.0, "heading_hits": 1.0, "marker_density": 0.0, "compactness": 0.0, "drift": 0.0},
            )
        placeholder_heading_rejected = False
        for idx, raw_ln in enumerate(lines_raw[:140]):
            ln = re.sub(r"\s+", " ", raw_ln).strip()
            if not ln:
                continue
            for cand in _extract_heading_snippets_from_line(ln):
                if _is_placeholder_heading_text(cand):
                    placeholder_heading_rejected = True
                    S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', cand[:120])
                    continue
                if _is_document_title_heading(cand, idx):
                    S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_document_title=True', cand[:120])
                    continue
                raw_candidates.append(cand)
                low_ln = cand.lower()
                heading_overlap = float(sum(1 for tok in query_focus_tokens if _has_query_token(low_ln, tok)))
                style = 1.0 if cand.endswith(":") else 0.0
                if re.match(r"^[A-Z][A-Za-z0-9\- ,()]{3,90}$", cand):
                    style += 0.75
                heading_candidates.append(((1.45 * heading_overlap) + style, idx, cand))

        S.logger.info("[HEADING SOURCE DEBUG] raw_candidates=%s", raw_candidates[:8])
        if not heading_candidates:
            S.logger.info('[HEADING SOURCE DEBUG] chosen_heading=""')
            S.logger.info("[HEADING SOURCE DEBUG] chosen_from=none")
            S.logger.info("[HEADING SOURCE DEBUG] no_real_heading_found=True")
            return (0.0, "", "", {"focus_hits": 0.0, "heading_hits": 0.0, "marker_density": 0.0, "compactness": 0.0, "drift": 1.0})

        heading_candidates.sort(key=lambda x: x[0], reverse=True)
        _anchor_score, anchor_idx, anchor_heading = heading_candidates[0]
        S.logger.info('[HEADING SOURCE DEBUG] chosen_heading="%s"', anchor_heading[:120])
        S.logger.info("[HEADING SOURCE DEBUG] chosen_from=body_line")

        stop_reason = "max_local_window_length"
        start_idx = anchor_idx
        end_idx = anchor_idx
        anchor_token_set = {t for t in re.findall(r"[a-z0-9]{3,}", anchor_heading.lower()) if t not in {"the", "and", "for", "with", "from", "section", "chapter", "unit"}}
        blank_run = 0
        prose_drift_run = 0
        max_chars = 2400
        max_lines = 52
        acc_chars = 0

        for j in range(anchor_idx, min(len(lines_raw), anchor_idx + max_lines)):
            cur = str(lines_raw[j] or "")
            cur_norm = re.sub(r"\s+", " ", cur).strip()
            if not cur_norm:
                blank_run += 1
                if blank_run >= 2 and j > anchor_idx + 2:
                    stop_reason = "clear_section_break"
                    break
                continue

            blank_run = 0
            if j > anchor_idx:
                if _heading_like(cur_norm) and (not _is_placeholder_heading_text(cur_norm)):
                    stop_reason = "next_heading"
                    break

                cur_tokens = {t for t in re.findall(r"[a-z0-9]{3,}", cur_norm.lower()) if t not in {"the", "and", "for", "with", "from", "is", "are", "was", "were"}}
                if cur_tokens and anchor_token_set:
                    inter = len(cur_tokens & anchor_token_set)
                    union = len(cur_tokens | anchor_token_set) or 1
                    if (inter / union) < 0.04 and (not re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", cur_norm)):
                        prose_drift_run += 1
                    else:
                        prose_drift_run = 0
                if prose_drift_run >= 3:
                    stop_reason = "strong_prose_drift"
                    break

            end_idx = j
            acc_chars += len(cur_norm)
            if acc_chars >= max_chars:
                stop_reason = "max_local_window_length"
                break

        block_lines = [re.sub(r"\s+", " ", str(x or "")).strip() for x in lines_raw[start_idx: end_idx + 1] if re.sub(r"\s+", " ", str(x or "")).strip()]
        block_text = "\n".join(block_lines).strip()
        if not block_text:
            return (0.0, "", "", {"focus_hits": 0.0, "heading_hits": 0.0, "marker_density": 0.0, "compactness": 0.0, "drift": 1.0})

        low = block_text.lower()
        focus_hits = float(sum(1 for tok in query_focus_tokens if _has_query_token(low, tok)))
        anchor_low = anchor_heading.lower()
        heading_hits = float(sum(1 for tok in query_focus_tokens if _has_query_token(anchor_low, tok)))
        marker = float(_marker_density(block_lines))
        drift = float(_topic_drift(block_lines))
        wc = len(re.findall(r"[a-z0-9]+", low))
        compactness = max(0.0, 1.0 - (abs(wc - 120) / 220.0))
        score = (1.5 * focus_hits) + (1.25 * heading_hits) + (2.0 * marker) + (0.9 * compactness) + (1.0 * (1.0 - min(1.0, drift)))

        sig_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", anchor_low) if t not in {"the", "and", "for", "with", "from", "section", "chapter", "unit"}][:4]
        section_signature = " ".join(sig_tokens)

        S.logger.info('[LOCAL SECTION WINDOW] anchor_heading="%s"', anchor_heading[:120])
        S.logger.info('[LOCAL SECTION WINDOW] start=%s end=%s reason_stop="%s"', start_idx, end_idx, stop_reason)
        S.logger.info("[LOCAL SECTION WINDOW] used_single_window=True")

        return (
            score,
            block_text,
            anchor_heading,
            {
                "focus_hits": focus_hits,
                "heading_hits": heading_hits,
                "marker_density": marker,
                "compactness": compactness,
                "drift": drift,
                "used_single_window": 1.0,
                "window_start": float(start_idx),
                "window_end": float(end_idx),
                "reason_stop": stop_reason,
                "section_signature": section_signature,
                "placeholder_heading_rejected": 1.0 if placeholder_heading_rejected else 0.0,
            },
        )

    def _base_score(doc: dict) -> float:
        for key in ("final_score", "similarity", "score"):
            try:
                if key in doc:
                    return float(doc.get(key) or 0.0)
            except Exception:
                pass
        return 0.0

    scored = []
    for doc in enriched_docs:
        txt = str((doc or {}).get("text") or (doc or {}).get("page_content") or "")
        md = (doc or {}).get("metadata") or {}
        head = "\n".join(str(md.get(k) or "") for k in ("unit", "chapter", "section", "title"))
        hay = f"{head}\n{txt[:2200]}".lower()
        score = _base_score(doc)

        q_tokens = [tok for tok in re.findall(r"[a-z0-9]{3,}", ql) if tok not in {"what", "which", "are", "the", "and", "for", "with", "from"}]
        token_hits = sum(1 for tok in q_tokens if _has_query_token(hay, tok))
        if q_tokens and token_hits == 0:
            continue

        for h in primary_heads:
            if h and h in hay:
                score += 1.2
            else:
                h_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", h) if t not in {"the", "and", "of", "for"}]
                token_hits = sum(1 for t in h_tokens if _has_query_token(hay, t))
                if h_tokens and token_hits >= max(1, min(2, len(h_tokens))):
                    score += 0.7

        for h in secondary_heads:
            if h and h in hay:
                score += 0.8

        if family == "overview_chapter_compare" and any(k in hay for k in ("table of contents", "contents", "chapter", "unit", "section")):
            score += 0.35

        if family == "list_structure":
            if re.search(r"(?:^|\n)\s*(?:[-•*]|\d+[.)])\s+", txt) or (txt.count(",") >= 2 and len(txt[:400]) < 420):
                score += 0.25

        scored.append((score, doc))

    scored.sort(key=lambda x: x[0], reverse=True)
    reranked = [doc for _, doc in scored]
    if not reranked:
        reranked = list(enriched_docs)

    # Heading-aligned context extraction: isolate block under matched heading.
    matched_headings = [h["heading"] for h in (matched.get("primary", []) + matched.get("secondary", []))]

    def _best_heading_for_doc(doc: dict) -> str:
        txt = str((doc or {}).get("text") or (doc or {}).get("page_content") or "")
        md = (doc or {}).get("metadata") or {}
        hay = f"{txt}\n{md.get('unit','')}\n{md.get('chapter','')}\n{md.get('section','')}\n{md.get('title','')}".lower()
        best_h = ""
        best_score = 0
        for h in matched_headings:
            hl = h.lower().strip()
            if not hl:
                continue
            score = 0
            if hl in hay:
                score += 3
            h_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", hl) if t not in {"the", "and", "of", "for"}]
            hits = sum(1 for t in h_tokens if re.search(rf"\b{re.escape(t)}\b", hay))
            score += hits
            if score > best_score:
                best_score = score
                best_h = h
        return best_h if best_score >= 2 else ""

    focused_docs: list[dict] = []
    if not matched_headings:
        focused_docs = reranked[: max(len(retrieved_docs), top_k)]
    else:
        for doc in reranked:
            best_heading = _best_heading_for_doc(doc)
            if not best_heading:
                focused_docs.append(doc)
                continue

            source_text = str((doc or {}).get("text") or (doc or {}).get("page_content") or "")
            section_block = _extract_section_block(source_text, best_heading)
            if not section_block:
                focused_docs.append(doc)
                continue

            doc_new = dict(doc)
            md_new = dict((doc.get("metadata") or {}))
            md_new["_matched_heading"] = best_heading
            doc_new["metadata"] = md_new
            doc_new["page_content"] = section_block
            doc_new["text"] = section_block
            focused_docs.append(doc_new)

    if list_or_section_query and focused_docs:
        promoted_docs: list[dict] = []
        for doc in focused_docs:
            raw_text = str((doc or {}).get("text") or (doc or {}).get("page_content") or "")
            if not raw_text.strip():
                promoted_docs.append(doc)
                continue

            md = dict((doc or {}).get("metadata") or {})
            chunk_idx = str(md.get("chunk_index") or "?")
            source = str(md.get("source") or md.get("filename") or "")

            local_score, local_text, local_anchor, local_meta = _best_local_window(raw_text, md)
            S.logger.info(
                "[LOCAL WINDOW DEBUG] chunk=%s source=%s best_score=%.3f focus_hits=%.1f heading_hits=%.1f marker_density=%.3f compactness=%.3f drift=%.3f",
                chunk_idx,
                source[:120],
                float(local_score),
                float(local_meta.get("focus_hits", 0.0)),
                float(local_meta.get("heading_hits", 0.0)),
                float(local_meta.get("marker_density", 0.0)),
                float(local_meta.get("compactness", 0.0)),
                float(local_meta.get("drift", 1.0)),
            )

            if local_anchor:
                S.logger.info(
                    "[LOCAL HEADING DEBUG] chunk=%s heading=%s focus_overlap=%.1f heading_score=%.3f",
                    chunk_idx,
                    local_anchor[:120],
                    float(local_meta.get("heading_hits", 0.0)),
                    float(local_score),
                )

            promote = bool(
                local_text
                and local_score >= 3.9
                and local_meta.get("focus_hits", 0.0) >= 1.0
                and (
                    local_meta.get("marker_density", 0.0) >= 0.08
                    or local_meta.get("heading_hits", 0.0) >= 1.0
                    or local_meta.get("focus_hits", 0.0) >= 2.0
                )
                and local_meta.get("drift", 1.0) <= 0.75
            )

            if promote:
                doc_new = dict(doc)
                md_new = dict(md)
                local_focus_hits = float(local_meta.get("focus_hits", 0.0) or 0.0)
                local_heading_match = float(local_meta.get("heading_hits", 0.0) or 0.0)
                local_list_density = float(local_meta.get("marker_density", 0.0) or 0.0)
                local_confidence_score = min(1.0, float(local_score) / 6.0)
                md_new["_local_window_promoted"] = True
                md_new["_local_anchor"] = local_anchor
                md_new["_local_window_score"] = round(float(local_score), 4)
                md_new["local_window_promoted"] = True
                md_new["local_focus_hits"] = round(local_focus_hits, 4)
                md_new["local_heading_match"] = round(local_heading_match, 4)
                md_new["local_list_density"] = round(local_list_density, 4)
                md_new["local_confidence_score"] = round(local_confidence_score, 4)
                md_new["_local_focus_hits"] = round(local_focus_hits, 4)
                md_new["_local_heading_match"] = round(local_heading_match, 4)
                md_new["_local_list_density"] = round(local_list_density, 4)
                md_new["_local_confidence_score"] = round(local_confidence_score, 4)
                md_new["_used_single_window"] = bool(local_meta.get("used_single_window", 0.0) >= 0.5)
                md_new["_placeholder_heading_rejected"] = bool(local_meta.get("placeholder_heading_rejected", 0.0) >= 0.5)
                md_new["_local_window_stop_reason"] = str(local_meta.get("reason_stop") or "")
                md_new["_section_signature"] = str(local_meta.get("section_signature") or "")
                md_new["_single_local_window_text"] = local_text[:6000]
                doc_new["metadata"] = md_new
                doc_new["page_content"] = local_text
                doc_new["text"] = local_text
                doc_new["_local_window_score"] = float(local_score)
                promoted_docs.append(doc_new)
                S.logger.info("[LOCAL WINDOW PROMOTION] chunk=%s promoted=True reason=local_window_match", chunk_idx)
                if local_anchor:
                    S.logger.info("[SECTION ANCHOR PROMOTION] chunk=%s anchor=%s score=%.3f", chunk_idx, local_anchor[:120], float(local_score))
            else:
                doc_keep = dict(doc)
                md_keep = dict(md)
                local_focus_hits = float(local_meta.get("focus_hits", 0.0) or 0.0)
                local_heading_match = float(local_meta.get("heading_hits", 0.0) or 0.0)
                local_list_density = float(local_meta.get("marker_density", 0.0) or 0.0)
                local_confidence_score = min(1.0, float(local_score) / 6.0)
                md_keep["local_focus_hits"] = round(local_focus_hits, 4)
                md_keep["local_heading_match"] = round(local_heading_match, 4)
                md_keep["local_list_density"] = round(local_list_density, 4)
                md_keep["local_confidence_score"] = round(local_confidence_score, 4)
                md_keep["_local_focus_hits"] = round(local_focus_hits, 4)
                md_keep["_local_heading_match"] = round(local_heading_match, 4)
                md_keep["_local_list_density"] = round(local_list_density, 4)
                md_keep["_local_confidence_score"] = round(local_confidence_score, 4)
                md_keep["_used_single_window"] = bool(local_meta.get("used_single_window", 0.0) >= 0.5)
                md_keep["_placeholder_heading_rejected"] = bool(local_meta.get("placeholder_heading_rejected", 0.0) >= 0.5)
                md_keep["_local_window_stop_reason"] = str(local_meta.get("reason_stop") or "")
                md_keep["_section_signature"] = str(local_meta.get("section_signature") or "")
                if local_text:
                    md_keep["_single_local_window_text"] = local_text[:6000]
                doc_keep["metadata"] = md_keep
                doc_keep["_local_window_score"] = float(local_score)
                promoted_docs.append(doc_keep)
                S.logger.info("[LOCAL WINDOW PROMOTION] chunk=%s promoted=False reason=weak_local_window", chunk_idx)

        promoted_docs.sort(key=lambda d: float(d.get("_local_window_score", 0.0)) + (0.35 * _base_score(d)), reverse=True)
        focused_docs = promoted_docs

    return focused_docs[: max(len(retrieved_docs), top_k)]

def _safe_int(v: Any) -> Optional[int]:
    """Convert a value to int safely; return None on failure."""
    try:
        return int(v)
    except Exception:
        return None

def _collect_local_window_support(docs: list[dict]) -> dict[str, Any]:
    support = {
        "promoted_count": 0.0,
        "focus_hits": 0.0,
        "phrase_hits": 0.0,
        "heading_match": 0.0,
        "list_density": 0.0,
        "confidence": 0.0,
        "used_single_window": 0.0,
        "placeholder_heading_rejected": 0.0,
        "merged_extra_chunks_count": 0.0,
        "source_chunk_count": 0.0,
        "chunk_span": 0.0,
        "source_chunks": [],
        "chunk_texts": [],
        "validation_scope": "selected_chunks",
        "single_local_window_text": "",
        "scope_chunk": -1.0,
        "same_section_adjacent_labels": 0.0,
    }
    source_chunks: set[int] = set()
    section_rows: list[dict[str, Any]] = []
    best_scope_conf = -1.0

    def _page_num(md: dict) -> int | None:
        raw_page = md.get("page")
        if raw_page is None:
            return None
        m = re.search(r"\d+", str(raw_page))
        if not m:
            return None
        try:
            return int(m.group(0))
        except Exception:
            return None

    def _clean_label_count(text: str) -> int:
        if not text:
            return 0
        inline_pattern_hits = 0
        seen_inline: set[str] = set()
        for m in re.finditer(
            r"\b([A-Z][A-Za-z\-']{2,}(?:\s+[A-Z][A-Za-z\-']{2,}){0,3})\s+(?:A|An)\s+(?:branch|category|type|kind|form|area)\s+of\b",
            str(text),
            flags=re.IGNORECASE,
        ):
            cand = re.sub(r"\s+", " ", str(m.group(1) or "")).strip(" ,;:-")
            if not cand:
                continue
            norm_c = re.sub(r"[^a-z0-9]+", " ", cand.lower()).strip()
            if not norm_c or norm_c in seen_inline:
                continue
            seen_inline.add(norm_c)
            inline_pattern_hits += 1

        lines = [ln.strip() for ln in str(text).splitlines() if ln.strip()]
        if not lines:
            lines = [p.strip() for p in re.split(r"(?<=[.!?])\s+", str(text)) if p.strip()]
        count = 0
        seen_norm: set[str] = set()
        for ln in lines[:60]:
            item = re.sub(r"^\s*(?:[-•*]|\d+[.)]|[a-z][.)])\s+", "", ln).strip(" ,;:-")
            if not item:
                continue
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
            wc = len(words)
            if wc < 1 or wc > 6:
                continue
            low = item.lower()
            if re.search(r"\b(?:is|are|was|were|be|been|being|include|includes|included|consist|consists|consisted|comprise|comprises|composed|focus|focuses|focused|study|studies|studied|explain|explains|explained|describe|describes|described|involv(?:e|es|ed)|concern(?:s|ed)?)\b", low):
                continue
            if re.search(r"[;:]", item) or ". " in item:
                continue
            norm = re.sub(r"[^a-z0-9]+", " ", low).strip()
            if not norm or norm in seen_norm:
                continue
            seen_norm.add(norm)
            count += 1
        return max(count, inline_pattern_hits)

    def _extract_inline_labels(text: str) -> list[str]:
        labels: list[str] = []
        seen: set[str] = set()
        src = str(text or "")
        for m in re.finditer(
            r"\b([A-Z][A-Za-z\-']{2,}(?:\s+[A-Z][A-Za-z\-']{2,}){0,3})\s+(?:A|An)\s+(?:branch|category|type|kind|form|area)\s+of\b",
            src,
            flags=re.IGNORECASE,
        ):
            cand = re.sub(r"\s+", " ", str(m.group(1) or "")).strip(" ,;:-")
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", cand)
            if len(words) < 1 or len(words) > 6:
                continue
            norm = re.sub(r"[^a-z0-9]+", " ", cand.lower()).strip()
            if not norm or norm in seen:
                continue
            seen.add(norm)
            labels.append(cand)

        title_candidates = [
            re.sub(r"\s+", " ", c).strip(" ,;:-")
            for c in re.findall(r"\b([A-Z][A-Za-z\-']+(?:\s+[A-Z][A-Za-z\-']+){1,3})\b", src)
        ]
        suffix_counter: Counter[str] = Counter()
        normalized_candidates: list[tuple[str, list[str]]] = []
        connector_words = {"of", "to", "for", "in", "on", "with", "by", "and", "or"}
        for cand in title_candidates:
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", cand)
            if len(words) < 2 or len(words) > 4:
                continue
            lw = [w.lower() for w in words]
            if any(w in connector_words for w in lw):
                continue
            normalized_candidates.append((cand, words))
            suffix_counter[words[-1].lower()] += 1

        dominant_suffix = ""
        if suffix_counter:
            top_suffix, top_count = suffix_counter.most_common(1)[0]
            if top_count >= 3:
                dominant_suffix = str(top_suffix)

        if dominant_suffix:
            for cand, words in normalized_candidates:
                if words[-1].lower() != dominant_suffix:
                    continue
                norm = re.sub(r"[^a-z0-9]+", " ", cand.lower()).strip()
                if not norm or norm in seen:
                    continue
                seen.add(norm)
                labels.append(cand)
        return labels

    for d in (docs or []):
        md = dict((d or {}).get("metadata") or {})
        chunk_idx = -1
        try:
            chunk_idx = int(md.get("chunk_index") or -1)
            source_chunks.add(chunk_idx)
        except Exception:
            pass
        promoted = bool(md.get("_local_window_promoted") or md.get("local_window_promoted"))
        chunk_text = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        source_name = str(md.get("source") or md.get("filename") or md.get("id") or "")
        page_num = _page_num(md)
        section_rows.append({
            "source": source_name,
            "page": page_num,
            "chunk": chunk_idx,
            "text": chunk_text,
            "clean_labels": _clean_label_count(chunk_text),
        })
        if chunk_text and isinstance(support.get("chunk_texts"), list):
            support["chunk_texts"].append({
                "chunk": int(chunk_idx) if "chunk_idx" in locals() else -1,
                "text": chunk_text[:3000],
            })
        conf_raw = float(md.get("local_confidence_score") or md.get("_local_confidence_score") or md.get("_local_window_score") or 0.0)
        conf = min(1.0, (conf_raw / 6.0)) if conf_raw > 1.0 else max(0.0, conf_raw)
        support["confidence"] = max(support["confidence"], conf)
        is_single_window = bool(md.get("_used_single_window"))
        if is_single_window:
            support["used_single_window"] = 1.0
        if bool(md.get("_placeholder_heading_rejected")):
            support["placeholder_heading_rejected"] = 1.0
        scope_text = str(md.get("_single_local_window_text") or chunk_text)
        if is_single_window and scope_text.strip() and conf > best_scope_conf:
            best_scope_conf = conf
            support["validation_scope"] = "single_local_window"
            support["single_local_window_text"] = scope_text[:8000]
            support["scope_chunk"] = float(chunk_idx)
        if not promoted:
            continue
        support["promoted_count"] += 1.0
        support["focus_hits"] = max(
            support["focus_hits"],
            float(md.get("local_focus_hits") or md.get("_local_focus_hits") or 0.0),
        )
        support["phrase_hits"] = max(
            support["phrase_hits"],
            float(md.get("local_phrase_hits") or md.get("_local_phrase_hits") or 0.0),
        )
        support["heading_match"] = max(
            support["heading_match"],
            float(md.get("local_heading_match") or md.get("_local_heading_match") or 0.0),
        )
        support["list_density"] = max(
            support["list_density"],
            float(md.get("local_list_density") or md.get("_local_list_density") or 0.0),
        )

    if section_rows:
        grouped: dict[str, list[dict[str, Any]]] = {}
        for row in section_rows:
            src = str(row.get("source") or "")
            if not src:
                continue
            grouped.setdefault(src, []).append(row)

        best_pair: tuple[int, list[dict[str, Any]]] | None = None
        for _src, rows in grouped.items():
            valid_rows = [r for r in rows if isinstance(r.get("chunk"), int) and (r.get("chunk") or 0) >= 0]
            valid_rows.sort(key=lambda r: int(r.get("chunk") or -1))
            for i in range(len(valid_rows) - 1):
                a = valid_rows[i]
                b = valid_rows[i + 1]
                ca = int(a.get("chunk") or -1)
                cb = int(b.get("chunk") or -1)
                if abs(cb - ca) != 1:
                    continue
                pa = a.get("page")
                pb = b.get("page")
                same_or_adj_page = bool(
                    (isinstance(pa, int) and isinstance(pb, int) and abs(pa - pb) <= 1)
                    or (pa is None)
                    or (pb is None)
                )
                if not same_or_adj_page:
                    continue
                labels_a = int(a.get("clean_labels") or 0)
                labels_b = int(b.get("clean_labels") or 0)
                if labels_a < 1 or labels_b < 1:
                    continue
                pair_score = labels_a + labels_b
                if best_pair is None or pair_score > best_pair[0]:
                    best_pair = (pair_score, [a, b])

        if best_pair is not None and best_pair[0] >= 3:
            pair_rows = best_pair[1]
            pair_chunks = [int(r.get("chunk") or -1) for r in pair_rows if int(r.get("chunk") or -1) >= 0]
            pair_labels: list[str] = []
            seen_pair_labels: set[str] = set()
            for r in pair_rows:
                for lbl in _extract_inline_labels(str(r.get("text") or "")):
                    norm_lbl = re.sub(r"[^a-z0-9]+", " ", lbl.lower()).strip()
                    if not norm_lbl or norm_lbl in seen_pair_labels:
                        continue
                    seen_pair_labels.add(norm_lbl)
                    pair_labels.append(lbl)
            pair_text = "\n".join(pair_labels) if len(pair_labels) >= 3 else "\n".join(str(r.get("text") or "") for r in pair_rows if str(r.get("text") or "").strip())
            if pair_chunks and pair_text.strip():
                support["same_section_adjacent_labels"] = 1.0
                if support.get("validation_scope") != "single_local_window":
                    support["validation_scope"] = "adjacent_local_section"
                    support["single_local_window_text"] = pair_text[:8000]
                    support["scope_chunk"] = float(min(pair_chunks))
                S.logger.info(
                    "[LOCAL SECTION ADJ] enabled=true chunks=%s label_score=%s labels=%s",
                    pair_chunks,
                    int(best_pair[0]),
                    len(pair_labels),
                )
    ordered_chunks = sorted(source_chunks)
    support["source_chunk_count"] = float(len(ordered_chunks))
    support["chunk_span"] = float((ordered_chunks[-1] - ordered_chunks[0]) if len(ordered_chunks) >= 2 else 0.0)
    support["source_chunks"] = ordered_chunks
    return support

def _clean_mixed_not_found_response(ai_text: str) -> str:
    S.logger.info("[LOG] _clean_mixed_not_found_response invoked | len=%s", len(str(ai_text or "")))
    if not ai_text:
        return ai_text
    if RAG_NO_MATCH_RESPONSE not in ai_text:
        return ai_text
    cleaned = ai_text.replace(RAG_NO_MATCH_RESPONSE, "").strip()
    if cleaned and len(re.findall(r"[A-Za-z]{3,}", cleaned)) >= 4:
        out = re.sub(r"\s+", " ", cleaned).strip()
        S.logger.info("[LOG] _clean_mixed_not_found_response produced cleaned text | len=%s", len(out))
        return out
    S.logger.info("[LOG] _clean_mixed_not_found_response returning original RAG_NO_MATCH_RESPONSE")
    return ai_text

def _count_list_like_items_in_docs(docs: list[dict]) -> int:
    """Count list-like items across retrieved docs. Detect bullets, numbered lines, and common list markers.

    Returns an integer count of detected items (best-effort).
    """
    if not docs:
        return 0
    count = 0
    for d in docs:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not txt:
            continue
        # bullets/numbered patterns
        count += len(re.findall(r"(?:^|\n)\s*(?:[-•*]|\d+[.)])\s+.+", txt))
        # comma-separated short lists (a, b, c)
        count += len(re.findall(r"\b\w+\s*,\s*\w+\s*,\s*\w+\b", txt))
        # generic heading/list markers (counts as weak signals)
        count += len(re.findall(r"\b(elements|figures|tables|sections|items|points)\b", txt, flags=re.IGNORECASE))
    return count

def _context_grounded_definition_override(query_text: str, retrieved_docs: list[dict], ai_text: str) -> str | None:
    S.logger.info("[LOG] _context_grounded_definition_override invoked | query='%s' ai_text_len=%s", (query_text or "")[:120], len(str(ai_text or "")))
    q = (query_text or "").strip().lower()
    if not (q.startswith("what is") or q.startswith("define")):
        return None

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    concept = (entity or "").strip()
    if not has_entity or len(concept) < 2:
        return None

    norm_concept = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9 ]+", " ", concept.lower())).strip()
    if not norm_concept:
        return None

    strict_def_re = re.compile(
        rf"\b{re.escape(norm_concept)}\b(?:[\s\"'`”’]+)(?:is|refers\s+to|can\s+be\s+defined\s+as)\b",
        flags=re.IGNORECASE,
    )
    concept_pattern = re.escape(norm_concept).replace("\\ ", r"\\s+")
    strict_def_span_re = re.compile(
        rf"\b{concept_pattern}\b(?:[\s\"'`”’]+)(?:is|refers\s+to|can\s+be\s+defined\s+as)\b[^.?!\n]{{0,240}}[.?!]",
        flags=re.IGNORECASE,
    )
    history_re = re.compile(r"\b(?:\d{4}|\d{3,4}s)\b")
    publication_re = re.compile(r"\b(?:translated|book|publication|edition|isbn|https?://|www\.|kdpublications|unit\s*\d+|chapter\s*\d+|table\s+of\s+contents|contents?)\b", flags=re.IGNORECASE)
    bio_re = re.compile(
        r"\b(?:he|she|his|her|born|birth|died|author|authored|wrote|writer|biography)\b",
        flags=re.IGNORECASE,
    )
    table_figure_re = re.compile(r"\b(?:table|figure)\b", flags=re.IGNORECASE)
    concept_def_verb_re = re.compile(r"\b(?:is|refers\s+to|defined\s+as|known\s+as)\b", flags=re.IGNORECASE)
    unrelated_mix_re = re.compile(r"\b(?:however|whereas|on\s+the\s+other\s+hand|in\s+contrast)\b", flags=re.IGNORECASE)

    def _sentences(text: str) -> list[str]:
        raw = str(text or "").strip()
        if not raw:
            return []
        parts = re.split(r"(?<=[.!?])\s+|\n+", raw)
        return [p.strip(" \t\r\n-•*") for p in parts if p and p.strip()]

    def _norm(s: str) -> str:
        return re.sub(r"\s+", " ", re.sub(r"[^a-z0-9 ]+", " ", (s or "").lower())).strip()

    def _is_valid_clean_definition(s: str) -> bool:
        if not s:
            return False
        s_norm = _norm(s)
        if not s_norm:
            return False
        if not strict_def_re.search(s_norm):
            return False
        if not concept_def_verb_re.search(s):
            return False
        if history_re.search(s) or publication_re.search(s) or bio_re.search(s):
            return False
        if table_figure_re.search(s):
            return False
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
        if len(words) < 6:
            return False
        if re.search(r"(?:\b[A-Za-z]\s+){5,}\b", s):
            return False
        if unrelated_mix_re.search(s) and (s.count(",") >= 2 or ";" in s):
            return False
        return True

    def _extract_clean_span(s: str) -> str | None:
        raw = str(s or "").strip()
        if not raw:
            return None
        m = strict_def_span_re.search(raw)
        if not m:
            return None
        span = raw[m.start():m.end()].strip()
        if not span:
            return None
        if history_re.search(span) or publication_re.search(span) or bio_re.search(span):
            return None
        if table_figure_re.search(span):
            return None
        if not concept_def_verb_re.search(span):
            return None
        if len(re.findall(r"[A-Za-z][A-Za-z\-']*", span)) < 6:
            return None
        if re.search(r"(?:\b[A-Za-z]\s+){5,}\b", span):
            return None
        if unrelated_mix_re.search(span) and (span.count(",") >= 2 or ";" in span):
            return None
        return span.rstrip(" .") + "."

    for sentence in _sentences(ai_text):
        normalized_sentence = _strip_attribution_prefix_for_definition(sentence)
        for candidate in (sentence, normalized_sentence) if normalized_sentence != sentence else (sentence,):
            span = _extract_clean_span(candidate)
            if span:
                S.logger.info("[LOG] _context_grounded_definition_override: found span in AI text | span_preview=%s", span[:160])
                return span
            if _is_valid_clean_definition(candidate):
                S.logger.info("[LOG] _context_grounded_definition_override: valid clean definition in AI text | sent_preview=%s", candidate[:160])
                return candidate.rstrip(" .") + "."

    for d in (retrieved_docs or [])[:4]:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        for sentence in _sentences(txt):
            normalized_sentence = _strip_attribution_prefix_for_definition(sentence)
            for candidate in (sentence, normalized_sentence) if normalized_sentence != sentence else (sentence,):
                span = _extract_clean_span(candidate)
                if span:
                    S.logger.info("[LOG] _context_grounded_definition_override: found span in retrieved docs | span_preview=%s", span[:160])
                    return span
                if _is_valid_clean_definition(candidate):
                    S.logger.info("[LOG] _context_grounded_definition_override: valid clean definition in retrieved docs | sent_preview=%s", candidate[:160])
                    return candidate.rstrip(" .") + "."

    return None

def _force_clean_definition_sentence(query_text: str, answer_text: str, retrieved_docs: list[dict] | None = None) -> str:
    q = (query_text or "").strip().lower()
    if not (q.startswith("what is") or q.startswith("define")):
        return str(answer_text or "")

    answer = str(answer_text or "").strip()
    if not answer:
        return answer

    cleaned = _context_grounded_definition_override(query_text, retrieved_docs or [], answer)
    if cleaned:
        cleaned = re.sub(r'^\s*([A-Za-z][A-Za-z0-9\- ]+)"\s+(is|refers to|can be defined as)\b', r'\1 \2', cleaned, flags=re.IGNORECASE)
        return cleaned

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    concept = (entity or "").strip().lower()
    if not has_entity or not concept:
        return answer

    concept_pattern = re.escape(concept).replace("\\ ", r"\\s+")
    span_re = re.compile(
        rf"\b{concept_pattern}\b(?:[\s\"'`”’]+)(?:is|refers\s+to|can\s+be\s+defined\s+as)\b[^.?!\n]{{0,240}}[.?!]",
        flags=re.IGNORECASE,
    )
    noise_re = re.compile(
        r"\b(?:\d{4}|\d{3,4}s|translated|book|publication|edition|isbn|https?://|www\.|kdpublications|unit\s*\d+|chapter\s*\d+|he|she|his|her|born|birth|died|author|authored|wrote|writer|biography)\b",
        flags=re.IGNORECASE,
    )
    compact = re.sub(r"\s+", " ", answer).strip()
    m = span_re.search(compact)
    if m:
        span = compact[m.start():m.end()].strip()
        if span and not noise_re.search(span):
            span = re.sub(r'^\s*([A-Za-z][A-Za-z0-9\- ]+)"\s+(is|refers to|can be defined as)\b', r'\1 \2', span, flags=re.IGNORECASE)
            return span.rstrip(" .") + "."
    return answer

def _is_document_summary_query(query_text: str) -> bool:
    """Generalized, document-agnostic detector for self-referential
    document-overview questions ("what is this document about?",
    "summarize the uploaded file", "give me an overview", "explain this
    handbook").

    This is a pure query-grammar classifier: it inspects determiners,
    generic container nouns, and summarization cues only. It never
    inspects or depends on document content, entity names, tenant data,
    or any specific phrase, so it generalizes to arbitrary future
    documents. The discriminator versus an entity definition such as
    "what is FDIC?" is that the grammatical object is a generic *document
    container* (or there is no concrete object at all), rather than a
    domain concept named inside the document.
    """
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False

    # Generic, domain-agnostic container nouns that point at the uploaded
    # source itself, never at a concept contained within it.
    container = (
        r"(?:documents?|docs?|pdfs?|files?|handbooks?|guides?|manuals?|"
        r"books?|texts?|papers?|reports?|articles?|whitepapers?|"
        r"presentations?|slides?|contents?|materials?|attachments?|"
        r"uploads?)"
    )
    # Determiners / qualifiers that mark a *self reference* to the active
    # upload rather than naming a specific titled work.
    selfref_det = (
        r"(?:this|that|these|those|the|its|your|our|my|current|"
        r"uploaded|attached|provided|given|whole|entire|above|present)"
    )
    # Allow at most one intervening adjective (e.g. "this uploaded pdf",
    # "the entire document") while staying purely structural.
    docref = rf"\b{selfref_det}\s+(?:[a-z]+\s+)?{container}\b"

    # Summarization / overview intent cues (generic verbs and nouns).
    summary_cue = (
        r"(?:summari[sz]e|summary|overview|outline|recap|gist|synopsis|"
        r"tl;?dr|high[- ]level)"
    )
    # Verbs that, applied to a document reference, express "tell me what
    # the whole thing is about".
    about_cue = (
        r"(?:about|discuss(?:es|ing|ed)?|cover(?:s|ing)?|contain(?:s|ing)?|"
        r"talk(?:s|ing)?\s+about|say(?:s)?|address(?:es|ing)?|"
        r"focus(?:es|ing)?\s+on)"
    )

    docref_match = re.search(docref, q)
    has_docref = bool(docref_match)

    # (1) Summarization intent aimed at the document itself, or a bare
    #     summarization request that has no concrete object (it then
    #     defaults to the active document corpus).
    if re.search(rf"\b{summary_cue}\b", q):
        if has_docref:
            return True
        objectless = re.match(
            rf"^\s*(?:can\s+you\s+|could\s+you\s+|please\s+|give\s+me\s+|"
            rf"provide\s+|write\s+|create\s+|make\s+|i\s+want\s+|i\s+need\s+|"
            rf"a\s+|an\s+|the\s+)*"
            rf"{summary_cue}"
            rf"(?:\s+(?:me|us|it|this|that|please|of|for))*\s*[?.!]?\s*$",
            q,
        )
        if objectless:
            return True

    # (2) Interrogative "what is <doc> about / what does <doc> discuss".
    # Keep the grammar anchored on the document reference itself so targeted
    # questions such as "what are the X discussed in this document" still route
    # to normal grounded retrieval instead of document-level summarization.
    docref_subject_about = False
    if docref_match:
        before_docref = q[: docref_match.start()].strip()
        after_docref = q[docref_match.end() :].strip()
        about_match = re.match(rf"^(?P<cue>{about_cue})\b(?P<rest>.*)$", after_docref)
        after_about_rest = re.sub(r"^[\s?.!,;:]+|[\s?.!,;:]+$", "", about_match.group("rest") if about_match else "")
        # Whole-document questions have the document as the object. Targeted
        # questions such as "what does the document say about Freud" have a
        # second object after the cue and must continue through focused RAG.
        docref_subject_about = bool(
            re.match(r"^(?:what\s+(?:does|do|is|are)|what's|tell\s+me\s+what)\s*$", before_docref)
            and about_match
            and not after_about_rest
        )
    generic_discussed_object = bool(
        re.match(
            rf"^\s*what\s+(?:topics?|subjects?|themes?|ideas?|points?|contents?|material)\s+"
            rf"(?:are|is)\s+{about_cue}\s+(?:in|within|by)\s+{docref}\b",
            q,
        )
    )
    if has_docref and (docref_subject_about or generic_discussed_object):
        return True

    # (3) "what is in <doc>" / "what's contained in <doc>" — objectless
    #     content question anchored on the document reference.
    if has_docref and re.match(r"^\s*what(?:'s| is| are)\s+(?:contained\s+)?in\b", q):
        return True

    # (4) "tell me about <doc>", "explain/describe <doc>", "walk me
    #     through <doc>" where the object is the document container itself.
    if has_docref and re.search(
        rf"\b(?:tell\s+me\s+about|explain|describe|walk\s+me\s+through)\s+{docref}",
        q,
    ):
        return True

    return False

def _is_definition_style_query(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if _is_definition_comparison_query(q):
        return False
    if _is_compare_query(q):
        return False
    # [DOMAIN CLEANUP] removed=hardcoded domain term blocklist (machine
    # learning|AI|blockchain|bitcoin|ethereum|neural network|cyber
    # security|elon musk). replacement=generic strict-grounding pipeline:
    # definition shape is decided by query grammar only, and any concept
    # absent from the indexed documents is rejected downstream by the
    # strict definition relevance guard / retrieval evidence checks,
    # which return exactly RAG_NO_MATCH_RESPONSE without any domain word
    # list.

    if re.match(r"^(?:what\s+is|define|who\s+is|who\s+was|who\s+introduced|who\s+is\s+considered)", q):
        return True

    if re.match(
        r"^\s*(?:please\s+)?(?:explain|describe)\s+.+\b(?:according\s+to|in|from|within)\s+(?:the\s+)?(?:documents?|docs?|pdfs?|files?|books?|texts?|sources?|passages?|chapters?|sections?)\b",
        q,
        flags=re.IGNORECASE,
    ):
        return False

    explanation_patterns = [
        r"^\s*(?:please\s+)?(?:explain|describe)\s+.+",
        r"^\s*what\s+does\s+.+\s+mean\s*\??\s*$",
        r"^\s*what\s+does\s+.+\s+focus\s+on\s*\??\s*$",
        r"^\s*how\s+does\s+.+\s+work\s*\??\s*$",
        r"^\s*what\s+is\s+the\s+idea\s+(?:of|behind)\s+.+\s*\??\s*$",
    ]
    return any(re.match(pat, q, flags=re.IGNORECASE) for pat in explanation_patterns)

def _definition_comparison_reason(query_text: str) -> str:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return ""

    definition_cue = bool(re.search(r"\b(?:define|defines|defined|definition|definitions|meaning|sense)\b", q))
    both_comparison_cue = bool(
        re.search(r"\bboth\b.{0,90}\band\b", q)
        or re.search(r"\b(?:broad|general|wide|technical|narrow|specific|formal|informal)\b.{0,50}\band\b.{0,50}\b(?:broad|general|wide|technical|narrow|specific|formal|informal)\b", q)
    )
    if re.search(r"\bhow\s+does\s+(?:the\s+)?(?:text|document|book|source|passage|chapter|section|author)\s+define\b", q):
        return "text_define_surface"
    if definition_cue and re.search(r"\bin\s+both\b", q):
        return "define_in_both"
    if definition_cue and re.search(r"\bcompare\s+(?:the\s+)?definitions?\b|\bdefinitions?\s+(?:compare|differ|differing)\b", q):
        return "compare_definitions"
    if definition_cue and re.search(r"\bdifference\s+between\b.+\band\b.+\bdefinitions?\b", q):
        return "difference_between_definition_senses"
    if definition_cue and both_comparison_cue:
        return "definition_with_two_senses"
    if re.search(r"\b(?:considered|viewed|treated|regarded|described)\s+both\s+(?:as\s+)?(?:an?\s+)?[a-z0-9\- ]{1,40}?\s+and\s+(?:an?\s+)?[a-z0-9\- ]+", q):
        return "considered_both_as"
    if re.search(r"\bboth\s+(?:an?\s+)?(?:art|science)\s+and\s+(?:an?\s+)?(?:art|science)\b", q):
        return "art_science_both_pair"
    if re.search(r"\bas\s+(?:an?\s+)?(?:art|science)\s+and\s+(?:an?\s+)?(?:art|science)\b", q):
        return "art_science_sense_pair"
    return ""

def _is_definition_comparison_query(query_text: str) -> bool:
    return bool(_definition_comparison_reason(query_text))

def _log_query_family_fix(query_text: str, family: str, reason: str) -> None:
    S.logger.info(
        "[QUERY FAMILY FIX] query=%s family=%s reason=%s",
        re.sub(r"\s+", " ", str(query_text or "").strip())[:220],
        family,
        reason,
    )

def _normalize_definition_entity(entity: str) -> str:
    out = str(entity or "").strip(" \t\n\r\"'`.,;:!?()[]{}")
    out = re.sub(
        r"^(?:meant\s+by|mean\s+by|meaning\s+of|definition\s+of|the\s+idea\s+of|the\s+idea\s+behind|idea\s+of|idea\s+behind|the\s+goal\s+of|goal\s+of|the\s+purpose\s+of|purpose\s+of|an?\s+explanation\s+of|explanation\s+of)\s+",
        "",
        out,
        flags=re.IGNORECASE,
    )
    out = re.sub(r"^(?:considered\s+)?(?:the\s+)?father\s+of\s+", "", out, flags=re.IGNORECASE)
    out = re.sub(r"^(?:known\s+as\s+)", "", out, flags=re.IGNORECASE)
    out = re.sub(r"^(?:the|a|an|term|concept)\s+", "", out, flags=re.IGNORECASE)
    out = re.sub(r"\b(?:in|of|for|from|about|within|during)\s+(?:the\s+)?[a-z][a-z0-9\s\-]{0,40}$", "", out, flags=re.IGNORECASE)
    out = re.sub(r"\b(?:focus(?:es)?\s+on|mean(?:s)?|work(?:s)?)\s*$", "", out, flags=re.IGNORECASE)
    out = re.sub(r"\b(?:fully|in\s+detail)\s*$", "", out, flags=re.IGNORECASE)
    out = re.sub(r"\b(?:in\s+general|generally|overall|in\s+simple\s+terms)\s*$", "", out, flags=re.IGNORECASE)
    out = _strip_query_instruction_modifiers(out)
    out = re.sub(r"\s+", " ", out).strip()
    return out

def _strip_query_instruction_modifiers(text: str) -> str:
    out = re.sub(r"\s+", " ", str(text or "")).strip()
    if not out:
        return ""

    trailing_modifier_patterns = [
        r"in\s+simple\s+words",
        r"in\s+simple\s+terms",
        r"simply",
        r"in\s+an\s+easy\s+way",
        r"for\s+beginners",
        r"briefly",
        r"shortly",
    ]

    for _ in range(3):
        before = out
        for pat in trailing_modifier_patterns:
            out = re.sub(rf"(?:\s*,?\s*{pat})\s*$", "", out, flags=re.IGNORECASE)
        out = re.sub(r"\s+", " ", out).strip(" \t\n\r\"'`.,;:!?-")
        if out == before:
            break

    return out

def _extract_entity_from_definition_query(query_text: str) -> tuple[bool, str]:
    S.logger.info("[LOG] _extract_entity_from_definition_query invoked | query='%s'", (query_text or "")[:160])
    q = (query_text or "").strip()
    if not q:
        return False, ""
    if _is_compare_query(q):
        S.logger.info("[LOG] _extract_entity_from_definition_query: compare query detected, skipping single-entity parse")
        return False, ""

    if _is_definition_comparison_query(q):
        comparison_patterns = [
            r"^\s*how\s+(?:does|do)\s+(?:the\s+)?(?:text|document|book|source|passage|chapter|section|author)\s+define\s+(.+?)(?:\s+in\s+both\b|\s+as\b|\s+according\b|[?.!]|$)",
            r"^\s*(?:define|describe|explain)\s+(.+?)\s+in\s+both\b",
            r"^\s*(?:how|why)\s+(?:is|are)\s+(.+?)\s+(?:considered|viewed|treated|regarded|described)\s+both\b",
            r"^\s*(.+?)\s+as\s+(?:an?\s+)?[a-z][a-z\-]+\s+and\s+(?:an?\s+)?[a-z][a-z\-]+\s*\??\s*$",
            r"^\s*(?:compare|contrast)\s+(?:the\s+)?definitions?\s+of\s+(.+?)(?:[?.!]|$)",
        ]
        for pat in comparison_patterns:
            m = re.match(pat, q, flags=re.IGNORECASE)
            if not m:
                continue
            entity_raw = re.sub(r"\s+", " ", (m.group(1) or "").strip())
            entity_raw = re.sub(r"\s+(?:in\s+both|as\s+(?:an?\s+)?[a-z][a-z\-]+\s+and\s+(?:an?\s+)?[a-z][a-z\-]+).*$", "", entity_raw, flags=re.IGNORECASE)
            entity = _normalize_definition_entity(entity_raw)
            if len(entity) >= 2:
                S.logger.info(
                    "[LOG] _extract_entity_from_definition_query: parsed entity='%s' (definition_comparison)",
                    entity,
                )
                return True, entity

    # MP-C9 — list / enumerative queries ("What are the characteristics of X",
    # "List the principles of X", "How many types of X are there"). The
    # existing single-entity patterns below only handle definition shapes
    # ("what is X", "define X", "explain X", ...). For list shapes we want
    # the TAIL after a generic connective (of|in|for|about|...), which is
    # the inverse of `_normalize_definition_entity` (which STRIPS such
    # tails). So we extract directly here and short-circuit before the
    # normaliser. Pure positional / connective logic — no domain words.
    list_query_patterns = [
        r"^\s*(?:what|which)\s+are\s+(?:all\s+|the\s+)?(.+?)\s*\??\s*$",
        r"^\s*(?:list|name|mention|identify|give|enumerate)\s+(?:all\s+|the\s+|some\s+)?(.+?)\s*\??\s*$",
        r"^\s*(?:tell\s+me|show\s+me)\s+(?:all\s+|the\s+|some\s+)?(.+?)\s*\??\s*$",
        r"^\s*how\s+many\s+(.+?)\s+(?:are\s+there|exist)\s*\??\s*$",
    ]
    list_subject = ""
    for pat in list_query_patterns:
        m = re.match(pat, q, flags=re.IGNORECASE)
        if m:
            list_subject = re.sub(r"\s+", " ", (m.group(1) or "")).strip(" \t\n\r\"'`.,;:!?")
            break

    if list_subject:
        # Drop trivial leading determiners/quantifiers from the captured
        # subject, then split on a generic connective. The TAIL is the
        # entity (e.g. "characteristics of management" -> "management";
        # "steps in the planning process" -> "planning process";
        # "types of organization" -> "organization").
        subj = re.sub(
            r"^(?:the|a|an|all|some|main|major|key|important|various|different|"
            r"following|above|below)\s+",
            "",
            list_subject,
            flags=re.IGNORECASE,
        ).strip()
        connective_match = re.search(
            r"\b(?:of|in|for|about|regarding|concerning|on|within|across|under|"
            r"between|behind)\b\s+(.+)$",
            subj,
            flags=re.IGNORECASE,
        )
        list_entity_raw = connective_match.group(1).strip() if connective_match else subj
        # Strip a leading determiner from the tail too ("the planning process"
        # -> "planning process") and trim trailing process-helper words that
        # don't belong to the entity ("...are there", "...listed").
        list_entity_raw = re.sub(
            r"^(?:the|a|an|its|their|his|her|our|this|that|these|those|"
            r"such|any)\s+",
            "",
            list_entity_raw,
            flags=re.IGNORECASE,
        ).strip()
        list_entity_raw = re.sub(
            r"\s+(?:are\s+there|listed|mentioned|given|described|explained|"
            r"in\s+detail|in\s+general)\s*$",
            "",
            list_entity_raw,
            flags=re.IGNORECASE,
        ).strip()
        list_entity_raw = _strip_query_instruction_modifiers(list_entity_raw)
        list_entity = re.sub(r"\s+", " ", list_entity_raw).strip(" \t\n\r\"'`.,;:!?-")
        if len(list_entity) >= 2:
            S.logger.info(
                "[LOG] _extract_entity_from_definition_query: parsed entity='%s' (list_query)",
                list_entity,
            )
            return True, list_entity
        # Fall through to legacy patterns if we somehow stripped everything.

    patterns = [
        r"^\s*(?:who|what)\s+(?:is|was)\s+(.+?)\s*\??\s*$",
        r"^\s*define\s+(.+?)\s*\??\s*$",
        r"^\s*who\s+introduced\s+(.+?)\s*\??\s*$",
        r"^\s*(?:please\s+)?(?:explain|describe)\s+(.+?)\s*\??\s*$",
        r"^\s*(?:please\s+)?(?:summarize|summarise)\s+(.+?)\s*\??\s*$",
        r"^\s*(?:please\s+)?summary\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*(?:please\s+)?(?:give\s+)?(?:an?\s+)?explanation\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*what\s+does\s+(.+?)\s+mean\s*\??\s*$",
        r"^\s*what\s+does\s+(.+?)\s+focus\s+on\s*\??\s*$",
        r"^\s*how\s+does\s+(.+?)\s+work\s*\??\s*$",
        r"^\s*how\s+does\s+(.+?)\s+work\s+in\s+detail\s*\??\s*$",
        r"^\s*what\s+is\s+the\s+(?:goal|purpose)\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*what\s+is\s+the\s+idea\s+(?:of|behind)\s+(.+?)\s*\??\s*$",
    ]
    entity = ""
    for pat in patterns:
        m = re.match(pat, q, flags=re.IGNORECASE)
        if m:
            entity = (m.group(1) or "").strip()
            break

    if not entity:
        S.logger.info("[LOG] _extract_entity_from_definition_query: no entity parsed")
        return False, ""

    entity = _normalize_definition_entity(entity)
    if len(entity) < 2:
        S.logger.info("[LOG] _extract_entity_from_definition_query: parsed entity too short='%s'", entity)
        return False, ""
    S.logger.info("[LOG] _extract_entity_from_definition_query: parsed entity='%s'", entity)
    return True, entity

def _promote_entity_definition_top_doc(query_text: str, doc_dicts: list[dict], top_k: int = 6) -> list[dict]:
    S.logger.info("[LOG] _promote_entity_definition_top_doc invoked | query='%s' candidates=%s", (query_text or "")[:120], len(doc_dicts) if doc_dicts else 0)
    if not doc_dicts:
        S.logger.info("[LOG] _promote_entity_definition_top_doc: no docs, returning")
        return doc_dicts

    S.logger.info("[LOG] _promote_entity_definition_top_doc: disabled (no-op), preserving incoming ranking")
    return doc_dicts

def _is_simple_factual_text_query(text: str) -> bool:
    cleaned = (text or "").strip().lower()
    if not cleaned:
        return False

    complex_markers = (
        "compare", "different", "perspective", "misconception", "evolved", "contribution",
        "explain",
    )
    if any(m in cleaned for m in complex_markers):
        return False
        
    words = cleaned.split()
    if len(words) > 12 or len(cleaned) > 80:
        return False
        
    factual_starts = (
        "what is", "what are", "who", "when", "where", "define", "list", "capital of", "give", "name", "ما هو", "من هو", "متى"
    )
    return cleaned.startswith(factual_starts)

def _is_numeric_fact_lookup_query(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if _query_needs_explanatory_answer(q):
        return False
    patterns = (
        # Generic value-lookup vocabulary (no domain/product terms).
        r"\b(?:coverage|limit|minimum|maximum|balance|fee|fees|rate|amount|price|cost|charge|deposit|insured|insurance|threshold|score)\b",
        r"\b(?:how much|how many)\b",
        r"\b(?:requirement|requirements)\b.*\b(?:balance|fee|deposit|amount|limit)\b",
        r"\b(?:balance|fee|deposit|amount|limit)\b.*\b(?:requirement|requirements)\b",
        # Fastest/instant *method* questions are value/attribute lookups too.
        r"\b(?:fastest|quickest|cheapest|lowest|highest)\b.*\b(?:method|option|way|transfer)\b",
    )
    return any(re.search(p, q) for p in patterns)

def _is_attribute_lookup_query(query_text: str) -> bool:
    """Entity-scoped attribute or reverse table-feature lookups (not definitions)."""
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if re.search(
        r"\bwhich\b.*\b(?:include|includes|support|supports|has|have|provides?|offer|offers|contain|contains)\b",
        q,
    ):
        return True
    if _query_needs_explanatory_answer(q):
        return False
    if _is_support_procedural_query(q) and not re.search(r"\bwhich\b", q):
        return False
    if _is_compare_query(q):
        return False
    if _is_numeric_fact_lookup_query(q):
        return True
    if _is_metric_fact_query(q):
        return True
    if re.match(r"^what is the\b", q) and re.search(r"\b(?:for|of)\s+[a-z0-9]", q):
        return True
    if re.match(r"^what is the\b", q) and re.search(
        r"\b(?:response\s+time|support|fee|fees|monthly|annual|price|cost|limit|projects?|users?|storage|memory|tier|audit|logs?)\b",
        q,
    ):
        return True
    if re.search(r"\bwhich\b.*\b(?:best|most|highest|lowest|fastest|largest|smallest|maximum|minimum)\b", q):
        return True
    return False

_TABLE_HEADER_TOKENS = frozenset(
    {
        "plan",
        "plans",
        "monthly",
        "annual",
        "yearly",
        "fee",
        "fees",
        "price",
        "cost",
        "feature",
        "features",
        "support",
        "tier",
        "tiers",
        "family",
        "families",
        "category",
        "option",
        "options",
        "name",
        "type",
        "types",
        "yes",
        "no",
        "included",
        "n/a",
    }
)

def _is_table_header_token(token: str) -> bool:
    norm = re.sub(r"\s+", " ", str(token or "").strip().lower())
    if not norm:
        return True
    if norm in _TABLE_HEADER_TOKENS:
        return True
    if len(norm.split()) == 1 and norm.endswith("ly") and len(norm) <= 10:
        return True
    return False

def _strip_prose_prefix_from_table_text(text: str) -> str:
    raw = str(text or "")
    for label in (
        "Plan", "Family", "Feature", "Tier", "Product", "Service",
        "Category", "Type", "Model", "Package", "Option", "Name",
    ):
        match = re.search(rf"\b{label}\s*\|", raw, flags=re.IGNORECASE)
        if match:
            return raw[match.start():]
    return raw

def _sanitize_table_cell_value(cell: str) -> str:
    value = re.sub(r"\s+", " ", str(cell or "").strip())
    if not value:
        return value
    for marker in (" Support is reached", " For security", " Customers must", " For your security"):
        idx = value.find(marker)
        if idx > 0:
            value = value[:idx].strip()
    if len(value) > 60 and re.search(r"\.\s+[A-Z]", value):
        value = re.split(r"\.\s+(?=[A-Z])", value, maxsplit=1)[0].strip()
    if re.search(r"\b(?:min|minute|hour|business)\b", value, flags=re.IGNORECASE):
        value = re.sub(r"<\s*(\d+)", r"under \1", value)
    return value.rstrip(" ,.;")

def _normalize_glued_inline_pipe_table(text: str) -> str:
    raw = _strip_prose_prefix_from_table_text(text)
    # Split short header/feature columns glued to the first row label (e.g. "| SSO Starter | $").
    raw = re.sub(
        r"(\|\s*[A-Z]{2,6})\s+([A-Z][a-z][A-Za-z0-9-]*)\s+\|(\s*\$[\d.,]+)",
        r"\1 | \2 |\3",
        raw,
    )
    raw = re.sub(
        r"(\|\s*[A-Za-z0-9 ,/<\-]{1,40})\s+([A-Z][a-z][A-Za-z0-9-]*)\s+\|(\s*\$[\d.,]+)",
        r"\1 | \2 |\3",
        raw,
    )
    raw = re.sub(
        r"(\|\s*(?:No|Yes|Custom|Included|Supported|Available|N/A|NA))\s+([A-Z][a-z][A-Za-z0-9-]*)\s+\|",
        r"\1 | \2 |",
        raw,
        flags=re.IGNORECASE,
    )
    raw = re.sub(
        r"([A-Za-z])(\s+)([A-Z][A-Za-z0-9-]{2,20})(\s*\|\s*\$[\d.,]+)",
        r"\1 | \3\4",
        raw,
    )
    raw = re.sub(
        r"([a-z0-9,\)\>\"])(\s+)([A-Z][A-Za-z0-9-]{2,20})(\s*\|\s*\$[\d.,]+)",
        r"\1 | \3\4",
        raw,
    )
    raw = re.sub(
        r"([a-z0-9,\)\>\"])(\s+)([A-Z][A-Za-z0-9-]{2,20})(\s*\|\s*Custom\s*\|)",
        r"\1 | \3\4",
        raw,
        flags=re.IGNORECASE,
    )
    raw = re.sub(
        r"([a-z0-9,\)\>\"])(\s+)([A-Z][A-Za-z0-9-]{2,20})(\s*\|\s*(?:Email|Chat))",
        r"\1 | \3\4",
        raw,
        flags=re.IGNORECASE,
    )
    raw = re.sub(
        r"(On-dem(?:and|\s+and)\s+price)(\s+)((?:General|Compute|Memory|GPU)\s*\()",
        r"\1 | \3",
        raw,
        flags=re.IGNORECASE,
    )
    vm_family_table = bool(
        re.search(r"\bfamily\b", raw, flags=re.IGNORECASE)
        and re.search(r"\bv\s*cpu\b", raw, flags=re.IGNORECASE)
        and re.search(r"\bmemory range\b", raw, flags=re.IGNORECASE)
    )
    if vm_family_table:
        raw = re.sub(
            r"((?:from\s+)?[\$€]?[\d.,]+\s*/(?:\s*(?:v\s*)?CPU-hr|\s*GPU-hr)?)(\s+)((?:Compute|Memory|GPU)\s*\()",
            r"\1 | \3",
            raw,
            flags=re.IGNORECASE,
        )
        raw = re.sub(
            r"(from\s+[\$€]?[\d.,]+\s*/?\s*)(\s+)((?:Memory|GPU)\s*\()",
            r"\1 | \3",
            raw,
            flags=re.IGNORECASE,
        )
        raw = re.sub(
            r"(/(?:\s*v\s*)?CPU-hr)(\s+)((?:Compute|Memory|GPU)\s*\()",
            r"\1 | \3",
            raw,
            flags=re.IGNORECASE,
        )
    return raw

def _rechunk_table_cells(cells: list[str], raw_text: str = "") -> list[list[str]]:
    cleaned = [re.sub(r"\s+", " ", str(c or "").strip()) for c in cells if str(c or "").strip()]
    if not cleaned:
        return []
    if len(cleaned) <= 6:
        return [cleaned]
    raw_l = str(raw_text or "").lower()
    header_region = raw_l[:400]
    wide_table_markers = ("sso", "hipaa", "audit", "pci", "private", "networking", "logging")
    has_wide_feature_cols = any(marker in header_region for marker in wide_table_markers)
    preferred: list[int] = []
    if re.search(r"\bv\s*cpu range\b", raw_l) and re.search(r"\bmemory range\b", raw_l):
        preferred.append(5)
    if re.search(r"\bmonthly platform fee\b", raw_l) or re.search(r"\bsupport response\b", raw_l):
        if has_wide_feature_cols:
            preferred.append(5)
        preferred.append(4)
    elif has_wide_feature_cols and re.search(r"\bplan\b", header_region):
        preferred.append(5)
    if re.search(r"\bfirst-response target\b", raw_l):
        preferred.append(4)
    col_candidates = preferred + [col for col in (5, 6, 4, 3) if col not in preferred]
    for col_count in col_candidates:
        if len(cleaned) == col_count:
            return [cleaned]
        if len(cleaned) > col_count and (len(cleaned) - col_count) % col_count == 0:
            header = cleaned[:col_count]
            body = [
                cleaned[col_count + idx: col_count + idx + col_count]
                for idx in range(0, len(cleaned) - col_count, col_count)
            ]
            if body and all(len(row[0]) <= 48 for row in body):
                return [header] + body
    return [cleaned]

def _needs_glued_table_normalization(text: str) -> bool:
    pipe_lines = [
        ln.strip()
        for ln in str(text or "").splitlines()
        if "|" in ln and ln.count("|") >= 2
    ]
    if len(pipe_lines) <= 1:
        combined = pipe_lines[0] if pipe_lines else str(text or "")
        return combined.count("|") >= 5
    return False

def _parse_pipe_table_rows(text: str) -> list[list[str]]:
    raw = str(text or "")
    normalized = _normalize_glued_inline_pipe_table(raw) if _needs_glued_table_normalization(raw) else raw
    line_candidates = [
        str(raw_line or "").strip()
        for raw_line in normalized.splitlines()
        if str(raw_line or "").strip() and not str(raw_line or "").strip().upper().startswith("[TABLE DATA]")
    ]
    pipe_lines = [ln for ln in line_candidates if "|" in ln and ln.count("|") >= 2]
    if len(pipe_lines) >= 2:
        simple_rows: list[list[str]] = []
        for line in pipe_lines:
            cells = [re.sub(r"\s+", " ", c).strip() for c in line.split("|") if c.strip()]
            if len(cells) >= 2:
                simple_rows.append(cells)
        if len(simple_rows) >= 2:
            widths = {len(row) for row in simple_rows}
            if len(widths) == 1 or (max(widths) - min(widths) <= 1):
                return simple_rows
    combined = pipe_lines[0] if len(pipe_lines) == 1 else " ".join(pipe_lines)
    if "|" in combined and combined.count("|") >= 5:
        cells = [re.sub(r"\s+", " ", c).strip() for c in combined.split("|") if c.strip()]
        rechunked = _rechunk_table_cells(cells, combined)
        if rechunked and len(rechunked) >= 2:
            return rechunked
    rows: list[list[str]] = []
    for line in pipe_lines:
        cells = [re.sub(r"\s+", " ", c).strip() for c in line.split("|") if c.strip()]
        if len(cells) >= 2:
            rows.append(cells)
    return rows

def _table_column_match_score(header: str, query_tokens: list[str]) -> float:
    header_l = re.sub(r"\s+", " ", str(header or "").strip().lower())
    if not header_l or not query_tokens:
        return 0.0
    header_tokens = set(re.findall(r"[a-z0-9]{2,}", header_l))
    hits = sum(1 for tok in query_tokens if tok in header_l or tok in header_tokens)
    synonym_groups = (
        ("monthly", "fee", "fees", "price", "cost", "pricing", "platform"),
        ("response", "time", "support", "sla", "target", "first"),
        ("memory", "ram", "gb", "range"),
        ("vcpu", "cpu", "core", "cores", "range"),
        ("audit", "logs", "logging"),
        ("networking", "network", "private"),
        ("compliance", "pci", "hipaa"),
        ("tam", "named"),
        ("sso", "sign"),
    )
    for group in synonym_groups:
        query_in_group = any(tok in group for tok in query_tokens)
        header_in_group = any(g in header_l or g in header_tokens for g in group)
        if query_in_group and header_in_group:
            hits += 1
    if hits <= 0:
        return 0.0
    return float(hits) / float(max(1, len(query_tokens)))

def _table_cell_is_affirmative(value: str) -> bool:
    val = re.sub(r"\s+", " ", str(value or "").strip().lower())
    if not val or val in {"no", "n/a", "na", "none", "-", "—", "not included", "not available"}:
        return False
    if val in {"yes", "included", "available", "supported", "true"}:
        return True
    if re.search(r"\b(?:yes|included|available|supported)\b", val):
        return True
    if _is_table_header_token(val):
        return False
    if re.search(r"\b(?:named|custom|dedicated|private|daily|hour|minute|business)\b", val):
        return True
    return False

def _format_reverse_lookup_labels(labels: list[str]) -> str:
    cleaned = [re.sub(r"\s+", " ", str(x or "").strip()) for x in labels if str(x or "").strip()]
    if not cleaned:
        return ""
    if len(cleaned) == 1:
        return cleaned[0]
    if len(cleaned) == 2:
        return f"{cleaned[0]} and {cleaned[1]}"
    return ", ".join(cleaned[:-1]) + f", and {cleaned[-1]}"

def _is_compact_table_answer(answer: str) -> bool:
    ans = str(answer or "").strip()
    if not ans:
        return False
    if ans.count("|") >= 2:
        return False
    pipe_rows = sum(
        1 for line in ans.splitlines()
        if "|" in line and line.count("|") >= 2
    )
    if pipe_rows >= 2:
        return False
    if len(ans) > 140 and pipe_rows >= 1:
        return False
    return True

def _table_row_entity_match_score(row_label: str, entity_phrases: list[str]) -> float:
    label_l = re.sub(r"\s+", " ", str(row_label or "").strip().lower())
    if not label_l:
        return 0.0
    head_tokens = _table_row_label_head_tokens(label_l)
    best = 0.0
    for phrase in entity_phrases or []:
        phrase_l = re.sub(r"\s+", " ", str(phrase or "").strip().lower())
        if not phrase_l:
            continue
        if phrase_l == label_l or phrase_l in label_l or label_l in phrase_l:
            best = max(best, 3.0)
        phrase_tokens = re.findall(r"[a-z0-9]{2,}", phrase_l)
        if phrase_tokens and all(re.search(rf"\b{re.escape(tok)}\b", label_l) for tok in phrase_tokens):
            best = max(best, 2.5)
        if head_tokens and phrase_l in head_tokens:
            best = max(best, 2.8)
        if head_tokens and all(re.search(rf"\b{re.escape(tok)}\b", phrase_l) for tok in head_tokens):
            best = max(best, 2.6)
    return best

def _table_numeric_value(cell: str) -> float | None:
    raw = str(cell or "").strip()
    if not raw:
        return None
    numbers: list[float] = []
    for match in re.findall(r"(\d+(?:\.\d+)?)", raw.replace(",", "")):
        try:
            numbers.append(float(match))
        except ValueError:
            continue
    if not numbers:
        return None
    if re.search(r"\d\s*-\s*\d", raw):
        return max(numbers)
    return numbers[0]

def _doc_retrieval_text(doc: dict | None) -> str:
    payload = doc or {}
    return str(
        payload.get("page_content")
        or payload.get("text")
        or payload.get("content")
        or payload.get("text_preview")
        or ""
    )

def _hydrate_route_docs(docs: list[dict]) -> list[dict]:
    hydrated: list[dict] = []
    for doc in docs or []:
        payload = dict(doc or {})
        text = _doc_retrieval_text(payload)
        if text:
            payload["page_content"] = text
        hydrated.append(payload)
    return hydrated

def _doc_text_fingerprint(text: str) -> str:
    return re.sub(r"\s+", " ", str(text or "").strip().lower()[:500])


def _resolve_enrichment_tenant_id(docs: list[dict]) -> int | None:
    for doc in docs or []:
        meta = dict((doc or {}).get("metadata") or {})
        try:
            return int(meta.get("tenant_id"))
        except (TypeError, ValueError):
            continue
    try:
        from backend.core.tenant_context import current_tenant_id

        tid = current_tenant_id()
        return int(tid) if tid is not None else None
    except Exception:
        return None


def _enrich_docs_with_collection_pipe_tables(docs: list[dict]) -> list[dict]:
    """Widen doc pool with tenant-scoped and collection pipe-table chunks (compare retry pattern)."""
    enriched: list[dict] = list(docs or [])
    seen_texts = {_doc_text_fingerprint(_doc_retrieval_text(d)) for d in enriched}
    tenant_id = _resolve_enrichment_tenant_id(docs)
    tenant_meta = {"chunk_role": "table"}
    if tenant_id is not None:
        tenant_meta["tenant_id"] = tenant_id
    for raw in _tenant_scoped_pipe_table_texts(docs):
        clean = _strip_repeated_kb_headings(raw)
        fp = _doc_text_fingerprint(clean)
        if clean and fp not in seen_texts:
            enriched.append({"page_content": clean, "text": clean, "metadata": dict(tenant_meta)})
            seen_texts.add(fp)
    for raw in _collection_pipe_table_chunks(tenant_id=tenant_id):
        clean = _strip_repeated_kb_headings(raw)
        fp = _doc_text_fingerprint(clean)
        if clean and fp not in seen_texts:
            enriched.append({"page_content": clean, "text": clean, "metadata": dict(tenant_meta)})
            seen_texts.add(fp)
    return enriched


def _collect_pipe_table_texts(docs: list[dict]) -> list[str]:
    texts: list[str] = []
    seen: set[str] = set()
    source_docs = list(docs or [])
    if not source_docs:
        source_docs = _enrich_docs_with_collection_pipe_tables([])
    for doc in source_docs:
        meta = dict((doc or {}).get("metadata") or {})
        raw = _doc_retrieval_text(doc).strip()
        if not raw:
            continue
        clean = _strip_repeated_kb_headings(raw)
        if _is_comparison_table_evidence(clean, meta) and clean not in seen:
            texts.append(clean)
            seen.add(clean)
    for raw in _tenant_scoped_pipe_table_texts(source_docs):
        clean = _strip_repeated_kb_headings(raw)
        if clean and clean not in seen and _is_comparison_table_evidence(clean, {}):
            texts.append(clean)
            seen.add(clean)
    if not texts:
        for doc in _enrich_docs_with_collection_pipe_tables(source_docs):
            raw = _doc_retrieval_text(doc).strip()
            if not raw:
                continue
            clean = _strip_repeated_kb_headings(raw)
            meta = dict((doc or {}).get("metadata") or {})
            if clean and clean not in seen and _is_comparison_table_evidence(clean, meta):
                texts.append(clean)
                seen.add(clean)
    return texts

def _table_header_fit_score(header: list[str], query_text: str, entity_phrases: list[str]) -> float:
    header_text = " ".join(str(h or "") for h in header).lower()
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    score = 0.0
    if entity_phrases and re.search(r"\bplan\b", header_text):
        if re.search(r"\b(?:monthly|platform|fee|pricing)\b", header_text):
            score += 3.0
        elif re.search(r"\b(?:channel|forum|hours)\b", header_text):
            score -= 1.5
        else:
            score += 1.0
    if re.search(r"\b(?:fee|fees|price|cost|monthly)\b", q) and re.search(r"\b(?:fee|fees|price|cost|monthly|platform)\b", header_text):
        score += 2.0
    if re.search(r"\b(?:response|time|support|sla)\b", q):
        if re.search(r"\bsupport response\b", header_text):
            score += 3.0
        elif re.search(r"\b(?:response|support|target|sla)\b", header_text):
            score += 1.0
    if re.search(r"\b(?:memory|vcpu|cpu|family|families)\b", q) and re.search(r"\b(?:memory|vcpu|cpu|family|range)\b", header_text):
        score += 2.0
    return score

def _extract_table_cell_answer(query_text: str, docs: list[dict]) -> str | None:
    """Generic pipe-table cell extraction: forward entity+attribute or reverse feature lookup."""
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return None
    focus_tokens = _table_fact_focus_tokens(query_text)
    entity_phrases = _table_fact_product_phrases(query_text)
    if not focus_tokens:
        return None

    reverse_lookup = bool(
        re.search(r"\bwhich\b", q)
        and re.search(r"\b(?:include|includes|support|supports|has|have|provides?|offer|offers|contain|contains)\b", q)
    )
    superlative_lookup = bool(re.search(r"\bwhich\b.*\b(?:best|most|highest|lowest|fastest|largest|smallest|maximum|minimum)\b", q))

    best_answer: str | None = None
    best_score = 0.0

    enriched_docs = _enrich_docs_with_collection_pipe_tables(list(docs or []))
    for table_text in _collect_pipe_table_texts(enriched_docs):
        rows = _parse_pipe_table_rows(table_text)
        if len(rows) < 2:
            continue
        header = rows[0]
        data_rows = rows[1:]
        table_bonus = _table_header_fit_score(header, query_text, entity_phrases)

        if (
            entity_phrases
            and not superlative_lookup
            and not any(
                _table_row_entity_match_score(re.sub(r"\s+", " ", str(row[0] or "")).strip(), entity_phrases) > 0
                for row in data_rows
                if row
            )
        ):
            continue
        if superlative_lookup and table_bonus < 1.5:
            continue
        if entity_phrases and re.search(r"\b(?:fee|fees|price|cost|monthly|response|time|support)\b", q) and table_bonus < 1.0:
            continue

        if superlative_lookup:
            superlative_terms = [
                tok
                for tok in focus_tokens
                if tok not in {"which", "family", "families", "plan", "plans", "best", "most", "has", "have", "the", "for", "largest", "smallest"}
            ]
            if re.search(r"\b(?:vcpu|cpu)\b", q):
                superlative_terms = [tok for tok in superlative_terms if tok not in {"memory", "ram", "gb"}]
            elif re.search(r"\bmemory\b|\bram\b", q):
                superlative_terms = [tok for tok in superlative_terms if tok not in {"vcpu", "cpu", "core", "cores", "vm"}]
            col_scores = [
                (idx, _table_column_match_score(header[idx], superlative_terms))
                for idx in range(1, len(header))
            ]
            col_scores = [
                (idx, score)
                for idx, score in col_scores
                if score > 0
                and any(
                    _table_numeric_value(row[idx]) is not None
                    for row in data_rows
                    if idx < len(row)
                )
            ]
            col_scores.sort(key=lambda item: item[1], reverse=True)
            if not col_scores:
                continue
            target_col = col_scores[0][0]
            direction = -1.0 if re.search(r"\b(?:lowest|least|smallest|minimum|cheapest)\b", q) else 1.0
            best_row_label = ""
            best_cell_value = ""
            best_metric = None
            for row in data_rows:
                if target_col >= len(row):
                    continue
                metric = _table_numeric_value(row[target_col])
                if metric is None:
                    continue
                if best_metric is None or (direction * metric) > (direction * best_metric):
                    best_metric = metric
                    best_row_label = re.sub(r"\s+", " ", row[0]).strip()
                    best_cell_value = re.sub(r"\s+", " ", row[target_col]).strip()
            if best_row_label and not _is_table_header_token(best_row_label):
                label = re.sub(r"\s+", " ", best_row_label).strip()
                if best_cell_value and not _is_table_header_token(best_cell_value):
                    return f"{label}, {best_cell_value}"
                return label

        if reverse_lookup:
            feature_tokens = [
                tok
                for tok in focus_tokens
                if tok not in {"which", "plan", "plans", "support", "supports", "include", "includes", "has", "have", "provides", "provide", "offer", "offers", "the", "a", "an", "named"}
            ]
            if re.search(r"\bnamed\b", q):
                feature_tokens.append("named")
            col_scores = [(idx, _table_column_match_score(header[idx], feature_tokens)) for idx in range(1, len(header))]
            col_scores.sort(key=lambda item: item[1], reverse=True)
            target_col = col_scores[0][0] if col_scores and col_scores[0][1] > 0 else None
            matching_labels: list[str] = []
            table_best_score = 0.0

            def _row_has_feature(row: list[str]) -> bool:
                row_text = " ".join(str(c or "") for c in row[1:]).lower()
                if not feature_tokens:
                    return False
                hits = sum(1 for tok in feature_tokens if tok in row_text)
                return hits >= max(1, min(len(feature_tokens), 2))

            for row in data_rows:
                if len(row) < 2:
                    continue
                row_label = re.sub(r"\s+", " ", row[0]).strip()
                if not row_label or _is_table_header_token(row_label):
                    continue
                affirmative = False
                score = 0.0
                if target_col is not None and target_col < len(row) and _table_cell_is_affirmative(row[target_col]):
                    affirmative = True
                    score = float(col_scores[0][1]) + 2.0
                elif _row_has_feature(row):
                    affirmative = True
                    score = 2.5 + sum(1 for tok in feature_tokens if tok in " ".join(row[1:]).lower())
                if not affirmative:
                    continue
                if score > table_best_score:
                    table_best_score = score
                    matching_labels = [row_label]
                elif abs(score - table_best_score) < 0.01 and row_label not in matching_labels:
                    matching_labels.append(row_label)
            if matching_labels:
                ordered_labels = [re.sub(r"\s+", " ", row[0]).strip() for row in data_rows if row and row[0]]
                if ordered_labels:
                    top_idx = min(
                        (ordered_labels.index(lbl) for lbl in matching_labels if lbl in ordered_labels),
                        default=-1,
                    )
                    if top_idx >= 0:
                        for inherited in ordered_labels[top_idx + 1:]:
                            if inherited and inherited not in matching_labels and not _is_table_header_token(inherited):
                                matching_labels.append(inherited)
                formatted = _format_reverse_lookup_labels(matching_labels)
                if formatted and table_best_score >= best_score:
                    best_score = table_best_score + table_bonus
                    best_answer = formatted
            continue

        attribute_tokens = [
            tok
            for tok in focus_tokens
            if tok not in {"what", "is", "the", "for", "of", "plan", "plans"}
        ]
        col_scores = [(idx, _table_column_match_score(header[idx], attribute_tokens or focus_tokens)) for idx in range(1, len(header))]
        col_scores.sort(key=lambda item: item[1], reverse=True)
        if not col_scores or col_scores[0][1] <= 0:
            continue
        target_col = col_scores[0][0]
        for row in data_rows:
            row_label = re.sub(r"\s+", " ", row[0]).strip()
            if not row_label:
                continue
            entity_score = _table_row_entity_match_score(row_label, entity_phrases)
            if entity_phrases and entity_score <= 0:
                continue
            if target_col >= len(row):
                continue
            cell_value = _sanitize_table_cell_value(re.sub(r"\s+", " ", row[target_col]).strip())
            if not cell_value or _is_table_header_token(cell_value):
                continue
            score = col_scores[0][1] + entity_score + (1.0 if entity_phrases else 0.0) + table_bonus
            if re.search(r"\bresponse\s+time\b", q) and len(cell_value) < 10:
                if not re.search(r"\b(?:hour|minute|day|business|chat|email|under|next)\b", cell_value.lower()):
                    score -= 3.0
            if re.search(r"\b(?:fee|fees|price|cost|monthly|annual)\b", q):
                if not re.search(r"[\$€£]|\b(?:custom|free)\b|\d", cell_value.lower()):
                    score -= 2.0
            if score > best_score:
                best_score = score
                best_answer = cell_value

    if best_answer:
        try:
            S.logger.info("[TABLE CELL EXTRACT] query=%s answer=%s score=%.2f", q[:120], best_answer[:120], best_score)
        except Exception:
            pass
    return best_answer

def _looks_like_table_blob_answer(answer: str) -> bool:
    ans = str(answer or "").strip()
    if not ans:
        return False
    if ans.count("|") >= 2:
        return True
    if "\n" in ans and "|" in ans:
        return True
    if re.search(r"\b(?:starter|growth|business|enterprise)\b", ans, flags=re.IGNORECASE) and ans.count("|") >= 1:
        return True
    return False

def _collapse_attribute_table_answer(query_text: str, answer: str, docs: list[dict]) -> str | None:
    """Re-extract compact plan labels or cell values from a table-shaped answer blob."""
    if not answer or not _looks_like_table_blob_answer(answer):
        return None
    blob_docs = list(docs or [])
    blob_docs.append({"page_content": str(answer), "metadata": {"chunk_role": "table"}})
    collapsed = _extract_table_cell_answer(query_text, blob_docs)
    return _accept_attribute_route_answer(query_text, collapsed)

def _extract_attribute_route_answer(query_text: str, docs: list[dict]) -> str | None:
    docs = _enrich_docs_with_collection_pipe_tables(list(docs or []))
    if not docs:
        return None
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    entity_phrases = _table_fact_product_phrases(query_text)
    reverse_lookup = bool(
        re.search(r"\bwhich\b", q)
        and re.search(r"\b(?:include|includes|support|supports|has|have|provides?|offer|offers|contain|contains)\b", q)
    )
    superlative_lookup = bool(
        re.search(r"\bwhich\b.*\b(?:best|most|highest|lowest|fastest|largest|smallest|maximum|minimum)\b", q)
    )
    prefer_cell_first = bool(entity_phrases or reverse_lookup or superlative_lookup)

    if prefer_cell_first:
        cell_answer = _accept_attribute_route_answer(query_text, _extract_table_cell_answer(query_text, docs))
        if cell_answer:
            return cell_answer

    if _is_numeric_fact_lookup_query(query_text) and not entity_phrases:
        table_answer = _accept_attribute_route_answer(query_text, _extract_table_fact_answer(query_text, docs))
        if table_answer:
            return table_answer

    cell_answer = _accept_attribute_route_answer(query_text, _extract_table_cell_answer(query_text, docs))
    if cell_answer:
        return cell_answer

    if _is_numeric_fact_lookup_query(query_text):
        table_answer = _accept_attribute_route_answer(query_text, _extract_table_fact_answer(query_text, docs))
        if table_answer:
            return table_answer
    if _is_metric_fact_query(query_text):
        metric_answer = _accept_attribute_route_answer(query_text, _extract_metric_fact_answer(query_text, docs))
        if metric_answer:
            return metric_answer
    if not superlative_lookup:
        fact_answer = _extract_fact_route_answer(query_text, docs)
        if fact_answer and _accept_attribute_route_answer(query_text, fact_answer):
            if _is_table_answer_grounded(fact_answer, docs):
                return fact_answer
    if _is_comparison_table_evidence(" ".join(_collect_pipe_table_texts(docs))):
        for table_text in _collect_pipe_table_texts(docs):
            retry_docs = list(docs) + [{"page_content": table_text, "metadata": {"chunk_role": "table"}}]
            retry = _accept_attribute_route_answer(query_text, _extract_table_cell_answer(query_text, retry_docs))
            if retry:
                return retry
    return None

def _is_table_answer_grounded(answer: str, docs: list[dict]) -> bool:
    ans = re.sub(r"\s+", " ", str(answer or "").strip().lower())
    if not ans:
        return False
    for table_text in _collect_pipe_table_texts(docs):
        for row in _parse_pipe_table_rows(table_text):
            for cell in row:
                cell_l = re.sub(r"\s+", " ", str(cell or "").strip().lower())
                if cell_l == ans or ans in cell_l or cell_l in ans:
                    return True
    return False

def _is_which_candidate_table_header(candidate: str, query_text: str, docs: list[dict]) -> bool:
    cand = re.sub(r"\s+", " ", str(candidate or "").strip())
    if not cand:
        return True
    if _is_table_header_token(cand):
        return True
    if len(cand.split()) <= 1 and cand.lower() in _TABLE_HEADER_TOKENS:
        return True
    if _is_table_answer_grounded(cand, docs):
        return False
    return _is_table_header_token(cand)

_TABLE_FACT_CURRENCY_RE = re.compile(
    r"(?:[\$€£]\s*)?(?:\d{1,3}(?:,\d{3})+|\d+)(?:\.\d{1,2})?(?:\s*(?:%|percent|per\s+depositor|per\s+account))?",
    re.IGNORECASE,
)

def _strip_repeated_kb_headings(text: str) -> str:
    """Repair common OCR/ingestion pollution before fact extraction.

    The Meridian-style chunks repeat a section heading (e.g. "7. Deposit
    Insurance", "1. About Meridian Financial Services") before every wrapped
    line, and glue "per" prepositions to the following word ("perdepositor").
    Both break sentence splitting and value capture. This repair is generic
    (no domain values) and only removes duplicate heading occurrences.
    """
    s = str(text or "")
    if not s.strip():
        return s
    # Repair glued "per X" prepositions seen in this corpus.
    s = re.sub(r"\bper(depositor|ownership|account|deposit|month|year|day)\b", r"per \1", s, flags=re.IGNORECASE)
    # Remove numbered section headings injected mid-sentence (surrounded by
    # lowercase context), e.g. "...per ownership 7. Deposit Insurance category".
    # A legitimate heading sits at a boundary, not glued between lowercase words.
    s = re.sub(
        r"(?<=[a-z,] )\d+\.\s+[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,4}\s+(?=[a-z])",
        "",
        s,
    )
    # Detect Title-Case / numbered section headings that repeat, and drop the
    # 2nd+ occurrences (they are injected mid-sentence by the chunker).
    heading_re = re.compile(r"(?:\d+\.\s+)?[A-Z][A-Za-z]+(?:[ &/,'\-]+[A-Z][A-Za-z]+){1,5}")
    counts: dict[str, int] = {}
    for m in heading_re.finditer(s):
        h = m.group(0).strip()
        counts[h] = counts.get(h, 0) + 1
    repeated = sorted([h for h, c in counts.items() if c >= 2], key=len, reverse=True)
    for h in repeated:
        parts = s.split(h)
        if len(parts) > 2:
            s = parts[0] + h + "".join(" " + p for p in parts[1:])
    # Collapse horizontal whitespace only — preserve newlines so table rows
    # stay on separate lines for downstream pipe-row parsing.
    s = re.sub(r"[ \t]+", " ", s)
    s = "\n".join(line.strip() for line in s.splitlines())
    return s.strip()

def _format_table_fact_answer(query_text: str, label: str, value: str) -> str:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    label_clean = re.sub(r"\s+", " ", str(label or "").strip())
    value_clean = re.sub(r"\s+", " ", str(value or "").strip())
    if "minimum balance" in q or ("minimum" in q and "balance" in q) or "min balance" in q:
        if label_clean:
            return f"{label_clean} requires a {value_clean} minimum balance."
        return f"The minimum balance requirement is {value_clean} minimum balance."
    if label_clean:
        return f"{label_clean}: {value_clean}."
    return value_clean

def _table_fact_product_phrases(query_text: str) -> list[str]:
    """Derive the entity/product phrase(s) a fact query is about, from the query
    itself — no hardcoded product or company names.

    Two generic signals are used:
      1. Phrases introduced by "for <X>" / "of <X>" before an attribute word
         (e.g. "minimum balance for everyday checking").
      2. Capitalized multi-word noun phrases in the original query, which almost
         always denote a named entity/product (e.g. "High-Yield Savings",
         "Money Market"). These are detected structurally (Title-Case runs),
         so any future document's entity names work the same way.
    """
    raw = str(query_text or "").strip()
    q = re.sub(r"\s+", " ", raw.lower())
    phrases: list[str] = []
    for pattern in (
        r"\bfor\s+([a-z][a-z0-9\s\-]{2,40}?)(?:\?|$|\s+(?:minimum|maximum|balance|fee|limit|coverage|response|time|support|monthly|annual))",
        r"\bof\s+([a-z][a-z0-9\s\-]{2,40}?)(?:\?|$|\s+(?:minimum|maximum|balance|fee|limit|coverage|response|time|support|monthly|annual))",
        r"\bfor\s+([a-z][a-z0-9\s\-]{1,40})\s*\?",
    ):
        match = re.search(pattern, q)
        if match:
            phrase = re.sub(r"\s+", " ", match.group(1).strip())
            if phrase and phrase not in phrases:
                phrases.append(phrase)
    # Capitalized multi-word noun phrases in the query are treated as candidate
    # entity names, derived purely from the user's wording (handles
    # "High-Yield Savings minimum balance?" for any corpus).
    for m in re.findall(r"\b[A-Z][A-Za-z]+(?:[\s\-][A-Z][A-Za-z]+)+\b", raw):
        ph = re.sub(r"\s+", " ", m.strip().lower())
        if ph and ph not in phrases:
            phrases.append(ph)
    for m in re.findall(r"\bfor\s+([A-Z][A-Za-z]+(?:[\s\-][A-Z][A-Za-z]+)*)\s*\?", raw):
        ph = re.sub(r"\s+", " ", m.strip().lower())
        if ph and ph not in phrases:
            phrases.append(ph)
    for m in re.findall(r"\bfor\s+([A-Z][a-z]+)\s*\?", raw):
        ph = re.sub(r"\s+", " ", m.strip().lower())
        if ph and ph not in phrases:
            phrases.append(ph)
    return [
        p
        for p in phrases
        if p and not re.match(r"^(?:which|what|how|when|where|who)\b", p)
    ]

def _table_fact_focus_tokens(query_text: str) -> list[str]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    stop = {
        "what", "is", "are", "the", "a", "an", "for", "of", "in", "to", "does", "do",
        "require", "requirement", "requirements", "tell", "me", "about", "please",
    }
    return [t for t in re.findall(r"[a-z0-9]{2,}", q) if t not in stop]

_MINBAL_HEADER_TOKENS = ("min. balance", "min balance", "minimum balance")

def _extract_minbalance_from_pipe_line(line: str, product_phrases: list[str]) -> str | None:
    """Read the min-balance value for a product from a `|`-delimited table row.

    Handles the real-corpus case where prose, the header row and the data row
    are concatenated on one physical line. Maps columns by header name so the
    correct currency cell (Min. balance) is returned rather than Monthly fee.
    """
    low = line.lower()
    if "|" in low and any(p in low for p in product_phrases) and any(h in low for h in _MINBAL_HEADER_TOKENS):
        cells = [c.strip() for c in line.split("|") if c.strip()]
        for cell in cells:
            cell_l = cell.lower()
            if any(h in cell_l for h in _MINBAL_HEADER_TOKENS):
                val_match = _TABLE_FACT_CURRENCY_RE.search(cell)
                if val_match:
                    return val_match.group(0)
    if "|" not in low or not any(h in low for h in _MINBAL_HEADER_TOKENS):
        return None
    if not any(p in low for p in product_phrases):
        return None
    cells = [c.strip() for c in line.split("|")]
    cells_l = [c.lower() for c in cells]

    # Locate the header columns (ordered) and the index of the min-balance col.
    account_col = monthly_col = minbal_col = None
    for i, cl in enumerate(cells_l):
        if account_col is None and "account" in cl:
            account_col = i
        if monthly_col is None and "monthly" in cl:
            monthly_col = i
        if minbal_col is None and any(h in cl for h in _MINBAL_HEADER_TOKENS):
            minbal_col = i
    if minbal_col is None or account_col is None:
        return None

    # Find the data cell that carries the product name (it may be glued into the
    # trailing header cell, e.g. "Highlights Everyday Checking").
    product_cell = None
    for i in range(account_col, len(cells_l)):
        if any(p in cells_l[i] for p in product_phrases):
            product_cell = i
            break
    if product_cell is None:
        return None

    # Values follow the product cell, one per header column after "account".
    value_cells = cells[product_cell + 1:]
    # Offset of min-balance among the value columns (account == product itself).
    offset = minbal_col - account_col - 1
    if offset < 0 or offset >= len(value_cells):
        return None
    val_match = _TABLE_FACT_CURRENCY_RE.search(value_cells[offset])
    if not val_match:
        return None
    return val_match.group(0)

_EVIDENCE_VALUE_PATTERNS: dict[str, re.Pattern] = {
    "per_period": re.compile(
        r"[\$€£]?\s?\d[\d,]*(?:\.\d{1,2})?\s*(?:/|per)\s*(?:day|month|year|week|hour)",
        re.IGNORECASE,
    ),
    "currency": re.compile(r"[\$€£]\s?\d[\d,]*(?:\.\d{1,2})?", re.IGNORECASE),
    "percent": re.compile(r"\d+(?:\.\d+)?\s?(?:%|percent)", re.IGNORECASE),
    "ratio": re.compile(r"\b\d+\.\d{2,}\b"),
    "number": re.compile(r"\b\d[\d,]*(?:\.\d+)?\b"),
}

_EVIDENCE_RANGE_VALUE_RE = re.compile(
    r"\b\d[\d,]*(?:\.\d+)?\s*[–-]\s*\d[\d,]*(?:\.\d+)?\b"
)

_EXPLANATORY_QUERY_PATTERNS: tuple[str, ...] = (
    r"\bwhy\b",
    r"\bhow\b",
    r"\bwhat happens\b",
    r"\bwill my\b",
    r"\bwhen will\b",
    r"\bhow long\b",
    r"\bare my\b",
    r"\bcan i\b",
    r"\bdo i\b",
    r"\bwhat are my options\b",
    r"\beligible\b",
    r"\bhandle\b",
)


def _query_needs_explanatory_answer(query_text: str) -> bool:
    """True when the user expects a process/policy explanation, not a bare metric."""
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if _is_support_procedural_query(q):
        return True
    return any(re.search(p, q) for p in _EXPLANATORY_QUERY_PATTERNS)


def _is_grounded_attribute_currency_value(query_text: str, answer: str) -> bool:
    if not _is_attribute_lookup_query(query_text):
        return False
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not re.search(r"\b(?:fee|fees|price|cost|monthly|annual)\b", q):
        return False
    stripped = re.sub(r"\s+", " ", str(answer or "").strip()).strip("|").strip()
    if re.fullmatch(r"[\$€£]\s?\d[\d,]*(?:\.\d{1,2})?\.?", stripped):
        return True
    if re.fullmatch(r"(?i)(?:custom|free|included|n/a|na)", stripped):
        return True
    return False

def _is_evidence_fragment_answer(query_text: str, answer: str) -> bool:
    """Reject bare numbers/currency or truncated rows unfit as user-facing answers."""
    ans = re.sub(r"\s+", " ", str(answer or "").strip())
    if not ans:
        return True
    if _is_grounded_attribute_currency_value(query_text, ans):
        return False
    stripped = ans.strip("|").strip()
    if re.fullmatch(r"\d[\d,]*(?:\.\d+)?\.?", stripped):
        return True
    if re.fullmatch(r"[\$€£]\s?\d[\d,]*(?:\.\d{1,2})?\.?", stripped):
        return True
    if len(stripped) <= 8 and not re.search(r"\b(?:yes|no|free)\b", stripped, re.IGNORECASE):
        return True
    if re.search(r"\bLine of$", stripped, re.IGNORECASE):
        return True
    q_support = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if _is_support_procedural_query(q_support) and re.search(r"\b(?:policy|refund|return|cancellation|cancel)\b", q_support):
        if len(stripped) >= 20 and re.search(
            r"\b(?:refund|credit|return|cancel|eligible|day|days|within|policy|fee|charge)\b",
            stripped,
            re.IGNORECASE,
        ):
            return False
    if (
        _query_needs_explanatory_answer(query_text)
        and len(stripped) < 40
        and not _is_attribute_lookup_query(query_text)
    ):
        return True
    if _query_needs_explanatory_answer(query_text) and len(stripped) > 50:
        list_markers = stripped.count(" - ") + stripped.count(";")
        if list_markers >= 2 and not re.search(
            r"\b(?:lock|report|dispute|restrict|verify|investigation|provisional|acknowledge|business day|forgot password|step)\b",
            stripped,
            re.IGNORECASE,
        ):
            return True
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if re.search(r"\bwhat happens\b", q) and re.search(r"\boverdraft\b", stripped, re.IGNORECASE):
        if not re.search(r"\b(?:declin|coverage|optional|exceed|balance)\b", stripped, re.IGNORECASE):
            return True
    if re.search(r"\bbusiness\b", q) and re.search(r"\bpersonal loan", stripped, re.IGNORECASE):
        if "business" not in stripped.lower():
            return True
    if _query_needs_explanatory_answer(query_text) and ";" in stripped and stripped.count(" - ") >= 1:
        if not re.search(r"\b(?:lock|report|dispute|restrict|investigation|provisional)\b", stripped, re.IGNORECASE):
            return True
    return False


def _accept_attribute_route_answer(query_text: str, answer: str | None) -> str | None:
    """Return answer only when it is a grounded compact cell/value, not a user-facing fragment."""
    if not answer or not _is_compact_table_answer(answer):
        return None
    if _is_evidence_fragment_answer(query_text, answer):
        return None
    return answer

_EVIDENCE_STOPWORDS: frozenset[str] = frozenset({
    "what", "which", "who", "whom", "whose", "when", "where", "why", "how",
    "the", "and", "for", "are", "was", "were", "does", "did", "has", "have",
    "with", "that", "this", "from", "about", "tell", "give", "show", "please",
    "exact", "much", "many", "value", "amount", "there", "your", "their", "its",
})

def _evidence_value_types_for_query(query_text: str) -> list[str]:
    """Pick the numeric shape(s) the question is asking for, from its wording."""
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    types: list[str] = []
    if re.search(r"\b(?:per\s+day|/\s*day|daily|per\s+month|monthly|per\s+year|annual)\b", q) and re.search(
        r"\b(?:limit|max|maximum|cap|transfer|allowance)\b", q
    ):
        types.append("per_period")
    if re.search(
        r"\b(?:fee|fees|price|cost|charge|balance|minimum|maximum|coverage|limit|amount|deposit|insured|insurance|premium|payment|salary|budget)\b",
        q,
    ):
        types.append("currency")
    if re.search(r"\b(?:rate|percentage|percent|apr|apy|yield|interest|discount)\b", q):
        types.append("percent")
    if re.search(r"\b(?:score|auc|ratio|coefficient|accuracy|precision|recall|index|threshold|probability)\b", q):
        types.extend(["ratio", "percent"])
    seen: set[str] = set()
    ordered = [t for t in types if not (t in seen or seen.add(t))]
    return ordered or ["currency", "percent", "ratio", "number"]

def _evidence_concept_tokens(query_text: str) -> list[str]:
    """Content tokens that the answer sentence must overlap with."""
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    return [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in _EVIDENCE_STOPWORDS]

def _evidence_candidate_units(clean_text: str) -> list[str]:
    """Split a chunk into scoreable units: table rows first, then sentences."""
    units: list[str] = []
    for raw_line in str(clean_text or "").splitlines():
        line = raw_line.strip()
        if "|" in line and line.count("|") >= 1:
            units.append(line)
    for sent in re.split(r"(?<=[.!?])\s+|\n+", str(clean_text or "")):
        s = re.sub(r"\s+", " ", str(sent or "").strip())
        if s:
            units.append(s)
    return units

def _extract_evidence_value_sentence(
    query_text: str,
    clean_text: str,
    value_types: list[str] | None = None,
    require_value: bool = True,
    extra_concept_tokens: list[str] | None = None,
) -> str | None:
    """Generic, evidence-driven extractor.

    Returns the sentence/row from the retrieved chunk that (a) overlaps the
    query's concept tokens and (b) contains a number of the requested shape —
    returned *verbatim* from the source. It contains no product names, company
    names, dollar amounts, percentages or metrics of its own; everything in the
    answer comes from the document. Works for any PDF because matching is by
    query↔evidence overlap, not by known entities or known values.
    """
    concept = _evidence_concept_tokens(query_text)
    if extra_concept_tokens:
        concept = concept + [t for t in extra_concept_tokens if t and t not in concept]
    if not concept:
        return None
    vtypes = value_types or _evidence_value_types_for_query(query_text)
    pats = [_EVIDENCE_VALUE_PATTERNS[t] for t in vtypes if t in _EVIDENCE_VALUE_PATTERNS]

    best: str | None = None
    best_score = -1
    for unit in _evidence_candidate_units(clean_text):
        u_low = unit.lower()
        hits = sum(1 for tok in concept if tok in u_low)
        if hits == 0:
            continue
        value_text: str | None = None
        range_match = _EVIDENCE_RANGE_VALUE_RE.search(unit)
        if range_match:
            value_text = range_match.group(0)
        else:
            for pat in pats:
                mm = pat.search(unit)
                if mm:
                    value_text = mm.group(0)
                    break
        if require_value and not value_text:
            continue
        # Prefer high concept overlap and a present value; gently penalise very
        # long blobs so a focused row/sentence wins over a wall of prose.
        # Prefer full sentences over bare table cells for explanatory queries.
        unit_candidate = re.sub(r"\s+", " ", unit).strip().strip("|").strip()
        fragment_penalty = 8 if _is_evidence_fragment_answer(query_text, unit_candidate) else 0
        score = hits * 10 + (len(value_text) if value_text else 0) - min(len(unit) // 40, 4) - fragment_penalty
        if score > best_score:
            best_score = score
            best = unit
    if not best:
        return None
    answer = re.sub(r"\s+", " ", best).strip().strip("|").strip()
    if answer and not re.search(r"[.!?]$", answer):
        answer += "."
    if _is_evidence_fragment_answer(query_text, answer):
        return None
    return answer or None

def _tenant_scoped_pipe_table_texts(docs: list[dict]) -> list[str]:
    tenant_ids: set[int] = set()
    for doc in docs or []:
        meta = dict((doc or {}).get("metadata") or {})
        try:
            tenant_id = int(meta.get("tenant_id"))
        except (TypeError, ValueError):
            continue
        tenant_ids.add(tenant_id)
    resolved = _resolve_enrichment_tenant_id(docs)
    if resolved is not None:
        tenant_ids.add(resolved)
    if not tenant_ids:
        return []
    texts: list[str] = []
    try:
        from backend.knowledge_base import get_or_create_collection

        for tenant_id in sorted(tenant_ids):
            col = get_or_create_collection(allow_empty=True, tenant_id=tenant_id)
            if col is None:
                continue
            payload = col.get(include=["documents", "metadatas"]) or {}
            documents = payload.get("documents") or []
            for raw in documents:
                if "|" in str(raw or ""):
                    texts.append(str(raw or ""))
        return texts
    except Exception:
        return []

def _collection_pipe_table_chunks(tenant_id: int | None = None) -> list[str]:
    """Return collection chunk texts that contain a pipe table (`|`).

    When tenant_id is provided, read only that tenant's isolated collection.
    """
    try:
        from backend.knowledge_base import get_or_create_collection

        col = None
        if tenant_id is not None:
            col = get_or_create_collection(allow_empty=True, tenant_id=tenant_id)
        if col is None:
            try:
                rag = S._active_rag()
                col = getattr(getattr(rag, "vs", None), "collection", None)
            except Exception:
                col = None
        if col is None:
            col = get_or_create_collection()
        if col is None:
            return []
        data = col.get(include=["documents"]) or {}
        return [str(d or "") for d in (data.get("documents") or []) if "|" in str(d or "")]
    except Exception:
        return []

def _extract_table_fact_answer(query_text: str, docs: list[dict]) -> str | None:
    docs = _enrich_docs_with_collection_pipe_tables(list(docs or []))
    if not docs:
        return None
    focus_tokens = _table_fact_focus_tokens(query_text)
    if not focus_tokens:
        return None
    product_phrases = _table_fact_product_phrases(query_text)
    q_low = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    # The only concept-specific flag retained is "minimum balance", because it
    # selects a *generic* column-mapped table reader (no values, no products).
    is_minbal_query = ("minimum balance" in q_low) or ("min balance" in q_low) or ("minimum" in q_low and "balance" in q_low)
    is_value_lookup = _is_numeric_fact_lookup_query(query_text)

    if product_phrases:
        cell_answer = _extract_table_cell_answer(query_text, docs)
        if cell_answer and _is_compact_table_answer(cell_answer):
            return cell_answer

    # Pre-clean each doc once (repairs glued tokens + injected headings).
    cleaned_docs = []
    for d in docs:
        raw = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if raw.strip():
            cleaned_docs.append(_strip_repeated_kb_headings(raw))

    # Deterministic fallback: an authoritative table can be out-ranked in
    # retrieval by a strong prose chunk. For any numeric/value lookup, also
    # consult the active collection's pipe-table chunks so the correct
    # row/column value is available regardless of ranking. This is generic — it
    # is keyed on the query *asking for a value*, not on any domain term.
    if is_value_lookup:
        seen_clean = set(cleaned_docs)
        enrich_tid = _resolve_enrichment_tenant_id(docs)
        for raw in _collection_pipe_table_chunks(tenant_id=enrich_tid):
            clean_extra = _strip_repeated_kb_headings(raw)
            if clean_extra and clean_extra not in seen_clean:
                cleaned_docs.append(clean_extra)
                seen_clean.add(clean_extra)

    # --- Generic min-balance-by-entity path (column-mapped, no hardcoded names) ---
    if is_minbal_query and product_phrases:
        for clean in cleaned_docs:
            for line in clean.splitlines():
                val = _extract_minbalance_from_pipe_line(line, product_phrases)
                if val is not None:
                    label = product_phrases[0].title()
                    return _format_table_fact_answer(query_text, label, val)

    # --- Generic evidence-driven value path: read the value the query asks for
    #     straight from the matching sentence/row, for any concept or domain. ---
    has_pipe_tables = bool(_collect_pipe_table_texts(docs))
    if is_value_lookup and not has_pipe_tables:
        for clean in cleaned_docs:
            ev = _extract_evidence_value_sentence(query_text, clean, require_value=False)
            if ev and _is_compact_table_answer(ev):
                return ev

    best_answer: str | None = None
    best_score = 0

    for clean in cleaned_docs:
        text = clean

        for raw_line in text.splitlines():
            line = str(raw_line or "").strip()
            if not line or line.upper().startswith("[TABLE DATA]"):
                continue

            if "|" in line:
                cells = [c.strip() for c in line.split("|") if c.strip()]
                if len(cells) < 2:
                    continue
                row_text = " ".join(cells).lower()
                if product_phrases and not any(p in row_text for p in product_phrases):
                    continue
                hits = sum(1 for tok in focus_tokens if tok in row_text)
                if hits == 0:
                    continue
                # Choose a clean label: the cell that contains the product phrase,
                # not a long prose blob glued into cell[0].
                label_cell = cells[0]
                if product_phrases:
                    for c in cells:
                        if any(p in c.lower() for p in product_phrases):
                            label_cell = product_phrases[0].title()
                            break
                if len(str(label_cell)) > 60 and not product_phrases:
                    continue
                for cell in cells[1:]:
                    match = _TABLE_FACT_CURRENCY_RE.search(cell)
                    if not match:
                        continue
                    score = hits * 10 + len(match.group(0))
                    if product_phrases:
                        score += 50
                    if score > best_score:
                        best_score = score
                        best_answer = _format_table_fact_answer(query_text, label_cell, match.group(0))
                continue

            if ":" in line and not re.search(r"https?://", line, flags=re.IGNORECASE):
                label, _, value_part = line.partition(":")
                label = label.strip()
                value_part = value_part.strip()
                if not label or not value_part:
                    continue
                label_l = label.lower()
                value_l = value_part.lower()
                hits = sum(1 for tok in focus_tokens if tok in label_l or tok in value_l)
                match = _TABLE_FACT_CURRENCY_RE.search(value_part)
                if hits >= 1 and match:
                    score = hits * 8
                    if score > best_score:
                        best_score = score
                        best_answer = _format_table_fact_answer(query_text, label, match.group(0))

        for sent in re.split(r"(?<=[.!?])\s+|\n+", text):
            sent_clean = re.sub(r"\s+", " ", str(sent or "").strip())
            if not sent_clean:
                continue
            sent_l = sent_clean.lower()
            hits = sum(1 for tok in focus_tokens if tok in sent_l)
            if hits == 0:
                continue
            match = _TABLE_FACT_CURRENCY_RE.search(sent_clean)
            if not match:
                continue
            # Relevance is already enforced by query-token overlap (hits > 0);
            # no domain-keyword gate is applied, so this works for any corpus.
            score = hits * 5 + len(match.group(0))
            if score > best_score:
                best_score = score
                if not re.search(r"[.!?]$", sent_clean):
                    sent_clean += "."
                best_answer = sent_clean

    if not best_answer:
        return None
    try:
        if _is_answer_grounded_in_docs(best_answer, docs, query_text=query_text):
            return best_answer
    except Exception:
        return best_answer
    # Built directly from retrieved doc/table lines — accept when match score is strong.
    if best_score >= 5:
        return best_answer
    return None

def _detect_fact_query_type(query_text: str) -> str | None:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return None
    if _is_support_procedural_query(q):
        return None
    if _is_compare_query(q):
        return None
    if _is_targeted_list_question(q):
        return None
    has_who = bool(re.search(r"\bwho\b", q) or re.search(r"\bwho\s+(?:was|is|established|proposed|developed|founded|introduced)\b", q))
    has_when = bool(re.search(r"\b(?:when|in\s+what\s+year|what\s+year|which\s+year|on\s+what\s+date)\b", q))
    if has_who and has_when:
        return "who_when"
    if has_who:
        return "who"
    if has_when:
        return "when"
    if re.search(r"\bwhich\b", q):
        return "which"
    if re.search(r"\bwhere\b", q):
        return "where"
    if re.search(r"\bwhat was the\b", q) or re.search(r"\bwhat is the exact\b", q):
        return "which"
    if _is_metric_fact_query(q):
        return "which"
    if _is_numeric_fact_lookup_query(q):
        return "numeric"
    return None

def _build_strict_fact_system_prompt(fact_type: str | None, allow_multi_chunk: bool = False) -> str:
    if allow_multi_chunk:
        base_prompt = (
            "You are extracting factual answers using multiple pieces of context.\n\n"
            "The answer may require combining information from different parts.\n"
            "Answer ONLY using the provided context.\n\n"
            "Return ONLY the final answer:\n"
            "- For WHO → return only the person name\n"
            "- For WHEN → return only the year\n\n"
            "Do NOT explain.\n"
            "Do NOT add extra text.\n\n"
            "If the answer cannot be confidently derived:\n"
            "return exactly:\n"
            "Not found in the document."
        )
    else:
        base_prompt = (
            "You are extracting factual answers.\n\n"
            "Answer ONLY using the provided context.\n\n"
            "Return ONLY the final answer:\n"
            "- For WHO → return only the person name\n"
            "- For WHEN → return only the year\n\n"
            "Do NOT explain.\n"
            "Do NOT add extra text.\n\n"
            "If the answer is not clearly present:\n"
            "return exactly:\n"
            "Not found in the document."
        )
    if fact_type == "who":
        return base_prompt + "\n\nExpected output format: a person name only."
    if fact_type == "when":
        return base_prompt + "\n\nExpected output format: a 4-digit year only."
    if fact_type == "who_when":
        return base_prompt + "\n\nExpected output format: Person Name, 4-digit year."
    return base_prompt

def _infer_fact_context_mode_from_docs(docs: list[dict]) -> str:
    for d in (docs or []):
        mode = str((d or {}).get("_fact_context_mode") or "").strip().lower()
        if mode in {"strict_relation", "multi_chunk"}:
            return mode
    return "strict_relation"

def _extract_multichunk_who_candidate(query_text: str, docs: list[dict]) -> Optional[str]:
    q_raw = re.sub(r"\s+", " ", str(query_text or "").strip())
    q_low = q_raw.lower()
    if not q_low or ("model" not in q_low and not re.search(r"\b[A-Z]{2,}\b", q_raw)):
        return None

    subject_terms = _extract_relation_subject_terms(q_raw, "who")
    if not subject_terms:
        return None

    subject_doc_idxs: list[int] = []
    for idx, d in enumerate(docs or []):
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        low = txt.lower()
        if any(re.search(rf"\b{re.escape(tok)}\b", low) for tok in subject_terms):
            subject_doc_idxs.append(idx)

    if not subject_doc_idxs:
        return None

    def _normalize_name(name: str) -> str:
        parts = [p for p in re.findall(r"[A-Za-z]+", str(name or "")) if p]
        if len(parts) < 2:
            return ""
        bad_tokens = {
            "that", "this", "these", "those", "about", "other", "people", "objects", "events",
            "behaviors", "beliefs", "model", "models", "theory", "approach",
        }
        if any(p.lower() in bad_tokens for p in parts):
            return ""
        use = parts[:4]
        return " ".join(p.capitalize() for p in use)

    patterns = [
        re.compile(
            r"\b(?:developed|proposed|introduced|established|founded|created|coined)\s+by\s+([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){1,3})\b",
            flags=re.IGNORECASE,
        ),
        re.compile(
            r"\b([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){1,3})\b.{0,64}\b(?:developed|proposed|introduced|established|founded|created|coined)\b",
            flags=re.IGNORECASE,
        ),
    ]

    candidates: list[tuple[int, str]] = []
    for idx, d in enumerate(docs or []):
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not txt.strip():
            continue
        for pat in patterns:
            for m in pat.finditer(txt):
                name = _normalize_name(m.group(1) or "")
                if re.fullmatch(r"[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}", name):
                    candidates.append((idx, name))

    if not candidates:
        return None

    best_name = None
    best_distance = 10**9
    for c_idx, c_name in candidates:
        local_best = min(abs(c_idx - s_idx) for s_idx in subject_doc_idxs)
        if local_best < best_distance:
            best_distance = local_best
            best_name = c_name

    return best_name

def _normalize_validated_fact_answer(fact_type: str | None, answer_text: str) -> str:
    candidate = re.sub(r"\s+", " ", str(answer_text or "")).strip(" .,:;!?")
    if not candidate:
        return RAG_NO_MATCH_RESPONSE

    no_match_norm = re.sub(r"\s+", " ", str(RAG_NO_MATCH_RESPONSE or "")).strip(" .,:;!?").lower()
    if candidate.lower() == no_match_norm:
        return RAG_NO_MATCH_RESPONSE

    if fact_type == "who":
        if re.fullmatch(r"[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}", candidate):
            return candidate
        return RAG_NO_MATCH_RESPONSE

    if fact_type == "when":
        y = re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", candidate)
        return y.group(1) if y else RAG_NO_MATCH_RESPONSE

    if fact_type == "who_when":
        cleaned = re.sub(r"\b(?:\d\s+){3,}\d\b", lambda m: re.sub(r"\s+", "", m.group(0)), candidate)
        cleaned = re.sub(r"\s+", " ", cleaned).strip(" .,:;!?")
        year_match = re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", cleaned)
        if not year_match:
            return RAG_NO_MATCH_RESPONSE
        year = year_match.group(1)
        name_match = re.search(r"\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,2})\b", cleaned)
        if not name_match:
            return RAG_NO_MATCH_RESPONSE
        person = re.sub(r"\s+", " ", name_match.group(1)).strip(" .,:;!?")
        if not re.fullmatch(r"[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,2}", person):
            return RAG_NO_MATCH_RESPONSE
        return f"{person}, {year}"

    return candidate

def _build_compact_fact_context_docs(query_text: str, docs: list[dict], max_snippets: int = FACT_CONTEXT_MAX_SNIPPETS, max_chars: int = FACT_CONTEXT_MAX_CHARS) -> list[dict]:
    if not docs:
        return []

    q = re.sub(r"\s+", " ", str(query_text or "")).strip().lower()
    fact_type = _detect_fact_query_type(query_text)
    stop = {
        "what", "which", "who", "when", "where", "is", "was", "were", "the", "a", "an", "of", "in", "on", "at", "to", "for", "and", "or", "by", "it", "year",
    }
    q_terms = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in stop]
    if not q_terms:
        q_terms = [t for t in re.findall(r"[a-z0-9]{3,}", q)]

    candidates: list[tuple[float, str, dict]] = []
    for d in (docs or [])[:8]:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
        if not txt.strip():
            continue
        for sent in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if str(s or "").strip()]:
            if len(sent) < 20 or len(sent) > 280:
                continue
            low = sent.lower()
            token_hits = sum(1 for t in q_terms if re.search(rf"\b{re.escape(t)}\b", low))
            if token_hits <= 0:
                continue
            score = float(token_hits)
            if fact_type in {"who", "who_when"} and re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b", sent):
                score += 1.8
            if fact_type in {"when", "who_when"} and re.search(r"\b(1[5-9]\d{2}|20\d{2})\b", sent):
                score += 1.8
            if re.search(r"\b(?:established|founded|proposed|developed|introduced|created|coined)\b", low):
                score += 0.8
            candidates.append((score, sent, d))

    if not candidates:
        fallback_docs = []
        for d in (docs or [])[: max(1, min(2, max_snippets))]:
            raw = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not raw.strip():
                continue
            trimmed = raw[: min(320, max_chars)]
            d2 = dict(d or {})
            d2["page_content"] = trimmed
            d2["text"] = trimmed
            fallback_docs.append(d2)
        return fallback_docs

    candidates.sort(key=lambda x: x[0], reverse=True)
    selected: list[dict] = []
    seen_sent: set[str] = set()
    total_chars = 0
    for _score, sent, base_doc in candidates:
        norm = re.sub(r"\s+", " ", sent).strip().lower()
        if norm in seen_sent:
            continue
        if len(selected) >= max_snippets:
            break
        if total_chars + len(sent) > max_chars:
            break
        seen_sent.add(norm)
        total_chars += len(sent)
        d2 = dict(base_doc or {})
        d2["page_content"] = sent
        d2["text"] = sent
        selected.append(d2)

    return selected

def _extract_fact_from_context(query: str, context_chunks: List[str]) -> Optional[str]:
    fact_type = _detect_fact_query_type(query)

    def _is_compact_fact_answer(text: str) -> bool:
        if not fact_type:
            return False
        s = re.sub(r"\s+", " ", str(text or "")).strip(" .,:;!?\"'")
        if not s:
            return False

        person_like = bool(re.fullmatch(r"[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}", s))
        year_like = bool(re.fullmatch(r"(?:1[5-9]\d{2}|20\d{2})", s))
        date_like = bool(
            re.fullmatch(
                r"(?:jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+\d{1,2},?\s+\d{4}",
                s,
                flags=re.IGNORECASE,
            )
        )
        location_like = bool(re.fullmatch(r"[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,5}(?:,\s*[A-Z][A-Za-z]+)?", s))

        if fact_type == "when":
            return year_like or date_like
        if fact_type == "who":
            return person_like
        if fact_type == "who_when":
            return person_like and bool(re.search(r"\b(?:1[5-9]\d{2}|20\d{2})\b", s))
        if fact_type == "where":
            return location_like
        if fact_type == "which":
            return len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) <= 8 and not re.search(r"\b(?:is|are|was|were|means|refers|defines|describes)\b", s, flags=re.IGNORECASE)
        return False
    if not fact_type:
        return None

    q_low = re.sub(r"\s+", " ", str(query or "").strip().lower())
    is_who_when_query = fact_type == "who_when"
    subject_terms = _extract_relation_subject_terms(query, fact_type)
    query_terms = [t for t in re.findall(r"[a-z0-9]{3,}", q_low) if t not in {"what", "which", "who", "when", "where", "why", "how", "the", "a", "an", "of", "in", "on", "at", "to", "for", "from", "and", "or", "by", "it", "its", "is", "are", "was", "were", "year", "date", "time"}]

    person_token_pattern = r"(?:[A-Z][a-z]+|[A-Z]\.)"
    person_name_re = re.compile(rf"\b({person_token_pattern}(?:\s+{person_token_pattern}){{0,4}})\b")
    role_noun_pat = r"(?:found(?:er|ers)|co-?found(?:er|ers)|creator|originator|establisher|developer|inventor|discoverer|pioneer|architect)"
    role_noun_of_re = re.compile(rf"\b{role_noun_pat}\s+of\b", flags=re.IGNORECASE)
    verb_person_re = re.compile(
        rf"\b({person_token_pattern}(?:\s+{person_token_pattern}){{1,4}})(?:\s+in\s+[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){{0,2}})?\s+(?:has\s+)?(?:established|proposed|developed|founded|introduced|created|coined)\b"
    )
    passive_person_re = re.compile(
        rf"\b(?:established|proposed|developed|founded|introduced|created|coined)\s+by\s+({person_token_pattern}(?:\s+{person_token_pattern}){{1,4}})\b",
        flags=re.IGNORECASE,
    )
    father_re = re.compile(r"\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3})\s+(?:is\s+)?(?:considered\s+)?the\s+father\s+of\b", flags=re.IGNORECASE)
    year_re = re.compile(r"\b(1[5-9]\d{2}|20\d{2})\b")
    lifespan_re = re.compile(rf"\b({person_token_pattern}(?:\s+{person_token_pattern}){{0,3}})\s*[:(,]?\s*(?:1[5-9]\d{{2}}|20\d{{2}})\s*[-–]\s*(?:1[5-9]\d{{2}}|20\d{{2}})\b")
    date_re = re.compile(r"\b(?:on\s+)?((?:jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+\d{1,2},?\s+\d{4})\b", flags=re.IGNORECASE)
    where_re = re.compile(r"\b(?:in|at|from)\s+([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,4}(?:,\s*[A-Z][A-Za-z]+)?)\b")

    disallowed_name_tokens = {
        "Table", "Figure", "Chapter", "Unit", "Theory", "Model", "Approach", "Document", "Contents",
        "Germany", "England", "France", "Greek", "Greece", "Leipzig", "Brain", "Mind",
        "Known", "As", "Thought", "Copyright", "Virtual", "University", "Prevalent", "Models", "Observational", "Learning",
        "Introduction", "Lesson", "Given", "Schools", "School",
    }

    def _is_ocr_noisy(sentence: str) -> bool:
        s = str(sentence or "")
        if not s.strip():
            return True
        alnum = len(re.findall(r"[A-Za-z0-9]", s))
        junk = len(re.findall(r"[^A-Za-z0-9\s.,;:'\"()\-]", s))
        singletons = len(re.findall(r"\b[a-zA-Z]\b", s))
        if alnum <= 6:
            return True
        if junk > max(5, int(0.22 * max(1, len(s)))):
            return True
        if singletons >= 5:
            return True
        return False

    def _is_complete_sentence(sentence: str) -> bool:
        s = re.sub(r"\s+", " ", str(sentence or "")).strip()
        word_count = len(re.findall(r"\b\w+\b", s))
        if word_count < 4:
            return False
        if re.search(r"[.!?]$", s):
            return True
        return word_count >= 7

    def _keyword_overlap_score(sentence_low: str) -> float:
        if not query_terms:
            return 0.0
        hits = 0
        for tok in query_terms:
            if re.search(rf"\b{re.escape(tok)}\b", sentence_low):
                hits += 1
        return float(hits) / float(max(1, len(query_terms)))

    def _token_hit(sentence_low: str, tok: str) -> bool:
        if re.search(rf"\b{re.escape(tok)}\b", sentence_low):
            return True
        if len(tok) >= 5:
            root = re.escape(tok[:5])
            if re.search(rf"\b{root}[a-z]*\b", sentence_low):
                return True
        return False

    def _subject_hit_count(sentence_low: str) -> int:
        return sum(1 for tok in subject_terms if re.search(rf"\b{re.escape(tok)}\b", sentence_low))

    def _verb_hit_count(sentence_low: str) -> int:
        return sum(
            1
            for pat in (
                r"\bproposed\b",
                r"\bdeveloped\b",
                r"\bintroduced\b",
                r"\bestablished\b",
                r"\bfounded\b",
                r"\bcreated\b",
                r"\bcoined\b",
                r"\bconsidered\b",
                r"\bformed\b",
                r"\bstarted\b",
                r"\boriginated\b",
                r"\bemerged\b",
            )
            if re.search(pat, sentence_low)
        )

    relation_cue_re = re.compile(
        rf"\b(?:established|proposed|developed|founded|introduced|created|coined|formed|started|originated|emerged)\b|"
        rf"\b{role_noun_pat}\s+of\b|\bfather\s+of\b",
        flags=re.IGNORECASE,
    )

    def _relation_windows_from_overlong_sentence(sentence: str) -> List[str]:
        """Recover local attribution evidence from OCR run-ons without trusting the whole run."""
        s = re.sub(r"\s+", " ", str(sentence or "")).strip()
        if len(s) <= 360:
            return [s] if s else []

        windows: List[str] = []
        seen: set[str] = set()
        for m in relation_cue_re.finditer(s):
            start = max(0, m.start() - 140)
            end = min(len(s), m.end() + 190)
            window = s[start:end].strip(" ,;:-")
            if len(window) > 360:
                cue_mid = (m.start() + m.end()) // 2
                start = max(0, cue_mid - 170)
                end = min(len(s), start + 340)
                window = s[start:end].strip(" ,;:-")
            key = window.lower()
            if len(window) >= 8 and key not in seen:
                seen.add(key)
                windows.append(window)
                S.logger.info(
                    "[FACT OCR CLEANUP] action=runon_window cue=%s window=%s",
                    str(m.group(0) or "")[:80],
                    window[:220],
                )
        return windows

    def _cleanup_ocr_for_fact_text(raw_text: str) -> str:
        s = re.sub(r"\s+", " ", str(raw_text or "")).strip()
        if not s:
            return s

        # Join spaced digit runs like "1 8 7 9" -> "1879"
        s = re.sub(r"\b(?:\d\s+){3,}\d\b", lambda m: re.sub(r"\s+", "", m.group(0)), s)

        no_join_heads = {"In", "On", "At", "Of", "For", "And", "The", "A", "An", "Who", "When", "What", "Where"}
        no_join_tails = {"in", "of", "and", "by", "to", "for", "from", "the", "on", "at", "with", "as"}

        def _join_cap_split(m: re.Match) -> str:
            left = str(m.group(1) or "")
            right = str(m.group(2) or "")
            if left in no_join_heads:
                return f"{left} {right}"
            if right.lower() in no_join_tails:
                return f"{left} {right}"
            return f"{left}{right}"

        # Join OCR-split name fragments using capitalization shape only.
        s = re.sub(r"\b([A-Z][a-z]{1,4})\s+([a-z]{2,5})\b", _join_cap_split, s)
        # Join OCR-split surname fragments using capitalization shape only.
        s = re.sub(r"\b([A-Z])\s+([a-z]{2,5})\s+([a-z])\b", lambda m: f"{m.group(1)}{m.group(2)}{m.group(3)}", s)
        s = re.sub(r"\s+", " ", s).strip()
        return s

    def _normalize_person_name(name: str) -> str:
        parts = [p for p in re.findall(r"[A-Za-z]\.?(?:[A-Za-z]+)?", str(name or "")) if p]

        # Merge OCR-split fragments in names (generic, length-constrained)
        merged: List[str] = []
        i = 0
        while i < len(parts):
            tok = parts[i]
            if (
                i + 1 < len(parts)
                and tok[0].isupper()
                and tok[1:].islower()
                and len(tok) <= 4
                and parts[i + 1].islower()
                and 2 <= len(parts[i + 1]) <= 5
            ):
                combined = tok + parts[i + 1]
                i += 2
                if i < len(parts) and parts[i].islower() and len(parts[i]) == 1:
                    combined += parts[i]
                    i += 1
                merged.append(combined)
                continue
            if len(tok) == 1 and tok.islower() and merged:
                merged[-1] += tok
                i += 1
                continue
            merged.append(tok)
            i += 1

        parts = merged
        deduped: List[str] = []
        for p in parts:
            if not deduped or deduped[-1].lower() != p.lower():
                deduped.append(p)
        filtered = [w for w in deduped if _person_token_key(w).capitalize() not in disallowed_name_tokens]
        use = filtered if filtered else deduped
        use = _strip_person_descriptor_tokens(use)
        if len(use) > 3:
            use = use[:3]

        def _format_name_token(token: str) -> str:
            key = _person_token_key(token)
            if len(key) == 1:
                return f"{key.upper()}."
            return key.capitalize()

        return " ".join(_format_name_token(w) for w in use)

    def _person_candidate_rejection_reason(name: str) -> str | None:
        n = re.sub(r"\s+", " ", str(name or "")).strip(" .,:;!?")
        if not n:
            return "empty"
        parts = n.split()
        lowered = [_person_token_key(p) for p in parts]

        if len(parts) < 1 or len(parts) > 3:
            return "token_count"
        if len(parts) == 1 and len(_person_token_key(parts[0])) < 4:
            return "single_token_too_short"
        if not all(re.match(r"^(?:[A-Z][a-z]+|[A-Z]\.)$", p) for p in parts):
            return "name_shape"
        if any(_is_person_descriptor_token(p) for p in parts):
            return "descriptor_token"
        if any(re.search(r"(?:tion|ment|ness|ity|ism|ship|ance|ence)$", p) for p in lowered[:-1]):
            return "non_name_morphology"

        if any(p.capitalize() in disallowed_name_tokens for p in lowered):
            return "disallowed_token"

        header_or_title_words = {
            "emergence", "schools", "thought", "important", "terminology", "introduction", "overview", "summary",
            "chapter", "lesson", "table", "figure", "contents", "model", "theory", "approach", "state", "states",
        }
        function_words = {"of", "and", "the", "in", "on", "for", "to", "from", "by", "with", "as"}

        if any(t in function_words for t in lowered):
            return "function_word_in_name"
        if any(t in header_or_title_words for t in lowered):
            return "header_word"
        if len(set(lowered)) < len(lowered):
            return "repeated_tokens"

        return None

    def _is_valid_person_name(name: str) -> bool:
        return _person_candidate_rejection_reason(name) is None

    def _validate_candidate(ftype: str, candidate: str) -> bool:
        c = re.sub(r"\s+", " ", str(candidate or "")).strip(" .,:;!?")
        if not c:
            return False
        if ftype == "who":
            rejection_reason = _person_candidate_rejection_reason(c)
            if rejection_reason:
                S.logger.info("[FACT PERSON VALIDATOR] action=reject candidate=%s reason=%s", c, rejection_reason)
                return False
            return True
        if ftype == "when":
            return bool(re.fullmatch(r"(?:1[5-9]\d{2}|20\d{2})", c) or date_re.search(c))
        if ftype == "where":
            return bool(re.match(r"^[A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,5}(?:,\s*[A-Z][A-Za-z]+)?$", c))
        if ftype == "which":
            if len(re.findall(r"\w+", c)) < 1:
                return False
            if _is_ocr_noisy(c):
                return False
            if _is_table_header_token(c):
                S.logger.info("[FACT WHICH VALIDATOR] action=reject candidate=%s reason=table_header_token", c)
                return False
            return True
        return False

    def _validated_who_candidate_from_span(raw_name: str) -> tuple[str | None, bool]:
        raw = re.sub(r"\s+", " ", str(raw_name or "")).strip(" .,:;!?")
        if not raw:
            return None, False

        connector_tokens = {"is", "was", "were", "known", "as", "considered", "the", "formal"}
        raw_tokens = re.findall(r"[A-Za-z]\.?(?:[A-Za-z]+)?", raw)
        while raw_tokens and _person_token_key(raw_tokens[-1]) in connector_tokens:
            raw_tokens.pop()
        if raw_tokens:
            raw = " ".join(raw_tokens)

        normalized = _normalize_person_name(raw)
        if _validate_candidate("who", normalized):
            return normalized, False

        tokens = re.findall(person_token_pattern, raw)
        # OCR column bleed usually prefixes a valid name with unrelated title-case
        # words. Prefer a full three-token span first; the validator rejects
        # common non-name bleed-through such as table labels before accepting it.
        for width in (3, 2, 1):
            if len(tokens) < width:
                continue
            salvage = _normalize_person_name(" ".join(tokens[-width:]))
            if salvage == normalized:
                continue
            if _validate_candidate("who", salvage):
                S.logger.info("[FACT PERSON VALIDATOR] action=salvage raw=%s candidate=%s", raw[:160], salvage)
                return salvage, True
        return None, False

    def _candidate_adjacency_bonus(sentence: str, match: re.Match, salvaged: bool) -> float:
        low = str(sentence or "").lower()
        bonus = 0.0
        if lifespan_re.search(sentence):
            bonus += 0.6
        near_start = max(0, match.start() - 50)
        near_end = min(len(sentence), match.end() + 80)
        nearby = sentence[near_start:near_end].lower()
        if relation_cue_re.search(nearby):
            bonus += 0.4
        if salvaged:
            bonus += 0.2
        if role_noun_of_re.search(low):
            bonus += 0.2
        return bonus

    def _expand_single_token_person_from_evidence(candidate: str, source_chunks: List[str]) -> str:
        base = re.sub(r"\s+", " ", str(candidate or "")).strip(" .,:;!?")
        base_key = _person_token_key(base)
        if not base_key or len(base.split()) != 1:
            return base

        best = base
        best_width = 1
        span_re = re.compile(rf"\b({person_token_pattern}(?:\s+{person_token_pattern}){{1,4}})\b")
        for chunk in source_chunks:
            text = _cleanup_ocr_for_fact_text(str(chunk or ""))
            for m in span_re.finditer(text):
                raw = re.sub(r"\s+", " ", m.group(1) or "").strip(" .,:;!?")
                raw_tokens = re.findall(person_token_pattern, raw)
                same_surname_index = next(
                    (idx for idx, tok in enumerate(raw_tokens) if _person_token_key(tok) == base_key and idx > 0),
                    None,
                )
                if same_surname_index is None:
                    continue
                raw = " ".join(raw_tokens[max(0, same_surname_index - 3): same_surname_index + 1])
                near = text[max(0, m.start() - 220): min(len(text), m.end() + 220)]
                if subject_terms and not any(_token_hit(near.lower(), t) for t in subject_terms):
                    continue
                if not relation_cue_re.search(near):
                    continue
                expanded = _normalize_person_name(raw)
                if not _validate_candidate("who", expanded):
                    continue
                width = len(expanded.split())
                if width > best_width:
                    best = expanded
                    best_width = width
        if best != base:
            S.logger.info("[FACT PERSON VALIDATOR] action=expand_single_token raw=%s expanded=%s", base, best)
        return best

    chunks = [str(c or "") for c in (context_chunks or []) if str(c or "").strip()]
    S.logger.info("[FACT EXTRACTION] type=%s query=%s total_chunks=%s", fact_type, (query or "")[:180], len(chunks))
    if not chunks:
        return None

    candidates: List[Dict[str, Any]] = []
    for chunk_idx, chunk in enumerate(chunks):
        chunk_clean = _cleanup_ocr_for_fact_text(chunk)
        if chunk_clean != chunk:
            S.logger.info(
                "[FACT OCR CLEANUP] chunk=%s applied=True before=%s after=%s",
                chunk_idx,
                re.sub(r"\s+", " ", chunk)[:120],
                re.sub(r"\s+", " ", chunk_clean)[:120],
            )
        sentences = [s.strip() for s in re.split(r"(?<![A-Z]\.)(?<=[.!?])\s+|\n+", chunk_clean) if str(s or "").strip()]
        for sent in sentences:
            s = _cleanup_ocr_for_fact_text(sent)
            s = re.sub(r"\s+", " ", s).strip()
            if len(s) > 360:
                if fact_type in {"who", "who_when"}:
                    sentences.extend(_relation_windows_from_overlong_sentence(s))
                continue
            if len(s) < 8:
                continue
            if _is_ocr_noisy(s):
                continue
            sl = s.lower()
            overlap = _keyword_overlap_score(sl)
            completeness_bonus = 0.35 if _is_complete_sentence(s) else 0.0
            clarity_bonus = 0.3 if not _is_ocr_noisy(s) else -1.2

            if fact_type in {"who", "who_when"}:
                requires_attribution_verb = bool(re.search(r"\b(established|proposed|developed|founded|introduced|created|coined)\b", q_low))
                founder_query = bool(re.search(r"\bfounder\s+of\b", q_low))
                verb_hits = _verb_hit_count(sl)
                role_noun_hit = bool(role_noun_of_re.search(s)) or bool(re.search(r"\bfather\s+of\b", sl))
                if requires_attribution_verb and verb_hits == 0 and not role_noun_hit:
                    continue
                if requires_attribution_verb and subject_terms and _subject_hit_count(sl) == 0:
                    S.logger.info(
                        "[FACT PERSON VALIDATOR] action=reject_sentence reason=missing_relation_subject sentence=%s",
                        s[:220],
                    )
                    continue

                subject_alt = "|".join(re.escape(t) for t in subject_terms)
                who_patterns = [
                    verb_person_re,
                    passive_person_re,
                    re.compile(
                        rf"\b({person_token_pattern}(?:\s+{person_token_pattern}){{0,3}})\b(?:\s*(?:[:\-–—•,]|(?i:\bis\b|\bwas\b|\bwere\b|\bknown\s+as\b|\bconsidered\b|\bthe\b|\bformal\b|\bas\b))){{0,8}}\s+(?i:(?:the\s+)?(?:formal\s+)?\b{role_noun_pat}\b)",
                    ),
                    re.compile(
                        rf"(?i:\b{role_noun_pat}\s+of\b)[^.\n]{{0,100}}?[,;:]\s*(?i:(?:the\s+)?)({person_token_pattern}(?:\s+{person_token_pattern}){{0,3}})\b",
                    ),
                ]
                if subject_alt:
                    who_patterns.append(
                        re.compile(
                            rf"(?i:\b{role_noun_pat}\s+of\b)[^.\n]{{0,100}}(?i:\b(?:{subject_alt})\b)\s+({person_token_pattern}(?:\s+{person_token_pattern}){{0,3}})\b"
                        )
                    )
                who_patterns.append(
                    re.compile(
                        rf"\b({person_token_pattern}(?:\s+{person_token_pattern}){{0,3}})\s*[:(,]?\s*(?:1[5-9]\d{{2}}|20\d{{2}})\s*[-–]\s*(?:1[5-9]\d{{2}}|20\d{{2}})(?=[^.\n]{{0,180}}(?i:(?:\b{role_noun_pat}\b|\b(?:founded|established|proposed|developed|introduced|created|coined)\b)))",
                    )
                )
                for pat in who_patterns:
                    for m in pat.finditer(s):
                        cand_name, salvaged = _validated_who_candidate_from_span((m.group(1) or "").strip())
                        if cand_name:
                            adjacency_bonus = _candidate_adjacency_bonus(s, m, salvaged)
                            name_width_bonus = min(0.8, 0.25 * max(0, len(cand_name.split()) - 1))
                            candidates.append({
                                "type": "who",
                                "candidate": cand_name,
                                "score": 6.0 + (2.5 * _keyword_overlap_score(sl)) + (0.6 * float(_subject_hit_count(sl))) + (0.8 * float(verb_hits)) + completeness_bonus + clarity_bonus + adjacency_bonus + name_width_bonus,
                                "sentence": s,
                                "chunk_idx": chunk_idx,
                            })

            if fact_type in {"when", "who_when"}:
                subj_hits = _subject_hit_count(sl)
                verb_hits = _verb_hit_count(sl)
                years = [m.group(1) for m in year_re.finditer(s)]
                dates = [m.group(1) for m in date_re.finditer(s)]
                for y in years:
                    if not _validate_candidate("when", y):
                        continue
                    if re.search(r"\b\d{4}\s*[-–]\s*\d{4}\b", s) or re.search(r"\(\s*\d{4}\s*[-–]", s):
                        continue
                    score = 2.0 + (2.0 * overlap) + completeness_bonus + clarity_bonus + (1.1 * float(subj_hits))
                    score += 0.8 * float(verb_hits)
                    if "emerge" in q_low:
                        if re.search(r"\b(emerge|emerged|emergence|began|started)\b", sl):
                            score += 1.8
                        elif re.search(r"\b(founded|introduced|originated)\b", sl):
                            score += 0.7
                        else:
                            score -= 0.8
                    if re.search(r"\b(in|established|founded|founded\s+in|was\s+founded\s+in|emerged|happened)\b", sl):
                        score += 1.0
                    candidates.append({
                        "type": "when",
                        "candidate": y,
                        "score": float(score),
                        "sentence": s,
                        "chunk_idx": chunk_idx,
                    })
                for dt in dates:
                    c = re.sub(r"\s+", " ", dt).strip(" .")
                    if not _validate_candidate("when", c):
                        continue
                    score = 2.2 + (2.0 * overlap) + completeness_bonus + clarity_bonus
                    candidates.append({
                        "type": "when",
                        "candidate": c,
                        "score": float(score),
                        "sentence": s,
                        "chunk_idx": chunk_idx,
                    })

            elif fact_type == "where":
                for m in where_re.finditer(s):
                    loc = re.sub(r"\s+", " ", m.group(1)).strip(" .,:;!?")
                    if not _validate_candidate("where", loc):
                        continue
                    score = 1.9 + (2.0 * overlap) + completeness_bonus + clarity_bonus
                    candidates.append({
                        "type": "where",
                        "candidate": loc,
                        "score": float(score),
                        "sentence": s,
                        "chunk_idx": chunk_idx,
                    })

            elif fact_type == "which":
                which_entity_re = re.compile(r"\b([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,4}(?:\s+(?:theory|model|approach|school|method))?)\b")
                for m in which_entity_re.finditer(s):
                    ent = re.sub(r"\s+", " ", m.group(1)).strip(" .,:;!?")
                    if not _validate_candidate("which", ent):
                        continue
                    score = 1.4 + (2.4 * overlap) + completeness_bonus + clarity_bonus
                    if re.search(r"\b(theory|model|approach|school|method)\b", ent.lower()):
                        score += 0.9
                    candidates.append({
                        "type": "which",
                        "candidate": ent,
                        "score": float(score),
                        "sentence": s,
                        "chunk_idx": chunk_idx,
                    })

    if not candidates:
        S.logger.info("[FACT EXTRACTION] no_candidates type=%s query=%s", fact_type, (query or "")[:180])
        return None

    candidates.sort(key=lambda c: float(c.get("score") or 0.0), reverse=True)
    top_candidates = candidates[:6]
    S.logger.info("[FACT EXTRACTION] candidates_count=%s type=%s", len(candidates), fact_type)
    for idx, cand in enumerate(top_candidates, start=1):
        S.logger.info(
            "[FACT CANDIDATE] rank=%s type=%s chunk=%s score=%.3f candidate=%s sentence=%s",
            idx,
            cand.get("type"),
            cand.get("chunk_idx"),
            float(cand.get("score") or 0.0),
            str(cand.get("candidate") or "")[:120],
            str(cand.get("sentence") or "")[:220],
        )

    if fact_type == "who_when":
        who_best = next((c for c in top_candidates if c.get("type") == "who" and _validate_candidate("who", str(c.get("candidate") or ""))), None)
        when_best = next((c for c in top_candidates if c.get("type") == "when" and _validate_candidate("when", str(c.get("candidate") or ""))), None)
        if who_best and when_best:
            who_val = re.sub(r"\s+", " ", str(who_best.get("candidate") or "")).strip(" .,:;!?")
            when_val = re.sub(r"\s+", " ", str(when_best.get("candidate") or "")).strip(" .,:;!?")
            combined = f"{who_val}, {when_val}"
            S.logger.info(
                "[FACT DECISION] type=%s final=%s who_score=%.3f when_score=%.3f",
                fact_type,
                combined,
                float(who_best.get("score") or 0.0),
                float(when_best.get("score") or 0.0),
            )
            S.logger.info("[FACT ACCEPTED] value=%s", combined)
            return combined
        S.logger.info("[FACT EXTRACTION] best_candidate_rejected type=%s candidate=%s", fact_type, "missing_who_or_when")
        return None

    best = next((c for c in top_candidates if c.get("type") == fact_type), top_candidates[0])
    chosen = re.sub(r"\s+", " ", str(best.get("candidate") or "")).strip(" .,:;!?")
    if fact_type == "who":
        chosen = _expand_single_token_person_from_evidence(chosen, chunks)
    if not _validate_candidate(fact_type, chosen):
        S.logger.info("[FACT EXTRACTION] best_candidate_rejected type=%s candidate=%s", fact_type, chosen)
        return None

    S.logger.info("[FACT DECISION] type=%s final=%s score=%.3f chunk=%s", fact_type, chosen, float(best.get("score") or 0.0), best.get("chunk_idx"))
    S.logger.info("[FACT ACCEPTED] value=%s", chosen)
    return chosen

def _rewrite_query_for_retrieval(query_text: str) -> str:
    # Disabled: preserve original user query exactly (no rewriting/injection).
    return query_text

def _extract_confident_factual_answer(query_text: str, retrieved_docs: list[dict]) -> str | None:
    return None

def _has_english_keyword_overlap(query_text: str, retrieved_docs: list[dict]) -> bool:
    """Return True when there is partial lexical overlap between query and retrieved context."""
    if not query_text or not retrieved_docs:
        return False

    stopwords = {
        "what", "which", "who", "when", "where", "why", "how", "the", "this", "that", "these", "those",
        "is", "are", "was", "were", "be", "to", "of", "in", "on", "for", "and", "or", "with", "from",
        "a", "an", "do", "does", "did", "can", "could", "should", "would", "about", "main", "only",
        "list", "explain", "define", "tell", "me",
    }
    tokens = [t for t in re.findall(r"[a-zA-Z]{3,}", (query_text or "").lower()) if t not in stopwords]
    if not tokens:
        return True

    corpus = "\n".join(str((d or {}).get("text") or "") for d in retrieved_docs).lower()
    def _variants(tok: str) -> set[str]:
        roots = {tok}
        for suf in ("ing", "ed", "es", "s", "ly", "ment", "tion", "al", "ical", "y"):
            if tok.endswith(suf) and len(tok) - len(suf) >= 4:
                roots.add(tok[: -len(suf)])
        return {r for r in roots if len(r) >= 3}

    matched = 0
    for tok in tokens:
        variants = _variants(tok)
        found = False
        for var in variants:
            if re.search(rf"\b{re.escape(var)}[a-z]*\b", corpus):
                found = True
                break
        if found:
            matched += 1

    if len(tokens) <= 4:
        return matched >= 1
    return matched >= 2

def _passes_hybrid_relevance_gate(query_text: str, retrieved_docs: list[dict]) -> bool:
    """Hybrid relevance gate: allow context-driven intents; reject only clear misses."""
    if not retrieved_docs:
        return False
    if _is_overview_query(query_text):
        return _has_meaningful_context(retrieved_docs)
    if _query_requires_structure(query_text):
        return _docs_have_structure_markers(retrieved_docs) or _has_meaningful_context(retrieved_docs)
    max_sim = _max_doc_similarity(retrieved_docs)
    
    # If reranked, trust the top candidate more even if semantic similarity is lower
    # (CrossEncoder often pulls up good chunks with low initial vector similarity)
    has_rerank_score = any("rerank_score" in d for d in retrieved_docs)
    if has_rerank_score:
        top_score = retrieved_docs[0].get("rerank_score", -999)
        if top_score > 0.0:  # CrossEncoder score > 0 is generally a decent signal
            return True

    semantic_ok = max_sim >= RAG_HYBRID_SEMANTIC_THRESHOLD
    lexical_ok = _has_english_keyword_overlap(query_text, retrieved_docs)
    return semantic_ok or lexical_ok

def _max_doc_similarity(retrieved_docs: list[dict]) -> float:
    if not retrieved_docs:
        return 0.0
    sims = []
    for d in retrieved_docs:
        for key in ("similarity", "score", "final_score", "rerank_score", "reranker_score", "semantic_score_used"):
            sim = (d or {}).get(key)
            if sim is None:
                continue
            try:
                sims.append(float(sim))
            except Exception:
                continue
    return max(sims) if sims else 0.0

def _query_requires_structure(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    if S._looks_like_arabic_list_query(q):
        return True
    if re.search(r"\blist\b", q):
        return True
    if re.match(r"^\s*(?:what|which)\s+are\b", q):
        return True
    if re.search(r"\b(?:chapter|section|unit|module|lesson|table of contents|contents|topics)\b", q):
        return True
    return False

def _is_overview_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    overview_markers = (
        "what is this document about",
        "what is this book about",
        "document about",
        "book about",
        "tell me about",
        "explain",
        "overview",
        "summary",
        "summarize",
        "main ideas",
        "topics covered",
        "purpose of this document",
    )
    if any(m in q for m in overview_markers):
        return True
    corrected = _lightweight_spelling_correction(q)
    if corrected and corrected != q:
        return any(m in corrected for m in overview_markers)
    return False

def _is_force_overview_paragraph_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    force_markers = ("tell me about", "explain", "overview")
    if any(m in q for m in force_markers):
        return True
    corrected = _lightweight_spelling_correction(q)
    if corrected and corrected != q:
        return any(m in corrected for m in force_markers)
    return False

def _lightweight_spelling_correction(query_text: str, seed_docs: list[dict] | None = None) -> str:
    q = str(query_text or "")
    try:
        S.logger.info("[FLOW] entering _lightweight_spelling_correction")
        S.logger.info("[FLOW] query_before = %s", (q or "")[:400])
    except Exception:
        pass
    if not q.strip():
        return q

    query_core_vocab = {
        "what", "who", "define", "tell", "about", "explain", "overview", "summary",
        "chapter", "section", "list", "compare", "difference", "between", "process",
        "general", "meaning", "definition", "introduced", "known",
        "when", "year", "text", "document", "source", "context", "broad", "technical",
        "sense", "science", "art", "relationship", "function", "system",
    }

    preserve_short_terms = set()

    def _edit_distance_leq(word_a: str, word_b: str, cap: int = 2) -> int:
        if word_a == word_b:
            return 0
        la, lb = len(word_a), len(word_b)
        if abs(la - lb) > cap:
            return cap + 1
        prev = list(range(lb + 1))
        for i, ca in enumerate(word_a, start=1):
            cur = [i] + [0] * lb
            row_min = cur[0]
            for j, cb in enumerate(word_b, start=1):
                cost = 0 if ca == cb else 1
                cur[j] = min(
                    prev[j] + 1,
                    cur[j - 1] + 1,
                    prev[j - 1] + cost,
                )
                if cur[j] < row_min:
                    row_min = cur[j]
            if row_min > cap:
                return cap + 1
            prev = cur
        return prev[lb]

    def _build_dynamic_vocab() -> tuple[set[str], Dict[str, int], Dict[str, list[str]], Dict[str, str]]:
        vocab_counter: Counter = Counter()
        source_map: Dict[str, str] = {}
        for tok in query_core_vocab:
            vocab_counter[tok] += 1
            source_map[tok] = "query_terms"

        cached_payload = getattr(_lightweight_spelling_correction, "_doc_vocab_cache", None)
        cache_key = None

        try:
            active_mgr = S._active_rag()
            collection = getattr(getattr(active_mgr, "vs", None), "collection", None)
            if collection is not None:
                collection_name = str(getattr(collection, "name", "") or "")
                try:
                    collection_count = int(collection.count())
                except Exception:
                    collection_count = 0
                cache_key = (collection_name, collection_count)
                if isinstance(cached_payload, dict) and cached_payload.get("key") == cache_key:
                    doc_freq = cached_payload.get("freq") or {}
                    for tok, freq in doc_freq.items():
                        if isinstance(tok, str):
                            vocab_counter[tok] += int(freq or 0)
                            source_map.setdefault(tok, "document_vocab")
                else:
                    payload = collection.get(include=["documents", "metadatas"], limit=min(max(collection_count, 1), 1500))
                    docs_blob = payload.get("documents") if isinstance(payload, dict) else None
                    metas_blob = payload.get("metadatas") if isinstance(payload, dict) else None
                    docs: list[str] = []
                    if isinstance(docs_blob, list):
                        for entry in docs_blob:
                            if isinstance(entry, str):
                                docs.append(entry)
                            elif isinstance(entry, list):
                                docs.extend(str(x) for x in entry if isinstance(x, str))
                    if isinstance(metas_blob, list):
                        for meta in metas_blob:
                            if isinstance(meta, dict):
                                docs.append(" ".join(str(v) for v in meta.values() if isinstance(v, (str, int, float))))
                    doc_counter: Counter = Counter()
                    for doc in docs:
                        for tok in re.findall(r"[a-z]{4,22}", doc.lower()):
                            doc_counter[tok] += 1
                    for tok, freq in doc_counter.items():
                        vocab_counter[tok] += freq
                        source_map.setdefault(tok, "document_vocab")
                    try:
                        setattr(_lightweight_spelling_correction, "_doc_vocab_cache", {"key": cache_key, "freq": dict(doc_counter)})
                    except Exception:
                        pass
        except Exception:
            pass

        seed_tokens: set[str] = set()
        for d in (seed_docs or [])[:4]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")[:3000]
            for tok in re.findall(r"[a-z]{4,22}", txt.lower()):
                vocab_counter[tok] += 1
                source_map[tok] = "retrieved_terms"
                seed_tokens.add(tok)

        filtered_vocab = {
            tok for tok, freq in vocab_counter.items()
            if len(tok) >= 4 and (freq >= 2 or tok in query_core_vocab or tok in seed_tokens)
        }
        if not filtered_vocab:
            filtered_vocab = set(query_core_vocab)

        by_initial: Dict[str, list[str]] = defaultdict(list)
        for tok in filtered_vocab:
            by_initial[tok[0]].append(tok)
        return filtered_vocab, dict(vocab_counter), by_initial, source_map

    vocab, freq_map, by_initial, source_map = _build_dynamic_vocab()

    q_low = re.sub(r"\s+", " ", q.strip().lower())
    list_query_mode = bool(
        _is_targeted_list_question(q_low)
        or re.match(r"^\s*(?:what|which)\s+are\b", q_low)
    )

    correction_events: list[dict] = []
    blocked_events: list[dict] = []

    def _case_like(original: str, replacement: str) -> str:
        if original.isupper():
            return replacement.upper()
        if original[:1].isupper():
            return replacement.capitalize()
        return replacement

    def _is_inflection_only_variant(original: str, candidate: str) -> bool:
        original_low = str(original or "").lower()
        candidate_low = str(candidate or "").lower()
        if len(original_low) < 4 or len(candidate_low) < 4 or original_low == candidate_low:
            return False
        direct_variants = {
            original_low + "s",
            original_low + "es",
            original_low + "d",
            original_low + "ed",
            original_low + "ing",
        }
        if original_low.endswith("e"):
            direct_variants.add(original_low[:-1] + "ing")
        if candidate_low in direct_variants:
            return True
        for suffix in ("ing", "ed", "es", "s", "d"):
            if candidate_low.endswith(suffix):
                stem = candidate_low[:-len(suffix)]
                if stem == original_low:
                    return True
                if suffix in {"d", "ed", "ing"} and stem + "e" == original_low:
                    return True
        # Reverse direction: original is an inflection of candidate (e.g. "ordered"→"order")
        for suffix in ("ing", "ed", "es", "s", "d"):
            if original_low.endswith(suffix):
                stem = original_low[:-len(suffix)]
                if stem == candidate_low:
                    return True
                if suffix in {"d", "ed", "ing"} and stem + "e" == candidate_low:
                    return True
        return False

    def _token_has_suspicious_typo_shape(value: str) -> bool:
        low_value = str(value or "").lower()
        if not low_value:
            return False
        if re.search(r"([a-z])\1{2,}", low_value):
            return True
        if len(low_value) >= 5 and not re.search(r"[aeiouy]", low_value):
            return True
        if re.search(r"[bcdfghjklmnpqrstvwxyz]{6,}", low_value):
            return True
        if re.search(r"(?:rn|vv|cl){2,}", low_value):
            return True
        return False

    def _looks_like_valid_english_token(value: str) -> bool:
        low_value = re.sub(r"[^a-z]+", "", str(value or "").lower())
        if not low_value:
            return False
        if low_value in query_core_vocab:
            return True
        if low_value in vocab:
            return True
        if len(low_value) < 4:
            return False
        if _token_has_suspicious_typo_shape(low_value):
            return False
        if not re.search(r"[aeiouy]", low_value):
            return False
        return True

    def _record_block(reason: str, original: str, candidate: str, confidence: float) -> None:
        if len(blocked_events) >= 3:
            return
        blocked_events.append({
            "reason": reason,
            "before": original,
            "after": candidate,
            "confidence": confidence,
        })

    def _replace_token(m: re.Match) -> str:
        token = m.group(0)
        low = token.lower()
        if token.isupper() and len(token) >= 3:
            return token
        if list_query_mode and len(low) >= 5 and low.endswith("s"):
            return token
        if low in preserve_short_terms:
            return token
        if len(low) < 4 or low in query_core_vocab:
            return token
        low_freq = int(freq_map.get(low, 0) or 0)
        if low in vocab and low_freq >= 2:
            return token
        if low in vocab and low_freq >= 1 and not _token_has_suspicious_typo_shape(low):
            return token
        # Pronouns, auxiliaries, conjunctions, and common function words must never be corrected
        # to a superficially similar document-vocab word (e.g. "they"→"that", "were"→"where").
        _PROTECTED = frozenset({
            "they", "them", "their", "these", "those", "then", "than",
            "this", "that", "with", "have", "from", "will", "were", "been",
            "when", "what", "which", "who", "how", "its", "your", "our",
            "you", "the", "and", "but", "for", "not", "are", "was",
            "can", "may", "might", "should", "would", "could", "must",
            "does", "did", "has", "had", "being", "also", "more",
            "into", "over", "under", "about", "other", "some", "such",
            "each", "both", "many", "much", "same", "very", "just",
        })
        if low in _PROTECTED:
            return token
        try:
            from backend.spelling_fallback import _COMMON_ENGLISH_WORDS as _dict_words_guard
            if low in _dict_words_guard:
                return token
        except Exception:
            pass

        candidates = [
            cand for cand in vocab
            if cand and cand[0] == low[0] and abs(len(cand) - len(low)) <= 2
        ]
        if not candidates:
            candidates = [cand for cand in by_initial.get(low[0], []) if abs(len(cand) - len(low)) <= 2]
        if not candidates:
            from backend.spelling_fallback import _COMMON_ENGLISH_WORDS

            candidates = [
                w
                for w in _COMMON_ENGLISH_WORDS
                if w and w[0] == low[0] and abs(len(w) - len(low)) <= 2
            ][:40]
        if not candidates:
            return token

        best = token
        best_dist = 3
        best_freq = -1
        second_best_freq = -1
        for cand in candidates:
            if cand == low:
                continue
            dist = _edit_distance_leq(low, cand, cap=2)
            if dist > 2:
                continue
            cand_freq = int(freq_map.get(cand, 0))
            if cand_freq == 0:
                try:
                    from backend.spelling_fallback import _COMMON_ENGLISH_WORDS as _dict_words
                    if cand in _dict_words:
                        cand_freq = 1
                except Exception:
                    pass
            if dist < best_dist or (dist == best_dist and cand_freq > best_freq):
                if dist == best_dist:
                    second_best_freq = max(second_best_freq, best_freq)
                else:
                    second_best_freq = best_freq
                best = cand
                best_dist = dist
                best_freq = cand_freq
            elif cand_freq > second_best_freq:
                second_best_freq = cand_freq

        if best_dist > 2 or best == token:
            return token
        confidence = 1.0 if best_dist == 0 else max(0.85, 0.95 - (best_dist - 1) * 0.05)
        if _token_has_suspicious_typo_shape(low):
            confidence += 0.05
        if best_freq >= 8:
            confidence += 0.05
        elif best_freq >= 4:
            confidence += 0.03
        if low not in vocab and best_freq >= 2:
            confidence = min(0.99, confidence + 0.04)
        if second_best_freq >= best_freq and best_freq < 4:
            _record_block("ambiguous_candidate", token, best, confidence)
            return token
        min_confidence = 0.88 if low not in vocab else 0.92
        if confidence < min_confidence:
            _record_block("confidence_below_threshold", token, best, confidence)
            return token
        if low in vocab and best_freq < max(low_freq * 5, low_freq + 8):
            _record_block("original_seen_in_document_vocab", token, best, confidence)
            return token
        if _is_inflection_only_variant(low, best):
            _record_block("inflection_only_variant", token, best, confidence)
            return token
        if best.lower().startswith(low) and 0 < (len(best) - len(low)) <= 3:
            _record_block("suffix_extension_guard", token, best, confidence)
            return token
        if (
            _looks_like_valid_english_token(low)
            and _looks_like_valid_english_token(best)
            and low in vocab
            and low_freq >= 1
        ):
            _record_block("valid_word_semantic_change", token, best, confidence)
            return token
        if low not in vocab and best_freq < (1 if best_dist == 1 else 2):
            _record_block("no_kb_vocab_match", token, best, confidence)
            return token
        correction_events.append({
            "before": token,
            "after": best,
            "confidence": confidence,
            "source": source_map.get(best, "document_vocab"),
        })
        return _case_like(token, best)

    corrected = re.sub(r"\b[a-zA-Z]{2,}\b", _replace_token, q)
    corrected = re.sub(r"\s+", " ", corrected).strip()
    applied = bool(correction_events and corrected and corrected.strip().lower() != q.strip().lower())
    for event in correction_events:
        S.logger.info(
            "[SPELLING CORRECTION] before=%s after=%s confidence=%.2f source=%s",
            event["before"],
            event["after"],
            event["confidence"],
            event["source"],
        )
    if applied:
        max_confidence = max(float(event.get("confidence", 0.0) or 0.0) for event in correction_events)
        S.logger.info(
            "[SPELL SAFE] reason=%s confidence=%.2f original=%s corrected=%s applied=%s",
            "extreme_confidence_typo",
            max_confidence,
            q[:240],
            corrected[:240],
            True,
        )
    else:
        blocked = blocked_events[0] if blocked_events else {}
        S.logger.info(
            "[SPELL SAFE] reason=%s confidence=%.2f original=%s corrected=%s applied=%s",
            str(blocked.get("reason") or "no_safe_correction"),
            float(blocked.get("confidence", 0.0) or 0.0),
            q[:240],
            q[:240],
            False,
        )
    S.logger.info("[FLOW] query_after = %s", (corrected or "")[:400])
    return corrected if applied else q

def _spelling_correction_preserving_exact_terms(query_text: str, seed_docs: list[dict] | None = None) -> str:
    if S._extract_protected_exact_query_terms(query_text):
        S.logger.info("[EXACT ENTITY GUARD] spelling_correction_skipped=True query=%s", str(query_text or "")[:160])
        return query_text
    try:
        return _lightweight_spelling_correction(query_text, seed_docs=seed_docs)
    except Exception:
        return query_text

def _normalize_definition_query_before_retrieval(query_text: str) -> tuple[str, str]:
    """Lightweight pre-retrieval normalization for retrieval robustness.

    - Lowercase normalization
    - Fast typo correction (edit distance <= 2)
    Returns (normalized_query, corrected_entity_or_empty)
    """
    q_raw = str(query_text or "")
    S.logger.info("[FLOW] entering _normalize_definition_query_before_retrieval")
    S.logger.info("[FLOW] query_before = %s", (q_raw or "")[:400])
    q = re.sub(r"\s+", " ", q_raw).strip()
    if not q:
        return q_raw, ""

    symbolic_query, symbolic_concept = S._normalize_symbolic_count_letter_list_query_before_retrieval(q)
    if symbolic_query and symbolic_query.strip().lower() != q.strip().lower():
        S.logger.info("[SYMBOLIC LIST NORM] '%s' -> '%s'", q[:120], symbolic_query[:120])
        S.logger.info("[FLOW] query_after = %s", (symbolic_query or "")[:400])
        return symbolic_query, symbolic_concept

    meaning_match = None
    meaning_patterns = [
        r"^\s*what\s+is\s+meant\s+by\s+(.+?)\s*\??\s*$",
        r"^\s*what\s+is\s+meant\s+with\s+(.+?)\s*\??\s*$",
        r"^\s*what\s+is\s+the\s+meaning\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*meaning\s+of\s+(.+?)\s*\??\s*$",
        r"^\s*define\s+(.+?)\s*\??\s*$",
    ]
    for patt in meaning_patterns:
        meaning_match = re.match(patt, q, flags=re.IGNORECASE)
        if meaning_match:
            break

    if meaning_match:
        entity_raw = (meaning_match.group(1) or "").strip(" \t\n\r\"'`.,;:!?()[]{}")
        entity_l = entity_raw.lower()
        if not entity_l:
            return q, ""

        if S._extract_protected_exact_query_terms(entity_raw):
            S.logger.info("[EXACT ENTITY GUARD] definition_normalization_skipped=True entity=%s", entity_raw[:160])
            corrected_entity = entity_l
        else:
            corrected_entity = _spelling_correction_preserving_exact_terms(entity_l)
        corrected_entity = re.sub(r"\s+", " ", str(corrected_entity or "").strip().lower())
        if not corrected_entity:
            corrected_entity = entity_l
        concept_aliases = {}
        corrected_entity = concept_aliases.get(corrected_entity, corrected_entity)

        normalized_query = f"what is {corrected_entity}".strip()
        if q.endswith("?"):
            normalized_query = f"{normalized_query}?"

        S.logger.info("[FLOW] normalized_meaning_query = %s", (normalized_query or "")[:400])
        S.logger.info("[FLOW] query_after = %s", (normalized_query or "")[:400])
        S.logger.info("[FLOW] normalized_entity = %s", (corrected_entity or "")[:160])

        if corrected_entity != entity_l:
            return normalized_query, corrected_entity
        return normalized_query, ""

    starter_m = re.match(r"^\s*(what\s+is|define|who\s+is)\b\s*(.+?)\s*\??\s*$", q, flags=re.IGNORECASE)
    if not starter_m:
        return q, ""

    starter = (starter_m.group(1) or "").strip().lower()
    entity_raw = (starter_m.group(2) or "").strip(" \t\n\r\"'`.,;:!?()[]{}")
    entity_l = entity_raw.lower()
    if S._extract_protected_exact_query_terms(entity_raw):
        S.logger.info("[EXACT ENTITY GUARD] definition_normalization_skipped=True entity=%s", entity_raw[:160])
        corrected_entity = entity_l
    else:
        corrected_entity = _spelling_correction_preserving_exact_terms(entity_l)
    corrected_entity = re.sub(r"\s+", " ", str(corrected_entity or "").strip().lower())
    if not corrected_entity:
        corrected_entity = entity_l
    concept_aliases = {}
    corrected_entity = concept_aliases.get(corrected_entity, corrected_entity)

    normalized_query = f"{starter} {corrected_entity}".strip()
    if q.endswith("?"):
        normalized_query = f"{normalized_query}?"

    S.logger.info("[FLOW] query_after = %s", (normalized_query or "")[:400])
    S.logger.info("[FLOW] normalized_entity = %s", (corrected_entity or "")[:160])

    if corrected_entity != entity_l:
        return normalized_query, corrected_entity
    return normalized_query, ""

def _is_controlled_definition_entity_query(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    return q.startswith("what is") or q.startswith("define") or q.startswith("who is")

def _distance_threshold_for_query(query_text: str) -> float:
    base = float(RAG_STRICT_DISTANCE_THRESHOLD)
    if _is_overview_query(query_text):
        return max(base, 1.35)
    if _query_requires_structure(query_text):
        return max(base, 1.10)
    return max(base, 0.85)

def _overview_seed_query() -> str:
    return "document overview summary introduction table of contents units chapters key topics"

def _select_document_summary_coverage_docs(docs: list[dict], max_docs: int = 8) -> list[dict]:
    """Select representative evidence for document-level summaries.

    The selector uses generic structural metadata only. It preserves high-scoring
    evidence while reserving room for early pages, TOC/introduction roles, and
    distinct section/chapter coverage.
    """
    if not docs:
        return []
    limit = max(1, int(max_docs or 1))

    def _metadata(doc: dict) -> dict:
        return (doc or {}).get("metadata") or {}

    def _score(doc: dict) -> float:
        for key in ("rerank_score", "score", "similarity"):
            try:
                if (doc or {}).get(key) is not None:
                    return float((doc or {}).get(key) or 0.0)
            except Exception:
                continue
        return 0.0

    def _page(doc: dict) -> int | None:
        try:
            value = _metadata(doc).get("page")
            return int(value) if value is not None and str(value).strip() else None
        except Exception:
            return None

    def _coverage_key(doc: dict) -> tuple[str, str]:
        md = _metadata(doc)
        for key in ("chapter", "section", "title", "page"):
            value = str(md.get(key) or "").strip().lower()
            if value:
                return (key, value)
        return ("id", str((doc or {}).get("id") or id(doc)))

    def _structural_priority(doc: dict) -> float:
        md = _metadata(doc)
        text = str((doc or {}).get("page_content") or (doc or {}).get("text") or "").lower()
        role = str(md.get("chunk_role") or "").strip().lower()
        section_blob = " ".join(str(md.get(k) or "") for k in ("section", "title", "chapter")).lower()
        page = _page(doc)
        priority = 0.0
        if page is not None and 0 < page <= 3:
            priority += 6.0
        elif page is not None and 0 < page <= 10:
            priority += 3.0
        if role in {"toc", "introduction", "summary", "chapter_intro", "chapter_heading", "section_heading"}:
            priority += 7.0
        if "table of contents" in section_blob or "contents" in section_blob:
            priority += 6.0
        if "introduction" in section_blob or "overview" in section_blob or "learning objectives" in section_blob:
            priority += 5.0
        if re.search(r"\b(chapter|unit|lesson|section)\s+\d+", section_blob + " " + text[:300]):
            priority += 3.0
        return priority

    ranked = sorted(list(docs or []), key=lambda doc: (_structural_priority(doc), _score(doc)), reverse=True)
    selected: list[dict] = []
    seen_ids: set[str] = set()
    seen_coverage: set[tuple[str, str]] = set()

    def _add(doc: dict, *, allow_same_coverage: bool = False) -> bool:
        if len(selected) >= limit:
            return False
        doc_id = str((doc or {}).get("id") or id(doc))
        if doc_id in seen_ids:
            return False
        coverage = _coverage_key(doc)
        if not allow_same_coverage and coverage in seen_coverage:
            return False
        selected.append(doc)
        seen_ids.add(doc_id)
        seen_coverage.add(coverage)
        return True

    for doc in ranked:
        if _structural_priority(doc) > 0:
            _add(doc)
    for doc in sorted(list(docs or []), key=_score, reverse=True):
        _add(doc)
    for doc in sorted(list(docs or []), key=_score, reverse=True):
        _add(doc, allow_same_coverage=True)
    return selected[:limit]

def _rerank_document_summary_for_coverage(docs: list[dict]) -> list[dict]:
    """Coverage-oriented rerank for document-summary retrieval candidates."""
    return _select_document_summary_coverage_docs(list(docs or []), max_docs=len(docs or []))

def _has_meaningful_context(retrieved_docs: list[dict]) -> bool:
    if not retrieved_docs:
        return False
    for d in retrieved_docs:
        md = (d or {}).get("metadata") or {}
        txt = str((d or {}).get("text") or "").strip()
        non_trivial_text = len(re.findall(r"\w+", txt)) >= 25
        has_structural_meta = bool(str(md.get("chapter") or "").strip() or str(md.get("section") or "").strip() or str(md.get("title") or "").strip())
        if non_trivial_text or has_structural_meta:
            return True
    return False

def _is_low_quality_doc(doc: dict) -> bool:
    md = (doc or {}).get("metadata") or {}
    txt = str((doc or {}).get("text") or "")
    section = str(md.get("section") or "")
    title = str(md.get("title") or "")
    chapter = str(md.get("chapter") or "")
    txt_l = txt[:900].lower()
    hay = f"{section}\n{chapter}\n{txt_l}".lower()
    if re.search(r"\b(commentary|further\s+reading|references?|bibliograph(?:y|ies)|works\s+cited|connections?\s+see\s+the)\b", txt_l):
        return True
    if re.search(r"\b(commentary|further\s+reading|references?|bibliograph(?:y|ies)|works\s+cited|connections?\s+see\s+the)\b", str(title).lower()):
        if len(txt.split()) < 120:
            return True
    if re.search(r"\b(self[-\s]*published|createspace|isbn|openstax|index)\b", hay):
        has_structure = bool(re.search(r"\bchapter\s+\d+\b", hay)) or bool(re.search(r"\b\d+\.\d+\b", hay))
        if not has_structure and (len(txt.split()) < 45 and len(re.findall(r"\([12][0-9]{3}\)|\[[0-9]{1,3}\]|https?://", hay)) >= 4):
            return True
    return False

def _docs_have_structure_markers(retrieved_docs: list[dict]) -> bool:
    for doc in retrieved_docs or []:
        md = (doc or {}).get("metadata") or {}
        txt = str((doc or {}).get("text") or "")[:1200]
        section = str(md.get("section") or "")
        title = str(md.get("title") or "")
        chapter = str(md.get("chapter") or "")
        unit = str(md.get("unit") or "")
        hay = f"{section}\n{title}\n{chapter}\n{unit}\n{txt}"
        if re.search(r"\b(?:chapter|unit)\s+\d+\b", hay, flags=re.IGNORECASE):
            return True
        if re.search(r"\b\d+(?:\.\d+){1,3}\b", hay):
            return True
        if any(marker in hay.lower() for marker in ("table of contents", "contents", "key terms", "introduction", "summary")):
            return True
    return False

def _retrieval_context_is_reliable(query_text: str, retrieved_docs: list[dict]) -> bool:
    if not retrieved_docs:
        return False

    cleaned = [d for d in retrieved_docs if not _is_low_quality_doc(d)]
    if not cleaned:
        return False

    if not _has_meaningful_context(cleaned):
        return False

    max_sim = _max_doc_similarity(cleaned)
    lexical_ok = _has_english_keyword_overlap(query_text, cleaned)
    overview_q = _is_overview_query(query_text)
    structure_q = _query_requires_structure(query_text)

    # Structure-sensitive questions require structure signals in context.
    if structure_q and not _docs_have_structure_markers(cleaned):
        return False

    # Overview/purpose requests should pass when meaningful context exists.
    if overview_q:
        noisy_ratio = 1.0 - (len(cleaned) / max(1, len(retrieved_docs)))
        return noisy_ratio <= 0.85

    # For topical non-overview questions, lexical grounding stays the primary guard.
    if (not structure_q) and (not lexical_ok):
        if max_sim < 0.15:
            return False

    if max_sim < 0.12 and not lexical_ok:
        return False

    # If nearly all docs look noisy, reject before LLM to prevent hallucination.
    noisy_ratio = 1.0 - (len(cleaned) / max(1, len(retrieved_docs)))
    if noisy_ratio > 0.90: # Loosened from 0.85
        return False

    return True

def _normalize_context_entities(query: str, text: str) -> str:
    """Detect names in query and normalize fuzzy near-misses (OCR noise) in text to match exactly."""
    if not query or not text:
        return text
    
    # 1. Identify proper names from the raw query (Capitalized words)
    # Target multi-word names first (e.g., "Peter Drucker")
    query_entities = re.findall(r'\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+)+\b', query)
    if not query_entities:
        # Fallback to significant single names
        query_entities = [e for e in re.findall(r'\b[A-Z][a-z]{4,}\b', query) 
                          if e.lower() not in ["what", "which", "where", "when", "this", "that", "there"]]
    
    if not query_entities:
        return text

    from difflib import get_close_matches
    cleaned_text = text
    # Extract unique TitleCase words from context as candidates for normalization
    doc_words = set(re.findall(r'\b[A-Z][a-z]+\b', cleaned_text))
    
    for entity in query_entities:
        parts = entity.split()
        # Usually last name is the best anchor for OCR fixes
        anchor = parts[-1]
        
        # Find variants in document that are very close to our query name
        matches = get_close_matches(anchor, doc_words, n=3, cutoff=0.75)
        for m in matches:
            if m != anchor and len(m) >= 4:
                # Replace fuzzy variant with canonical anchor from query
                cleaned_text = re.sub(rf'\b{re.escape(m)}\b', anchor, cleaned_text)
                
    return cleaned_text

def _clean_ocr_artifacts(text: str) -> str:
    """Lightweight cleanup for common knowledge chunk OCR noise (merged words, line joins, junk)."""
    if not text:
        return text
    text = _repair_split_words(text)
    
    # 1. WHITESPACE: Normalize line joins and multiple spaces (very common in PDF columnar exports)
    text = re.sub(r'\r\n|\r', '\n', text)
    # Preserve basic line boundaries, collapse multiple blank lines
    lines = [l.strip() for l in text.splitlines()]

    # 2. Remove obvious boilerplate-ish lines (page headers/footers, urls, copyright)
    cleaned_lines = []
    for l in lines:
        if not l:
            continue
        low = l.lower()
        # page numbers or short digit-only footers
        if re.fullmatch(r'page\s*\d{1,4}', low) or re.fullmatch(r'\d{1,4}', low):
            continue
        if 'http://' in low or 'https://' in low or low.startswith('www.'):
            continue
        if 'copyright' in low or 'all rights reserved' in low:
            continue
        # very short lines that are unlikely to be meaningful headers
        if len(l) < 3:
            continue
        cleaned_lines.append(l)

    text = ' \n'.join(cleaned_lines)

    # 3. MERGED CAMELCASE: Split merged CamelCase: "ManagementPublished" -> "Management Published"
    text = re.sub(r'([a-z])([A-Z])', r'\1 \2', text)

    # 4. NOISE SUFFIXES: Separate common OCR-merged connectors (of, in, and, published, etc.)
    # P6: Removed domain-specific tokens (principles, management); kept only generic
    # function words and structural markers that apply across documents.
    merged_noise_suffixes = [
        'of', 'in', 'by', 'the', 'and', 'at', 'for', 'from', 'with', 'to',
        'published', 'about', 'chapter', 'unit'
    ]
    for suffix in merged_noise_suffixes:
        text = re.sub(fr'\b([A-Za-z]{{3,}})({re.escape(suffix)})\b', r'\1 \2', text, flags=re.IGNORECASE)

    # 5. OCR TOKEN REPAIR: Generic prefix/suffix repairs for common PDF spacing loss
    text, _prefix_split_changed = _split_safe_ocr_merged_prefix_words(text)
    text, _split_merge_changed = _followup_merge_safe_ocr_split_words(text)

    # 6. BROKEN TOKENS: Remove isolated noise letters usually seen in mis-spaced names or list headers
    text = re.sub(r'\b[A-Za-z]\b\s+([A-Z][a-z]+)', r'\1', text)

    # 7. COLLAPSE repeated adjacent phrases (e.g., "the the" or longer repeated spans)
    # Collapse simple word repeats
    text = re.sub(r'\b(\w+)(?:\s+\1){2,}\b', r'\1', text, flags=re.IGNORECASE)
    # Collapse longer repeated substring sequences (two-or-more repeats)
    text = re.sub(r'(\b[\w\s]{8,120}?\b)(?:\s+\1){1,}', r'\1', text, flags=re.IGNORECASE)

    # 8. REPEATED CHARS: Clean duplicated characters or punctuation (OCR artifacts)
    text = re.sub(r'([.,:;!?])\1+', r'\1', text)
    text = re.sub(r'([a-zA-Z])\1{3,}', r'\1', text)

    # 9. Normalize inner whitespace
    text = re.sub(r'\s+', ' ', text)

    return text.strip()

def _is_list_query(query: str) -> bool:
    return detect_query_intent(query) == "list"

def _is_list_or_process_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    if _is_targeted_list_question(q):
        return True
    if re.match(r"^\s*how\b", q):
        return True
    return False

def _is_compare_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    if _is_definition_comparison_query(q):
        return False
    return bool(
        re.search(r"\b(?:difference|differences|different|distinction)\b", q)
        or re.search(r"\b(?:compare|compared|comparison|contrast|contrasts)\b", q)
        or re.search(r"\b(?:differentiate|distinguish)\b", q)
        or re.search(r"\b(?:relationship|relation)\b.+\bbetween\b.+\band\b", q)
        or re.search(r"\bhow\s+(?:does|do|is|are)\b.+\brelat(?:e|es|ed)\b.+\b(?:to|with)\b", q)
        or re.search(r"^\s*(?:what\s+is|define|explain)\s+.+?\s+(?:and|;)\s+(?:what\s+is|define|explain)\s+.+", q)
        or re.search(r"\b(?:versus|vs\.?)\b", q)
        or re.search(r"\bbetween\b.+\band\b", q)
    )

def _is_strict_overview_query(query_text: str) -> bool:
    q = (query_text or "").strip().lower()
    if not q:
        return False
    markers = (
        "what does this document talk about",
        "what is this document about",
        "what is this book about",
        "main sections",
        "document talk about",
        "overview",
        "summary",
        "main ideas",
        "topics covered",
    )
    return any(m in q for m in markers)

def _is_safe_definition_fast_path_query(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if not (q.startswith("who is") or q.startswith("what is")):
        return False
    if _is_list_or_process_query(q):
        return False
    if _is_compare_query(q):
        return False
    if _is_strict_overview_query(q):
        return False
    if _classify_query_family(q) == "out_of_scope_candidate":
        return False
    return True

def _is_incomplete_fragment_sentence(sentence: str) -> bool:
    s = str(sentence or "").strip()
    if not s:
        return True
    if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) < 6:
        return True
    if re.match(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", s, flags=re.IGNORECASE):
        return True
    if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
        return True
    if not re.search(r"[.!?]$", s):
        return True
    return False

def _is_feature_only_definition_sentence(sentence: str) -> bool:
    s = re.sub(r"\s+", " ", str(sentence or "")).strip()
    if not s:
        return True
    low = s.lower()
    if ":" in s:
        return True
    if re.match(r"^\s*[a-z][a-z\-]*(?:\s+[a-z][a-z\-]*){0,4}\b", s):
        if len(re.findall(r"[a-z][a-z\-']*", low)) <= 14:
            return True
    aspect_terms = {
        "division", "hierarchy", "specialization", "specialisation", "authority",
        "responsibility", "rules", "procedures", "impersonality", "unity", "span", "control",
    }
    aspect_hits = [t for t in aspect_terms if re.search(rf"\b{re.escape(t)}\b", low)]
    has_definition_verb = bool(re.search(r"\b(is|refers to|defined as)\b", low))
    has_explanatory_verb = bool(re.search(r"\b(involves|focuses on|aims to|includes)\b", low))
    if len(aspect_hits) == 1 and (not has_definition_verb) and (not has_explanatory_verb):
        if len(re.findall(r"[a-z][a-z\-']*", low)) <= 14:
            return True
    return False

def _concept_specific_signal_terms(entity_l: str) -> List[str]:
    return []
    return []

def _has_required_concept_specific_signal(sentence: str, entity_l: str) -> bool:
    signals = _concept_specific_signal_terms(entity_l)
    if not signals:
        return True
    low = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
    if not low:
        return False
    for term in signals:
        term_re = re.escape(term).replace("\\ ", r"\\s+")
        if re.search(rf"\b{term_re}\b", low):
            return True
    return False

def _count_concept_specific_signals(sentence: str, entity_l: str) -> int:
    signals = _concept_specific_signal_terms(entity_l)
    if not signals:
        return 0
    low = re.sub(r"\s+", " ", str(sentence or "").strip().lower())
    if not low:
        return 0
    count = 0
    for term in signals:
        term_re = re.escape(term).replace("\\ ", r"\\s+")
        if re.search(rf"\b{term_re}\b", low):
            count += 1
    return count

def _is_over_generic_definition_template(sentence: str, entity_l: str) -> bool:
    # P3: Replaced hard-coded management-phrase blacklist with a generic, lexicon-free
    # "empty body" detector. A sentence is over-generic when it has a definition verb
    # but virtually no content after it once the entity itself and stopwords are removed.
    s = re.sub(r"\s+", " ", str(sentence or "").strip())
    if not s:
        return True
    low = s.lower()
    m = re.search(r"\b(?:is|was|refers\s+to|defined\s+as|means)\b", low)
    if not m:
        return False
    body = low[m.end():].strip(" .,:;!?\t")
    if entity_l:
        body = re.sub(rf"\b{re.escape(entity_l)}\b", " ", body)
    body_words = re.findall(r"[a-z][a-z\-']{2,}", body)
    generic_stop = {
        "a", "an", "the", "of", "to", "for", "in", "on", "at", "by", "with",
        "and", "or", "that", "this", "these", "those", "such", "kind", "type",
        "form", "way", "general", "various", "many", "some", "any",
    }
    content = [w for w in body_words if w not in generic_stop]
    if len(content) >= 3:
        return False
    if _has_required_concept_specific_signal(s, entity_l):
        return False
    return True

def _s_definition_sentence(sentence: str, entity_l: str, entity_tokens: List[str]) -> int:
    s = re.sub(r"\s+", " ", str(sentence or "")).strip()
    if not s:
        return -99
    low = s.lower()
    word_count = len(re.findall(r"[A-Za-z][A-Za-z\-']*", s))

    if re.match(r"^\s*(?:three\s+main|how\s+do\s+we\s+learn|basic\s+terminology|historical\s+background|introduction|overview|summary|contents?|table\s+of\s+contents|key\s+terms?)\b", low):
        return -99
    if re.match(r"^\s*[A-Z][A-Za-z0-9\s\-,:]{3,110}\s*$", s) and not re.search(r"[.!?]$", s):
        return -99

    if re.search(r"\b(this\s+course|students\s+will\s+learn|students\s+will|purpose\s+of\s+this\s+course|course\s+description|main\s+focus\s+is\s+to\s+help\s+students)\b", low):
        return -99

    if not re.search(r"[.!?]$", s):
        return -99

    def _ocr_noise_hits(txt: str) -> int:
        t = str(txt or "")
        hits = 0
        hits += len(re.findall(r"\b[a-z]\s+[a-z]\b", t.lower()))
        hits += len(re.findall(r"\bwil\s+helm\b|\bw\s*und\s*t\b|\bcont\s+rolling\b|\bbe\s+havior\b", t.lower()))
        hits += len(re.findall(r"(?:\b[A-Za-z]{1,2}\b\s+){3,}", t))
        return hits

    score = 0

    concept_clear = False
    if entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low):
        concept_clear = True
    elif entity_tokens:
        token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
        root_hits = 0
        for t in entity_tokens:
            if len(t) >= 6 and re.search(rf"\b{re.escape(t[:6])}[a-z]*\b", low):
                root_hits += 1
        need = max(1, min(2, len(entity_tokens)))
        concept_clear = token_hits >= need or root_hits >= need

    if concept_clear and re.search(r"\b(is|refers to|defined as|means|includes|involves|consists of|characterized by|focused\s+upon|focused\s+on|focuses\s+on|grew\s+out\s+of)\b", low):
        score += 3

    full_phrase_matches = len(re.findall(rf"\b{re.escape(entity_l)}\b", low)) if entity_l else 0
    if full_phrase_matches >= 1:
        score += 2
    if full_phrase_matches >= 2:
        score += 1

    if re.search(r"\b(involves|focuses on|aims to|includes|consists of|characterized by|grew\s+out\s+of)\b", low):
        score += 2

    specific_signal_count = _count_concept_specific_signals(s, entity_l)

    if not concept_clear and specific_signal_count < 2:
        score -= 2

    if not re.search(r"\b(is|refers to|defined as|means|involves|focuses on|focused\s+upon|focused\s+on|aims to|includes|consists of|characterized by|grew\s+out\s+of)\b", low):
        score -= 1

    has_def_verb = bool(re.search(r"\b(is|refers to|defined as|means|involves|includes|consists of|characterized by|forms an association|associates)\b", low))
    if (":" in s or ";" in s or "•" in s or "|" in s or len(re.findall(r",", s)) >= 2) and (not has_def_verb):
        score -= 9
    if re.search(r"[•ò]\s*[A-Za-z]", s):
        score -= 10

    if _is_feature_only_definition_sentence(s):
        score -= 3

    aspect_terms = {
        "division", "hierarchy", "specialization", "specialisation", "authority",
        "responsibility", "rules", "procedures", "impersonality", "unity", "span", "control",
    }
    aspect_hits = [t for t in aspect_terms if re.search(rf"\b{re.escape(t)}\b", low)]
    if len(aspect_hits) == 1 and not re.search(r"\b(is|refers to|defined as|involves|focuses on|aims to|includes)\b", low):
        score -= 3

    if _has_required_concept_specific_signal(s, entity_l):
        score += 3
    elif _concept_specific_signal_terms(entity_l):
        score -= 4
    if specific_signal_count >= 2:
        score += 2

    if _is_over_generic_definition_template(s, entity_l):
        score -= 8

    if defines_other_concept(low, entity_l):
        score -= 12

    if re.match(r"^\s*(he|she|they|it|this)\b", low):
        score -= 8

    if re.search(r"\b(known\s+as\s+the\s+born|biography|worked\s+as)\b", low):
        score -= 10

    rubric_score = 0
    if re.search(r"\b(is|refers to|defined as|means)\b", low):
        rubric_score += 3
    if entity_l and re.search(rf"^\s*(?:the\s+)?{re.escape(entity_l)}\s+(?:is|refers\s+to|defined\s+as|means)\b", low):
        rubric_score += 2
    elif entity_l and re.search(rf"^\s*(?:the\s+)?{re.escape(entity_l)}\b", low):
        rubric_score += 1

    ocr_hits = _ocr_noise_hits(s)
    if ocr_hits == 0:
        rubric_score += 2
    else:
        rubric_score -= 3

    if 8 <= word_count <= 24:
        rubric_score += 1
    elif word_count > 35:
        rubric_score -= 1

    if re.search(r"\b(this\s+course|students\s+will|course\s+description|objectives?)\b", low):
        rubric_score -= 2

    if not concept_clear:
        rubric_score -= 2

    score += rubric_score

    return score

def _extract_best_scored_concept_sentence_from_docs(query_text: str, docs: list[dict], max_docs: int = 3) -> str | None:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not (q.startswith("what is") or q.startswith("define")):
        return None

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not has_entity or not entity_l:
        return None

    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to", "is", "are"}
    ]

    reject_re = re.compile(
        r"\b(?:criticism|criticisms|limitations?|drawbacks?|table|figure|isbn|contents?)\b",
        flags=re.IGNORECASE,
    )
    definition_verb_re = re.compile(
        r"\b(?:is|are|has|have|had|refers\s+to|means|defined\s+as|includes|include|involves|consists\s+of|"
        r"characterized\s+by|focuses\s+on|offers|offer|provides|provide|charges|charge|comes\s+with|"
        r"lets|let|allows|allow|requires|require|earns|earn|pays|pay)\b",
        flags=re.IGNORECASE,
    )

    best: Tuple[float, str] | None = None
    for d in (docs or [])[:max(1, min(5, int(max_docs)))]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue

        for s in [x.strip() for x in re.split(r"(?<=[.!?])\s+|\n+", src) if x.strip()][:8]:
            low = s.lower()
            quality_reason = _definition_quality_rejected_reason(s, entity_l, require_definition_cue=True)
            if quality_reason:
                _log_definition_quality_rejection(s, quality_reason)
                continue
            if reject_re.search(low):
                _log_definition_quality_rejection(s, "heading_or_source_noise")
                continue
            if _looks_table_or_heading_like_chunk(s):
                _log_definition_quality_rejection(s, "table_or_heading_fragment")
                continue
            if defines_other_concept(low, entity_l):
                _log_definition_quality_rejection(s, "defines_other_concept")
                continue
            if not definition_verb_re.search(low):
                _log_definition_quality_rejection(s, "missing_definition_cue")
                continue

            token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            min_hits = max(1, min(2, len(entity_tokens)))
            has_numeric = bool(re.search(r"(?:[\$€£]\s*)?\d", s))
            if _is_numeric_fact_lookup_query(query_text):
                min_hits = 1
                if has_numeric and token_hits >= 1:
                    pass
                elif has_numeric and any(t in low for t in entity_tokens[:2]):
                    pass
                elif token_hits < min_hits:
                    _log_definition_quality_rejection(s, "missing_query_entity")
                    continue
            elif token_hits < min_hits:
                _log_definition_quality_rejection(s, "missing_query_entity")
                continue

            score = float(_s_definition_sentence(s, entity_l, entity_tokens))
            if score <= 0:
                _log_definition_quality_rejection(s, "low_definition_score")
                continue
            if re.search(rf"\b{re.escape(entity_l)}\b", re.sub(r"[^a-z0-9 ]+", " ", low)):
                score += 1.0

            cleaned = re.sub(r"\s+", " ", s).strip()
            if best is None or score > best[0]:
                best = (score, cleaned)

    if not best:
        return None

    sentence = best[1]
    if not re.search(r"[.!?]$", sentence):
        sentence += "."
    S.logger.info("[DEF QUALITY] selected_sentence=%s", _preview_for_quality_log(sentence, 220))
    return sentence

def _extract_simple_definition_sentence(query_text: str, docs: list[dict]) -> str | None:
    if not docs:
        return None
    q = (query_text or "").strip().lower()
    if not (q.startswith("who is") or q.startswith("who was") or q.startswith("who introduced") or q.startswith("what is") or q.startswith("define")):
        return None
    is_who_query = q.startswith("who is") or q.startswith("who was") or q.startswith("who introduced")
    is_who_identity_query = q.startswith("who is") or q.startswith("who was")
    is_concept_query = q.startswith("what is") or q.startswith("define")
    is_person_attribution_query = q.startswith("who introduced") or q.startswith("who developed")

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = (entity or "").strip().lower()
    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]
    # P7: Removed "management" from generic_concept_tokens (domain-leak); the remaining
    # tokens are truly cross-domain generic concept words.
    generic_concept_tokens = {"theory", "process", "system", "approach", "concept", "method", "model"}
    required_concept_anchor_tokens = [t for t in entity_tokens if t not in generic_concept_tokens]

    entity_compact = re.sub(r"[^a-z0-9]+", "", entity_l)
    who_full_name_re = None
    if is_who_identity_query and len(entity_tokens) >= 2:
        parts = [re.escape(t) for t in entity_tokens]
        if len(parts) == 2:
            who_full_name_re = re.compile(
                rf"\b{parts[0]}(?:\s+[a-z]{{2,}}){{0,3}}\s+{parts[1]}\b",
                flags=re.IGNORECASE,
            )
        else:
            middle = ""
            for p in parts[1:-1]:
                middle += rf"(?:\s+[a-z]{{2,}}){{0,2}}\s+{p}"
            who_full_name_re = re.compile(
                rf"\b{parts[0]}{middle}(?:\s+[a-z]{{2,}}){{0,3}}\s+{parts[-1]}\b",
                flags=re.IGNORECASE,
            )

    def _concept_in_sentence(sentence_low: str, strict_mode: bool) -> bool:
        sentence_compact = re.sub(r"[^a-z0-9]+", "", sentence_low)
        if has_entity and entity_l and re.search(rf"\b{re.escape(entity_l)}\b", sentence_low):
            return True
        if entity_compact and entity_compact in sentence_compact:
            return True
        if entity_tokens:
            token_hits = 0
            for t in entity_tokens:
                root_hit = False
                if len(t) >= 6:
                    root = re.escape(t[:6])
                    root_hit = bool(re.search(rf"\b{root}[a-z]*\b", sentence_low))
                if re.search(rf"\b{re.escape(t)}\b", sentence_low) or t in sentence_compact or root_hit:
                    token_hits += 1
            if is_who_query:
                min_hits = 2 if strict_mode and len(entity_tokens) >= 2 else 1
                return token_hits >= min_hits
            return token_hits >= (2 if strict_mode and len(entity_tokens) >= 2 else 1)
        return False

    def _is_rejectable_sentence(sentence: str) -> bool:
        low = sentence.lower()
        allows_explanatory_concept_definition = bool(
            is_concept_query
            and _concept_in_sentence(low, strict_mode=False)
            and re.search(r"\b(refers to|includes|involves|consists of|characterized by)\b", low)
        )
        if len(sentence) > 260:
            return True
        if "the answers to all these questions can be found" in low:
            return True
        if re.search(r"\bwho\s+is\s+.+?\s+most\s+effective\s+with\b", low):
            return True
        if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", sentence, flags=re.IGNORECASE):
            return True
        if sentence.count("•") >= 2:
            return True
        if re.search(r"[•ò]\s*[A-Za-z]", sentence):
            return True
        if re.search(r"\b(one\s+of\s+the\s+components?|listed\s+with|associating\s+model)\b", low):
            return True
        if re.search(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", low):
            return True
        if re.search(r"\b(?:table|figure)\b", low):
            return True
        if re.match(r"^\s*[A-Z][A-Za-z\s]{6,50}\s+\d{1,3}\b", sentence):
            return True
        if re.search(r"\b(?:fig|fig\.)\b", low):
            return True
        if re.search(r"\b(?:classification|contributors?)\b", low):
            return True
        # DISABLED_CHEATING_LOGIC: Domain-specific management-ideas row detector.
        # if re.search(r"\bmanagement\s+ideas\s+contributors\b", low):
        #     return True
        if re.search(r"\b\d+\.\s*[A-Z][A-Za-z\s\-]{2,50}\s+[A-Z][a-z]+\s+[A-Z][a-z]+\b", sentence):
            return True
        if re.search(r"^\s*[A-Z][A-Za-z0-9\s\-]{3,90}\s*:\s*(?:[-•*]|\d+[.)])\s+", sentence):
            return True
        if re.search(r"^\s*(?:introduction|overview|summary|contents?|table of contents|chapter\s+\d+|unit\s+\d+|learning objectives?|key terms?)\s*[:\-–—]?\s*$", sentence, flags=re.IGNORECASE):
            return True
        if "he thought" in low or "it can be said" in low or "he claimed" in low or "she claimed" in low:
            return True
        if re.match(r"^\s*(before|after|when|if|during|for\s+example|this\s+leads)\b", sentence, flags=re.IGNORECASE):
            return True
        if re.search(r"\b(first|second|third|step\s+\d+|should|must|need\s+to|you\s+can|to\s+do\s+this|follow\s+these|start\s+by)\b", low):
            return True
        if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", sentence):
            return True
        if re.match(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", sentence, flags=re.IGNORECASE) and (not allows_explanatory_concept_definition):
            return True
        if "|" in sentence or "\t" in sentence:
            return True
        if re.search(r"(?:\b[A-Za-z]\s+){5,}\b", sentence):
            return True
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", sentence)
        caps = re.findall(r"\b[A-Z][a-z]{2,}\b", sentence)
        if len(words) <= 12 and len(caps) >= 4 and not re.search(r"\b(?:is|refers\s+to|means|defined\s+as)\b", low):
            return True
        if ":" in sentence and (not re.search(r"[.!?]$", sentence)) and (not allows_explanatory_concept_definition):
            return True
        # PATCH 4: reject short numbered row structures ("1. Concept Name")
        if re.match(r"^\s*\d+\.", sentence) and len(re.findall(r"[A-Za-z][A-Za-z\-']*", sentence)) <= 8:
            return True
        # PATCH 4: reject compact concept-person mapping fragments
        if re.match(r"^\s*[A-Z][A-Za-z\s\-]{3,30}\s+[A-Z][a-z]+\s+[A-Z][a-z]+\s*$", sentence.strip()):
            return True
        return False

    def _normalize_person_sentence(sentence: str) -> str:
        if not is_who_query or not has_entity or not entity_l:
            return sentence
        if is_who_identity_query:
            return sentence.strip()
        s = sentence.strip()
        s_low = s.lower()
        if re.search(rf"\b{re.escape(entity_l)}\b", s_low):
            return s
        if not entity_tokens:
            return s
        person_name = " ".join(w.capitalize() for w in entity_l.split())
        for tok in sorted(entity_tokens, key=len, reverse=True):
            if re.search(rf"\b{re.escape(tok)}\b", s_low):
                return re.sub(rf"\b{re.escape(tok)}\b", person_name, s, count=1, flags=re.IGNORECASE)
        return s

    def _extract_from_text(source_text: str) -> str | None:
        if not source_text:
            return None
        raw_sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", source_text) if (s or "").strip()]
        if not raw_sentences:
            return None

        max_scan = min(12, len(raw_sentences))
        candidate_indices: List[int] = list(range(max_scan))

        if (not is_concept_query) and has_entity and entity_l:
            anchor = -1
            for i, s in enumerate(raw_sentences[:max_scan]):
                low = s.lower()
                compact = re.sub(r"[^a-z0-9]+", "", low)
                if re.search(rf"\b{re.escape(entity_l)}\b", low) or (entity_compact and entity_compact in compact):
                    anchor = i
                    break
            if anchor >= 0:
                local = [idx for idx in range(max(0, anchor - 2), min(len(raw_sentences), anchor + 10))]
                merged = []
                seen = set()
                for idx in local + candidate_indices:
                    if idx not in seen and len(merged) < 12:
                        seen.add(idx)
                        merged.append(idx)
                candidate_indices = merged

        definition_verbs = re.compile(r"\b(is|was|refers to|can be defined as|defined as|known as|introduced|means|consists of|includes|involves|characterized by|grew out of)\b")
        concept_definition_verbs = re.compile(r"\b(is\s+defined\s+as|refers\s+to|means|is\s+considered|is|includes|involves|consists\s+of|characterized\s+by|grew\s+out\s+of)\b", flags=re.IGNORECASE)
        concept_explanatory_verbs = re.compile(r"\b(focuses\s+on|involves|aims\s+to|uses|applies)\b", flags=re.IGNORECASE)
        attribution_verbs = re.compile(r"\b(introduced|developed|known as)\b")
        who_definition_verbs = re.compile(r"\b(is|was|known as|introduced|developed)\b")
        # PATCH 2: action verbs for entity query fallback
        who_action_verbs = re.compile(r"\b(said|proposed|described|developed|argued|believed|established|founded|formulated|advocated|contributed|emphasized|suggested|coined)\b")
        concept_person_attribution_re = re.compile(
            r"\b(?:introduced by|he\s+is\s+known\s+as|he\s+was\s+known\s+as|is\s+associated\s+with)\b",
            flags=re.IGNORECASE,
        )
        hard_def_verbs_re = re.compile(r"\b(?:is|refers to|defined as)\b", flags=re.IGNORECASE)
        concept_person_row_re = re.compile(
            r"^\s*(?:\d+[.)]?\s+)?[A-Z][A-Za-z\-]+(?:\s+[A-Za-z][A-Za-z\-]+){0,4}\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\s*$"
        )
        # P1: Removed hard-coded surname allow-list (taylor|fayol|...). Biographical sentences
        # are filtered generically via concept_person_bio_re below.
        concept_person_bio_re = re.compile(
            r"\b(?:he|she|his|her|who|born|known\s+as|was\s+a|said|proposed|developed|introduced)\b",
            flags=re.IGNORECASE,
        )
        concept_example_or_list_re = re.compile(
            r"\b(?:for\s+example|such\s+as|e\.g\.|i\.e\.|example)\b",
            flags=re.IGNORECASE,
        )

        def _person_signal(sentence: str) -> bool:
            s = sentence.strip()
            s_low = s.lower()
            if re.search(r"\b(classification|contributors?|table|figure|chapter|unit|contents?)\b", s_low):
                return False
            if re.search(r"\b[A-Z][a-z]+\s+[A-Z][a-z]+\b", s):
                return True
            if re.search(r"\b[A-Z]\.\s*[A-Z]\.\s*[A-Z][a-z]+\b", s):
                return True
            return bool(re.search(r"\b(mr\.?|ms\.?|dr\.?|prof\.?|sir)\s+[A-Z][a-z]+\b", s))

        scored: List[Tuple[float, int, str]] = []

        immediate_concept_hit: Optional[str] = None

        def _collect_candidates(window_indices: List[int]) -> Tuple[List[Tuple[float, int, str]], List[Dict[str, Any]]]:
            nonlocal immediate_concept_hit
            local_scored: List[Tuple[float, int, str]] = []
            local_concept_candidates: List[Dict[str, Any]] = []
            for local_pos, idx in enumerate(window_indices):
                s = raw_sentences[idx]
                if is_concept_query:
                    s = re.sub(r",\s*in\s+the\s+words\s+of\s+[^,]{1,120},\s*", " ", s, flags=re.IGNORECASE)
                    s = re.sub(r'\b([A-Za-z][A-Za-z0-9\- ]{2,90})\s*["“”]\s*(is|refers\s+to|means|defined\s+as|is\s+defined\s+as|is\s+considered)\b', r'\1 \2', s, flags=re.IGNORECASE)
                    s = re.sub(r"\s+", " ", s).strip()
                low = s.lower()
                sentence_compact = re.sub(r"[^a-z0-9]+", "", low)
                if is_concept_query and entity_l and defines_other_concept(low, entity_l):
                    continue
                token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) if entity_tokens else 0
                full_entity_hit = bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
                compact_phrase_hit = bool(entity_compact and entity_compact in sentence_compact)
                classical_alias_hit = bool(
                    is_concept_query
                    and False
                    and re.search(r"\b(?:classical\s+management\s+theory|classical\s+method|classical\s+management)\b", low)
                )
                phrase_hit = full_entity_hit or compact_phrase_hit or classical_alias_hit
                table_like = _looks_table_or_heading_like_chunk(s)

                if _is_rejectable_sentence(s):
                    continue
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) < 6:
                    continue
                if table_like:
                    continue
                if is_concept_query and not concept_definition_verbs.search(low):
                    continue
                if is_concept_query and not re.search(r"[.!?]$", s.strip()):
                    continue

                # PATCH 1: For concept queries, accept both strict definition and explanatory sentences
                if is_concept_query:
                    person_name_led = bool(re.match(r"^\s*[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\s+(?:is|was)\b", s))
                    full_entity_tokens_hit = bool(entity_tokens) and all(re.search(rf"\b{re.escape(tok)}\b", low) for tok in entity_tokens)
                    feature_label_only = bool(re.match(r"^\s*[A-Za-z][A-Za-z\s\-]{2,50}:\s+", s))
                    has_strict_concept_verb = bool(concept_definition_verbs.search(low))
                    has_explanatory_verb = bool(concept_explanatory_verbs.search(low))
                    explicit_concept_hit = bool(full_entity_hit or compact_phrase_hit)
                    if (not explicit_concept_hit) and required_concept_anchor_tokens:
                        explicit_concept_hit = all(
                            re.search(rf"\b{re.escape(tok)}\b", low) or tok in sentence_compact
                            for tok in required_concept_anchor_tokens
                        )

                    if concept_person_attribution_re.search(s):
                        continue
                    if _looks_table_or_heading_like_chunk(s):
                        continue
                    if concept_person_row_re.match(s.strip()):
                        continue
                    # P1: Removed surname-list filter; rely on generic biographical-verb detector below.
                    if concept_person_bio_re.search(s):
                        continue
                    if concept_example_or_list_re.search(s):
                        continue
                    cap_words = re.findall(r"\b[A-Z][a-z]{2,}\b", s)
                    if len(cap_words) >= 2 and (not hard_def_verbs_re.search(low)):
                        continue
                    if person_name_led and not full_entity_tokens_hit:
                        continue
                    if feature_label_only and not full_entity_tokens_hit:
                        continue
                    if not explicit_concept_hit:
                        continue
                    if required_concept_anchor_tokens and not any(
                        re.search(rf"\b{re.escape(tok)}\b", low) or tok in sentence_compact
                        for tok in required_concept_anchor_tokens
                    ):
                        continue
                    pronoun_start = bool(re.match(r"^\s*(he|she|they|this|it)\b", low))
                    # FINAL TUNING: keep strict pronoun blocking for concept definitions
                    if pronoun_start:
                        continue
                    # Additional filter: reject narrative pronoun claims for concept definitions
                    if pronoun_start and re.search(r"\b(claimed|argued|suggested|believed)\b", low):
                        continue
                    if (":" in s) and not (concept_definition_verbs.search(low) or concept_explanatory_verbs.search(low)):
                        continue
                    if not (has_strict_concept_verb or has_explanatory_verb):
                        continue

                    if _is_over_generic_definition_template(s, entity_l):
                        continue

                    concept_quality_score = _s_definition_sentence(s, entity_l, entity_tokens)
                    if concept_quality_score <= 0:
                        continue

                    if not _has_required_concept_specific_signal(s, entity_l):
                        continue

                    if explicit_concept_hit:
                        if re.search(rf"\b{re.escape(entity_l)}\b\s+is\b", low):
                            concept_quality_score += 4
                        elif re.search(rf"\b{re.escape(entity_l)}\b\s+refers\s+to\b", low):
                            concept_quality_score += 3
                        elif re.search(rf"\b{re.escape(entity_l)}\b\s+(?:focuses\s+on|involves|aims\s+to|uses|applies)\b", low):
                            concept_quality_score += 1

                if is_who_query:
                    if not _concept_in_sentence(low, strict_mode=True):
                        continue
                    # FINAL FIX: for "who is X", require full queried name in the selected sentence
                    if is_who_identity_query and has_entity:
                        full_name_present = bool(
                            (entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
                            or (who_full_name_re and who_full_name_re.search(low))
                        )
                        if not full_name_present:
                            continue
                    # PATCH 2: Accept identity verbs OR action verbs for who queries
                    has_identity_verb = bool(who_definition_verbs.search(low))
                    has_action_verb = bool(who_action_verbs.search(low))
                    if not (has_identity_verb or has_action_verb):
                        continue
                    if not _person_signal(s):
                        continue

                if is_concept_query and full_entity_hit and bool(concept_definition_verbs.search(low)) and (not defines_other_concept(low, entity_l)):
                    immediate_concept_hit = s
                    return local_scored, local_concept_candidates

                strict_zone = local_pos < 5
                concept_ok = _concept_in_sentence(low, strict_mode=strict_zone)
                has_def_verb = bool(definition_verbs.search(low))

                bio_fragment = bool(re.search(r"\b(he|she|his|her)\b", low)) or bool(re.search(r"\b(born|worked as|engineer|biography)\b", low))
                alias_style = bool(re.search(r"\b(you can also call it|also called|also known as)\b", low))
                # DISABLED_CHEATING_LOGIC: Domain-specific management phrase penalty.
                # generic_ungrounded_concept = is_concept_query and ("management" in low) and (not phrase_hit)
                generic_ungrounded_concept = False

                score = 0.0
                if full_entity_hit:
                    score += 3.0
                elif compact_phrase_hit:
                    score += 2.6
                if token_hits:
                    score += min(1.8, 0.7 * token_hits)
                if has_def_verb and (phrase_hit or token_hits >= 1):
                    score += 2.8
                elif has_def_verb:
                    score += 0.8

                if re.match(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", s, flags=re.IGNORECASE):
                    score -= 2.5
                if bio_fragment:
                    score -= 1.8
                if alias_style:
                    score -= 2.2
                if generic_ungrounded_concept:
                    score -= 3.0
                if table_like:
                    score -= 3.0

                if is_who_query:
                    local_neighbors = raw_sentences[max(0, idx - 1): min(len(raw_sentences), idx + 2)]
                    neighbor_text = " ".join(local_neighbors)
                    grounded = _person_signal(s) or _person_signal(neighbor_text)
                    if grounded:
                        score += 1.6
                    else:
                        score -= 2.0
                else:
                    grounded = False

                if is_person_attribution_query:
                    attribution_ok = bool(attribution_verbs.search(low))
                    token_grounded = token_hits >= max(1, min(2, len(entity_tokens))) if entity_tokens else bool(entity_l and entity_l in low)
                    if attribution_ok and (grounded or token_grounded):
                        score += 4.5
                    else:
                        score -= 5.0

                if concept_ok:
                    score += 0.8

                if is_concept_query:
                    has_strict_concept_verb = bool(concept_definition_verbs.search(low))
                    has_explanatory_verb = bool(concept_explanatory_verbs.search(low))
                    if has_explanatory_verb and not has_strict_concept_verb:
                        score -= 1.5
                    if re.search(rf"\b{re.escape(entity_l)}\b\s+is\b", low):
                        score += 2.5
                    elif re.search(rf"\b{re.escape(entity_l)}\b\s+refers\s+to\b", low):
                        score += 1.8
                    elif re.search(rf"\b{re.escape(entity_l)}\b\s+(?:focuses\s+on|involves|aims\s+to|uses|applies)\b", low):
                        score += 0.8
                    concept_quality_score = _s_definition_sentence(s, entity_l, entity_tokens)
                    if concept_quality_score <= 0:
                        continue
                    local_concept_candidates.append({
                        "idx": idx,
                        "sentence": s,
                        "score": score,
                        "concept_quality_score": concept_quality_score,
                        "phrase_hit": phrase_hit,
                        "token_hits": token_hits,
                        "has_concept_verb": has_strict_concept_verb,
                        "has_explanatory_verb": has_explanatory_verb,
                        "generic_ungrounded_concept": generic_ungrounded_concept,
                        "bio_fragment": bio_fragment,
                        "alias_style": alias_style,
                        "table_like": table_like,
                        "continuation": bool(re.match(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", s, flags=re.IGNORECASE)),
                    })

                local_scored.append((score, idx, s))
            return local_scored, local_concept_candidates

        def _pick_concept_candidate(concept_candidates: List[Dict[str, Any]]) -> str | None:
            if not concept_candidates:
                return None
            ranked_matches: List[Tuple[int, float, int, str]] = []
            for c in concept_candidates:
                if not c["phrase_hit"]:
                    continue
                if c["continuation"] or c["alias_style"]:
                    continue
                quality_score = int(c.get("concept_quality_score", -99))
                if quality_score < 0:
                    continue
                if c.get("table_like"):
                    continue
                ranked_matches.append((quality_score, float(c.get("score", 0.0)), int(c.get("idx", 0)), str(c.get("sentence", ""))))

            if ranked_matches:
                ranked_matches.sort(key=lambda x: (x[0], x[1]), reverse=True)
                return ranked_matches[0][3]
            return None

        if is_concept_query:
            scan_cap = min(25, len(raw_sentences))
            phase1_end = min(12, scan_cap)
            phase1_indices = list(range(0, phase1_end))
            phase2_indices = list(range(phase1_end, scan_cap)) if scan_cap > phase1_end else []

            _scored1, concept_candidates1 = _collect_candidates(phase1_indices)
            if immediate_concept_hit:
                return immediate_concept_hit
            selected1 = _pick_concept_candidate(concept_candidates1)
            if selected1:
                return selected1

            if phase2_indices:
                _scored2, concept_candidates2 = _collect_candidates(phase2_indices)
                if immediate_concept_hit:
                    return immediate_concept_hit
                selected2 = _pick_concept_candidate(concept_candidates2)
                if selected2:
                    return selected2
            # PATCH 1: If strict and explanatory concept candidate both failed,
            # try one more scan collecting ALL explanatory sentences from all docs
            return None

        scored, _unused_concept_candidates = _collect_candidates(candidate_indices[:12])

        if not scored:
            return None

        scored.sort(key=lambda x: x[0], reverse=True)
        # HARD PRIORITY: prefer non-table/non-classification prose sentences
        prose_best = None
        for s, i, t in scored:
            if s >= 1.6 and not _looks_table_or_heading_like_chunk(t):
                prose_best = (s, i, t)
                break
        if prose_best:
            return _normalize_person_sentence(prose_best[2])

        # Fallback to table-like if no prose candidate qualifies
        best_score, _best_idx, best_sentence = scored[0]
        if best_score < 1.6:
            return None
        return _normalize_person_sentence(best_sentence)

    def _is_weak_definition_answer(sentence: str) -> bool:
        s = str(sentence or "").strip()
        if not s:
            return True
        if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) <= 6:
            return True
        sl = s.lower()
        if re.search(r"\b(isbn|https?://|www\.|unit\s+\d+)\b", sl):
            return True
        if re.search(r"\b(table\s*\d+|contributors?|classification|contents?)\b", sl):
            return True
        if _is_rejectable_sentence(s):
            return True
        if is_concept_query and not re.search(r"\b(?:is|refers\s+to|means|defined\s+as|is\s+considered|focuses\s+on|involves|aims\s+to|uses|applies)\b", sl):
            return True
        if is_concept_query and required_concept_anchor_tokens:
            anchor_hit = any(re.search(rf"\b{re.escape(tok)}\b", sl) for tok in required_concept_anchor_tokens)
            if not anchor_hit:
                return True
        if is_concept_query and (not _has_required_concept_specific_signal(s, entity_l)):
            return True
        if _is_over_generic_definition_template(s, entity_l):
            return True
        return False

    top_text = str((docs[0] or {}).get("page_content") or (docs[0] or {}).get("text") or "")
    if not top_text:
        return None

    dense_answer = _extract_from_text(top_text)
    top_is_table_like = _looks_table_or_heading_like_chunk(top_text)
    dense_weak = _is_weak_definition_answer(dense_answer) if dense_answer else True

    if dense_answer and (not dense_weak) and ((is_concept_query) or (not top_is_table_like)):
        return dense_answer

    if len(docs) >= 2:
        for d in docs[1:8]:
            next_text = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not next_text:
                continue
            next_answer = _extract_from_text(next_text)
            next_is_table_like = _looks_table_or_heading_like_chunk(next_text)
            next_weak = _is_weak_definition_answer(next_answer) if next_answer else True
            if next_answer and (not next_weak) and ((is_concept_query) or (not next_is_table_like)):
                return next_answer

    should_try_bm25 = (dense_answer is None) or dense_weak or top_is_table_like
    if should_try_bm25:
        bm25_docs, bm25_ms = _search_bm25_definition_fallback(query_text, top_k=2)
        if bm25_docs:
            for bd in bm25_docs[:2]:
                bm25_text = str((bd or {}).get("page_content") or (bd or {}).get("text") or "")
                bm25_answer = _extract_from_text(bm25_text)
                if bm25_answer and not _is_weak_definition_answer(bm25_answer):
                    S.logger.info("BM25 rescue hit | query='%s' | bm25_ms=%.1f", query_text, bm25_ms)
                    return bm25_answer
            S.logger.info("BM25 rescue miss | query='%s' | bm25_ms=%.1f", query_text, bm25_ms)

    def _compose_definition_from_weak_signals(source_docs: list[dict]) -> str | None:
        if not is_concept_query or not has_entity or not entity_l:
            return None
        if not source_docs:
            return None

        stop_terms = {"the", "a", "an", "of", "and", "in", "to", "for", "with", "by", "on"}
        concept_tokens = [
            t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
            if t not in stop_terms
        ]
        if not concept_tokens:
            return None

        # P7: Removed "management" from generic_concept_terms (domain-leak); rest are truly generic.
        generic_concept_terms = {
            "theory", "process", "system", "concept", "approach", "model", "method", "principle"
        }
        anchor_tokens = [t for t in concept_tokens if t not in generic_concept_terms]
        if not anchor_tokens:
            anchor_tokens = concept_tokens[:]

        # P2: Removed hard-coded management-domain keyword set. Evidence selection now relies
        # on generic concept/anchor coverage only (full_phrase_hit + anchor_hits below).

        def _token_or_root_hits(text_low: str, tokens: List[str]) -> set[str]:
            hits: set[str] = set()
            compact_words = re.findall(r"[a-z0-9]{2,}", text_low)
            for tok in tokens:
                if re.search(rf"\b{re.escape(tok)}\b", text_low):
                    hits.add(tok)
                    continue
                if len(tok) >= 5:
                    root = tok[:5]
                    if any(w.startswith(root) for w in compact_words):
                        hits.add(tok)
            return hits

        max_docs = min(5, len(source_docs))
        cleaned_sentences: List[Dict[str, Any]] = []
        seen_norm: set[str] = set()

        for d in source_docs[:max_docs]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            raw_sents = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if s.strip()]
            for s in raw_sents[:18]:
                clean = re.sub(r"\s+", " ", s).strip(" -•*|\t")
                clean = re.sub(r",\s*in\s+the\s+words\s+of\s+[^,]{1,120},\s*", " ", clean, flags=re.IGNORECASE)
                clean = re.sub(r'\b([A-Za-z][A-Za-z0-9\- ]{2,90})\s*["“”]\s*(is|refers\s+to|means|defined\s+as|is\s+defined\s+as|is\s+considered)\b', r'\1 \2', clean, flags=re.IGNORECASE)
                clean = re.sub(r"\s+", " ", clean).strip()
                if not clean:
                    continue
                low = clean.lower()
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", clean)) <= 6:
                    continue
                if _is_rejectable_sentence(clean):
                    continue
                if _looks_table_or_heading_like_chunk(clean):
                    continue
                if re.search(r"\b(table\s*\d+|isbn|https?://|unit\s+\d+)\b", low):
                    continue
                if re.search(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", low):
                    continue
                if re.search(r"\b(?:he|she|his|her|who|born|known\s+as|was\s+a|said|proposed|developed|introduced)\b", low):
                    continue
                # P1: Removed hard-coded surname rejection list; biographical-verb test above is generic.
                if re.search(r"^\s*[A-Z][A-Za-z0-9\s\-]{3,90}\s*:\s*(?:[-•*]|\d+[.)])\s+", clean):
                    continue
                if _s_definition_sentence(clean, entity_l, concept_tokens) <= 0:
                    continue
                if not _has_required_concept_specific_signal(clean, entity_l):
                    continue

                norm = re.sub(r"[^a-z0-9]+", " ", low).strip()
                if not norm or norm in seen_norm:
                    continue
                seen_norm.add(norm)

                full_phrase_hit = bool(re.search(rf"\b{re.escape(entity_l)}\b", low))
                anchor_hits = _token_or_root_hits(low, anchor_tokens)
                # P2: domain_hits removed (was hard-coded management lexicon).

                cleaned_sentences.append({
                    "sentence": clean,
                    "low": low,
                    "full_phrase_hit": full_phrase_hit,
                    "anchor_hits": anchor_hits,
                })

        if not cleaned_sentences:
            return None

        # Out-of-scope protection: if concept topic is absent from retrieved text, skip composition.
        concept_present = any(s["full_phrase_hit"] or bool(s["anchor_hits"]) for s in cleaned_sentences)
        if not concept_present:
            return None

        evidence: List[Dict[str, Any]] = []
        for s in cleaned_sentences:
            # P2: Dropped domain-keyword co-requirement (was a management lexicon).
            # Sentence qualifies as evidence on generic concept coverage alone.
            has_concept_or_related = s["full_phrase_hit"] or bool(s["anchor_hits"])
            if has_concept_or_related:
                evidence.append(s)

        # Strict evidence condition: usually need 2 strong sentences.
        # For specific concept definitions, allow 1 strong sentence to avoid false "Not found".
        min_evidence = 1 if bool(required_concept_anchor_tokens) else 2
        if len(evidence) < min_evidence:
            return None

        # Consistency condition: supporting evidence must point to same concept anchors.
        anchor_counter: Counter[str] = Counter()
        for s in evidence:
            for a in s["anchor_hits"]:
                anchor_counter[a] += 1
        consistent_anchor = next((a for a, c in anchor_counter.items() if c >= 2), None)
        if not consistent_anchor and not any(s["full_phrase_hit"] for s in evidence[:3]):
            return None

        def _score_evidence(s: Dict[str, Any]) -> float:
            score = 0.0
            if s["full_phrase_hit"]:
                score += 3.0
            if consistent_anchor and consistent_anchor in s["anchor_hits"]:
                score += 2.0
            score += min(1.5, 0.6 * len(s["anchor_hits"]))
            # P2: Removed score bonus from domain_hits (hard-coded management lexicon).
            if re.search(r"\b(is|was|refers to|defined as|known as|focuses on|deals with|includes)\b", s["low"]):
                score += 1.2
            return score

        ranked = sorted(evidence, key=_score_evidence, reverse=True)
        selected: List[str] = []
        for item in ranked:
            sent = str(item["sentence"]).strip()
            if not re.search(r"[.!?]$", sent):
                sent += "."
            if sent in selected:
                continue
            selected.append(sent)
            if len(selected) >= max(1, min_evidence):
                break

        if len(selected) < max(1, min_evidence):
            return None

        composed = " ".join(selected[:2]).strip()
        if len(re.findall(r"[A-Za-z][A-Za-z\-']*", composed)) < 12:
            return None
        return composed

    composed_answer = _compose_definition_from_weak_signals(docs[:5])
    if composed_answer:
        return composed_answer

    def _rescue_from_concept_signals(source_docs: list[dict]) -> str | None:
        # DISABLED_CHEATING_LOGIC: Domain-specific concept-signal rescue mapping.
        return None
        if not is_concept_query or not has_entity or not entity_l:
            return None
        signals = _concept_specific_signal_terms(entity_l)
        if not signals:
            return None
        canonical_map = {
            "scientific": "scientific principles",
            "science": "scientific principles",
            "standards": "standardization",
            "work": "work methods",
            "planning": "planning work",
            "division of work": "division of labor",
        }
        found: List[str] = []
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+", txt) if p.strip()]
            for p in parts[:40]:
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                low = p.lower()
                if re.search(r"\b(?:he|she|his|her|born|known\s+as|was\s+a|said|proposed|developed|introduced)\b", low):
                    continue
                for sig in signals:
                    sig_re = re.escape(sig).replace("\\ ", r"\\s+")
                    if re.search(rf"\b{sig_re}\b", low):
                        canonical = canonical_map.get(sig, sig)
                        if canonical not in found:
                            found.append(canonical)
                if len(found) >= 2:
                    break
            if len(found) >= 2:
                break
        if len(found) < 2:
            return None
        entity_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", entity_l)) or entity
        candidate = f"{entity_title} is characterized by {found[0]} and {found[1]}."
        if _is_over_generic_definition_template(candidate, entity_l):
            return None
        return candidate

    signal_rescue = _rescue_from_concept_signals(docs[:5])
    if signal_rescue:
        return signal_rescue

    def _title_case_entity(e: str) -> str:
        return " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", e or ""))

    def _extract_concept_person_pair_from_line(line: str) -> Optional[Tuple[str, str]]:
        line_norm = re.sub(r"\s+", " ", str(line or "")).strip()
        if not line_norm:
            return None
        patterns = [
            re.compile(r"^\s*\d+[.)]?\s+([A-Za-z][A-Za-z\- ]{2,100}?)\s+(?:[-–—:|])\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\s*$"),
            re.compile(r"^\s*([A-Za-z][A-Za-z\- ]{2,100}?)\s+(?:[-–—:|])\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\s*$"),
            re.compile(r"(?:^|\s)(\d+)[.)]?\s+([A-Za-z][A-Za-z\- ]{2,80}?)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2})(?=\s+\d+[.)]?\s+|$)"),
        ]
        for pat in patterns:
            m = pat.search(line_norm)
            if not m:
                continue
            if m.lastindex == 3:
                concept_cell = (m.group(2) or "").strip()
                person_cell = (m.group(3) or "").strip()
            else:
                concept_cell = (m.group(1) or "").strip()
                person_cell = (m.group(2) or "").strip()
            if len(person_cell.split()) < 2:
                continue
            return concept_cell, person_cell
        return None

    def _extract_person_attribution_from_docs(source_docs: list[dict], allow_concept_fallback: bool = False) -> str | None:
        if not ((is_person_attribution_query or (allow_concept_fallback and is_concept_query)) and has_entity and entity_l):
            return None
        ent_need = max(1, min(2, len(entity_tokens))) if entity_tokens else 1
        banned_name_tokens = {"theory", "model", "approach", "school", "method", "system", "table", "figure", "chapter", "section", "contributors", "classification"}
        org_or_place_tokens = {"company", "corporation", "corp", "inc", "ltd", "limited", "university", "college", "states", "state", "industry", "industries", "steel"}
        role_tokens = {"chief", "engineer", "manager", "director", "officer", "president", "professor", "doctor", "dr", "mr", "ms", "mrs"}
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue

            # Strict same-line mapping only: concept and person must be in the same row/line.
            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                pair = _extract_concept_person_pair_from_line(line_norm)
                if not pair:
                    continue
                concept_cell, name_cell = pair
                concept_low = concept_cell.lower()
                hit_count = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", concept_low)) if entity_tokens else 0
                name_tokens = [t for t in re.findall(r"[a-z]+", name_cell.lower()) if t]
                if any(t in banned_name_tokens for t in name_tokens):
                    continue
                if hit_count >= ent_need:
                    entity_title = _title_case_entity(entity_l) or entity
                    concept_title = re.sub(r"\s+", " ", str(concept_cell or "").strip())
                    if concept_title:
                        concept_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", concept_title))
                    if not concept_title:
                        concept_title = entity_title
                    mapped_name = name_cell
                    mapped_name_tokens = [t.lower() for t in re.findall(r"[A-Za-z]{2,}", mapped_name)]
                    if any(t in org_or_place_tokens for t in mapped_name_tokens):
                        continue
                    if any(t in role_tokens for t in mapped_name_tokens):
                        continue
                    if q.startswith("who introduced"):
                        return f"{mapped_name} introduced {concept_title}."

            # Same-line loose fallback: concept tokens and person name in one line/chunk only.
            person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b")
            banned_name_tokens = {
                "theory", "principles", "functions", "process", "organization", "organisation", "method",
                "system", "approach", "model", "table", "figure", "chapter", "section", "classification",
                "united", "states",
            }
            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                low_line = line_norm.lower()
                hit_count = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low_line)) if entity_tokens else 0
                if hit_count < ent_need:
                    continue
                name_candidates = person_name_re.findall(line_norm)
                if not name_candidates:
                    continue
                mapped_name = None
                for candidate in reversed(name_candidates):
                    toks = [t.lower() for t in re.findall(r"[A-Za-z]{2,}", candidate)]
                    if len(toks) < 2:
                        continue
                    if any(t in banned_name_tokens for t in toks):
                        continue
                    if any(t in org_or_place_tokens for t in toks):
                        continue
                    if any(t in role_tokens for t in toks):
                        continue
                    mapped_name = candidate.strip()
                    break
                if not mapped_name:
                    continue
                concept_title = _title_case_entity(entity_l) or entity
                if q.startswith("who introduced"):
                    return f"{mapped_name} introduced {concept_title}."
            # FINAL FIX: no prose inference for attribution queries; same-line mapping only.
        return None

    attribution_answer = _extract_person_attribution_from_docs(docs[:5])
    if attribution_answer:
        return attribution_answer

    def _extract_person_identity_fallback_from_docs(source_docs: list[dict]) -> str | None:
        if not (is_who_query and (not is_person_attribution_query) and has_entity and entity_l):
            return None
        entity_words = [w for w in entity_l.split() if w]
        if not entity_words:
            return None
        full_name_tokens = [t for t in re.findall(r"[a-z]{2,}", entity_l) if t]
        full_name_re = None
        if len(full_name_tokens) >= 2:
            full_name_re = re.compile(
                rf"\b{re.escape(full_name_tokens[0])}\b(?:\s+[a-z]+){{0,3}}\s+\b{re.escape(full_name_tokens[-1])}\b",
                flags=re.IGNORECASE,
            )
        last_name = entity_words[-1]
        preferred_first = entity_words[0] if len(entity_words) >= 2 else ""
        entity_title = _title_case_entity(entity_l) or entity
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            # Table-like fallback: map person to concept in same row.
            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                pair = _extract_concept_person_pair_from_line(line_norm)
                if not pair:
                    continue
                concept_cell, name_cell = pair
                low_name = name_cell.lower()
                if full_name_re and not full_name_re.search(low_name):
                    continue
                if not re.search(rf"\b{re.escape(last_name)}\b", low_name):
                    continue
                if preferred_first and (preferred_first not in low_name):
                    continue
                clean_concept = re.sub(r"\s+", " ", concept_cell).strip(" .")
                if clean_concept:
                    # FINAL FIX: fallback accepted only from strict same-line table mapping.
                    role = "scholar"
                    return f"{entity_title} is a {role} known for {clean_concept}."
        return None

    person_identity_fallback = _extract_person_identity_fallback_from_docs(docs[:5])
    if person_identity_fallback:
        return person_identity_fallback

    def _extract_who_action_fallback_from_docs(source_docs: list[dict]) -> str | None:
        if not (is_who_query and (not is_person_attribution_query)):
            return None
        action_re = re.compile(r"\b(said|proposed|described|developed|argued|believed|established|founded|formulated|advocated|contributed|emphasized|suggested|coined)\b", flags=re.IGNORECASE)
        person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b")
        full_name_re = None
        if is_who_identity_query and len(entity_tokens) >= 2:
            first = re.escape(entity_tokens[0])
            last = re.escape(entity_tokens[-1])
            full_name_re = re.compile(rf"\b{first}(?:\s+[a-z]{{2,}}){{0,3}}\s+{last}\b", flags=re.IGNORECASE)
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+", txt) if p.strip()]
            for p in parts[:24]:
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                low = p.lower()
                if is_who_identity_query:
                    full_hit = bool(full_name_re.search(low)) if full_name_re else bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
                    token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) if entity_tokens else 0
                    if not (full_hit or token_hits >= max(2, min(3, len(entity_tokens)))):
                        continue
                if action_re.search(low) and person_name_re.search(p):
                    return _normalize_person_sentence(p)
        return None

    who_action_fallback = _extract_who_action_fallback_from_docs(docs[:5])
    if who_action_fallback:
        return who_action_fallback

    def _synthesize_concept_definition_from_evidence(source_docs: list[dict]) -> str | None:
        if not is_concept_query or not has_entity or not entity_l:
            return None
        ent_need = 1
        best_sentence = None
        best_score = -1.0
        concept_person_attribution_re = re.compile(
            r"\b(?:introduced by|he\s+is\s+known\s+as|he\s+was\s+known\s+as|is\s+associated\s+with)\b",
            flags=re.IGNORECASE,
        )
        concept_valid_verb_re = re.compile(
            r"\b(?:is|refers to|defined as|means|involves|consists of|includes|characterized by|focuses on|deals with)\b",
            flags=re.IGNORECASE,
        )
        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+", txt) if p.strip()]
            for p in parts[:28]:
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                if _s_definition_sentence(p, entity_l, entity_tokens) <= 0:
                    continue
                low = p.lower()
                if concept_person_attribution_re.search(low):
                    continue
                if re.match(r"^\s*(he|she|they|it|this|that)\b", low):
                    continue
                if not concept_valid_verb_re.search(low):
                    continue
                if re.search(r"\b(claims?|argues?|in the words of|who claims)\b", low):
                    continue
                if re.search(r"\b[A-Z][a-z]+\s+[A-Z][a-z]+\b", p) and not re.search(rf"\b{re.escape(entity_l)}\b", low):
                    continue
                if not _has_required_concept_specific_signal(p, entity_l):
                    continue
                token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) if entity_tokens else 0
                if token_hits < ent_need:
                    continue
                non_generic_hits = sum(
                    1 for t in entity_tokens
                    if t not in {"theory", "system", "approach", "concept", "model", "method"}
                    and re.search(rf"\b{re.escape(t)}\b", low)
                )
                if entity_tokens and non_generic_hits <= 0 and not re.search(rf"\b{re.escape(entity_l)}\b", low):
                    continue
                wc = len(re.findall(r"[A-Za-z][A-Za-z\-']*", p))
                if wc < 8 or wc > 35:
                    continue
                score = float(token_hits)
                if re.search(r"\b(is|refers to|defined as|known as|means|method|approach|purpose|function|role)\b", low):
                    score += 1.2
                if score > best_score:
                    best_score = score
                    best_sentence = p
        if not best_sentence:
            return None
        sentence = re.sub(r"\s+", " ", best_sentence).strip().rstrip(".")
        entity_title = _title_case_entity(entity_l) or entity
        synthesized = f"{entity_title} refers to {sentence}."
        if _passes_fast_path_definition_validation(query_text, synthesized):
            return synthesized
        return None

    synthesized_definition = _synthesize_concept_definition_from_evidence(docs[:5])
    if synthesized_definition:
        return synthesized_definition

    if is_concept_query and has_entity and entity_l:
        rescue_verb_re = re.compile(
            r"\b(?:is|refers\s+to|means|defined\s+as|includes|involves|consists\s+of|characterized\s+by|focuses\s+on|deals\s+with)\b",
            flags=re.IGNORECASE,
        )
        for d in (docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+", txt) if p.strip()]
            for p in parts[:36]:
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                low = p.lower()
                if not _concept_in_sentence(low, strict_mode=False):
                    continue
                if not rescue_verb_re.search(low):
                    continue
                if re.search(r"\b(?:table|figure|classification|contributors?|contents?)\b", low):
                    continue
                if _s_definition_sentence(p, entity_l, entity_tokens) < 0:
                    continue
                if not _has_required_concept_specific_signal(p, entity_l):
                    continue
                sent = re.sub(r"\s+", " ", p).strip()
                if not re.search(r"[.!?]$", sent):
                    sent += "."
                return sent

    if False:
        strict_classical_re = re.compile(
            r"\bclassical\s+management\s+theory\b.{0,120}\bgrew\s+out\s+of\b.{0,180}\b(?:industrial\s+revolution|classical\s+method)\b",
            flags=re.IGNORECASE,
        )
        for d in (docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            for p in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if s.strip()][:42]:
                low = p.lower()
                if _is_rejectable_sentence(p):
                    continue
                if _looks_table_or_heading_like_chunk(p):
                    continue
                if strict_classical_re.search(low):
                    clean = re.sub(r"\s+", " ", p).strip().strip('"“”')
                    clean = clean.rstrip(".")
                    return None
            flat_low = re.sub(r"\s+", " ", txt.lower())
            if (
                re.search(r"\bclassical\s+management\s+theory\b", flat_low)
                and (
                    re.search(r"\bgrew\s+out\s+of\b", flat_low)
                    or re.search(r"\bindustrial\s+revolution\b", flat_low)
                    or re.search(r"\bclassical\s+method\b", flat_low)
                )
            ):
                return None

    if dense_answer and (not _is_weak_definition_answer(dense_answer)) and _passes_fast_path_definition_validation(query_text, dense_answer):
        return dense_answer

    # PATCH 3: STRICT same-row table mapping for attribution queries.
    # Concept and person MUST appear on the same logical line / short fragment.
    # No cross-row merging, no guessing from neighboring rows.
    if is_person_attribution_query and has_entity and entity_l:
        entity_tokens_set = set(re.findall(r"[a-z]{3,}", entity_l))
        if not entity_tokens_set:
            return None
        for d in docs[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                pair = _extract_concept_person_pair_from_line(line_norm)
                if not pair:
                    continue
                concept_cell, person_cell = pair
                concept_hits = sum(1 for tok in entity_tokens_set if re.search(rf"\b{re.escape(tok)}\b", concept_cell.lower()))
                if concept_hits < max(1, min(2, len(entity_tokens_set))):
                    continue
                if len(person_cell.split()) < 2:
                    continue
                concept_title = re.sub(r"\s+", " ", str(concept_cell or "").strip())
                if concept_title:
                    concept_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", concept_title))
                if not concept_title:
                    concept_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", entity_l))
                return f"{person_cell} is associated with {concept_title}."

    def _extract_related_concept_sentence_from_docs(source_docs: list[dict]) -> str | None:
        return None

    related_concept_answer = _extract_related_concept_sentence_from_docs(docs[:5])
    if related_concept_answer:
        return related_concept_answer

    if is_concept_query:
        S.logger.info("[DEF REJECT WEAK] entity=%s reason=no_strong_definition_sentence", entity_l)
        return None

    def _extract_concept_same_line_mapping_fallback(source_docs: list[dict]) -> str | None:
        if not (is_concept_query and has_entity and entity_l):
            return None

        clear_entity_tokens = [
            t for t in required_concept_anchor_tokens
            if t not in {"general", "overall", "common", "basic"}
        ]
        if not clear_entity_tokens:
            return None

        concept_title = _title_case_entity(entity_l) or entity
        concept_token_need = max(1, min(2, len(clear_entity_tokens)))
        person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\b")
        banned_value_tokens = {
            "theory", "ideas", "contributors", "classification", "table", "figure", "contents",
            "chapter", "unit", "process", "model", "approach", "system", "method", "principles",
        }

        for d in (source_docs or [])[:5]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue

            for line in txt.splitlines():
                line_norm = re.sub(r"\s+", " ", line or "").strip()
                if not line_norm:
                    continue
                if re.search(r"\b(?:table\s*\d+|figure|fig\.?)\b", line_norm, flags=re.IGNORECASE):
                    continue
                if re.search(r"\b(?:chapter\s+\d+|unit\s+\d+)\b", line_norm, flags=re.IGNORECASE):
                    continue
                if re.search(r"\b(?:introduction|overview|summary|key\s+terms?)\b", line_norm, flags=re.IGNORECASE):
                    continue

                pair = _extract_concept_person_pair_from_line(line_norm)
                concept_cell_norm = ""
                mapped_value_norm = ""
                if pair:
                    concept_cell, mapped_value = pair
                    concept_cell_norm = re.sub(r"\s+", " ", str(concept_cell or "")).strip()
                    mapped_value_norm = re.sub(r"\s+", " ", str(mapped_value or "")).strip()
                else:
                    low_line = line_norm.lower()
                    full_phrase_hit = bool(re.search(rf"\b{re.escape(entity_l)}\b", low_line))
                    token_hits = sum(1 for t in clear_entity_tokens if re.search(rf"\b{re.escape(t)}\b", low_line))
                    if not (full_phrase_hit or token_hits >= concept_token_need):
                        continue
                    if re.search(r"[,;/]", line_norm) or re.search(r"\band\b", line_norm, flags=re.IGNORECASE):
                        continue
                    value_candidates = person_name_re.findall(line_norm)
                    if not value_candidates:
                        continue
                    picked = None
                    for candidate in reversed(value_candidates):
                        toks = [t.lower() for t in re.findall(r"[A-Za-z]{2,}", candidate)]
                        if not toks:
                            continue
                        if any(t in banned_value_tokens for t in toks):
                            continue
                        if len(toks) > 4:
                            continue
                        picked = candidate.strip()
                        break
                    if not picked:
                        continue
                    concept_cell_norm = entity_l
                    mapped_value_norm = picked

                if not concept_cell_norm or not mapped_value_norm:
                    continue
                if re.search(r"\d", concept_cell_norm):
                    continue
                if re.search(r"[,;/]", concept_cell_norm) or re.search(r"\band\b", concept_cell_norm, flags=re.IGNORECASE):
                    continue
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", mapped_value_norm)) > 5:
                    continue
                mapped_toks = [t.lower() for t in re.findall(r"[A-Za-z]{2,}", mapped_value_norm)]
                if any(t in banned_value_tokens for t in mapped_toks):
                    continue

                concept_low = concept_cell_norm.lower()
                full_phrase_hit = bool(re.search(rf"\b{re.escape(entity_l)}\b", concept_low))
                token_hits = sum(1 for t in clear_entity_tokens if re.search(rf"\b{re.escape(t)}\b", concept_low))
                if not (full_phrase_hit or token_hits >= concept_token_need):
                    continue

                return f"{concept_title} is associated with {mapped_value_norm}."

        return None

    concept_same_line_fallback = _extract_concept_same_line_mapping_fallback(docs[:5])
    if concept_same_line_fallback:
        return concept_same_line_fallback

    concept_mapping_from_existing_logic = _extract_person_attribution_from_docs(docs[:5], allow_concept_fallback=True)
    if concept_mapping_from_existing_logic:
        return concept_mapping_from_existing_logic

    return None

def _extract_simple_list_from_docs(docs: list[dict], query_text: str = "") -> str | None:
    if not docs:
        return None
    bullet_num_re = re.compile(r"^\s*(?:[-•*]|\d+[.)])\s+(.+)$")
    weak_list_start_re = re.compile(
        r"^(?:should\s+be|for\s+the|such\s+as|he\b|she\b|they\b|this\b|these\b|those\b|it\b|according\s+to)\b",
        flags=re.IGNORECASE,
    )
    list_noise_re = re.compile(r"\b(?:table|figure|isbn|https?://|www\.|works?\s+of)\b", flags=re.IGNORECASE)

    def _starts_with_noun_or_gerund(item: str) -> bool:
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item or "")
        if not words:
            return False
        first = words[0].lower()
        if first in {"this", "it", "these", "should", "according", "that", "those", "they", "we", "you", "i"}:
            return False
        if first.endswith("ing"):
            return True
        if first in {"is", "are", "was", "were", "be", "been", "being", "have", "has", "had", "do", "does", "did", "can", "could", "would", "will", "shall", "may", "might", "must"}:
            return False
        if first in {"to", "for", "of", "with", "by", "from", "on", "at", "into", "within", "under", "while", "whereas", "and", "or", "but"}:
            return False
        return True

    def _finalize_items(items: List[str], limit: int = 12) -> List[str]:
        out: List[str] = []
        seen: set[str] = set()
        local_ql = (query_text or "").lower()
        # DISABLED_CHEATING_LOGIC: Domain-specific planning-process list gate.
        # is_planning_process_q = ("planning" in local_ql) and ("process" in local_ql)
        is_planning_process_q = False
        process_action_re = re.compile(
            r"\b(formulat|develop|identif|evaluat|select|set(?:ting)?|schedul|follow|implement|monitor|review|establish|determin|decid|analyz|assess|prioritiz)\w*\b",
            flags=re.IGNORECASE,
        )
        for raw in items:
            cleaned = _clean_list_item(raw)
            if not cleaned:
                continue
            if not _starts_with_noun_or_gerund(cleaned):
                continue
            # DISABLED_CHEATING_LOGIC: Domain-specific planning-process item filter.
            # if is_planning_process_q:
            #     cl = cleaned.lower()
            #     if re.search(r"\btypes?\b", cl):
            #         continue
            #     if re.search(r"\bplans?\b", cl) and not process_action_re.search(cl):
            #         continue
            if re.search(r"\b(?:this|it|these|should|according\s+to)\b", cleaned, flags=re.IGNORECASE):
                continue
            if re.search(r"(?:\.{2,}|\|)", cleaned):
                continue
            if ":" in cleaned:
                continue
            if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from)\s*$", cleaned, flags=re.IGNORECASE):
                continue
            cleaned = cleaned[0].upper() + cleaned[1:] if cleaned else cleaned
            if not re.search(r"[.!?]$", cleaned):
                cleaned += "."
            norm = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", cleaned.lower())).strip()
            if not norm or norm in seen:
                continue
            seen.add(norm)
            out.append(cleaned)
            if len(out) >= limit:
                break
        return out

    def _clean_list_item(raw_item: str) -> str | None:
        ql = (query_text or "").lower()
        # DISABLED_CHEATING_LOGIC: Domain-specific advantages query special casing.
        # is_advantages_query = "advantage" in ql
        item = re.sub(r"\s+", " ", str(raw_item or "")).strip(" ,;:-\"'")
        item = re.sub(r"^(?:[:;,.\-–—]+\s*)+", "", item)
        item = re.sub(r"^\s*(?:and|or|also|then|such\s+as|for\s+example)\s+", "", item, flags=re.IGNORECASE)
        item = re.sub(r"\s+\d+\.?$", "", item).strip()
        if not item:
            return None
        max_words = 14
        if len(item.split()) < 2 or len(item.split()) > max_words:
            return None
        if weak_list_start_re.match(item):
            return None
        if list_noise_re.search(item):
            return None
        if item and item[0].islower():
            return None
        if item.endswith(":"):
            return None
        if ":" in item:
            return None
        if re.match(r"^\d+(?:\.\d+)*$", item):
            return None
        if re.match(r"^\d+(?:\.\d+)+", item):
            return None
        if re.match(r"^[A-Za-z\s]{2,20}$", item, flags=re.IGNORECASE) and len(item.split()) <= 2:
            return None
        if re.search(r"\b(introduction\s+concepts?|\w+\s+of\s+\w+)\b", item, flags=re.IGNORECASE):
            return None
        return item

    ql = (query_text or "").lower()

    def _list_topic_gate(text: str) -> bool:
        return True

    for d in docs[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        lines = [ln.rstrip() for ln in src.splitlines()]
        for i, ln in enumerate(lines):
            if not bullet_num_re.match(ln):
                continue
            pre_context = " ".join(lines[max(0, i - 2): min(len(lines), i + 2)])
            if not _list_topic_gate(pre_context):
                continue
            items: List[str] = []
            j = i
            current_item = ""
            while j < len(lines):
                m = bullet_num_re.match(lines[j])
                if m:
                    if current_item:
                        normalized = _clean_list_item(current_item)
                        if normalized:
                            items.append(normalized)
                    item = _clean_list_item(m.group(1))
                    current_item = item or ""
                    j += 1
                    continue
                if lines[j].strip() == "":
                    if current_item:
                        normalized = _clean_list_item(current_item)
                        if normalized:
                            items.append(normalized)
                        current_item = ""
                    j += 1
                    if j < len(lines) and (not bullet_num_re.match(lines[j])) and re.match(r"^\s*[A-Z][A-Za-z0-9\s\-]{3,90}\s*$", lines[j].strip()):
                        break
                    continue
                if current_item and not bullet_num_re.match(lines[j]):
                    cont = re.sub(r"\s+", " ", lines[j]).strip(" -•*\t")
                    if cont and not re.match(r"^[A-Z][A-Za-z0-9\s\-]{3,90}\s*$", cont):
                        current_item = f"{current_item} {cont}".strip()
                        j += 1
                        continue
                break
            if current_item:
                normalized = _clean_list_item(current_item)
                if normalized:
                    items.append(normalized)
            items = [it for it in items if _list_topic_gate(it)]
            items = _finalize_items(items, limit=12)
            if len(items) >= 2:
                return "\n".join(f"- {it}" for it in items)

    # Inline prose enumeration extraction: handles continuous-prose lists of the shape
    #   "<introducer phrase>: a, b, c, d, e, and f"
    #   "<introducer phrase> are/include/comprise/consist of a, b, c, ..., and f"
    #   "<introducer phrase>, namely a, b, c, ..., and f"
    # These never match the bullet/numbered walker above and never match the lettered
    # OCR-table extractor below, but they are the single most common form authors use
    # to enumerate a small fixed set inside narrative text. Generic across domains.
    #
    # Strict guards (anti-fabrication, anti-shortcut):
    #   * Requires an explicit introducer cue (`:` or are/is/include/comprise/consist of/namely)
    #     so we never split arbitrary comma-separated prose into a list.
    #   * Items must be 1-5 words each, capitalized or lowercase noun-like, no verbs.
    #   * Requires 3-12 items with a closing conjunction (and/or) before the last item.
    #   * If the query specifies a count (digit or English cardinal), the enumeration MUST
    #     contain exactly that many items. This is the strongest grounding gate.
    #   * The sentence containing the enumeration must contain ALL discriminating query
    #     tokens (same gate philosophy as `_list_relevance_ok`).
    _q_low_inline = (query_text or "").lower()
    _CARDINAL_WORDS = {
        "two": 2, "three": 3, "four": 4, "five": 5, "six": 6, "seven": 7,
        "eight": 8, "nine": 9, "ten": 10, "eleven": 11, "twelve": 12,
    }
    _q_count_target: int | None = None
    _q_count_match = re.search(r"\b(\d{1,2})\b", _q_low_inline)
    if _q_count_match:
        try:
            _v = int(_q_count_match.group(1))
            if 2 <= _v <= 20:
                _q_count_target = _v
        except Exception:
            _q_count_target = None
    if _q_count_target is None:
        for _w, _v in _CARDINAL_WORDS.items():
            if re.search(rf"\b{_w}\b", _q_low_inline):
                _q_count_target = _v
                break

    _q_terms_inline = [
        t for t in re.findall(r"[a-z0-9]{3,}", _q_low_inline)
        if t not in {
            "what", "which", "name", "give", "mention", "identify", "list", "from",
            "document", "about", "are", "the", "and", "for", "with", "main", "major",
            "only", "popular", "areas", "area", "mentioned", "chapter", "section",
            "tell", "show", "explain", "define",
        }
    ]
    _q_terms_inline_norm = [_light_normalize_query_token(t) for t in _q_terms_inline if t]

    _enum_introducer_re = re.compile(
        r"(?P<intro>[A-Za-z][A-Za-z0-9 ,\-]{2,80}?)"
        r"(?:\s*:\s*|\s+(?:are|is|include|includes|comprise|comprises|consist\s+of|consists\s+of|namely)\s+)"
        r"(?P<body>[A-Za-z][^.;\n]{8,400}?\band\s+[A-Za-z][A-Za-z\-']{1,30}(?:\s+[A-Za-z\-']{1,30}){0,4})"
        r"(?=[.;\n]|$)",
        flags=re.IGNORECASE,
    )
    _verb_in_item_re = re.compile(
        r"\b(?:is|are|was|were|be|been|being|have|has|had|do|does|did|"
        r"can|could|would|will|shall|may|might|must|"
        r"include|includes|consist|consists|comprise|comprises|"
        r"focus|focuses|focused|study|studies|studied|"
        r"explain|explains|describe|describes|involve|involves|concern|concerns)\b",
        flags=re.IGNORECASE,
    )

    def _split_inline_enumeration(body_text: str) -> list[str]:
        body = re.sub(r"\s+", " ", str(body_text or "")).strip(" ,;:.-")
        if not body:
            return []
        # If the body contains a secondary introducer colon (e.g. when the outer match
        # selected an "include"/"are" cue but a tighter ":" cue exists inside the body
        # such as in "...would include the six Ms: people, money, ..."), take only the
        # tail after the last colon, which is the actual enumeration.
        if ":" in body:
            body = body.rsplit(":", 1)[-1].strip(" ,;:.-")
            if not body:
                return []
        # Split on commas; the trailing item is preceded by " and " / " or "
        body = re.sub(r",\s*(?:and|or)\s+", ", ", body, flags=re.IGNORECASE)
        body = re.sub(r"\s+(?:and|or)\s+", ", ", body, flags=re.IGNORECASE)
        raw_parts = [p.strip(" ,;:.-") for p in body.split(",")]
        out: list[str] = []
        for p in raw_parts:
            if not p:
                continue
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", p)
            wc = len(words)
            if wc < 1 or wc > 5:
                return []
            if _verb_in_item_re.search(p):
                return []
            if list_noise_re.search(p):
                return []
            out.append(p)
        return out

    for _d_inline in docs[:3]:
        _src_inline = str((_d_inline or {}).get("page_content") or (_d_inline or {}).get("text") or "")
        if not _src_inline:
            continue
        for _sent in re.split(r"(?<=[.!?])\s+|\n+", _src_inline):
            _sent_clean = re.sub(r"\s+", " ", str(_sent or "")).strip()
            if len(_sent_clean) < 20 or len(_sent_clean) > 600:
                continue
            _sent_low = _sent_clean.lower()
            if _q_terms_inline_norm:
                _grounded = sum(
                    1 for _qt in _q_terms_inline_norm if _token_match_light(_sent_low, _qt)
                )
                if _grounded < len(_q_terms_inline_norm):
                    continue
            _m = _enum_introducer_re.search(_sent_clean)
            if not _m:
                continue
            _items_inline = _split_inline_enumeration(_m.group("body") or "")
            if len(_items_inline) < 3 or len(_items_inline) > 12:
                continue
            if _q_count_target is not None and len(_items_inline) != _q_count_target:
                continue
            _formatted: list[str] = []
            _seen_inline: set[str] = set()
            for _it in _items_inline:
                _shaped = _it[0].upper() + _it[1:] if _it else _it
                if not re.search(r"[.!?]$", _shaped):
                    _shaped += "."
                _key = re.sub(r"[^a-z0-9]+", " ", _shaped.lower()).strip()
                if not _key or _key in _seen_inline:
                    continue
                _seen_inline.add(_key)
                _formatted.append(_shaped)
            if len(_formatted) < 3:
                continue
            if _q_count_target is not None and len(_formatted) != _q_count_target:
                continue
            return "\n".join(f"- {it}" for it in _formatted)

    # Lightweight fallback (top 2 chunks only): reconstruct 3-5 meaningful items from commas/sentences.
    fallback_items: List[str] = []
    seen: set[str] = set()
    bad_starts = re.compile(r"^(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", flags=re.IGNORECASE)

    # Inline lettered-list extraction: handles OCR-linearized two-column tables that look like
    # "a. Item one. b. Item two. c. Item three. ... n. Item N." in a single line of text.
    # Generic textbook OCR pattern; requires the markers to start at "a" and include >=4 distinct
    # early-alphabet letters, so it doesn't match arbitrary period-prefixed prose.
    # Runs BEFORE the prose/sentence fallback so a clean lettered table wins over heuristic prose.
    for d in docs[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        cleaned_src = re.sub(r"(?:table|figure)\s+\d+(?:\.\d+)*\s*[:\-–—]\s*[^a-z\n]{0,80}", "", src, flags=re.IGNORECASE)
        letter_matches = re.findall(r"(?:^|\s)([a-z])\.\s+([A-Z][A-Za-z][^.\n]{2,80}\.)", cleaned_src)
        if len(letter_matches) < 4:
            continue
        seen_letters: list[str] = []
        for ltr, _ in letter_matches:
            if ltr not in seen_letters:
                seen_letters.append(ltr)
        early_alphabet = set("abcdefghijklmnop")
        if not seen_letters or seen_letters[0] != "a":
            continue
        if sum(1 for l in seen_letters[:8] if l in early_alphabet) < 4:
            continue
        by_letter: dict[str, str] = {}
        for ltr, payload in letter_matches:
            if ltr in by_letter:
                continue
            by_letter[ltr] = payload
        ordered_letters = sorted(by_letter.keys())
        seen_letter_items: set[str] = set()
        lettered_items: List[str] = []
        for ltr in ordered_letters:
            payload = by_letter.get(ltr) or ""
            item = re.sub(r"\s+", " ", payload).strip().rstrip(".").strip(" ,;:-\"'")
            if not item:
                continue
            wc = len(item.split())
            if wc < 1 or wc > 12:
                continue
            if not item[0].isupper():
                continue
            if list_noise_re.search(item):
                continue
            if ":" in item:
                continue
            if re.match(r"^\d", item):
                continue
            if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from)\s*$", item, flags=re.IGNORECASE):
                continue
            low = item.lower()
            if low in seen_letter_items:
                continue
            if bad_starts.match(item):
                continue
            seen_letter_items.add(low)
            if not re.search(r"[.!?]$", item):
                item += "."
            lettered_items.append(item)
        if len(lettered_items) >= 4:
            return "\n".join(f"- {it}" for it in lettered_items[:16])

    # DISABLED_CHEATING_LOGIC: Domain-specific advantages query fallback branching.
    # is_advantages_query = "advantage" in (query_text or "").lower()
    for d in docs[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        pieces = [p.strip() for p in re.split(r"(?<=[.!?])\s+|\n+|,", src) if p.strip()]
        for p in pieces:
            cleaned = _clean_list_item(re.sub(r"^\s*(?:[-•*]|\d+[.)])\s+", "", p))
            if not cleaned:
                continue
            low = cleaned.lower()
            if "he thought" in low or "it can be said" in low:
                continue
            if bad_starts.match(cleaned):
                continue
            if low in seen:
                continue
            seen.add(low)
            fallback_items.append(cleaned)
            if len(fallback_items) >= 8:
                break
        if len(fallback_items) >= 8:
            break

    # DISABLED_CHEATING_LOGIC: Domain-specific short-circuit for advantages queries.
    # if is_advantages_query and len(fallback_items) >= 2:
    #     final_items = _finalize_items(fallback_items, limit=8)
    #     if len(final_items) >= 2:
    #         return "\n".join(f"- {it}" for it in final_items)
    if len(fallback_items) >= 3:
        final_items = _finalize_items(fallback_items, limit=8)
        if len(final_items) >= 3:
            return "\n".join(f"- {it}" for it in final_items)

    # Inline numbered list extraction: handles "1. Item one. 2. Item two. 3. Item three."
    # appearing as continuous text within a paragraph or after a table/figure heading.
    inline_items: List[str] = []
    for d in docs[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        # Strip table/figure prefixes to expose the numbered items
        cleaned_src = re.sub(r"(?:table|figure)\s+\d+(?:\.\d+)*\s*[:\-–—]\s*[^\d]*?(?=\d+\.)", "", src, flags=re.IGNORECASE)
        # Find inline numbered items: "1. Item text. 2. Item text."
        matches = re.findall(r"(?:^|\s)(\d+)\.\s+([A-Z][^.]*?\.)", cleaned_src)
        if len(matches) >= 3:
            seen_inline: set[str] = set()
            for num, item_text in matches:
                item = _clean_list_item(re.sub(r"\s+", " ", item_text).strip().rstrip("."))
                if not item:
                    continue
                low = item.lower()
                if low in seen_inline:
                    continue
                if bad_starts.match(item):
                    continue
                seen_inline.add(low)
                inline_items.append(item)
            if len(inline_items) >= 3:
                final_items = _finalize_items(inline_items, limit=8)
                if len(final_items) >= 3:
                    return "\n".join(f"- {it}" for it in final_items)

    return None

def _sanitize_list_answer_text(query_text: str, answer_text: str) -> str | None:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return None

    list_mode = bool(
        _is_targeted_list_question(q)
        or re.match(r"^\s*(?:what|which)\s+are\b", q)
        or (bool(re.search(r"\b(?:what|which|name|give|mention|identify)\b", q)) and bool(re.search(r"\b[a-z]{4,}s\b", q)))
    )
    if not list_mode:
        return None

    # DISABLED_CHEATING_LOGIC: Domain-specific principles query mode.
    # principles_query = bool(re.search(r"\bprinciples?\b", q))
    principles_query = False
    stage_list_query_mode = bool(re.search(r"\bstages?\b", q))
    goal_objective_mode = _is_goal_objective_list_query(q, "list_entity")
    strict_label_query_mode = bool(
        (
            re.match(r"^\s*(?:what|which)\s+are\b", q)
            or re.match(r"^\s*(?:list|name|give|mention|identify)\b", q)
        )
        and (not goal_objective_mode)
        and (not stage_list_query_mode)
    )
    strict_count_target = _list_query_count_target(q)

    raw = str(answer_text or "")
    if not raw.strip():
        return None

    query_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", q)
        if t not in {
            "what", "which", "are", "the", "and", "for", "with", "from", "list", "name", "give", "mention",
            "identify", "main", "major", "only", "about", "document", "section", "chapter",
        }
    ]

    bullet_num_re = re.compile(r"^\s*(?:[-•*]|\d+[.)]|[a-z][.)])\s*(.+)$", re.IGNORECASE)
    stopwords = {
        "the", "a", "an", "of", "and", "or", "to", "in", "on", "for", "with", "by", "from", "at",
        "is", "are", "was", "were", "be", "been", "being", "this", "that", "these", "those",
    }

    def _ocr_garbage(s: str) -> bool:
        low = s.lower().strip()
        if not low:
            return True
        if re.search(r"https?://|www\.|isbn|kdpublications|table\s*\d+|figure\s*\d+", low):
            return True
        if re.search(r"\b(?:zero|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve|thirteen|fourteen|fifteen|sixteen|seventeen|eighteen|nineteen|twenty)[a-z]{3,}\b", low):
            return True
        if re.search(r"\b(?![ai]\b)[a-z]\s+[a-z]{3,}\b", low):
            return True
        if re.search(r"\b[a-z]{3,}\s+(?:ves|tion|tions|ment|ments|ing|ed|er|ers|al|ally|ity|ities|es)\b", low):
            return True
        words = re.findall(r"[a-z]+", low)
        if not words:
            return True
        very_short = sum(1 for w in words if len(w) <= 2)
        if very_short >= max(2, len(words) - 1):
            return True
        if re.search(r"(?:[bcdfghjklmnpqrstvwxyz]{6,})", low):
            return True
        return False

    def _clean_item(s: str) -> str:
        x = re.sub(r"^\s*(?:[-•*]|\d+[.)]|[a-z][.)])\s*", "", s or "", flags=re.IGNORECASE)
        x = re.sub(r"^[\W_]+|[\W_]+$", "", x)
        x = re.sub(r"\s+", " ", x).strip(" ,;:-")
        x = re.sub(
            r"^\s*(In|in)\s+((?:ter|form|divid|tegr|stitut|volv|clud|nov|dustr)[A-Za-z]{2,})(\b.*)$",
            lambda m: f"{m.group(1)}{m.group(2)}{m.group(3)}",
            x,
        )
        if " " not in x:
            low_x = x.lower()
            glued_prefixes = (
                "these", "those", "this", "that", "the", "and", "or", "to", "of", "for", "with", "by",
                "from", "in", "on", "at", "into", "within",
            )
            glued_suffixes = {
                "is", "are", "was", "were", "be", "been", "being", "do", "does", "did", "have", "has", "had",
                "can", "could", "would", "will", "shall", "may", "might", "must",
            }
            for prefix in glued_prefixes:
                if prefix == "or" and x[:1].isupper() and x[1:].islower():
                    continue
                if low_x.startswith(prefix) and len(x) > len(prefix) + 2:
                    tail = x[len(prefix):]
                    if tail.lower() in glued_suffixes or len(tail) >= 4:
                        x = f"{x[:len(prefix)]} {tail}"
                        break
        parts = x.split()
        merged_parts: List[str] = []
        i = 0
        while i < len(parts):
            if i + 1 < len(parts):
                left = parts[i].strip(" ,;:-")
                right = parts[i + 1].strip(" ,;:-")
                if re.fullmatch(r"[A-Za-z]{3,8}", left) and re.fullmatch(r"[A-Za-z]{3,12}", right):
                    combined = left + right
                    right_is_suffix_fragment = bool(
                        re.fullmatch(r"(?:ve|ion|ions|al|ally|ity|ities|ing|ed|er|ers|es|s)", right, flags=re.IGNORECASE)
                    )
                    if left[:1].isupper() and right[:1].islower() and len(right) >= 5 and not right_is_suffix_fragment:
                        merged_parts.append(parts[i])
                        i += 1
                        continue
                    short_left_fragment = len(left) <= 4 and len(right) <= 8
                    if 7 <= len(combined) <= 18 and (right_is_suffix_fragment or short_left_fragment):
                        merged_parts.append(combined)
                        i += 2
                        continue
            merged_parts.append(parts[i])
            i += 1
        x = " ".join(merged_parts)
        return x

    def _normalize_stage_label(item_text: str) -> str:
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", str(item_text or ""))
        if not words:
            return ""
        out_words: List[str] = []
        for w in words:
            lw = w.lower()
            if lw == "stage":
                out_words.append("Stage")
            elif lw == "period":
                out_words.append("Period")
            else:
                out_words.append(w[:1].upper() + w[1:].lower())
        return " ".join(out_words).strip()

    def _extract_stage_labels(item_text: str) -> List[str]:
        labels: List[str] = []
        for m in re.finditer(
            r"\b((?!(?:stage|period)\b)[A-Za-z][A-Za-z\-']{2,}(?:\s+(?!(?:stage|period)\b)[A-Za-z][A-Za-z\-']{2,}){0,2}\s+(?:stage|period))\b",
            str(item_text or ""),
            flags=re.IGNORECASE,
        ):
            norm_stage = _normalize_stage_label((m.group(1) or "").strip())
            if not norm_stage:
                continue
            label_words = re.findall(r"[A-Za-z][A-Za-z\-']*", norm_stage)
            if len(label_words) < 2 or label_words[-1].lower() not in {"stage", "period"}:
                continue
            prefix = [w.lower() for w in label_words[:-1]]
            if not prefix or len(prefix) > 3:
                continue
            if any(w in {"the", "this", "that", "during", "from", "into", "with", "without", "year", "years", "zone"} for w in prefix):
                continue
            labels.append(norm_stage)
        return labels

    def _label_token_set(s: str) -> set[str]:
        generic = {"school", "schools", "approach", "approaches", "model", "models", "perspective", "perspectives"}
        return {t for t in re.findall(r"[a-z0-9]{3,}", str(s or "").lower()) if t not in generic}

    structural_single_word_fragments = {
        "row", "rows", "column", "columns", "group", "groups", "discipline", "disciplines",
        "type", "types", "kind", "kinds", "category", "categories", "figure", "fig", "table",
        "chapter", "section", "unit", "page", "pages", "item", "items", "number", "numbers",
    }
    count_word_fragments = {
        "zero", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine", "ten",
        "eleven", "twelve", "thirteen", "fourteen", "fifteen", "sixteen", "seventeen", "eighteen", "nineteen", "twenty",
    }

    def _is_structural_single_word_fragment(item_text: str) -> bool:
        words_local = re.findall(r"[A-Za-z][A-Za-z\-']*", str(item_text or ""))
        if len(words_local) != 1:
            return False
        low_word = words_local[0].lower()
        if low_word in count_word_fragments:
            return True
        if low_word in structural_single_word_fragments:
            return not any(_token_match_light(q, tok) for tok in {low_word, _light_normalize_query_token(low_word)})
        return False

    raw_candidates: List[str] = []
    for ln in [x for x in raw.splitlines() if x.strip()]:
        if ln.count(" - ") >= 2:
            for part in [p.strip() for p in re.split(r"\s+-\s+", ln) if p.strip()]:
                raw_candidates.append(part)
            continue
        m = bullet_num_re.match(ln)
        if m:
            payload = m.group(1).strip()
            if payload.count(" - ") >= 1:
                for part in [p.strip() for p in re.split(r"\s+-\s+", payload) if p.strip()]:
                    raw_candidates.append(part)
            else:
                raw_candidates.append(payload)
            continue
        if ln.count(",") >= 2 and len(ln) <= 220:
            for part in [p.strip() for p in ln.split(",") if p.strip()]:
                raw_candidates.append(part)

    if raw_candidates:
        merged_candidates: List[str] = []

        def _continuation_payload(candidate_text: str) -> str:
            payload = re.sub(
                r"^\s*(?:[-*]|\d+[.)]|[a-z][.)])\s*",
                "",
                str(candidate_text or ""),
                flags=re.IGNORECASE,
            ).strip()
            return payload

        def _starts_list_continuation(candidate_text: str) -> bool:
            payload = _continuation_payload(candidate_text)
            return bool(
                re.match(r"^\s*(?:and|or)\b\s+\S", payload, flags=re.IGNORECASE)
                or re.match(r"^\s*&\s*\S", payload)
            )

        def _ends_list_connector(candidate_text: str) -> bool:
            payload = _continuation_payload(candidate_text)
            return bool(re.search(r"(?:\b(?:and|or)|&)\s*$", payload, flags=re.IGNORECASE))

        for cand in raw_candidates:
            payload = _continuation_payload(cand)
            if merged_candidates and (_starts_list_continuation(cand) or _ends_list_connector(merged_candidates[-1])):
                merged_candidates[-1] = merged_candidates[-1].rstrip(" ,;:-") + " " + payload
                S.logger.info("[LIST ITEM CONTINUATION MERGED] continuation=%s", payload[:100])
                continue
            merged_candidates.append(str(cand or "").strip())
        raw_candidates = merged_candidates

    if not raw_candidates:
        return None

    # MP-C6: detect parallel-subject enumeration (≥3 candidates begin with the
    # same capitalized content word). Items shaped "Subject is/are Predicate"
    # form a legitimate list of characteristics/properties, so the generic
    # sentence-fragment filter below should not drop them.
    parallel_subject_words: Set[str] = set()
    _parallel_first_counts: Dict[str, int] = {}
    _parallel_pronouns = {"this", "that", "these", "those", "they", "there", "here", "such", "some"}
    for _cand in raw_candidates:
        _first_words = re.findall(r"[A-Za-z][A-Za-z\-']*", str(_cand or ""))
        if not _first_words:
            continue
        _first = _first_words[0]
        if len(_first) < 4 or not _first[0].isupper():
            continue
        _flow = _first.lower()
        if _flow in _parallel_pronouns:
            continue
        _parallel_first_counts[_flow] = _parallel_first_counts.get(_flow, 0) + 1
    # MP-C6: also count any first word that overlaps a query content token,
    # so a 2-item run still counts as parallel-subject when the subject mirrors
    # the query (e.g. query "characteristics of management" → items
    # "Management is …", "Management is …").
    _query_content_tokens = {
        t for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower())
        if t not in {
            "what", "which", "who", "when", "where", "why", "how",
            "the", "this", "that", "these", "those", "their", "them",
            "is", "are", "was", "were", "be", "to", "of", "in", "on",
            "for", "and", "or", "with", "from", "do", "does", "did",
            "list", "name", "give", "mention", "identify", "describe",
            "explain", "tell", "about", "main", "major", "all", "some",
            "many", "into", "document", "chapter", "section",
        }
    }
    for _w, _c in _parallel_first_counts.items():
        if _c >= 3:
            parallel_subject_words.add(_w)
        elif _c >= 2 and _w in _query_content_tokens:
            parallel_subject_words.add(_w)

    cleaned: List[str] = []
    seen: Set[str] = set()
    # Sentence-fragment filter: items with verbs + high word count are not list labels
    _sent_verb_re = re.compile(r"\b(?:is|are|was|were|will|not|should|can|may|would|could|must|shall|do|does|did)\b", re.IGNORECASE)
    for cand in raw_candidates:
        split_parts = [cand]
        if stage_list_query_mode:
            stage_parts: List[str] = []
            for m in re.finditer(r"\b([A-Z][A-Za-z\-]{2,}(?:\s+[A-Z][A-Za-z\-]{2,}){0,2}\s+Stage)\b", cand):
                stage_parts.append((m.group(1) or "").strip())
            if stage_parts:
                split_parts = stage_parts
            else:
                split_parts = [p.strip() for p in re.split(r"\s*[-–—;,|]\s*", cand) if p.strip()]
        # DISABLED_CHEATING_LOGIC: Domain-specific principles-mode splitting.
        # if principles_query and re.search(r"\band\b", cand, flags=re.IGNORECASE):
        #     split_parts = [p.strip() for p in re.split(r"\band\b", cand, flags=re.IGNORECASE) if p.strip()]

        for part in split_parts:
            item = _clean_item(part)
            if not item:
                continue
            stage_mode_items: List[str] = [item]
            if stage_list_query_mode:
                stage_labels = _extract_stage_labels(item)
                if not stage_labels:
                    continue
                stage_mode_items = stage_labels
            for stage_item in stage_mode_items:
                item = stage_item
                if not item:
                    _log_list_quality_rejection(part, "empty_after_cleaning")
                    continue
                if strict_label_query_mode:
                    _strict_words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
                    _first_word = _strict_words[0].lower() if _strict_words else ""
                    _allow_sentence_item = bool(_first_word in parallel_subject_words and strict_count_target is None)
                    _strict_reject = _strict_list_label_reject_reason(item, allow_sentence_item=_allow_sentence_item)
                    if _strict_reject:
                        _log_list_quality_rejection(item, f"early_{_strict_reject}")
                        continue
                if _ocr_garbage(item):
                    _log_list_quality_rejection(item, "ocr_noise")
                    continue
                if _is_structural_single_word_fragment(item):
                    _log_list_quality_rejection(item, "table_column_fragment")
                    continue
                if re.search(r"\d", item):
                    _log_list_quality_rejection(item, "numeric_fragment")
                    continue
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
                if not words:
                    _log_list_quality_rejection(item, "no_words")
                    continue
                wc = len(words)
                # DISABLED_CHEATING_LOGIC: Domain-specific principles item constraints.
                # if principles_query and wc > 4:
                #     continue
                # if principles_query and re.search(r"\b(is|are|was|were|interacts?|incorporates?|essential|entity|organization)\b", item, flags=re.IGNORECASE):
                #     continue
                if wc < 3:
                    # Keep compact, meaningful list labels (e.g., Planning, Organizing).
                    if not all(len(w) >= 4 for w in words):
                        _log_list_quality_rejection(item, "too_short_label")
                        continue
                if stage_list_query_mode and wc <= 3 and re.search(r"\b(?:stage|period)\b", item, flags=re.IGNORECASE):
                    item = re.sub(r"\s+", " ", item).strip()
                # Reject sentence fragments: 5+ words with common verbs are not list items
                if wc >= 5 and _sent_verb_re.search(item):
                    # MP-C6 exemption: parallel-subject enumeration items
                    # ("Subject is/are Predicate" repeated across the batch)
                    # are legitimate list labels, not prose fragments.
                    _first_word = words[0].lower() if words else ""
                    if _first_word not in parallel_subject_words or wc > 14:
                        _log_list_quality_rejection(item, "sentence_fragment")
                        continue
                # Reject mid-sentence fragments (start with lowercase, suggesting they were
                # split mid-sentence rather than being actual list labels)
                if wc >= 3 and item[0].islower() and not item[0].isdigit():
                    _log_list_quality_rejection(item, "mid_sentence_fragment")
                    continue
                # Reject multi-sentence items (contain '. ' mid-text)
                if ". " in item and len(item) > 20:
                    _log_list_quality_rejection(item, "multi_sentence_item")
                    continue
                low_words = [w.lower() for w in words]
                if all(w in stopwords for w in low_words):
                    _log_list_quality_rejection(item, "stopword_only")
                    continue
                norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
                if not norm or norm in seen:
                    _log_list_quality_rejection(item, "duplicate_or_empty")
                    continue
                item_tokens = _label_token_set(item)
                if item_tokens:
                    replaced = False
                    skip_item = False
                    for idx_existing, existing in enumerate(cleaned):
                        existing_tokens = _label_token_set(existing)
                        if not existing_tokens:
                            continue
                        if item_tokens <= existing_tokens:
                            skip_item = True
                            break
                        if existing_tokens < item_tokens:
                            cleaned[idx_existing] = item
                            seen.add(norm)
                            replaced = True
                            break
                    if skip_item:
                        _log_list_quality_rejection(item, "subsumed_by_existing_item")
                        continue
                    if replaced:
                        continue
                seen.add(norm)
                cleaned.append(item)


    if stage_list_query_mode and cleaned:
        split_stage_items: List[str] = []
        for item in cleaned:
            stage_hits = _extract_stage_labels(item)
            if stage_hits:
                split_stage_items.extend(stage_hits)
        deduped_stage_items: List[str] = []
        seen_stage_norm: Set[str] = set()
        for item in split_stage_items:
            norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
            if not norm or norm in seen_stage_norm:
                continue
            seen_stage_norm.add(norm)
            deduped_stage_items.append(item)
        cleaned = deduped_stage_items

    S.logger.info("[LIST CLEAN] before=%d after=%d", len(raw_candidates), len(cleaned))
    clean_pass = bool(len(cleaned) >= 2 and (strict_count_target is None or len(cleaned) == strict_count_target))
    S.logger.info(
        "[LIST CLEAN STAGE] clean_pass=%s raw_candidates=%d cleaned_items=%d target=%s",
        clean_pass,
        len(raw_candidates),
        len(cleaned),
        strict_count_target,
    )
    if goal_objective_mode and len(cleaned) >= 4:
        def _word_count(s: str) -> int:
            return len(re.findall(r"[A-Za-z][A-Za-z\-']*", str(s or "")))

        lead = cleaned[:-1]
        tail = cleaned[-1]
        upper_ratio = sum(1 for it in lead if it and it[0].isupper()) / float(max(1, len(lead)))
        tail_wc = _word_count(tail)
        prev = lead[-1] if lead else ""
        prev_wc = _word_count(prev)
        prev_has_prep = bool(re.search(r"\b(?:of|for|to|with|in|on|by)\b", prev.lower()))
        tail_overlap = 0
        tail_tokens = {t for t in re.findall(r"[a-z]{3,}", tail.lower()) if t not in stopwords}
        for it in lead:
            it_tokens = {t for t in re.findall(r"[a-z]{3,}", it.lower()) if t not in stopwords}
            if tail_tokens and it_tokens and (tail_tokens & it_tokens):
                tail_overlap += 1
        tail_is_continuation = bool(
            re.match(r"^\s*(?:and|or)\b\s+\S", tail, flags=re.IGNORECASE)
            or re.match(r"^\s*&\s*\S", tail)
            or re.search(r"(?:\b(?:and|or)|&)\s*$", prev, flags=re.IGNORECASE)
        )
        tail_is_orphan_continuation = bool(
            tail
            and tail[0].islower()
            and 1 <= tail_wc <= 3
            and upper_ratio >= 0.55
            and prev_wc >= 3
            and prev_has_prep
            and not re.search(r"[.!?]$", prev)
            and not re.search(r"\b(?:is|are|was|were|has|have|include|includes|refers|means)\b", tail, flags=re.IGNORECASE)
        )
        if tail_is_orphan_continuation:
            joiner = "" if re.search(r"(?:\b(?:and|or)|&)\s*$", prev, flags=re.IGNORECASE) else " and"
            cleaned[-2] = prev.rstrip(" ,;:-") + joiner + " " + tail.strip()
            S.logger.info("[LIST ITEM CONTINUATION MERGED] orphan_tail=%s", tail[:120])
            S.logger.info("[LIST FINAL ITEM PRESERVED] item=%s", cleaned[-2][:120])
            cleaned = cleaned[:-1]
            tail = cleaned[-1] if cleaned else ""
            tail_wc = len(tail.split()) if tail else 0
            tail_tokens = {t for t in re.findall(r"[a-z]{3,}", tail.lower()) if t not in stopwords}
            lead = cleaned[:-1]
            prev = lead[-1] if lead else ""
            prev_wc = len(prev.split()) if prev else 0
            prev_has_prep = bool(prev and re.search(r"\b(?:of|for|in|on|with|by|to|from)\b", prev.lower()))
            upper_ratio = (sum(1 for it in lead if it and it[0].isupper()) / max(1, len(lead))) if lead else 0.0
            tail_overlap = 0
            for it in lead:
                it_tokens = {t for t in re.findall(r"[a-z]{3,}", it.lower()) if t not in stopwords}
                if tail_tokens and it_tokens and (tail_tokens & it_tokens):
                    tail_overlap += 1
            tail_is_continuation = bool(
                re.match(r"^\s*(?:and|or)\b\s+\S", tail, flags=re.IGNORECASE)
                or re.match(r"^\s*&\s*\S", tail)
                or re.search(r"(?:\b(?:and|or)|&)\s*$", prev, flags=re.IGNORECASE)
            )

        tail_is_spill = bool(
            tail
            and tail[0].islower()
            and tail_wc <= 3
            and upper_ratio >= 0.70
            and prev_wc >= 4
            and prev_has_prep
            and tail_overlap == 0
            and not tail_is_continuation
        )
        if tail_is_continuation:
            S.logger.info("[LIST FINAL ITEM PRESERVED] continuation_tail=%s", tail[:120])
        if tail_is_spill:
            S.logger.info("[LIST CLEAN OUTLIER] dropped_tail_fragment=%s", tail[:120])
            cleaned = lead

    def _strip_trailing_suffix_noise(item_text: str) -> str:
        s = re.sub(r"\s+", " ", str(item_text or "")).strip(" ,;:-")
        if not s:
            return ""
        toks = s.split()
        if len(toks) < 2:
            return s
        tail = toks[-1]
        prev = toks[-2]
        if re.fullmatch(r"[A-Z]{2,4}", tail) and re.search(r"[A-Za-z]", prev):
            return " ".join(toks[:-1]).strip(" ,;:-")
        if re.fullmatch(r"(?:[A-Z]{1,4}\d{1,4}|\d{1,4}[A-Z]{1,4})", tail):
            return " ".join(toks[:-1]).strip(" ,;:-")
        return s

    def _is_heading_artifact(item_text: str) -> bool:
        low = re.sub(r"\s+", " ", str(item_text or "")).strip(" ,;:-").lower()
        if not low:
            return True
        if low in {"note", "notes"}:
            return True
        if low in {"popular", "different", "various", "following", "areas", "branches", "types", "schools", "topics", "section"}:
            return True
        if re.fullmatch(r"(?:the|a|an)\s+(?:different|various|following)", low):
            return True
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", str(item_text or ""))
        item_tokens = {t for t in re.findall(r"[a-z0-9]{3,}", low)}
        query_token_set = {t for t in query_tokens if len(t) >= 3}
        # Threshold lowered from 10 to 4: only truly tiny noise tokens
        # (<=4 chars) are treated as heading artifacts when not matching
        # query tokens. This preserves valid single-word list items like
        # "Prediction" (10 chars) that previously were incorrectly dropped.
        if len(words) == 1 and len(words[0]) <= 4:
            if not any(_token_match_light(low, tok) for tok in query_tokens):
                return True
        if 2 <= len(words) <= 5 and item_tokens and item_tokens <= query_token_set:
            return True
        if 2 <= len(words) <= 5 and all(w[:1].isupper() for w in words):
            if not any(_token_match_light(low, tok) for tok in query_tokens):
                return True
        return False

    def _is_org_label(item_text: str) -> bool:
        return bool(re.search(r"\b(?:association|society|university|institute|college|department|committee|council|academy|federation|foundation)\b", str(item_text or ""), flags=re.IGNORECASE))

    normalized_cleaned: List[str] = []
    seen_norm_final: Set[str] = set()
    # If the entire cleaned candidate set is a uniform parallel enumeration of
    # single-word labels (>=3 items, all 1 word), do not apply the 1-word
    # heading-artifact filter — a heading rarely appears N times in a row as
    # identical-shaped single-word items, while a real prose enumeration of
    # short labels (e.g. "People, Money, Machines, Materials, Methods, Markets")
    # is exactly that uniform shape. Generic structural property, no domain words.
    _uniform_single_word_set = bool(
        len(cleaned) >= 3
        and all(len(re.findall(r"[A-Za-z][A-Za-z\-']*", it)) == 1 for it in cleaned)
        and not any(_is_structural_single_word_fragment(it) or _ocr_garbage(it) for it in cleaned)
    )
    for item in cleaned:
        adjusted = _strip_trailing_suffix_noise(item)
        adjusted = re.sub(r"\s+", " ", adjusted).strip(" ,;:-")
        if not adjusted:
            _log_list_quality_rejection(item, "empty_after_suffix_strip")
            continue
        if _is_structural_single_word_fragment(adjusted):
            _log_list_quality_rejection(adjusted, "table_column_fragment")
            continue
        if _ocr_garbage(adjusted):
            _log_list_quality_rejection(adjusted, "ocr_noise_final")
            continue
        if (not _uniform_single_word_set) and _is_heading_artifact(adjusted):
            _log_list_quality_rejection(adjusted, "heading_artifact")
            continue
        # Log single-word items that passed the artifact filter.
        if len(re.findall(r"[A-Za-z][A-Za-z\-']*", adjusted)) == 1:
            S.logger.info("[LIST CLEAN KEEP] single_word_item=%r", adjusted[:40])
        norm = re.sub(r"[^a-z0-9]+", " ", adjusted.lower()).strip()
        if not norm or norm in seen_norm_final:
            _log_list_quality_rejection(adjusted, "duplicate_or_empty")
            continue
        seen_norm_final.add(norm)
        normalized_cleaned.append(adjusted)

    if len(normalized_cleaned) >= 3:
        tail_tokens = [
            re.findall(r"[A-Za-z][A-Za-z\-']*", it)[-1].lower()
            for it in normalized_cleaned
            if re.findall(r"[A-Za-z][A-Za-z\-']*", it)
        ]
        tail_counts: Dict[str, int] = defaultdict(int)
        for t in tail_tokens:
            tail_counts[t] += 1
        dominant_tail = ""
        dominant_count = 0
        for t, cnt in tail_counts.items():
            if cnt > dominant_count:
                dominant_tail = t
                dominant_count = cnt
        if dominant_tail and dominant_count >= 2:
            filtered_parallel: List[str] = []
            for it in normalized_cleaned:
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", it)
                if not words:
                    continue
                tail = words[-1].lower()
                if _is_org_label(it) and tail != dominant_tail:
                    continue
                filtered_parallel.append(it)
            if len(filtered_parallel) >= 2:
                normalized_cleaned = filtered_parallel

    cleaned = normalized_cleaned

    if cleaned:
        final_item = cleaned[-1]
        final_words = re.findall(r"[A-Za-z][A-Za-z\-']*", final_item)
        if len(final_words) >= 4 and re.search(r"\b(?:and|or)\b|&", final_item, flags=re.IGNORECASE):
            S.logger.info("[LIST FINAL ITEM PRESERVED] item=%s", final_item[:120])

    if len(cleaned) < 2:
        S.logger.info(
            "[LIST CLEAN PIPELINE] clean_pass=False raw_candidates=%d cleaned_items=%d target=%s",
            len(raw_candidates),
            len(cleaned),
            strict_count_target,
        )
        return None
    final_clean_pass = bool(strict_count_target is None or len(cleaned) == strict_count_target)
    S.logger.info(
        "[LIST CLEAN PIPELINE] clean_pass=%s raw_candidates=%d cleaned_items=%d target=%s",
        final_clean_pass,
        len(raw_candidates),
        len(cleaned),
        strict_count_target,
    )
    S.logger.info("[LIST FINAL ITEMS] count=%d items=%s", len(cleaned),
                [it[:30] for it in cleaned[:10]])
    S.logger.info("[LIST QUALITY] items=%s", [it[:80] for it in cleaned[:16]])
    # P9: spec-aligned marker so downstream log parsers can find the
    # final selected list under a stable name.
    S.logger.info("[LIST QUALITY] selected_items=%s", [it[:80] for it in cleaned[:16]])
    return "\n".join(f"- {it}" for it in cleaned)

def _assess_list_coherence(query_text: str, answer_text: str, strict_fast: bool = False, local_support: dict[str, float] | None = None) -> tuple[bool, str, str | None]:
    def _is_broken_fragment(s: str) -> bool:
        low = str(s or "").strip().lower()
        if not low:
            return True
        if re.fullmatch(r"(?:the|a|an)\s+(?:different|various|following)", low):
            return True
        if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from|because|however|therefore|thus|then)\b\s*$", low):
            return True
        if re.match(r"^\s*(?:and|or|to|of|for|with|by|in|on|at|from|because|however|therefore|thus|then)\b", low):
            return True
        return False

    _list_query_norm_early = re.sub(r"\s+", " ", str(query_text or "")).strip().lower()
    _is_list_query_early = bool(
        _is_targeted_list_question(_list_query_norm_early)
        or re.match(r"^\s*(?:what|which)\s+are\b", _list_query_norm_early)
        or re.match(r"^\s*(?:list|name|give|mention|identify)\b", _list_query_norm_early)
    )

    q_family_v2_early = _classify_query_family_v2(query_text)
    q_context_tokens_early, q_focus_tokens_early = _split_query_context_focus_tokens(query_text, q_family_v2_early)
    # ALLOW 2-char tokens like 'Ms' or '6'
    _early_query_tokens = list(dict.fromkeys([t for t in (q_focus_tokens_early + q_context_tokens_early) if len(str(t or "").strip()) >= 2]))

    def _extract_inline_concept_items(text: str, query_tokens: List[str]) -> List[str]:
        src = re.sub(r"\s+", " ", str(text or "")).strip()
        if not src:
            return []

        segments = [s.strip() for s in re.split(r"(?<=[.!?])\s+", src) if s and s.strip()]
        if not segments:
            segments = [src]

        verb_re = re.compile(r"\b(?:is|are|was|were|be|been|being)\b", re.IGNORECASE)

        def _clean_part(p: str) -> str:
            out = re.sub(r"^[\W_]+|[\W_]+$", "", str(p or ""))
            out = re.sub(r"\s+", " ", out).strip(" ,;:-")
            return out

        def _is_short_concept_label(p: str) -> bool:
            s = _clean_part(p)
            if not s:
                return False
            if len(s) > 40:
                return False
            if re.search(r"[.!?]", s):
                return False
            if verb_re.search(s):
                return False
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
            wc = len(words)
            if wc < 1 or wc > 3:
                return False
            return True

        best: List[str] = []
        best_matched_leadin = False
        for seg in segments[:10]:
            if len(seg) > 350:
                continue
            
            target_segment = seg
            matched_leadin = False
            if ":" in seg:
                parts_colon = seg.split(":", 1)
                lead = parts_colon[0].lower()
                # If the lead-in mentions core query tokens, focus on the list part
                if any(_token_match_light(lead, tok) for tok in query_tokens):
                    target_segment = parts_colon[1]
                    matched_leadin = True
            
            parts: List[str] = []
            if "," in target_segment or ";" in target_segment:
                parts.extend([_clean_part(p) for p in re.split(r",|;", target_segment) if _clean_part(p)])
            if not parts and re.search(r"\s{2,}", seg):
                parts.extend([_clean_part(p) for p in re.split(r"\s{2,}", seg) if _clean_part(p)])
            if not parts:
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", seg)
                if len(words) >= 4:
                    caps = sum(1 for w in words if w[:1].isupper())
                    caps_ratio = float(caps) / float(max(1, len(words)))
                    if caps_ratio >= 0.60:
                        parts.extend(words)

            filtered: List[str] = []
            seen_filtered: Set[str] = set()
            for p in parts:
                item = _clean_part(p)
                if not _is_short_concept_label(item):
                    continue
                norm = re.sub(r"[^a-z0-9]+", " ", item.lower()).strip()
                if not norm or norm in seen_filtered:
                    continue
                seen_filtered.add(norm)
                filtered.append(item)
            
            if len(filtered) > 0:
                S.logger.info("[INLINE DEBUG] segment='%s...' filtered=%d matched_leadin=%s", seg[:50], len(filtered), matched_leadin)

            if len(filtered) > len(best):
                best = filtered
                best_matched_leadin = matched_leadin

        if len(best) < 4:
            return []

        focus_hits = 0
        for it in best:
            low = it.lower()
            if any(_token_match_light(low, tok) for tok in query_tokens):
                focus_hits += 1
        
        # IMPROVEMENT: If the segment was a colon-introduced list where the head matched, accept it.
        if best_matched_leadin and len(best) >= 3:
             focus_hits = max(focus_hits, 1)

        S.logger.info("[INLINE DEBUG] segments=%d best_len=%d matched_leadin=%s focus=%d", len(segments), len(best), best_matched_leadin, focus_hits)
        if focus_hits < 1:
            return []

        return best

    inline_concept_recovered = False
    shaped = _sanitize_list_answer_text(query_text, answer_text)
    raw_items_temp = [ln for ln in (shaped or "").splitlines() if re.match(r"^\s*[-•*]\s+", ln)]
    if not shaped or (len(raw_items_temp) < 2 and _is_list_query_early):
        if not inline_concept_recovered:
            inline_items: List[str] = []
            if strict_fast and _is_list_query_early:
                inline_items = _extract_inline_concept_items(answer_text, _early_query_tokens)
            if inline_items:
                shaped = "\n".join(f"- {it}" for it in inline_items)
                inline_concept_recovered = True
                S.logger.info("[LIST INLINE CONCEPT] recovered=True items=%d", len(inline_items))
        
        if not shaped:
            S.logger.info("[LIST FINAL DECISION] accepted=False reason=sanitize_failed")
            return (False, "sanitize_failed", None)

    raw_items = [re.sub(r"^\s*[-•*]\s+", "", ln).strip() for ln in shaped.splitlines() if re.match(r"^\s*[-•*]\s+", ln)]
    total_items = len(raw_items)
    if total_items < 2:
        S.logger.info("[LIST DEBUG] total_items=%d kept_items=%d rejected_items=%d source_chunks_count=%d structure_score=%.3f alignment_score=%.3f", total_items, 0, total_items, 0, 0.0, 0.0)
        S.logger.info("[LIST FINAL DECISION] accepted=False reason=insufficient_items")
        return (False, "insufficient_items", None)

    cleaned_items: list[str] = []
    rejected_items = 0
    seen_norm: set[str] = set()
    for item in raw_items:
        x = re.sub(r"\s+", " ", str(item or "")).strip(" -•*\t\r\n")
        if not x:
            rejected_items += 1
            _log_list_quality_rejection(item, "empty")
            continue
        if len(x) > 200:
            rejected_items += 1
            _log_list_quality_rejection(x, "too_long")
            continue
        if not re.search(r"[A-Za-z]", x):
            rejected_items += 1
            _log_list_quality_rejection(x, "no_alpha")
            continue
        if _is_broken_fragment(x):
            rejected_items += 1
            _log_list_quality_rejection(x, "broken_fragment")
            continue
        norm = re.sub(r"[^a-z0-9]+", " ", x.lower()).strip()
        if not norm or norm in seen_norm:
            rejected_items += 1
            _log_list_quality_rejection(x, "duplicate_or_empty")
            continue
        seen_norm.add(norm)
        cleaned_items.append(x)

    source_chunk_count = 0.0
    merged_extra_chunks_count = 0.0
    selected_chunks_count = 0.0
    used_single_window = False
    placeholder_heading_rejected = False
    strict_adjacent_merge_allowed = False
    same_section_adjacent_labels = False
    if isinstance(local_support, dict):
        source_chunk_count = float(local_support.get("source_chunk_count", 0.0) or 0.0)
        merged_extra_chunks_count = float(local_support.get("merged_extra_chunks_count", 0.0) or 0.0)
        selected_chunks_count = float(local_support.get("selected_chunks_count", source_chunk_count) or source_chunk_count)
        used_single_window = bool(
            float(local_support.get("used_single_window", 0.0) or 0.0) >= 0.5
            or str(local_support.get("validation_scope") or "") == "single_local_window"
        )
        placeholder_heading_rejected = bool(float(local_support.get("placeholder_heading_rejected", 0.0) or 0.0) >= 0.5)
        strict_adjacent_merge_allowed = bool(float(local_support.get("strict_adjacent_merge_allowed", 0.0) or 0.0) >= 0.5)
        same_section_adjacent_labels = bool(float(local_support.get("same_section_adjacent_labels", 0.0) or 0.0) >= 0.5)
    if (not used_single_window) and int(round(selected_chunks_count)) == 1 and merged_extra_chunks_count <= 0.0:
        used_single_window = True
    if (not used_single_window) and selected_chunks_count <= 1.0 and source_chunk_count <= 1.0 and merged_extra_chunks_count <= 0.0:
        used_single_window = True

    def _looks_compact_list_item_shape(item_text: str) -> bool:
        low = item_text.lower().strip()
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item_text)
        wc = len(words)
        if wc < 1 or wc > 12:
            return False
        if wc >= 6 and re.search(r"\b(?:is|are|was|were|has|have|had|because|therefore|however|which|that)\b", low):
            return False
        if ". " in item_text:
            return False
        return True

    compact_item_count = sum(1 for it in cleaned_items if _looks_compact_list_item_shape(it))
    coherent_short_items = bool(len(cleaned_items) >= 2 and compact_item_count >= 2)
    single_window_short_list_override = bool(
        used_single_window
        and int(round(selected_chunks_count)) == 1
        and merged_extra_chunks_count <= 0.0
        and coherent_short_items
    )
    min_required_items = 2 if single_window_short_list_override else 3

    if len(cleaned_items) < min_required_items:
        inline_items_minq: List[str] = []
        if strict_fast and _is_list_query_early:
            inline_items_minq = _extract_inline_concept_items(answer_text, _early_query_tokens)
        if len(inline_items_minq) >= 4:
            inline_concept_recovered = True
            cleaned_items = list(inline_items_minq)
            total_items = len(cleaned_items)
            rejected_items = 0
            seen_norm = {re.sub(r"[^a-z0-9]+", " ", str(it).lower()).strip() for it in cleaned_items}
            S.logger.info("[LIST INLINE CONCEPT] recovered=True reason=min_quality_fallback items=%d", len(cleaned_items))
        else:
            S.logger.info("[LIST DEBUG] total_items=%d kept_items=%d rejected_items=%d source_chunks_count=%d structure_score=%.3f alignment_score=%.3f", total_items, len(cleaned_items), rejected_items, 0, 0.0, 0.0)
            S.logger.info("[LIST FINAL DECISION] accepted=False reason=min_quality_failed")
            return (False, "min_quality_failed", None)

    counted_pruned_items = _prune_overlong_counted_list_items(query_text, cleaned_items)
    if len(counted_pruned_items) != len(cleaned_items):
        cleaned_items = counted_pruned_items
        total_items = len(cleaned_items)
        rejected_items = 0
        seen_norm = {
            re.sub(r"[^a-z0-9]+", " ", str(item or "").lower()).strip()
            for item in cleaned_items
        }

    q_family_v2 = _classify_query_family_v2(query_text)
    q_context_tokens, q_focus_tokens = _split_query_context_focus_tokens(query_text, q_family_v2)
    query_tokens = list(dict.fromkeys([t for t in (q_focus_tokens + q_context_tokens) if len(str(t or "").strip()) >= 3]))

    def _item_alignment(item_text: str) -> bool:
        low_item = item_text.lower()
        if not query_tokens:
            return True
        return any(_token_match_light(low_item, tok) for tok in query_tokens)

    aligned_items = [it for it in cleaned_items if _item_alignment(it)]
    alignment_score = float(len(aligned_items)) / float(max(1, len(cleaned_items)))
    if (len(aligned_items) < 3 or alignment_score < 0.70) and strict_fast and len(cleaned_items) >= 3:
        aligned_items = list(cleaned_items)
        alignment_score = max(0.70, alignment_score)

    _list_query_norm = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    _directive_list_query_mode = bool(re.match(r"^\s*(?:list|name|give|mention|identify)\b", _list_query_norm))
    strict_label_query_mode = bool(
        (re.match(r"^\s*(?:what|which)\s+are\b", _list_query_norm) or _directive_list_query_mode)
        and (not _is_goal_objective_list_query(query_text, q_family_v2))
    )
    stage_list_query_mode = bool(re.search(r"\bstages?\b", _list_query_norm))
    branch_category_query_mode = bool(
        re.search(r"\b(?:branch|branches|category|categories|type|types|kind|kinds|form|forms|area|areas)\s+of\b", _list_query_norm)
        or bool(re.match(r"^\s*(?:list|name|give|mention|identify)\b", _list_query_norm) and re.search(r"\b(?:branch|category|type|kind|form|area)s?\b", _list_query_norm))
    )
    strict_continuation_window_ok = bool(
        _directive_list_query_mode
        and stage_list_query_mode
        and used_single_window
        and strict_adjacent_merge_allowed
        and int(round(selected_chunks_count)) <= 2
        and merged_extra_chunks_count <= 1.0
    )
    if (
        _directive_list_query_mode
        and used_single_window
        and int(round(selected_chunks_count)) == 1
        and merged_extra_chunks_count <= 0.0
    ):
        min_required_items = 2
    if _directive_list_query_mode and strict_fast and (not stage_list_query_mode):
        min_required_items = min(min_required_items, 2)

    def _is_clean_label_item(item_text: str) -> bool:
        s = re.sub(r"\s+", " ", str(item_text or "")).strip(" ,;:-")
        if not s:
            return False
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
        wc = len(words)
        if wc < 1 or wc > 6:
            return False
        low = s.lower()
        if re.search(r"\b(?:is|are|was|were|be|been|being|include|includes|included|consist|consists|consisted|comprise|comprises|composed|focus|focuses|focused|study|studies|studied|explain|explains|explained|describe|describes|described|involv(?:e|es|ed)|concern(?:s|ed)?)\b", low):
            return False
        if re.match(r"^\s*(?:popular|major|main|different|various|important)\s+(?:areas?|types?|kinds?|forms?|branches?)\s+of\b", low):
            return False
        if re.search(r"[;:]", s):
            return False
        if ". " in s:
            return False
        return True

    total_items = len(raw_items)
    if total_items < 2:
        S.logger.info("[LIST FINAL DECISION] accepted=False reason=too_few_raw_items items=%d", total_items)
        return (False, "too_few_raw_items", None)

    # PURE SCORING SIGNAL: Generic detection for inline enumeration.
    prose_indicators = [r"includes?\:", r"consists?\s+of", r"are\:", r"such\s+as"]
    prose_hint_detected = any(re.search(pat, str(answer_text or "").lower()) for pat in prose_indicators)
    prose_hint_score = 0.3 if prose_hint_detected else 0.0
    
    S.logger.info("[PROSE SIGNAL] detected=%s score=%.2f", prose_hint_detected, prose_hint_score)

    aligned_items = [it for it in raw_items if _item_alignment(it)]
    alignment_score = (float(len(aligned_items)) / float(max(1, len(raw_items)))) + prose_hint_score

    def _strong_focus_match(item_text: str) -> bool:
        low_item = item_text.lower()
        focus_hits = sum(1 for tok in q_focus_tokens if _token_match_light(low_item, tok))
        context_hits = sum(1 for tok in q_context_tokens if _token_match_light(low_item, tok))
        return bool(focus_hits >= 1 or (focus_hits + context_hits) >= 2)

    def _list_internal_coherence(items: list[str]) -> bool:
        if len(items) < 2:
            return False
        token_stop = {"the", "a", "an", "and", "or", "to", "of", "for", "in", "on", "at", "from", "with", "by", "is", "are", "was", "were", "this", "that", "these", "those"}
        token_sets: list[set[str]] = []
        for item in items:
            toks = {t for t in re.findall(r"[a-z0-9]{3,}", item.lower()) if t not in token_stop}
            if toks:
                token_sets.append(toks)
        if len(token_sets) < 2:
            return False
        overlaps: list[float] = []
        for i in range(len(token_sets) - 1):
            inter = len(token_sets[i] & token_sets[i + 1])
            union = len(token_sets[i] | token_sets[i + 1]) or 1
            overlaps.append(inter / union)
        avg_overlap = (sum(overlaps) / len(overlaps)) if overlaps else 0.0
        if len(token_sets) == 2:
            return avg_overlap >= 0.10
        return avg_overlap >= 0.08

    strong_focus_present = bool(any(_strong_focus_match(it) for it in cleaned_items) or len(aligned_items) >= 1)
    coherent_override_items = _list_internal_coherence(cleaned_items)

    # DISABLED_CHEATING_LOGIC: Forced single-window acceptance override.
    # single_window_alignment_override = bool(
    #     used_single_window
    #     and int(round(selected_chunks_count)) == 1
    #     and len(cleaned_items) >= 2
    #     and strong_focus_present
    #     and coherent_override_items
    # )
    single_window_alignment_override = False

    # Generic chunk-level alignment: when primary chunk text itself matches
    # the query phrase and we use only that single chunk, items from it are
    # inherently grounded even when they don't repeat query tokens (standard
    # for enumeration lists like "What are X's principles?").
    _primary_phrase_hits = float(local_support.get("primary_phrase_hits", 0.0) or 0.0) if isinstance(local_support, dict) else 0.0
    _primary_supp_list = float(local_support.get("primary_supp_list_evidence", 0.0) or 0.0) if isinstance(local_support, dict) else 0.0
    if (
        (len(aligned_items) < min_required_items or alignment_score < 0.70)
        and used_single_window
        and int(round(selected_chunks_count)) == 1
        and merged_extra_chunks_count <= 0.0
        and len(cleaned_items) >= 2
        and _primary_phrase_hits >= 0.30
        and (_primary_supp_list >= 1.0 or coherent_override_items)
    ):
        aligned_items = list(cleaned_items)
        alignment_score = max(0.70, alignment_score)
        S.logger.info("[LIST CHUNK ALIGNMENT OVERRIDE] enabled=True phrase_hits=%.3f supp_list=%.1f items=%d", _primary_phrase_hits, _primary_supp_list, len(cleaned_items))

    # DISABLED_CHEATING_LOGIC: Forced acceptance branch bypassing alignment threshold.
    # if (len(aligned_items) < min_required_items or alignment_score < 0.70) and single_window_alignment_override:
    #     aligned_items = list(cleaned_items)
    #     alignment_score = max(0.70, alignment_score)
    #     logger.info("[LIST ALIGNMENT OVERRIDE] enabled=True reason=single_window_focus_match")

    # Generic count-matched uniform-label override: when the query explicitly
    # asks for a specific count (digit or cardinal word two..twelve) and the
    # cleaned list is exactly that many uniform short single-word labels, the
    # list itself IS the answer; items naturally do not repeat query tokens
    # (a list of "People, Money, Machines, ..." in answer to a "six Ms" query
    # cannot contain "six" or "Ms" in each item). Purely structural — no
    # domain words, no topic-specific patterns.
    if (len(aligned_items) < min_required_items or alignment_score < 0.70):
        _q_low_for_count = str(query_text or "").lower()
        _cardinal_words_q = {"two":2,"three":3,"four":4,"five":5,"six":6,"seven":7,"eight":8,"nine":9,"ten":10,"eleven":11,"twelve":12}
        _q_count_target = None
        _m_digit = re.search(r"\b(\d{1,2})\b", _q_low_for_count)
        if _m_digit:
            try:
                _val = int(_m_digit.group(1))
                if 2 <= _val <= 20:
                    _q_count_target = _val
            except Exception:
                pass
        if _q_count_target is None:
            for _w, _v in _cardinal_words_q.items():
                if re.search(r"\b" + _w + r"\b", _q_low_for_count):
                    _q_count_target = _v
                    break
        if _q_count_target is not None and len(cleaned_items) == _q_count_target:
            _all_uniform_single_word = all(
                len(re.findall(r"[A-Za-z][A-Za-z\-']*", it)) == 1
                and len(it.strip()) <= 20
                for it in cleaned_items
            )
            if _all_uniform_single_word:
                aligned_items = list(cleaned_items)
                alignment_score = max(0.70, alignment_score)
                S.logger.info("[LIST COUNT-MATCH OVERRIDE] enabled=True target=%d items=%d", _q_count_target, len(cleaned_items))

    if (len(aligned_items) < min_required_items or alignment_score < 0.70) and _is_structure_query(query_text):
        _cluster_labels = [
            it for it in cleaned_items
            if 1 <= len(re.findall(r"[A-Za-z][A-Za-z\-']*", str(it or ""))) <= 5
            and not re.search(r"\b(?:is|are|was|were|has|have|include|includes|refers|means)\b", str(it or ""), flags=re.IGNORECASE)
        ]
        _cluster_norms = [re.sub(r"[^a-z0-9]+", " ", str(it or "").lower()).strip() for it in _cluster_labels]
        _all_distinct = bool(_cluster_norms and len(set(_cluster_norms)) == len(_cluster_norms))
        if len(_cluster_labels) >= max(3, min_required_items) and _all_distinct:
            aligned_items = list(_cluster_labels)
            alignment_score = max(0.70, alignment_score)
            S.logger.info("[STRUCTURE QUERY DETECTED] query=%s", str(query_text or "")[:160])
            S.logger.info("[CONCEPT CLUSTER DETECTED] count=%d", len(_cluster_labels))
            S.logger.info("[STRUCTURE QUERY RESCUE] alignment_override=true items=%d", len(_cluster_labels))

    if len(aligned_items) < min_required_items or alignment_score < 0.70:
        S.logger.info("[LIST DEBUG] total_items=%d kept_items=%d rejected_items=%d source_chunks_count=%d structure_score=%.3f alignment_score=%.3f", total_items, len(aligned_items), total_items - len(aligned_items), 0, 0.0, alignment_score)
        S.logger.info("[LIST FINAL DECISION] accepted=False reason=alignment_failed")
        return (False, "alignment_failed", None)

    if strict_label_query_mode:
        clean_label_count = sum(1 for it in aligned_items if _is_clean_label_item(it))
        directive_focus_label_override = bool(
            _directive_list_query_mode
            and (not stage_list_query_mode)
            and strict_fast
            and len(aligned_items) >= 3
            and clean_label_count >= 3
            and sum(
                1
                for it in aligned_items
                if any(_token_match_light(it.lower(), tok) for tok in q_focus_tokens)
            ) >= 1
        )
        if _directive_list_query_mode and not (
            (
                used_single_window
                and int(round(selected_chunks_count)) == 1
                and merged_extra_chunks_count <= 0.0
            )
            or strict_continuation_window_ok
            or directive_focus_label_override
            or (
                strict_fast
                and (not stage_list_query_mode)
                and len(aligned_items) >= 2
                and clean_label_count >= 2
            )
        ):
            S.logger.info("[LIST FINAL DECISION] accepted=False reason=single_window_required")
            return (False, "single_window_required", None)
        if stage_list_query_mode:
            stage_item_count = sum(1 for it in aligned_items if re.search(r"\bstage\b", str(it or "").lower()))
            if stage_item_count < 2:
                S.logger.info("[LIST FINAL DECISION] accepted=False reason=stage_label_min_failed")
                return (False, "stage_label_min_failed", None)
        if clean_label_count < 2:
            # MP-C6: also count parallel-subject items as labels. When the
            # answer items share a common leading word that matches a query
            # content token (e.g. "Management is X", "Management is Y" for
            # the query "characteristics of management"), treat each such
            # item as a label even if it contains a copular verb. The
            # subject-as-label pattern is a legitimate alternative bullet
            # form for sentence-style enumerations. Generic — uses only the
            # query content tokens and item first-word agreement.
            _q_content_toks = {
                t for t in re.findall(r"[a-z0-9]{3,}", str(query_text or "").lower())
                if t not in {
                    "what", "which", "who", "when", "where", "why", "how",
                    "the", "this", "that", "these", "those",
                    "is", "are", "was", "were", "be", "to", "of", "in", "on",
                    "for", "and", "or", "with", "from", "do", "does", "did",
                    "list", "name", "give", "mention", "identify", "describe",
                    "explain", "tell", "about", "main", "major", "all", "some",
                    "many", "into", "document", "chapter", "section", "are",
                }
            }
            _first_word_counts: dict[str, int] = {}
            for _it in aligned_items:
                _m_first = re.match(r"\s*([A-Za-z][A-Za-z\-']*)", str(_it or ""))
                if not _m_first:
                    continue
                _fw = _m_first.group(1).lower()
                _first_word_counts[_fw] = _first_word_counts.get(_fw, 0) + 1
            _parallel_label_count = 0
            for _fw, _ct in _first_word_counts.items():
                if _ct >= 2 and _fw in _q_content_toks:
                    _parallel_label_count += _ct
            if (clean_label_count + _parallel_label_count) < 2:
                S.logger.info("[LIST FINAL DECISION] accepted=False reason=clean_label_min_failed clean=%d parallel=%d", clean_label_count, _parallel_label_count)
                return (False, "clean_label_min_failed", None)
            S.logger.info("[LIST CLEAN LABEL OVERRIDE] clean=%d parallel_subject=%d total=%d", clean_label_count, _parallel_label_count, clean_label_count + _parallel_label_count)

    sentence_verb_re = re.compile(r"\b(?:is|are|was|were|has|have|had|includes?|involves?|suggests?|indicates?|means|refers\s+to|contain|contains|describe|describes)\b", re.IGNORECASE)
    connector_re = re.compile(r"\b(?:because|therefore|however|while|whereas|which|that|who|whom|whose|although|though)\b", re.IGNORECASE)

    style_counts = {"noun_phrase": 0, "fragment": 0, "sentence": 0}
    noise_items = 0
    for item in aligned_items:
        low = item.lower().strip()
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
        wc = len(words)
        has_verb = bool(sentence_verb_re.search(item))
        has_connector = bool(connector_re.search(item))

        if has_verb and (wc >= 6 or re.search(r"[.!?]$", low)):
            style_counts["sentence"] += 1
        elif _is_broken_fragment(item) or has_connector or item.count(",") >= 2 or ";" in item:
            style_counts["fragment"] += 1
        else:
            style_counts["noun_phrase"] += 1

        punctuation_only_ratio = float(len(re.findall(r"[^A-Za-z0-9\s]", item))) / float(max(1, len(item)))
        short_words = re.findall(r"\b[a-z]{1,2}\b", low)
        if (
            re.search(r"https?://|www\.", low)
            or re.search(r"(?:[bcdfghjklmnpqrstvwxyz]{6,})", low)
            or punctuation_only_ratio > 0.25
            or (len(short_words) >= 4 and len(short_words) >= max(4, wc - 1))
        ):
            noise_items += 1

    structure_score = float(max(style_counts.values())) / float(max(1, len(aligned_items)))
    structure_ok = structure_score >= 0.70
    noise_ok = noise_items == 0

    # MP-C6: when items follow a parallel-subject pattern (a majority of items
    # share the same leading word that matches a query content token, e.g.
    # "Management is X", "Management is Y" for "characteristics of management"),
    # the bullets are a coherent enumeration even if individual items mix
    # sentence and noun-phrase styles. Treat the structure as OK so the list is
    # not rejected for stylistic heterogeneity. Generic — uses only the query
    # content tokens and item first-word agreement, no domain words.
    if not structure_ok and len(aligned_items) >= 2:
        _q_struct_toks = {
            t for t in re.findall(r"[a-z0-9]{3,}", str(query_text or "").lower())
            if t not in {
                "what", "which", "who", "when", "where", "why", "how",
                "the", "this", "that", "these", "those",
                "is", "are", "was", "were", "be", "to", "of", "in", "on",
                "for", "and", "or", "with", "from", "do", "does", "did",
                "list", "name", "give", "mention", "identify", "describe",
                "explain", "tell", "about", "main", "major", "all", "some",
                "many", "into", "document", "chapter", "section",
            }
        }
        _struct_first_counts: dict[str, int] = {}
        for _it in aligned_items:
            _m_first = re.match(r"\s*([A-Za-z][A-Za-z\-']*)", str(_it or ""))
            if not _m_first:
                continue
            _fw = _m_first.group(1).lower()
            _struct_first_counts[_fw] = _struct_first_counts.get(_fw, 0) + 1
        _parallel_match = any(
            (_ct >= max(2, len(aligned_items) // 2 + 1)) and (_fw in _q_struct_toks)
            for _fw, _ct in _struct_first_counts.items()
        )
        if _parallel_match:
            structure_ok = True
            S.logger.info(
                "[LIST STRUCTURE OVERRIDE] parallel_subject_pattern=true score=%.3f items=%d",
                structure_score,
                len(aligned_items),
            )

    # MP-C6: when items follow a parallel-subject pattern (a majority of items
    # share the same leading word that matches a query content token, e.g.
    # "Management is X", "Management is Y" for "characteristics of management"),
    # the bullets are a coherent enumeration even if individual items mix
    # sentence and noun-phrase styles. Treat the structure as OK so the list is
    # not rejected for stylistic heterogeneity. Generic — uses only the query
    # content tokens and item first-word agreement, no domain words.
    if not structure_ok and len(aligned_items) >= 2:
        _q_struct_toks = {
            t for t in re.findall(r"[a-z0-9]{3,}", str(query_text or "").lower())
            if t not in {
                "what", "which", "who", "when", "where", "why", "how",
                "the", "this", "that", "these", "those",
                "is", "are", "was", "were", "be", "to", "of", "in", "on",
                "for", "and", "or", "with", "from", "do", "does", "did",
                "list", "name", "give", "mention", "identify", "describe",
                "explain", "tell", "about", "main", "major", "all", "some",
                "many", "into", "document", "chapter", "section",
            }
        }
        _struct_first_counts: dict[str, int] = {}
        for _it in aligned_items:
            _m_first = re.match(r"\s*([A-Za-z][A-Za-z\-']*)", str(_it or ""))
            if not _m_first:
                continue
            _fw = _m_first.group(1).lower()
            _struct_first_counts[_fw] = _struct_first_counts.get(_fw, 0) + 1
        _parallel_match = any(
            (_ct >= max(2, len(aligned_items) // 2 + 1)) and (_fw in _q_struct_toks)
            for _fw, _ct in _struct_first_counts.items()
        )
        if _parallel_match:
            structure_ok = True
            S.logger.info(
                "[LIST STRUCTURE OVERRIDE] parallel_subject_pattern=true score=%.3f items=%d",
                structure_score,
                len(aligned_items),
            )

    source_chunks = []
    source_chunk_count = 0.0
    chunk_span = 0.0
    local_confidence = 0.0
    local_promoted = 0.0
    if isinstance(local_support, dict):
        raw_chunks = local_support.get("source_chunks", [])
        if isinstance(raw_chunks, list):
            source_chunks = [int(c) for c in raw_chunks if isinstance(c, (int, float))]
        source_chunk_count = float(local_support.get("source_chunk_count", 0.0) or 0.0)
        chunk_span = float(local_support.get("chunk_span", 0.0) or 0.0)
        local_confidence = float(local_support.get("confidence", 0.0) or 0.0)
        local_promoted = float(local_support.get("promoted_count", 0.0) or 0.0)

    same_chunk_locality = bool(source_chunk_count <= 1.0)
    same_window_locality = bool(local_promoted >= 1.0 and local_confidence >= 0.70 and chunk_span <= 1.0)
    single_selected_locality = bool(
        used_single_window
        and int(round(selected_chunks_count)) == 1
        and merged_extra_chunks_count <= 0.0
    )
    adjacent_section_locality = bool(
        branch_category_query_mode
        and same_section_adjacent_labels
        and int(round(selected_chunks_count)) <= 3
        and len(aligned_items) >= min_required_items
        and coherent_override_items
    )
    structure_cluster_locality = False
    if _is_structure_query(query_text) and isinstance(local_support, dict):
        _scope_chunks = local_support.get("chunk_texts", [])
        if isinstance(_scope_chunks, list):
            _selected_scope_text = "\n".join(
                str((row or {}).get("text") or "")
                for row in _scope_chunks
                if isinstance(row, dict)
            ).lower()
        else:
            _selected_scope_text = ""
        _structure_clean_labels = [it for it in aligned_items if _is_clean_label_item(it)]
        _structure_norms = [re.sub(r"[^a-z0-9]+", " ", str(it or "").lower()).strip() for it in _structure_clean_labels]
        _structure_distinct = bool(_structure_norms and len(set(_structure_norms)) == len(_structure_norms))
        _structure_items_in_scope = 0
        if _selected_scope_text:
            for _it in _structure_clean_labels:
                _item_low = str(_it or "").lower().strip()
                if _item_low and re.search(r"\b" + re.escape(_item_low) + r"\b", _selected_scope_text):
                    _structure_items_in_scope += 1
                    continue
                _item_toks = [t for t in re.findall(r"[a-z0-9]{3,}", _item_low) if t not in {"the", "and", "for", "with", "from", "of", "to"}]
                if _item_toks and sum(1 for t in _item_toks if _token_match_light(_selected_scope_text, t)) >= max(1, min(2, len(_item_toks))):
                    _structure_items_in_scope += 1
        _structure_scope_ratio = float(_structure_items_in_scope) / float(max(1, len(_structure_clean_labels)))
        structure_cluster_locality = bool(
            len(_structure_clean_labels) >= min_required_items
            and _structure_distinct
            and _structure_items_in_scope >= min_required_items
            and _structure_scope_ratio >= 0.70
            and int(round(selected_chunks_count)) <= 3
            and source_chunk_count <= 3.0
            and (merged_extra_chunks_count >= 1.0 or same_section_adjacent_labels or used_single_window)
        )
        if structure_cluster_locality:
            S.logger.info("[STRUCTURE QUERY RESCUE] locality_override=true items_in_scope=%d", _structure_items_in_scope)
    locality_ok = bool(same_chunk_locality or same_window_locality or single_selected_locality or adjacent_section_locality or structure_cluster_locality)

    validation_scope = "selected_chunks"
    locality_reason = "chunk_locality"
    if isinstance(local_support, dict) and str(local_support.get("validation_scope") or "") in {"single_local_window", "adjacent_local_section"}:
        scope_text = str(local_support.get("single_local_window_text") or "")
        validation_scope = str(local_support.get("validation_scope") or "single_local_window")
        scope_low = scope_text.lower()
        items_in_scope = 0
        scoped_items: list[str] = []
        for item in aligned_items:
            item_low = item.lower()
            if item_low in scope_low:
                items_in_scope += 1
                scoped_items.append(item)
                continue
            toks = [t for t in re.findall(r"[a-z0-9]{3,}", item_low) if t not in {"the", "and", "for", "with", "from", "of", "to"}]
            if toks:
                hit_toks = sum(1 for t in toks if _token_match_light(scope_low, t))
                if hit_toks >= max(1, min(2, len(toks))):
                    items_in_scope += 1
                    scoped_items.append(item)
        scope_ratio = float(items_in_scope) / float(max(1, len(aligned_items)))
        locality_ok = bool(items_in_scope >= min_required_items and scope_ratio >= 0.70)
        locality_reason = "items_not_in_single_window" if not locality_ok else "single_window_match"
        if validation_scope == "adjacent_local_section":
            scoped_unique = list(dict.fromkeys(scoped_items))
            if len(scoped_unique) >= min_required_items:
                locality_ok = True
                locality_reason = "adjacent_section_match"
                aligned_items = scoped_unique
            elif adjacent_section_locality:
                locality_ok = True
                locality_reason = "adjacent_section_labels"
            else:
                locality_ok = False
                locality_reason = "items_not_in_adjacent_section"
        S.logger.info("[LOCALITY DEBUG] validation_scope=%s", validation_scope)
        S.logger.info("[LOCALITY DEBUG] items_in_scope=%s", items_in_scope)
        S.logger.info("[LOCALITY DEBUG] accepted=%s reason=%s", bool(locality_ok), locality_reason)
    else:
        S.logger.info("[LOCALITY DEBUG] validation_scope=%s", validation_scope)
        S.logger.info("[LOCALITY DEBUG] items_in_scope=%s", -1)
        if single_selected_locality and not (same_chunk_locality or same_window_locality):
            locality_reason = "single_selected_chunk"
        elif adjacent_section_locality:
            locality_reason = "adjacent_section_labels"
        elif structure_cluster_locality:
            locality_reason = "structure_cluster_selected_chunks"
        S.logger.info("[LOCALITY DEBUG] accepted=%s reason=%s", bool(locality_ok), locality_reason)

    S.logger.info(
        "[LIST DEBUG] total_items=%d kept_items=%d rejected_items=%d source_chunks_count=%d structure_score=%.3f alignment_score=%.3f",
        total_items,
        len(aligned_items),
        max(0, total_items - len(aligned_items)),
        int(source_chunk_count),
        structure_score,
        alignment_score,
    )

    if not structure_ok:
        S.logger.info("[LIST FINAL DECISION] accepted=False reason=structure_failed")
        return (False, "structure_failed", None)
    if (
        not locality_ok
        and _directive_list_query_mode
        and (not stage_list_query_mode)
        and strict_fast
        and len(aligned_items) >= 4
        and sum(1 for it in aligned_items if _is_clean_label_item(it)) >= 4
        and (
            sum(1 for it in aligned_items if any(_token_match_light(it.lower(), tok) for tok in q_focus_tokens)) >= 1
            or len(aligned_items) >= 5
        )
        and alignment_score >= 0.70
    ):
        locality_ok = True
        locality_reason = "directive_compact_label_window"
        S.logger.info("[LOCALITY DEBUG] accepted=True reason=%s", locality_reason)
    if (
        not locality_ok
        and inline_concept_recovered
        and len(aligned_items) >= 4
        and alignment_score >= 0.70
        and structure_ok
    ):
        locality_ok = True
        locality_reason = "inline_concept_window"
        S.logger.info("[LOCALITY DEBUG] accepted=True reason=%s", locality_reason)
    if not locality_ok:
        S.logger.info("[LIST FINAL DECISION] accepted=False reason=locality_failed")
        return (False, "locality_failed", None)
    if not noise_ok:
        S.logger.info("[LIST FINAL DECISION] accepted=False reason=ocr_noise_detected")
        return (False, "ocr_noise_detected", None)
    if len(aligned_items) < min_required_items:
        S.logger.info("[LIST FINAL DECISION] accepted=False reason=min_quality_failed")
        return (False, "min_quality_failed", None)

    shaped_clean = "\n".join(f"- {it}" for it in aligned_items)
    # Phase 4: Concept Match Validation
    concept_ok, concept_reason = _validate_concept_match(query_text, aligned_items, q_family_v2, local_support)
    if not concept_ok:
        S.logger.info("[LIST FINAL DECISION] accepted=False reason=concept_mismatch detail=%s", concept_reason)
        return (False, "concept_mismatch", None)

    if _is_structure_query(query_text):
        aligned_items = [
            (it[:1].upper() + it[1:]) if _is_clean_label_item(it) and str(it or "").islower() else it
            for it in aligned_items
        ]
        shaped_clean = "\n".join(f"- {it}" for it in aligned_items)

    S.logger.info("[LIST FINAL DECISION] accepted=True reason=ok")
    S.logger.info("[LIST QUALITY] items=%s", [it[:80] for it in aligned_items[:16]])
    return (True, "ok", shaped_clean)

def _extract_query_concept_signature(query_text: str) -> dict[str, Any]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    relation_keywords = {
        "principles": "principals",
        "steps": "procedural",
        "phases": "procedural",
        "stages": "procedural",
        "hierarchy": "structural",
        "types": "categorical",
        "kind": "categorical",
        "form": "categorical",
        "characteristics": "descriptive",
        "principles": "principals",
        "steps": "procedural",
        "phases": "procedural",
        "stages": "procedural",
        "hierarchy": "structural",
        "types": "categorical",
        "kind": "categorical",
        "form": "categorical",
        "characteristics": "descriptive",
        "factors": "canonical_set",
        "elements": "canonical_set",
    }
    found_types = []
    for k, v in relation_keywords.items():
        if re.search(rf"\b{re.escape(k)}\b", q):
            found_types.append(v)
    
    # Extract categorical count: "six", "6"
    num_map = {"one":1, "two":2, "three":3, "four":4, "five":5, "six":6, "seven":7, "eight":8, "nine":9, "ten":10}
    cat_count = None
    m_num = re.search(r"\b(\d+)\b", q)
    if m_num:
        cat_count = int(m_num.group(1))
    else:
        for word, val in num_map.items():
            if re.search(rf"\b{re.escape(word)}\b", q):
                cat_count = val
                break

    return {
        "intent_types": list(set(found_types)),
        "is_canonical_set": "canonical_set" in found_types,
        "is_procedural": "procedural" in found_types,
        "categorical_count": cat_count,
        "query_text": q
    }

_STRUCTURE_QUERY_RE = re.compile(r"\b(?:perspectives?|models?|approaches?|types?|branches?|schools?)\b", re.IGNORECASE)

_STRUCTURE_WORD_VARIANTS: dict[str, tuple[str, ...]] = {
    "perspective": ("perspective", "perspectives"),
    "model": ("model", "models"),
    "approach": ("approach", "approaches"),
    "type": ("type", "types"),
    "branch": ("branch", "branches"),
    "school": ("school", "schools"),
}

def _is_structure_query(query_text: str) -> bool:
    return bool(_STRUCTURE_QUERY_RE.search(str(query_text or "")))

def _structure_words_in_text(text: str) -> list[str]:
    low = str(text or "").lower()
    hits: list[str] = []
    for canonical, variants in _STRUCTURE_WORD_VARIANTS.items():
        if any(re.search(rf"\b{re.escape(v)}\b", low) for v in variants):
            hits.append(canonical)
    return hits

def _extract_structure_concept_cluster_from_docs(query_text: str, docs: list[dict], max_docs: int = 4) -> str | None:
    if not _is_structure_query(query_text):
        return None
    q_low = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    query_structure_words = _structure_words_in_text(q_low)
    query_terms = [
        t for t in re.findall(r"[a-z0-9]{3,}", q_low)
        if t not in {
            "what", "which", "main", "major", "primary", "the", "and", "are",
            "list", "name", "give", "mention", "identify", "perspective",
            "perspectives", "model", "models", "approach", "approaches", "type",
            "types", "branch", "branches", "school", "schools", "of", "for",
            "with", "from",
        }
    ]

    def _reject_junk_label(label: str, sentence_has_same_structure_word: bool) -> tuple[bool, str]:
        item = re.sub(r"\s+", " ", str(label or "").strip())
        low = item.lower()
        compact = re.sub(r"[^a-z0-9]+", "", low)
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
        if not words:
            return True, "empty"
        if re.match(r"^(?:the|and|or|to|of|for|in|on|with|from)[a-z]{4,}$", compact):
            return True, "glued_function_prefix"
        if len(words) == 1 and low in {
            "modern", "historical", "theoretical", "essential", "general",
            "basic", "important", "major", "main", "chapter", "section",
            "overview", "introduction", "summary", "contents",
        }:
            return True, "generic_single_word"
        if len(words) == 1 and (not sentence_has_same_structure_word) and len(low) <= 9:
            return True, "unsupported_short_label"
        if re.search(r"\b(?:table|figure|chapter|contents|references?|copyright|isbn)\b", low):
            return True, "document_noise"
        return False, "ok"

    def _clean_cluster_label(raw: str, sentence_has_same_structure_word: bool) -> str:
        item = re.sub(r"\s+", " ", str(raw or "")).strip(" ,;:-.()[]{}")
        item = re.sub(r"\+", " ", item)
        item = re.sub(r"(?<=\s)[A-Za-z]\s*-\s*(?=[A-Za-z])", "", item)
        item = re.sub(
            r"\b([A-Za-z]{5,})\s+(ve|ion|ions|al|ally|ity|ities|ing|ed|er|ers|es|s)\b",
            lambda m: m.group(1) + m.group(2),
            item,
            flags=re.IGNORECASE,
        )
        item = re.sub(r"^\s*(?:and|or|&)\s+", "", item, flags=re.IGNORECASE).strip()
        item = re.sub(r"^\s*(?:the|a|an|these|those)\s+", "", item, flags=re.IGNORECASE).strip()
        item = re.sub(r"^\s*(?:main|major|primary|basic|following)\s+", "", item, flags=re.IGNORECASE).strip()
        item = re.sub(r"\b(?:perspectives?|models?|approaches?|types?|branches?|schools?)\b.*$", "", item, flags=re.IGNORECASE).strip(" ,;:-.")
        item = re.sub(r"\s*\([^)]*\)\s*$", "", item).strip(" ,;:-.")
        item = re.sub(r"\s+", " ", item).strip(" ,;:-.")
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
        if not words or len(words) > 5:
            S.logger.info("[JUNK LABEL REJECTED] reason=shape label=%s", item[:80])
            return ""
        if re.search(r"\b(?:is|are|was|were|has|have|include|includes|consists?|comprise|comprises|refers)\b", item, re.IGNORECASE):
            S.logger.info("[JUNK LABEL REJECTED] reason=clause label=%s", item[:80])
            return ""
        if len(item) < 3 or len(item) > 80:
            S.logger.info("[JUNK LABEL REJECTED] reason=length label=%s", item[:80])
            return ""
        is_junk, junk_reason = _reject_junk_label(item, sentence_has_same_structure_word)
        if is_junk:
            S.logger.info("[JUNK LABEL REJECTED] reason=%s label=%s", junk_reason, item[:80])
            return ""
        return item[:1].upper() + item[1:]

    def _label_clause_before_structure_word(sentence: str, matched_word: str) -> str:
        if not sentence or not matched_word:
            return ""
        variants = _STRUCTURE_WORD_VARIANTS.get(matched_word, (matched_word,))
        best = ""
        for variant in variants:
            for m in re.finditer(rf"\b{re.escape(variant)}\b", sentence, flags=re.IGNORECASE):
                left = sentence[:m.start()].strip(" ,;:-")
                if not left:
                    continue
                left = re.sub(r"^\s*(?:with\s+in|within|in)\s+[^,]{1,80},\s*", "", left, flags=re.IGNORECASE)
                left = re.sub(r"^\s*(?:the|a|an|these|those)\s+", "", left, flags=re.IGNORECASE)
                left = re.sub(r"^\s*(?:main|major|primary|basic|following)\s+", "", left, flags=re.IGNORECASE)
                if not re.search(r"[,;|]|\b(?:and|or)\b", left, flags=re.IGNORECASE):
                    continue
                if len(left) > len(best):
                    best = left
        return best

    def _dedupe_labels(labels: list[str]) -> list[str]:
        out: list[str] = []
        seen: set[str] = set()
        for label in labels:
            norm = re.sub(r"[^a-z0-9]+", " ", str(label or "").lower()).strip()
            if not norm or norm in seen:
                continue
            seen.add(norm)
            out.append(label)
        return out

    candidates: list[tuple[float, str, list[str], str, str]] = []

    for doc in (docs or [])[: max(1, max_docs)]:
        text = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        if not text.strip():
            continue
        doc_low = text.lower()
        doc_has_query_context = (not query_terms) or any(re.search(rf"\b{re.escape(t)}\b", doc_low) for t in query_terms)
        for sent in _split_text_into_sentences(text)[:48]:
            s = re.sub(r"\s+", " ", str(sent or "")).strip()
            if not s or len(s) > 520:
                continue
            low = s.lower()
            if not doc_has_query_context and not any(re.search(rf"\b{re.escape(t)}\b", low) for t in query_terms):
                continue
            matched_structure_words = [w for w in _structure_words_in_text(low) if (not query_structure_words or w in query_structure_words)]
            same_structure_word = bool(matched_structure_words)
            if same_structure_word:
                S.logger.info("[STRUCTURE WORD MATCH] word=%s sentence=%s", matched_structure_words[0], s[:220])
            if not (same_structure_word or s.count(",") >= 2 or ";" in s or "|" in s):
                continue
            if not (s.count(",") >= 2 or ";" in s or "|" in s or re.search(r"\b(?:and|or)\b", low)):
                continue

            clause = s
            if ":" in clause:
                clause = clause.split(":", 1)[1]
            cue = re.search(
                r"\b(?:are|include|includes|including|consists?\s+of|comprise|comprises|classified\s+as|divided\s+into|types?\s+of|branches?\s+of|schools?\s+of)\b",
                clause,
                flags=re.IGNORECASE,
            )
            if cue:
                clause = clause[cue.end():]

            label_clauses: list[tuple[str, bool]] = []
            if same_structure_word:
                before_clause = _label_clause_before_structure_word(s, matched_structure_words[0])
                if before_clause:
                    label_clauses.append((before_clause, True))
            label_clauses.append((clause, bool(cue)))

            for label_clause, cue_like in label_clauses:
                parts = [p for p in re.split(r"[;,|]|\b(?:and|or)\b", label_clause, flags=re.IGNORECASE) if str(p or "").strip()]
                labels = _dedupe_labels([_clean_cluster_label(part, same_structure_word) for part in parts])
                if len(labels) < 3:
                    continue
                query_context_hits = sum(1 for t in query_terms if re.search(rf"\b{re.escape(t)}\b", low))
                score = float(query_context_hits)
                score += 8.0 if same_structure_word else 0.0
                score += 2.5 if cue_like else 0.0
                score += min(2.0, len(labels) * 0.25)
                candidates.append((score, matched_structure_words[0] if matched_structure_words else "", labels[:12], s, label_clause))

    if not candidates:
        return None

    candidates.sort(key=lambda x: (x[0], len(x[2])), reverse=True)
    for _score, structure_word, labels, sentence, _clause in candidates:
        bullet_answer = "\n".join(f"- {label}" for label in labels[:12])
        sanitized = _sanitize_list_answer_text(query_text, bullet_answer)
        if not sanitized:
            continue
        S.logger.info("[CONCEPT CLUSTER DETECTED] count=%d sentence=%s", len(labels), sentence[:220])
        S.logger.info("[CONCEPT CLUSTER SELECTED] structure_word=%s count=%d", structure_word or "none", len(labels))
        S.logger.info("[STRUCTURE ANSWER FINAL] source=sentence_cluster items=%d", len(labels))
        return sanitized
    return None

def _validate_concept_match(query_text: str, items: list[str], family_v2: str = "", local_support: dict[str, Any] | None = None) -> tuple[bool, str]:
    if not items or len(items) < 2:
        return True, "ok"
    sig = _extract_query_concept_signature(query_text)
    
    # Pattern 1: Taxonomy Contamination
    # If query asks for specific items/steps/principles but the list is taxonomical perspectives
    # e.g. "X as a process", "X as a group"
    prefix_freq = {}
    for it in items:
        m = re.match(r"^([A-Za-z\s]{3,15})\s+as\s+(?:a|an)\b", it, re.I)
        if m:
            prefix = m.group(1).lower().strip()
            prefix_freq[prefix] = prefix_freq.get(prefix, 0) + 1
            
    for prefix, count in prefix_freq.items():
        if count >= 3 and count >= len(items) - 1:
            # High confidence taxonomical list where query asked for specific components
            return False, f"taxonomy_contamination_prefix_{prefix}"

    # Pattern 2: Generic Category Mismatch
    # If the query asks for a specific count group (e.g. "six Ms")
    # but the items are generic section labels from a top-level summary
    # common in "Intro" chapters.
    if sig["is_canonical_set"]:
        # Logic: If items contain the core entity name + generic section markers
        # but don't look like specific naming markers.
        low_items = [it.lower() for it in items]
        perspective_items = sum(1 for low in low_items if " as " in low or low.startswith("introduction to ") or low.startswith("principles of "))
        if perspective_items >= len(items) - 1:
             return False, "generic_category_perspective_mismatch"

    # MP-C5: Pattern 3 — EXACT LIST-TOPIC CONTAMINATION GUARD
    # Generic structural rule (no domain words, no topic vocabulary):
    # When a query has a NARROW focus token (a focus token that is NOT also a
    # context token — i.e. the modifier word that distinguishes the requested
    # subtype from the broad entity, e.g. "characteristics" in
    # "characteristics of management"), AND the cleaned list is uniformly
    # short single-token labels (1-2 words each), the items must show some
    # evidence of belonging to that exact subtype concept rather than just
    # the broad domain. Acceptance requires ANY of:
    #   * at least one item contains the narrow focus token
    #   * the query contains an explicit count target matching len(items)
    #     (canonical-set lists like "six Ms" naturally have no narrow-focus
    #     token in items — items ARE the answer)
    #   * items aren't uniformly short single-token labels (multi-word
    #     descriptive characteristics/steps phrasing — guard does not apply)
    # The combination matches the contamination shape (broad nearby category
    # words) without false-rejecting normal multi-word characteristic / step
    # phrasing or count-anchored canonical sets.
    try:
        fam_for_split = family_v2 or _classify_query_family_v2(query_text)
        ctx_toks_v, focus_toks_v = _split_query_context_focus_tokens(query_text, fam_for_split)
    except Exception:
        ctx_toks_v, focus_toks_v = [], []
    _ctx_set = {str(t or "").strip().lower() for t in (ctx_toks_v or []) if t}
    _generic_modifier_stop = {"the", "and", "for", "with", "from", "main", "major", "popular"}
    narrow_focus = [
        str(t or "").strip().lower()
        for t in (focus_toks_v or [])
        if t
        and len(str(t)) >= 4
        and str(t).strip().lower() not in _ctx_set
        and str(t).strip().lower() not in _generic_modifier_stop
    ]
    if narrow_focus:
        def _short_label(it: str) -> bool:
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", str(it or ""))
            return 1 <= len(words) <= 2
        uniform_short_labels = bool(len(items) >= 3 and all(_short_label(it) for it in items))
        if uniform_short_labels:
            has_narrow_in_items = any(
                any(_token_match_light(str(it or "").lower(), tok) for tok in narrow_focus)
                for it in items
            )
            cat_count = sig.get("categorical_count")
            count_anchored = bool(cat_count is not None and int(cat_count) == len(items))
            if (not has_narrow_in_items) and (not count_anchored):
                # Concept-cluster rescue: if the narrow focus token is an
                # enumeration-type meta-word (perspectives, approaches, schools,
                # theories, etc.) the ANSWER items are expected to be the NAMES
                # of each perspective/approach — NOT to repeat the meta-word
                # inside every item. Accept when items form a clean distinct
                # cluster of short labels. Generic: no domain vocabulary.
                _enum_type_modifiers = {
                    "perspectives", "perspective", "approaches", "approach",
                    "models", "model", "types", "type", "branches", "branch",
                    "schools", "school", "theories", "theory",
                    "viewpoints", "viewpoint", "orientations", "orientation",
                    "frameworks", "framework",
                }
                _nf_is_enum_type = any(tok in _enum_type_modifiers for tok in narrow_focus)
                if _nf_is_enum_type:
                    _cluster_labels = [
                        it for it in items
                        if 1 <= len(re.findall(r"[A-Za-z][A-Za-z\-']*", it)) <= 5
                    ]
                    _all_distinct = (
                        len({re.sub(r"[^a-z]+", " ", it.lower()).strip() for it in _cluster_labels})
                        == len(_cluster_labels)
                    )
                    if len(_cluster_labels) >= 3 and _all_distinct:
                        S.logger.info(
                            "[CONCEPT CLUSTER DETECTED] %d distinct labels for enum-type narrow_focus=%s",
                            len(_cluster_labels), narrow_focus,
                        )
                        S.logger.info(
                            "[STRUCTURE QUERY RESCUE] items form distinct concept cluster -> accepted"
                        )
                        return True, "ok"
                S.logger.info(
                    "[CONCEPT MATCH GUARD] reject narrow_focus_missing focus=%s items=%d count_target=%s",
                    narrow_focus,
                    len(items),
                    str(cat_count),
                )
                return False, "narrow_focus_missing_in_short_labels"

    return True, "ok"

_OCR_GLUED_FUNCTION_PREFIXES = (
    "The", "A", "An", "And", "To", "Of", "For", "In", "On", "At", "By",
    "With", "From", "Into", "Onto", "Upon", "This", "That", "These", "Those",
    "Many", "Most", "All", "Each", "Every", "Both", "Either", "Neither",
    "Various", "Several", "Other", "Another", "Such", "More", "Less", "Few",
    "Much",
)

_OCR_GLUED_PREFIX_RE = re.compile(
    r"\b("
    + "|".join(sorted(_OCR_GLUED_FUNCTION_PREFIXES, key=len, reverse=True))
    + r")([a-z]{3,})\b"
)  # case-sensitive: only capitalized OCR-glue patterns are split, which

_OCR_CAMELCASE_BOUNDARY_RE = re.compile(r"([a-z])([A-Z])")

def _ocr_repair_glued_tokens(text: str) -> str:
    """Apply purely structural OCR fixes to a single line of text.

    Generic — uses only English function words and CamelCase boundaries.
    No domain-specific vocabulary. Safe for any document type.
    """
    if not text:
        return text
    repaired = _OCR_CAMELCASE_BOUNDARY_RE.sub(r"\1 \2", text)
    # Apply glued-prefix split iteratively because cascades can occur
    # (e.g. "Thevariousfactors" -> "The variousfactors" -> "The various factors")
    for _ in range(3):
        new_text = _OCR_GLUED_PREFIX_RE.sub(r"\1 \2", repaired)
        if new_text == repaired:
            break
        repaired = new_text
    return re.sub(r"\s+", " ", repaired).strip()

def _preclean_list_answer_for_assessment(answer_text: str) -> str:
    raw = str(answer_text or "")
    if not raw.strip():
        return ""

    def _line_broken(line: str) -> bool:
        low = line.lower().strip()
        if not low:
            return True
        if re.match(r"^\s*(?:and|or|to|of|for|with|by|in|on|at|from|because|however|therefore|thus|then)\b", low):
            return True
        return False

    bullet_prefix_re = re.compile(r"^(\s*(?:[-•*]|\d+[.)]|[a-z][.)])\s*)(.+)$", re.IGNORECASE)

    def _strip_marker_for_continuation(line: str) -> str:
        m = bullet_prefix_re.match(str(line or "").strip())
        if m:
            return (m.group(2) or "").strip()
        return str(line or "").strip()

    def _starts_list_continuation(line: str) -> bool:
        payload = _strip_marker_for_continuation(line)
        return bool(
            re.match(r"^\s*(?:and|or)\b\s+\S", payload, flags=re.IGNORECASE)
            or re.match(r"^\s*&\s*\S", payload)
        )

    def _ends_list_connector(line: str) -> bool:
        payload = _strip_marker_for_continuation(line)
        return bool(re.search(r"(?:\b(?:and|or)|&)\s*$", payload, flags=re.IGNORECASE))

    kept: list[str] = []
    for ln in raw.splitlines():
        s = re.sub(r"[ \t]+", " ", str(ln or "")).strip()
        if not s:
            continue
        # MP-C4: Apply generic OCR token repair while preserving bullet markers.
        m = bullet_prefix_re.match(s)
        if m:
            s = (m.group(1) or "") + _ocr_repair_glued_tokens(m.group(2) or "")
        else:
            s = _ocr_repair_glued_tokens(s)
        s = re.sub(r"\s+", " ", s).strip()
        if not s:
            continue
        if len(s) > 200:
            continue
        if not re.search(r"[A-Za-z]", s):
            continue
        if kept and (_starts_list_continuation(s) or _ends_list_connector(kept[-1])):
            payload = _strip_marker_for_continuation(s)
            kept[-1] = kept[-1].rstrip(" ,;:-") + " " + payload
            S.logger.info("[LIST ITEM CONTINUATION MERGED] continuation=%s", payload[:100])
            continue
        if _line_broken(s):
            continue
        kept.append(s)
    return "\n".join(kept).strip()

def _extract_simple_overview_from_docs(docs: list[dict]) -> str | None:
    headings = _extract_document_headings((docs or [])[:3])
    top = []
    seen = set()
    for h in headings:
        name = re.sub(r"\s+", " ", str(h.get("heading") or "")).strip()
        if not name:
            continue
        low = name.lower()
        if low in seen:
            continue
        if re.search(r"\b(table of contents|contents|index|references?)\b", low):
            continue
        seen.add(low)
        top.append(name)
        if len(top) >= 3:
            break
    if len(top) >= 2:
        return f"This document mainly covers {', '.join(top[:3])}."
    return None

_DEFINITION_DESCRIPTIVE_PENALTY_RE = re.compile(
    r"\b(?:"
    r"come(?:s)?\s+to\s+mind|"               # associative recall, not definition
    r"put\s+forward\s+by|"                    # attribution of authorship
    r"you\s+can\s+(?:also\s+)?call(?:\s+it)?|"  # alternate naming
    r"whenever\s+we\s+talk|"                  # narrative framing
    r"important\s+era|"                       # historical framing
    r"evolution\s+of|"                        # historical framing
    r"changed\s+over\s+time|"                 # historical framing
    r"history\s+of|"                          # historical framing
    r"before\s+we\s+can|"                     # preamble
    r"we\s+need\s+to\s+look|"                 # preamble
    r"to\s+put\s+it\s+another\s+way|"         # paraphrase preamble
    r"in\s+other\s+words"                     # paraphrase preamble
    r")\b",
    flags=re.IGNORECASE,
)

_DEFINITION_QUOTED_DEF_RE = re.compile(
    r"[\"\u201c\u201d\u2018\u2019'`]\s*(?:is|are|refers\s+to|defined\s+as|means)\b",
    flags=re.IGNORECASE,
)

_DEFINITION_VERB_NEAR_RE = re.compile(
    r"\b(?:is|are|refers\s+to|defined\s+as|means)\b",
    flags=re.IGNORECASE,
)

def _definition_structural_signal_delta(sentence: str, entity_l: str) -> float:
    """Return a generic score delta for a candidate definition sentence.

    Signals are purely structural / linguistic (no domain or topic words):
      + entity appears at the start, followed shortly by a definition verb
      + sentence carries a quoted definition span ("... is ...")
      - sentence uses descriptive/historical/associative framing instead of
        a definitional clause
    """
    s = str(sentence or "").strip()
    if not s:
        return 0.0
    low = s.lower()
    delta = 0.0
    ent = re.sub(r"\s+", " ", str(entity_l or "").strip().lower())

    # Boost A: entity at the start, then a definition verb within a short bridge
    # (allow common attribution punctuation/words like commas, quotes, or short
    # parentheticals between the entity and the verb).
    if ent:
        anchored = re.match(
            rf"^\s*(?:the\s+)?{re.escape(ent)}\b[\s,;:'\"`\-()\u201c\u201d\u2018\u2019]{{0,140}}"
            rf"\b(?:is|are|refers\s+to|defined\s+as|means)\b",
            low,
        )
        if anchored:
            delta += 4.0

    # Boost B: a quoted definitional clause (attributed quoted definitions are
    # a strong structural signal — e.g., "... is ..." inside quotation marks).
    if _DEFINITION_QUOTED_DEF_RE.search(s):
        delta += 3.0
    elif _DEFINITION_VERB_NEAR_RE.search(low) and re.search(
        r"[\"\u201c\u2018'`][^\"\u201d\u2019'`]{20,260}[\"\u201d\u2019'`]", s
    ):
        delta += 2.0

    # Penalty: descriptive / historical / associative framing patterns. These
    # introduce or contextualize a topic instead of defining it.
    if _DEFINITION_DESCRIPTIVE_PENALTY_RE.search(low):
        delta -= 6.0

    return delta

def _strip_attribution_prefix_for_definition(sentence: str) -> str:
    """Generic structural normalization of attributed quoted definitions.

    Removes a single inline attribution clause of the form
    ", in the words of <person>, " between the subject and a quoted definition
    so that downstream regexes can match the underlying "<entity> is ..."
    pattern. No domain knowledge required.
    """
    s = str(sentence or "")
    if not s:
        return s
    s = re.sub(r",\s*in\s+the\s+words\s+of\s+[^,]{1,120},\s*", " ", s, flags=re.IGNORECASE)
    s = re.sub(
        r'\b([A-Za-z][A-Za-z0-9\- ]{2,90})\s*["\u201c\u201d\u2018\u2019]\s*(is|are|refers\s+to|means|defined\s+as|is\s+defined\s+as|is\s+considered)\b',
        r"\1 \2",
        s,
        flags=re.IGNORECASE,
    )
    return re.sub(r"\s+", " ", s).strip()

def _extract_candidate_definition_sentence_from_docs(query_text: str, docs: list[dict], max_docs: int = 2) -> str | None:
    if not docs:
        return None
    max_docs = max(1, min(3, int(max_docs)))
    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = (entity or "").strip().lower()
    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]

    query_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower())
        if t not in {"what", "who", "is", "was", "the", "a", "an", "of", "and", "in", "to", "define", "does", "this", "document", "talk", "about"}
    ]
    weak_phrases = ("he thought", "it can be said", "in this way", "before we can")
    person_indicators = ("born", "known as", "considered", "introduced", "engineer", "theorist", "manager")
    reject_marker_re = re.compile(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", flags=re.IGNORECASE)
    heading_intro_re = re.compile(
        r"^\s*(?:introduction|overview|summary|contents?|table of contents|chapter\s+\d+|unit\s+\d+|learning objectives?|key terms?)\s*[:\-–—]?\s*$",
        flags=re.IGNORECASE,
    )
    concept_def_verb_re = re.compile(r"\b(?:is|refers to|defined as|known as)\b", flags=re.IGNORECASE)
    attribution_verb_re = re.compile(r"\b(?:introduced|developed|known as)\b", flags=re.IGNORECASE)
    person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b")
    continuation_starts = re.compile(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", flags=re.IGNORECASE)
    q_low = (query_text or "").strip().lower()
    is_who_query = q_low.startswith("who is") or q_low.startswith("who was")
    is_concept_query = q_low.startswith("what is") or q_low.startswith("define")
    is_person_attribution_query = q_low.startswith("who introduced") or q_low.startswith("who developed")
    early_exit_threshold = 8.0
    max_sentences_per_doc = 10

    best: tuple[float, str] | None = None
    for d in docs[:max_docs]:
        source_text = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not source_text:
            continue
        sentence_candidates = [s for s in re.split(r"(?<=[.!?])\s+|\n+", source_text) if (s or "").strip()]
        for sent in sentence_candidates[:max_sentences_per_doc]:
            s = (sent or "").strip()
            if not s:
                continue
            low = s.lower()
            if reject_marker_re.search(low):
                continue
            if heading_intro_re.match(s) and not re.search(r"[.!?]$", s):
                continue
            if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
                continue
            if "|" in s or "\t" in s:
                continue
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
            wc = len(words)
            if wc < 6 or wc > 40:
                continue
            if re.match(r"^[A-Z][A-Za-z0-9\s\-,:]{2,100}$", s) and not re.search(r"[.!?]$", s):
                continue
            if is_concept_query and _is_over_generic_definition_template(s, entity_l):
                continue
            if is_concept_query and entity_l and defines_other_concept(low, entity_l):
                continue
            score = 0.0

            has_definition_verb = bool(re.search(r"\b(is|was|refers to|defined as|known as)\b", low))
            if has_definition_verb:
                score += 6.0

            normalized_low = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", low)).strip()
            full_phrase_hit = bool(entity_l and normalized_low and re.search(rf"\b{re.escape(entity_l)}\b", normalized_low))

            if is_concept_query and entity_l:
                if full_phrase_hit and concept_def_verb_re.search(low):
                    score += 8.5
                else:
                    score -= 6.5

                concept_quality_score = _s_definition_sentence(s, entity_l, entity_tokens)
                if concept_quality_score <= 0:
                    continue
                if not _has_required_concept_specific_signal(s, entity_l):
                    continue
                score += float(concept_quality_score)

            full_concept_hit = False
            if has_entity and full_phrase_hit:
                full_concept_hit = True
                score += 6.0

            token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            if token_hits >= max(1, min(2, len(entity_tokens))):
                score += 3.0
                if len(entity_tokens) >= 2 and token_hits >= min(2, len(entity_tokens)):
                    full_concept_hit = True

            query_hits = sum(1 for t in query_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            if query_hits >= 2:
                full_concept_hit = True

            if full_concept_hit:
                score += 6.0

            if query_hits > 0:
                score += 3.0
            if query_hits >= 1:
                score += 1.5
            if is_who_query and any(ind in low for ind in person_indicators):
                score += 3.0

            if is_person_attribution_query:
                token_grounding = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) >= max(1, min(2, len(entity_tokens)))
                has_attribution = bool(attribution_verb_re.search(low))
                has_person_name = bool(person_name_re.search(s))
                if has_attribution and (has_person_name or token_grounding):
                    score += 10.0
                else:
                    score -= 8.0

            first_alpha = next((ch for ch in s if ch.isalpha()), "")
            if first_alpha and first_alpha.islower():
                score -= 5.0
            if continuation_starts.match(s):
                score -= 5.0
            if any(p in low for p in weak_phrases):
                score -= 5.0
            if re.search(r"\b(this|these|such)\s+(approach|theory|concept|method)\b", low):
                score -= 3.0

            # MP-C2: generic structural definition-shape signals (no domain words)
            score += _definition_structural_signal_delta(s, entity_l)

            if score >= early_exit_threshold:
                return s

            if best is None or score > best[0]:
                best = (score, s)
    return best[1] if best else None

def _top_chunk_has_exact_entity_phrase(query_text: str, docs: list[dict]) -> bool:
    if not docs:
        return False
    has_entity, entity = _extract_entity_from_definition_query(query_text)
    if not has_entity:
        return False
    top_text = str((docs[0] or {}).get("page_content") or (docs[0] or {}).get("text") or "")
    if not top_text.strip():
        return False
    norm_entity = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", entity.lower())).strip()
    norm_top = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", top_text.lower())).strip()
    if not norm_entity or not norm_top:
        return False
    return bool(re.search(rf"\b{re.escape(norm_entity)}\b", norm_top))

def _passes_fast_path_definition_validation(query_text: str, answer_sentence: str) -> bool:
    sentence = str(answer_sentence or "").strip()
    if not sentence:
        return False

    s_low = sentence.lower()
    if re.search(r"\b(?:criticism|criticisms|limitations?|drawbacks?|red\s+tape)\b", s_low):
        return False

    if not re.search(r"\b(is|was|refers to|defined as|means|known as|considered|introduced)\b", s_low):
        return False

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    if not has_entity:
        return False

    norm_entity = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", entity.lower())).strip()
    norm_sentence = re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", sentence.lower())).strip()
    if not norm_entity or not norm_sentence:
        return False

    q_low = (query_text or "").strip().lower()
    is_concept_query = q_low.startswith("what is") or q_low.startswith("define")
    is_person_attribution_query = q_low.startswith("who introduced") or q_low.startswith("who developed")

    if is_concept_query:
        if defines_other_concept(s_low, norm_entity):
            return False
        if _is_over_generic_definition_template(sentence, norm_entity):
            return False
        if not _has_required_concept_specific_signal(sentence, norm_entity):
            return False

    if norm_entity in norm_sentence:
        if is_concept_query:
            if re.search(rf"\b{re.escape(norm_entity)}\b\s+(is|was|refers to|defined as|means)", norm_sentence):
                return True
        else:
            return True

    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", norm_entity)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]
    if not entity_tokens:
        return False
    hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", norm_sentence))
    token_grounded = hits >= max(1, min(2, len(entity_tokens)))
    if is_person_attribution_query:
        has_attr = bool(re.search(r"\b(introduced|developed|known as)\b", s_low))
        has_person_name = bool(re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2}\b", sentence))
        return token_grounded and has_attr and has_person_name
    return token_grounded

def _definition_entity_or_reference_match(query_text: str, answer_text: str) -> bool:
    a_low = re.sub(r"\s+", " ", str(answer_text or "").strip().lower())
    if not a_low:
        return False

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    if not has_entity:
        return True

    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not entity_l:
        return True

    if re.search(rf"\b{re.escape(entity_l)}\b", a_low):
        return True

    stop = {"the", "a", "an", "of", "and", "in", "to", "what", "is", "define"}
    generic_entity_tokens = {"approach", "theory", "method", "model", "system", "concept", "perspective", "school", "view"}
    entity_tokens = [t for t in re.findall(r"[a-z0-9]{2,}", entity_l) if t not in stop]
    specific_tokens = [t for t in entity_tokens if t not in generic_entity_tokens]

    if specific_tokens:
        # P3: allow obvious surface-form variants (plural/singular/lemma) when
        # matching entity tokens against the answer. Reuses the existing
        # _token_match_light helper, which normalizes -s / -es / -ies / -y
        # without any domain-specific term list. Falls back to exact word
        # boundary match for tokens shorter than the helper's normalization
        # threshold.
        def _entity_token_hit(tok: str) -> bool:
            try:
                if _token_match_light(a_low, tok):
                    return True
            except Exception:
                pass
            return bool(re.search(rf"\b{re.escape(tok)}\b", a_low))

        specific_hits = sum(1 for t in specific_tokens if _entity_token_hit(t))
        # MP-C1 generic tightening: when the entity has multiple specific
        # (non-stopword, non-generic) tokens, require ALL of them in the
        # answer. A single matching token from a multi-word entity (e.g.
        # only "quantum" from "quantum comparing") routinely picks up
        # unrelated polysemous content. For single-token entities the
        # single hit remains sufficient. No domain words.
        if len(specific_tokens) >= 2:
            if specific_hits >= len(specific_tokens):
                return True
            # Not enough specific tokens matched: refuse outright instead of
            # falling through to the looser query-overlap branch (which can
            # accept on a single shared token plus a generic noun like
            # "view"/"approach" appearing anywhere in the answer).
            return False
        else:
            if specific_hits >= 1:
                return True

    query_l = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    query_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", query_l) if t not in stop]
    query_overlap_hits = sum(1 for t in query_tokens if re.search(rf"\b{re.escape(t)}\b", a_low))
    generic_hits = sum(1 for t in generic_entity_tokens if re.search(rf"\b{re.escape(t)}\b", a_low))
    has_definition_verb = bool(re.search(r"\b(?:is|was|refers\s+to|defined\s+as|means|focuses\s+on|emphasizes|involves)\b", a_low))
    has_clear_reference = bool(
        re.search(r"^\s*(?:it|this|that|the)\s+(?:approach|theory|model|method|system|concept|perspective|school)\b", a_low)
        or re.search(r"\bthis\s+(?:approach|theory|model|method|system|concept|perspective|school)\b", a_low)
    )

    return bool(has_definition_verb and (has_clear_reference or generic_hits >= 1) and query_overlap_hits >= 1)

def _passes_strict_definition_relevance_guard(query_text: str, answer_sentence: str) -> bool:
    q_low = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    s = re.sub(r"\s+", " ", str(answer_sentence or "").strip())
    if not s:
        S.logger.info("[STRICT DEF PREF MISS] query=%s reason=empty_answer", q_low[:120])
        return False
    if re.search(r"(?:©|copyright|virtual\s+university|\b[a-z]{2,5}\s*\d{3}\b)", s, flags=re.IGNORECASE):
        S.logger.info("[STRICT DEF PREF MISS] query=%s reason=ocr_noise", q_low[:120])
        return False
    if _is_definition_boilerplate_sentence(s.lower()):
        S.logger.info("[STRICT DEF PREF MISS] query=%s reason=boilerplate", q_low[:120])
        return False
    # MP-C1 generic tightening: ensure the answer references the queried
    # entity (or a clear reference to it). Without this check the strict
    # guard previously returned True for any non-empty, non-boilerplate
    # sentence — letting unrelated content leak through whenever the route
    # produced a deterministic answer (e.g. a sentence that merely shares
    # a polysemous word with the entity). Generic, no domain words.
    if not _definition_entity_or_reference_match(query_text, s):
        S.logger.info("[STRICT DEF PREF MISS] query=%s reason=entity_not_referenced", q_low[:120])
        return False
    S.logger.info("[STRICT DEF PREF PASS] query=%s reason=generic_grounded_check", q_low[:120])
    return True

_PERSON_ROLE_TOKENS = frozenset({
    "ceo", "chief", "executive", "president", "chairman", "founder", "cofounder",
    "co-founder", "creator", "developer", "inventor", "author", "owner", "director",
})

def _is_person_identity_query(query_text: str) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if re.match(r"^who\s+(?:is|was|are|were|founded|created|developed)\b", q):
        return True
    if re.search(r"\b(?:ceo|chief\s+executive|founder|inventor|author|president|chairman)\b", q):
        return True
    return False

def _looks_like_organization_name(name: str) -> bool:
    tokens = [t.lower() for t in re.findall(r"[A-Za-z]+", str(name or ""))]
    org_markers = (
        "cloud", "solutions", "inc", "llc", "corp", "corporation", "company", "group",
        "systems", "services", "technologies", "technology", "platform", "networks",
        "holdings", "partners", "consulting", "bank", "financial", "insurance",
        "global", "international", "enterprises", "foundation", "institute", "university",
    )
    return any(token in org_markers for token in tokens)

def _sentence_has_person_name(sentence: str) -> bool:
    for match in re.finditer(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b", str(sentence or "")):
        if not _looks_like_organization_name(match.group(0)):
            return True
    return False

def _person_identity_signal_text(text: str) -> bool:
    low = re.sub(r"\s+", " ", str(text or "").strip().lower())
    if not low:
        return False
    return bool(
        re.search(
            r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
            r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
            low,
        )
        or re.search(r"\b(?:born|died|introduced\s+by|developed\s+by|founded|histor(?:y|ical)|century|in\s+\d{3,4}|during\s+the)\b", low)
    )

def _surname_led_identity_match(text: str, entity_l: str) -> bool:
    if not entity_l or " " in entity_l.strip():
        return False
    low = text.lower()
    if not re.search(rf"\b{re.escape(entity_l)}\b", low):
        return False
    ent_cap = entity_l[:1].upper() + entity_l[1:]
    if re.match(rf"^{re.escape(ent_cap)}\s+(?:is|was)\s+(?:an?\s+|the\s+)?", text.strip(), flags=re.IGNORECASE):
        return _person_identity_signal_text(text)
    if re.match(rf"^{re.escape(ent_cap)}\s+(?:is|was)\s+", text.strip(), flags=re.IGNORECASE):
        return _person_identity_signal_text(text)
    return False

def _answer_contains_person_evidence(answer: str, query_text: str = "") -> bool:
    text = re.sub(r"\s+", " ", str(answer or "").strip())
    if not text:
        return False
    low = text.lower()
    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower()) if has_entity else ""
    if entity_l and _surname_led_identity_match(text, entity_l):
        return True
    if not _sentence_has_person_name(text):
        return False
    if re.search(
        r"\b(?:is|was|are|were)\s+(?:the\s+)?(?:ceo|chief|executive|founder|president|chairman|owner|director|creator|developer|inventor|author)\b",
        low,
    ):
        return True
    if re.search(r"\b(?:founded|created|developed|invented|authored)\s+by\b", low):
        return True
    person_match = re.search(r"\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\s+(?:is|was)\s+(?:the\s+)?", text)
    if person_match and not _looks_like_organization_name(person_match.group(1)):
        return True
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if q and any(tok in low for tok in _PERSON_ROLE_TOKENS if tok in q):
        return bool(re.search(r"\b(?:ceo|chief|executive|founder|president|chairman|owner|director|creator|developer|inventor|author)\b", low))
    return False

def _has_person_evidence_in_docs(query_text: str, docs: list[dict]) -> bool:
    if _has_exact_who_person_evidence(query_text, docs):
        return True
    for d in (docs or [])[:5]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        for sentence in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]:
            if _answer_contains_person_evidence(sentence, query_text):
                return True
    return False

def _has_exact_who_person_evidence(query_text: str, docs: list[dict]) -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q or not re.match(r"^who\s+(is|was)\b", q):
        return False
    if not docs:
        return False

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not has_entity or not entity_l:
        return False

    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]
    if not entity_tokens:
        return False

    full_name_re = None
    if len(entity_tokens) >= 2:
        first = re.escape(entity_tokens[0])
        last = re.escape(entity_tokens[-1])
        full_name_re = re.compile(rf"\b{first}(?:\s+[a-z]{{2,}}){{0,3}}\s+{last}\b", flags=re.IGNORECASE)

    person_name_re = re.compile(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\b")
    min_hits = 1 if len(entity_tokens) == 1 else max(2, min(3, len(entity_tokens)))

    for d in (docs or [])[:5]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        for sentence in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]:
            low = sentence.lower()
            if full_name_re and full_name_re.search(low):
                return True
            token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            if len(entity_tokens) == 1 and token_hits >= 1 and _person_identity_signal_text(sentence):
                if _surname_led_identity_match(sentence, entity_l):
                    return True
            if token_hits >= min_hits and person_name_re.search(sentence):
                if any(t in _PERSON_ROLE_TOKENS for t in entity_tokens):
                    if not re.search(r"\b(?:ceo|chief|executive|founder|president|chairman|owner|director|creator|developer|inventor|author)\b", low):
                        continue
                if not any(not _looks_like_organization_name(name) for name in person_name_re.findall(sentence)):
                    continue
                return True
    return False

def _enrich_who_identity_answer(query_text: str, docs: list[dict], base_answer: str) -> str:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not re.match(r"^who\s+(is|was)\b", q):
        return base_answer
    if not base_answer:
        return base_answer

    base = re.sub(r"\s+", " ", str(base_answer)).strip()
    if not re.search(r"\bis\s+associated\s+with\b", base, flags=re.IGNORECASE):
        return base

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    if not has_entity or not entity_l:
        return base

    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]
    if not entity_tokens:
        return base

    full_name_re = None
    if len(entity_tokens) >= 2:
        first = re.escape(entity_tokens[0])
        last = re.escape(entity_tokens[-1])
        full_name_re = re.compile(rf"\b{first}(?:\s+[a-z]{{2,}}){{0,3}}\s+{last}\b", flags=re.IGNORECASE)

    rich_marker_re = re.compile(r"\b(known as|introduced|developed)\b", flags=re.IGNORECASE)
    association_re = re.compile(r"\bis\s+associated\s+with\b", flags=re.IGNORECASE)

    for d in (docs or [])[:5]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]
        for s in sentences[:24]:
            if association_re.search(s):
                continue
            if not rich_marker_re.search(s):
                continue
            low = s.lower()
            token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            full_hit = bool(full_name_re.search(low)) if full_name_re else False
            surname_hit = bool(entity_tokens and re.search(rf"\b{re.escape(entity_tokens[-1])}\b", low))
            if not (full_hit or token_hits >= max(2, min(3, len(entity_tokens))) or surname_hit):
                continue
            right = s[0].lower() + s[1:] if len(s) > 1 else s.lower()
            merged = f"{base.rstrip('.')} and {right.rstrip('.')}."
            return re.sub(r"\s+", " ", merged).strip()
    return base

def _extract_topic_pure_overview_from_docs(query_text: str, docs: list[dict]) -> str | None:
    if not docs:
        return None

    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return None

    stop = {
        "what", "is", "are", "who", "was", "were", "the", "a", "an", "of", "and", "in", "to", "for",
        "tell", "me", "about", "explain", "overview", "summary", "document", "this", "that",
    }
    topic_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in stop]
    if not topic_tokens:
        return None

    
    requires_principles = False
    requires_planning_process = False
    requires_polarity = False

  

    candidates: List[Tuple[float, str]] = []
    seen: set[str] = set()
    for d in (docs or [])[:3]:
        src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if not src:
            continue
        sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]
        for s in sentences[:30]:
            low = s.lower()
            if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) < 6:
                continue
            if re.search(r"\b(table|figure|isbn|chapter\s+\d+|unit\s+\d+)\b", low):
                continue
          # removed stale topic gate check
            overlap = sum(1 for tok in topic_tokens if re.search(rf"\b{re.escape(tok)}\b", low))
            if overlap <= 0:
                continue
            score = float(overlap)
           
            if requires_polarity and re.search(r"\b(?:pros|cons|benefits?|drawbacks?|limitations?|criticisms?|merits?)\b", low):
                score += 1.2
            norm = re.sub(r"[^a-z0-9]+", " ", low).strip()
            if not norm or norm in seen:
                continue
            seen.add(norm)
            candidates.append((score, s))

    if not candidates:
        return None

    candidates.sort(key=lambda x: x[0], reverse=True)
    picked = [s for _, s in candidates[:3]]
    answer = " ".join(picked).strip()
    return answer or None

def _refine_concept_definition_answer(query_text: str, docs: list[dict], answer: str) -> str:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not (q.startswith("what is") or q.startswith("define")):
        return answer

    base = re.sub(r"\s+", " ", str(answer or "")).strip()
    if not base:
        return answer

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
    entity_tokens = [
        t for t in re.findall(r"[a-z0-9]{2,}", entity_l)
        if t not in {"the", "a", "an", "of", "and", "in", "to"}
    ]

    def _extract_concept_level_from_docs() -> str | None:
        if not docs or not entity_l:
            return None
        def_re = re.compile(r"\b(is|refers to|defined as|can be explained as|involves|is a system of|is an approach to|focuses on|is concerned with)\b", flags=re.IGNORECASE)
        best: Tuple[float, str] | None = None
        for d in (docs or [])[:5]:
            src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not src:
                continue
            sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]
            for s in sentences[:40]:
                low = s.lower()
                if defines_other_concept(low, entity_l):
                    continue
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) < 8:
                    continue
                if re.search(r"\b(table|figure|isbn|chapter\s+\d+|unit\s+\d+|contents?)\b", low):
                    continue
                if re.match(r"^\s*(he|she|they|this|it)\b", low):
                    continue
                if not def_re.search(low):
                    continue
                phrase_hit = bool(re.search(rf"\b{re.escape(entity_l)}\b", low))
                token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low))
                root_hits = 0
                for t in entity_tokens:
                    if len(t) >= 6 and re.search(rf"\b{re.escape(t[:6])}[a-z]*\b", low):
                        root_hits += 1
                if not (phrase_hit or token_hits >= max(1, min(2, len(entity_tokens))) or root_hits >= max(1, min(2, len(entity_tokens)))):
                    continue
                if re.match(r"^\s*[A-Za-z][A-Za-z\s\-]{2,50}:\s+", s) and not phrase_hit:
                    continue
                score = 0.0
                if phrase_hit:
                    score += 3.0
                score += min(2.0, 0.8 * token_hits)
                score += min(1.5, 0.6 * root_hits)
                if re.search(rf"\b{re.escape(entity_l)}\b\s+(is|refers to|defined as)", low):
                    score += 2.0
                if best is None or score > best[0]:
                    best = (score, re.sub(r"\s+", " ", s).strip())
        return best[1] if best and best[0] >= 2.2 else None

    def _extract_contributor_from_docs() -> str | None:
        return None

    def _extract_richer_explanatory_sentence_from_docs() -> str | None:
        if not docs or not entity_l:
            return None
        cues = [
            r"\bdefined\s+as\b",
            r"\brefers\s+to\b",
            r"\bmeans\b",
            r"\binvolves?\b",
            r"\bincludes?\b",
            r"\bconsists?\s+of\b",
            r"\baims?\s+to\b",
            r"\bused\s+to\b",
            r"\bfocus(?:ed)?\s+on\b",
        ]
        best: tuple[float, str] | None = None
        for d in (docs or [])[:5]:
            src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not src:
                continue
            chunk_has_entity = bool(re.search(rf"\b{re.escape(entity_l)}\b", src.lower()))
            for sent in [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", src) if s.strip()]:
                low_sent = sent.lower()
                if _is_table_or_classification_sentence(sent):
                    continue
                if len(re.findall(r"[A-Za-z][A-Za-z\-']*", sent)) < 10:
                    continue
                sent_has_entity = bool(re.search(rf"\b{re.escape(entity_l)}\b", low_sent))
                cue_hits = sum(1 for pat in cues if re.search(pat, low_sent, flags=re.IGNORECASE))
                if cue_hits <= 0:
                    continue
                if not (sent_has_entity or chunk_has_entity):
                    continue
                score = float(cue_hits) + (0.6 if re.search(r"\b(is|refers to|means|focuses on)\b", low_sent) else 0.0)
                if sent_has_entity:
                    score += 0.8
                if best is None or score > best[0]:
                    best = (score, re.sub(r"\s+", " ", sent).strip())
        return best[1] if best else None

    low = base.lower()
    if entity_l and defines_other_concept(low, entity_l):
        S.logger.info("[DEF REJECT WEAK] entity=%s reason=answer_defines_other_concept", entity_l)
        alt = _extract_concept_level_from_docs() or _extract_candidate_definition_sentence_from_docs(query_text, docs or [], max_docs=3)
        if alt and (not defines_other_concept(alt.lower(), entity_l)):
            return alt
        return RAG_NO_MATCH_RESPONSE
    feature_label = bool(re.match(r"^\s*[A-Za-z][A-Za-z\s\-]{2,50}:\s+", base))
    contains_entity = bool(entity_l and re.search(rf"\b{re.escape(entity_l)}\b", low))
    token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", low)) if entity_tokens else 0

    if (not contains_entity) and token_hits < max(1, min(2, len(entity_tokens))):
        alt_direct = _extract_concept_level_from_docs()
        if alt_direct:
            return alt_direct

    if re.search(r"\bis\s+characterized\s+by\b", low) and len(re.findall(r"[a-z0-9]+", low)) <= 14:
        rich_sent = _extract_richer_explanatory_sentence_from_docs()
        if rich_sent:
            rich_sent = re.sub(r"^\s*[A-Za-z]+\s*,\s*", "", rich_sent).strip()
            if entity_l and not re.search(rf"\b{re.escape(entity_l)}\b", rich_sent.lower()):
                entity_title = " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", entity_l)) or str(entity or "").strip()
                rich_sent = f"{entity_title} {rich_sent[0].lower() + rich_sent[1:] if rich_sent else rich_sent}"
            words = re.findall(r"\S+", rich_sent)
            if len(words) > 34:
                rich_sent = " ".join(words[:34]).rstrip(" ,;:-") + "."
            return rich_sent
        alt_rich = _extract_concept_level_from_docs()
        if alt_rich and len(re.findall(r"[a-z0-9]+", alt_rich.lower())) > len(re.findall(r"[a-z0-9]+", low)) + 2:
            return alt_rich

    if re.search(r"\bone\s+of\s+the\s+components\s+listed\s+with\b", low):
        return RAG_NO_MATCH_RESPONSE

    if feature_label and (not contains_entity):
        alt = _extract_concept_level_from_docs() or _extract_candidate_definition_sentence_from_docs(query_text, docs or [], max_docs=3)
        if alt:
            alt_norm = re.sub(r"\s+", " ", str(alt)).strip()
            alt_low = alt_norm.lower()
            alt_feature_label = bool(re.match(r"^\s*[A-Za-z][A-Za-z\s\-]{2,50}:\s+", alt_norm))
            if (not alt_feature_label) and re.search(r"\b(is|refers to|defined as|can be explained as|involves|is a system of|is an approach to)\b", alt_low):
                return alt_norm
    return base

def detect_query_intent(query: str) -> str:
    q = (query or "").strip().lower()
    if _detect_fact_query_type(q):
        return "fact"
    if _is_definition_comparison_query(q):
        return "definition"
    if _is_definition_style_query(q):
        return "definition"
    if _is_targeted_list_question(q):
        return "list"
    return "general"

def _is_metric_fact_query(query: str) -> bool:
    """Detect numeric/metric fact questions that must not use list extraction."""
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if not q:
        return False
    if re.search(r"\bwhat is the exact\b", q):
        return True
    if re.search(r"\bwhat was the\b.{0,80}\b(?:score|rate|percentage|ratio|threshold|auc|value)\b", q):
        return True
    if re.search(r"\b(?:exact|overall|baseline)\b.{0,80}\b(?:rate|score|percentage|ratio|auc|threshold|value)\b", q):
        return True
    # Generic superlative-over-a-category lookups ("which X has the highest Y?").
    if re.search(r"\bwhich\b.{0,40}\b(?:highest|lowest|most|least|largest|smallest|greatest|maximum|minimum)\b", q):
        return True
    if re.search(r"\b(?:rate|score|percentage|ratio|auc|threshold)\b", q) and re.search(r"\b(?:what|which|exact)\b", q):
        return True
    return False

def _extract_metric_fact_answer(query_text: str, docs: list[dict]) -> str | None:
    """Evidence-driven extraction for numeric/metric fact queries.

    Reads the value the question asks about (rate, score, ratio, threshold, …)
    straight from the retrieved chunks. No metric, percentage or number is
    hardcoded: the answer is the source sentence that overlaps the query's
    concept tokens and carries a number of the requested shape, so it works for
    any document's metrics — not just one corpus.
    """
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q or not docs:
        return None

    corpus_parts: list[str] = []
    for d in docs[:15]:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "").strip()
        if txt:
            corpus_parts.append(txt)
    if not corpus_parts:
        return None
    corpus = _repair_split_words(re.sub(r"\s+", " ", " ".join(corpus_parts)))

    answer = _extract_evidence_value_sentence(query_text, corpus, require_value=True)
    if answer and not _is_evidence_fragment_answer(query_text, answer):
        return _repair_split_words(answer)
    return None

def _is_targeted_list_question(query: str) -> bool:
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if not q:
        return False
    if _is_metric_fact_query(q):
        return False
    # Numeric attribute lookups ("minimum balance for High-Yield Savings?") are
    # NOT list questions even though the product name ends in a plural-looking
    # token ("savings"). Without this guard they route to list extraction, fail
    # alignment, and fall back to a wrong/not-found LLM answer.
    if _is_numeric_fact_lookup_query(q):
        return False
    if _is_attribute_lookup_query(q):
        return False
    if _is_support_procedural_query(q):
        return False
    if S._looks_like_arabic_list_query(q):
        return True
    if re.search(r"\blist\b", q):
        return True
    if re.match(r"^\s*(?:what|which)\s+are\b", q):
        return True
    # Comparison questions ("X compared to Y", "X vs Y", "difference between
    # A and B") are not bullet-list extractions. Excluding them here keeps the
    # v2 classifier consistent with the legacy compare family and prevents the
    # list-coherence sanitizer from rejecting tabular/numeric answers.
    if _is_compare_query(q):
        return False
    # "what happens if ...", "what does X mean", etc. are explanatory, not list
    # questions. Common 3rd-person verbs ending in -s must NOT count as plural
    # list nouns, otherwise "What happens if I report fraud?" is misrouted to
    # list extraction (which fails) instead of an explanatory answer.
    _verb_s_stop = {
        "this", "was", "is", "does", "has", "happens", "means", "includes", "requires",
        "involves", "offers", "provides", "gives", "gets", "goes", "comes", "needs",
        "works", "helps", "uses", "looks", "says", "makes", "takes", "keeps", "seems",
        "appears", "occurs", "applies", "exists", "covers", "charges", "lets", "allows",
        "its", "us", "as",
    }
    tokens = re.findall(r"[a-z]{3,}", q)
    plural_tokens = [tok for tok in tokens if tok.endswith("s") and tok not in _verb_s_stop]
    if re.match(r"^\s*(?:name|give|mention|identify)\b", q) and plural_tokens:
        return True
    if re.search(r"\b(?:what|which)\b", q) and plural_tokens and (" and " in q or " or " in q or q.endswith("?")):
        return True
    return False

def _classify_query_family(query: str) -> str:
    q = (query or "").strip().lower()
    if not q:
        return "general"

    if _is_document_summary_query(q):
        _log_query_family_fix(q, "document_summary", "self_referential_document_overview")
        return "document_summary"

    if _is_definition_style_query(q):
        return "definition_entity"

    definition_comparison_reason = _definition_comparison_reason(q)
    if definition_comparison_reason:
        _log_query_family_fix(q, "definition_comparison", definition_comparison_reason)
        return "definition_comparison"

    if _is_support_procedural_query(q):
        return "general"

    if _is_relationship_or_explanation_query(q):
        _log_query_family_fix(q, "relationship_explanation", "relationship_or_explanation_signal")
        return "relationship_explanation"

    if _is_compare_query(q):
        _log_query_family_fix(q, "compare", "generic_compare_signal")
        return "overview_chapter_compare"

    if _is_targeted_list_question(q):
        return "list_structure"

    if _detect_fact_query_type(q):
        return "fact_entity"
    if _is_support_procedural_query(q):
        return "general"
    return "overview_chapter_compare"

def _classify_query_family_v2(query: str) -> str:
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if not q:
        return "explanatory_compare"

    # Document-level summarization/overview requests ("what is this document
    # about?", "summarize the uploaded file", "give me an overview") target
    # the active document corpus itself, not a domain entity. They must be
    # detected BEFORE the definition-style check, otherwise the definition
    # pipeline parses a fake entity (e.g. "this document about") and rejects
    # otherwise valid retrieved evidence.
    if _is_document_summary_query(q):
        _log_query_family_fix(q, "document_summary", "self_referential_document_overview")
        return "document_summary"

    # Table-scoped attribute lookups (entity + column, reverse feature, superlative)
    # must win over generic fact_entity so pipe-table cell extraction runs first.
    if _is_attribute_lookup_query(q) and not _is_support_procedural_query(q):
        return "attribute_lookup"

    # Numeric/metric fact lookups ("what is the minimum balance / outgoing wire
    # fee / FDIC coverage limit for X") are FACT questions even when phrased like
    # a definition ("what is the ..."). They must be classified as fact_entity
    # BEFORE the definition-style check, otherwise the definition path runs: it
    # (a) applies an explanation filter that discards the pipe table holding the
    # answer, and (b) rejects the numeric answer with a strict entity-reference
    # guard. Pure definitions ("what is Everyday Checking?") do not match the
    # numeric-lookup patterns and still fall through to definition_entity.
    if _is_numeric_fact_lookup_query(q) and not _is_support_procedural_query(q):
        return "fact_entity"

    if _is_attribute_lookup_query(q):
        return "attribute_lookup"

    if _is_support_procedural_query(q):
        return "general"

    if _is_definition_style_query(q):
        return "definition_entity"

    definition_comparison_reason = _definition_comparison_reason(q)
    if definition_comparison_reason:
        _log_query_family_fix(q, "definition_comparison", definition_comparison_reason)
        return "definition_comparison"

    if _is_metric_fact_query(q):
        return "fact_entity"

    if _is_targeted_list_question(q):
        return "list_entity"

    if _is_support_procedural_query(q):
        return "general"

    if _detect_fact_query_type(q):
        return "fact_entity"

    return "explanatory_compare"

def _doc_ocr_noise_score(text: str) -> float:
    t = str(text or "")
    if not t:
        return 1.0
    low = t.lower()
    score = 0.0
    score += 0.4 * len(re.findall(r"\b[a-z]\s+[a-z]\b", low))
    score += 0.3 * len(re.findall(r"\b[a-z]{1,2}\s+[a-z]{1,2}\s+[a-z]{1,2}\b", low))
    score += 0.5 * len(re.findall(r"\b[a-z]{2,5}\s+[a-z]{2,5}\b", low))
    score += 0.2 * len(re.findall(r"\b(?:vu|copyright|all rights reserved)\b", low))
    return score

def _light_normalize_query_token(token: str) -> str:
    t = re.sub(r"[^a-z0-9]+", "", str(token or "").lower())
    if len(t) <= 3:
        return t
    if t.endswith("ies") and len(t) > 5:
        return t[:-3] + "y"
    if re.search(r"(?:ches|shes|sses|xes|zes)$", t) and len(t) > 5:
        return t[:-2]
    if t.endswith("es") and len(t) > 6:
        return t[:-2]
    if t.endswith("s") and len(t) > 4 and (not t.endswith("ss")):
        return t[:-1]
    return t

def _token_match_light(haystack: str, token: str) -> bool:
    hs = str(haystack or "").lower()
    if not hs:
        return False
    base = _light_normalize_query_token(token)
    if not base:
        return False
    forms = {base}
    if len(base) > 3:
        forms.add(base + "s")
        forms.add(base + "es")
        if base.endswith("y") and len(base) > 4:
            forms.add(base[:-1] + "ies")
    for f in forms:
        if re.search(rf"\b{re.escape(f)}\b", hs):
            return True
    if len(base) >= 4:
        pref = re.escape(base[: min(6, len(base))])
        if re.search(rf"\b{pref}[a-z]{{0,4}}\b", hs):
            return True
    return False

def _query_section_tokens(query_text: str, family_v2: str = "") -> list[str]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return []
    stop = {
        "what", "which", "who", "when", "where", "why", "how", "is", "are", "was", "were", "the", "a", "an",
        "of", "to", "in", "on", "for", "from", "with", "and", "or", "list", "name", "give", "mention", "identify",
        "tell", "show", "me", "about", "explain", "define", "document", "chapter", "section", "mentioned",
    }
    toks = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in stop]
    out: list[str] = []
    seen: set[str] = set()
    for t in toks:
        cand = _light_normalize_query_token(t)
        if cand in seen:
            continue
        seen.add(cand)
        out.append(cand)
    if family_v2 in {"list_entity", "list_structure"}:
        out = [t for t in out if t not in {"thing", "topic", "item", "point"}] or out
    return out[:8]

def _split_query_context_focus_tokens(query_text: str, family_v2: str = "") -> tuple[list[str], list[str]]:
    all_tokens = _query_section_tokens(query_text, family_v2)
    section_phrases = _query_section_phrases(query_text)
    focus_tokens: list[str] = []
    seen_focus: set[str] = set()
    for ph in section_phrases:
        for tok in re.findall(r"[a-z0-9]{3,}", str(ph or "").lower()):
            norm = _light_normalize_query_token(tok)
            if norm in seen_focus:
                continue
            seen_focus.add(norm)
            focus_tokens.append(norm)
    if not focus_tokens and all_tokens:
        ql = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
        if re.match(r"^\s*(?:list|what\s+are|which\s+are|name|mention|identify|give)\b", ql):
            focus_tokens = [all_tokens[0]]

    context_tokens = [t for t in all_tokens if t not in set(focus_tokens)]
    if not context_tokens and all_tokens and len(all_tokens) > 1:
        context_tokens = all_tokens[1:]
    return context_tokens[:8], focus_tokens[:8]

def _has_strong_local_window_support(local_support: dict[str, Any] | None, confidence_threshold: float = 0.58) -> bool:
    support = dict(local_support or {})
    promoted = float(support.get("promoted_count", 0.0) or 0.0)
    conf = float(support.get("confidence", 0.0) or 0.0)
    focus = float(support.get("focus_hits", 0.0) or 0.0)
    density = float(support.get("list_density", 0.0) or 0.0)
    return bool(
        promoted >= 1.0
        and conf >= confidence_threshold
        and (focus >= 1.0 or density >= 0.10)
    )

def _list_query_alignment_metrics(query_text: str, answer_text: str) -> dict[str, float]:
    q_family_v2 = _classify_query_family_v2(query_text)
    context_tokens, focus_tokens = _split_query_context_focus_tokens(query_text, q_family_v2)
    raw = str(answer_text or "")
    items = [
        re.sub(r"^\s*[-•*]\s+", "", ln).strip()
        for ln in raw.splitlines()
        if re.match(r"^\s*[-•*]\s+", ln)
    ]
    if not items:
        compact = re.sub(r"\s+", " ", raw).strip()
        if " - " in compact:
            items = [p.strip(" ,;:-") for p in compact.split(" - ") if p.strip(" ,;:-")]

    item_count = len(items)
    if item_count <= 0:
        return {
            "item_count": 0.0,
            "focus_hit_items": 0.0,
            "context_hit_items": 0.0,
            "focus_ratio": 0.0,
            "mismatch_penalty": 2.0,
        }

    focus_hit_items = 0
    context_hit_items = 0
    avg_item_words = 0.0
    label_like_items = 0
    for item in items:
        low_item = item.lower()
        wc = len(re.findall(r"[a-z0-9]{2,}", low_item))
        avg_item_words += float(wc)
        has_link_verb = bool(re.search(r"\b(?:is|are|was|were|has|have|had|includes?|involves?|means|refers\s+to)\b", low_item))
        if (not has_link_verb) and 1 <= wc <= 7:
            label_like_items += 1
        if focus_tokens and any(_token_match_light(low_item, tok) for tok in focus_tokens):
            focus_hit_items += 1
        if context_tokens and any(_token_match_light(low_item, tok) for tok in context_tokens):
            context_hit_items += 1

    avg_item_words = (avg_item_words / max(1.0, float(item_count))) if item_count else 0.0
    structured_label_list = bool(
        item_count >= 4
        and avg_item_words <= 5.8
        and label_like_items >= max(3, item_count - 1)
    )

    focus_ratio = float(focus_hit_items) / max(1.0, float(item_count))
    mismatch_penalty = 0.0
    if focus_tokens and focus_hit_items <= 0:
        mismatch_penalty += 0.7 if structured_label_list else 2.2
    elif focus_tokens and focus_ratio < 0.34:
        mismatch_penalty += 1.1
    if context_tokens and (focus_hit_items + context_hit_items) <= 0:
        mismatch_penalty += 0.5 if structured_label_list else 1.6
    if context_tokens and context_hit_items <= 0 and focus_hit_items <= 0:
        mismatch_penalty += 0.3 if structured_label_list else 0.8

    return {
        "item_count": float(item_count),
        "focus_hit_items": float(focus_hit_items),
        "context_hit_items": float(context_hit_items),
        "focus_ratio": float(focus_ratio),
        "mismatch_penalty": float(mismatch_penalty),
    }

def _debug_section_confidence(sig: dict[str, float], local_score: float = 0.0) -> float:
    local_focus_hits = float(sig.get("local_focus_hits", 0.0) or 0.0)
    local_heading_match = float(sig.get("local_heading_match", 0.0) or 0.0)
    local_list_density = float(sig.get("local_list_density", 0.0) or 0.0)
    local_conf_score = float(sig.get("local_confidence_score", 0.0) or 0.0)
    local_promoted = float(sig.get("local_promoted", 0.0) or 0.0)
    score = (
        (0.70 * float(sig.get("phrase_hits", 0.0)))
        + (0.55 * float(sig.get("heading_hits", 0.0)))
        + (0.35 * float(sig.get("marker_score", 0.0)))
        + (0.45 * float(sig.get("focus_hits", 0.0)))
        + (0.40 * local_focus_hits)
        + (0.35 * local_heading_match)
        + (0.55 * local_list_density)
        + (0.75 * local_conf_score)
        + (0.25 * local_promoted)
        + (20.0 * float(sig.get("density", 0.0)))
        - (0.40 * float(sig.get("missing_penalty", 0.0)))
        - (0.55 * float(sig.get("generic_penalty", 0.0)))
        + (0.18 * float(local_score or 0.0))
    )
    conf = float(max(0.0, min(1.0, score / 2.5)))
    return float(max(0.0, min(1.0, conf)))

def _query_section_phrases(query_text: str) -> list[str]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return []
    phrases: list[str] = []

    def _add_phrase(raw: str) -> None:
        ph = re.sub(r"\s+", " ", str(raw or "").strip(" .,:;!?-–—"))
        if not ph:
            return
        words = ph.split()
        if len(words) < 2:
            return
        if len(words) > 10:
            ph = " ".join(words[:10])
        if ph not in phrases:
            phrases.append(ph)

    patterns = [
        r"^\s*(?:list|name|mention|identify|give)\s+(?:all\s+|the\s+)?(.+?)(?:[?.!]|$)",
        r"^\s*(?:what|which)\s+are\s+(?:all\s+|the\s+)?(.+?)(?:[?.!]|$)",
    ]
    for patt in patterns:
        m = re.search(patt, q)
        if not m:
            continue
        chunk = re.sub(r"\s+", " ", str(m.group(1) or "")).strip()
        if not chunk:
            continue
        _add_phrase(chunk)
        # Also keep a compact head phrase for partial heading matches.
        if len(chunk.split()) >= 3:
            _add_phrase(" ".join(chunk.split()[:4]))

    return phrases[:4]

def _query_main_entity_tokens(query_text: str, family_v2: str = "") -> tuple[list[str], list[str]]:
    """Generic main-entity extraction for section-anchor scoring.

    Splits the query's section phrase (e.g. "characteristics of management") into
    a STRUCTURE part ("characteristics") and an ENTITY part ("management") around
    the connectives of/in/for/about/regarding/concerning/on. Returns
    (entity_tokens, structure_tokens). When no connective is present the last
    surviving token of the phrase is treated as the entity. No domain words are
    used; this is purely positional/syntactic.
    """
    if family_v2 in {"definition_entity", "definition_comparison"}:
        has_entity, entity = _extract_entity_from_definition_query(query_text)
        entity_tokens: list[str] = []
        if has_entity and entity:
            seen_entity: set[str] = set()
            for raw in re.findall(r"[a-z0-9]{3,}", str(entity or "").lower()):
                norm = _light_normalize_query_token(raw)
                if norm and norm not in seen_entity:
                    seen_entity.add(norm)
                    entity_tokens.append(norm)
        if entity_tokens:
            all_tokens = _query_section_tokens(query_text, family_v2)
            struct_tokens = [tok for tok in all_tokens if tok not in set(entity_tokens)]
            return entity_tokens[:6], struct_tokens[:4]

    section_phrases = _query_section_phrases(query_text)
    stop = {
        "the", "a", "an", "all", "some", "any", "main", "major", "key", "important",
        "this", "that", "these", "those", "its", "their", "his", "her", "our",
        "such", "various", "different", "many", "few", "every", "each",
    }
    if not section_phrases:
        all_toks = _query_section_tokens(query_text, family_v2)
        if not all_toks:
            return [], []
        # No phrase pattern matched (short query) — last token is the entity.
        entity = [all_toks[-1]]
        struct = [t for t in all_toks if t not in set(entity)]
        return entity, struct[:4]

    phrase = section_phrases[0]
    m = re.search(
        r"^(.*?)\s+\b(?:of|in|for|about|regarding|concerning|on|with|to|from)\b\s+(.+)$",
        phrase,
        flags=re.IGNORECASE,
    )
    if m:
        head_part = m.group(1).strip()
        tail_part = m.group(2).strip()
    else:
        words = phrase.split()
        if len(words) >= 2:
            head_part = " ".join(words[:-1])
            tail_part = words[-1]
        else:
            head_part = ""
            tail_part = phrase

    def _toks(part: str) -> list[str]:
        out: list[str] = []
        seen: set[str] = set()
        for raw in re.findall(r"[a-z0-9]{3,}", part.lower()):
            if raw in stop:
                continue
            norm = _light_normalize_query_token(raw)
            if not norm or norm in seen:
                continue
            seen.add(norm)
            out.append(norm)
        return out

    entity_tokens = _toks(tail_part)
    structure_tokens = _toks(head_part)

    # When the structural part is an enumeration meta-word, promote those
    # tokens so section anchor scoring discriminates on the requested grouping
    # noun rather than only on the broad tail entity.
    # Generic set: universal English concept-grouping nouns.
    _ENUM_META_NORMALIZED = {
        "perspectiv", "perspective",  # perspectives / perspective
        "approach",                   # approaches / approach
        "model",                      # models / model
        "type",                       # types / type
        "kind",                       # kinds / kind
        "school",                     # schools / school
        "theory",                     # theories / theory
        "viewpoint",                  # viewpoints / viewpoint
        "orientation",                # orientations / orientation
        "framework",                  # frameworks / framework
    }
    _promoted = [t for t in structure_tokens if t in _ENUM_META_NORMALIZED]
    if _promoted:
        # Prepend promoted tokens; entity alignment will now check for them
        # first, boosting chunks that contain the specific meta-word in their
        # heading and penalising chunks that lack it entirely.
        entity_tokens = list(dict.fromkeys(_promoted + entity_tokens))[:3]
        structure_tokens = [t for t in structure_tokens if t not in _ENUM_META_NORMALIZED][:4]

    if not entity_tokens and structure_tokens:
        # Phrase was structure-only ("characteristics") — treat the same token
        # as the entity to avoid an empty entity set.
        entity_tokens = [structure_tokens[-1]]
        structure_tokens = structure_tokens[:-1]
    return entity_tokens[:3], structure_tokens[:4]

def _list_marker_score(text: str) -> float:
    t = str(text or "")
    if not t:
        return 0.0
    score = 0.0
    score += 0.35 * len(re.findall(r"(?:^|\n)\s*(?:[-•*]|\d+[.)])\s+", t))
    score += 0.25 * len(re.findall(r"(?:^|[\s,;])[a-z]\)\s", t, flags=re.IGNORECASE))
    score += 0.20 * len(re.findall(r"\b(?:include|includes|consists\s+of|classified\s+as|are\s*:)\b", t, flags=re.IGNORECASE))
    
    # Heuristic: 3+ capitalized noun phrases close together -> treat as list region
    if re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+)*\s*(?:,\s*[A-Z][a-z]+(?:\s+[A-Z][a-z]+)*){2,}\b", t):
        score += 0.65

    short_non_sentence = [
        ln.strip()
        for ln in t.splitlines()
        if ln.strip()
        and len(re.findall(r"[A-Za-z0-9]+", ln)) <= 8
        and not re.search(r"[.!?]$", ln.strip())
    ]
    if len(short_non_sentence) >= 4:
        score += 0.45
        
    score += 0.15 * len(re.findall(r"\n", t[:1800]))
    return min(2.5, score)

def _normalize_phrase_text(text: str) -> str:
    return re.sub(r"\s+", " ", re.sub(r"[^a-z0-9]+", " ", str(text or "").lower())).strip()

def _is_goal_objective_list_query(query_text: str, family_v2: str = "") -> bool:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    if not q:
        return False
    if family_v2 and family_v2 not in {"list_entity", "list_structure"}:
        return False
    has_list_intent = bool(re.match(r"^\s*(?:list|name|mention|identify|give|what\s+are|which\s+are)\b", q))
    has_goal_like = bool(re.search(r"\b(?:goals?|objectives?|aims?)\b", q))
    return bool(has_list_intent and has_goal_like)

def _is_attribution_or_citation_heading_text(text: str) -> bool:
    s = re.sub(r"\s+", " ", str(text or "").strip())
    if not s:
        return False
    low = s.lower()
    if re.search(r"\b(?:given|proposed|developed|introduced|formulated|presented)\s+by\b", low):
        return True
    if re.search(r"\b(?:colleagues|et\s*al\.?|researchers?)\b", low) and re.search(r"\(\s*(?:19|20)\d{2}[a-z]?\s*\)", low):
        return True
    if re.search(r"\(\s*(?:19|20)\d{2}[a-z]?\s*\)", low) and len(re.findall(r"[A-Za-z][A-Za-z\-']*", s)) <= 14:
        return True
    return False

def _is_placeholder_heading_text(text: str) -> bool:
    s = re.sub(r"\s+", " ", str(text or "").strip())
    if not s:
        return True
    low = s.lower()
    
    # 1) Standard rejections
    if low in {"unknown", "document", "front matter", "body", "content", "contents", "table of contents"}:
        return True
    if re.match(r"^\[source:.*\]$", low):
        return True
    if re.match(r"^(?:page|p\.)\s*[0-9ivxlcdm]+$", low):
        return True
    if re.match(r"^(?:chapter|unit)\s+\d+(?:\.\d+){0,2}$", low):
        return True
    if re.match(r"^section\s+\d+(?:\.\d+){0,4}$", low):
        return True
    if re.match(r"^\d+$", low):
        return True

    # 2) Generic Junk Filters (ISBN, URL, Metadata)
    
    # ISBN patterns: 978-81-...
    if re.search(r"\b\d{2,}-\d{2,}-\d{2,}", low):
        return True
        
    # URL/Domain patterns
    if any(x in low for x in ["http", "www", ".com", ".in", ".org", ".net", ".edu"]):
        if low.count(".") > 1 or "www" in low or "http" in low or "://" in low:
            return True

    # Repeated structural tokens: "Unit 1 Unit 1"
    if re.search(r"\b(\w+\s+\d+)\s+\1\b", low):
        return True

    # Digit/Word ratio: metadata usually has many numbers vs real words
    words = re.findall(r"[a-z]{3,}", low)
    digits = re.findall(r"\d+", low)
    if digits and len(digits) > len(words):
        # Allow small headings like "3. Concepts" (len(digits)=1, len(words)=1)
        if len(digits) > 2:
            return True
        
    # Complexity/Junk check (long lines with high symbol/digit density)
    if len(s) > 60:
        symbols = re.findall(r"[^A-Za-z0-9\s]", s)
        if len(symbols) > 5 or len(digits) > 4:
            return True
            
    # Mostly Uppercase with no real words (excludes acronyms if they are part of words)
    if s.isupper() and not any(len(w) > 2 for w in re.findall(r"[A-Z]+", s)):
        if len(s) > 4: # Allow very short markers like "SECTION" or "PART"
            return True

    return False

def _is_heading_candidate_line(line: str) -> bool:
    s = re.sub(r"\s+", " ", str(line or "").strip())
    if not s:
        return False
    if _is_placeholder_heading_text(s):
        return False
    word_count = len(re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", s))
    if word_count < 3 or word_count > 10:
        return False
    punct = re.findall(r"[,:;.!?]", s)
    if len(punct) > 1:
        return False
    if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
        return False
    words = [w for w in re.findall(r"[A-Za-z][A-Za-z'\-]*", s)]
    if not words:
        return False
    title_case_count = sum(1 for w in words if w[:1].isupper())
    all_caps_count = sum(1 for w in words if w.isupper() and len(w) >= 2)
    title_like = title_case_count >= max(2, int(0.5 * len(words)))
    all_caps_like = all_caps_count >= max(2, int(0.5 * len(words)))
    return bool(title_like or all_caps_like or s.endswith(":"))

def _extract_heading_like_lines_from_chunk(text: str, max_lines: int = 24) -> list[str]:
    lines = [re.sub(r"\s+", " ", ln).strip() for ln in str(text or "").splitlines()[: max(1, max_lines)] if str(ln or "").strip()]
    out: list[str] = []
    for ln in lines:
        if len(ln) > 120:
            continue
        if ln.startswith("[Source:"):
            continue
        if _is_placeholder_heading_text(ln):
            S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', ln[:120])
            continue
        if _is_heading_candidate_line(ln):
            out.append(ln)
    return out[:10]

def _extract_heading_snippets_from_line(line: str) -> list[str]:
    s = re.sub(r"\s+", " ", str(line or "").strip())
    if not s:
        return []
    if s.startswith("[Source:") and "]" in s:
        s = s.split("]", 1)[1].strip()
    if not s:
        return []

    segments = [
        re.sub(r"\s+", " ", seg).strip(" -–—:;,.\t")
        for seg in re.split(r"[•\|]|\s{2,}|\s+[-–—]\s+|(?<=[?!:])\s+", s)
        if str(seg or "").strip()
    ]

    out: list[str] = []
    seen: set[str] = set()
    for seg in segments[:8]:
        if len(seg) > 110:
            continue
        if _is_placeholder_heading_text(seg):
            continue
        words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", seg)
        if not (3 <= len(words) <= 10):
            continue
        if re.search(r"\b(?:is|are|was|were|has|have|had|because|therefore|however|which|that|who)\b", seg.lower()):
            continue
        if not _is_heading_candidate_line(seg):
            continue
        low = seg.lower()
        if low in seen:
            continue
        seen.add(low)
        out.append(seg)
    return out[:6]

def _is_document_title_heading_text(text: str) -> bool:
    s = re.sub(r"\s+", " ", str(text or "")).strip()
    if not s:
        return True
    low = s.lower()
    if _is_placeholder_heading_text(s):
        return True
    words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
    title_case_words = sum(1 for w in words if re.match(r"^[A-Z][a-zA-Z\-']+$", w))
    title_ratio = (float(title_case_words) / float(max(1, len(words)))) if words else 0.0
    has_local_marker = bool(
        s.endswith(":")
        or re.match(r"^\s*\d+(?:\.\d+)*\s+[A-Za-z]", s)
        or re.search(r"\b(?:section|part|topic|subsection)\s+\d+\b", low)
    )
    if has_local_marker:
        return False
    if re.search(r"\b[A-Za-z]{2,8}\s*[-–—]?\s*\d{2,4}[A-Za-z]?\b", s, flags=re.IGNORECASE):
        return True
    if re.search(r"[-–—]\s*[A-Za-z]{2,8}\s*\d{2,4}", s, flags=re.IGNORECASE):
        return True
    if re.search(r"\b(?:introduction|intro\s*duction|fundamentals|basics|overview)\s+to\b", s, flags=re.IGNORECASE):
        return True
    if re.search(r"\b(?:course|syllabus|textbook|edition|semester|module|manual)\b", s, flags=re.IGNORECASE) and title_ratio >= 0.5:
        return True
    return False

def _resolve_doc_heading_source(query_text: str, doc: dict) -> dict[str, Any]:
    txt = str((doc or {}).get("page_content") or (doc or {}).get("text") or "")
    metadata = (doc or {}).get("metadata") or {}
    list_goal_mode = _is_goal_objective_list_query(query_text)
    q_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", str(query_text or "").lower())
        if t not in {"what", "which", "are", "the", "and", "for", "with", "from", "list", "name", "give", "mention", "identify"}
    ]

    raw_candidates: list[str] = []
    scored: list[tuple[float, str]] = []
    placeholder_rejected = False
    document_title_rejected = False
    metadata_candidates: list[str] = []
    for key in ("title", "section", "chapter"):
        value = re.sub(r"\s+", " ", str(metadata.get(key) or "").strip())
        if not value or value.lower() in {"document", "page"}:
            continue
        if _is_placeholder_heading_text(value):
            placeholder_rejected = True
            S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', value[:120])
            continue
        if list_goal_mode and _is_attribution_or_citation_heading_text(value):
            S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_attribution_citation=True', value[:120])
            continue
        if value.lower() not in {v.lower() for v in metadata_candidates}:
            metadata_candidates.append(value)
    if metadata_candidates:
        chosen = metadata_candidates[0]
        S.logger.info("[HEADING SOURCE DEBUG] raw_candidates=%s", metadata_candidates[:8])
        S.logger.info('[HEADING SOURCE DEBUG] chosen_heading="%s"', chosen[:120])
        S.logger.info("[HEADING SOURCE DEBUG] chosen_from=metadata")
        return {
            "chosen_heading": chosen,
            "chosen_from": "metadata",
            "raw_candidates": metadata_candidates[:8],
            "heading_lines": metadata_candidates[:6],
            "placeholder_rejected": bool(placeholder_rejected),
            "document_title_rejected": bool(document_title_rejected),
        }
    lines = str(txt or "").splitlines()[:140]
    for raw_ln in lines:
        ln = re.sub(r"\s+", " ", str(raw_ln or "").strip())
        if not ln:
            continue
        for cand in _extract_heading_snippets_from_line(ln):
            if _is_placeholder_heading_text(cand):
                placeholder_rejected = True
                S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', cand[:120])
                continue
            if list_goal_mode and _is_attribution_or_citation_heading_text(cand):
                S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_attribution_citation=True', cand[:120])
                continue
            if _is_document_title_heading_text(cand):
                document_title_rejected = True
                S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_document_title=True', cand[:120])
                continue
            raw_candidates.append(cand)
            low = cand.lower()
            overlap = sum(1 for tok in q_tokens if _token_match_light(low, tok))
            title_like = 1.0 if bool(re.match(r"^[A-Z][A-Za-z0-9\- ,()]{3,90}$", cand)) else 0.0
            all_caps = 0.8 if bool(re.match(r"^[A-Z0-9\- ]{3,90}$", cand) and re.search(r"[A-Z]{3,}", cand)) else 0.0
            colon = 0.7 if cand.endswith(":") else 0.0
            score = (1.45 * float(overlap)) + title_like + all_caps + colon
            scored.append((score, cand))

    S.logger.info("[HEADING SOURCE DEBUG] raw_candidates=%s", raw_candidates[:8])

    if not scored:
        S.logger.info('[HEADING SOURCE DEBUG] chosen_heading=""')
        S.logger.info("[HEADING SOURCE DEBUG] chosen_from=none")
        S.logger.info("[HEADING SOURCE DEBUG] no_real_heading_found=True")
        return {
            "chosen_heading": "",
            "chosen_from": "none",
            "raw_candidates": raw_candidates[:8],
            "heading_lines": [],
            "placeholder_rejected": bool(placeholder_rejected),
            "document_title_rejected": bool(document_title_rejected),
        }

    scored.sort(key=lambda x: x[0], reverse=True)
    chosen = scored[0][1]
    S.logger.info('[HEADING SOURCE DEBUG] chosen_heading="%s"', chosen[:120])
    S.logger.info("[HEADING SOURCE DEBUG] chosen_from=body_line")
    return {
        "chosen_heading": chosen,
        "chosen_from": "body_line",
        "raw_candidates": raw_candidates[:8],
        "heading_lines": [x[1] for x in scored[:6]],
        "placeholder_rejected": bool(placeholder_rejected),
        "document_title_rejected": bool(document_title_rejected),
    }

def _concept_proximity_score(
    query_tokens: list[str],
    heading_text: str,
    body_text: str,
) -> tuple[float, float]:
    """Generic concept-alignment scorer (MP-C3).

    For every pair of distinct query tokens, count how often they
    co-occur in a tight word-level window inside the chunk's heading
    and body. Repeated tight co-occurrences indicate that the chunk
    actually talks about the queried concept as a whole. A single
    incidental neighbour is not enough to outscore a chunk whose
    primary topic is the queried concept.

    Returns (proximity_score, dispersion_penalty), each roughly in
    [0, ~1.5]. Pure positional logic on the query's own non-stopword
    tokens — no domain words, no special cases.
    """
    raw_toks = [t for t in (query_tokens or []) if t and len(t) >= 3]
    seen: set[str] = set()
    uniq: list[str] = []
    for t in raw_toks:
        norm = _light_normalize_query_token(t)
        if not norm or norm in seen:
            continue
        seen.add(norm)
        uniq.append(norm)
    if len(uniq) < 2:
        return 0.0, 0.0

    def _positions(text: str, max_words: int) -> tuple[dict[str, list[int]], int]:
        words = re.findall(r"[a-z0-9]+", str(text or "").lower())
        if max_words and len(words) > max_words:
            words = words[:max_words]
        pos: dict[str, list[int]] = {}
        for i, w in enumerate(words):
            n = _light_normalize_query_token(w)
            if not n:
                continue
            pos.setdefault(n, []).append(i)
        return pos, len(words)

    head_pos, _head_n = _positions(heading_text, 200)
    body_pos, _body_n = _positions(body_text, 4000)

    def _close_pair_count(a: list[int], b: list[int], window: int) -> tuple[int, int]:
        """Return (close_pairs, min_distance)."""
        if not a or not b:
            return 0, 10**9
        a_s = sorted(a)
        b_s = sorted(b)
        close = 0
        best = 10**9
        # Two-pointer for min-distance + window-count via merged scan
        for ai in a_s:
            # Count b positions within window of ai
            for bj in b_s:
                d = abs(ai - bj)
                if d < best:
                    best = d
                if d <= window:
                    close += 1
            # Cap pairs per anchor to keep score bounded
        return close, best

    pair_scores: list[float] = []
    pair_disp: list[float] = []
    for i in range(len(uniq)):
        for j in range(i + 1, len(uniq)):
            a, b = uniq[i], uniq[j]
            head_close, head_d = _close_pair_count(
                head_pos.get(a, []), head_pos.get(b, []), window=12
            )
            body_close, body_d = _close_pair_count(
                body_pos.get(a, []), body_pos.get(b, []), window=8
            )
            score = 0.0
            # Heading co-occurrence is the strongest signal.
            if head_close > 0:
                score += 1.0 + (0.15 * min(3, head_close - 1))
            # Body tight co-occurrences accumulate (saturating).
            if body_close > 0:
                score += min(1.0, 0.30 * body_close)
            # Modest credit for any same-paragraph-ish proximity.
            if score == 0.0 and body_d <= 40:
                score = 0.20
            elif score == 0.0 and body_d <= 120:
                score = 0.05
            pair_scores.append(score)

            a_present = bool(head_pos.get(a) or body_pos.get(a))
            b_present = bool(head_pos.get(b) or body_pos.get(b))
            if not (a_present and b_present):
                pair_disp.append(0.6)
            elif body_close == 0 and head_close == 0 and body_d > 60:
                pair_disp.append(0.4)
            else:
                pair_disp.append(0.0)

    n = max(1, len(pair_scores))
    return float(sum(pair_scores) / n), float(sum(pair_disp) / n)

def _doc_query_token_signals(query_text: str, family_v2: str, doc: dict) -> dict[str, float]:
    tokens = _query_section_tokens(query_text, family_v2)
    section_phrases = _query_section_phrases(query_text)
    phrase_tokens: set[str] = set()
    for ph in section_phrases:
        for pt in re.findall(r"[a-z0-9]{3,}", ph.lower()):
            phrase_tokens.add(pt[:-1] if pt.endswith("s") and len(pt) > 4 else pt)
    md = dict((doc or {}).get("metadata") or {})
    txt = str((doc or {}).get("page_content") or (doc or {}).get("text") or "")
    low_txt = txt.lower()
    norm_txt = _normalize_phrase_text(txt)
    local_promoted = bool(md.get("_local_window_promoted") or md.get("local_window_promoted"))
    local_focus_hits_raw = float(md.get("local_focus_hits") or md.get("_local_focus_hits") or 0.0)
    local_heading_match_raw = float(md.get("local_heading_match") or md.get("_local_heading_match") or 0.0)
    local_list_density_raw = float(md.get("local_list_density") or md.get("_local_list_density") or 0.0)
    local_conf_raw = float(md.get("local_confidence_score") or md.get("_local_confidence_score") or md.get("_local_window_score") or 0.0)
    local_conf_norm = min(1.0, (local_conf_raw / 6.0)) if local_conf_raw > 1.0 else max(0.0, local_conf_raw)
    heading_src = _resolve_doc_heading_source(query_text, doc)
    heading_parts: list[str] = []
    chosen_heading = str(heading_src.get("chosen_heading") or "").strip()
    if chosen_heading:
        heading_parts.append(chosen_heading)
    for k in ("heading", "section", "title", "chapter", "role"):
        val = str(md.get(k) or "").strip()
        if not val:
            continue
        if _is_placeholder_heading_text(val):
            S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_placeholder=True', val[:120])
            continue
        if _is_document_title_heading_text(val):
            S.logger.info('[HEADING SOURCE DEBUG] raw_heading="%s" rejected_as_document_title=True', val[:120])
            continue
        heading_parts.append(val)
    heading_lines = [str(x).strip() for x in (heading_src.get("heading_lines") or []) if str(x).strip()]
    heading_parts.extend(heading_lines)
    heading_blob = " ".join(heading_parts).lower()
    norm_heading = _normalize_phrase_text(" ".join(heading_parts))
    heading_detected = bool(chosen_heading)
    toc_like = bool(re.search(r"\b(?:table\s+of\s+contents|contents?)\b", f"{heading_blob}\n{low_txt[:900]}"))
    goal_list_mode = _is_goal_objective_list_query(query_text, family_v2)
    possessive_owner_tokens = [
        t for t in re.findall(r"\b([a-z0-9][a-z0-9\-]{2,})[’']s\b", str(query_text or "").lower())
        if t not in {"what", "which", "list", "name", "give", "mention", "identify", "stage", "stages", "development"}
    ]

    if not tokens:
        return {
            "token_hits": 0.0,
            "heading_hits": 0.0,
            "missing_penalty": 0.0,
            "generic_penalty": 0.0,
            "density": 0.0,
        }

    token_hits = 0.0
    heading_hits = 0.0
    focus_hits = 0.0
    matched = 0
    for tok in tokens:
        tok_weight = 1.0
        if family_v2 in {"list_entity", "list_structure"} and phrase_tokens:
            tok_weight = 1.0 if tok in phrase_tokens else 0.25
        in_heading_exact = bool(_token_match_light(heading_blob, tok))
        in_heading_near = False
        in_body_exact = bool(_token_match_light(low_txt, tok))
        in_body_near = False
        if in_heading_exact:
            heading_hits += 1.0 * tok_weight
        elif in_heading_near:
            heading_hits += 0.65 * tok_weight
        if in_body_exact:
            token_hits += 1.0 * tok_weight
        elif in_body_near:
            token_hits += 0.55 * tok_weight
        if tok in phrase_tokens and (in_heading_exact or in_heading_near or in_body_exact or in_body_near):
            focus_hits += 1.0
        if in_heading_exact or in_heading_near or in_body_exact or in_body_near:
            matched += 1

    missing = max(0, len(tokens) - matched)
    words = re.findall(r"[a-z0-9]+", low_txt)
    density = token_hits / max(12.0, float(len(words)))

    phrase_hits = 0.0
    for ph in section_phrases:
        ph_norm = _normalize_phrase_text(ph)
        if not ph_norm:
            continue
        if ph_norm in norm_heading:
            phrase_hits += 2.2
            heading_hits += 0.9
            heading_detected = True
            continue
        # MP-C1 generic widening: previously the body scan only looked at
        # the first 1800 normalised characters, which missed in-chunk
        # subsection headings further down (e.g. a "Characteristics of X"
        # heading appearing after a long preamble). Scan the full chunk
        # body so a literal phrase match anywhere is rewarded. Cheap.
        if ph_norm in norm_txt:
            phrase_hits += 1.4
            continue

        ph_toks = [t for t in re.findall(r"[a-z0-9]{3,}", ph_norm)]
        if ph_toks:
            heading_overlap = sum(1 for t in ph_toks if _token_match_light(heading_blob, t)) / max(1, len(ph_toks))
            body_overlap = sum(1 for t in ph_toks if _token_match_light(low_txt, t)) / max(1, len(ph_toks))
            if heading_overlap >= 0.60:
                phrase_hits += 0.95
                heading_hits += 0.55
                heading_detected = True
            elif body_overlap >= 0.60:
                phrase_hits += 0.60

    if tokens and heading_lines:
        for ln in heading_lines[:6]:
            ln_low = ln.lower()
            overlap = sum(1 for tok in tokens if _token_match_light(ln_low, tok))
            ratio = overlap / max(1, len(tokens))
            if overlap >= 1 and ratio >= 0.35:
                heading_hits += 0.65 + (0.25 * min(1.0, ratio))
                heading_detected = True

    marker_score = _list_marker_score(txt) if family_v2 in {"list_entity", "list_structure"} else 0.0
    if local_promoted:
        marker_score = max(marker_score, min(1.5, local_list_density_raw * 1.8))
        focus_hits += max(0.0, 0.65 * local_focus_hits_raw)
        heading_hits += max(0.0, 0.45 * local_heading_match_raw)
        phrase_hits += max(0.0, 0.25 * local_heading_match_raw)

    generic_penalty = 0.0
    if family_v2 in {"list_entity", "list_structure"}:
        if heading_hits <= 0.0 and token_hits <= 0.0:
            generic_penalty += 0.9
        if re.search(r"\b(?:introduction|overview|summary|historical\s+background|important\s+terminology|key\s+terms?)\b", heading_blob):
            generic_penalty += 0.55
        if marker_score <= 0.05:
            generic_penalty += 0.35
        if heading_hits <= 0.0 and marker_score <= 0.10 and phrase_hits <= 0.0:
            generic_penalty += 0.85
        if phrase_tokens and focus_hits <= 0.0:
            generic_penalty += 0.75
        if toc_like:
            # Keep TOC chunks as heading hints, but lower content priority for answers.
            generic_penalty += 0.45
            if phrase_hits > 0.0 or heading_hits > 0.0:
                heading_hits += 0.25
                phrase_hits += 0.20
            else:
                generic_penalty += 0.55
        if local_promoted:
            generic_penalty -= (0.45 * local_conf_norm)
            generic_penalty -= (0.20 * min(1.0, local_focus_hits_raw / 2.0))
            generic_penalty -= (0.20 * min(1.0, local_list_density_raw / 0.2))
            generic_penalty = max(0.0, generic_penalty)

        if goal_list_mode:
            context_tokens_local, _focus_tokens_local = _split_query_context_focus_tokens(query_text, family_v2)
            relation_match = False
            for ctx_tok in context_tokens_local[:3]:
                ctx = re.escape(ctx_tok)
                if re.search(rf"\b(?:goals?|objectives?|aims?)\s+(?:of|for)\s+(?:the\s+)?{ctx}\b", heading_blob):
                    relation_match = True
                    break
                if re.search(rf"\b{ctx}\s+(?:goals?|objectives?|aims?)\b", heading_blob):
                    relation_match = True
                    break
                if re.search(rf"\b(?:goals?|objectives?|aims?)\s+(?:of|for)\s+(?:the\s+)?{ctx}\b", low_txt[:1400]):
                    relation_match = True
                    break
                if re.search(rf"\b{ctx}\s+(?:goals?|objectives?|aims?)\b", low_txt[:1400]):
                    relation_match = True
                    break

            has_goal_lexeme = bool(re.search(r"\b(?:goals?|objectives?|aims?)\b", f"{chosen_heading.lower()} {low_txt[:1400]}"))
            heading_goal_like = bool(re.search(r"\b(?:goals?|objectives?|aims?)\b", chosen_heading.lower()))

            if chosen_heading and _is_attribution_or_citation_heading_text(chosen_heading):
                heading_detected = False
                generic_penalty += 0.95
            if heading_detected and chosen_heading and (not heading_goal_like):
                heading_detected = False
                generic_penalty += 0.75
            if not relation_match:
                phrase_hits *= 0.35
                generic_penalty += 0.85
                if has_goal_lexeme:
                    marker_score = min(marker_score, 0.35)
                    generic_penalty += 2.35
                    if re.search(r"\b(?:setting|evaluating|maintaining|achieving|pursuing|tracking)\s+goals?\b", low_txt[:1400]):
                        generic_penalty += 2.25

        if possessive_owner_tokens:
            owner_hit = any(
                _token_match_light(f"{heading_blob} {low_txt[:2200]}", owner_tok)
                for owner_tok in possessive_owner_tokens[:2]
            )
            owner_stage_relation = any(
                re.search(
                    rf"\b{re.escape(owner_tok)}\b[^\n.]{{0,80}}\b(?:stage|stages|development|theory|model|approach)\b",
                    f"{heading_blob} {low_txt[:2200]}"
                )
                for owner_tok in possessive_owner_tokens[:2]
            )
            if not owner_hit:
                phrase_hits *= 0.55
                heading_hits *= 0.65
                token_hits *= 0.75
                generic_penalty += 2.35
            elif not owner_stage_relation:
                generic_penalty += 0.55
            else:
                phrase_hits += 0.45

    # Phase 5: Consolidated Prose Ranking Boost logic
    prose_list_hint = 0.0
    # (Generic hint logic removed to prevent noise/timeouts)

    # MP-C3: Generic concept-proximity alignment.
    # Reward chunks where the query's own non-stopword tokens co-occur
    # close together (heading or body); penalise chunks where the tokens
    # are scattered or only one is present. Pure positional logic — no
    # domain words, no special cases.
    concept_proximity, concept_dispersion = _concept_proximity_score(
        tokens, heading_blob, low_txt
    )

    return {
        "token_hits": float(token_hits),
        "heading_hits": float(heading_hits),
        "phrase_hits": float(phrase_hits + prose_list_hint),
        "focus_hits": float(focus_hits),
        "marker_score": float(marker_score),
        "missing_penalty": float(0.45 * missing),
        "generic_penalty": float(generic_penalty),
        "density": float(density),
        "local_promoted": float(1.0 if local_promoted else 0.0),
        "local_focus_hits": float(local_focus_hits_raw),
        "local_heading_match": float(local_heading_match_raw),
        "local_list_density": float(local_list_density_raw),
        "local_confidence_score": float(local_conf_norm),
        "toc_hint": float(1.0 if toc_like else 0.0),
        "heading_detected": float(1.0 if heading_detected else 0.0),
        "heading_placeholder_rejected": float(1.0 if heading_src.get("placeholder_rejected") else 0.0),
        "heading_document_title_rejected": float(1.0 if heading_src.get("document_title_rejected") else 0.0),
        "concept_proximity": float(concept_proximity),
        "concept_dispersion": float(concept_dispersion),
    }

def _apply_heading_boost_for_family(query_text: str, family_v2: str, docs: list[dict]) -> list[dict]:
    if not docs:
        return docs
    S.logger.info("[HEADING BOOST DISABLED] family=%s docs=%d", family_v2, len(docs or []))
    return list(docs or [])


    context_tokens, focus_tokens = _split_query_context_focus_tokens(query_text, family_v2)

    def _doc_debug_key(doc: dict) -> str:
        md_local = dict((doc or {}).get("metadata") or {})
        src = str(md_local.get("source") or md_local.get("filename") or md_local.get("id") or "")
        return f"{src}::{md_local.get('chunk_index')}"

    scored: list[tuple[float, dict, float, float]] = []
    base_rank_items: list[tuple[float, str]] = []
    heading_debug_rows: list[dict[str, Any]] = []
    for d in docs:
        md = dict((d or {}).get("metadata") or {})
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        head = " ".join(str(md.get(k) or "") for k in ("section", "title", "chapter", "heading", "role")).lower()
        hay = f"{head}\n{txt[:1800].lower()}"

        base = 0.0
        for k in ("score", "final_score", "similarity"):
            if k in (d or {}):
                try:
                    base = float((d or {}).get(k) or 0.0)
                except Exception:
                    base = 0.0
                break
        base_rank_items.append((base, _doc_debug_key(d)))

        boost = 0.0
        sig = _doc_query_token_signals(query_text, family_v2, d)
        boost += (0.75 * sig.get("heading_hits", 0.0))
        boost += (0.45 * sig.get("token_hits", 0.0))
        boost += (0.85 * sig.get("phrase_hits", 0.0))
        boost += (0.35 * sig.get("marker_score", 0.0))
        boost += (20.0 * sig.get("density", 0.0))
        boost -= sig.get("missing_penalty", 0.0)
        boost -= sig.get("generic_penalty", 0.0)
        if family_v2 in {"toc_structure"}:
            if "table of contents" in hay:
                boost += 0.85
        if family_v2 in {"definition_entity", "definition_comparison", "fact_entity"}:
            if re.search(r"\bdefined\s+as\b|\brefers\s+to\b", hay):
                boost += 1.1

        noise = _doc_ocr_noise_score(txt)
        if noise > 0:
            boost -= min(0.9, 0.15 * noise)

        final_score = base + boost
        d2 = dict(d)
        d2["_heading_boost"] = round(boost, 4)
        d2["_noise_score"] = round(noise, 4)
        d2["_boosted_score"] = round(final_score, 4)
        d2["_section_token_hits"] = round(sig.get("token_hits", 0.0), 4)
        d2["_section_heading_hits"] = round(sig.get("heading_hits", 0.0), 4)
        d2["_section_phrase_hits"] = round(sig.get("phrase_hits", 0.0), 4)
        d2["_section_marker_score"] = round(sig.get("marker_score", 0.0), 4)
        d2["_section_density"] = round(sig.get("density", 0.0), 6)
        heading_src = _resolve_doc_heading_source(query_text, d)
        heading_line = str(heading_src.get("chosen_heading") or "").strip()
        if not heading_line:
            heading_lines_local = _extract_heading_like_lines_from_chunk(txt, max_lines=8)
            heading_line = heading_lines_local[0] if heading_lines_local else ""
        heading_l = heading_line.lower()
        heading_query_match = bool(any(re.search(rf"\b{re.escape(t)}\b", heading_l) for t in context_tokens)) if context_tokens else False
        heading_focus_match = bool(any(re.search(rf"\b{re.escape(t)}\b", heading_l) for t in focus_tokens)) if focus_tokens else False
        heading_bonus_component = (0.75 * sig.get("heading_hits", 0.0))
        heading_debug_rows.append({
            "key": _doc_debug_key(d),
            "chunk": md.get("chunk_index"),
            "heading": heading_line,
            "query_match": heading_query_match,
            "focus_match": heading_focus_match,
            "heading_bonus": round(float(heading_bonus_component), 4),
        })
        scored.append((final_score, d2, boost, noise))

    scored.sort(key=lambda x: x[0], reverse=True)
    boosted_docs = [x[1] for x in scored]

    if family_v2 in {"list_entity", "list_structure"}:
        base_rank_items.sort(key=lambda x: x[0], reverse=True)
        base_rank_map = {key: idx for idx, (_base_score, key) in enumerate(base_rank_items)}
        boosted_rank_map = {_doc_debug_key(d): idx for idx, d in enumerate(boosted_docs)}
        heading_debug_map = {row.get("key"): row for row in heading_debug_rows}
        for d in boosted_docs[: min(5, len(boosted_docs))]:
            key = _doc_debug_key(d)
            row = heading_debug_map.get(key) or {}
            before_rank = base_rank_map.get(key, 999)
            after_rank = boosted_rank_map.get(key, 999)
            won_by_heading = bool(after_rank < before_rank)
            S.logger.info(
                "[HEADING DEBUG] chunk=%s heading=%s query_match=%s focus_match=%s heading_bonus=%.3f won_by_heading_boost=%s",
                row.get("chunk"),
                (row.get("heading") or "")[:120],
                bool(row.get("query_match")),
                bool(row.get("focus_match")),
                float(row.get("heading_bonus", 0.0) or 0.0),
                won_by_heading,
            )

    if family_v2 in {"list_entity", "list_structure", "toc_structure"} and len(boosted_docs) >= 2:
        best_i = 0
        best_cluster_score = -10**9
        for i, d in enumerate(boosted_docs[: min(8, len(boosted_docs))]):
            md = dict((d or {}).get("metadata") or {})
            source_id = str(md.get("source") or md.get("filename") or md.get("id") or "")
            chunk_idx = md.get("chunk_index")
            try:
                chunk_idx_int = int(chunk_idx)
            except Exception:
                chunk_idx_int = None

            center = float((d or {}).get("_boosted_score", 0.0) or 0.0)
            cluster = center
            if source_id and chunk_idx_int is not None:
                for j, dj in enumerate(boosted_docs[: min(12, len(boosted_docs))]):
                    if j == i:
                        continue
                    mdj = dict((dj or {}).get("metadata") or {})
                    source_j = str(mdj.get("source") or mdj.get("filename") or mdj.get("id") or "")
                    if source_j != source_id:
                        continue
                    try:
                        cj = int(mdj.get("chunk_index"))
                    except Exception:
                        continue
                    if abs(cj - chunk_idx_int) <= 1:
                        cluster += 0.45 * float((dj or {}).get("_boosted_score", 0.0) or 0.0)
            if cluster > best_cluster_score:
                best_cluster_score = cluster
                best_i = i

        if best_i > 0:
            anchor = boosted_docs[best_i]
            md_a = dict((anchor or {}).get("metadata") or {})
            src_a = str(md_a.get("source") or md_a.get("filename") or md_a.get("id") or "")
            try:
                idx_a = int(md_a.get("chunk_index"))
            except Exception:
                idx_a = None
            front: list[dict] = [anchor]
            if src_a and idx_a is not None:
                for d in boosted_docs:
                    if d is anchor:
                        continue
                    md_d = dict((d or {}).get("metadata") or {})
                    src_d = str(md_d.get("source") or md_d.get("filename") or md_d.get("id") or "")
                    if src_d != src_a:
                        continue
                    try:
                        idx_d = int(md_d.get("chunk_index"))
                    except Exception:
                        continue
                    if abs(idx_d - idx_a) <= 1:
                        front.append(d)
            tail = [d for d in boosted_docs if d not in front]
            boosted_docs = front + tail
            S.logger.info("[SECTION CONSISTENCY] family=%s anchor_moved_from=%s cluster_docs=%s", family_v2, best_i, len(front))

    top_trace = []
    for idx, d in enumerate(boosted_docs[:3]):
        md = dict((d or {}).get("metadata") or {})
        top_trace.append({
            "rank": idx,
            "id": str(md.get("id") or md.get("doc_id") or md.get("source") or "unknown"),
            "chunk_index": md.get("chunk_index"),
            "boost": d.get("_heading_boost"),
            "noise": d.get("_noise_score"),
        })
    S.logger.info("[HEADING BOOST] family=%s trace=%s", family_v2, top_trace)
    return boosted_docs

def clean_ocr_noise(text: str) -> str:
    if not text:
        return text

    text = text.replace("’", "'").replace("‘", "'")
    text = text.replace("“", '"').replace("”", '"')
    text = text.replace("–", "-").replace("—", "-")
    text = re.sub(r"[^\x00-\x7F]+", " ", text)
    text = re.sub(r"^(DEFINITION|KEY TERMS|TERMS|CONCEPT)\s*[:\-]?\s*", "", text, flags=re.IGNORECASE)
    _ocr_split_heads = {
        "acti", "emoti", "behav", "consequ", "organi", "experi", "environ", "scien"
    }
    text = re.sub(
        r"\b([A-Za-z]{2,8})\s+([A-Za-z]{2,})\b",
        lambda m: (m.group(1) + m.group(2)) if m.group(1).lower() in _ocr_split_heads else m.group(0),
        text,
    )
    split_fixes = [
        (r"\bin\s+dividuals?\b", lambda m: "individual" if m.group(0).lower().endswith("ual") else "individuals"),
        (r"\bfor\s+mulas?\b", lambda m: "formula" if m.group(0).lower().endswith("ula") else "formulas"),
    ]
    for patt, repl in split_fixes:
        text = re.sub(patt, repl, text, flags=re.IGNORECASE)
    text = re.sub(r"\s*/\s*", " / ", text)
    text = re.sub(r"\b(\w+)\s+\1\b", r"\1", text, flags=re.IGNORECASE)
    text = re.sub(r"[ \t]+", " ", text).strip()

    return text

def _strip_doc_structure_separators(text: str) -> str:
    """Remove ====, ---- separators and doc-title lines but KEEP Q:/A: labels.
    Used during sentence extraction so we can still skip Q: lines and prefer A: lines."""
    if not text:
        return text
    text = re.sub(r"(?m)^[=\-_~|]{4,}\s*$", "", text)
    text = re.sub(r"(?m)^.{3,80}\n[=\-_~]{4,}\s*$", "", text)
    text = re.sub(r"(?m)^[A-Z][A-Z0-9 &()/\-]{4,}\n[-=_]{4,}", "", text)
    text = re.sub(r"\s*[=\-_~]{4,}\s*", " ", text)
    text = re.sub(r"\n{3,}", "\n\n", text).strip()
    return text

def _strip_doc_structure_artifacts(text: str) -> str:
    """Remove document-header formatting (====, ----, Q:/A: labels) from answer text."""
    if not text:
        return text
    text = _strip_doc_structure_separators(text)
    # Strip Q:/A: labels from Q&A-style document chunks; keep the content
    text = re.sub(r"(?m)^Q:\s+", "", text)
    text = re.sub(r"(?m)^A:\s+", "", text)
    text = re.sub(r"\n{3,}", "\n\n", text).strip()
    return text

def _cleanup_final_answer_text(answer_text: str) -> str:
    raw = _strip_doc_structure_artifacts(str(answer_text or "").strip())
    txt = clean_ocr_noise(_repair_split_words(re.sub(r"[ \t]+", " ", raw).strip()))
    if not txt:
        return txt

    def _preserve_structured_list(value: str) -> str | None:
        lines = [re.sub(r"[ \t]+", " ", line).strip() for line in str(value or "").splitlines() if line.strip()]
        if len(lines) < 2:
            return None
        list_line_count = sum(
            1 for line in lines
            if re.match(r"^\s*(?:[-*\u2022]|\d+[.)])\s+\S", line)
        )
        if list_line_count < 2:
            return None
        normalized_lines: list[str] = []
        for line in lines:
            line = re.sub(r"^\s*[-*\u2022]\s+", "- ", line)
            normalized_lines.append(line)
        return "\n".join(normalized_lines)

    def _preserve_inline_bullet_chain(value: str) -> str | None:
        compact = re.sub(r"[ \t]+", " ", str(value or "")).strip()
        if not re.match(r"^\s*[-*\u2022]\s+\S", compact):
            return None
        body = re.sub(r"^\s*[-*\u2022]\s+", "", compact).strip()
        parts = [part.strip(" ,;:.") for part in re.split(r"\s+[-*\u2022]\s+", body) if part.strip(" ,;:.")]
        if len(parts) < 3:
            return None
        for part in parts:
            words = re.findall(r"[A-Za-z0-9][A-Za-z0-9'\-]*", part)
            if not (1 <= len(words) <= 8) or len(part) > 80:
                return None
        return "\n".join(f"- {part}" for part in parts)

    fixes = [
        (r"\bme\s*mory\b", "memory"),
        (r"\bin\s*dividuals?\b", "individual"),
        (r"\bfor\s*mulas?\b", "formula"),
    ]
    for patt, repl in fixes:
        txt = re.sub(patt, repl, txt, flags=re.IGNORECASE)

    txt, _prefix_repaired = _split_safe_ocr_merged_prefix_words(txt)
    # Do not merge normal English word pairs in user-visible answers.

    txt = re.sub(r"(?:^|\n)\s*[-•*]\s*(?:the|a|an)\s+(?:different|various|following)\s*(?=\n|$)", "", txt, flags=re.IGNORECASE)
    txt = re.sub(r"\s+-\s*(?:the|a|an)\s+(?:different|various|following)\s*$", "", txt, flags=re.IGNORECASE)

    glued_prefixes = (
        "these", "those", "this", "that", "the", "and", "or", "to", "of", "for", "with", "by",
        "from", "on", "into", "within",
    )
    glued_suffixes = {
        "is", "are", "was", "were", "be", "been", "being", "do", "does", "did", "have", "has", "had",
        "can", "could", "would", "will", "shall", "may", "might", "must",
    }
    rebuilt_words: list[str] = []
    for word in re.split(r"(\s+)", txt):
        if not word or word.isspace():
            rebuilt_words.append(word)
            continue
        # MP-C15: don't split well-formed capitalized words (e.g.
        # "Forecasting" → "For ecasting", "Organising" → "Or ganising").
        if re.match(r"^[A-Z][a-z]{4,}[,.;:!?\)]*$", word):
            rebuilt_words.append(word)
            continue
        lowered = word.lower()
        split_word = None
        for prefix in glued_prefixes:
            if lowered.startswith(prefix) and len(word) > len(prefix) + 2:
                tail = word[len(prefix):]
                tail_l = tail.lower().strip(".,:;!?)]}")
                safe_tail = bool(
                    tail_l in glued_suffixes
                    or _OCR_PREFIX_REMAINDER_SUFFIX_RE.search(tail_l)
                )
                if safe_tail:
                    split_word = f"{word[:len(prefix)]} {tail}"
                    break
        rebuilt_words.append(split_word or word)
    txt = "".join(rebuilt_words)

    txt = re.sub(r"\b([A-Z][a-z]{2,})\s+([A-Z])\s+([a-z]{2,})\b", r"\1 \2\3", txt)
    txt = re.sub(r"\b([A-Z][a-z]{2,})\s+([A-Z][a-z]{2,})\s+([A-Z][a-z]{2,})\b", r"\1 \2 \3", txt)
    txt = re.sub(r"\s+([,.;:!?])", r"\1", txt)

    inline_list = _preserve_inline_bullet_chain(txt)
    if inline_list is not None:
        return inline_list.strip('"\'“”‘’')

    preserved_list = _preserve_structured_list(txt)
    if preserved_list is not None:
        return preserved_list.strip('"\'“”‘’')

    parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+", txt) if p.strip()]
    if parts:
        deduped = []
        seen = set()
        for p in parts:
            key = re.sub(r"[^a-z0-9]+", " ", p.lower()).strip()
            if key and key not in seen:
                seen.add(key)
                deduped.append(p)
        parts = deduped

        is_labeled_comparison_answer = bool(
            len(re.findall(r"(?m)^\s*[A-Z][A-Za-z0-9'’\- ]{1,60}:\s+\S", txt)) >= 2
        )
        is_definition_like = bool(
            len(parts) > 1
            and re.search(r"\b(is|refers to|defined as|means)\b", parts[0].lower())
            and not re.match(r"^\s*after\b", parts[0], flags=re.IGNORECASE)
        )
        has_numeric_metric = any(re.search(r"\d+(?:\.\d+)?%", p) for p in parts)
        is_metric_fact_like = bool(
            has_numeric_metric
            and re.search(
                r"\b(?:exact|overall|total|average|highest|lowest|net|rate|percentage|percent)\b",
                txt,
                flags=re.IGNORECASE,
            )
        )
        if is_definition_like and not is_labeled_comparison_answer and not is_metric_fact_like:
            txt = parts[0]
        else:
            txt = " ".join(parts)

    txt = re.sub(r"\s{2,}", " ", txt).strip()
    txt = txt.strip('"\'“”‘’')
    return txt

_AR_FINAL_POLISH_STOPWORDS: set[str] = {
    "ما", "ماذا", "من", "كيف", "لماذا", "هل", "هذا", "هذه", "ذلك", "تلك", "بين", "في", "من", "عن", "على", "علي",
    "إلى", "الى", "و", "او", "أو", "هي", "هو", "هم", "هن", "يكون", "تكون", "يمكن", "يمكنك", "اشرح", "وضح", "لخص",
    "اختصر", "العلاقة", "العلاقه", "مهم", "مهمة", "مهمه",
}

def _is_structured_bullet_answer(value: str) -> bool:
    lines = [line for line in str(value or "").splitlines() if line.strip()]
    if len(lines) < 2:
        return False
    bullet_lines = sum(1 for line in lines if re.match(r"^\s*(?:[-*\u2022]|\d+[.)])\s+\S", line))
    return bullet_lines >= 2

def _normalize_final_bullet_format(value: str) -> str:
    text = str(value or "").strip()
    if not text:
        return text
    lines = [re.sub(r"[ \t]+", " ", line).strip() for line in text.splitlines() if line.strip()]
    if len(lines) >= 2 and sum(1 for line in lines if re.match(r"^\s*(?:[-*\u2022]|\d+[.)])\s+\S", line)) >= 2:
        out_lines: list[str] = []
        for line in lines:
            line = re.sub(r"^\s*(?:[-*\u2022]|\d+[.)])\s+", "- ", line)
            line = re.sub(r"\s+([,.;:!?؟،؛])", r"\1", line).strip()
            out_lines.append(line)
        return "\n".join(out_lines).strip()

    if re.match(r"^\s*[-*\u2022]\s+\S", text) and len(re.findall(r"\s[-*\u2022]\s+", text)) >= 2:
        body = re.sub(r"^\s*[-*\u2022]\s+", "", text).strip()
        parts = [part.strip(" \t\r\n-•*.,;:،؛") for part in re.split(r"\s+[-*\u2022]\s+", body) if part.strip(" \t\r\n-•*.,;:،؛")]
        if len(parts) >= 2:
            return "\n".join(f"- {part}" for part in parts)

    return text

def _normalize_arabic_readability_terms(value: str) -> str:
    text = str(value or "")
    if not _is_arabic_text(text):
        return text
    replacements = [
        (r"\b(?:السيطرة|التحكم)\b", "الرقابة"),
        (r"(?<![\u0621-\u064A])(?:و?رقابة)(?![\u0621-\u064A])", "الرقابة"),
        (r"(?<![\u0621-\u064A])(?:و?ضبط\s+الجودة)(?![\u0621-\u064A])", "الرقابة"),
        (r"\b(?:القيادة)\b", "التوجيه"),
        (r"(?<![\u0621-\u064A])(?:و?الإشراف|و?اشراف|و?إشراف|و?إرشاد|و?ارشاد)(?![\u0621-\u064A])", "التوجيه"),
        (r"\b(?:التعيين|استقطاب\s+العاملين)\b", "التوظيف"),
        (r"\b(?:الترتيب\s+الإداري|الترتيب\s+الاداري)\b", "التنظيم"),
        (r"(?<![\u0621-\u064A])تخطيط(?![\u0621-\u064A])", "التخطيط"),
        (r"(?<![\u0621-\u064A])تنظيم(?![\u0621-\u064A])", "التنظيم"),
        (r"(?<![\u0621-\u064A])توظيف(?![\u0621-\u064A])", "التوظيف"),
        (r"(?<![\u0621-\u064A])توجيه(?![\u0621-\u064A])", "التوجيه"),
    ]
    for pattern, replacement in replacements:
        text = re.sub(pattern, replacement, text)
    return text

def _arabic_final_query_tokens(query: str) -> list[str]:
    tokens: list[str] = []
    for token in re.findall(r"[\u0600-\u06FF]{3,}", str(query or "")):
        normalized = token.strip()
        if not normalized or normalized in _AR_FINAL_POLISH_STOPWORDS:
            continue
        if normalized not in tokens:
            tokens.append(normalized)
    return tokens[:8]

def _split_arabic_answer_units(value: str) -> list[str]:
    text = re.sub(r"[ \t]+", " ", str(value or "")).strip()
    if not text:
        return []
    line_units = [line.strip(" \t\r\n-•*،؛.,;:") for line in text.splitlines() if line.strip()]
    if len(line_units) >= 2:
        return [line for line in line_units if line]
    units = [part.strip(" \t\r\n-•*،؛.,;:") for part in re.split(r"(?<=[.!؟])\s+|[؛;]\s+", text) if part.strip(" \t\r\n-•*،؛.,;:")]
    if len(units) >= 2:
        return units
    comma_units = [part.strip(" \t\r\n-•*،؛.,;:") for part in re.split(r"\s+،\s+", text) if part.strip(" \t\r\n-•*،؛.,;:")]
    return comma_units if len(comma_units) >= 2 else ([text] if text else [])

def _clean_arabic_final_text(value: str) -> str:
    text = str(value or "").strip()
    if not text:
        return text
    text = text.replace("\ufffd", " ")
    text = re.sub(r"[\ud800-\udfff]", " ", text)
    text = re.sub(r"[\u2e80-\u2fff\u3000-\u9fff\uf900-\ufaff\ufe30-\ufe4f\uff00-\uffef]+", " ", text)
    text = re.sub(r"[ \t]+", " ", text)
    text = re.sub(r"\s+([،؛؟.!?,;:])", r"\1", text)
    text = re.sub(r"([،؛؟.!?,;:])(?:\s*\1)+", r"\1", text)
    text = re.sub(r"\s*\n\s*", "\n", text)
    text = _normalize_final_bullet_format(text)
    text = _normalize_arabic_readability_terms(text)
    if _is_structured_bullet_answer(text):
        return text.strip(" \t\r\n،,.;:")
    return text.strip(" \t\r\n-،,.;:")

def _shorten_arabic_spoken_answer(query: str, answer: str) -> str:
    text = _clean_arabic_final_text(answer)
    if not text or len(text) <= 350 or _is_structured_bullet_answer(text):
        return text
    units = _split_arabic_answer_units(text)
    if len(units) <= 1:
        return text
    query_tokens = _arabic_final_query_tokens(query)
    scored_units: list[tuple[float, int, str]] = []
    seen: set[str] = set()
    for idx, unit in enumerate(units):
        cleaned = _clean_arabic_final_text(unit)
        if not cleaned or len(cleaned) < 18:
            continue
        key = re.sub(r"[^\u0600-\u06FF0-9]+", " ", cleaned).strip()
        if not key or key in seen:
            continue
        seen.add(key)
        score = 0.0
        if query_tokens:
            score += 2.0 * sum(1 for token in query_tokens if token in cleaned)
        if re.search(r"\b(?:لذلك|لأن|لان|يساعد|يدعم|يوضح|يرتبط|العلاقة|أهمية|اهمية|ضروري|مهم)\b", cleaned):
            score += 1.0
        if re.search(r"\b(?:مثال|صفحة|الشكل|الجدول|الفصل|المصدر)\b", cleaned):
            score -= 0.8
        score += max(0.0, 0.6 - (len(cleaned) / 700.0))
        scored_units.append((score, idx, cleaned))
    if not scored_units:
        return text
    scored_units.sort(key=lambda item: (-item[0], item[1]))
    selected = sorted(scored_units[:3], key=lambda item: item[1])
    out_lines: list[str] = []
    total_chars = 0
    for _score, _idx, unit in selected:
        if len(out_lines) >= 3:
            break
        if total_chars and total_chars + len(unit) > 360:
            continue
        out_lines.append(unit)
        total_chars += len(unit)
    if not out_lines:
        out_lines = [scored_units[0][2]]
    shortened = "\n".join(out_lines[:3]).strip()
    return shortened if shortened and len(shortened) < len(text) else text

def _polish_final_response_text(query: str, answer: str) -> str:
    raw = str(answer or "").strip()
    if not raw or raw.lower() == RAG_NO_MATCH_RESPONSE.lower():
        return RAG_NO_MATCH_RESPONSE if raw.lower() == RAG_NO_MATCH_RESPONSE.lower() else raw
    if _is_arabic_text(raw):
        return _shorten_arabic_spoken_answer(query, raw)
    polished = _normalize_final_bullet_format(raw)
    polished = re.sub(r"([.!?,;:])(?:\s*\1)+", r"\1", polished)
    polished = re.sub(r"[ \t]+", " ", polished)
    polished = re.sub(r"\s+([,.;:!?])", r"\1", polished)
    return polished.strip('"\'“”‘’')

def _extract_fallback_list(query_text: str, docs: list[dict]) -> str | None:
    return None

def _query_tokens_for_evidence(query_text: str) -> list[str]:
    stop = {
        "what", "which", "who", "when", "where", "why", "how", "the", "this", "that", "these", "those",
        "is", "are", "was", "were", "be", "to", "of", "in", "on", "for", "and", "or", "with", "from",
        "a", "an", "do", "does", "did", "can", "could", "should", "would", "about", "main", "only",
        "list", "explain", "define", "tell", "me", "document", "chapter", "section", "topics", "covered",
        "difference", "between", "compared", "compare",
    }
    arabic_stop = {
        "ما", "ماذا", "من", "متي", "متى", "اين", "أين", "كيف", "لماذا", "هل", "هذا", "هذه", "ذلك", "تلك",
        "هؤلاء", "عن", "علي", "على", "في", "من", "الي", "إلى", "الى", "او", "أو", "و", "ثم", "مع", "ب", "ل",
        "هو", "هي", "هم", "هن", "انت", "أنت", "يمكن", "يمكنك", "ممكن", "هل", "اشرح", "لخص", "اذكر", "عدد",
        "قارن", "عرف", "تعريف", "المستند", "الوثيقه", "الوثيقة", "الفصل", "القسم", "الموضوعات", "ذلك",
        "الذي", "التي", "الذين", "اللتان", "الذى", "اي", "أي", "وما", "وهل", "وكيف", "بذلك",
    }
    normalized = str(query_text or "").lower()
    try:
        normalized = _normalize_query_for_router(query_text)
    except Exception:
        normalized = re.sub(r"\s+", " ", normalized).strip()

    tokens: list[str] = []
    for token in re.findall(r"[a-z0-9]{3,}|[\u0600-\u06FF]{2,}", normalized):
        if re.search(r"[\u0600-\u06FF]", token):
            arabic_token = re.sub(r"[\u064B-\u065F\u0670\u0640]", "", token)
            arabic_token = re.sub(r"[إأآٱ]", "ا", arabic_token)
            arabic_token = arabic_token.replace("ى", "ي").replace("ؤ", "و").replace("ئ", "ي").replace("ة", "ه")
            arabic_token = arabic_token.strip()
            if len(arabic_token) >= 2 and arabic_token not in arabic_stop:
                tokens.append(arabic_token)
            continue
        if token not in stop:
            tokens.append(token)
    return tokens

def _retrieval_evidence_metrics(query_text: str, retrieved_docs: list[dict]) -> Dict[str, float]:
    if not retrieved_docs:
        return {
            "coverage": 0.0,
            "focus_ratio": 0.0,
            "max_similarity": 0.0,
            "query_tokens": 0.0,
        }

    tokens = _query_tokens_for_evidence(query_text)
    top_docs = retrieved_docs[:4]
    top_texts = [str((d or {}).get("page_content") or (d or {}).get("text") or "").lower() for d in top_docs]
    combined = "\n".join(top_texts)

    if not tokens:
        return {
            "coverage": 1.0,
            "focus_ratio": 1.0,
            "max_similarity": _max_doc_similarity(retrieved_docs),
            "query_tokens": 0.0,
        }

    matched = {t for t in tokens if re.search(rf"\b{re.escape(t)}\b", combined)}
    coverage = len(matched) / max(1, len(set(tokens)))

    focused_chunks = 0
    min_hits = 1 if len(tokens) <= 2 else 2
    for txt in top_texts:
        hits = sum(1 for t in set(tokens) if re.search(rf"\b{re.escape(t)}\b", txt))
        if hits >= min_hits:
            focused_chunks += 1

    return {
        "coverage": float(coverage),
        "focus_ratio": float(focused_chunks / max(1, len(top_docs))),
        "max_similarity": float(_max_doc_similarity(retrieved_docs)),
        "query_tokens": float(len(set(tokens))),
    }

def _is_weak_retrieval_evidence(query_text: str, family: str, retrieved_docs: list[dict]) -> bool:
    if not retrieved_docs:
        return True

    metrics = _retrieval_evidence_metrics(query_text, retrieved_docs)
    coverage = metrics["coverage"]
    focus_ratio = metrics["focus_ratio"]
    max_similarity = metrics["max_similarity"]

    reliable = _retrieval_context_is_reliable(query_text, retrieved_docs)

    if family == "out_of_scope_candidate":
        return (coverage < 0.50) or (focus_ratio <= 0.0) or (max_similarity < 0.18)

    if family in {"definition_entity", "definition_comparison"}:
        return (coverage < 0.15 and focus_ratio <= 0.0 and max_similarity < 0.12)

    if family == "overview_chapter_compare":
        q = (query_text or "").lower()
        if ("chapter" in q or "main sections" in q or "document" in q) and not _docs_have_structure_markers(retrieved_docs):
            if coverage < 0.25 and max_similarity < 0.15:
                return True
        m = re.search(r"difference\s+between\s+(.+?)\s+and\s+(.+?)(?:\?|$)", q)
        if m:
            left = [t for t in re.findall(r"[a-z0-9]{3,}", m.group(1)) if t not in {"the", "and", "of"}]
            right = [t for t in re.findall(r"[a-z0-9]{3,}", m.group(2)) if t not in {"the", "and", "of"}]
            top_text = "\n".join(str((d or {}).get("page_content") or (d or {}).get("text") or "").lower() for d in retrieved_docs[:4])
            left_ok = any(re.search(rf"\b{re.escape(t)}\b", top_text) for t in left)
            right_ok = any(re.search(rf"\b{re.escape(t)}\b", top_text) for t in right)
            if not (left_ok and right_ok) and coverage < 0.35 and max_similarity < 0.18:
                return True
        return (coverage < 0.18 and focus_ratio <= 0.0 and max_similarity < 0.12)

    if family == "list_structure":
        return (coverage < 0.12 and focus_ratio <= 0.0 and max_similarity < 0.10)

    return (coverage < 0.22 and focus_ratio <= 0.0 and max_similarity < 0.15) or (not reliable and coverage < 0.35)

def _is_current_world_or_personal_query(query_text: str) -> bool:
    query_norm = _normalize_query_for_router(query_text)
    if not query_norm:
        return False
    question_like = bool(re.search(r"\b(?:what|which|who|when|where|why|how|do|does|did|can|could|should)\b", query_norm))
    if not question_like:
        return False
    if re.search(r"\b(?:today|tonight|tomorrow|yesterday|now|right now|current date|current time)\b", query_norm):
        return True
    if re.search(r"\b(?:weather|forecast|news|latest|recent|live|real time|currently)\b", query_norm):
        return True
    if re.search(r"\b(?:my name|my age|my location|my address|where do i|who am i|what am i doing)\b", query_norm):
        return True
    # Only flag opinion / subjective queries — NOT procedural "What should I do if..." support questions
    if re.search(r"\b(?:your opinion|do you think)\b", query_norm):
        return True
    if re.search(r"\bshould i\b", query_norm) and not re.search(
        r"\b(?:do|return|exchange|cancel|contact|report|use|pay|order|track|ship|get|check|request|claim|apply|submit)\b",
        query_norm,
    ):
        return True
    return False

def _is_generic_grounding_sentence(answer_text: str) -> bool:
    answer_norm = re.sub(r"\s+", " ", str(answer_text or "").strip().lower())
    if not answer_norm:
        return False
    if re.search(
        r"\b(?:concept|topic|term|subject|thing|idea|area)\s+"
        r"(?:discussed|mentioned|covered|found|available)\s+in\s+"
        r"(?:the\s+)?(?:document|context|text|material)\b",
        answer_norm,
    ):
        return True
    if re.search(
        r"\b(?:document|context|text|material)\s+"
        r"(?:mentions|discusses|covers|contains)\b.{0,80}\b"
        r"(?:concept|topic|term|subject|thing|idea|area)\b",
        answer_norm,
    ):
        return True
    if re.fullmatch(
        r"[a-z0-9'\- ]{1,80}\s+is\s+(?:a|an|the)?\s*"
        r"(?:concept|topic|term|subject|thing|idea|area)\.?",
        answer_norm,
    ):
        return True
    if re.search(r"\b(?:not enough|insufficient)\s+(?:information|context|evidence)\b", answer_norm):
        return True
    return False

def _has_symbolic_count_letter_support(query_text: str, answer_text: str, selected_docs: list[dict]) -> bool:
    query_info = S._detect_short_symbolic_list_query(query_text)
    if not query_info:
        return False
    support_text = "\n".join(
        [str(answer_text or "")]
        + [str((doc or {}).get("page_content") or (doc or {}).get("text") or "") for doc in (selected_docs or [])[:6]]
    )
    support_norm = S._normalize_symbolic_list_surface(support_text)
    if not support_norm:
        return False

    phrase_variants = [str(value or "") for value in (query_info.get("phrase_variants") or []) if str(value or "").strip()]
    if any(variant and variant in support_norm for variant in phrase_variants):
        return True

    count_value = query_info.get("count")
    count_terms: set[str] = set()
    if isinstance(count_value, int):
        count_terms.add(str(count_value))
        if count_value in _SYMBOLIC_LIST_NUMBER_WORDS:
            count_terms.add(_SYMBOLIC_LIST_NUMBER_WORDS[count_value])
    label_variants = {str(value or "") for value in (query_info.get("label_variants") or []) if str(value or "").strip()}
    has_count = bool(count_terms and any(re.search(rf"\b{re.escape(term)}\b", support_norm) for term in count_terms))
    has_label = bool(label_variants and any(re.search(rf"\b{re.escape(label)}\b", support_norm) for label in label_variants))
    return bool(has_count and has_label)

def _is_low_confidence_grounding(
    query: str,
    selected_docs: list[dict],
    answer: str,
    metadata: Dict[str, Any] | None = None,
) -> bool:
    answer_text = re.sub(r"\s+", " ", str(answer or "").strip())
    if not answer_text or answer_text.lower() == RAG_NO_MATCH_RESPONSE.lower():
        return False

    metadata_dict = dict(metadata or {})
    family = str(metadata_dict.get("query_family") or _classify_query_family_v2(query) or "")
    answer_type = str(metadata_dict.get("answer_type") or "")
    source_mode = str(metadata_dict.get("source_mode") or "")

    if source_mode in {"multi_source_synthesis", "generation", "executive_memo", "quiz_generation", "extreme_summary"}:
        return False
    if S._skip_deterministic_rag_shortcuts(query):
        return False

    if _is_current_world_or_personal_query(query):
        S.logger.info("[LOW CONFIDENCE GROUNDING] blocked reason=current_world_or_personal query=%s", str(query or "")[:160])
        return True

    if _is_generic_grounding_sentence(answer_text):
        S.logger.info("[LOW CONFIDENCE GROUNDING] blocked reason=generic_grounding_sentence answer=%s", answer_text[:180])
        return True

    if not selected_docs:
        S.logger.info("[LOW CONFIDENCE GROUNDING] blocked reason=no_selected_docs")
        return True

    if answer_type == "definition_structure_recovery":
        return False

    if _detect_language(answer_text) == "ar" and _detect_language(query) != "ar":
        return False

    metrics = _retrieval_evidence_metrics(query, selected_docs or [])
    coverage = float(metrics.get("coverage", 0.0) or 0.0)
    focus_ratio = float(metrics.get("focus_ratio", 0.0) or 0.0)
    max_similarity = float(metrics.get("max_similarity", 0.0) or 0.0)
    query_tokens = list(dict.fromkeys(_query_tokens_for_evidence(query)))
    symbolic_support = _has_symbolic_count_letter_support(query, answer_text, selected_docs or [])

    try:
        semantically_grounded = bool(_is_answer_grounded_in_docs(answer_text, selected_docs or [], query_text=query))
    except Exception:
        semantically_grounded = False

    combined_doc_text = "\n".join(
        str((doc or {}).get("page_content") or (doc or {}).get("text") or "")
        for doc in (selected_docs or [])[:4]
    ).lower()
    answer_norm = answer_text.lower()
    doc_token_hits = sum(1 for token in query_tokens if _token_match_light(combined_doc_text, token))
    answer_token_hits = sum(1 for token in query_tokens if _token_match_light(answer_norm, token))
    has_concept_overlap = bool(symbolic_support or doc_token_hits > 0 or answer_token_hits > 0)

    if query_tokens and not has_concept_overlap:
        S.logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=no_concept_overlap coverage=%.3f focus=%.3f top=%.3f tokens=%s",
            coverage,
            focus_ratio,
            max_similarity,
            query_tokens[:6],
        )
        return True

    # Trust semantic grounding when the answer is supported by retrieved docs.
    if semantically_grounded and (symbolic_support or coverage >= 0.25 or max_similarity >= 0.12):
        return False

    if family in {"list_entity", "list_structure"} or answer_type.startswith("list_"):
        if not (symbolic_support or semantically_grounded or coverage >= 0.35 or focus_ratio > 0.0):
            S.logger.info(
                "[LOW CONFIDENCE GROUNDING] blocked reason=weak_list_grounding coverage=%.3f focus=%.3f top=%.3f",
                coverage,
                focus_ratio,
                max_similarity,
            )
            return True
        return False

    if len(query_tokens) >= 2 and coverage < 0.50 and focus_ratio <= 0.0 and not semantically_grounded and not symbolic_support:
        S.logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=multi_token_weak_grounding coverage=%.3f focus=%.3f top=%.3f",
            coverage,
            focus_ratio,
            max_similarity,
        )
        return True

    if len(query_tokens) >= 2 and coverage < 0.12 and focus_ratio <= 0.0 and not semantically_grounded and not symbolic_support:
        S.logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=keyword_only_partial_match coverage=%.3f focus=%.3f top=%.3f",
            coverage,
            focus_ratio,
            max_similarity,
        )
        return True

    if not semantically_grounded and coverage < 0.35 and focus_ratio <= 0.0 and not symbolic_support:
        S.logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=ungrounded_weak_evidence coverage=%.3f focus=%.3f top=%.3f",
            coverage,
            focus_ratio,
            max_similarity,
        )
        return True

    if max_similarity < 0.12 and coverage < 0.50 and not semantically_grounded:
        S.logger.info(
            "[LOW CONFIDENCE GROUNDING] blocked reason=weak_semantic_score coverage=%.3f focus=%.3f top=%.3f",
            coverage,
            focus_ratio,
            max_similarity,
        )
        return True

    return False

def _normalize_query_for_router(query: str) -> str:
    q = str(query or "").strip().lower()
    # Double-submit / missing space often glues "do" + "tell" (e.g. "dotell").
    q = re.sub(r"(?i)dotell", "do tell", q)
    q = re.sub(r"(?i)\bdo\s*tell\b", "do tell", q)
    q = re.sub(r"[\u064B-\u065F\u0670\u0640]", "", q)
    q = re.sub(r"[إأآٱ]", "ا", q)
    q = re.sub(r"ى", "ي", q)
    q = re.sub(r"ؤ", "و", q)
    q = re.sub(r"ئ", "ي", q)
    q = re.sub(r"ة", "ه", q)
    q = re.sub(r"[^0-9a-z\u0600-\u06FF]+", " ", q)
    q = re.sub(r"\s+", " ", q).strip()
    # Normalize repeated-letter greeting variants (hii, heyy, helloo, thankss, okk).
    if q and " " not in q and q.isalpha() and len(q) <= 14:
        if re.fullmatch(r"h+i+", q):
            q = "hi"
        elif re.fullmatch(r"he+y+", q):
            q = "hey"
        elif re.fullmatch(r"hello+", q):
            q = "hello"
        elif re.fullmatch(r"thank+s+", q):
            q = "thanks"
        elif re.fullmatch(r"ok+k*", q) or re.fullmatch(r"okay+", q):
            q = "ok"
        elif re.fullmatch(r"yo+", q):
            q = "yo"
    for phrase in ("tell me what you can do", "what can you do"):
        if phrase in q and q.count(phrase) >= 2:
            return phrase
    return q

def _route_response_language(query: str, language: str | None = None) -> str:
    explicit = str(language or "").strip().lower()
    if explicit in {"en", "ar"}:
        return explicit
    return "ar" if _detect_language(str(query or "")) == "ar" else "en"

_SMALLTALK_RESPONSES = {
    "en": {
        "thanks": "You're very welcome! Is there anything else I can help you with today?",
        "greeting": "Hello! Thank you for contacting support. How can I help you today?",
        "wellbeing": "I'm doing well, thank you for asking. How can I help you with your support question today?",
        "ack": "Of course. What would you like help with?",
    },
    "ar": {
        "thanks": "العفو! هل هناك أي شيء آخر يمكنني مساعدتك به اليوم؟",
        "greeting": "أهلاً! شكراً لتواصلك مع الدعم. كيف يمكنني مساعدتك اليوم؟",
        "wellbeing": "أنا بخير، شكراً لسؤالك. كيف يمكنني مساعدتك في سؤال الدعم اليوم؟",
        "ack": "بالتأكيد. بماذا تود المساعدة؟",
    },
}

def _classify_smalltalk_intent(text: str) -> str:
    q = _normalize_query_for_router(text)
    if not q:
        return "unknown"
    lang = _route_response_language(text)
    if lang == "ar":
        if re.fullmatch(r"(?:شكرا|شكرن|تسلم|تسلمي|متشكر|متشكره)(?:\s+(?:جدا|اوي|ليك|لك))?", q):
            return "thanks"
        if re.fullmatch(r"(?:ازيك|ازايك|كيف حالك|عامل ايه|عامله ايه|اخبارك ايه|كيفك)", q):
            return "wellbeing"
        if re.fullmatch(r"(?:تمام|ماشي|حاضر|اوكي|اوك|طيب)", q):
            return "ack"
        if re.fullmatch(r"(?:اهلا|اهلا وسهلا|مرحبا|السلام عليكم|صباح الخير|مساء الخير|هلا)", q):
            return "greeting"
        return "unknown"

    if re.fullmatch(
        r"(?:thanks|thank you|thx|thank u|ok thanks|okay thanks|ok thank you|okay thank you|"
        r"thanks a lot|thank you very much|much appreciated|appreciate it|thanks okay|thank you okay|"
        r"thank+s+|thank\s+you+)",
        q,
    ):
        return "thanks"
    if re.fullmatch(r"(?:(?:hi|hello|hey|h+i+|he+y+|hello+)\s+)?(?:how\s+(?:are\s+)?you(?:\s+doing)?|how\s+are\s+u|how\s+r\s+u|how\s+you\s+doing|how\s+are\s+things|how\s+(?:is|s)\s+it\s+going)(?:\s+today)?", q):
        return "wellbeing"
    if re.fullmatch(r"(?:ok|okay|alright|all right|got it|sure|fine|ok+k*|okay+)", q):
        return "ack"
    if re.fullmatch(r"(?:hi|hello|hey|h+i+|he+y+|hello+|good morning|good afternoon|good evening)(?:\s+there)?", q):
        return "greeting"
    if re.search(r"\b(?:thanks?|thank\s+you|thx|appreciate(?:\s+it)?|appreciated)\b", q):
        if len(q.split()) <= 5 and not _looks_like_document_question(text):
            return "thanks"
    return "unknown"

def _is_pure_smalltalk_query(query: str) -> bool:
    return _classify_smalltalk_intent(query) != "unknown"

_CONVERSATIONAL_INTENT_REDIRECTS: dict[str, dict[str, str]] = {
    "listening": {"en": CONVERSATIONAL_LISTENING_EN, "ar": CONVERSATIONAL_LISTENING_AR},
    "presence": {"en": CONVERSATIONAL_PRESENCE_EN, "ar": CONVERSATIONAL_PRESENCE_AR},
    "understanding": {"en": CONVERSATIONAL_UNDERSTANDING_EN, "ar": CONVERSATIONAL_UNDERSTANDING_AR},
    "online": {"en": CONVERSATIONAL_ONLINE_EN, "ar": CONVERSATIONAL_ONLINE_AR},
}

def _conversational_redirect(query: str, language: str | None = None) -> str:
    lang = _route_response_language(query, language)
    intent = _classify_conversational_ack_intent(query)
    if intent != "unknown":
        group = _CONVERSATIONAL_INTENT_REDIRECTS.get(intent) or {}
        text = group.get(lang)
        if text:
            return text
    return CONVERSATIONAL_REDIRECT_AR if lang == "ar" else CONVERSATIONAL_REDIRECT_EN

def _assistant_meta_direct_answer(query: str, language: str | None = None) -> str:
    lang = _route_response_language(query, language)
    intent = _classify_assistant_meta_intent(query)
    if intent == "document_only_behavior":
        return ASSISTANT_META_DOCUMENT_ONLY_AR if lang == "ar" else ASSISTANT_META_DOCUMENT_ONLY_EN
    if intent == "not_found_behavior":
        return ASSISTANT_META_NOT_FOUND_BEHAVIOR_AR if lang == "ar" else ASSISTANT_META_NOT_FOUND_BEHAVIOR_EN
    return ASSISTANT_META_RESPONSE_AR if lang == "ar" else ASSISTANT_META_RESPONSE_EN

def _classify_conversational_ack_intent(query: str) -> str:
    q = _normalize_query_for_router(query)
    if not q:
        return "unknown"
    if _detect_language(query) == "ar":
        if re.search(r"\bهل\s+(?:تسمع|تستمع)\s*(?:لي|ني)?\b", q):
            return "listening"
        if re.search(r"\bهل\s+(?:تستقبل|وصلت|وصلتك)\s+(?:لي|ني|رسالتي|رسائلي)\b", q):
            return "presence"
        if re.search(r"\bهل\s+انت\s+هنا\b", q):
            return "presence"
        if re.search(r"\bهل\s+(?:تفهم|فهمت)(?:ني)?\b", q):
            return "understanding"
        if re.search(r"\bهل\s+انت\s+(?:متصل|متاح|شغال|تعمل)\b", q):
            return "online"
        if re.search(r"\b(?:هل\s+)?(?:وصلك|وصلت)\s+(?:رسالتي|رسائلي)\b", q):
            return "presence"
        return "unknown"
    patterns: list[tuple[str, str]] = [
        ("listening", r"\bcan\s+you\s+(?:hear|listen(?:\s+to)?)\s+me\b"),
        ("listening", r"\b(?:do|can)\s+you\s+hear\s+me\b"),
        ("listening", r"\b(?:do|are)\s+you\s+(?:hear|listening)\s+me\b"),
        ("presence", r"\bare\s+you\s+there\b"),
        ("presence", r"\b(?:tell\s+me\s+)?are\s+you\s+(?:there|getting|receiving)\s+(?:my\s+)?(?:message|messages|text|input)\b"),
        ("presence", r"\b(?:did\s+you\s+get|are\s+you\s+getting)\s+(?:my\s+)?(?:message|messages)\b"),
        ("presence", r"\b(?:are\s+you\s+getting|did\s+you\s+get|you\s+getting)\s+me\b"),
        ("presence", r"\bare\s+you\s+receiving\s+me\b"),
        ("understanding", r"\bdo\s+you\s+understand\s+me\b"),
        ("understanding", r"\b(?:do\s+you\s+get|you\s+get)\s+me\b"),
        ("online", r"\bare\s+you\s+(?:online|available|working|awake)\b"),
        ("presence", r"\bhello\s*\?\s*$"),
    ]
    for intent, pattern in patterns:
        if re.search(pattern, q):
            return intent
    return "unknown"

def _is_conversational_ack_query(query: str) -> bool:
    return _classify_conversational_ack_intent(query) != "unknown"

def _is_assistant_behavior_complaint_query(query: str) -> bool:
    """Meta questions about document-only / not-found behavior (not document content)."""
    return _classify_assistant_meta_intent(query) in {
        "document_only_behavior",
        "not_found_behavior",
    }

def _is_rag_no_match_sentinel(value: str) -> bool:
    """True when *value* is the internal strict not-found sentinel."""
    s = re.sub(r"\s+", " ", str(value or "").strip().lower()).rstrip(".")
    target = RAG_NO_MATCH_RESPONSE.lower().strip().rstrip(".")
    return s == target

def _looks_like_rag_no_match_stream(value: str) -> bool:
    """True when streamed text matches or is building toward the not-found sentinel."""
    s = re.sub(r"\s+", " ", str(value or "").strip().lower()).rstrip(".")
    if not s:
        return False
    target = RAG_NO_MATCH_RESPONSE.lower().strip().rstrip(".")
    if s == target:
        return True
    if target.startswith(s):
        return True
    if s.startswith("not found in the document"):
        return True
    return False

def _effective_user_query(user_query: str | None = None) -> str:
    q = str(user_query or "").strip()
    if q:
        return q
    try:
        return str(_current_user_query.get() or "").strip()
    except Exception:
        return ""

def _route_lang_for_user_visible(language: str | None, *, arabic_mode: bool, query: str) -> str:
    route_lang = str(language or "").strip().lower()
    if arabic_mode or route_lang.startswith("ar"):
        return "ar"
    if query:
        return _route_response_language(query, language)
    return route_lang or "en"

def _ensure_user_visible_support_answer(
    answer: str,
    *,
    user_query: str | None = None,
    language: str | None = None,
    arabic_mode: bool = False,
    retrieved_docs: list[dict] | None = None,
) -> str:
    """Map internal sentinel answers to warm customer-support copy (never leak sentinel)."""
    query = _effective_user_query(user_query)
    route_lang = _route_lang_for_user_visible(language, arabic_mode=arabic_mode, query=query)
    response_text = str(answer or "")
    if query:
        response_text = _finalize_user_visible_answer(query, response_text, route_lang, retrieved_docs)
    if _is_rag_no_match_sentinel(response_text) or not str(response_text or "").strip():
        response_text = _customer_service_no_match_response(query, route_lang)
    return response_text

def _finalize_user_visible_answer(
    query: str,
    answer: str,
    language: str | None = None,
    retrieved_docs: list[dict] | None = None,
) -> str:
    raw = str(answer or "").strip()
    if raw.lower() == RAG_NO_MATCH_RESPONSE.lower() and _classify_query_family_v2(query) == "document_summary" and retrieved_docs:
        summary_fallback = _build_document_summary_fallback_answer(query, retrieved_docs or [])
        if summary_fallback:
            return summary_fallback
    if S._is_kb_unanswerable_detail_query(query):
        return _customer_service_no_match_response(query, language)
    if raw.lower() != RAG_NO_MATCH_RESPONSE.lower():
        return answer
    if _is_assistant_behavior_complaint_query(query):
        return _assistant_meta_direct_answer(query, language)
    if _is_conversational_ack_query(query) or _is_unsupported_unclear_query(query):
        return _conversational_redirect(query, language)
    if _is_pure_smalltalk_query(query):
        return _smalltalk_response(query)
    if retrieved_docs:
        rescued = _rescue_support_procedural_from_docs(query, retrieved_docs)
        if rescued:
            return rescued
    return _customer_service_no_match_response(query, language)

def _apply_customer_support_tone(
    query: str,
    answer: str,
    language: str | None = None,
    retrieved_docs: list[dict] | None = None,
) -> str:
    """Wrap a model/document answer in a friendly customer-support voice.

    - The strict ``RAG_NO_MATCH_RESPONSE`` sentinel is never surfaced to the
      customer; it is mapped to the human "not found" fallback (which may be
      rescued from docs / routed to a conversational reply).
    - Bullet / numbered list answers get a short, professional lead-in so the
      reply reads like a support agent rather than a raw dump.
    """
    raw = str(answer or "").strip()
    if not raw:
        return raw

    if raw.lower() == RAG_NO_MATCH_RESPONSE.lower():
        return _finalize_user_visible_answer(query, RAG_NO_MATCH_RESPONSE, language, retrieved_docs)

    raw = _decontaminate_faq_answer(query, raw)

    lines = [ln for ln in raw.splitlines() if ln.strip()]
    is_list = len(lines) >= 2 and all(
        re.match(r"^\s*(?:[-*\u2022]|\d+[.)])\s+", ln) for ln in lines
    )
    if is_list:
        lang = _route_response_language(query, language)
        intro = (
            "إليك الخطوات من مواد المساعدة لدينا:"
            if lang == "ar"
            else "Here are the steps from our help materials:"
        )
        return f"{intro}\n{raw}"

    return raw

def _classify_assistant_meta_intent(query: str) -> str:
    q = _normalize_query_for_router(query)
    if not q:
        return "unknown"

    if _detect_language(query) == "ar":
        if re.search(r"\b(?:قدراتك|امكانياتك|امكاناتك|مهاراتك)\b", q):
            return "capabilities"
        if re.search(r"\b(?:انا\s+)?(?:بتكلم|اتكلم)\s+عنك\b", q):
            return "about_assistant"
        if re.search(r"\bاقصد\s+(?:امكانياتك|امكاناتك|قدراتك|انت|حضرتك)\b", q):
            return "clarified_capabilities"
        if re.search(r"\b(?:ماذا|ما)\s+(?:يمكنك|تقدر|تستطيع)\s+(?:ان\s+)?(?:تفعل|تعمل)\b", q):
            return "capabilities"
        if re.search(r"\b(?:بتعرف|تعرف|تقدر)\s+(?:تعمل|تفعل)\s+(?:ايه|ماذا)\b", q):
            return "capabilities"
        if re.search(r"\b(?:تقدر|ممكن|يمكنك|هل\s+يمكنك)\s+تساعد(?:ني)?\s+(?:في|ب)\s+(?:ايه|ماذا)\b", q):
            return "help_scope"
        if re.search(r"\b(?:اقدر|ممكن)\s+اسالك\s+عن\s+(?:ايه|ماذا)\b", q):
            return "ask_scope"
        if re.search(r"\bما\s+هي\s+(?:قدراتك|امكانياتك|امكاناتك)\b", q):
            return "capabilities"
        return "unknown"

    if q == "help":
        return "help_command"
    patterns: list[tuple[str, str]] = [
        ("identity", r"\bwho\s+are\s+you\b"),
        ("how_it_works", r"\bhow\s+do\s+you\s+work\b"),
        ("ask_scope", r"\bwhat\s+can\s+i\s+ask\s+you\b"),
        ("capabilities", r"\bwhat\s+are\s+your\s+(?:abilities|capabilities)\b"),
        ("capabilities", r"\b(?:your|you(?:r)?)\s+(?:abilities|capabilities)\b"),
        ("about_assistant", r"\b(?:i\s+am|i\s*m|im|i)\s+(?:talking|asking)\s+about\s+you\b"),
        ("clarified_capabilities", r"\b(?:i\s+mean|i\s+meant|mean|meant|talking\s+about)\s+(?:your\s+)?(?:abilities|capabilities)\b"),
        ("help_scope", r"\b(?:what|which)\s+(?:can|could|do)\s+you\s+(?:do|help)(?:\s+(?:me|us))?(?:\s+with)?\b"),
        ("help_scope", r"\bhow\s+(?:can|could|do)\s+you\s+help(?:\s+(?:me|us))?\b"),
        ("help_scope", r"\bwhat\s+(?:you\s+can|can\s+you)\s+help\s+with\b"),
        ("capabilities", r"\btell\s+me\s+what\s+you\s+can\s+do\b"),
        ("capabilities", r"\bwhat\s+can\s+you\s+do\b"),
        ("capabilities", r"\b(?:tell\s+me\s+)?(?:if\s+you\s+)?can\s+(?:you\s+)?do\s+anything\b"),
        (
            "document_only_behavior",
            r"\bwhy\s+(?:are\s+you|do\s+you)\s+only\b.*\b(?:find|search|look|use)\b.*\b(?:document|documents)\b",
        ),
        (
            "document_only_behavior",
            r"\bwhy\s+(?:can(?:not|'t)|won(?:not|'t))\s+you\s+answer\s+(?:without|outside)\s+(?:the\s+)?(?:document|documents)\b",
        ),
        (
            "not_found_behavior",
            r"\bwhy\s+(?:do\s+you|are\s+you)\s+(?:keep\s+)?(?:saying|tell(?:ing)?)\s+(?:not\s+found|that\s+it\s+is\s+not\s+found)\b",
        ),
        (
            "not_found_behavior",
            r"\bwhy\s+(?:do\s+you|are\s+you)\s+only\s+(?:saying|give|return(?:ing)?)\s+not\s+found\b",
        ),
    ]
    for intent, pattern in patterns:
        if re.search(pattern, q):
            return intent
    return "unknown"

def _is_assistant_capability_or_meta_query(query: str) -> bool:
    return _classify_assistant_meta_intent(query) != "unknown"

def _is_unsupported_unclear_query(query: str) -> bool:
    q = _normalize_query_for_router(query)
    if not q:
        return True
    if re.fullmatch(r"(?:what|which)\s+(?:is|are)\s+(?:today|tonight|tomorrow|yesterday|now)", q):
        return True
    if re.fullmatch(r"(?:what|which)\s+(?:day|date|time)\s+(?:is|are)\s+(?:it|today|now)", q):
        return True
    if re.fullmatch(r"(?:what|which)\s+(?:is|are)\s+(?:the\s+)?(?:date|time)(?:\s+(?:today|now))?", q):
        return True
    if re.fullmatch(r"(?:bro\s+)?what", q):
        return True
    if re.search(r"\bwhat\s+are\s+you\s+saying\b", q):
        return True
    if re.fullmatch(r"(?:no\s+)+i\s+mean\s+(?:that|this)\s+thing", q):
        return True
    if re.fullmatch(r"(?:that|this)\s+thing", q):
        return True
    if re.fullmatch(r"random\s+nonsense", q):
        return True
    if re.fullmatch(r"(?:no\s*){2,}(?:i\s+mean\s*)?(?:that|this|it)?", q):
        return True
    return False

def _looks_like_document_question(query: str) -> bool:
    q = _normalize_query_for_router(query)
    if not q:
        return False
    if _detect_language(query) == "ar":
        return bool(
            re.search(r"\b(?:ما|ماذا|من|متي|اين|كيف|لماذا|هل)\b", q)
            or re.search(r"\b(?:اشرح|عرف|لخص|قارن|اذكر|عدد|استخرج)\b", q)
        )

    if re.search(r"\b(?:what|which|who|when|where|why|how)\b", q):
        return True
    if re.match(r"^\s*(?:define|explain|summari[sz]e|compare|list|name|give|mention|identify|describe|tell\s+me\s+about|understand|learn\s+about)\b", q):
        return True
    try:
        family_v2 = _classify_query_family_v2(query)
        if family_v2 in {"definition_entity", "definition_comparison", "list_entity", "fact_entity", "explanatory_compare", "sequence_lookup", "lesson_lookup", "toc_structure"}:
            return True
    except Exception:
        pass
    tokens = [t for t in re.findall(r"[a-z0-9]{3,}", q) if t not in {"please", "also", "just"}]
    return len(tokens) >= 2

def classify_query_route(query: str) -> str:
    if _is_conversational_ack_query(query):
        return "conversational_ack"
    if _is_assistant_capability_or_meta_query(query):
        return "assistant_meta"
    if _is_pure_smalltalk_query(query):
        return "smalltalk"
    if _is_unsupported_unclear_query(query):
        return "unsupported_unclear"
    if _looks_like_document_question(query):
        return "document_question"
    if _is_support_procedural_query(query):
        return "document_question"
    return "document_question"

def _direct_route_answer(query: str, route: str, language: str | None = None) -> str:
    lang = _route_response_language(query, language)
    if route == "assistant_meta":
        return _assistant_meta_direct_answer(query, lang)
    if route == "smalltalk":
        return _smalltalk_response(query)
    if route in {"conversational_ack", "unsupported_unclear"}:
        return _conversational_redirect(query, lang)
    return RAG_NO_MATCH_RESPONSE

def _log_direct_route_handled(route: str, query: str, language: str | None = None) -> None:
    lang = _route_response_language(query, language)
    if route == "conversational_ack":
        intent = _classify_conversational_ack_intent(query)
        S.logger.info("[ROUTER CONVERSATIONAL] handled=True language=%s intent=%s query=%s", lang, intent, str(query or "")[:240])
        S.logger.info("[CONVERSATION INTENT] intent=conversational:%s language=%s handled=True", intent, lang)
    elif route == "assistant_meta":
        intent = _classify_assistant_meta_intent(query)
        S.logger.info("[ROUTER META] handled=True language=%s intent=%s query=%s", lang, intent, str(query or "")[:240])
        S.logger.info("[CONVERSATION INTENT] intent=meta:%s language=%s handled=True", intent, lang)
    elif route == "smalltalk":
        intent = _classify_smalltalk_intent(query)
        S.logger.info("[ROUTER SMALLTALK] handled=True language=%s intent=%s query=%s", lang, intent, str(query or "")[:240])
        S.logger.info("[CONVERSATION INTENT] intent=smalltalk:%s language=%s handled=True", intent, lang)
    elif route == "unsupported_unclear":
        S.logger.info("[ROUTER PERMISSION] handled=True route=unsupported_unclear query=%s", str(query or "")[:240])
        S.logger.info("[CONVERSATION INTENT] intent=unsupported_unclear language=%s handled=True", lang)

def _should_allow_generic_answer(query: str, docs: list[dict], family_v2: str, answer_type: str) -> bool:
    generic_type = str(answer_type or "").lower()
    family = str(family_v2 or _classify_query_family_v2(query) or "")
    top_score_early = _max_doc_similarity(docs or [])
    if _is_support_procedural_query(query) and docs:
        # Support/scenario questions ("what happens if I report fraud?") are often
        # scored low by the cross-encoder even when the handling steps are present
        # in the retrieved chunks. Allow when either the rerank score clears the
        # floor OR the retrieved docs share meaningful topic tokens with the query
        # (so relevant-but-low-scored support evidence is not discarded).
        sp_metrics = _retrieval_evidence_metrics(query, docs or [])
        sp_focus = float(sp_metrics.get("focus_ratio", 0.0) or 0.0)
        sp_coverage = float(sp_metrics.get("coverage", 0.0) or 0.0)
        if top_score_early >= -2.0 or sp_focus > 0.0 or sp_coverage >= 0.34:
            S.logger.info(
                "[ANSWER PERMISSION] allowed=True reason=support_procedural_retrieval top_score=%.3f focus=%.3f coverage=%.3f",
                top_score_early,
                sp_focus,
                sp_coverage,
            )
            return True
    if _is_weak_generic_request(query):
        S.logger.info("[ANSWER PERMISSION] allowed=False reason=weak_generic_request")
        return False
    if not (generic_type.startswith("generic") or family in {"general", "out_of_scope_candidate"}):
        S.logger.info("[ANSWER PERMISSION] allowed=True reason=structured_route")
        return True

    top_score = _max_doc_similarity(docs or [])
    if top_score < -2.0:
        S.logger.info("[ANSWER PERMISSION] allowed=False reason=top_score_below_floor top_score=%.3f", top_score)
        return False

    metrics = _retrieval_evidence_metrics(query, docs or [])
    coverage = float(metrics.get("coverage", 0.0) or 0.0)
    focus_ratio = float(metrics.get("focus_ratio", 0.0) or 0.0)

    # Strong retrieval signal: allow answering even when token coverage is partial.
    if top_score >= 0.65 or focus_ratio > 0.0:
        S.logger.info(
            "[ANSWER PERMISSION] allowed=True reason=strong_retrieval_signal top_score=%.3f focus=%.3f coverage=%.3f",
            top_score,
            focus_ratio,
            coverage,
        )
        return True

    combined_doc_text = "\n".join(
        str((doc or {}).get("page_content") or (doc or {}).get("text") or "")
        for doc in (docs or [])[:4]
    ).lower()
    query_numeric = re.findall(r"\d+\.?\d*", str(query or ""))
    if query_numeric and any(num in combined_doc_text for num in query_numeric):
        S.logger.info("[ANSWER PERMISSION] allowed=True reason=numeric_token_in_docs")
        return True

    q_norm = _normalize_query_for_router(query)
    explanatory_markers = re.search(
        r"\b(?:explain|compare|difference|different|summari[sz]e|summary|overview|describe|tell\s+me\s+about|how|why)\b",
        q_norm,
    )
    if family == "explanatory_compare" and not explanatory_markers and not S._doc_router_implies_comparison(query):
        S.logger.info("[ANSWER PERMISSION] allowed=False reason=family_explanatory_without_explanatory_intent")
        return False

    meaningful_tokens = [
        t for t in _query_tokens_for_evidence(query)
        if t not in {"help", "ability", "abilities", "capability", "capabilities", "assist", "assistant"}
    ]

    heading_blob = " ".join(
        " ".join(str((dict((d or {}).get("metadata") or {})).get(k) or "") for k in ("heading", "section", "title", "chapter"))
        for d in (docs or [])[:4]
    ).lower()
    weak_only_tokens = bool(_query_tokens_for_evidence(query) and not meaningful_tokens)
    weak_token_heading_hit = bool(
        weak_only_tokens
        and any(re.search(rf"\b{re.escape(tok)}\b", heading_blob) for tok in _query_tokens_for_evidence(query))
    )
    if weak_only_tokens and not weak_token_heading_hit:
        S.logger.info("[ANSWER PERMISSION] allowed=False reason=no_meaningful_concept_tokens")
        return False

    if not meaningful_tokens and not weak_token_heading_hit:
        S.logger.info("[ANSWER PERMISSION] allowed=False reason=no_entity_or_concept_coverage")
        return False
    vague_generic_request = bool(re.match(r"^\s*(?:tell\s+me\s+about|explain|describe|overview\s+of|talk\s+about)\b", q_norm))
    if vague_generic_request and (coverage < 0.50 or focus_ratio <= 0.0):
        S.logger.info(
            "[ANSWER PERMISSION] allowed=False reason=vague_query_weak_retrieval coverage=%.3f focus=%.3f top_score=%.3f",
            coverage,
            focus_ratio,
            top_score,
        )
        return False
    if len(set(meaningful_tokens)) <= 1 and coverage < 1.0 and focus_ratio <= 0.0:
        S.logger.info(
            "[ANSWER PERMISSION] allowed=False reason=incidental_single_token_match coverage=%.3f focus=%.3f top_score=%.3f",
            coverage,
            focus_ratio,
            top_score,
        )
        return False
    if coverage < 0.25 and focus_ratio <= 0.0 and top_score < 0.55:
        S.logger.info(
            "[ANSWER PERMISSION] allowed=False reason=weak_query_coverage coverage=%.3f focus=%.3f top_score=%.3f",
            coverage,
            focus_ratio,
            top_score,
        )
        return False
    if _is_weak_retrieval_evidence(query, "out_of_scope_candidate", docs or []):
        S.logger.info(
            "[ANSWER PERMISSION] allowed=False reason=weak_concept_coverage coverage=%.3f focus=%.3f top_score=%.3f",
            coverage,
            focus_ratio,
            top_score,
        )
        return False

    S.logger.info(
        "[ANSWER PERMISSION] allowed=True reason=generic_context_supported coverage=%.3f focus=%.3f top_score=%.3f",
        coverage,
        focus_ratio,
        top_score,
    )
    return True

def _is_smalltalk(text: str) -> bool:
    return _is_pure_smalltalk_query(text)

def _smalltalk_response(text: str) -> str:
    lang = _route_response_language(text)
    intent = _classify_smalltalk_intent(text)
    response_group = _SMALLTALK_RESPONSES.get(lang) or _SMALLTALK_RESPONSES["en"]
    return response_group.get(intent, response_group["greeting"])

def _not_found_response(query: str, confidence: str):
    return RAG_NO_MATCH_RESPONSE


def _is_not_found_like_answer(answer: str) -> bool:
    low = str(answer or "").strip().lower()
    if not low:
        return False
    return bool(
        low == RAG_NO_MATCH_RESPONSE.lower()
        or "not found in the document" in low
        or "couldn't find" in low
        or "could not find" in low
        or "not in the uploaded materials" in low
        or "not in the uploaded help materials" in low
        or bool(re.search(r"\bnot\b.{0,120}\b(?:uploaded|help)\s+materials\b", low))
        or "request timed out" in low
        or "timed out" in low
    )


def _clean_summary_fallback_sentence(sentence: str) -> str:
    s = re.sub(r"\s+", " ", str(sentence or "").strip())
    s = s.strip(" -?*\t")
    if not s:
        return ""
    if len(s) < 24 or len(s) > 260:
        return ""
    low = s.lower()
    if re.search(r"\b(?:copyright|all rights reserved|virtual university of pakistan)\b", low):
        return ""
    if re.search(r"^\s*(?:chapter|unit|section|contents?|table of contents|references?)\b", low):
        return ""
    if not re.search(r"[A-Za-z]", s):
        return ""
    if not re.search(r"[.!?]$", s):
        s += "."
    return s



def _extract_document_anchored_entity_terms(query: str) -> List[str]:
    q = re.sub(r"\s+", " ", str(query or "").strip())
    if not q:
        return []
    docref = r"(?:the\s+)?(?:documents?|docs?|pdfs?|files?|books?|texts?|sources?|passages?|chapters?|sections?|materials?)"
    patterns = [
        rf"\bwhat\s+does\s+{docref}\s+(?:say|state|mention|discuss|explain|describe)\s+(?:about|regarding|concerning)\s+(.+?)\s*[?.!]*$",
        rf"\b(?:according\s+to|in|from|within)\s+{docref}\s*,?\s*(?:what\s+does\s+it\s+say\s+about\s+)?(.+?)\s*[?.!]*$",
        rf"\b(?:explain|describe|clarify)\s+(.+?)\s+(?:according\s+to|in|from|within)\s+{docref}\s*[?.!]*$",
    ]
    raw = ""
    for pattern in patterns:
        m = re.search(pattern, q, flags=re.IGNORECASE)
        if m:
            raw = m.group(1)
            break
    if not raw:
        return []
    raw = re.sub(r"\b(?:please|briefly|in\s+detail|according\s+to\s+the\s+document)\b", " ", raw, flags=re.IGNORECASE)
    stop = {
        "the", "a", "an", "and", "or", "of", "to", "for", "in", "on", "about",
        "document", "documents", "doc", "docs", "file", "files", "source", "sources",
        "say", "says", "state", "states", "mention", "mentions", "discuss", "discusses",
    }
    terms = [t.lower() for t in re.findall(r"[A-Za-z][A-Za-z0-9'\-]{2,}", raw) if t.lower() not in stop]
    seen: Set[str] = set()
    ordered: List[str] = []
    for term in terms:
        norm = term.strip("'-")
        if norm and norm not in seen:
            seen.add(norm)
            ordered.append(norm)
    return ordered[:5]


def _build_document_anchored_entity_fallback_answer(query: str, doc_dicts: List[Dict[str, Any]]) -> str:
    terms = _extract_document_anchored_entity_terms(query)
    if not terms or not doc_dicts:
        return ""
    selected: List[str] = []
    seen_sentences: Set[str] = set()
    for doc in doc_dicts[:8]:
        text_value = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        for raw_sentence in _split_text_into_sentences(text_value)[:12]:
            sentence = _clean_summary_fallback_sentence(raw_sentence)
            if not sentence:
                continue
            low = sentence.lower()
            if not any(term in low for term in terms):
                continue
            key = re.sub(r"\s+", " ", low).strip()
            if key in seen_sentences:
                continue
            seen_sentences.add(key)
            selected.append(sentence)
            if len(selected) >= 4:
                break
        if len(selected) >= 4:
            break
    if not selected:
        return ""
    return "Based on the retrieved document evidence:\n" + "\n".join(f"- {s}" for s in selected[:4])

def _build_document_summary_fallback_answer(query: str, doc_dicts: List[Dict[str, Any]]) -> str:
    if _classify_query_family_v2(query) != "document_summary" or not doc_dicts:
        return ""
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    wants_chapter = bool(re.search(r"\b(?:chapter[- ]by[- ]chapter|chapter\s+overview|chapters?|sections?)\b", q))

    if wants_chapter:
        headings: List[str] = []
        seen_headings: Set[str] = set()
        for doc in doc_dicts[:10]:
            for heading in _heading_candidates_from_doc(doc):
                h = re.sub(r"\s+", " ", str(heading or "").strip(" -?*\t:"))
                if not h or len(h) < 4 or len(h) > 100:
                    continue
                low = h.lower()
                if re.search(r"\b(?:contents?|table of contents|index|references?|copyright)\b", low):
                    continue
                if low in seen_headings:
                    continue
                seen_headings.add(low)
                headings.append(h)
                if len(headings) >= 6:
                    break
            if len(headings) >= 6:
                break
        if headings:
            lines = ["Retrieved chapter/section evidence includes:"]
            lines.extend(f"- {h}" for h in headings[:6])
            return "\n".join(lines)

    sentences: List[str] = []
    seen_sentences: Set[str] = set()
    for doc in doc_dicts[:8]:
        text_value = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        for raw_sentence in _split_text_into_sentences(text_value)[:8]:
            sentence = _clean_summary_fallback_sentence(raw_sentence)
            if not sentence:
                continue
            key = sentence.lower()
            if key in seen_sentences:
                continue
            seen_sentences.add(key)
            sentences.append(sentence)
            break
        if len(sentences) >= 5:
            break
    if sentences:
        return "Based on the retrieved document evidence, the document covers:\n" + "\n".join(f"- {s}" for s in sentences[:5])
    return ""

def _customer_service_no_match_response(query: str, language: str | None = None) -> str:
    lang = _route_response_language(query, language)
    return CS_NO_MATCH_RESPONSE_AR if lang == "ar" else CS_NO_MATCH_RESPONSE_EN

def _apply_not_found_ux(
    query: str,
    answer: str,
    doc_dicts: List[Dict[str, Any]],
    language: str | None = None,
) -> str:
    ans = str(answer or "").strip()
    # #region agent log
    try:
        import traceback as _tb
        _al = ans.lower()
        _is_refusal = (
            _al == RAG_NO_MATCH_RESPONSE.lower()
            or "don't have that specific detail" in _al
            or "not found in the document" in _al
        )
        _stack = _tb.extract_stack(limit=6)[:-1]
        _callers = [f"{fr.name}:{fr.lineno}" for fr in _stack]
        S._dbg7d3bbb("assistify_rag_server.py:_apply_not_found_ux", "final answer outcome", {
            "is_refusal": _is_refusal,
            "doc_dicts_count": len(doc_dicts or []),
            "answer_preview": ans[:120],
            "query": str(query or "")[:120],
            "callers": _callers,
        }, "H-F")
    except Exception:
        pass
    # #endregion
    if not ans:
        return ans

    def _finalize(a: str) -> str:
        raw = str(a or "").strip()
        if _is_not_found_like_answer(raw) and doc_dicts:
            if _classify_query_family_v2(query) == "document_summary":
                fallback = _build_document_summary_fallback_answer(query, doc_dicts or [])
                if fallback:
                    return fallback
            entity_fallback = _build_document_anchored_entity_fallback_answer(query, doc_dicts or [])
            if entity_fallback:
                return entity_fallback
        if raw.lower() == RAG_NO_MATCH_RESPONSE.lower():
            return _finalize_user_visible_answer(
                query, RAG_NO_MATCH_RESPONSE, language, doc_dicts or None
            )
        if _is_arabic_text(raw):
            cleaned = _polish_final_response_text(query, raw)
        else:
            if _is_definition_comparison_query(query):
                cleaned = _cleanup_definition_comparison_answer_text(raw)
            else:
                cleaned = _cleanup_final_answer_text(raw)
            cleaned = _polish_final_response_text(query, cleaned)
        if cleaned != raw:
            S.logger.info("[OCR CLEANUP APPLIED] before=%s | after=%s", raw[:180], cleaned[:180])
        return _apply_customer_support_tone(query, cleaned, language, doc_dicts or None)

    ans = _finalize(ans)
    if _is_not_found_like_answer(ans) and doc_dicts:
        if _classify_query_family_v2(query) == "document_summary":
            fallback = _build_document_summary_fallback_answer(query, doc_dicts or [])
            if fallback:
                S.logger.info("[POSTPROCESS SUMMARY FALLBACK] %s", fallback[:280])
                return fallback
        entity_fallback = _build_document_anchored_entity_fallback_answer(query, doc_dicts or [])
        if entity_fallback:
            S.logger.info("[POSTPROCESS ENTITY FALLBACK] %s", entity_fallback[:280])
            return entity_fallback
    if ans.lower() != RAG_NO_MATCH_RESPONSE.lower():
        S.logger.info("[POSTPROCESS FINAL ANSWER] %s", ans[:280])
        return ans

    final = _finalize_user_visible_answer(query, RAG_NO_MATCH_RESPONSE, language, doc_dicts or None)
    S.logger.info("[POSTPROCESS FINAL ANSWER] %s", final[:280])
    return final

def _is_explicit_oos_query(query: str) -> bool:
    # [DOMAIN CLEANUP] removed=hardcoded domain term blocklist (machine
    # learning|AI|blockchain|bitcoin|ethereum|neural network|cyber
    # security|elon musk). replacement=retrieval-grounded out-of-scope
    # decision. Out-of-scope answers are now decided exclusively by
    # retrieval evidence / strict definition relevance guard / list
    # coherence guard, which return exactly RAG_NO_MATCH_RESPONSE when
    # the indexed documents do not support the query. No domain word
    # list is consulted here.
    _ = (query or "").strip().lower()
    return False

def _heading_candidates_from_doc(doc: Dict[str, Any]) -> List[str]:
    md = (doc or {}).get("metadata") or {}
    txt = str((doc or {}).get("page_content") or (doc or {}).get("text") or "")
    candidates: List[str] = []

    for key in ("chapter", "unit", "section", "title"):
        value = str(md.get(key) or "").strip()
        if value:
            candidates.append(value)

    for ln in txt.splitlines():
        line = re.sub(r"\s+", " ", ln).strip(" -•\t")
        if not line or len(line) < 3 or len(line) > 90:
            continue
        if re.search(r"[.!?]$", line):
            continue
        if re.search(r"\b(?:chapter|unit|section)\s+\d+\b", line, flags=re.IGNORECASE):
            candidates.append(line)
            continue
        if re.search(r"^\d+(?:\.\d+){1,3}\s+[A-Za-z]", line):
            candidates.append(line)
            continue
        words = line.split()
        title_like = sum(1 for w in words if re.match(r"^[A-Z][a-zA-Z\-]{2,}$", w))
        if len(words) <= 10 and title_like >= max(2, len(words) // 2):
            candidates.append(line)

    seen = set()
    ordered: List[str] = []
    for c in candidates:
        norm = re.sub(r"\s+", " ", c).strip().lower()
        if norm and norm not in seen:
            seen.add(norm)
            ordered.append(c)
    return ordered

def _extract_overview_chapter_compare_answer(query: str, doc_dicts: List[Dict[str, Any]], focused_context: str) -> Optional[str]:
    q = (query or "").strip().lower()
    if not q:
        return None

    if _is_force_overview_paragraph_query(query):
        top_docs = (doc_dicts or [])[:2]
        if not top_docs and focused_context:
            top_docs = [{"page_content": str(focused_context or "")[:1500], "metadata": {}}]

        query_tokens = [
            t for t in re.findall(r"[a-z0-9]{3,}", q)
            if t not in {"tell", "about", "explain", "overview", "what", "this", "that", "document", "the", "and", "for"}
        ]

        def _looks_explanatory(low: str) -> bool:
            return bool(re.search(r"\b(is|are|refers to|focuses on|emphasizes|concerned with|describes|involves|includes|deals with|helps)\b", low))

        def _is_noise_sentence(s: str) -> bool:
            low = s.lower()
            if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
                return True
            if not re.match(r"^[A-Z]", s):
                return True
            if re.match(r"^(?:of|and|or|but|with|for|to|in|on|by|from|as)\b", low):
                return True
            if re.search(r"^\s*(?:chapter\s+\d+|unit\s+\d+|contents?|table of contents|summary|introduction)\s*[:\-–—]?\s*$", s, flags=re.IGNORECASE):
                return True
            if re.search(r"\b(?:page\s*\d+|p\.\s*\d+|isbn|kdpublications|preface|unit\s*\d+)\b", low):
                return True
            if re.search(r"\b\d{1,4}\b", low):
                return True
            if re.search(r"\b(criticism|criticized|limitations?|drawbacks?)\b", low):
                return True
            if re.search(r"\b(?:[A-Z][a-z]+\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+)?)\b", s):
                return True
            return False

        candidates: List[Tuple[float, str]] = []
        for d in top_docs:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")[:900]
            if not txt:
                continue
            sents = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if s.strip()]
            for s in sents:
                low = s.lower()
                wc = len(re.findall(r"[a-z0-9]+", low))
                if wc < 10 or wc > 32:
                    continue
                if _is_noise_sentence(s):
                    continue
                if not re.search(r"[.!?]$", s):
                    continue
                if s.count(',') > 2:
                    continue
                if query_tokens:
                    hits = sum(1 for t in query_tokens if re.search(rf"\b{re.escape(t)}\b", low))
                    if hits == 0 and not _looks_explanatory(low):
                        continue
                elif not _looks_explanatory(low):
                    continue
                score = 0.0
                if _looks_explanatory(low):
                    score += 3.0
                score += 1.5 * sum(1 for t in query_tokens if re.search(rf"\b{re.escape(t)}\b", low))
                # DISABLED_CHEATING_LOGIC: Domain-specific score boosts for management/principles/process tokens.
                # score += 2.0 * sum(1 for t in ("management", "principles", "process") if re.search(rf"\b{re.escape(t)}\b", low))
                if re.search(r"\b(theory|theorist|coined|introduced|known as)\b", low):
                    score -= 3.5
                # DISABLED_CHEATING_LOGIC: Domain-specific process-verb score boost.
                # if re.search(r"\b(organization|administration|planning|controlling|coordinating)\b", low):
                #     score += 0.8
                candidates.append((score, s))

        if not candidates:
            return None

        candidates.sort(key=lambda x: x[0], reverse=True)
        selected: List[str] = []
        seen_norm: Set[str] = set()
        for _score, sent in candidates:
            norm = re.sub(r"\s+", " ", sent).strip().lower()
            if not norm or norm in seen_norm:
                continue
            seen_norm.add(norm)
            selected.append(sent)
            if len(selected) >= 2:
                break

        if not selected:
            return None

        paragraph = " ".join(selected[:2]).strip()
        paragraph = re.sub(r"\s+", " ", paragraph)
        if len(paragraph) > 520:
            paragraph = paragraph[:520].rstrip(" ,;:-") + "."
        paragraph = paragraph.replace("\n", " ")
        paragraph = re.sub(r"\s+", " ", paragraph).strip()
        if re.search(r"(?:^|\s)(?:[-•*]|\d+[.)])\s+", paragraph):
            paragraph = re.sub(r"(?:^|\s)(?:[-•*]|\d+[.)])\s+", " ", paragraph).strip()
        return paragraph

    diff_match = re.search(r"difference\s+between\s+(.+?)(?:\?|$)", q)
    cmp_match = re.search(r"compare\s+(.+?)(?:\?|$)", q)
    compare_match = diff_match or cmp_match
    if compare_match:
        compare_entities = _compare_entities_from_query(query)
        if len(compare_entities) < 2:
            return _apply_not_found_ux(query, RAG_NO_MATCH_RESPONSE, doc_dicts)
        left_raw = compare_entities[0]
        right_raw = compare_entities[1]

        top_docs = (doc_dicts or [])[:2]
        compare_context = "\n\n".join(
            str(d.get("page_content") or d.get("text") or "")
            for d in top_docs
        )
        if not compare_context.strip():
            compare_context = focused_context or ""

        left_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", left_raw) if t not in {"the", "and", "of"}]
        right_tokens = [t for t in re.findall(r"[a-z0-9]{3,}", right_raw) if t not in {"the", "and", "of"}]

        def _term_present(term_tokens: list[str], src: str) -> bool:
            if not term_tokens:
                return False
            low = (src or "").lower()
            hits = sum(1 for t in term_tokens if re.search(rf"\b{re.escape(t)}\b", low))
            return hits >= max(1, min(2, len(term_tokens)))

        if not (_term_present(left_tokens, compare_context) and _term_present(right_tokens, compare_context)):
            return _apply_not_found_ux(query, RAG_NO_MATCH_RESPONSE, doc_dicts)

        sentences = [
            s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", compare_context)
            if s and len(s.strip().split()) >= 6
        ]

        def _pick_summary(term_tokens: list[str]) -> Optional[str]:
            best = None
            best_score = -1.0
            for s in sentences:
                low = s.lower()
                token_hits = sum(1 for t in term_tokens if re.search(rf"\b{re.escape(t)}\b", low))
                if token_hits == 0:
                    continue
                score = float(token_hits)
                if any(k in low for k in ("is", "was", "refers to", "focuses on", "concerned with", "emphasizes")):
                    score += 1.5
                if any(k in low for k in ("whereas", "while", "but", "however", "on the other hand")):
                    score += 1.0
                if score > best_score:
                    best_score = score
                    best = s
            return best

        left_sent = _pick_summary(left_tokens)
        right_sent = _pick_summary(right_tokens)
        if not left_sent or not right_sent:
            return _apply_not_found_ux(query, RAG_NO_MATCH_RESPONSE, doc_dicts)

        diff_sent = None
        for s in sentences:
            low = s.lower()
            if any(k in low for k in ("whereas", "while", "however", "on the other hand", "differs", "difference")) and (
                _term_present(left_tokens, low) or _term_present(right_tokens, low)
            ):
                diff_sent = s
                break
        if not diff_sent:
            diff_sent = f"{left_raw.title()} and {right_raw.title()} differ in their main focus and approach."

        return (
            f"- {left_raw.title()} summary: {left_sent}\n"
            f"- {right_raw.title()} summary: {right_sent}\n"
            f"- Key difference: {diff_sent}"
        )

    doc_scores: List[Tuple[float, Dict[str, Any]]] = []
    for d in doc_dicts:
        md = d.get("metadata") or {}
        txt = str(d.get("page_content") or d.get("text") or "")
        hay = f"{md.get('chapter','')}\n{md.get('section','')}\n{md.get('title','')}\n{txt[:1200]}".lower()
        score = 0.0
        if any(k in hay for k in ("table of contents", "contents", "chapter", "unit", "introduction", "summary")):
            score += 3.0
        if re.search(r"\bchapter\s+\d+\b", hay):
            score += 2.5
        if re.search(r"\b\d+(?:\.\d+){1,3}\b", hay):
            score += 1.0
        if any(k in q for k in ("chapter", "topics", "main sections", "document talk", "discussed")):
            score += 1.0
        doc_scores.append((score, d))

    doc_scores.sort(key=lambda x: x[0], reverse=True)
    prioritized = [d for _, d in doc_scores[:3]]

    chapter_match = re.search(r"chapter\s+\d+", q)
    headings: List[str] = []
    for d in prioritized:
        heading_list = _heading_candidates_from_doc(d)
        if chapter_match:
            chap = chapter_match.group(0)
            chapter_specific = [h for h in heading_list if chap in h.lower() or re.search(r"^\d+(?:\.\d+)*\s+", h)]
            headings.extend(chapter_specific[:3])
        else:
            headings.extend(heading_list[:3])

    deduped: List[str] = []
    seen = set()
    for h in headings:
        norm = re.sub(r"\s+", " ", h).strip().lower()
        if norm and norm not in seen:
            seen.add(norm)
            deduped.append(h)
        if len(deduped) >= 3:
            break

    if deduped:
        if chapter_match:
            return f"{chapter_match.group(0).title()} discusses:\n" + "\n".join(f"- {h}" for h in deduped[:3])
        if any(k in q for k in ("main sections", "document talk", "topics", "discussed", "overview", "what does this document talk about")):
            top3 = deduped[:3]
            if len(top3) >= 3:
                return f"This document mainly covers {top3[0]}, {top3[1]}, and {top3[2]}."
            return "Main topics/sections:\n" + "\n".join(f"- {h}" for h in deduped[:3])

    if any(k in q for k in ("main sections", "document talk", "topics", "discussed", "overview", "document")):
        all_headings = _extract_document_headings(doc_dicts)
        topic_candidates: List[str] = []

        for h in all_headings:
            line = re.sub(r"\s+", " ", str(h.get("heading") or "")).strip()
            if not line:
                continue
            low = line.lower()
            if re.search(r"\b(table of contents|contents|index)\b", low):
                continue
            if len(line) < 4 or len(line) > 110:
                continue
            topic_candidates.append(line)

        if len(topic_candidates) < 3:
            for raw in str(focused_context or "").splitlines():
                ln = re.sub(r"\s+", " ", raw).strip(" \t-•*:")
                if not ln:
                    continue
                if len(ln) < 4 or len(ln) > 110:
                    continue
                if re.search(r"[.!?]$", ln):
                    continue
                if re.search(r"\b(table of contents|contents|chapter|unit|section)\b", ln, flags=re.IGNORECASE) or re.search(r"^\d+(?:\.\d+){1,4}\s+[A-Za-z]", ln):
                    topic_candidates.append(ln)

        seen_topics: Set[str] = set()
        ordered_topics: List[str] = []
        for item in topic_candidates:
            norm = re.sub(r"\s+", " ", item).strip().lower()
            if not norm or norm in seen_topics:
                continue
            seen_topics.add(norm)
            ordered_topics.append(item)
            if len(ordered_topics) >= 6:
                break

        if len(ordered_topics) >= 3:
            top3 = ordered_topics[:3]
            return f"This document mainly covers {top3[0]}, {top3[1]}, and {top3[2]}."

        # Safe generic fallback: synthesize only from heading-like metadata, never raw chunks.
        heading_pool = _extract_document_headings(doc_dicts)
        heading_names: List[str] = []
        seen_headings: Set[str] = set()
        for h in heading_pool:
            name = re.sub(r"\s+", " ", str(h.get("heading") or "")).strip()
            if not name:
                continue
            low = name.lower()
            if re.search(r"\b(table of contents|contents|index|references?)\b", low):
                continue
            if len(name) < 4 or len(name) > 95:
                continue
            if low in seen_headings:
                continue
            seen_headings.add(low)
            heading_names.append(name)
            if len(heading_names) >= 5:
                break
        if len(heading_names) >= 3:
            top3 = heading_names[:3]
            return f"This document mainly covers {top3[0]}, {top3[1]}, and {top3[2]}."

    return None

def extract_list_items(text: str) -> List[str]:
    if not text:
        return []

    lines = [ln.strip() for ln in str(text).splitlines()]
    items: List[str] = []

    def _clean_item(raw: str) -> str:
        item = (raw or "").strip()
        item = re.sub(r"^\s*(?:[-•*]|\d+[.)])\s*", "", item)
        item = re.sub(r"\s+", " ", item).strip(" ,;:-")
        return item

    def _valid_item(candidate: str) -> bool:
        if not candidate:
            return False
        low = candidate.lower()
        if low.startswith(("figure", "fig.", "fig ", "table", "caption")):
            return False
        if len(candidate) < 2 or len(candidate) > 140:
            return False
        if re.search(r"[.!?]", candidate):
            return False
        wc = len(candidate.split())
        if wc == 0 or wc > 14:
            return False
        return True

    bullet_or_num = re.compile(r"^\s*(?:[-•*]|\d+[.)])\s+(.+)$")
    for ln in lines:
        m = bullet_or_num.match(ln)
        if not m:
            continue
        item = _clean_item(m.group(1))
        if _valid_item(item):
            items.append(item)

    for ln in lines:
        if ln.count(",") < 2:
            continue
        if len(ln) > 220:
            continue
        if re.search(r"[.!?]", ln):
            continue
        parts = [p.strip() for p in re.split(r",", ln) if p.strip()]
        short_parts = []
        for part in parts:
            part = _clean_item(part)
            if 1 <= len(part.split()) <= 8 and _valid_item(part):
                short_parts.append(part)
        if len(short_parts) >= 2:
            items.extend(short_parts)

    ordered: List[str] = []
    seen: Set[str] = set()
    for item in items:
        norm = re.sub(r"\s+", " ", item).strip().lower()
        if not norm or norm in seen:
            continue
        seen.add(norm)
        ordered.append(item)
    return ordered

def _definition_mode_from_query(query: str) -> str:
    q = (query or "").strip().lower()
    if q.startswith("who is") or q.startswith("who was") or q.startswith("who introduced"):
        return "person"
    if q.startswith("what is") or q.startswith("define"):
        return "concept"
    return "concept"

def _is_definition_sentence(s: str) -> bool:
    low = f" {(s or '').lower()} "
    return any(x in low for x in [" is ", " refers to ", " means ", " defined as "])

def _is_biography_sentence(s: str) -> bool:
    low = f" {(s or '').lower()} "
    return any(x in low for x in [" was ", " is ", " born ", " known as ", " considered ", " introduced "])

def _normalize_compare_entity_term(term: str) -> str:
    value = re.sub(r"\s+", " ", str(term or "").strip().lower())
    value = value.strip(" .?!,;:'\"")
    value = re.sub(r"^(?:the|a|an)\s+", "", value)
    value = re.sub(
        r"\s+(?:from|in|according\s+to|based\s+on)\s+(?:the\s+)?(?:document|book|text|context|source)\b.*$",
        "",
        value,
    )
    value = re.sub(
        r"\s+as\s+(?:described|mentioned|noted|stated)(?:\s+in\s+the\s+document)?\b.*$",
        "",
        value,
    )
    value = re.sub(r"\s+(?:please|kindly)\s*$", "", value)
    value = re.sub(r"\s+(?:vm\s+)?(?:families|family|plans|plan|options|tiers|types)\s*$", "", value)
    value = re.sub(r"\s+vm\s*$", "", value)
    value = re.sub(r"\s+", " ", value).strip(" .?!,;:'\"")
    if value in {"it", "this", "that", "these", "those", "they", "them"}:
        return ""
    return value

def _table_row_label_head_tokens(label: str) -> list[str]:
    """Leading label tokens before parenthetical series suffix, e.g. 'GPU (x-series)' -> ['gpu']."""
    head = re.sub(r"\s+", " ", str(label or "").strip())
    head = re.split(r"\s*\(", head, maxsplit=1)[0].strip().lower()
    return [tok for tok in re.findall(r"[a-z0-9]{2,}", head) if tok not in {"the", "and", "of"}]

def _strip_shared_entity_suffix(entities: list[str]) -> list[str]:
    """Strip a trailing noun shared by every entity (e.g. 'plans'), never append tails."""
    if len(entities) < 2:
        return entities
    token_lists = [
        [t for t in re.findall(r"[a-z0-9]{2,}", str(entity or "").lower()) if t not in {"the", "and", "of"}]
        for entity in entities
    ]
    if not all(token_lists):
        return entities
    min_len = min(len(tokens) for tokens in token_lists)
    shared_suffix: list[str] = []
    for idx in range(1, min_len + 1):
        tail = [tokens[-idx] for tokens in token_lists]
        if len(set(tail)) == 1:
            shared_suffix.insert(0, tail[0])
        else:
            break
    if not shared_suffix:
        return entities
    suffix_phrase = " ".join(shared_suffix)
    stripped: list[str] = []
    for entity in entities:
        value = re.sub(r"\s+", " ", str(entity or "").strip().lower())
        if value.endswith(suffix_phrase):
            value = value[: -len(suffix_phrase)].strip(" ,;:-")
        stripped.append(_normalize_compare_entity_term(value))
    return [entity for entity in stripped if entity]

def _split_compare_entity_segment(segment: str) -> list[str]:
    """Split comma-separated entity names within one compare segment."""
    parts: list[str] = []
    for piece in re.split(r"\s*,\s*", str(segment or "").strip()):
        normalized = _normalize_compare_entity_term(piece)
        if normalized:
            parts.append(normalized)
    return parts

def _compare_all_class_tokens(query: str) -> list[str]:
    q = re.sub(r"\s+", " ", str(query or "").strip().lower())
    match = re.search(r"\bcompare\s+all\s+(.+?)(?:[?.!]|$)", q)
    if not match:
        return []
    blob = match.group(1).strip(" ,;:")
    tokens = [tok for tok in re.findall(r"[a-z0-9]{2,}", blob) if tok not in {"the", "and", "or", "all"}]
    return tokens[:6]

def _discover_compare_entities_from_tables(docs: list[dict], class_tokens: list[str] | None = None) -> list[str]:
    entities: list[str] = []
    seen: set[str] = set()
    for table_text in _collect_pipe_table_texts(docs):
        rows = _parse_pipe_table_rows(table_text)
        if len(rows) < 2:
            continue
        header_l = " ".join(rows[0]).lower()
        if class_tokens:
            class_hit = any(
                tok in header_l
                or tok.rstrip("s") in header_l
                or f"{tok.rstrip('s')} " in header_l
                for tok in class_tokens
            )
            first_labels = " ".join(row[0].lower() for row in rows[1:3])
            if not class_hit and not any(tok.rstrip("s") in first_labels for tok in class_tokens):
                continue
        for row in rows[1:]:
            label = re.sub(r"\s+", " ", str(row[0] or "").strip())
            norm = _normalize_compare_entity_term(label)
            if not norm or norm in seen or _is_table_header_token(label):
                continue
            seen.add(norm)
            entities.append(norm)
    return entities[:6]

def _format_structured_table_comparison(docs: list[dict], entities: list[str]) -> str | None:
    if len(entities) < 2:
        return None
    best_table: list[list[str]] | None = None
    best_hits = 0
    for table_text in _collect_pipe_table_texts(docs):
        rows = _parse_pipe_table_rows(table_text)
        if len(rows) < 2:
            continue
        hits = 0
        labels = [re.sub(r"\s+", " ", row[0]).strip().lower() for row in rows[1:]]
        for entity in entities:
            entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
            if any(entity_l in label or label in entity_l for label in labels):
                hits += 1
        if hits > best_hits:
            best_hits = hits
            best_table = rows
    if not best_table or best_hits < 2:
        return None

    header = best_table[0]
    data_rows = best_table[1:]

    def _display_entity(entity: str) -> str:
        return " ".join(part.upper() if part.isupper() else part.capitalize() for part in str(entity or "").split())

    def _row_for_entity(entity: str) -> list[str] | None:
        entity_l = re.sub(r"\s+", " ", str(entity or "").strip().lower())
        entity_tokens = [tok for tok in re.findall(r"[a-z0-9]{2,}", entity_l) if tok not in {"the", "and", "of", "vm"}]
        for row in data_rows:
            label_l = re.sub(r"\s+", " ", row[0]).strip().lower()
            if entity_l in label_l or label_l in entity_l:
                return row
            head_tokens = _table_row_label_head_tokens(label_l)
            if head_tokens and all(re.search(rf"\b{re.escape(tok)}\b", entity_l) for tok in head_tokens):
                return row
            if entity_tokens and all(re.search(rf"\b{re.escape(tok)}\b", label_l) for tok in entity_tokens):
                return row
        return None

    blocks: list[str] = []
    for entity in entities:
        row = _row_for_entity(entity)
        if not row:
            continue
        lines = [_display_entity(entity)]
        for col_idx in range(1, min(len(header), len(row))):
            header_label = re.sub(r"\s+", " ", header[col_idx]).strip()
            cell_value = re.sub(r"\s+", " ", row[col_idx]).strip()
            if not header_label or not cell_value:
                continue
            if cell_value.lower() in {"no", "n/a", "na", "-", "—"}:
                continue
            lines.append(f"- {header_label}: {cell_value}")
        if len(lines) >= 2:
            blocks.append("\n".join(lines))
    if len(blocks) >= 2:
        return "\n\n".join(blocks).strip()
    return None

def _anchor_compare_docs_to_table_source(docs: list[dict]) -> list[dict]:
    docs = list(docs or [])
    table_docs = [
        d
        for d in docs
        if _is_comparison_table_evidence(
            str((d or {}).get("page_content") or (d or {}).get("text") or ""),
            dict((d or {}).get("metadata") or {}),
        )
    ]
    if not table_docs:
        return docs
    anchor_meta = dict((table_docs[0] or {}).get("metadata") or {})
    anchor_source = str(
        anchor_meta.get("source")
        or anchor_meta.get("filename")
        or anchor_meta.get("file_name")
        or anchor_meta.get("display_source")
        or ""
    ).strip().lower()
    if not anchor_source:
        return table_docs + [d for d in docs if d not in table_docs]
    filtered = [
        d
        for d in docs
        if str(
            dict((d or {}).get("metadata") or {}).get("source")
            or dict((d or {}).get("metadata") or {}).get("filename")
            or dict((d or {}).get("metadata") or {}).get("file_name")
            or ""
        ).strip().lower()
        == anchor_source
        or _is_comparison_table_evidence(
            str((d or {}).get("page_content") or (d or {}).get("text") or ""),
            dict((d or {}).get("metadata") or {}),
        )
    ]
    return filtered or docs

def _compare_entities_from_query(query: str) -> list[str]:
    q = re.sub(r"\s+", " ", (query or "").strip().lower())
    if not q:
        return []

    entity_blob = ""
    patterns = [
        r"\b(?:difference|differences|distinction)\s+between\s+(.+?)(?:[?.!]|$)",
        r"\b(?:compare|contrast|differentiate|distinguish)\s+(?:between\s+)?(.+?)(?:[?.!]|$)",
        r"\b(?:relationship|relation)\s+between\s+(.+?)(?:[?.!]|$)",
        r"\bhow\s+(?:does|do)\s+(.+?)\s+relat(?:e|es)?\s+(?:to|with)\s+(.+?)(?:[?.!]|$)",
        r"\bhow\s+(?:is|are)\s+(.+?)\s+related\s+(?:to|with)\s+(.+?)(?:[?.!]|$)",
        r"^\s*(?:what\s+is|define|explain)\s+(.+?)\s+(?:and|;)\s+(?:what\s+is|define|explain)\s+(.+?)(?:[?.!]|$)",
        r"\bbetween\s+(.+?)(?:[?.!]|$)",
        r"^(.+?)\s+(?:vs\.?|versus)\s+(.+?)(?:[?.!]|$)",
        r"\bhow\s+(?:is|are)\s+(.+?)\s+and\s+(.+?)\s+different\b(?:[?.!]|$)",
        r"\bwhat\s+(?:is|are)\s+the\s+differences?\s+between\s+(.+?)(?:[?.!]|$)",
    ]
    two_part_match = None
    for pattern in patterns[2:]:
        match = re.search(pattern, q)
        if match and match.lastindex and match.lastindex >= 2:
            two_part_match = match
            break
    if two_part_match:
        left = _normalize_compare_entity_term(two_part_match.group(1))
        right = _normalize_compare_entity_term(two_part_match.group(2))
        entities = [entity for entity in [left, right] if entity and left != right]
    else:
        for pattern in patterns[:2]:
            match = re.search(pattern, q)
            if match:
                entity_blob = match.group(1).strip()
                break
        if not entity_blob:
            return []
        split_match = re.search(
            r"^(.*)\s+(?:and|vs\.?|versus|with|to)\s+(.+)$",
            entity_blob,
            flags=re.IGNORECASE,
        )
        if split_match:
            left_blob = split_match.group(1).strip(" ,;:")
            right_blob = split_match.group(2).strip(" ,;:")
            entities = _split_compare_entity_segment(left_blob) + _split_compare_entity_segment(right_blob)
        else:
            entities = _split_compare_entity_segment(entity_blob)

    deduped: list[str] = []
    seen: set[str] = set()
    for entity in entities:
        norm = _normalize_compare_entity_term(entity)
        if not norm or norm in seen:
            continue
        seen.add(norm)
        deduped.append(norm)
    if len(deduped) >= 2:
        deduped = _strip_shared_entity_suffix(deduped)
        if entity_blob:
            deduped = _strip_list_trailing_modifier(entity_blob, deduped)
            if re.search(r"\bvm families\s*$", entity_blob, flags=re.IGNORECASE):
                vm_stripped: list[str] = []
                for entity in deduped:
                    value = re.sub(r"\s+vm\s*$", "", str(entity or ""), flags=re.IGNORECASE)
                    vm_stripped.append(_normalize_compare_entity_term(value) or entity)
                deduped = [entity for entity in vm_stripped if entity]
    if len(deduped) < 2:
        return []
    try:
        S.logger.info("[COMPARE ENTITIES] entities=%s source=query", deduped[:6])
    except Exception:
        pass
    return deduped[:6]

def _strip_list_trailing_modifier(entity_blob: str, entities: list[str]) -> list[str]:
    """When a trailing noun applies to the whole list (e.g. '... Enterprise plans')."""
    if len(entities) < 2:
        return entities
    blob_tokens = re.findall(r"[a-z0-9]{2,}", str(entity_blob or "").lower())
    if not blob_tokens:
        return entities
    trailing = blob_tokens[-1]
    if any(trailing in entity for entity in entities[:-1]):
        return entities
    if trailing not in entities[-1]:
        return entities
    stripped: list[str] = []
    for entity in entities:
        value = re.sub(rf"\s+{re.escape(trailing)}\s*$", "", str(entity or "").strip(), flags=re.IGNORECASE)
        stripped.append(_normalize_compare_entity_term(value) or entity)
    return [entity for entity in stripped if entity]

def _compare_terms_from_query(query: str) -> Tuple[str, str]:
    entities = _compare_entities_from_query(query)
    if len(entities) >= 2:
        return entities[0], entities[1]
    return "", ""

def _contains_compare_terms(text: str, term1: str, term2: str) -> bool:
    low = (text or "").lower()
    if not low or not term1 or not term2:
        return False

    def _term_ok(term: str) -> bool:
        toks = [t for t in re.findall(r"[a-z0-9]{2,}", term.lower()) if t not in {"the", "and", "of"}]
        if not toks:
            return False
        hits = sum(1 for t in toks if re.search(rf"\b{re.escape(t)}\b", low))
        return hits >= max(1, min(2, len(toks)))

    return _term_ok(term1) and _term_ok(term2)

def _is_valid_overview_answer(answer: str, query: str = "") -> bool:
    if not answer:
        return False
    a = (answer or "").strip()
    low = a.lower()

    if any(k in low for k in (" born ", " founder of ", " known as ", " biograph")):
        return False

    bullet_items = re.findall(r"(?:^|\n)\s*(?:[-•*]|\d+[.)])\s+(.+)", a)
    heading_lines = [
        ln.strip() for ln in a.splitlines()
        if ln.strip() and not re.search(r"[.!?]$", ln.strip()) and 3 <= len(ln.strip()) <= 90
    ]

    meaningful_items = 0
    for item in bullet_items:
        words = len(re.findall(r"[a-z0-9]+", item.lower()))
        if words >= 2:
            meaningful_items += 1

    if meaningful_items >= 2:
        return True

    if len(heading_lines) >= 2:
        return True

    sentence_count = len([s for s in re.split(r"(?<=[.!?])\s+", a) if s.strip()])
    if sentence_count <= 1:
        return False

    if any(k in (query or "").lower() for k in ("chapter", "topics", "main sections", "document", "discussed", "overview")):
        return False

    return True

def _extract_definition_sentence(text: str, query: str = "", mode: Optional[str] = None) -> Optional[str]:
    if not text:
        return None

    normalized = re.sub(r"\s+", " ", str(text)).strip()
    if not normalized:
        return None

    q_raw = (query or "").strip()
    q_low = q_raw.lower()

    _, extracted_entity = _extract_entity_from_definition_query(q_raw)
    entity_parts = [
        p for p in re.findall(r"[a-z0-9]{2,}", (extracted_entity or "").lower())
        if p not in {"the", "a", "an", "of", "and", "in", "to"}
    ]

    person_indicators = ["born", "known", "considered", "introduced"]
    biography_indicators = ["engineer", "manager", "theorist", "founder"]
    bad_markers = ["criticism", "example", "•", "items", "points"]
    is_person_q = _definition_mode_from_query(query) == "person"

    chunk_candidates = [c.strip() for c in re.split(r"\n\s*\n+", normalized) if c and c.strip()]
    if not chunk_candidates:
        chunk_candidates = [normalized]
    limited_chunks = chunk_candidates[:3]

    candidates: List[str] = []
    for chunk in limited_chunks:
        raw_sentences = re.split(r"(?<=[.!?])\s+|\n+", chunk)
        chunk_sents = [s.strip() for s in raw_sentences if (s or "").strip()]
        candidates.extend(chunk_sents[:5])
    if not candidates:
        return None

    # KEYWORD-ANCHOR: prioritize sentences that contain main entity/concept keywords.
    anchor_sentences = []
    if entity_parts:
        for s in candidates:
            low = s.lower()
            if any(part in low for part in entity_parts):
                anchor_sentences.append(s)

    pool = anchor_sentences if anchor_sentences else candidates

    is_specific_concept_query = (
        (mode or _definition_mode_from_query(query)) == "concept"
        and len(entity_parts) >= 2
        and bool(re.search(r"^(what\s+is|define)\b", q_low))
    )
    if is_specific_concept_query:
        exact_phrase = re.sub(r"\s+", " ", str(extracted_entity or "")).strip().lower()
        strict_pool = []
        for s in candidates:
            low = s.lower()
            phrase_hit = bool(exact_phrase and exact_phrase in low)
            token_hit = all(part in low for part in entity_parts)
            if phrase_hit or token_hit:
                strict_pool.append(s)
        if strict_pool:
            pool = strict_pool

    query_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", q_low)
        if t not in {"what", "who", "is", "was", "the", "a", "an", "of", "and", "in", "to", "define", "about"}
    ]
    weak_phrases = ("he thought", "it can be said", "in this way")
    continuation_starts = re.compile(r"^\s*(and|but|or|so|because|therefore|thus|also|then|while|whereas)\b", flags=re.IGNORECASE)
    weak_definition_starts = re.compile(r"^\s*(before|after|when|if|during|for\s+example|this\s+leads)\b", flags=re.IGNORECASE)
    procedural_sentence_re = re.compile(r"\b(?:first|second|third|step\s+\d+|should|must|need\s+to|you\s+can|to\s+do\s+this|follow\s+these|start\s+by)\b", flags=re.IGNORECASE)
    concept_person_attribution_re = re.compile(
        r"\b(?:introduced by|he\s+is\s+known\s+as|he\s+was\s+known\s+as|is\s+associated\s+with)\b",
        flags=re.IGNORECASE,
    )
    concept_person_row_re = re.compile(
        r"^\s*(?:\d+[.)]?\s+)?[A-Z][A-Za-z\-]+(?:\s+[A-Za-z][A-Za-z\-]+){0,5}\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,4}\s*$"
    )
    person_name_led_re = re.compile(r"^\s*[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3}\s+(?:is|was)\b")
    strict_definition_verb_re = re.compile(r"\b(?:is|refers\s+to|means|defined\s+as)\b", flags=re.IGNORECASE)
    concept_mode = ((mode or _definition_mode_from_query(query)) == "concept")

    def _passes_sentence_quality_gate(sentence: str) -> bool:
        s = (sentence or "").strip()
        if not s:
            return False
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
        if len(words) < 6:
            return False
        first_alpha = next((ch for ch in s if ch.isalpha()), "")
        if not first_alpha or first_alpha.islower():
            return False
        if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
            return False
        if "|" in s or "\t" in s:
            return False
        if ":" in s and ((not re.search(r"[.!?]$", s)) or (len(words) < 8)):
            return False
        if re.search(r"\b(table|figure|classification|contributors?|contents?)\b", s.lower()):
            return False
        return True

    scored: List[Tuple[float, int, str]] = []
    early_exit_threshold = 8.0
    for idx, sentence in enumerate(pool):
        s = sentence.strip()
        low = f" {s.lower()} "
        low_plain = s.lower()
        words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
        if not _passes_sentence_quality_gate(s):
            continue
        if len(words) < 6 or len(words) > 40:
            continue
        if re.match(r"^\s*(?:[-•*]|\d+[.)])\s+", s):
            continue
        if re.match(r"^\s*\d+\s*:\s*", s):
            continue
        if "|" in s or "\t" in s:
            continue
        if re.match(r"^[A-Z][A-Za-z0-9\s\-,:]{2,100}$", s) and not re.search(r"[.!?]$", s):
            continue
        if re.search(r"\b(chapter|table|figure|fig\.?|appendix|contents)\b", low_plain):
            continue
        if re.search(r"\bbefore\s+we\s+can\b", low_plain):
            continue
        if re.search(r"\bin the words of\b", low_plain):
            continue
        if any(p in low_plain for p in weak_phrases):
            continue
        if weak_definition_starts.match(s):
            continue
        # P2: soften procedural rejection — only drop when the sentence does
        # NOT also fully reference the queried entity. A procedural sentence
        # that explicitly defines our concept (e.g. "<X> is the process by
        # which one must follow these steps...") is a valid definition.
        if ((mode or _definition_mode_from_query(query)) == "concept") and procedural_sentence_re.search(low_plain):
            _entity_fully_present = bool(entity_parts) and all(part in low_plain for part in entity_parts)
            if not _entity_fully_present:
                continue
        if concept_mode and extracted_entity and defines_other_concept(low_plain, extracted_entity.lower()):
            continue
        if ((mode or _definition_mode_from_query(query)) == "concept"):
            if concept_person_attribution_re.search(s):
                continue
            if concept_person_row_re.match(s):
                continue
            starts_person_identity = bool(person_name_led_re.match(s))
            full_entity_tokens_hit = bool(entity_parts) and all(part in low_plain for part in entity_parts)
            if starts_person_identity and not full_entity_tokens_hit:
                continue
        allows_explanatory_continuation = bool(
            concept_mode
            and entity_parts
            and all(part in low_plain for part in entity_parts)
            and re.search(r"\b(refers\s+to|includes|involves|consists\s+of|characterized\s+by)\b", low_plain)
        )
        if continuation_starts.match(s) and (not allows_explanatory_continuation):
            continue
        if ((mode or _definition_mode_from_query(query)) == "concept") and re.match(r"^\s*(he|she|they|it)\b", low_plain):
            continue
        if re.search(r"\b[A-Z]\.$", s):
            continue
        if concept_mode and _looks_table_or_heading_like_chunk(s):
            continue
        # P2: soften strict-definition-verb rejection. Allow implicit
        # definitions (e.g. "<X> involves / consists of / focuses on / is
        # characterized by ...") to enter scoring when the sentence fully
        # mentions the queried entity. They are still penalized below versus
        # explicit "is/refers to/means/defined as" candidates.
        _has_strict_def_verb = bool(strict_definition_verb_re.search(low_plain))
        if concept_mode and not _has_strict_def_verb:
            _explanatory_verb = bool(re.search(
                r"\b(?:involves|consists\s+of|focuses\s+on|is\s+based\s+on|is\s+characterized\s+by|encompasses|comprises|describes|aims\s+to|deals\s+with|emphasizes|applies|uses)\b",
                low_plain,
            ))
            _entity_fully_present = bool(entity_parts) and all(part in low_plain for part in entity_parts)
            if not (_explanatory_verb and _entity_fully_present):
                continue
        if concept_mode and not re.search(r"[.!?]$", s):
            continue

        score = 0.0

        has_definition_verb = any(x in low for x in [" is ", " was ", " refers to ", " defined as ", " known as "])
        # PATCH 1: explanatory verb fallback (lower priority than definition verbs)
        has_explanatory_verb = bool(re.search(r"\b(involves|focuses on|is based on|aims to|uses|applies|emphasizes|deals with|concerned with)\b", low_plain))
        if has_definition_verb:
            score += 6.0

        full_concept_hit = False
        if entity_parts and all(part in low for part in entity_parts):
            full_concept_hit = True
            score += 6.0

        if query_tokens:
            q_hits = sum(1 for tok in query_tokens if re.search(rf"\b{re.escape(tok)}\b", low_plain))
            if q_hits >= 2:
                full_concept_hit = True
            if q_hits > 0:
                score += 3.0
        else:
            q_hits = 0

        # PATCH 1: add explanatory verb score AFTER full_concept_hit is computed
        if has_explanatory_verb and full_concept_hit and not has_definition_verb:
            score += 3.0

        if full_concept_hit:
            score += 6.0

        if q_hits >= 1:
            score += 1.5

        if any(word in low for word in biography_indicators):
            score += 3.0

        if any(ind in low for ind in person_indicators):
            score += 1.0

        if is_person_q:
            cap_tokens = re.findall(r"\b[A-Z][a-z]{2,}\b", s)
            if len(cap_tokens) >= 2:
                score += 2.0
            if len(cap_tokens) <= 1:
                score -= 2.0

        if " born " in low:
            score -= 3.0

        first_alpha = next((ch for ch in s if ch.isalpha()), "")
        if first_alpha and first_alpha.islower():
            score -= 5.0
        if continuation_starts.match(s):
            score -= 5.0
        if any(p in low_plain for p in weak_phrases):
            score -= 5.0
        if re.search(r"\b(this|these|such)\s+(approach|theory|concept|method)\b", low_plain):
            score -= 3.0

        if any(marker in low for marker in bad_markers):
            score -= 5.0

        # PATCH 4: heavily penalize table/classification text so clean prose always wins
        if re.search(r"\b(table|figure|classification|contributors?)\b", low_plain):
            score -= 5.0
        if re.match(r"^\s*\d+\.\s+[A-Z]", s) and len(words) <= 8:
            score -= 5.0

        if is_person_q:
            if not _is_biography_sentence(s):
                score -= 2.0
        else:
            if not _is_definition_sentence(s):
                score -= 2.0

        # MP-C2: generic structural definition-shape signals (no domain words).
        # Only apply when entity context is meaningful (concept queries).
        if not is_person_q:
            score += _definition_structural_signal_delta(s, str(extracted_entity or "").lower())

        if score >= early_exit_threshold:
            return s.strip()

        scored.append((score, idx, s))

    if not scored:
        return None

    scored.sort(key=lambda x: x[0], reverse=True)

    # P9: emit per-candidate definition-quality breakdown (top 3) so we can
    # see WHY the chosen sentence won versus close alternatives.
    try:
        for _rank, (_score, _idx, _sent) in enumerate(scored[:3], start=1):
            S.logger.info("[DEF QUALITY] candidate rank=%d score=%.2f sentence=%s",
                        _rank, float(_score), _preview_for_quality_log(_sent, 220))
    except Exception:
        pass

    if not is_person_q:
        strict_verbs_re = re.compile(r"\b(?:is|refers to|defined as|means|includes|involves|consists of|characterized by)\b", flags=re.IGNORECASE)
        strict_ranked: List[Tuple[float, int, str]] = []
        for score, idx, sent in scored:
            sent_low = sent.lower()
            phrase_or_entity_hit = (not entity_parts) or all(part in sent_low for part in entity_parts)
            if not phrase_or_entity_hit:
                continue
            if strict_verbs_re.search(sent_low):
                strict_ranked.append((score, idx, sent))
        if strict_ranked:
            scored = strict_ranked
        else:
            return None

    def _expand_to_sentence_boundary(source_text: str, snippet: str) -> tuple[str, Optional[int]]:
        src = str(source_text or "")
        sn = str(snippet or "").strip()
        if not src:
            return sn, None
        if not sn:
            return "", None

        src_low = src.lower()
        sn_low = sn.lower()
        pos = src_low.find(sn_low)
        if pos < 0:
            return sn, None

        start = pos
        end = pos + len(sn)

        prev_period = src.rfind(".", 0, start)
        if prev_period >= 0:
            scan = prev_period
            while scan >= 0:
                candidate_start = scan + 1
                while candidate_start < len(src) and src[candidate_start].isspace():
                    candidate_start += 1
                if candidate_start < start and candidate_start < len(src) and src[candidate_start].isupper():
                    start = candidate_start
                    break
                scan = src.rfind(".", 0, scan)

        next_period = src.find(".", end)
        if next_period >= 0:
            end = next_period + 1

        expanded = src[start:end].strip()
        return expanded, start

    def _is_valid_extracted_sentence(sentence: str, source_text: str, start_idx: Optional[int]) -> bool:
        s = str(sentence or "").strip()
        if not s:
            return False

        if start_idx is not None and start_idx > 0 and start_idx < len(source_text):
            prev_char = source_text[start_idx - 1]
            curr_char = source_text[start_idx]
            if prev_char.isalnum() and curr_char.isalnum():
                return False

        first_alpha = next((ch for ch in s if ch.isalpha()), "")
        if not first_alpha or first_alpha.islower():
            return False

        word_count = len(re.findall(r"[A-Za-z][A-Za-z\-']*", s))
        if word_count < 6 or word_count > 36:
            return False

        return True

    best_score, best_idx, best_sentence = scored[0]
    selected = None
    for score, idx, sent in scored:
        expanded_sentence, start_idx = _expand_to_sentence_boundary(normalized, sent)
        candidate_sentence = expanded_sentence or sent
        if _is_valid_extracted_sentence(candidate_sentence, normalized, start_idx):
            selected = (score, idx, candidate_sentence)
            break

    if selected is not None:
        best_score, best_idx, best_sentence = selected
    else:
        fallback_expanded, _ = _expand_to_sentence_boundary(normalized, best_sentence)
        if fallback_expanded:
            best_sentence = fallback_expanded

    def _shorten_definition_output(ans: str, max_sentences: int = 2) -> str:
        parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+", str(ans or "")) if p.strip()]
        if not parts:
            return ""
        compact = " ".join(parts[:max_sentences]).strip()
        compact = re.sub(r"^[A-Z][A-Za-z\s]{3,80}\s+\d+\s+(?=(?:It|This|He|She|They)\b)", "", compact).strip()
        words = compact.split()
        if len(words) > 40:
            compact = " ".join(words[:40]).rstrip(" ,;:-") + "."
        return compact

    def _extract_person_name(s: str) -> Optional[str]:
        if not s:
            return None

        capital_tokens = re.findall(r"\b[A-Z][a-z]{2,}\b", s)
        forbidden = {
            "Theory", "Model", "Principles", "Contributors", "Classification", "Approaches",
            "Method", "System", "Framework", "Chapter", "Section", "Table", "Figure",
        }

        best_name = ""
        best_score = float("-inf")
        n = len(capital_tokens)
        for size in (2, 3):
            if n < size:
                continue
            for i in range(0, n - size + 1):
                parts = capital_tokens[i:i + size]
                candidate = " ".join(parts).strip()
                non_forbidden = sum(1 for p in parts if p not in forbidden)
                forbidden_count = size - non_forbidden

                score = (2.0 * non_forbidden) - (1.5 * forbidden_count) + (0.1 * i)
                if entity_parts and (q_low.startswith("who is") or q_low.startswith("who was")):
                    ent_hits = sum(1 for ep in entity_parts if ep in candidate.lower())
                    score += 2.0 * ent_hits
                if len(set(parts)) < len(parts):
                    score -= 2.5

                if score > best_score:
                    best_score = score
                    best_name = candidate

        if best_name and best_score >= 1.5:
            return best_name

        m = re.search(r"\b([A-Z]\.\s*[A-Z][a-z]{2,})\b", s)
        if m:
            return m.group(1).strip()
        return None

    if is_person_q and not _is_biography_sentence(best_sentence):
        best_name = _extract_person_name(best_sentence)
        if q_low.startswith("who introduced") and best_name and extracted_entity:
            return f"{best_name} introduced {extracted_entity}."
        if best_name:
            topic_prefix = ""
            name_pos = best_sentence.lower().find(best_name.lower())
            if name_pos > 0:
                raw_prefix = best_sentence[:name_pos].strip(" :;,-.\t")
                raw_prefix = re.sub(r"\s+", " ", raw_prefix)
                raw_prefix = re.sub(r"\b\d+[.)]?\b", "", raw_prefix).strip()
                if raw_prefix and 2 <= len(raw_prefix.split()) <= 6:
                    topic_prefix = raw_prefix.lower()
            if topic_prefix:
                role = "scholar"
                return f"{best_name} is a {role} known for {topic_prefix}."
            return f"{best_name} was a scholar mentioned in the document."

    if (not is_person_q) and (not _is_definition_sentence(best_sentence)) and extracted_entity:
        best_name = _extract_person_name(best_sentence)
        coined_pat = rf"coined\s+the\s+term\s+['\"]?{re.escape((extracted_entity or '').lower())}['\"]?"
        if re.search(coined_pat, best_sentence.lower()):
            if best_name:
                return f"{extracted_entity.title()} is a term coined by {best_name}."
            return f"{extracted_entity.title()} is a term mentioned in the document."
        cleaned_best = re.sub(r"\s+", " ", best_sentence).strip(" :;,-")
        return f"{extracted_entity.title()} refers to {cleaned_best}."

    max_sents = 2 if is_person_q else 1
    return _shorten_definition_output(best_sentence, max_sentences=max_sents)

def _is_answer_grounded_in_docs(answer: str, retrieved_docs: list[dict], query_text: str = "") -> bool:
    if not answer:
        return False
    if not retrieved_docs:
        return False

    ctx = "\n".join(str((d or {}).get("page_content") or (d or {}).get("text") or "") for d in (retrieved_docs or []))
    if not ctx.strip():
        return False

    stop = {
        "the", "and", "for", "with", "that", "this", "from", "into", "about", "were", "have", "has",
        "what", "which", "who", "when", "where", "why", "how", "their", "there", "your", "than",
        "document", "according", "provided", "context", "based",
    }

    def _tokens(s: str) -> list[str]:
        return [t for t in re.findall(r"[a-z0-9]{3,}", (s or "").lower()) if t not in stop]

    ans_tokens = _tokens(answer)
    if len(ans_tokens) < 4:
        return True

    ctx_tokens = set(_tokens(ctx))
    ctx_low = ctx.lower()
    if not ctx_tokens:
        return False

    overlap = sum(1 for t in ans_tokens if t in ctx_tokens)
    overlap_ratio = overlap / max(1, len(ans_tokens))

    # Sentence-level support: each substantive answer sentence should be context-grounded.
    sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+", answer) if s.strip()]
    supported = 0
    substantive = 0
    for sent in sentences:
        sent_tokens = _tokens(sent)
        if len(sent_tokens) < 5:
            continue
        substantive += 1
        hits = sum(1 for t in sent_tokens if t in ctx_tokens)
        if (hits / max(1, len(sent_tokens))) >= 0.45:
            supported += 1

    q = (query_text or "").strip().lower()
    is_definition_query = bool(
        q.startswith("what is ")
        or q.startswith("define ")
        or re.search(r"\bmeaning\s+of\b", q)
        or _is_definition_comparison_query(q)
    )

    if substantive == 0:
        return overlap_ratio >= (0.40 if is_definition_query else 0.55)

    sentence_support_ratio = supported / max(1, substantive)

    # Query-term grounding: generic guard against unsupported world-knowledge answers.
    query_tokens = [
        t for t in re.findall(r"[a-z0-9]{3,}", (query_text or "").lower())
        if t not in stop and t not in {"explain", "define", "describe", "tell", "about"}
    ]
    if query_tokens:
        q_ctx_hits = sum(1 for t in query_tokens if t in ctx_tokens)
        q_ans_hits = sum(1 for t in query_tokens if t in set(ans_tokens))
        q_ctx_ratio = q_ctx_hits / max(1, len(query_tokens))
        q_ans_ratio = q_ans_hits / max(1, len(query_tokens))
    else:
        q_ctx_ratio = 1.0
        q_ans_ratio = 1.0

    # Phrase-level support: require some multi-token answer phrases to exist in context.
    phrase_hits = 0
    phrase_candidates = []
    ans_words = [w for w in re.findall(r"[a-z0-9]{3,}", answer.lower()) if w not in stop]
    for i in range(0, max(0, len(ans_words) - 1)):
        phrase = f"{ans_words[i]} {ans_words[i+1]}"
        if len(phrase) >= 8:
            phrase_candidates.append(phrase)
        if len(phrase_candidates) >= 20:
            break
    for ph in phrase_candidates:
        if ph in ctx_low:
            phrase_hits += 1

    # For broad/general queries, keep strong anti-hallucination checks,
    # but allow mild phrasing mismatch for definition queries.
    is_general_explain = q.startswith("explain ") or q.startswith("what is ")
    if is_definition_query:
        return (
            (overlap_ratio >= 0.35)
            and (sentence_support_ratio >= 0.40)
            and (q_ctx_ratio >= 0.35)
            and (q_ans_ratio >= 0.25)
            and (phrase_hits >= 1)
        )
    if is_general_explain:
        return (overlap_ratio >= 0.50) and (sentence_support_ratio >= 0.50) and (q_ctx_ratio >= 0.50) and (q_ans_ratio >= 0.40) and (phrase_hits >= 2)
    return (overlap_ratio >= 0.40) and (sentence_support_ratio >= 0.50) and (q_ctx_ratio >= 0.35) and (phrase_hits >= 1)

def _extract_strict_same_line_person_identity_from_retrieved_docs(query_text: str, retrieved_docs: list[dict]) -> str | None:
    q_low = (query_text or "").strip().lower()
    if not q_low.startswith("who is"):
        return None

    has_entity, entity = _extract_entity_from_definition_query(query_text)
    entity_l = (entity or "").strip().lower()
    if not has_entity or not entity_l:
        return None

    full_name_tokens = [t for t in re.findall(r"[a-z]{2,}", entity_l) if t]
    if len(full_name_tokens) < 2:
        return None

    if len(full_name_tokens) == 2:
        full_name_re = re.compile(
            r"\b" + re.escape(full_name_tokens[0]) + r"(?:\s+[a-z]{2,}){0,3}\s+" + re.escape(full_name_tokens[1]) + r"\b",
            flags=re.IGNORECASE,
        )
    else:
        mid = ""
        for tok in full_name_tokens[1:-1]:
            mid += r"(?:\s+[a-z]{2,}){0,2}\s+" + re.escape(tok)
        full_name_re = re.compile(
            r"\b" + re.escape(full_name_tokens[0]) + mid + r"(?:\s+[a-z]{2,}){0,3}\s+" + re.escape(full_name_tokens[-1]) + r"\b",
            flags=re.IGNORECASE,
        )

    row_patterns = [
        re.compile(r"^\s*\d+[.)]?\s+([A-Za-z][A-Za-z\- ]{2,100}?)\s+(?:[-–—:|])\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\s*$"),
        re.compile(r"^\s*([A-Za-z][A-Za-z\- ]{2,100}?)\s+(?:[-–—:|])\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,3})\s*$"),
        re.compile(r"(?:^|\s)(\d+)[.)]?\s+([A-Za-z][A-Za-z\- ]{2,80}?)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,2})(?=\s+\d+[.)]?\s+|$)"),
    ]

    def _to_title(s: str) -> str:
        return " ".join(w.capitalize() for w in re.findall(r"[A-Za-z0-9]+", s or ""))

    def _extract_concept_from_same_line(line_norm: str, person_text: str) -> str | None:
        if not line_norm or not person_text:
            return None
        line_clean = re.sub(r"^\s*\d+[.)]?\s*", "", line_norm).strip()
        p_low = person_text.lower().strip()
        m = re.search(re.escape(p_low), line_clean.lower())
        if not m:
            return None
        left = line_clean[:m.start()].strip(" -–—:|,;")
        if not left:
            return None
        left = re.sub(r"\s+", " ", left).strip()
        # Prefer a concise trailing concept phrase on the same line.
        tail_match = re.search(r"([A-Z][A-Za-z\-]+(?:\s+[A-Za-z][A-Za-z\-]+){0,4})$", left)
        if tail_match:
            concept = tail_match.group(1).strip()
            if 1 <= len(concept.split()) <= 5:
                return concept
        # Fallback: last up-to-4 words from left side.
        words = re.findall(r"[A-Za-z][A-Za-z\-]*", left)
        if 1 <= len(words) <= 12:
            concept = " ".join(words[-4:]).strip()
            if concept:
                return concept
        return None

    for doc in (retrieved_docs or [])[:8]:
        src = str((doc or {}).get("page_content") or (doc or {}).get("text") or (doc or {}).get("content") or "")
        if not src:
            continue
        for line in src.splitlines():
            line_norm = re.sub(r"\s+", " ", str(line or "")).strip()
            if not line_norm:
                continue
            if not full_name_re.search(line_norm.lower()):
                continue
            for pat in row_patterns:
                m = pat.search(line_norm)
                if not m:
                    continue
                if m.lastindex == 3:
                    concept_cell = (m.group(2) or "").strip()
                    person_cell = (m.group(3) or "").strip()
                else:
                    concept_cell = (m.group(1) or "").strip()
                    person_cell = (m.group(2) or "").strip()
                if not full_name_re.search(person_cell.lower()):
                    continue
                if len(concept_cell.split()) < 1:
                    continue
                concept_title = _to_title(concept_cell)
                role = "scholar"
                return f"{_to_title(person_cell)} is a {role} known for {concept_title}."

            # Same-line fallback: full name exists; extract concept from same line without row merging.
            person_match = re.search(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+){1,4}\b", line_norm)
            person_text = person_match.group(0).strip() if person_match else ""
            if person_text and full_name_re.search(person_text.lower()):
                concept_cell = _extract_concept_from_same_line(line_norm, person_text)
                if concept_cell:
                    concept_title = _to_title(concept_cell)
                    role = "scholar"
                    return f"{_to_title(person_text)} is a {role} known for {concept_title}."

    return None

def _is_bad_output_text(answer: str) -> bool:
    if not answer:
        return False
    cleaned = re.sub(r"\s+", " ", str(answer)).strip()
    if len(cleaned.split()) < 3:
        return True
    # Generic low-quality detector: highly repetitive output fragments.
    tokens = re.findall(r"[a-z0-9]+", cleaned.lower())
    if len(tokens) >= 8:
        uniq = len(set(tokens))
        if uniq / max(1, len(tokens)) < 0.35:
            return True
    return False

def _enforce_runtime_answer_acceptance(query: str, decision: Dict[str, Any], retrieved_docs: List[Dict[str, Any]]) -> Dict[str, Any]:
    dec = dict(decision or {})
    if S._skip_deterministic_rag_shortcuts(query):
        if dec.get("used_llm") or str(dec.get("answer") or "").strip():
            return dec
        dec["used_llm"] = True
        dec.setdefault("answer_type", "generation_llm_required")
        dec.setdefault("source_mode", "generation")
        return dec

    if dec.get("used_llm") and str(dec.get("answer_type") or "").endswith("_llm_required"):
        S.logger.info(
            "[FINAL DECISION DEBUG] answer_type=%s source_mode=%s used_llm=%s rejected=%s rejection_reason=%s",
            dec.get("answer_type"),
            dec.get("source_mode"),
            dec.get("used_llm"),
            False,
            "llm_required_passthrough",
        )
        return dec

    def _log_final_decision_debug(rejected: bool, rejection_reason: str = "") -> None:
        S.logger.info(
            "[FINAL DECISION DEBUG] answer_type=%s source_mode=%s used_llm=%s rejected=%s rejection_reason=%s",
            dec.get("answer_type"),
            dec.get("source_mode"),
            dec.get("used_llm"),
            rejected,
            rejection_reason,
        )

    ans = dec.get("answer")
    if ans is None:
        dec["answer"] = RAG_NO_MATCH_RESPONSE
        dec["used_llm"] = False
        dec["answer_type"] = "none_answer_rejected"
        dec["source_mode"] = "not_found_guard"
        _log_final_decision_debug(rejected=True, rejection_reason="none_answer_rejected")
        return dec

    answer = re.sub(r"[ \t]+", " ", str(ans or "")).strip()
    if not answer:
        dec["answer"] = RAG_NO_MATCH_RESPONSE
        dec["used_llm"] = False
        dec["answer_type"] = "empty_answer_rejected"
        dec["source_mode"] = "not_found_guard"
        _log_final_decision_debug(rejected=True, rejection_reason="empty_answer_rejected")
        return dec

    family = str(dec.get("query_family") or _classify_query_family_v2(query) or "")
    q_low = re.sub(r"\s+", " ", str(query or "")).strip().lower()
    is_list_mode = bool(
        family in {"list_entity", "list_structure"}
        or _is_targeted_list_question(q_low)
        or re.match(r"^\s*(?:what|which)\s+are\b", q_low)
    )
    is_definition_mode = bool(
        family in {"definition_entity", "definition_comparison"}
        or _is_definition_comparison_query(q_low)
        or q_low.startswith("what is")
        or q_low.startswith("define")
    )
    fact_type = _detect_fact_query_type(query)

    def _fragmentary_ocr(text: str) -> bool:
        reason = _ocr_filter_rejected_reason(text, query)
        if reason:
            _log_ocr_filter_rejection(text, reason)
            return True
        return False

    if answer == RAG_NO_MATCH_RESPONSE:
        dec["answer"] = RAG_NO_MATCH_RESPONSE
        _log_final_decision_debug(rejected=True, rejection_reason="not_found")
        return dec

    answer_type_for_permission = str(dec.get("answer_type") or "")
    source_mode_for_permission = str(dec.get("source_mode") or "")
    if (
        not dec.get("used_llm", False)
        and (
            answer_type_for_permission.startswith("generic")
            or source_mode_for_permission == "generic"
            or (family in {"general", "out_of_scope_candidate"} and not (is_list_mode or is_definition_mode or fact_type))
        )
        and not _should_allow_generic_answer(query, retrieved_docs or [], family, answer_type_for_permission)
    ):
        S.logger.info("[ANSWER BLOCKED] reason=low_confidence_generic")
        dec["answer"] = RAG_NO_MATCH_RESPONSE
        dec["used_llm"] = False
        dec["answer_type"] = "generic_low_confidence_blocked"
        dec["source_mode"] = "not_found_guard"
        _log_final_decision_debug(rejected=True, rejection_reason="low_confidence_generic")
        return dec

    if fact_type:
        S.logger.info("[FACT ANSWER GUARD] enabled=true fact_type=%s answer=%s", fact_type, answer[:220])
    elif (
        str(dec.get("answer_type") or "").startswith("attribute_")
        or str(dec.get("answer_type") or "") == "support_procedural_rescue"
        or family == "attribute_lookup"
        or (_is_support_procedural_query(query) and len(answer) >= 20)
    ):
        pass
    elif _fragmentary_ocr(answer):
        S.logger.info("[FINAL CANDIDATE REJECTED] reason=fragmentary_ocr answer=%s", answer[:220])
        dec["answer"] = RAG_NO_MATCH_RESPONSE
        dec["used_llm"] = False
        dec["answer_type"] = "fragmentary_ocr_rejected"
        dec["source_mode"] = "not_found_guard"
        _log_final_decision_debug(rejected=True, rejection_reason="fragmentary_ocr")
        return dec

    if is_list_mode:
        answer_type = str(dec.get("answer_type") or "")
        fast_deterministic_mode = bool((not dec.get("used_llm", False)) and answer_type in {"list_deterministic_context", "list_fast_simple", "list_extractor", "list_route_deterministic", "list_lexical_rescue"})
        list_support = dict(dec.get("_list_local_support") or {}) if isinstance(dec.get("_list_local_support"), dict) else {}
        if not list_support:
            list_support = _collect_local_window_support(retrieved_docs or [])
        grounding_docs = list(retrieved_docs or [])
        if answer_type == "list_lexical_rescue":
            rescue_window_text = str(list_support.get("single_local_window_text") or "")
            if rescue_window_text.strip():
                grounding_docs.insert(0, {"page_content": rescue_window_text, "text": rescue_window_text, "metadata": {"source": "lexical_rescue_window"}})
        list_ok, list_reason, shaped = _assess_list_coherence(query, _preclean_list_answer_for_assessment(answer), strict_fast=fast_deterministic_mode, local_support=list_support)
        S.logger.info("[LIST COHERENCE DEBUG] accepted=%s reason=%s", bool(list_ok), list_reason)
        if fast_deterministic_mode:
            S.logger.info("[FAST LIST GUARD] accepted=%s reason=%s", bool(list_ok), list_reason)
        if (not list_ok) or (not shaped):
            recovered_shaped: str | None = None
            if fast_deterministic_mode and str(list_reason or "") in {"min_quality_failed", "sanitize_failed", "locality_failed", "single_window_required"}:
                q_family_tmp = _classify_query_family_v2(query)
                q_ctx_tmp, q_focus_tmp = _split_query_context_focus_tokens(query, q_family_tmp)
                q_toks_tmp = [t for t in (q_focus_tmp + q_ctx_tmp) if len(str(t or "").strip()) >= 3]
                verb_re = re.compile(r"\b(?:is|are|was|were|be|been|being)\b", re.IGNORECASE)

                def _clean_inline_item(s: str) -> str:
                    out = re.sub(r"^[\W_]+|[\W_]+$", "", str(s or ""))
                    out = re.sub(r"\s+", " ", out).strip(" ,;:-")
                    return out

                def _valid_inline_item(s: str) -> bool:
                    item = _clean_inline_item(s)
                    if not item:
                        return False
                    if re.search(r"[.!?]", item):
                        return False
                    if len(item) > 40:
                        return False
                    if verb_re.search(item):
                        return False
                    words = re.findall(r"[A-Za-z][A-Za-z\-']*", item)
                    wc = len(words)
                    return bool(1 <= wc <= 3)

                best_items: List[str] = []
                for d in (retrieved_docs or [])[:4]:
                    src = str((d or {}).get("page_content") or (d or {}).get("text") or "")
                    if not src:
                        continue
                    segments = [s.strip() for s in re.split(r"[\n]+|(?<=[.!?])\s+", src) if s and s.strip()]
                    for seg in segments[:80]:
                        sseg = re.sub(r"\s+", " ", seg).strip()
                        if len(sseg) < 12 or len(sseg) > 240:
                            continue
                        seg_low = sseg.lower()
                        seg_focus_hit = bool(any(_token_match_light(seg_low, tok) for tok in q_toks_tmp))
                        parts: List[str] = []
                        if re.search(r"[,;•]", sseg):
                            parts.extend([_clean_inline_item(p) for p in re.split(r"[,;•]", sseg) if _clean_inline_item(p)])
                        if not parts and re.search(r"\s{2,}", sseg):
                            parts.extend([_clean_inline_item(p) for p in re.split(r"\s{2,}", sseg) if _clean_inline_item(p)])
                        if not parts:
                            words = re.findall(r"[A-Za-z][A-Za-z\-']*", sseg)
                            if len(words) >= 4:
                                cap_ratio = float(sum(1 for w in words if w[:1].isupper())) / float(max(1, len(words)))
                                if cap_ratio >= 0.60:
                                    parts.extend(words)

                        cand: List[str] = []
                        seen_cand: Set[str] = set()
                        for p in parts:
                            it = _clean_inline_item(p)
                            if not _valid_inline_item(it):
                                continue
                            norm = re.sub(r"[^a-z0-9]+", " ", it.lower()).strip()
                            if not norm or norm in seen_cand:
                                continue
                            seen_cand.add(norm)
                            cand.append(it)

                        if len(cand) >= 4:
                            focus_hits = sum(1 for it in cand if any(_token_match_light(it.lower(), tok) for tok in q_toks_tmp))
                            if (focus_hits >= 1 or seg_focus_hit) and len(cand) > len(best_items):
                                best_items = cand

                if len(best_items) >= 4:
                    recovered_shaped = "\n".join(f"- {it}" for it in best_items)

            if recovered_shaped:
                shaped = recovered_shaped
                list_ok = True
                S.logger.info("[LIST RECOVERED] mode=inline_concept_docs items=%d", len([ln for ln in shaped.splitlines() if ln.strip()]))
            else:
                S.logger.info("[LIST CANDIDATE REJECTED] reason=%s answer=%s", list_reason, answer[:220])
                dec["answer"] = RAG_NO_MATCH_RESPONSE
                dec["used_llm"] = False
                dec["answer_type"] = "list_incoherent_rejected"
                dec["source_mode"] = "not_found_guard"
                _log_final_decision_debug(rejected=True, rejection_reason=f"list_{list_reason}")
                return dec
        align = _list_query_alignment_metrics(query, shaped)
        mismatch_penalty = float(align.get("mismatch_penalty", 0.0) or 0.0)
        _effective_mismatch_threshold = 1.5
        if mismatch_penalty > _effective_mismatch_threshold:
            S.logger.info("[LIST TOKEN MISMATCH] rejected=true penalty=%.3f threshold=%.1f focus_hits=%s context_hits=%s items=%s", mismatch_penalty, _effective_mismatch_threshold, int(align.get("focus_hit_items", 0.0)), int(align.get("context_hit_items", 0.0)), int(align.get("item_count", 0.0)))
            dec["answer"] = RAG_NO_MATCH_RESPONSE
            dec["used_llm"] = False
            dec["answer_type"] = "list_query_token_mismatch_rejected"
            dec["source_mode"] = "not_found_guard"
            _log_final_decision_debug(rejected=True, rejection_reason="list_query_token_mismatch")
            return dec

        _candidate_docs = list(grounding_docs or [])
        _item_token_stop = {"the", "a", "an", "and", "or", "to", "of", "for", "in", "on", "at", "from", "with", "by", "is", "are", "was", "were", "this", "that", "these", "those"}
        _item_tokens: set[str] = set()
        for ln in str(shaped or "").splitlines():
            line = re.sub(r"^\s*(?:[-*•]|\d+[\.)])\s+", "", ln).strip().lower()
            if not line:
                continue
            for tok in re.findall(r"[a-z0-9]{4,}", line):
                if tok not in _item_token_stop:
                    _item_tokens.add(tok)

        if _candidate_docs:
            _q_family_for_docs = _classify_query_family_v2(query)
            _q_ctx_for_docs, _q_focus_for_docs = _split_query_context_focus_tokens(query, _q_family_for_docs)

            def _doc_relevance_for_list_guard(d: dict) -> float:
                md = dict((d or {}).get("metadata") or {})
                hay = (
                    str((d or {}).get("page_content") or (d or {}).get("text") or "")[:1800]
                    + "\n"
                    + " ".join(str(md.get(k) or "") for k in ("heading", "section", "title", "chapter"))
                ).lower()
                if not hay.strip():
                    return 0.0
                q_hits = sum(1 for tok in (_q_focus_for_docs + _q_ctx_for_docs) if _token_match_light(hay, tok))
                item_hits = sum(1 for tok in _item_tokens if _token_match_light(hay, tok))
                return (2.0 * float(item_hits)) + float(q_hits)

            _ranked_guard_docs = sorted(_candidate_docs, key=_doc_relevance_for_list_guard, reverse=True)
            list_docs = _ranked_guard_docs[:4]
        else:
            list_docs = []
        section_keys: set[str] = set()
        chunk_idxs: list[int] = []
        for d in list_docs:
            md = dict((d or {}).get("metadata") or {})
            source = str(md.get("source") or md.get("filename") or md.get("id") or "").strip().lower()
            section = str(md.get("heading") or md.get("section") or md.get("title") or md.get("chapter") or "").strip().lower()
            section_keys.add(f"{source}::{section}")
            try:
                chunk_idxs.append(int(md.get("chunk_index") or -1))
            except Exception:
                pass
        support_chunk_count = float(list_support.get("source_chunk_count", 0.0) or 0.0) if isinstance(list_support, dict) else 0.0
        strict_adjacent_scope = bool(
            isinstance(list_support, dict)
            and float(list_support.get("strict_adjacent_merge_allowed", 0.0) or 0.0) >= 0.5
            and float(list_support.get("selected_chunks_count", 0.0) or 0.0) <= 2.0
            and float(list_support.get("merged_extra_chunks_count", 0.0) or 0.0) <= 1.0
        )
        anchored_single_scope = bool((support_chunk_count <= 1.0) or strict_adjacent_scope)
        if (not anchored_single_scope) and (len(section_keys) > 1 or (len(chunk_idxs) >= 2 and (max(chunk_idxs) - min(chunk_idxs) > 3))):
            q_family_v2 = _classify_query_family_v2(query)
            q_ctx_tokens, q_focus_tokens = _split_query_context_focus_tokens(query, q_family_v2)

            source_counts: dict[str, int] = {}
            doc_token_sets: list[set[str]] = []
            token_stop = {"the", "a", "an", "and", "or", "to", "of", "for", "in", "on", "at", "from", "with", "by", "is", "are", "was", "were", "this", "that", "these", "those"}
            query_hits_docs = 0

            for d in list_docs:
                md = dict((d or {}).get("metadata") or {})
                src = str(md.get("source") or md.get("filename") or md.get("id") or "").strip().lower()
                if src:
                    source_counts[src] = source_counts.get(src, 0) + 1

                hay = (
                    str((d or {}).get("page_content") or (d or {}).get("text") or "")[:1500]
                    + "\n"
                    + " ".join(str(md.get(k) or "") for k in ("heading", "section", "title", "chapter"))
                ).lower()
                if any(_token_match_light(hay, tok) for tok in (q_focus_tokens + q_ctx_tokens)):
                    query_hits_docs += 1

                toks = {t for t in re.findall(r"[a-z0-9]{3,}", hay[:1200]) if t not in token_stop}
                if toks:
                    doc_token_sets.append(toks)

            same_source_cluster = bool(source_counts) and (max(source_counts.values()) >= max(2, len(list_docs) - 1))
            chunk_spread_ok = bool((not chunk_idxs) or (max(chunk_idxs) - min(chunk_idxs) <= 8))

            topic_drift_pairs = 0
            for i in range(len(doc_token_sets) - 1):
                inter = len(doc_token_sets[i] & doc_token_sets[i + 1])
                union = len(doc_token_sets[i] | doc_token_sets[i + 1])
                overlap = (inter / union) if union else 0.0
                if overlap < 0.05:
                    topic_drift_pairs += 1
            low_drift = bool(topic_drift_pairs <= 1)

            same_section_same_source_allow = bool(
                len(section_keys) == 1
                and len(source_counts) == 1
                and query_hits_docs >= 1
                and low_drift
            )

            shaped_items = [
                re.sub(r"^\s*(?:[-*•]|\d+[\.)])\s+", "", ln).strip()
                for ln in str(shaped or "").splitlines()
                if re.match(r"^\s*(?:[-*•]|\d+[\.)])\s+", str(ln or ""))
            ]
            compact_label_count = 0
            focus_hit_item_count = 0
            label_verb_re = re.compile(r"\b(?:is|are|was|were|has|have|had|include|includes|including|means|refers|describe|describes|explains|suggests|indicates)\b", re.IGNORECASE)
            for it in shaped_items:
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", it)
                wc = len(words)
                if 1 <= wc <= 6 and not label_verb_re.search(it) and ". " not in it and ";" not in it:
                    compact_label_count += 1
                if any(_token_match_light(it.lower(), tok) for tok in q_focus_tokens):
                    focus_hit_item_count += 1
            compact_ratio = float(compact_label_count) / float(max(1, len(shaped_items)))
            _guard_query_norm = re.sub(r"\s+", " ", str(query or "")).strip().lower()
            _guard_directive_mode = bool(re.match(r"^\s*(?:list|name|give|mention|identify)\b", _guard_query_norm))
            _guard_stage_mode = bool(re.search(r"\bstages?\b", _guard_query_norm))
            cross_section_compact_label_allow = bool(
                len(source_counts) == 1
                and len(shaped_items) >= 3
                and compact_ratio >= 0.80
                and focus_hit_item_count >= 1
                and low_drift
            )
            directive_compact_label_allow = bool(
                _guard_directive_mode
                and (not _guard_stage_mode)
                and same_source_cluster
                and len(shaped_items) >= 4
                and compact_ratio >= 0.80
                and focus_hit_item_count >= 1
            )

            controlled_nearby_ok = bool(
                same_source_cluster
                and chunk_spread_ok
                and query_hits_docs >= max(2, len(list_docs) - 1)
                and low_drift
            )
            if same_section_same_source_allow:
                controlled_nearby_ok = True
            if cross_section_compact_label_allow:
                controlled_nearby_ok = True
            if directive_compact_label_allow:
                controlled_nearby_ok = True

            if not controlled_nearby_ok:
                S.logger.info("[LIST CANDIDATE REJECTED] reason=multi_section_contamination keys=%s", list(section_keys)[:4])
                dec["answer"] = RAG_NO_MATCH_RESPONSE
                dec["used_llm"] = False
                dec["answer_type"] = "list_multi_section_rejected"
                dec["source_mode"] = "not_found_guard"
                _log_final_decision_debug(rejected=True, rejection_reason="list_multi_section_contamination")
                return dec

            S.logger.info("[LIST NEARBY SECTION ALLOW] enabled=true reason=controlled_nearby_alignment")

        def _list_items_grounded_in_docs(shaped_text: str, docs_for_grounding: list[dict]) -> bool:
            grounding_context = "\n".join(
                str((doc_for_grounding or {}).get("page_content") or (doc_for_grounding or {}).get("text") or "")
                for doc_for_grounding in (docs_for_grounding or [])
            ).lower()
            if not grounding_context.strip():
                return False
            grounding_tokens = {
                token for token in re.findall(r"[a-z0-9]{3,}", grounding_context)
                if token not in _item_token_stop
            }
            if not grounding_tokens:
                return False
            item_rows = [
                re.sub(r"^\s*(?:[-*•]|\d+[\.)])\s+", "", line).strip()
                for line in str(shaped_text or "").splitlines()
                if re.match(r"^\s*(?:[-*•]|\d+[\.)])\s+", str(line or ""))
            ]
            if len(item_rows) < 2:
                return False
            supported_rows = 0
            for item_row in item_rows:
                item_terms = [
                    token for token in re.findall(r"[a-z0-9]{3,}", item_row.lower())
                    if token not in _item_token_stop
                ]
                if not item_terms:
                    return False
                term_hits = sum(1 for token in item_terms if token in grounding_tokens)
                if term_hits < max(1, math.ceil(len(item_terms) * 0.75)):
                    return False
                supported_rows += 1
            return supported_rows == len(item_rows)

        lexical_item_grounded = bool(
            str(dec.get("answer_type") or "") == "list_lexical_rescue"
            and float(list_support.get("primary_phrase_hits", 0.0) or 0.0) >= 0.5
            and _list_items_grounded_in_docs(shaped, grounding_docs or [])
        )
        if lexical_item_grounded:
            S.logger.info("[LIST GROUNDING] lexical_rescue_item_support=true")

        if not str(dec.get("answer_type") or "").startswith("list_route") and not lexical_item_grounded and not _is_answer_grounded_in_docs(shaped, grounding_docs or [], query_text=query):
            S.logger.info("[LIST CANDIDATE REJECTED] reason=ungrounded answer=%s", shaped[:220])
            dec["answer"] = RAG_NO_MATCH_RESPONSE
            dec["used_llm"] = False
            dec["answer_type"] = "list_ungrounded_rejected"
            dec["source_mode"] = "not_found_guard"
            _log_final_decision_debug(rejected=True, rejection_reason="list_ungrounded")
            return dec
        dec["answer"] = shaped

    if (
        is_definition_mode
        and not fact_type
        and family != "attribute_lookup"
        and not str(dec.get("answer_type") or "").startswith("attribute_")
        and str(dec.get("answer_type") or "") != "support_procedural_rescue"
    ):
        # Fact/metric questions phrased as "what is the X fee/limit/coverage/
        # minimum ..." also match is_definition_mode (they start with "what is"),
        # but the answer is a number/value that legitimately does NOT echo the
        # full entity phrase (e.g. "FDIC-insured up to $250,000 per depositor"
        # for "What is the FDIC coverage limit?"). Those answers are already
        # validated by the fact guard above, so skip the definition
        # entity-reference rejection for them (it was the root cause of valid
        # Meridian fact evidence being rejected as "not found").
        #
        # MP-C15: definition_structure_recovery answers were already
        # built and grounded against a wider corpus pool by the
        # structure-aware route. Skip re-validation against the narrow
        # `retrieved_docs` here — that pool may not contain the
        # cross-chunk evidence the answer was assembled from.
        if str(dec.get("answer_type") or "") == "definition_structure_recovery":
            S.logger.info("[DEFINITION ROUTE TRUST] reason=structure_recovery_already_validated answer=%s", answer[:220])
        else:
            has_entity, entity = _extract_entity_from_definition_query(query)
            semantically_grounded = _is_answer_grounded_in_docs(answer, retrieved_docs or [], query_text=query)
            entity_or_reference_grounded = _definition_entity_or_reference_match(query, answer)
            strict_pref_ok = _passes_strict_definition_relevance_guard(query, answer)
            _person_definition_query = bool(re.match(r"^who\s+(?:is|was|are|were)\b", re.sub(r"\s+", " ", str(query or "").strip().lower())))
            _answer_low = re.sub(r"\s+", " ", str(answer or "").lower())
            _answer_identity = bool(
                re.search(
                    r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
                    r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
                    _answer_low,
                )
            )
            _answer_theory = bool(
                re.search(r"\b\w+['\u2019]s\s+(?:idea|theory|concept|notion|hypothesis|view|belief|principle|doctrine)\b", _answer_low)
                or re.search(r"\b(?:idea|theory|concept|notion|hypothesis|belief|doctrine)\s+that\b", _answer_low)
            )

            if _person_definition_query and semantically_grounded and _answer_identity and not _answer_theory:
                if not strict_pref_ok:
                    S.logger.info("[DEFINITION SOFT ACCEPT] reason=grounded_person_identity answer=%s", answer[:220])
            elif semantically_grounded and entity_or_reference_grounded:
                if not strict_pref_ok:
                    S.logger.info("[DEFINITION SOFT ACCEPT] reason=strict_guard_miss_but_grounded answer=%s", answer[:220])
            else:
                rescue_answer = _extract_best_scored_concept_sentence_from_docs(query, retrieved_docs or [], max_docs=3)
                if not rescue_answer:
                    rescue_answer = _extract_simple_definition_sentence(query, retrieved_docs or [])
                rescue_answer = re.sub(r"\s+", " ", str(rescue_answer or "")).strip()
                rescue_ok = bool(
                    rescue_answer
                    and _definition_entity_or_reference_match(query, rescue_answer)
                    and _is_answer_grounded_in_docs(rescue_answer, retrieved_docs or [], query_text=query)
                )
                if rescue_ok and _person_definition_query:
                    _rescue_low = re.sub(r"\s+", " ", str(rescue_answer or "").lower())
                    _rescue_identity = bool(
                        re.search(
                            r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
                            r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
                            _rescue_low,
                        )
                    )
                    _rescue_theory = bool(
                        re.search(r"\b\w+['\u2019]s\s+(?:idea|theory|concept|notion|hypothesis|view|belief|principle|doctrine)\b", _rescue_low)
                        or re.search(r"\b(?:idea|theory|concept|notion|hypothesis|belief|doctrine)\s+that\b", _rescue_low)
                    )
                    if _rescue_theory or not _rescue_identity:
                        S.logger.info("[DEFINITION VALIDATION RESCUE] rejected reason=person_not_identity answer=%s", rescue_answer[:220])
                        rescue_ok = False
                if rescue_ok:
                    if not _passes_strict_definition_relevance_guard(query, rescue_answer):
                        S.logger.info("[DEFINITION SOFT ACCEPT] reason=strict_guard_miss_but_rescue_grounded answer=%s", rescue_answer[:220])
                    S.logger.info("[DEFINITION VALIDATION RESCUE] accepted=true answer=%s", rescue_answer[:220])
                    dec["answer"] = rescue_answer
                    dec["used_llm"] = False
                    dec["answer_type"] = "definition_candidate_rescued"
                    dec["source_mode"] = "definition"
                else:
                    S.logger.info("[DEFINITION CANDIDATE REJECTED] reason=entity_reference_or_grounding_failure answer=%s", answer[:220])
                    dec["answer"] = RAG_NO_MATCH_RESPONSE
                    dec["used_llm"] = False
                    dec["answer_type"] = "definition_candidate_rejected"
                    dec["source_mode"] = "not_found_guard"
                    _log_final_decision_debug(rejected=True, rejection_reason="definition_candidate_rejected")
                    return dec

    final_grounding_answer = str(dec.get("answer") or "").strip()
    if _is_low_confidence_grounding(
        query,
        retrieved_docs or [],
        final_grounding_answer,
        {
            "query_family": family,
            "answer_type": dec.get("answer_type"),
            "source_mode": dec.get("source_mode"),
            "used_llm": dec.get("used_llm"),
        },
    ):
        dec["answer"] = RAG_NO_MATCH_RESPONSE
        dec["used_llm"] = False
        dec["answer_type"] = "low_confidence_grounding_blocked"
        dec["source_mode"] = "not_found_guard"
        _log_final_decision_debug(rejected=True, rejection_reason="low_confidence_grounding")
        return dec

    S.logger.info("[FINAL ANSWER SOURCE] source_mode=%s answer_type=%s used_llm=%s", dec.get("source_mode"), dec.get("answer_type"), dec.get("used_llm"))
    _log_final_decision_debug(rejected=False, rejection_reason="")
    return dec

def _shared_rag_final_answer_decision( # type: ignore
    query: str,
    doc_dicts: List[Dict[str, Any]],
    llm_text: Optional[str] = None,
) -> Dict[str, Any]:
    # #region agent log
    S._dbg7d3bbb("assistify_rag_server.py:_shared_rag_final_answer_decision", "decision fn entry", {
        "n_docs": len(doc_dicts or []),
        "llm_text_present": llm_text is not None,
        "query": str(query or "")[:120],
    }, "H-G")
    # #endregion
    if S._skip_deterministic_rag_shortcuts(query) and llm_text is None:
        family_v2 = _classify_query_family_v2(query)
        return {
            "intent": detect_query_intent(query),
            "query_family": family_v2,
            "answer": "",
            "used_llm": True,
            "answer_type": "generation_llm_required",
            "extractor_items_count": 0,
            "source_mode": "generation",
        }
    routed_docs = _apply_heading_boost_for_family(query, _classify_query_family_v2(query), doc_dicts or [])
    routed_docs = _hydrate_route_docs(list(routed_docs or []))
    if _classify_query_family_v2(query) in {"list_entity", "list_structure"}:
        combined_docs = list(routed_docs or [])
        seen_doc_keys: set[str] = set()
        for d in combined_docs:
            md = dict((d or {}).get("metadata") or {})
            key = str(md.get("chunk_index") or md.get("page") or "") or str((d or {}).get("page_content") or (d or {}).get("text") or "")[:220]
            seen_doc_keys.add(key)
        for d in (doc_dicts or []):
            md = dict((d or {}).get("metadata") or {})
            key = str(md.get("chunk_index") or md.get("page") or "") or str((d or {}).get("page_content") or (d or {}).get("text") or "")[:220]
            if key in seen_doc_keys:
                continue
            seen_doc_keys.add(key)
            combined_docs.append(d)
        widened_docs = S._select_list_context_docs(query, combined_docs, max_docs=min(8, len(combined_docs)), scan_limit=min(20, len(combined_docs)))
        if widened_docs:
            routed_docs = widened_docs
    focused_context = "\n\n".join(
        (d.get("page_content") or d.get("text") or "")
        for d in (routed_docs or doc_dicts or [])
    )

    def _limited_context_from_docs(docs: List[Dict[str, Any]], max_docs: int, max_sentences_per_doc: int) -> str:
        parts: List[str] = []
        for d in (docs or [])[:max_docs]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            sents = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if (s or "").strip()]
            if sents:
                parts.append(" ".join(sents[:max_sentences_per_doc]))
        return "\n\n".join(parts)

    definition_context = _limited_context_from_docs(routed_docs or doc_dicts or [], max_docs=3, max_sentences_per_doc=5) or focused_context
    list_context = focused_context
    overview_context = _limited_context_from_docs(routed_docs or doc_dicts or [], max_docs=2, max_sentences_per_doc=5) or focused_context
    if len(overview_context) > 1500:
        overview_context = overview_context[:1500].rstrip(" ,;:-") + "."
    intent = detect_query_intent(query)
    family_legacy = _classify_query_family(query)
    family_v2 = _classify_query_family_v2(query)
    family = family_v2
    fact_type = _detect_fact_query_type(query)
    S.logger.info("[QUERY FAMILY] legacy=%s v2=%s query=%s", family_legacy, family_v2, (query or "")[:140])
    context_tokens_dbg, focus_tokens_dbg = _split_query_context_focus_tokens(query, family_v2)
    if family_v2 in {"list_entity", "list_structure"}:
        S.logger.info("[QUERY TOKEN DEBUG] query=%s", (query or "")[:220])
        S.logger.info("[QUERY TOKEN DEBUG] context_tokens=%s", context_tokens_dbg)
        S.logger.info("[QUERY TOKEN DEBUG] focus_tokens=%s", focus_tokens_dbg)
    list_section_confident = True
    list_debug_selected_chunks: list[Any] = []
    list_debug_section_confidences: list[float] = []
    list_debug_blocked_reason = ""
    list_local_support = _collect_local_window_support(routed_docs or doc_dicts or [])
    list_local_override = _has_strong_local_window_support(list_local_support, confidence_threshold=0.58)

    if _is_support_procedural_query(query):
        _early_support = _rescue_support_procedural_from_docs(query, routed_docs or doc_dicts or [])
        if _early_support and _valid_procedural_rescue_answer(query, _early_support):
            S.logger.info("[SUPPORT PROCEDURAL EARLY] query=%s chars=%s", str(query or "")[:180], len(_early_support))
            return {
                "intent": intent,
                "query_family": family_v2,
                "answer": _early_support,
                "used_llm": False,
                "answer_type": "support_procedural_rescue",
                "extractor_items_count": 0,
                "source_mode": "support_kb",
                "_list_local_support": dict(list_local_support or {}),
            }

    # Default stub — overridden with a real closure inside list_entity/list_structure branch.
    # Ensures the name is always bound even when that branch is not taken.
    def _fetch_adjacent_doc_from_store(source_name: str, chunk_idx: int) -> None:  # type: ignore[return]
        return None

    if family_v2 in {"list_entity", "list_structure"} and (routed_docs or doc_dicts):
        _list_query_norm = re.sub(r"\s+", " ", str(query or "").strip().lower())
        _directive_list_query = bool(re.match(r"^\s*(?:list|name|give|mention|identify)\b", _list_query_norm))
        strict_label_query = bool(
            (re.match(r"^\s*(?:what|which)\s+are\b", _list_query_norm) or _directive_list_query)
            and (not _is_goal_objective_list_query(query, family_v2))
        )
        _owner_tokens_for_strict = [
            t for t in re.findall(r"\b([a-z0-9][a-z0-9\-]{2,})[’']s\b", _list_query_norm)
            if t not in {"what", "which", "list", "name", "give", "mention", "identify", "stage", "stages", "development"}
        ]

        def _strict_clean_label_count(doc_text: str) -> int:
            if not strict_label_query:
                return 0
            doc_low = str(doc_text or "").lower()
            if _owner_tokens_for_strict:
                owner_stage_relation = any(
                    re.search(
                        rf"\b{re.escape(owner_tok)}\b[^\n.]{{0,100}}\b(?:stage|stages|development|theory|model|approach)\b",
                        doc_low,
                    )
                    for owner_tok in _owner_tokens_for_strict[:2]
                )
                if not owner_stage_relation:
                    return 0
            items_local: list[str] = _extract_strict_clean_label_candidates(str(doc_text or ""))

            if len(items_local) < 2:
                raw_text = str(doc_text or "")
                heuristic_candidates: list[str] = []
                if raw_text:
                    for seg in [s.strip() for s in re.split(r"\s*[�•]\s*", raw_text) if s.strip()]:
                        if ":" in seg:
                            heuristic_candidates.append(seg.split(":", 1)[0].strip())

                    heuristic_candidates.extend(
                        [
                            m.strip()
                            for m in re.findall(
                                r"\b([A-Z][A-Za-z\-]+(?:\s+[A-Z][A-Za-z\-]+){0,3})\s+(?:It|An|A|The)\s+(?:is|was|are|were|focused|focuses|concentrated|views|approach)\b",
                                raw_text,
                            )
                        ]
                    )

                    heuristic_candidates.extend(
                        [
                            m.strip()
                            for m in re.findall(
                                r"\b([A-Z][A-Za-z\-]+(?:\s+[A-Z][A-Za-z\-]+){0,3})\s*:\s*",
                                raw_text,
                            )
                        ]
                    )

                seen_local: set[str] = set()
                for cand in heuristic_candidates:
                    norm_c = re.sub(r"\s+", " ", str(cand or "")).strip(" ,;:-")
                    if not norm_c:
                        continue
                    key = re.sub(r"[^a-z0-9]+", " ", norm_c.lower()).strip()
                    if not key or key in seen_local:
                        continue
                    seen_local.add(key)
                    items_local.append(norm_c)
            count = 0
            for it in items_local:
                if _strict_list_label_reject_reason(it):
                    continue
                low_it = it.lower()
                words = re.findall(r"[A-Za-z][A-Za-z\-']*", it)
                wc = len(words)
                if wc < 1 or wc > 6:
                    continue
                if re.search(r"\b(?:is|are|was|were|be|been|being|include|includes|included|consist|consists|consisted|comprise|comprises|composed|focus|focuses|focused|study|studies|studied|explain|explains|explained|describe|describes|described|involv(?:e|es|ed)|concern(?:s|ed)?)\b", low_it):
                    continue
                if re.match(r"^\s*(?:popular|major|main|different|various|important)\s+(?:areas?|types?|kinds?|forms?|branches?)\s+of\b", low_it):
                    continue
                if re.search(r"[;:]", it) or ". " in it:
                    continue
                count += 1
            return count

        list_ranked: list[tuple[float, dict, dict, int]] = []
        # Generic IDF-like rarity signal computed across the candidate pool only.
        # For each query token, count how many candidate chunks contain it (heading or body).
        # A token appearing in only a small fraction of the pool is highly discriminative
        # FOR THIS QUERY — chunks containing it deserve a coverage boost; chunks missing it
        # deserve an extra penalty proportional to the token's pool-rarity. This rebalances
        # the structural bonuses (heading_hits, marker_score, list_density) which can otherwise
        # dominate when an off-topic chunk has a strong structural shape.
        # Pure presence-counting on real chunk text — no domain words, no special cases.
        _pool_docs_for_idf = list((routed_docs or doc_dicts or [])[:10])
        _pool_tokens_for_idf = _query_section_tokens(query, family_v2)
        _pool_size_for_idf = max(1, len(_pool_docs_for_idf))
        _token_chunk_count_idf: dict[str, int] = {}
        for _idf_tok in _pool_tokens_for_idf:
            _hit_n = 0
            for _idf_doc in _pool_docs_for_idf:
                _idf_md = dict((_idf_doc or {}).get("metadata") or {})
                _idf_heading = " ".join(
                    str(_idf_md.get(k) or "") for k in ("heading", "section", "title", "chapter")
                ).lower()
                _idf_body = str(
                    (_idf_doc or {}).get("page_content") or (_idf_doc or {}).get("text") or ""
                ).lower()
                if _token_match_light(_idf_heading, _idf_tok) or _token_match_light(_idf_body, _idf_tok):
                    _hit_n += 1
            _token_chunk_count_idf[_idf_tok] = _hit_n

        # MP-C8 — Generic main-entity / structure split for section anchor scoring.
        # The query "What are the characteristics of management?" has main-entity
        # "management" and structure "characteristics". Without this, a chunk whose
        # heading is "characteristics of organisational framework" can outrank the
        # true target ("characteristics of management") because both share the
        # structural token. We reward chunks whose heading carries the entity and
        # penalise chunks whose heading matches only the structure but lacks the
        # entity. Pure positional logic — no domain words.
        _mpc8_entity_tokens, _mpc8_struct_tokens = _query_main_entity_tokens(query, family_v2)
        if family_v2 in {"list_entity", "list_structure"}:
            S.logger.info(
                "[MP-C8 ENTITY] entity_tokens=%s structure_tokens=%s",
                _mpc8_entity_tokens,
                _mpc8_struct_tokens,
            )

        # MP-C10 — Hard entity-alignment gate.
        # Before entering the per-doc scoring loop, scan the full candidate
        # pool to decide whether the entity is present in *any* chunk.
        # If at least one chunk carries the entity (in heading OR body), we
        # activate the hard filter: chunks that lack the entity receive a
        # large penalty that overrides even a strong list-structure score.
        # If NO chunk in the pool carries the entity at all (e.g. the query
        # is about a topic not in this document), the gate stays OFF and the
        # system falls back to the original soft behaviour — so no regression
        # for queries like "What is quantum computing?" where the entity is
        # legitimately absent everywhere.
        _mpc10_any_entity_present = False
        if _mpc8_entity_tokens and family_v2 in {"list_entity", "list_structure"}:
            for _pre_d in (routed_docs or doc_dicts or [])[:10]:
                _pre_text = str(
                    (_pre_d or {}).get("page_content") or (_pre_d or {}).get("text") or ""
                )
                _pre_md = dict((_pre_d or {}).get("metadata") or {})
                _pre_heading = " ".join(
                    str(_pre_md.get(k) or "")
                    for k in ("heading", "section", "title", "chapter")
                ).lower()
                _pre_window = f"{_pre_heading} {_pre_text[:2000].lower()}"
                if any(_token_match_light(_pre_window, t) for t in _mpc8_entity_tokens):
                    _mpc10_any_entity_present = True
                    break
            S.logger.info(
                "[MP-C10 GATE] entity_tokens=%s any_entity_present=%s",
                _mpc8_entity_tokens,
                _mpc10_any_entity_present,
            )

        for d in (routed_docs or doc_dicts or [])[:10]:
            sig = _doc_query_token_signals(query, family_v2, d)
            cand_text = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            clean_label_count = _strict_clean_label_count(cand_text)
            local_priority_bonus = 0.0
            if sig.get("local_promoted", 0.0) >= 0.5 and sig.get("local_confidence_score", 0.0) >= 0.58:
                local_priority_bonus = 1.6 + (0.9 * sig.get("local_confidence_score", 0.0))
            if strict_label_query:
                if clean_label_count >= 2:
                    local_priority_bonus += 1.6 + (0.35 * min(6, clean_label_count))
                else:
                    local_priority_bonus -= 1.2
            # ── List-primary: demote intro/general, prefer answer-bearing ──
            _lp_adj = 0.0
            _lp_md = dict((d or {}).get("metadata") or {})
            _lp_heading = " ".join(
                str(_lp_md.get(k) or "") for k in ("heading", "section", "title", "chapter")
            ).lower()
            _lp_marker = float(sig.get("marker_score", 0.0))
            _lp_phrase = float(sig.get("phrase_hits", 0.0))
            _lp_gp = float(sig.get("generic_penalty", 0.0))
            _lp_wc = len(re.findall(r"[a-z0-9]+", cand_text.lower()))
            _lp_top = cand_text[:2000]
            # Demote chunks whose heading signals intro/overview/general
            # when they lack list-structure evidence
            if (
                re.search(
                    r"\b(?:introduction|overview|summary|preface|"
                    r"historical\s+background|important\s+terminology|key\s+terms?)\b",
                    _lp_heading,
                )
                and _lp_marker < 0.30
            ):
                _lp_adj -= 1.5
            # Demote very short chunks (title-only / header-only)
            if _lp_wc < 60 and _lp_marker < 0.15:
                _lp_adj -= 1.0
            # Supplementary list evidence that marker_score may miss:
            # inline lettered items "a. Word", "b. Word" etc.
            _supp_list = 0.0
            _inline_letters = len(re.findall(
                r"(?:^|[.\s,;:])\s*[a-o]\.\s+[A-Z][a-z]", _lp_top))
            if _inline_letters >= 2:
                _supp_list += 0.40 * min(10, _inline_letters)
            # comma-separated capitalized terms
            _comma_caps = len(re.findall(
                r"[A-Z][a-z]{2,}(?:\s+[A-Z][a-z]+){0,2}\s*,", _lp_top))
            if _comma_caps >= 3:
                _supp_list += 0.20 * min(6, _comma_caps)
            _lp_adj += 0.5 * _supp_list
            # Offset generic_penalty when chunk has phrase evidence
            # and local list structure that marker_score missed
            if _lp_gp >= 0.5 and _lp_phrase >= 0.3 and _supp_list >= 0.5:
                _lp_adj += min(0.55, 0.45 * _lp_gp)
            sig["_supp_list_evidence"] = float(_supp_list)

            # Per-doc rarity coverage / missing-rare penalty (IDF-style; see precomputation above).
            _doc_md_idf = dict((d or {}).get("metadata") or {})
            _doc_heading_idf = " ".join(
                str(_doc_md_idf.get(k) or "") for k in ("heading", "section", "title", "chapter")
            ).lower()
            _doc_body_idf = str(
                (d or {}).get("page_content") or (d or {}).get("text") or ""
            ).lower()
            _rarity_coverage = 0.0
            _rarity_missing = 0.0
            _rare_threshold = max(1, _pool_size_for_idf // 3)
            for _idf_tok in _pool_tokens_for_idf:
                _df = _token_chunk_count_idf.get(_idf_tok, _pool_size_for_idf)
                _idf_w = math.log(1.0 + (_pool_size_for_idf / max(1.0, float(_df))))
                _present = _token_match_light(_doc_heading_idf, _idf_tok) or _token_match_light(_doc_body_idf, _idf_tok)
                if _present:
                    _rarity_coverage += _idf_w
                else:
                    if _df > 0 and _df <= _rare_threshold:
                        _rarity_missing += _idf_w

            # MP-C8 — Per-doc entity alignment. Boost chunks whose heading
            # carries the query's main entity, penalise chunks whose heading
            # only carries the structural token but lacks the entity. Heading
            # is approximated by metadata heading_blob plus the first ~300
            # characters of the chunk (where inline section titles like
            # "1.2 Characteristics of Management" appear).
            _mpc8_entity_align = 0.0
            _mpc8_entity_in_heading = False
            _mpc8_struct_in_heading = False
            _mpc8_entity_body_freq = 0
            if _mpc8_entity_tokens and family_v2 in {"list_entity", "list_structure"}:
                _mpc8_chunk_top = cand_text[:300].lower()
                _mpc8_heading_extended = f"{_lp_heading} {_mpc8_chunk_top}"
                _mpc8_entity_in_heading = any(
                    _token_match_light(_mpc8_heading_extended, t)
                    for t in _mpc8_entity_tokens
                )
                _mpc8_struct_in_heading = bool(_mpc8_struct_tokens) and any(
                    _token_match_light(_mpc8_heading_extended, t)
                    for t in _mpc8_struct_tokens
                )
                _mpc8_body_scan = cand_text[:2000].lower()
                for _ent_tok in _mpc8_entity_tokens:
                    _ent_norm = _light_normalize_query_token(_ent_tok)
                    if not _ent_norm:
                        continue
                    _mpc8_entity_body_freq += len(
                        re.findall(rf"\b{re.escape(_ent_norm)}s?\b", _mpc8_body_scan)
                    )
                # MP-C10 — Hard entity-alignment filter.
                # A chunk "passes" when the entity token appears either in the
                # extended heading (metadata + first 300 chars) OR anywhere in
                # the first 2 000 chars of the body.  When the pre-pass gate
                # confirmed that at least one other chunk does carry the entity,
                # failing chunks receive a large penalty (-8.0) that overrides
                # even the strongest list-structure score.  When the gate is
                # OFF (entity absent from all candidates) the system degrades
                # gracefully to the original soft penalty so out-of-document
                # queries are not harmed.
                _mpc10_entity_in_window = _mpc8_entity_body_freq >= 1
                _mpc10_entity_passes = _mpc8_entity_in_heading or _mpc10_entity_in_window
                if _mpc8_entity_in_heading:
                    # Entity present in heading/top: strong positive signal.
                    _mpc8_entity_align += 2.6
                elif _mpc10_entity_in_window:
                    # Entity in body but not heading: modest reward — do not
                    # over-penalise answer-bearing prose chunks that lack an
                    # explicit subsection heading for the entity.
                    _mpc8_entity_align += min(0.6, 0.20 * _mpc8_entity_body_freq)
                else:
                    # Entity absent from both heading and local window.
                    if _mpc10_any_entity_present:
                        # Gate is ON: at least one other chunk carries the entity.
                        # Hard penalty — makes this chunk unselectable as the
                        # section anchor regardless of its list-structure score.
                        _mpc8_entity_align -= 8.0
                    elif _mpc8_struct_in_heading:
                        # Gate is OFF (entity not found anywhere) — fall back to
                        # the original soft penalty for the struct-without-entity
                        # heading shape so nothing regresses.
                        _mpc8_entity_align -= 2.4
            sig["_mpc8_entity_align"] = float(_mpc8_entity_align)
            sig["_mpc8_entity_in_heading"] = float(1.0 if _mpc8_entity_in_heading else 0.0)
            sig["_mpc8_struct_in_heading"] = float(1.0 if _mpc8_struct_in_heading else 0.0)
            sig["_mpc8_entity_body_freq"] = float(_mpc8_entity_body_freq)
            sig["_mpc10_entity_passes"] = float(
                1.0 if (
                    _mpc8_entity_tokens
                    and family_v2 in {"list_entity", "list_structure"}
                    and (_mpc8_entity_in_heading or _mpc8_entity_body_freq >= 1)
                ) else 0.0
            )

            local_score = (1.2 * sig.get("phrase_hits", 0.0)) + (0.5 * sig.get("heading_hits", 0.0)) + (0.7 * sig.get("token_hits", 0.0)) + (0.5 * sig.get("marker_score", 0.0)) + (28.0 * sig.get("density", 0.0)) + (0.95 * sig.get("local_confidence_score", 0.0)) + (0.55 * sig.get("local_focus_hits", 0.0)) + (0.45 * sig.get("local_heading_match", 0.0)) + (0.40 * sig.get("local_list_density", 0.0)) + local_priority_bonus + _lp_adj - sig.get("generic_penalty", 0.0) - (2.5 * sig.get("missing_penalty", 0.0)) + (1.2 * _rarity_coverage) - (2.5 * _rarity_missing) + (8.0 * sig.get("concept_proximity", 0.0)) - (2.0 * sig.get("concept_dispersion", 0.0)) + _mpc8_entity_align
            list_ranked.append((float(local_score), d, sig, int(clean_label_count)))
        list_ranked.sort(key=lambda x: x[0], reverse=True)

        if list_ranked:
            S.logger.info("[SECTION DEBUG] query=%s", (query or "")[:220])
        for rank_idx, (cand_score, cand_doc, cand_sig, cand_clean_count) in enumerate(list_ranked[: min(5, len(list_ranked))], start=1):
            md_c = dict((cand_doc or {}).get("metadata") or {})
            cand_txt = str((cand_doc or {}).get("page_content") or (cand_doc or {}).get("text") or "")
            heading_parts = [str(md_c.get(k) or "") for k in ("heading", "section", "title", "chapter", "role")]
            heading_blob = " ".join(heading_parts).lower()
            low_cand = cand_txt.lower()
            query_hits = [
                tok for tok in (context_tokens_dbg + focus_tokens_dbg)
                if re.search(rf"\b{re.escape(tok)}\b", f"{heading_blob} {low_cand[:1800]}")
            ]
            focus_hits = [
                tok for tok in focus_tokens_dbg
                if re.search(rf"\b{re.escape(tok)}\b", f"{heading_blob} {low_cand[:1800]}")
            ]
            semantic_score = 0.0
            for sk in ("similarity", "score", "final_score", "_boosted_score"):
                if sk in (cand_doc or {}):
                    try:
                        semantic_score = float((cand_doc or {}).get(sk) or 0.0)
                    except Exception:
                        semantic_score = 0.0
                    break
            section_conf = _debug_section_confidence(cand_sig, cand_score)
            preview = re.sub(r"\s+", " ", cand_txt).strip()[:160]
            S.logger.info(
                "[SECTION DEBUG] rank=%s chunk=%s source=%s semantic=%.4f final=%.4f query_hits=%s focus_hits=%s heading_hits=%.3f section_phrase_hits=%.3f list_density=%.3f generic_penalty=%.3f heading_detected=%s toc_hint=%s section_confidence=%.3f concept_proximity=%.3f concept_dispersion=%.3f mpc8_entity_align=%.3f mpc8_entity_in_heading=%s mpc8_struct_in_heading=%s mpc10_entity_passes=%s preview=%s",
                rank_idx,
                md_c.get("chunk_index"),
                str(md_c.get("source") or md_c.get("filename") or md_c.get("id") or "")[:120],
                semantic_score,
                float(cand_score),
                query_hits,
                focus_hits,
                float(cand_sig.get("heading_hits", 0.0) or 0.0),
                float(cand_sig.get("phrase_hits", 0.0) or 0.0),
                float(cand_sig.get("marker_score", 0.0) or 0.0),
                float(cand_sig.get("generic_penalty", 0.0) or 0.0),
                bool(cand_sig.get("heading_detected", 0.0) >= 0.5),
                bool(cand_sig.get("toc_hint", 0.0) >= 0.5),
                section_conf,
                float(cand_sig.get("concept_proximity", 0.0) or 0.0),
                float(cand_sig.get("concept_dispersion", 0.0) or 0.0),
                float(cand_sig.get("_mpc8_entity_align", 0.0) or 0.0),
                bool(cand_sig.get("_mpc8_entity_in_heading", 0.0) >= 0.5),
                bool(cand_sig.get("_mpc8_struct_in_heading", 0.0) >= 0.5),
                bool(cand_sig.get("_mpc10_entity_passes", 0.0) >= 0.5),
                preview,
            )
            if strict_label_query:
                S.logger.info("[SECTION DEBUG] rank=%s clean_label_count=%s", rank_idx, int(cand_clean_count))

        top_sig = list_ranked[0][2] if list_ranked else {}
        top_score = float(list_ranked[0][0]) if list_ranked else -999.0
        strong_anchor = bool(
            top_sig.get("phrase_hits", 0.0) >= 0.55
            or top_sig.get("heading_hits", 0.0) >= 0.65
            or (top_sig.get("token_hits", 0.0) >= 1.2 and top_sig.get("marker_score", 0.0) >= 0.20)
            or (top_sig.get("local_focus_hits", 0.0) >= 1.0 and top_sig.get("local_confidence_score", 0.0) >= 0.45)
        )
        list_section_confident = bool((top_score >= 1.15 or top_sig.get("local_confidence_score", 0.0) >= 0.55) and strong_anchor and top_sig.get("generic_penalty", 0.0) < 1.35)
        selected_ranked: list[tuple[float, dict, dict]] = []
        merged_extra_chunks: list[Any] = []
        strict_adjacent_merge_allowed = False
        list_count_target_for_lock = _list_query_count_target(query)

        def _section_signature_for_doc(d: dict) -> str:
            md_local = dict((d or {}).get("metadata") or {})
            sig = str(md_local.get("_section_signature") or "").strip().lower()
            if sig:
                return sig
            anchor = str(md_local.get("_local_anchor") or "").strip().lower()
            if not anchor:
                return ""
            toks = [t for t in re.findall(r"[a-z0-9]{3,}", anchor) if t not in {"the", "and", "for", "with", "from", "section", "chapter", "unit"}][:4]
            return " ".join(toks)

        def _same_section_signature(sig_a: str, sig_b: str) -> bool:
            a = str(sig_a or "").strip().lower()
            b = str(sig_b or "").strip().lower()
            if not a or not b:
                return False
            if a == b:
                return True
            ta = set(re.findall(r"[a-z0-9]{3,}", a))
            tb = set(re.findall(r"[a-z0-9]{3,}", b))
            if not ta or not tb:
                return False
            overlap = len(ta & tb) / float(max(1, len(ta | tb)))
            return overlap >= 0.55

        def _owner_focus_consistent(doc_a: dict, doc_b: dict) -> bool:
            if not _owner_tokens_for_strict:
                return True
            txt_a = str((doc_a or {}).get("page_content") or (doc_a or {}).get("text") or "")
            txt_b = str((doc_b or {}).get("page_content") or (doc_b or {}).get("text") or "")
            md_a = dict((doc_a or {}).get("metadata") or {})
            md_b = dict((doc_b or {}).get("metadata") or {})
            blob_a = f"{md_a.get('heading') or ''} {md_a.get('section') or ''} {md_a.get('title') or ''} {txt_a[:2200]}".lower()
            blob_b = f"{md_b.get('heading') or ''} {md_b.get('section') or ''} {md_b.get('title') or ''} {txt_b[:2200]}".lower()
            owner_hits_a = any(_token_match_light(blob_a, owner_tok) for owner_tok in _owner_tokens_for_strict[:2])
            owner_hits_b = any(_token_match_light(blob_b, owner_tok) for owner_tok in _owner_tokens_for_strict[:2])
            if owner_hits_a and owner_hits_b:
                return True
            query_anchor_terms = [t for t in (focus_tokens_dbg or context_tokens_dbg) if len(str(t or "")) >= 3][:6]
            if not query_anchor_terms:
                return False
            anchor_hits_a = sum(1 for tok in query_anchor_terms if _token_match_light(blob_a, tok))
            anchor_hits_b = sum(1 for tok in query_anchor_terms if _token_match_light(blob_b, tok))
            return bool(anchor_hits_a >= 1 and anchor_hits_b >= 1)

        def _page_num(md: dict) -> int | None:
            raw_page = md.get("page")
            if raw_page is None:
                return None
            m = re.search(r"\d+", str(raw_page))
            if not m:
                return None
            try:
                return int(m.group(0))
            except Exception:
                return None

        def _page_adjacent_or_same(md_a: dict, md_b: dict) -> bool:
            pa = _page_num(md_a)
            pb = _page_num(md_b)
            if pa is None or pb is None:
                return False
            return abs(pa - pb) <= 1

        def _semantic_signal(doc_obj: dict, sig_obj: dict, ranked_score: float) -> float:
            dense = float((sig_obj or {}).get("density", 0.0) or 0.0)
            local_conf = float((sig_obj or {}).get("local_confidence_score", 0.0) or 0.0)
            token_hits = float((sig_obj or {}).get("token_hits", 0.0) or 0.0)
            raw_sem = 0.0
            for sk in ("similarity", "score", "final_score", "_boosted_score"):
                if sk in (doc_obj or {}):
                    try:
                        raw_sem = float((doc_obj or {}).get(sk) or 0.0)
                    except Exception:
                        raw_sem = 0.0
                    break
            return max(raw_sem, ranked_score, local_conf, dense * 10.0, token_hits * 0.35)

        def _is_weakly_semantic_match(doc_obj: dict, sig_obj: dict, ranked_score: float) -> bool:
            sem_gate = _semantic_signal(doc_obj, sig_obj, ranked_score) >= 0.40
            token_gate = float((sig_obj or {}).get("token_hits", 0.0) or 0.0) >= 0.60
            phrase_gate = float((sig_obj or {}).get("phrase_hits", 0.0) or 0.0) >= 0.30
            local_focus_gate = float((sig_obj or {}).get("local_focus_hits", 0.0) or 0.0) >= 0.60
            return bool(sem_gate or token_gate or phrase_gate or local_focus_gate)

        candidate_pool = list(routed_docs or doc_dicts or [])[:20]
        neighbor_map: dict[tuple[str, int], tuple[float, dict, dict, int]] = {}
        for pool_doc in candidate_pool:
            md_pool = dict((pool_doc or {}).get("metadata") or {})
            src_pool = str(md_pool.get("source") or md_pool.get("filename") or md_pool.get("id") or "")
            idx_pool = _safe_int(md_pool.get("chunk_index"))
            if not src_pool or idx_pool is None:
                continue
            sig_pool = _doc_query_token_signals(query, family_v2, pool_doc)
            clean_pool = _strict_clean_label_count(str((pool_doc or {}).get("page_content") or (pool_doc or {}).get("text") or "")) if strict_label_query else 0
            sem_pool = 0.0
            for sk in ("similarity", "score", "final_score", "_boosted_score"):
                if sk in (pool_doc or {}):
                    try:
                        sem_pool = float((pool_doc or {}).get(sk) or 0.0)
                    except Exception:
                        sem_pool = 0.0
                    break
            key_pool = (src_pool, idx_pool)
            prev_entry = neighbor_map.get(key_pool)
            if (prev_entry is None) or (sem_pool > float(prev_entry[0])):
                neighbor_map[key_pool] = (sem_pool, pool_doc, sig_pool, int(clean_pool))

        def _fetch_adjacent_doc_from_store(source_name: str, chunk_idx: int) -> tuple[float, dict, dict, int] | None:
            if not source_name:
                return None
            try:
                collection = getattr(getattr(S.live_rag, "vs", None), "collection", None)
            except Exception:
                collection = None
            if collection is None:
                return None

            rows = None
            where_candidates = [
                {"$and": [{"source": source_name}, {"chunk_index": int(chunk_idx)}]},
                {"$and": [{"source": source_name}, {"chunk_index": str(chunk_idx)}]},
            ]
            for where_clause in where_candidates:
                try:
                    rows = collection.get(where=where_clause, include=["documents", "metadatas"])
                except Exception:
                    rows = None
                if rows and rows.get("documents"):
                    break

            if not rows or not rows.get("documents"):
                return None

            docs_list = rows.get("documents") or []
            metas_list = rows.get("metadatas") or []
            if not docs_list:
                return None

            fetched_text_raw = str(docs_list[0] or "")
            fetched_text_norm = _normalize_context_entities(query, _clean_ocr_artifacts(fetched_text_raw) or fetched_text_raw)
            fetched_text = S._focus_doc_to_query_window(query, fetched_text_norm)
            fetched_meta = dict(metas_list[0] or {}) if metas_list else {}
            fetched_doc = {
                "page_content": fetched_text,
                "text": fetched_text,
                "content": fetched_text,
                "metadata": fetched_meta,
            }
            fetched_sig = _doc_query_token_signals(query, family_v2, fetched_doc)
            fetched_clean = _strict_clean_label_count(fetched_text) if strict_label_query else 0
            return (0.0, fetched_doc, fetched_sig, int(fetched_clean))

        primary_clean_count = 0
        primary_section_confidence = 0.0
        primary_has_deterministic_list_candidate = False
        primary_strong_section_for_merge_guard = False
        primary_clean_source_locked = False
        if list_ranked:
            primary_tuple = list_ranked[0]
            if strict_label_query:
                clean_preferred_tuple = None
                if isinstance(list_count_target_for_lock, int):
                    for cand in list_ranked:
                        if int(cand[3]) == int(list_count_target_for_lock):
                            clean_preferred_tuple = cand
                            break
                if clean_preferred_tuple is None:
                    if not isinstance(list_count_target_for_lock, int):
                        for cand in list_ranked:
                            if int(cand[3]) >= 5:
                                clean_preferred_tuple = cand
                                break
                if clean_preferred_tuple is None:
                    for cand in list_ranked:
                        if int(cand[3]) >= 2:
                            clean_preferred_tuple = cand
                            break
                if clean_preferred_tuple is not None:
                    primary_tuple = clean_preferred_tuple
            primary_score, primary_doc, primary_sig, primary_clean_count = primary_tuple
            selected_ranked = [(primary_score, primary_doc, primary_sig)]
            md_primary = dict((primary_doc or {}).get("metadata") or {})
            primary_chunk = md_primary.get("chunk_index")
            primary_source = str(md_primary.get("source") or md_primary.get("filename") or md_primary.get("id") or "")
            primary_signature = _section_signature_for_doc(primary_doc)
            primary_section_confidence = _debug_section_confidence(primary_sig, primary_score)
            primary_has_deterministic_list_candidate = bool(
                int(primary_clean_count) >= 2
                or (
                    float(primary_sig.get("marker_score", 0.0) or 0.0) >= 0.16
                    and (
                        float(primary_sig.get("phrase_hits", 0.0) or 0.0) >= 0.30
                        or float(primary_sig.get("heading_hits", 0.0) or 0.0) >= 0.35
                        or float(primary_sig.get("local_focus_hits", 0.0) or 0.0) >= 1.0
                    )
                )
                or float(primary_sig.get("_supp_list_evidence", 0.0) or 0.0) >= 1.5
            )
            primary_strong_section_for_merge_guard = bool(
                list_section_confident or primary_section_confidence >= 0.42
            )
            S.logger.info("[LIST SOURCE DEBUG] primary_chunk=%s", primary_chunk)
            if strict_label_query:
                S.logger.info("[LIST SOURCE DEBUG] primary_clean_label_count=%s", int(primary_clean_count))

            if strict_label_query and int(primary_clean_count) >= 2:
                S.logger.info("[LIST SOURCE DEBUG] strict_single_window_mode=true reason=clean_labels_in_primary")
            primary_clean_source_locked = bool(
                strict_label_query
                and int(primary_clean_count) >= 5
                and (
                    not isinstance(list_count_target_for_lock, int)
                    or int(primary_clean_count) == int(list_count_target_for_lock)
                )
            )
            S.logger.info(
                "[LIST CLEAN PIPELINE] clean_pass=%s primary_locked=%s clean_label_count=%s target=%s chunk=%s",
                bool(primary_clean_source_locked),
                bool(primary_clean_source_locked),
                int(primary_clean_count),
                list_count_target_for_lock,
                primary_chunk,
            )
            p_idx = _safe_int(primary_chunk)
            strict_mode = bool(strict_label_query and int(primary_clean_count) >= 2)
            structure_query_merge_mode = _is_structure_query(query)
            if structure_query_merge_mode:
                S.logger.info("[STRUCTURE QUERY DETECTED] query=%s", str(query or "")[:160])
            if p_idx is None or not primary_source:
                S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="primary_chunk_missing"', primary_chunk)
            else:
                md_primary_page = dict((primary_doc or {}).get("metadata") or {})
                selected_seen_chunks: set[int] = {p_idx}
                if primary_clean_source_locked:
                    S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=* reason="clean_primary_locked"')
                for n_idx in ([] if primary_clean_source_locked else [p_idx - 1, p_idx + 1]):
                    if len(selected_ranked) >= 3:
                        break
                    cand_tuple = neighbor_map.get((primary_source, n_idx))
                    if cand_tuple is None:
                        fetched_tuple = _fetch_adjacent_doc_from_store(primary_source, n_idx)
                        if fetched_tuple is None:
                            S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="adjacent_chunk_missing"', n_idx)
                            continue
                        cand_tuple = fetched_tuple
                        neighbor_map[(primary_source, n_idx)] = cand_tuple
                        S.logger.info('[LIST SOURCE DEBUG] merge_allowed_chunk=%s reason="adjacent_chunk_fetched"', n_idx)
                    cand_score, cand_doc, cand_sig, _cand_clean_count = cand_tuple
                    md_cand = dict((cand_doc or {}).get("metadata") or {})
                    cand_chunk = md_cand.get("chunk_index")
                    c_idx = _safe_int(cand_chunk)
                    if c_idx is None or c_idx in selected_seen_chunks:
                        S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="duplicate_or_invalid_chunk"', cand_chunk)
                        continue
                    if abs(c_idx - p_idx) != 1:
                        S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="non_contiguous_chunk"', cand_chunk)
                        continue
                    if not _page_adjacent_or_same(md_primary_page, md_cand):
                        S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="non_adjacent_page"', cand_chunk)
                        continue
                    if not _is_weakly_semantic_match(cand_doc, cand_sig, cand_score):
                        S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="weak_semantic_match"', cand_chunk)
                        continue
                    cand_signature = _section_signature_for_doc(cand_doc)
                    same_section = _same_section_signature(primary_signature, cand_signature)
                    owner_consistent = _owner_focus_consistent(primary_doc, cand_doc)
                    structure_adjacent_labels = bool(
                        structure_query_merge_mode
                        and int(_cand_clean_count) >= 3
                        and _is_weakly_semantic_match(cand_doc, cand_sig, cand_score)
                    )
                    if (
                        primary_strong_section_for_merge_guard
                        and primary_has_deterministic_list_candidate
                        and not same_section
                        and not structure_adjacent_labels
                    ):
                        S.logger.info("[LIST MERGE GUARD] primary_chunk=%s", primary_chunk)
                        S.logger.info("[LIST MERGE GUARD] primary_section_confidence=%.3f", float(primary_section_confidence))
                        S.logger.info("[LIST MERGE GUARD] adjacent_chunk=%s", cand_chunk)
                        S.logger.info("[LIST MERGE GUARD] same_section=False")
                        S.logger.info("[LIST MERGE GUARD] merge=False reason=strong_primary_section_preserved")
                        S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="strong_primary_section_preserved"', cand_chunk)
                        continue
                    if structure_adjacent_labels:
                        S.logger.info("[CONCEPT CLUSTER DETECTED] adjacent_chunk=%s clean_labels=%d", cand_chunk, int(_cand_clean_count))
                        S.logger.info('[LIST SOURCE DEBUG] merge_allowed_chunk=%s reason="structure_query_adjacent_labels" same_section=%s semantic=%.3f', cand_chunk, same_section, _semantic_signal(cand_doc, cand_sig, cand_score))
                    elif strict_mode:
                        if not owner_consistent:
                            S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="strict_mode_owner_mismatch"', cand_chunk)
                            continue
                        if not same_section and primary_signature and cand_signature:
                            S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="strict_mode_different_section"', cand_chunk)
                            continue
                        S.logger.info('[LIST SOURCE DEBUG] merge_allowed_chunk=%s reason="strict_mode_bidirectional_adjacent" same_section=%s semantic=%.3f', cand_chunk, same_section, _semantic_signal(cand_doc, cand_sig, cand_score))
                        strict_adjacent_merge_allowed = True
                    else:
                        if not same_section and primary_signature and cand_signature:
                            S.logger.info('[LIST SOURCE DEBUG] merge_rejected_chunk=%s reason="different_section_signature"', cand_chunk)
                            continue
                        S.logger.info('[LIST SOURCE DEBUG] merge_allowed_chunk=%s reason="bidirectional_adjacent" same_section=%s semantic=%.3f', cand_chunk, same_section, _semantic_signal(cand_doc, cand_sig, cand_score))

                    selected_ranked.append((cand_score, cand_doc, cand_sig))
                    selected_seen_chunks.add(c_idx)
                    merged_extra_chunks.append(cand_chunk)

                def _chunk_sort_key(row: tuple[float, dict, dict]) -> tuple[int, float]:
                    md_row = dict((row[1] or {}).get("metadata") or {})
                    idx_row = _safe_int(md_row.get("chunk_index"))
                    if idx_row is None:
                        idx_row = 10**9
                    return (idx_row, -float(row[0]))

                selected_ranked = sorted(selected_ranked, key=_chunk_sort_key)[:3]

            S.logger.info("[LIST SOURCE DEBUG] merged_extra_chunks=%s", merged_extra_chunks)

        list_docs = [d for score, d, sig in selected_ranked]

        section_coherence_ok = False
        section_coherence_reason = "no_ranked_candidates"
        if selected_ranked:
            section_scores = [_debug_section_confidence(sig, score) for score, _d, sig in selected_ranked]
            max_section_score = max(section_scores) if section_scores else 0.0
            avg_section_score = (sum(section_scores) / max(1, len(section_scores))) if section_scores else 0.0
            heading_or_phrase_hits = sum(
                1
                for _score, _d, sig in selected_ranked
                if (sig.get("heading_hits", 0.0) >= 0.35 or sig.get("phrase_hits", 0.0) >= 0.30)
            )
            marker_hits = sum(1 for _score, _d, sig in selected_ranked if sig.get("marker_score", 0.0) >= 0.12 or float(sig.get("_supp_list_evidence", 0.0) or 0.0) >= 1.5)
            local_promoted_hits = sum(1 for _score, _d, sig in selected_ranked if sig.get("local_promoted", 0.0) >= 0.5)
            local_focus_total = sum(float(sig.get("local_focus_hits", 0.0) or 0.0) for _score, _d, sig in selected_ranked)
            local_list_total = sum(float(sig.get("local_list_density", 0.0) or 0.0) for _score, _d, sig in selected_ranked)

            sources: list[str] = []
            chunk_idxs: list[int] = []
            for _score, d_sel, _sig in selected_ranked:
                md_sel = dict((d_sel or {}).get("metadata") or {})
                src_sel = str(md_sel.get("source") or md_sel.get("filename") or md_sel.get("id") or "")
                if src_sel:
                    sources.append(src_sel)
                try:
                    chunk_idxs.append(int(md_sel.get("chunk_index") or -1))
                except Exception:
                    pass
            single_source = bool(sources) and (len(set(sources)) == 1)
            compact_window = bool(single_source and len(chunk_idxs) >= 2 and (max(chunk_idxs) - min(chunk_idxs) <= 3))

            token_stop = {"the", "a", "an", "and", "or", "to", "of", "for", "in", "on", "at", "from", "with", "by", "is", "are", "was", "were", "this", "that", "these", "those"}
            doc_token_sets: list[set[str]] = []
            for _score, d_sel, _sig in selected_ranked:
                txt_sel = str((d_sel or {}).get("page_content") or (d_sel or {}).get("text") or "")[:1200].lower()
                toks_sel = {t for t in re.findall(r"[a-z0-9]{3,}", txt_sel) if t not in token_stop}
                if toks_sel:
                    doc_token_sets.append(toks_sel)
            topic_drift_pairs = 0
            for i in range(len(doc_token_sets) - 1):
                inter = len(doc_token_sets[i] & doc_token_sets[i + 1])
                union = len(doc_token_sets[i] | doc_token_sets[i + 1])
                overlap = (inter / union) if union else 0.0
                if overlap < 0.06:
                    topic_drift_pairs += 1
            low_drift = bool(topic_drift_pairs <= 1)

            section_coherence_ok = bool(
                (max_section_score >= 0.42 or (local_promoted_hits >= 1 and local_focus_total >= 1.0))
                and (avg_section_score >= 0.28 or local_promoted_hits >= 1)
                and (compact_window or heading_or_phrase_hits >= 1)
                and (marker_hits >= 1 or heading_or_phrase_hits >= 2 or local_list_total >= 0.14)
                and (low_drift or local_promoted_hits >= 1)
            )
            if strict_label_query and len(selected_ranked) == 1 and int(primary_clean_count) >= 2:
                section_coherence_ok = True
                section_coherence_reason = "strict_clean_single_window"
            if section_coherence_ok:
                section_coherence_reason = "coherent_local_window"
            elif not (max_section_score >= 0.42 and avg_section_score >= 0.28):
                section_coherence_reason = "low_section_confidence"
            elif not (compact_window or heading_or_phrase_hits >= 1):
                section_coherence_reason = "no_local_anchor"
            elif not (marker_hits >= 1 or heading_or_phrase_hits >= 2):
                section_coherence_reason = "weak_list_structure"
            else:
                section_coherence_reason = "high_topic_drift"

        list_section_confident = bool(list_section_confident and section_coherence_ok)
        S.logger.info("[SECTION COHERENCE DEBUG] coherent=%s reason=%s", bool(list_section_confident), section_coherence_reason)
        if list_docs:
            list_debug_selected_chunks = [dict((d or {}).get("metadata") or {}).get("chunk_index") for d in list_docs]
            list_debug_section_confidences = [round(_debug_section_confidence(sig, score), 3) for score, d, sig in selected_ranked[: len(list_docs)]]
            selected_local_support = _collect_local_window_support(list_docs)
            list_local_support["used_single_window"] = max(float(list_local_support.get("used_single_window", 0.0) or 0.0), float(selected_local_support.get("used_single_window", 0.0) or 0.0))
            list_local_support["placeholder_heading_rejected"] = max(float(list_local_support.get("placeholder_heading_rejected", 0.0) or 0.0), float(selected_local_support.get("placeholder_heading_rejected", 0.0) or 0.0))
            if str(selected_local_support.get("validation_scope") or "") == "single_local_window":
                list_local_support["validation_scope"] = "single_local_window"
                list_local_support["single_local_window_text"] = str(selected_local_support.get("single_local_window_text") or "")
            list_local_support["merged_extra_chunks_count"] = float(len(merged_extra_chunks))
            list_local_support["selected_chunks_count"] = float(len(list_debug_selected_chunks))
            list_local_support["strict_adjacent_merge_allowed"] = 1.0 if strict_adjacent_merge_allowed else 0.0
            if len(list_debug_selected_chunks) == 1 and len(merged_extra_chunks) == 0:
                list_local_support["used_single_window"] = 1.0
            if any(float(sig.get("heading_placeholder_rejected", 0.0) or 0.0) >= 0.5 for _s, _d, sig in selected_ranked):
                list_local_support["placeholder_heading_rejected"] = 1.0
            if any((float(sig.get("heading_placeholder_rejected", 0.0) or 0.0) >= 0.5) or (float(sig.get("heading_document_title_rejected", 0.0) or 0.0) >= 0.5) for _s, _d, sig, _clean in list_ranked[: min(6, len(list_ranked))]):
                list_local_support["placeholder_heading_rejected"] = 1.0
            S.logger.info("[SECTION SELECT] family=%s selected_docs=%s top_score=%.3f confident=%s", family_v2, len(list_docs), top_score, list_section_confident)

            if list_section_confident:
                routed_docs = list_docs
                if strict_adjacent_merge_allowed and len(list_docs) >= 2:
                    focused_context = "\n".join((d.get("page_content") or d.get("text") or "") for d in list_docs)
                else:
                    focused_context = "\n\n".join((d.get("page_content") or d.get("text") or "") for d in list_docs)
                list_context = focused_context
                list_local_support = _collect_local_window_support(list_docs)
                list_local_support["merged_extra_chunks_count"] = float(len(merged_extra_chunks))
                list_local_support["selected_chunks_count"] = float(len(list_debug_selected_chunks))
                if selected_ranked:
                    _top_sig_ls = selected_ranked[0][2]
                    list_local_support["primary_phrase_hits"] = float(_top_sig_ls.get("phrase_hits", 0.0) or 0.0)
                    list_local_support["primary_supp_list_evidence"] = float(_top_sig_ls.get("_supp_list_evidence", 0.0) or 0.0)
                list_local_support["strict_adjacent_merge_allowed"] = 1.0 if strict_adjacent_merge_allowed else 0.0
                if len(list_debug_selected_chunks) == 1 and len(merged_extra_chunks) == 0:
                    list_local_support["used_single_window"] = 1.0
                if any(float(sig.get("heading_placeholder_rejected", 0.0) or 0.0) >= 0.5 for _s, _d, sig in selected_ranked):
                    list_local_support["placeholder_heading_rejected"] = 1.0
                if any((float(sig.get("heading_placeholder_rejected", 0.0) or 0.0) >= 0.5) or (float(sig.get("heading_document_title_rejected", 0.0) or 0.0) >= 0.5) for _s, _d, sig, _clean in list_ranked[: min(6, len(list_ranked))]):
                    list_local_support["placeholder_heading_rejected"] = 1.0
                list_local_override = _has_strong_local_window_support(list_local_support, confidence_threshold=0.58)
                S.logger.info("[LOCAL SIGNAL USE] promoted=%s focus=%.2f heading=%.2f density=%.3f confidence=%.3f", int(list_local_support.get("promoted_count", 0.0)), float(list_local_support.get("focus_hits", 0.0)), float(list_local_support.get("heading_match", 0.0)), float(list_local_support.get("list_density", 0.0)), float(list_local_support.get("confidence", 0.0)))
            else:
                S.logger.info("[SECTION SELECT] low_confidence_single_chunk=true action=keep_original_context")

    answer_source_mode = "prose"

    def _result(ans: str | None, used_llm: bool, answer_type: str, items_count: int = 0) -> Dict[str, Any]:
        nonlocal answer_source_mode
        # #region agent log
        S._dbg7d3bbb("assistify_rag_server.py:_shared_rag_final_answer_decision._result", "decision branch", {
            "answer_type": answer_type,
            "used_llm": used_llm,
            "family_v2": family_v2,
            "fact_type": fact_type,
            "ans_preview": str(ans or "")[:160],
            "n_docs": len(routed_docs or doc_dicts or []),
            "llm_text_present": llm_text is not None,
        }, "H-D")
        # #endregion

        def _is_fragmentary_ocr(text: str) -> bool:
            reason = _ocr_filter_rejected_reason(text, query)
            if reason:
                _log_ocr_filter_rejection(text, reason)
                return True
            return False

        def _is_definition_answer_valid(ans_text: str) -> bool:
            if family_v2 == "attribute_lookup" or str(answer_type or "").startswith("attribute_"):
                return True
            if str(answer_type or "") == "support_procedural_rescue":
                return True
            q_low = re.sub(r"\s+", " ", str(query or "")).strip().lower()
            if not (q_low.startswith("what is") or q_low.startswith("define") or family_v2 in {"definition_entity", "definition_comparison"}):
                return True
            cand = re.sub(r"\s+", " ", str(ans_text or "")).strip()
            if not cand or cand == RAG_NO_MATCH_RESPONSE:
                return False
            if _is_fragmentary_ocr(cand):
                return False
            support_docs = routed_docs or doc_dicts or []
            if not _is_answer_grounded_in_docs(cand, support_docs, query_text=query):
                return False
            if not _definition_entity_or_reference_match(query, cand):
                return False
            if family_v2 == "definition_comparison":
                sentences_local = [s for s in re.split(r"(?<=[.!?])\s+", cand) if s.strip()]
                if len(sentences_local) > 4:
                    return False
                return True
            # MP-C14 — For definition_entity, generic_grounded_check is NOT
            # sufficient. The candidate must satisfy the strict shared
            # `_is_valid_definition_sentence` validator (entity present,
            # real definition cue, not attribution-only / pronoun-led /
            # heading / table / OCR fragment). Otherwise the answer is
            # rejected and the upstream pipeline returns Not found.
            if family_v2 == "definition_entity":
                _ent_has, _ent_v = _extract_entity_from_definition_query(query)
                _ent_v_l = re.sub(r"\s+", " ", str(_ent_v or "").strip().lower()) if _ent_has else ""
                if not _is_valid_definition_sentence(cand, _ent_v_l):
                    S.logger.info("[DEF QUALITY REJECT] mode=post_llm_validator entity=%s preview=%s", _ent_v_l, cand[:160])
                    return False
                return True
            if not _passes_strict_definition_relevance_guard(query, cand):
                S.logger.info("[DEFINITION SOFT ACCEPT] reason=strict_guard_miss_but_grounded answer=%s", cand[:220])
            return True

        def _is_coherent_list_answer(ans_text: str) -> tuple[bool, str | None]:
            q_low = re.sub(r"\s+", " ", str(query or "")).strip().lower()
            list_mode = bool(
                family_v2 == "list_entity"
                or family == "list_structure"
                or _is_targeted_list_question(q_low)
                or re.match(r"^\s*(?:what|which)\s+are\b", q_low)
            )
            if not list_mode:
                if S._doc_router_implies_comparison(query):
                    return True, str(ans_text or "").strip()
                return True, re.sub(r"\s+", " ", str(ans_text or "")).strip()
            answer_type_local = str(answer_type or "")
            strict_fast = bool((not used_llm) and answer_type_local in {"list_deterministic_context", "list_fast_simple", "list_extractor", "list_route_deterministic"})
            list_ok_local, list_reason_local, shaped = _assess_list_coherence(query, _preclean_list_answer_for_assessment(str(ans_text or "")), strict_fast=strict_fast, local_support=list_local_support)
            S.logger.info("[LIST COHERENCE DEBUG] accepted=%s reason=%s", bool(list_ok_local), list_reason_local)
            if strict_fast:
                S.logger.info("[FAST LIST GUARD] accepted=%s reason=%s", bool(list_ok_local), list_reason_local)
            if not list_ok_local or (not shaped):
                return False, None
            align = _list_query_alignment_metrics(query, shaped)
            mismatch_penalty = float(align.get("mismatch_penalty", 0.0) or 0.0)
            _inner_mismatch_threshold = 1.5
            route_list_answer = str(answer_type or "").startswith("list_route")
            if mismatch_penalty > _inner_mismatch_threshold and not route_list_answer:
                S.logger.info("[LIST TOKEN MISMATCH] rejected=true penalty=%.3f threshold=%.1f focus_hits=%s context_hits=%s items=%s", mismatch_penalty, _inner_mismatch_threshold, int(align.get("focus_hit_items", 0.0)), int(align.get("context_hit_items", 0.0)), int(align.get("item_count", 0.0)))
                return False, None
            lines = [ln for ln in shaped.splitlines() if re.match(r"^\s*[-•*]\s+", ln)]
            if len(lines) < 2:
                if route_list_answer and len(shaped.splitlines()) >= 2:
                    return True, shaped
                return False, None
            return True, shaped

        if ans is not None and family_v2 == "definition_comparison":
            cleaned_ans = _cleanup_definition_comparison_answer_text(ans or "")
        else:
            cleaned_ans = _cleanup_final_answer_text(ans or "") if ans is not None else ans
        if cleaned_ans is not None and cleaned_ans != RAG_NO_MATCH_RESPONSE:
            cleaned_ans = _decontaminate_faq_answer(query, str(cleaned_ans))
        if (
            cleaned_ans is not None
            and cleaned_ans != RAG_NO_MATCH_RESPONSE
            and _is_evidence_fragment_answer(query, str(cleaned_ans))
            and str(answer_type or "") != "support_procedural_rescue"
        ):
            procedural_rescue = _rescue_support_procedural_from_docs(query, routed_docs or doc_dicts or [])
            if procedural_rescue:
                cleaned_ans = procedural_rescue
                answer_type = "support_procedural_rescue"
                answer_source_mode = "support_kb"
            elif _query_needs_explanatory_answer(query):
                cleaned_ans = RAG_NO_MATCH_RESPONSE
                used_llm = True
                answer_type = "evidence_fragment_rejected"
                answer_source_mode = "not_found_guard"
        if ans is not None and family_v2 in {"fact_entity", "attribute_lookup"}:
            cleaned_ans = _normalize_validated_fact_answer(fact_type, str(cleaned_ans or ""))
        if ans is not None and _is_targeted_list_question(query):
            shaped = _sanitize_list_answer_text(query, str(cleaned_ans or ""))
            if shaped:
                cleaned_ans = shaped
        if cleaned_ans is not None and cleaned_ans != RAG_NO_MATCH_RESPONSE:
            list_ok, list_shaped = _is_coherent_list_answer(str(cleaned_ans))
            if not list_ok:
                S.logger.info("[LIST CANDIDATE REJECTED] reason=incoherent answer=%s", str(cleaned_ans)[:220])
                cleaned_ans = RAG_NO_MATCH_RESPONSE
                used_llm = False
                answer_type = "list_incoherent_rejected"
                answer_source_mode = "not_found_guard"
            elif list_shaped and list_shaped != cleaned_ans:
                cleaned_ans = list_shaped
        _cleaned_person_identity_answer = False
        if cleaned_ans is not None and cleaned_ans != RAG_NO_MATCH_RESPONSE and family_v2 == "definition_entity":
            _person_final_query = bool(re.match(r"^who\s+(?:is|was|are|were)\b", re.sub(r"\s+", " ", str(query or "").strip().lower())))
            if _person_final_query:
                _cleaned_low = re.sub(r"\s+", " ", str(cleaned_ans or "").lower())
                _cleaned_identity = bool(
                    re.search(
                        r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
                        r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
                        _cleaned_low,
                    )
                )
                _cleaned_theory = bool(
                    re.search(r"\b\w+['\u2019]s\s+(?:idea|theory|concept|notion|hypothesis|view|belief|principle|doctrine)\b", _cleaned_low)
                    or re.search(r"\b(?:idea|theory|concept|notion|hypothesis|belief|doctrine)\s+that\b", _cleaned_low)
                )
                _cleaned_person_identity_answer = bool(
                    _cleaned_identity
                    and not _cleaned_theory
                    and _is_answer_grounded_in_docs(str(cleaned_ans), routed_docs or doc_dicts or [], query_text=query)
                )
        if cleaned_ans is not None and cleaned_ans != RAG_NO_MATCH_RESPONSE and family_v2 not in {"fact_entity", "attribute_lookup"} and str(answer_type or "") != "support_procedural_rescue" and not str(answer_type or "").startswith("attribute_") and str(answer_type or "") != "definition_structure_recovery" and not str(answer_type or "").startswith("fact_") and str(answer_type or "") != "definition_table_fact" and not _cleaned_person_identity_answer:
            if not _is_definition_answer_valid(str(cleaned_ans)):
                rescued = False
                if family_v2 in {"definition_entity", "definition_comparison"}:
                    support_docs = routed_docs or doc_dicts or []
                    rescue_ans = _extract_definition_comparison_answer(query, support_docs) if family_v2 == "definition_comparison" else None
                    if not rescue_ans:
                        rescue_ans = _extract_best_scored_concept_sentence_from_docs(query, support_docs, max_docs=3)
                    if not rescue_ans:
                        rescue_ans = _extract_simple_definition_sentence(query, support_docs)
                    if not rescue_ans:
                        _ent_has, _ent_v = _extract_entity_from_definition_query(query)
                        _ent_l = re.sub(r"\s+", " ", str(_ent_v or "").strip().lower()) if _ent_has else ""
                        rescue_ans = _extract_evidence_preserving_definition_answer(query, support_docs, _ent_l)
                    if rescue_ans and family_v2 == "definition_comparison":
                        rescue_ans = _cleanup_definition_comparison_answer_text(str(rescue_ans or "")).strip()
                    else:
                        rescue_ans = _cleanup_final_answer_text(str(rescue_ans or "")).strip() if rescue_ans else ""
                    if rescue_ans and family_v2 == "definition_entity":
                        _person_rescue_query = bool(re.match(r"^who\s+(?:is|was|are|were)\b", re.sub(r"\s+", " ", str(query or "").strip().lower())))
                        if _person_rescue_query:
                            _resc_low = re.sub(r"\s+", " ", str(rescue_ans or "").lower())
                            _resc_identity = bool(
                                re.search(
                                    r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
                                    r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
                                    _resc_low,
                                )
                            )
                            _resc_theory = bool(
                                re.search(r"\b\w+['\u2019]s\s+(?:idea|theory|concept|notion|hypothesis|view|belief|principle|doctrine)\b", _resc_low)
                                or re.search(r"\b(?:idea|theory|concept|notion|hypothesis|belief|doctrine)\s+that\b", _resc_low)
                            )
                            if _resc_theory or not _resc_identity:
                                S.logger.info("[DEFINITION VALIDATION RESCUE] rejected reason=person_not_identity answer=%s", str(rescue_ans)[:220])
                                rescue_ans = ""
                    if rescue_ans and family_v2 == "definition_entity" and not _is_definition_answer_valid(str(rescue_ans)):
                        _ent_has, _ent_v = _extract_entity_from_definition_query(query)
                        _ent_l = re.sub(r"\s+", " ", str(_ent_v or "").strip().lower()) if _ent_has else ""
                        rescue_alt = _extract_evidence_preserving_definition_answer(query, support_docs, _ent_l)
                        if rescue_alt:
                            rescue_ans = _cleanup_final_answer_text(str(rescue_alt or "")).strip()
                    if rescue_ans and _is_definition_answer_valid(str(rescue_ans)):
                        S.logger.info("[DEFINITION VALIDATION RESCUE] accepted=true answer=%s", str(rescue_ans)[:220])
                        cleaned_ans = rescue_ans
                        used_llm = False
                        answer_type = "definition_candidate_rescued"
                        answer_source_mode = "definition"
                        rescued = True
                if not rescued:
                    S.logger.info("[DEFINITION CANDIDATE REJECTED] reason=entity_or_grounding_validation_failed answer=%s", str(cleaned_ans)[:220])
                    cleaned_ans = RAG_NO_MATCH_RESPONSE
                    used_llm = False
                    answer_type = "definition_candidate_rejected"
                    answer_source_mode = "not_found_guard"
        if cleaned_ans is not None and cleaned_ans != RAG_NO_MATCH_RESPONSE and family_v2 not in {"fact_entity", "attribute_lookup"} and _is_fragmentary_ocr(str(cleaned_ans)):
            S.logger.info("[FINAL CANDIDATE REJECTED] reason=fragmentary_ocr answer=%s", str(cleaned_ans)[:220])
            cleaned_ans = RAG_NO_MATCH_RESPONSE
            used_llm = False
            answer_type = "fragmentary_ocr_rejected"
            answer_source_mode = "not_found_guard"
        if ans is not None and cleaned_ans != ans:
            S.logger.info("[OCR CLEANUP APPLIED] before=%s | after=%s", str(ans)[:180], str(cleaned_ans)[:180])
        if cleaned_ans == RAG_NO_MATCH_RESPONSE:
            _support_rescue = _rescue_support_procedural_from_docs(
                query, routed_docs or doc_dicts or []
            )
            if _support_rescue:
                cleaned_ans = _support_rescue
                used_llm = False
                answer_type = "support_procedural_rescue"
                answer_source_mode = "support_kb"
        rejected = bool(cleaned_ans == RAG_NO_MATCH_RESPONSE)
        rejection_reason = ""
        if rejected:
            if "rejected" in str(answer_type or ""):
                rejection_reason = str(answer_type)
            elif str(answer_source_mode) == "not_found_guard":
                rejection_reason = "not_found_guard"
        S.logger.info("[FINAL ANSWER SOURCE] source_mode=%s answer_type=%s used_llm=%s", answer_source_mode, answer_type, used_llm)
        S.logger.info(
            "[FINAL DECISION DEBUG] answer_type=%s source_mode=%s used_llm=%s rejected=%s rejection_reason=%s",
            answer_type,
            answer_source_mode,
            used_llm,
            rejected,
            rejection_reason,
        )
        return {
            "intent": intent,
            "query_family": family_v2,
            "answer": cleaned_ans,
            "used_llm": used_llm,
            "answer_type": answer_type,
            "extractor_items_count": items_count,
            "source_mode": answer_source_mode,
            "_list_local_support": dict(list_local_support or {}),
        }

    answer_route = S._resolve_grounded_answer_route(query)
    if family_v2 == "definition_entity":
        answer_route = "definition"
    elif family_v2 == "attribute_lookup":
        answer_route = "attribute"
    elif family_v2 == "fact_entity" and _is_attribute_lookup_query(query):
        answer_route = "attribute"
    S.logger.info(
        "[ANSWER ROUTE] selected=%s family=%s docs=%d",
        answer_route,
        family_v2,
        len(routed_docs or doc_dicts or []),
    )
    route_docs = _hydrate_route_docs(list(routed_docs or doc_dicts or []))
    cmp_entities_early = _compare_entities_from_query(query)
    cmp_all_tokens = _compare_all_class_tokens(query)
    if family_v2 != "definition_comparison" and (len(cmp_entities_early) >= 2 or cmp_all_tokens):
        answer_source_mode = "compare"
        cmp_answer_early = _compare_answer_from_docs(query, route_docs)
        if not cmp_answer_early:
            cmp_answer_early = _extract_overview_chapter_compare_answer(query, route_docs[:5], overview_context)
            if cmp_answer_early:
                S.logger.info("[COMPARE ANSWER] %s", str(cmp_answer_early)[:280])
        if cmp_answer_early:
            return _result(cmp_answer_early, used_llm=False, answer_type="compare_explanation_fallback", items_count=0)

    if answer_route == "attribute":
        attr_answer = _extract_attribute_route_answer(query, route_docs)
        if attr_answer and not _is_evidence_fragment_answer(query, attr_answer) and _is_compact_table_answer(attr_answer) and _is_table_answer_grounded(attr_answer, route_docs):
            S.logger.info("[ANSWER ROUTE] mode=attribute deterministic=true answer=%s", attr_answer[:220])
            return _result(attr_answer, used_llm=False, answer_type="attribute_route_deterministic", items_count=1)
        if attr_answer and not _is_evidence_fragment_answer(query, attr_answer) and _is_compact_table_answer(attr_answer) and not _is_table_header_token(attr_answer):
            S.logger.info("[ANSWER ROUTE] mode=attribute deterministic=true answer=%s", attr_answer[:220])
            return _result(attr_answer, used_llm=False, answer_type="attribute_route_deterministic", items_count=1)
        for table_text in _collect_pipe_table_texts(route_docs):
            collapsed = _collapse_attribute_table_answer(query, table_text, route_docs)
            if collapsed:
                S.logger.info("[ANSWER ROUTE] mode=attribute deterministic=collapsed_table answer=%s", collapsed[:220])
                return _result(collapsed, used_llm=False, answer_type="attribute_route_deterministic", items_count=1)
        S.logger.info("[ANSWER ROUTE] mode=attribute deterministic=false action=llm_required")
        return {
            "intent": intent,
            "query_family": family_v2,
            "answer": "",
            "used_llm": True,
            "answer_type": "attribute_llm_required",
            "extractor_items_count": 0,
            "source_mode": "attribute",
            "_list_local_support": dict(list_local_support or {}),
        }

    if answer_route == "definition":
        if _is_support_procedural_query(query):
            _def_support = _rescue_support_procedural_from_docs(query, route_docs or doc_dicts or [])
            if _def_support and _valid_procedural_rescue_answer(query, _def_support):
                S.logger.info("[SUPPORT PROCEDURAL DEFINITION OVERRIDE] query=%s chars=%s", str(query or "")[:180], len(_def_support))
                return _result(_def_support, used_llm=False, answer_type="support_procedural_rescue", items_count=0)
        if family_v2 == "definition_comparison":
            comparison_route_answer = _extract_definition_comparison_answer(query, route_docs)
            if comparison_route_answer:
                answer_source_mode = "definition"
                S.logger.info("[ANSWER ROUTE] mode=definition_comparison deterministic=true answer=%s", comparison_route_answer[:220])
                return _result(comparison_route_answer, used_llm=False, answer_type="definition_comparison_extractor", items_count=1)
            answer_source_mode = "not_found_guard"
            S.logger.info("[DEFINITION COMPARISON] rejected reason=no_supported_structured_answer")
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="definition_comparison_not_found", items_count=0)

        if _is_person_identity_query(query) and not _has_person_evidence_in_docs(query, route_docs):
            answer_source_mode = "not_found_guard"
            S.logger.info("[PERSON IDENTITY GUARD] early_not_found query=%s", str(query or "")[:160])
            return _result("Not found in the document.", used_llm=False, answer_type="who_identity_not_found_strict", items_count=0)

        route_answer = _extract_definition_route_answer(query, route_docs)
        if route_answer and _is_person_identity_query(query) and not _answer_contains_person_evidence(route_answer, query):
            answer_source_mode = "not_found_guard"
            S.logger.info("[PERSON IDENTITY GUARD] rejected_non_person_answer query=%s", str(query or "")[:160])
            return _result("Not found in the document.", used_llm=False, answer_type="who_identity_not_found_strict", items_count=0)
        if route_answer:
            S.logger.info("[ANSWER ROUTE] mode=definition deterministic=true answer=%s", route_answer[:220])
            _route_person_definition = bool(re.match(r"^who\s+(?:is|was|are|were)\b", re.sub(r"\s+", " ", str(query or "").strip().lower())))
            _route_answer_type = "fact_route_deterministic" if _route_person_definition else "definition_route_deterministic"
            return _result(route_answer, used_llm=False, answer_type=_route_answer_type, items_count=1)

        # MP-C14 — Hard stop on weak LLM fallback for definition_entity.
        # When the deterministic route extractor returns nothing, attempt
        # one final deterministic local-recovery pass (best-scored / simple
        # definition sentence). The candidate is gated by the strict shared
        # validator `_is_valid_definition_sentence`. If validation fails the
        # query short-circuits with RAG_NO_MATCH_RESPONSE (used_llm=False)
        # so the WS layer never streams a provisional weak LLM answer that
        # would later be replaced. Generic — no domain words.
        if family_v2 == "definition_comparison":
            answer_source_mode = "not_found_guard"
            S.logger.info("[DEFINITION COMPARISON] rejected reason=no_supported_structured_answer")
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="definition_comparison_not_found", items_count=0)

        if family_v2 == "definition_entity":
            _has_ent, _ent = _extract_entity_from_definition_query(query)
            _ent_l = re.sub(r"\s+", " ", str(_ent or "").strip().lower()) if _has_ent else ""
            _person_definition_query = bool(re.match(r"^who\s+(?:is|was|are|were)\b", re.sub(r"\s+", " ", str(query or "").strip().lower())))
            _local = _extract_best_scored_concept_sentence_from_docs(query, route_docs, max_docs=3)
            if not _local:
                _local = _extract_simple_definition_sentence(query, route_docs)
            _local = _cleanup_final_answer_text(re.sub(r"\s+", " ", str(_local or "")).strip())
            if _person_definition_query and _local:
                _local_low = re.sub(r"\s+", " ", _local.lower())
                _local_identity = bool(
                    re.search(
                        r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
                        r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
                        _local_low,
                    )
                )
                _local_theory = bool(
                    re.search(r"\b\w+['\u2019]s\s+(?:idea|theory|concept|notion|hypothesis|view|belief|principle|doctrine)\b", _local_low)
                    or re.search(r"\b(?:idea|theory|concept|notion|hypothesis|belief|doctrine)\s+that\b", _local_low)
                )
                if _local_theory or not _local_identity:
                    S.logger.info("[DEFINITION LOCAL RECOVERY] rejected reason=person_not_identity answer=%s", _local[:220])
                    _local = ""
            if (
                _local
                and _is_answer_grounded_in_docs(_local, route_docs, query_text=query)
                and _is_valid_definition_sentence(_local, _ent_l)
            ):
                S.logger.info("[ANSWER ROUTE] mode=definition deterministic=local_recovery answer=%s", _local[:220])
                return _result(_local, used_llm=False, answer_type="definition_local_recovery", items_count=1)

            # MP-C15 — Structure-aware definition recovery. Real documents
            # often define a concept through structure (heading + nearby
            # prose, table label + adjacent paragraph, concept + defining
            # list) rather than a single "X is Y" sentence. Try one
            # deterministic structural pass before short-circuiting to
            # not_found. Pronoun-led sentences are allowed only when their
            # antecedent is the entity heading anchor we located. Generic.
            #
            # Build a wider candidate doc pool (route_docs + full doc_dicts,
            # deduped). The narrowed `route_docs` may not contain the chunk
            # that holds the concept's heading — broaden first.
            def _doc_dedupe_key(_dd: dict) -> str:
                _t = str((_dd or {}).get("page_content") or (_dd or {}).get("text") or "")
                return _t[:160]

            _struct_pool: list[dict] = []
            _struct_seen: set[str] = set()
            for _dd in list(route_docs) + list(doc_dicts or []):
                _k = _doc_dedupe_key(_dd)
                if not _k or _k in _struct_seen:
                    continue
                _struct_seen.add(_k)
                _struct_pool.append(_dd)
            _struct_ans, _struct_dbg = _extract_structure_aware_definition(
                query, _struct_pool, _ent_l
            )

            # Same-source micro-retrieval rescue: trigger when the
            # structural pass has either no anchor at all OR an anchor that
            # yielded zero passing candidates. Generic, bounded
            # (top_k=12, no rerank) and same-source gated so out-of-scope
            # concepts (e.g. "BioChem") still return not_found.
            _need_micro = (not _struct_ans) and (
                not _struct_dbg.get("structure_recovery_mode")
                or len(_struct_dbg.get("candidate_definition_sentences") or []) == 0
            )
            if _need_micro and _ent_l:
                try:
                    _allowed_sources: set[str] = set()
                    for _dd in _struct_pool:
                        _src = str(
                            (_dd or {}).get("source")
                            or ((_dd or {}).get("metadata") or {}).get("source")
                            or ""
                        )
                        if _src:
                            _allowed_sources.add(_src)
                    _micro_kept: list[dict] = []
                    # Try several query phrasings to broaden recall while
                    # staying same-source: the bare entity, the head token,
                    # and an explicit "what is" prefix. Generic.
                    _ent_head = re.split(r"\s+", _ent_l)[0]
                    _queries = [_ent_l]
                    if _ent_head and _ent_head != _ent_l:
                        _queries.append(_ent_head)
                    _queries.append(f"what is {_ent_l}")
                    _micro_total = 0
                    for _q in _queries:
                        try:
                            _batch = S._active_rag().search(
                                query=_q,
                                top_k=12,
                                return_dicts=True,
                                enable_rerank=False,
                            ) or []
                        except Exception:
                            _batch = []
                        _micro_total += len(_batch)
                        for _md in _batch:
                            _src = str(
                                (_md or {}).get("source")
                                or ((_md or {}).get("metadata") or {}).get("source")
                                or ""
                            )
                            if _allowed_sources and _src not in _allowed_sources:
                                continue
                            _k = _doc_dedupe_key(_md)
                            if not _k or _k in _struct_seen:
                                continue
                            _struct_seen.add(_k)
                            _micro_kept.append(_md)
                    S.logger.info(
                        "[STRUCT-AWARE DEF] micro_retrieval entity=%s fetched=%d kept_same_source=%d",
                        _ent_l, _micro_total, len(_micro_kept),
                    )
                    if _micro_kept:
                        _struct_pool = _struct_pool + _micro_kept
                        _struct_ans, _struct_dbg = _extract_structure_aware_definition(
                            query, _struct_pool, _ent_l
                        )
                except Exception as _exc:
                    S.logger.info("[STRUCT-AWARE DEF] micro_retrieval error=%s", str(_exc)[:160])

            # Final corpus-wide structural fallback. The retrieval pipeline
            # caps results at ~3 chunks per query through its quality
            # filter, so heading-anchored chunks (e.g. an "Elements of X:"
            # block in another part of the same document) often never
            # reach the structure-aware helper above. Scan the entire
            # active vector-store collection for chunks containing the
            # entity stem, gated by the same allowed-source set so
            # out-of-document concepts (BioChem) still return not_found.
            _need_corpus = (not _struct_ans) and (
                not _struct_dbg.get("structure_recovery_mode")
                or len(_struct_dbg.get("candidate_definition_sentences") or []) == 0
                and len(_struct_dbg.get("candidate_definition_list_items") or []) < 3
            )
            if _need_corpus and _ent_l:
                try:
                    _allowed_sources_c: set[str] = set()
                    for _dd in _struct_pool:
                        _src = str(
                            (_dd or {}).get("source")
                            or ((_dd or {}).get("metadata") or {}).get("source")
                            or ""
                        )
                        if _src:
                            _allowed_sources_c.add(_src)
                    _corpus_hits = _mpc15_corpus_filter_by_entity(
                        _ent_l, allowed_sources=_allowed_sources_c or None, limit=10
                    )
                    _added = 0
                    for _ch in _corpus_hits:
                        _k = _doc_dedupe_key(_ch)
                        if not _k or _k in _struct_seen:
                            continue
                        _struct_seen.add(_k)
                        _struct_pool.append(_ch)
                        _added += 1
                    S.logger.info(
                        "[STRUCT-AWARE DEF] corpus_fallback entity=%s scanned_hits=%d added=%d",
                        _ent_l, len(_corpus_hits), _added,
                    )
                    if _added:
                        _struct_ans, _struct_dbg = _extract_structure_aware_definition(
                            query, _struct_pool, _ent_l
                        )
                except Exception as _exc:
                    S.logger.info("[STRUCT-AWARE DEF] corpus_fallback error=%s", str(_exc)[:160])

            S.logger.info(
                "[STRUCT-AWARE DEF] entity=%s mode=%s anchor=%s window=%s candidates=%d list_items=%d reason=%s",
                _ent_l,
                _struct_dbg.get("structure_recovery_mode"),
                str(_struct_dbg.get("anchor_preview") or "")[:120],
                str(_struct_dbg.get("focused_window_preview") or "")[:160],
                len(_struct_dbg.get("candidate_definition_sentences") or []),
                len(_struct_dbg.get("candidate_definition_list_items") or []),
                _struct_dbg.get("final_recovery_reason"),
            )
            for _i, _cand in enumerate((_struct_dbg.get("candidate_definition_sentences") or [])[:5]):
                S.logger.info("[STRUCT-AWARE DEF] cand[%d]=%s", _i, str(_cand)[:200])
            for _i, _li in enumerate((_struct_dbg.get("candidate_definition_list_items") or [])[:5]):
                S.logger.info("[STRUCT-AWARE DEF] list_item[%d]=%s", _i, str(_li)[:140])
            _struct_grounded = bool(_struct_ans) and _is_answer_grounded_in_docs(_struct_ans, _struct_pool, query_text=query)
            if _person_definition_query and _struct_ans:
                _struct_low = re.sub(r"\s+", " ", str(_struct_ans or "").lower())
                _struct_identity = bool(
                    re.search(
                        r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
                        r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
                        _struct_low,
                    )
                )
                _struct_theory = bool(
                    re.search(r"\b\w+['\u2019]s\s+(?:idea|theory|concept|notion|hypothesis|view|belief|principle|doctrine)\b", _struct_low)
                    or re.search(r"\b(?:idea|theory|concept|notion|hypothesis|belief|doctrine)\s+that\b", _struct_low)
                )
                if _struct_theory or not _struct_identity:
                    S.logger.info("[STRUCT-AWARE DEF] rejected reason=person_not_identity answer=%s", str(_struct_ans)[:220])
                    _struct_grounded = False
            S.logger.info("[STRUCT-AWARE DEF] returned_answer=%s grounded=%s pool_size=%d",
                        str(_struct_ans or "")[:200], _struct_grounded, len(_struct_pool))
            if _struct_ans and _struct_grounded:
                S.logger.info(
                    "[ANSWER ROUTE] mode=definition deterministic=structure_recovery answer=%s",
                    _struct_ans[:220],
                )
                return _result(_struct_ans, used_llm=False, answer_type="definition_structure_recovery", items_count=1)

            _evidence_synthesis = _extract_evidence_preserving_definition_answer(
                query, _struct_pool or route_docs or doc_dicts, _ent_l
            )
            if _person_definition_query and _evidence_synthesis:
                _ev_low = re.sub(r"\s+", " ", str(_evidence_synthesis or "").lower())
                _ev_identity = bool(
                    re.search(
                        r"\b(?:known\s+as|regarded\s+as|considered|founder|father|pioneer|creator|originator|"
                        r"born|was\s+an?|is\s+an?|served\s+as|physician|psychologist|psychiatrist|neurologist)\b",
                        _ev_low,
                    )
                )
                _ev_theory = bool(
                    re.search(r"\b\w+['\u2019]s\s+(?:idea|theory|concept|notion|hypothesis|view|belief|principle|doctrine)\b", _ev_low)
                    or re.search(r"\b(?:idea|theory|concept|notion|hypothesis|belief|doctrine)\s+that\b", _ev_low)
                )
                if _ev_theory or not _ev_identity:
                    S.logger.info("[DEFINITION EVIDENCE SYNTHESIS] rejected reason=person_not_identity answer=%s", str(_evidence_synthesis)[:220])
                    _evidence_synthesis = ""
            if _evidence_synthesis:
                S.logger.info(
                    "[ANSWER ROUTE] mode=definition deterministic=evidence_synthesis answer=%s",
                    _evidence_synthesis[:220],
                )
                return _result(_evidence_synthesis, used_llm=False, answer_type="definition_structure_recovery", items_count=1)

            _table_fact = _extract_table_fact_answer(query, doc_dicts)
            if _table_fact:
                S.logger.info(
                    "[ANSWER ROUTE] mode=definition deterministic=table_fact answer=%s",
                    _table_fact[:220],
                )
                return _result(_table_fact, used_llm=False, answer_type="definition_table_fact", items_count=1)

            S.logger.info(
                "[ANSWER ROUTE] mode=definition deterministic=false action=not_found_strict entity=%s preview=%s",
                _ent_l,
                (_local or "")[:160],
            )
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="definition_not_found_strict", items_count=0)

        S.logger.info("[ANSWER ROUTE] mode=definition deterministic=false action=llm_required")
        return {
            "intent": intent,
            "query_family": family_v2,
            "answer": "",
            "used_llm": True,
            "answer_type": "definition_llm_required",
            "extractor_items_count": 0,
            "source_mode": "definition",
            "_list_local_support": dict(list_local_support or {}),
        }

    if answer_route == "list":
        answer_source_mode = "list"
        # MP-C6: extend the locality "single_local_window_text" with anchored
        # subsection slices from any retrieved chunk whose body contains a
        # heading or caption matching the query focus tokens. Without this,
        # the section pre-shortlist may keep one off-topic chunk while the
        # answer-bearing chunk's window is excluded, causing the downstream
        # locality guard to falsely reject correct items as out-of-window.
        # Generic — uses only the structural anchor scorer + slicer.
        if isinstance(list_local_support, dict):
            _existing_window = str(list_local_support.get("single_local_window_text") or "")
            _extra_pieces: list[str] = []
            for _d in (doc_dicts or []):
                _txt = str((_d or {}).get("page_content") or (_d or {}).get("text") or "")
                if not _txt:
                    continue
                _sliced = _slice_chunk_to_query_subsection(_txt, query)
                # Only include chunks whose body actually slices to a
                # query-anchored subsection (i.e. the slicer found and applied
                # an inline heading / caption matching the query focus). This
                # avoids appending entire off-topic chunks merely because they
                # share a common token with the query.
                if not _sliced or _sliced == _txt:
                    continue
                if _sliced not in _existing_window:
                    _extra_pieces.append(_sliced)
            if _extra_pieces:
                _combined_parts = [p for p in [_existing_window] + _extra_pieces if p]
                list_local_support["single_local_window_text"] = "\n\n".join(_combined_parts)[:16000]
                if not list_local_support.get("validation_scope"):
                    list_local_support["validation_scope"] = "single_local_window"
        # MP-C6: when an anchored route chunk contains an enumeration heading
        # but only one enumeration letter (e.g. only "A.") inside the sliced
        # subsection, the remaining items are likely in adjacent chunks (the
        # PDF chunker split a long enumeration across page boundaries). Fetch
        # sibling chunks by chunk_index ±N from the underlying vector store,
        # slice each to the query subsection, and append any non-empty slices
        # to both the locality window and the route's extra_docs. Generic —
        # uses only chunk_index adjacency + the same query-anchored slicer.
        try:
            _augmented_doc_dicts = list(doc_dicts or [])
            _seen_aug_chunks: set[int] = set()
            for _d in _augmented_doc_dicts:
                _ci_seen = _safe_int(dict((_d or {}).get("metadata") or {}).get("chunk_index"))
                if _ci_seen is not None:
                    _seen_aug_chunks.add(int(_ci_seen))
            _enum_letter_re = re.compile(r"(?:^|[\s\n])([A-J])\.\s+[A-Z][a-zA-Z]+")
            _merged_super_pieces: list[str] = []
            _merged_route_meta: dict | None = None

            # MP-C7 helper: try to synthesize a deterministic A./B./C. answer
            # from a single chunk's anchored subsection slice. Returns the
            # final answer dict if it succeeds, else None. Pure structural —
            # uses only enumeration letter adjacency.
            def _mpc7_try_direct_enum_from_chunk(_d: dict, _origin: str):
                _md = dict((_d or {}).get("metadata") or {})
                _txt = str((_d or {}).get("page_content") or (_d or {}).get("text") or "")
                if not _txt:
                    return None
                _sliced = _slice_chunk_to_query_subsection(_txt, query)
                if not _sliced or _sliced == _txt:
                    return None
                _letters = {m.group(1).upper() for m in _enum_letter_re.finditer(_sliced)}
                if not ("A" in _letters and "B" in _letters and "C" in _letters):
                    return None
                _slice_norm_loc = re.sub(
                    r"(?<!\n)\s*(?=[A-J]\.\s+[A-Z][a-zA-Z])",
                    "\n",
                    _sliced,
                )
                _enum_line_re_local = re.compile(
                    r"(?:^|\n)\s*([A-J])\.\s+([^\n]{4,300})"
                )
                _pairs_local: list[tuple[str, str]] = []
                _seen_letters_local: set[str] = set()
                for _m in _enum_line_re_local.finditer(_slice_norm_loc):
                    _let = _m.group(1).upper()
                    if _let in _seen_letters_local:
                        continue
                    _seen_letters_local.add(_let)
                    _txt_item = re.sub(r"\s+", " ", _m.group(2)).strip()
                    _txt_item = re.split(
                        r"(?<=[.:])\s+(?=[A-Z])|\.\s|:\s",
                        _txt_item,
                        maxsplit=1,
                    )[0].strip(" .:;,")
                    if _txt_item:
                        _pairs_local.append((_let, _txt_item))
                if not (len(_pairs_local) >= 3 and _pairs_local[0][0] == "A"):
                    return None
                _expected_l = "A"
                _items_l: list[str] = []
                for _let, _txt_item in _pairs_local:
                    if _let != _expected_l:
                        break
                    # Drop the letter label from the item text so downstream
                    # sanitize/coherence sees the actual subject as the first
                    # word (enabling the parallel-subject exemption for
                    # "Subject is/are Predicate" enumerations). The letter
                    # itself is purely a structural marker and adds no
                    # informational content. Generic — applies regardless of
                    # the document's labeling convention.
                    _items_l.append(f"- {_txt_item}")
                    _expected_l = chr(ord(_expected_l) + 1)
                if len(_items_l) < 3:
                    return None
                _direct_answer_loc = "\n".join(_items_l)
                if isinstance(list_local_support, dict):
                    _cur_w_loc = str(list_local_support.get("single_local_window_text") or "")
                    if _slice_norm_loc not in _cur_w_loc:
                        list_local_support["single_local_window_text"] = (
                            "\n\n".join([p for p in [_cur_w_loc, _slice_norm_loc] if p])[:24000]
                        )
                        if not list_local_support.get("validation_scope"):
                            list_local_support["validation_scope"] = "single_local_window"
                S.logger.info(
                    "[MP-C7 DIRECT ENUM %s] chunk=%s items=%d answer=%s",
                    _origin, _md.get("chunk_index"), len(_items_l),
                    _direct_answer_loc.replace("\n", " | ")[:300],
                )
                return _result(
                    _direct_answer_loc,
                    used_llm=False,
                    answer_type="list_route_deterministic",
                    items_count=len(_items_l),
                )

            # MP-C7: first try the route docs (highest priority), then fall
            # back to extra docs. The answer-bearing chunk with the labeled
            # A./B./C. enumeration may not always be the route's top pick
            # (the section ranker may select a TOC/index chunk instead).
            for _route_d in (route_docs or []):
                _direct_route_result = _mpc7_try_direct_enum_from_chunk(_route_d, "ROUTE-SLICE")
                if _direct_route_result is not None:
                    return _direct_route_result
            for _extra_d in (doc_dicts or []):
                # Skip docs already tried as route_docs (same source+chunk_index).
                _emd = dict((_extra_d or {}).get("metadata") or {})
                _key = (str(_emd.get("source") or ""), _emd.get("chunk_index"))
                if any(
                    (str(dict((_rd or {}).get("metadata") or {}).get("source") or ""),
                     dict((_rd or {}).get("metadata") or {}).get("chunk_index")) == _key
                    for _rd in (route_docs or [])
                ):
                    continue
                _direct_extra_result = _mpc7_try_direct_enum_from_chunk(_extra_d, "EXTRA-SLICE")
                if _direct_extra_result is not None:
                    return _direct_extra_result

            for _route_d in (route_docs or []):
                _route_md = dict((_route_d or {}).get("metadata") or {})
                _route_src = str(_route_md.get("source") or "")
                _route_ci = _safe_int(_route_md.get("chunk_index"))
                if _route_ci is None or not _route_src:
                    continue
                _route_txt = str((_route_d or {}).get("page_content") or (_route_d or {}).get("text") or "")
                _route_sliced = _slice_chunk_to_query_subsection(_route_txt, query)
                if not _route_sliced or _route_sliced == _route_txt:
                    continue
                _letters_in_slice = {m.group(1).upper() for m in _enum_letter_re.finditer(_route_sliced)}
                # Trigger sibling fetch when the enumeration starts at A but
                # the immediate successor letter (B) is absent in the slice —
                # this signals a truncated enumeration whose continuation is
                # in adjacent chunks. Generic — relies on enumeration letter
                # adjacency only.
                if not ("A" in _letters_in_slice and "B" not in _letters_in_slice):
                    continue
                # Seed the merged super-doc with the route's anchored slice.
                if not _merged_super_pieces:
                    _merged_super_pieces.append(_route_sliced)
                    _merged_route_meta = dict(_route_md)
                # Walk forward only (since enumeration starts at A and is
                # truncated after A in the route slice, continuation letters
                # B, C, D, ... live in chunks with higher chunk_index). Each
                # accepted sibling must contain at least one letter that
                # extends the contiguous A,B,C,... sequence; siblings that
                # only contain letters already covered or letters that skip
                # the next-needed letter are rejected (they belong to a
                # different enumeration). Generic — uses sequential letter
                # adjacency only.
                _expected_next = "B"
                for _offset in range(1, 8):
                    _sib_idx = int(_route_ci) + _offset
                    if _sib_idx in _seen_aug_chunks:
                        continue
                    _sib_tuple = _fetch_adjacent_doc_from_store(_route_src, _sib_idx)
                    if _sib_tuple is None:
                        break
                    _sib_doc = _sib_tuple[1] if isinstance(_sib_tuple, tuple) and len(_sib_tuple) >= 2 else None
                    _sib_txt = str(((_sib_doc or {}).get("page_content") or (_sib_doc or {}).get("text") or ""))
                    if not _sib_txt:
                        break
                    _sib_sliced = _slice_chunk_to_query_subsection(_sib_txt, query)
                    _candidate_text = _sib_sliced if (_sib_sliced and _sib_sliced != _sib_txt) else _sib_txt
                    _sib_letters = {m.group(1).upper() for m in _enum_letter_re.finditer(_candidate_text)}
                    # Sibling must contain the next-expected letter; otherwise
                    # it's an unrelated section.
                    if _expected_next not in _sib_letters:
                        break
                    _seen_aug_chunks.add(_sib_idx)
                    _new_doc = {
                        "page_content": _candidate_text,
                        "text": _candidate_text,
                        "content": _candidate_text,
                        "metadata": dict((_sib_doc or {}).get("metadata") or {}),
                    }
                    _augmented_doc_dicts.append(_new_doc)
                    _merged_super_pieces.append(_candidate_text)
                    # Also extend the locality window so the downstream
                    # locality guard accepts items from sibling chunks.
                    if isinstance(list_local_support, dict):
                        _cur_window = str(list_local_support.get("single_local_window_text") or "")
                        if _candidate_text not in _cur_window:
                            _new_window = "\n\n".join([p for p in [_cur_window, _candidate_text] if p])
                            list_local_support["single_local_window_text"] = _new_window[:16000]
                            if not list_local_support.get("validation_scope"):
                                list_local_support["validation_scope"] = "single_local_window"
                    S.logger.info(
                        "[MP-C6 SIBLING FETCH] route_chunk=%s sibling_chunk=%s letters=%s expected=%s",
                        _route_ci, _sib_idx, sorted(_sib_letters), _expected_next,
                    )
                    # Advance expected_next to the highest contiguous letter.
                    while _expected_next in _sib_letters and _expected_next < "Z":
                        _expected_next = chr(ord(_expected_next) + 1)
            # Build a single merged super-doc combining the route slice with
            # all sibling slices and prepend it so the per-chunk anchored
            # extractor sees the full enumeration in one pass (avoids picking
            # up the truncated route slice that yields a single garbage item).
            if len(_merged_super_pieces) >= 2:
                _merged_text = "\n".join(_merged_super_pieces)[:16000]
                # Normalise inline enumeration markers ("A. Foo: ...", "B. Bar:")
                # into one-per-line form so the downstream list extractor can
                # detect them as separate list items. Generic — only inserts a
                # newline before letter-period-space enumeration markers.
                _merged_text = re.sub(
                    r"(?<!\n)\s*(?=[A-J]\.\s+[A-Z][a-zA-Z])",
                    "\n",
                    _merged_text,
                )
                _super_meta = dict(_merged_route_meta or {})
                # Use a unique synthetic chunk_index so the downstream
                # de-duplication in _extract_list_route_answer (which keys on
                # source + chunk_index) does NOT discard this merged doc as a
                # duplicate of the original route chunk.
                _super_meta["chunk_index"] = f"mpc6_merged_{_super_meta.get('chunk_index', 'x')}"
                _super_doc = {
                    "page_content": _merged_text,
                    "text": _merged_text,
                    "content": _merged_text,
                    "metadata": _super_meta,
                }
                _augmented_doc_dicts.insert(0, _super_doc)
                # Add the normalised merged text to the locality window so the
                # downstream locality guard accepts items extracted from it.
                if isinstance(list_local_support, dict):
                    _cur_window = str(list_local_support.get("single_local_window_text") or "")
                    if _merged_text not in _cur_window:
                        _new_window = "\n\n".join([p for p in [_cur_window, _merged_text] if p])
                        list_local_support["single_local_window_text"] = _new_window[:24000]
                        if not list_local_support.get("validation_scope"):
                            list_local_support["validation_scope"] = "single_local_window"
                S.logger.info(
                    "[MP-C6 SIBLING FETCH] merged_super_doc pieces=%d total_len=%d",
                    len(_merged_super_pieces), len(_merged_text),
                )
                # Direct deterministic enumeration: when the merged text contains
                # a clean A/B/C/... sequence (≥3 contiguous letters starting at A),
                # synthesize the list answer directly from the enumeration lines
                # rather than relying on the noun-phrase explode extractor (which
                # often mangles single-paragraph slices into garbage tokens).
                _enum_line_re = re.compile(
                    r"(?:^|\n)\s*([A-J])\.\s+([^\n]{4,200})"
                )
                _enum_pairs: list[tuple[str, str]] = []
                _seen_letters_for_enum: set[str] = set()
                for _m in _enum_line_re.finditer(_merged_text):
                    _let = _m.group(1).upper()
                    if _let in _seen_letters_for_enum:
                        continue
                    _seen_letters_for_enum.add(_let)
                    _txt = re.sub(r"\s+", " ", _m.group(2)).strip()
                    # Trim at sentence end / paragraph break to keep one-line items.
                    _txt = re.split(r"(?<=[.:])\s+(?=[A-Z])|\.\s|:\s", _txt, maxsplit=1)[0].strip(" .:;,")
                    if _txt:
                        _enum_pairs.append((_let, _txt))
                # Require ≥3 items starting at A with contiguous letters.
                if len(_enum_pairs) >= 3 and _enum_pairs[0][0] == "A":
                    _expected = "A"
                    _contig: list[str] = []
                    for _let, _txt in _enum_pairs:
                        if _let != _expected:
                            break
                        _contig.append(f"- {_let}. {_txt}")
                        _expected = chr(ord(_expected) + 1)
                    if len(_contig) >= 3:
                        _direct_answer = "\n".join(_contig)
                        S.logger.info(
                            "[MP-C6 DIRECT ENUM] items=%d answer=%s",
                            len(_contig), _direct_answer.replace("\n", " | ")[:300],
                        )
                        return _result(
                            _direct_answer,
                            used_llm=False,
                            answer_type="list_route_deterministic",
                            items_count=len(_contig),
                        )
            doc_dicts = _augmented_doc_dicts
        except Exception as _sib_exc:
            S.logger.info("[MP-C6 SIBLING FETCH] error=%s", _sib_exc)
        try:
            _route_chunk_ids = [dict((d or {}).get("metadata") or {}).get("chunk_index") for d in (route_docs or [])]
            _extra_chunk_ids = [dict((d or {}).get("metadata") or {}).get("chunk_index") for d in (doc_dicts or [])]
            S.logger.info("[MP-C6 ROUTE] route_docs=%s extra_docs=%s", _route_chunk_ids, _extra_chunk_ids)
        except Exception:
            pass
        route_answer = _extract_list_route_answer(query, route_docs, context_text=list_context, extra_docs=doc_dicts)
        if route_answer:
            route_ok, route_reason, route_shaped = _assess_list_coherence(
                query,
                _preclean_list_answer_for_assessment(route_answer),
                strict_fast=True,
                local_support=list_local_support,
            )
            S.logger.info("[ANSWER ROUTE LIST GUARD] accepted=%s reason=%s", bool(route_ok), route_reason)
            if route_ok and route_shaped:
                S.logger.info("[ANSWER ROUTE] mode=list deterministic=true answer=%s", route_shaped[:220])
                return _result(route_shaped, used_llm=False, answer_type="list_route_deterministic", items_count=len([ln for ln in str(route_shaped).splitlines() if ln.strip()]))
            S.logger.info("[ANSWER ROUTE] mode=list deterministic_rejected reason=%s", route_reason)

        lexical_route_answer, lexical_route_count, lexical_route_doc, lexical_route_support, lexical_route_reason = S._extract_symbolic_list_lexical_rescue_answer(query, route_docs or doc_dicts or [])
        if lexical_route_answer and lexical_route_doc is not None:
            routed_docs = [lexical_route_doc]
            route_docs = [lexical_route_doc]
            list_context = str((lexical_route_doc or {}).get("page_content") or (lexical_route_doc or {}).get("text") or "")
            list_local_support = dict(lexical_route_support or {})
            list_section_confident = True
            list_debug_selected_chunks = [dict((lexical_route_doc or {}).get("metadata") or {}).get("chunk_index")]
            list_debug_section_confidences = [round(float((lexical_route_support or {}).get("confidence", 0.0) or 0.0), 3)]
            S.logger.info("[LIST WINNER] mode=lexical_rescue_route items=%s", lexical_route_count)
            return _result(lexical_route_answer, used_llm=False, answer_type="list_lexical_rescue", items_count=lexical_route_count)
        if lexical_route_reason and lexical_route_reason != "not_symbolic_list_query":
            S.logger.info("[ANSWER ROUTE] mode=list lexical_rescue=false reason=%s", lexical_route_reason)
        S.logger.info("[ANSWER ROUTE] mode=list deterministic=false action=llm_required")
        return {
            "intent": intent,
            "query_family": family_v2,
            "answer": "",
            "used_llm": True,
            "answer_type": "list_llm_required",
            "extractor_items_count": 0,
            "source_mode": "list",
            "_list_local_support": dict(list_local_support or {}),
        }

    if answer_route == "fact":
        if _is_support_procedural_query(query):
            support_early = _rescue_support_procedural_from_docs(routed_docs or doc_dicts or [])
            if support_early:
                S.logger.info("[ANSWER ROUTE] mode=fact support_procedural_override chars=%s", len(support_early))
                return _result(support_early, used_llm=False, answer_type="support_procedural_rescue", items_count=0)
        if _is_metric_fact_query(query):
            metric_docs = list(doc_dicts or route_docs or [])
            metric_answer = _extract_metric_fact_answer(query, metric_docs)
            if not metric_answer:
                metric_answer_retry = _extract_metric_fact_answer(query, list(doc_dicts or [])[:25])
                if metric_answer_retry:
                    metric_answer = metric_answer_retry
            if metric_docs and not metric_answer:
                anchored = _select_fact_anchor_docs(
                    query,
                    metric_docs,
                    top_k=min(8, len(metric_docs)),
                    scan_limit=min(25, len(metric_docs)),
                )
                metric_answer = _extract_metric_fact_answer(query, anchored) or metric_answer
            if llm_text is None:
                if metric_answer:
                    S.logger.info("[ANSWER ROUTE] mode=fact metric_symbolic answer=%s", metric_answer[:220])
                    return _result(metric_answer, used_llm=False, answer_type="fact_metric_symbolic", items_count=1)
                S.logger.info("[ANSWER ROUTE] mode=fact deterministic=skipped reason=metric_compound_query action=llm_required")
                return {
                    "intent": intent,
                    "query_family": family_v2,
                    "answer": "",
                    "used_llm": True,
                    "answer_type": "fact_metric_llm_required",
                    "extractor_items_count": 0,
                    "source_mode": "fact",
                    "_list_local_support": dict(list_local_support or {}),
                }
            llm_candidate = re.sub(r"\s+", " ", str(llm_text or "")).strip()
            if llm_candidate and len(llm_candidate) > 12 and _is_answer_grounded_in_docs(llm_candidate, metric_docs, query_text=query):
                S.logger.info("[ANSWER ROUTE] mode=fact metric_llm answer=%s", llm_candidate[:220])
                return _result(llm_candidate, used_llm=True, answer_type="fact_metric_llm", items_count=1)
            if metric_answer:
                S.logger.info("[ANSWER ROUTE] mode=fact metric_symbolic_fallback answer=%s", metric_answer[:220])
                return _result(metric_answer, used_llm=False, answer_type="fact_metric_symbolic_fallback", items_count=1)
            S.logger.info("[ANSWER ROUTE] mode=fact metric_not_found")
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="fact_metric_not_found", items_count=0)
        route_answer = _extract_fact_route_answer(query, route_docs)
        if route_answer:
            S.logger.info("[ANSWER ROUTE] mode=fact deterministic=true answer=%s", route_answer[:220])
            return _result(route_answer, used_llm=False, answer_type="fact_route_deterministic", items_count=1)
        S.logger.info("[ANSWER ROUTE] mode=fact deterministic=false action=llm_required")
        return {
            "intent": intent,
            "query_family": family_v2,
            "answer": "",
            "used_llm": True,
            "answer_type": "fact_llm_required",
            "extractor_items_count": 0,
            "source_mode": "fact",
            "_list_local_support": dict(list_local_support or {}),
        }

    # Comparison/numeric questions (e.g. "net sales for Americas in 2023
    # compared to 2022") are poorly served by the deterministic sentence
    # extractor, which tends to emit a table heading fragment. Defer them to
    # the LLM so it can read the retrieved table context and compute the
    # comparison instead.
    if S._doc_router_implies_comparison(query):
        S.logger.info("[ANSWER ROUTE] mode=generic deterministic=skipped reason=comparison_query action=llm_required")
        return {
            "intent": intent,
            "query_family": family_v2,
            "answer": "",
            "used_llm": True,
            "answer_type": "generic_llm_required",
            "extractor_items_count": 0,
            "source_mode": "generic",
            "_list_local_support": dict(list_local_support or {}),
        }
    generic_route_answer = _build_grounded_llm_answer(query, route_docs)
    if generic_route_answer and _is_evidence_fragment_answer(query, generic_route_answer):
        rescued_generic = _rescue_support_procedural_from_docs(query, route_docs)
        if rescued_generic:
            generic_route_answer = rescued_generic
        else:
            generic_route_answer = ""
    if generic_route_answer:
        if not _should_allow_generic_answer(query, route_docs, family_v2, "generic_route_grounded"):
            S.logger.info("[ANSWER BLOCKED] reason=low_confidence_generic")
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="generic_low_confidence_blocked", items_count=0)
        S.logger.info("[ANSWER ROUTE] mode=generic deterministic=true answer=%s", generic_route_answer[:220])
        return _result(generic_route_answer, used_llm=False, answer_type="generic_route_grounded", items_count=1)
    S.logger.info("[ANSWER ROUTE] mode=generic deterministic=false action=llm_required")
    return {
        "intent": intent,
        "query_family": family_v2,
        "answer": "",
        "used_llm": True,
        "answer_type": "generic_llm_required",
        "extractor_items_count": 0,
        "source_mode": "generic",
        "_list_local_support": dict(list_local_support or {}),
    }

    if family_v2 == "fact_entity":
        answer_source_mode = "fact"
        fact_docs = list(routed_docs or doc_dicts or [])
        if fact_docs:
            fact_docs = _select_fact_anchor_docs(
                query,
                fact_docs,
                top_k=min(5, len(fact_docs)),
                scan_limit=min(20, len(fact_docs)),
            )
        if _is_metric_fact_query(query):
            metric_answer = _extract_metric_fact_answer(query, fact_docs)
            if llm_text is None:
                if metric_answer:
                    S.logger.info("[FACT METRIC] action=symbolic_pre_llm answer=%s", metric_answer[:220])
                    return _result(metric_answer, used_llm=False, answer_type="fact_metric_symbolic", items_count=1)
                return _result(None, used_llm=True, answer_type="fact_metric_llm_required", items_count=0)
            llm_candidate = re.sub(r"\s+", " ", str(llm_text or "")).strip()
            if llm_candidate and len(llm_candidate) > 12 and _is_answer_grounded_in_docs(llm_candidate, fact_docs, query_text=query):
                S.logger.info("[FACT METRIC] action=accept_llm answer=%s", llm_candidate[:220])
                return _result(llm_candidate, used_llm=True, answer_type="fact_metric_llm", items_count=1)
            if metric_answer:
                S.logger.info("[FACT METRIC] action=symbolic_fallback answer=%s", metric_answer[:220])
                return _result(metric_answer, used_llm=False, answer_type="fact_metric_symbolic_fallback", items_count=1)
            S.logger.info("[FACT METRIC] action=not_found")
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="fact_metric_not_found", items_count=0)

        fact_context_mode = _infer_fact_context_mode_from_docs(fact_docs)
        compact_fact_docs = _build_compact_fact_context_docs(query, fact_docs, max_snippets=FACT_CONTEXT_MAX_SNIPPETS, max_chars=FACT_CONTEXT_MAX_CHARS)
        fact_context_limit = len(compact_fact_docs) if compact_fact_docs else (8 if fact_context_mode == "multi_chunk" else 5)
        fact_context_chunks = [
            str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "")
            for d in (compact_fact_docs or fact_docs)[:fact_context_limit]
            if str((d or {}).get("page_content") or (d or {}).get("text") or (d or {}).get("content") or "").strip()
        ]
        S.logger.info("[FACT CONTEXT] final_snippets=%s final_chars=%s mode=%s", len(fact_context_chunks), sum(len(c) for c in fact_context_chunks), fact_context_mode)

        # #region agent log
        try:
            _joined = " ".join(fact_context_chunks).lower()
            S._dbg7d3bbb("assistify_rag_server.py:_shared_rag_final_answer_decision.fact", "fact context built", {
                "fact_type": fact_type,
                "n_chunks": len(fact_context_chunks),
                "llm_text_present": llm_text is not None,
                "has_currency": bool(_EVIDENCE_VALUE_PATTERNS["currency"].search(_joined)),
                "has_percent": bool(_EVIDENCE_VALUE_PATTERNS["percent"].search(_joined)),
                "has_ratio": bool(_EVIDENCE_VALUE_PATTERNS["ratio"].search(_joined)),
                "chunk_previews": [c[:220] for c in fact_context_chunks[:3]],
            }, "H-D1")
        except Exception:
            pass
        # #endregion

        if not fact_context_chunks:
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="fact_not_found_no_context", items_count=0)

        context_fact_candidate = _extract_fact_from_context(query, fact_context_chunks)

        if llm_text is None:
            S.logger.info("[FACT ROUTE] context_present=true action=strict_grounded_llm")
            return _result(None, used_llm=True, answer_type="fact_strict_llm_required", items_count=0)

        llm_candidate = re.sub(r"\s+", " ", str(llm_text or "")).strip()
        if not llm_candidate:
            S.logger.info("[FACT FALLBACK] llm_empty action=not_found")
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="fact_not_found_after_llm", items_count=0)

        normalized_fact = _normalize_validated_fact_answer(fact_type, llm_candidate)
        context_fact_normalized = _normalize_validated_fact_answer(fact_type, context_fact_candidate or "")
        if (
            fact_type == "when"
            and fact_context_mode == "multi_chunk"
            and normalized_fact != RAG_NO_MATCH_RESPONSE
            and context_fact_normalized != RAG_NO_MATCH_RESPONSE
            and context_fact_normalized != normalized_fact
            and re.search(r"\b(?:emerg|origin|began|started|first|establish|founded)\b", str(query or "").lower())
            and _is_answer_grounded_in_docs(context_fact_normalized, fact_docs, query_text=query)
        ):
            S.logger.info(
                "[FACT MULTI-CHUNK FALLBACK] action=prefer_context_year llm=%s context=%s",
                normalized_fact,
                context_fact_normalized,
            )
            normalized_fact = context_fact_normalized

        if normalized_fact == RAG_NO_MATCH_RESPONSE:
            if (
                context_fact_normalized != RAG_NO_MATCH_RESPONSE
                and _is_answer_grounded_in_docs(context_fact_normalized, fact_docs, query_text=query)
            ):
                S.logger.info(
                    "[FACT MULTI-CHUNK FALLBACK] action=accept_context_candidate type=%s candidate=%s",
                    fact_type,
                    context_fact_normalized,
                )
                S.logger.info("[FACT ACCEPTED] value=%s", context_fact_normalized)
                return _result(
                    context_fact_normalized,
                    used_llm=False,
                    answer_type=f"fact_{fact_type or 'generic'}_context_fallback",
                    items_count=1,
                )
            expanded_fact_docs = _build_compact_fact_context_docs(query, fact_docs, max_snippets=6, max_chars=2200)
            expanded_chunks = [
                str((d or {}).get("page_content") or (d or {}).get("text") or "")
                for d in (expanded_fact_docs or [])
                if str((d or {}).get("page_content") or (d or {}).get("text") or "").strip()
            ]
            if expanded_chunks:
                expanded_candidate = _extract_fact_from_context(query, expanded_chunks)
                expanded_norm = _normalize_validated_fact_answer(fact_type, expanded_candidate or "")
                if expanded_norm != RAG_NO_MATCH_RESPONSE and _is_answer_grounded_in_docs(expanded_norm, fact_docs, query_text=query):
                    S.logger.info("[FACT FALLBACK] action=accept_expanded_context candidate=%s", expanded_norm)
                    S.logger.info("[FACT ACCEPTED] value=%s", expanded_norm)
                    return _result(expanded_norm, used_llm=False, answer_type=f"fact_{fact_type or 'generic'}_expanded_context", items_count=1)
            if fact_type == "who":
                stitched = _extract_multichunk_who_candidate(query, fact_docs)
                stitched_norm = _normalize_validated_fact_answer(fact_type, stitched or "")
                if stitched_norm != RAG_NO_MATCH_RESPONSE and _is_answer_grounded_in_docs(stitched_norm, fact_docs, query_text=query):
                    S.logger.info("[FACT MULTI-CHUNK FALLBACK] action=accept_stitched_who candidate=%s", stitched_norm)
                    S.logger.info("[FACT ACCEPTED] value=%s", stitched_norm)
                    return _result(stitched_norm, used_llm=False, answer_type="fact_who_multichunk_stitched", items_count=1)
            S.logger.info("[FACT FALLBACK] llm_format_invalid type=%s action=not_found", fact_type)
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="fact_not_found_invalid_type", items_count=0)

        # #region agent log
        try:
            _grounded_dbg = _is_answer_grounded_in_docs(normalized_fact, routed_docs or doc_dicts or [], query_text=query)
            S._dbg7d3bbb("assistify_rag_server.py:_shared_rag_final_answer_decision.fact", "fact llm grounding", {
                "fact_type": fact_type,
                "llm_candidate": str(llm_candidate or "")[:200],
                "normalized_fact": str(normalized_fact or "")[:200],
                "context_fact_candidate": str(context_fact_candidate or "")[:200],
                "context_fact_normalized": str(context_fact_normalized or "")[:200],
                "grounded": bool(_grounded_dbg),
            }, "H-D3")
        except Exception:
            pass
        # #endregion
        if not _is_answer_grounded_in_docs(normalized_fact, routed_docs or doc_dicts or [], query_text=query):
            S.logger.info("[FACT FALLBACK] llm_grounded=false action=not_found")
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="fact_not_found_ungrounded", items_count=0)

        S.logger.info("[FACT FALLBACK] llm_grounded=true action=accept_llm")
        S.logger.info("[FACT ACCEPTED] value=%s", normalized_fact)
        return _result(normalized_fact, used_llm=True, answer_type=f"fact_{fact_type or 'generic'}_llm_grounded", items_count=1)

    if family == "out_of_domain_or_format_mismatch":
        S.logger.info("[FORMAT MISMATCH GUARD] family=%s query=%s", family, (query or "")[:120])
        answer_source_mode = "not_found_guard"
        return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="format_or_domain_mismatch_guard", items_count=0)

    family = {
        "list_entity": "list_structure",
        "explanatory_compare": "overview_chapter_compare",
        "out_of_domain_or_format_mismatch": "out_of_scope_candidate",
        "toc_structure": "overview_chapter_compare",
        
        "sequence_lookup": "overview_chapter_compare",
    }.get(family_v2, family_v2)

    cmp_left, cmp_right = _compare_terms_from_query(query)
    if cmp_left and cmp_right:
        answer_source_mode = "compare"
        cmp_answer = _compare_answer_from_docs(query, routed_docs or doc_dicts or [])
        if not cmp_answer:
            cmp_answer = _extract_overview_chapter_compare_answer(query, (routed_docs or doc_dicts or [])[:5], overview_context)
            if cmp_answer:
                S.logger.info("[COMPARE ANSWER] %s", str(cmp_answer)[:280])
        if cmp_answer:
            return _result(cmp_answer, used_llm=False, answer_type="compare_explanation_fallback", items_count=0)

    def _extract_primary_simple_answer_from_top_docs(query_text: str, docs: List[Dict[str, Any]], family_name: str) -> Optional[str]:
        if not docs:
            return None
        if family_name in {"list_entity", "overview_chapter_compare", "explanatory_compare", "fact_entity"}:
            return None

        ql = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
        stop = {"what", "is", "are", "the", "a", "an", "of", "in", "to", "for", "and", "or", "define", "explain", "who", "was", "compare"}
        key_terms = [t for t in re.findall(r"[a-z0-9]{3,}", ql) if t not in stop]
        query_keywords = key_terms or [t for t in re.findall(r"[a-z0-9]{3,}", ql)]
        is_definition_like = bool(re.match(r"^(what\s+is|define|who\s+is|who\s+was)\b", ql))

        def _clean_candidate_sentence(raw: str) -> str:
            s = _clean_definition_like_sentence(raw)
            if not s:
                return ""
            ocr_no_join_heads = {
                "for", "and", "the", "with", "from", "that", "this", "into", "over", "under",
                "when", "then", "than", "while", "where", "which", "who", "whom", "whose", "because",
            }

            def _join_ocr_split(m: re.Match) -> str:
                h = str(m.group(1) or "")
                mid = str(m.group(2) or "")
                tail = str(m.group(3) or "")
                if h.lower() in ocr_no_join_heads:
                    return f"{h} {mid} {tail}"
                return f"{h}{mid} {tail}"

            s = re.sub(r"\b([a-z]{2,})\s+([a-z])\s+([a-z]{2,})\b", _join_ocr_split, s, flags=re.IGNORECASE)
            s = re.sub(r"\b(is)\s+(it)\b", r"\1", s, flags=re.IGNORECASE)
            s = re.sub(r"\b(\w+)\s+\1\b", r"\1", s, flags=re.IGNORECASE)
            s = re.sub(r"\s+", " ", s).strip()
            s = re.sub(r"\b(?:and|or|but|because|which|that|who|whom|whose|where|when|while|with|of|to|for|in|on|by|as|than|if)\s*$", "", s, flags=re.IGNORECASE).strip()
            return s

        def _score_sentence(sent: str) -> tuple[int, int, bool, bool, bool]:
            low = sent.lower()
            words = re.findall(r"[a-z0-9]+", low)
            word_count = len(words)
            has_def_marker = bool(re.search(r"\b(?:is|refers\s+to|defined\s+as|means)\b", low))
            has_query_keyword = bool(query_keywords and any(re.search(rf"\b{re.escape(t)}\b", low) for t in query_keywords))
            starts_pronoun = bool(re.match(r"^\s*(?:it|this|they|he|she)\b", low))
            too_short = word_count < 6
            looks_overview_start = bool(re.match(r"^\s*(?:three\s+main|how\s+do\s+we\s+learn|basic\s+terminology|historical\s+background|introduction|overview|summary|contents?|table\s+of\s+contents|key\s+terms?)\b", low))
            list_like_without_definition = bool((":" in sent or ";" in sent or "•" in sent or "|" in sent or len(re.findall(r",", sent)) >= 2) and (not has_def_marker))
            complete_sentence = bool(re.search(r"[.!?]$", sent.strip()))
            score = 0
            if has_def_marker:
                score += 2
            if has_query_keyword:
                score += 2
            if starts_pronoun:
                score -= 2
            if too_short:
                score -= 2
            if looks_overview_start:
                score -= 8
            if list_like_without_definition:
                score -= 8
            if complete_sentence:
                score += 1
            else:
                score -= 2
            return score, word_count, has_def_marker, has_query_keyword, starts_pronoun

        best_sent = None
        best_score = -10**9
        best_meta = None
        has_ent, ent = _extract_entity_from_definition_query(query_text)
        ent_l = re.sub(r"\s+", " ", str(ent or "").strip().lower()) if has_ent else ""
        entity_tokens = [t for t in re.findall(r"[a-z0-9]{2,}", ent_l) if t not in {"the", "a", "an", "of", "and", "in", "to"}]
        bad_markers = re.compile(r"\b(procedure|experiment|known as|founded|founder|criticism|table of contents|learning objectives|chapter\s+\d+)\b", re.IGNORECASE)

        def _reject_definition_list_overview_sentence(sent: str) -> bool:
            s = re.sub(r"\s+", " ", str(sent or "")).strip()
            if not s:
                return True
            sl = s.lower()
            if re.match(r"^\s*(?:three\s+main|how\s+do\s+we\s+learn|basic\s+terminology|historical\s+background|introduction|overview|summary|contents?|table\s+of\s+contents|key\s+terms?)\b", sl):
                return True
            if re.match(r"^\s*[A-Z][A-Za-z0-9\s\-,:]{3,110}\s*$", s) and not re.search(r"[.!?]$", s):
                return True
            has_def_verb = bool(re.search(r"\b(is|refers to|defined as|means|involves|includes|consists of|characterized by|forms an association|associates)\b", sl))
            list_like = bool((":" in s or ";" in s or "•" in s or "|" in s or len(re.findall(r",", s)) >= 2))
            if list_like and not has_def_verb:
                return True
            if ent_l:
                has_entity_phrase = bool(re.search(rf"\b{re.escape(ent_l)}\b", sl))
                token_hits = sum(1 for t in entity_tokens if re.search(rf"\b{re.escape(t)}\b", sl))
                if token_hits >= 2 and (not has_entity_phrase) and (not has_def_verb):
                    return True
            return False

        for d in (docs or [])[:2]:
            txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
            if not txt:
                continue
            sentences = [s.strip() for s in re.split(r"(?<=[.!?])\s+|\n+", txt) if (s or "").strip()]
            for sent in sentences:
                if len(sent) > 320:
                    continue
                low = sent.lower()
                if re.search(r"\b(table of contents|contents|figure|fig\.?|caption|copyright)\b", low):
                    continue
                if bad_markers.search(sent):
                    continue
                if family_name == "definition_entity" and _reject_definition_list_overview_sentence(sent):
                    continue

                if family_name == "definition_entity" and ent_l:
                    has_entity_phrase = bool(re.search(rf"\b{re.escape(ent_l)}\b", low))
                    has_entity_tokens = bool(entity_tokens) and all(re.search(rf"\b{re.escape(t)}\b", low) for t in entity_tokens[:2])
                    if not (has_entity_phrase or has_entity_tokens):
                        continue

                score, word_count, has_def_marker, has_query_keyword, starts_pronoun = _score_sentence(sent)
                if is_definition_like and (not has_def_marker):
                    score -= 1

                if score > best_score:
                    best_score = score
                    best_sent = _clean_candidate_sentence(sent)
                    best_meta = {
                        "words": word_count,
                        "has_def": has_def_marker,
                        "has_kw": has_query_keyword,
                        "starts_pronoun": starts_pronoun,
                        "raw": sent,
                    }

        if not best_sent:
            return None
        if best_score < 1:
            S.logger.info("[PRIMARY SIMPLE SCORE] no_good_sentence score=%s sentence=%s", best_score, ((best_meta or {}).get("raw", ""))[:200])
            return None

        if family_name == "definition_entity" and (not _passes_strict_definition_relevance_guard(query_text, best_sent)):
            S.logger.info("[PRIMARY SIMPLE SCORE] rejected_by_strict_guard score=%s sentence=%s", best_score, best_sent[:200])
            return None

        S.logger.info(
            "[PRIMARY SIMPLE SCORE] selected score=%s words=%s has_def=%s has_kw=%s starts_pronoun=%s sentence=%s",
            best_score,
            (best_meta or {}).get("words", 0),
            (best_meta or {}).get("has_def", False),
            (best_meta or {}).get("has_kw", False),
            (best_meta or {}).get("starts_pronoun", False),
            best_sent[:220],
        )
        return best_sent

    simple_top_answer = _extract_primary_simple_answer_from_top_docs(query, routed_docs or doc_dicts or [], family_v2)
    if simple_top_answer and family_v2 == "definition_entity":
        strict_definition_from_docs = _extract_best_scored_concept_sentence_from_docs(query, routed_docs or doc_dicts or [], max_docs=3)
        if strict_definition_from_docs and _passes_strict_definition_relevance_guard(query, strict_definition_from_docs):
            S.logger.info("[DEFINITION WINNER] mode=strict_scored_over_primary answer=%s", str(strict_definition_from_docs)[:220])
            return _result(strict_definition_from_docs, used_llm=False, answer_type="definition_fast_rescue_scored", items_count=0)
        if not _passes_strict_definition_relevance_guard(query, simple_top_answer):
            S.logger.info("[PRIMARY SIMPLE SCORE] rejected_for_definition_priority sentence=%s", str(simple_top_answer)[:200])
            simple_top_answer = None
    if simple_top_answer:
        S.logger.info("[PRIMARY SIMPLE ANSWER] from_top_docs=true answer=%s", str(simple_top_answer)[:220])
        return _result(simple_top_answer, used_llm=False, answer_type="primary_simple_top_chunks", items_count=1)

    def _specific_concept_not_found_rescue(query_text: str, docs: List[Dict[str, Any]]) -> str | None:
        return None

    q_low = re.sub(r"\s+", " ", str(query or "").strip().lower())
    is_who_identity_query = bool(re.match(r"^who\s+(is|was)\b", q_low))
    is_who_attribution_query = q_low.startswith("who introduced") or q_low.startswith("who developed")

    if family == "definition_entity" and is_who_identity_query and (not is_who_attribution_query):
        if not _has_exact_who_person_evidence(query, routed_docs or doc_dicts or []):
            answer_source_mode = "not_found_guard"
            return _result("Not found in the document.", used_llm=False, answer_type="who_identity_not_found_strict", items_count=0)

    if family == "definition_entity":
        answer_source_mode = "definition"
        q_low_def = re.sub(r"\s+", " ", str(query or "").strip().lower())
        merged_def_ctx = "\n".join(str((d or {}).get("page_content") or (d or {}).get("text") or "") for d in (routed_docs or doc_dicts or [])[:5])

        indirect_doc = None
        for d in (routed_docs or doc_dicts or []):
            md_local = dict((d or {}).get("metadata") or {})
            if bool(md_local.get("_indirect_definition_mode")):
                indirect_doc = d
                break
        if indirect_doc is not None:
            md_indirect = dict((indirect_doc or {}).get("metadata") or {})
            evidence_lines = [
                re.sub(r"\s+", " ", str(s or "").strip())
                for s in (md_indirect.get("_indirect_evidence") or [])
                if str(s or "").strip()
            ]
            if evidence_lines:
                has_ent_local, ent_local = _extract_entity_from_definition_query(query)
                ent_local_l = re.sub(r"\s+", " ", str(ent_local or "").strip().lower()) if has_ent_local else ""
                intro_entity = ent_local_l if ent_local_l else str(md_indirect.get("_indirect_entity") or "").strip().lower()
                if not intro_entity:
                    intro_entity = "the concept"
                ranked_candidates = [
                    (float(max(0.0, 2.0 - (idx * 0.2))), _is_table_or_classification_sentence(s), s)
                    for idx, s in enumerate(evidence_lines)
                ]
                concise_evidence = _choose_top_complementary_indirect_sentences(intro_entity, ranked_candidates, max_pick=2)
                if not concise_evidence:
                    concise_evidence = evidence_lines[:1]
                for sent in concise_evidence:
                    S.logger.info("[INDIRECT WINNER] sentence=%s", sent[:220])
                answer_text, concise_evidence = _build_indirect_definition_answer(intro_entity, concise_evidence)
                if not answer_text:
                    answer_text = concise_evidence[0] if concise_evidence else "Not found in the document."
                S.logger.info("[INDIRECT ANSWER] built_from=%d_sentences", len(concise_evidence))
                S.logger.info("[DEFINITION WINNER] mode=indirect evidence=%s", answer_text[:220])
                return _result(answer_text, used_llm=False, answer_type="definition_indirect_evidence", items_count=len(concise_evidence))

        fast_def = _extract_simple_definition_sentence(query, routed_docs or doc_dicts or [])
        if fast_def:
            fast_def = _refine_concept_definition_answer(query, routed_docs or doc_dicts or [], fast_def)
            if fast_def and re.search(r"\b(course\s+will|main\s+focus|students\s+will|help\s+students|areas\s+of\s+study)\b", fast_def, flags=re.IGNORECASE):
                fast_def = None
            ql_local = re.sub(r"\s+", " ", str(query or "").strip().lower())
            if ql_local.startswith("what is") or ql_local.startswith("define"):
                has_ent_local, ent_local = _extract_entity_from_definition_query(query)
                ent_local_l = re.sub(r"\s+", " ", str(ent_local or "").strip().lower())
                ent_local_tokens = [
                    t for t in re.findall(r"[a-z0-9]{2,}", ent_local_l)
                    if t not in {"the", "a", "an", "of", "and", "in", "to"}
                ]
                if has_ent_local and _s_definition_sentence(fast_def, ent_local_l, ent_local_tokens) <= 0:
                    alt_def = _extract_candidate_definition_sentence_from_docs(query, routed_docs or doc_dicts or [], max_docs=3)
                    if alt_def and _s_definition_sentence(alt_def, ent_local_l, ent_local_tokens) > 0:
                        fast_def = alt_def
                    else:
                        fast_def = None
            if not fast_def:
                ql_local = re.sub(r"\s+", " ", str(query or "").strip().lower())
                if ql_local.startswith("what is") or ql_local.startswith("define"):
                    rescue_def = _extract_best_scored_concept_sentence_from_docs(query, routed_docs or doc_dicts or [], max_docs=3)
                    if rescue_def:
                        fast_def = rescue_def
            if fast_def and re.search(r"\b(course\s+will|main\s+focus|students\s+will|help\s+students|areas\s+of\s+study)\b", fast_def, flags=re.IGNORECASE):
                fast_def = None
            if not fast_def:
                fallback_def = _definition_explanation_fallback(query, routed_docs or doc_dicts or [], _extract_entity_from_definition_query(query)[1])
                if fallback_def and _passes_strict_definition_relevance_guard(query, fallback_def):
                    return _result(fallback_def, used_llm=False, answer_type="definition_explanation_fallback", items_count=0)
                answer_source_mode = "not_found_guard"
                return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="definition_not_found_simple", items_count=0)
            has_ent_local, ent_local = _extract_entity_from_definition_query(query)
            ent_local_l = re.sub(r"\s+", " ", str(ent_local or "").strip().lower()) if has_ent_local else ""
            if ent_local_l:
                fast_def_low = re.sub(r"\s+", " ", str(fast_def or "").strip().lower())
                ent_tokens = [t for t in re.findall(r"[a-z0-9]{2,}", ent_local_l) if t not in {"the", "a", "an", "of", "and", "in", "to"}]
                token_hits = sum(1 for tok in ent_tokens if re.search(rf"\b{re.escape(tok)}\b", fast_def_low))
                if token_hits < max(1, min(2, len(ent_tokens))):
                    fallback_def = _definition_explanation_fallback(query, routed_docs or doc_dicts or [], ent_local_l)
                    if fallback_def:
                        return _result(fallback_def, used_llm=False, answer_type="definition_explanation_fallback", items_count=0)
            if not _passes_strict_definition_relevance_guard(query, fast_def):
                fallback_def = _definition_explanation_fallback(query, routed_docs or doc_dicts or [], _extract_entity_from_definition_query(query)[1])
                if fallback_def:
                    return _result(fallback_def, used_llm=False, answer_type="definition_explanation_fallback", items_count=0)
                answer_source_mode = "not_found_guard"
                return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="definition_not_found_strict_relevance", items_count=0)
            if is_who_identity_query and (not is_who_attribution_query):
                fast_def = _enrich_who_identity_answer(query, routed_docs or doc_dicts or [], fast_def)
            S.logger.info("[DEFINITION WINNER] mode=fast answer=%s", str(fast_def)[:220])
            return _result(fast_def, used_llm=False, answer_type="definition_fast_simple", items_count=0)

    if family_v2 == "list_entity" or family == "list_structure":
        answer_source_mode = "list"
        S.logger.info("[LIST EXTRACTION MODE] family=%s query=%s", family_v2, (query or "")[:120])
        if not list_section_confident:
            list_debug_blocked_reason = "weak section evidence"
        S.logger.info("[LIST DEBUG] query=%s", (query or "")[:220])
        S.logger.info("[LIST DEBUG] selected_chunks=%s", list_debug_selected_chunks)
        S.logger.info("[LIST DEBUG] section_confidences=%s", list_debug_section_confidences)
        S.logger.info("[LIST DEBUG] deterministic_allowed=%s", bool(list_section_confident))
        S.logger.info("[LIST DEBUG] blocked_reason=%s", list_debug_blocked_reason or "")
        S.logger.info("[LIST DEBUG] fallback_to_llm=%s", bool(not list_section_confident))
        q_list_local = re.sub(r"\s+", " ", str(query or "").strip().lower())
        structure_query_mode = _is_structure_query(query)
        if structure_query_mode:
            S.logger.info("[STRUCTURE QUERY DETECTED] query=%s", (query or "")[:160])

        def _try_structure_query_rescue() -> tuple[str | None, int]:
            if not structure_query_mode:
                return None, 0
            cluster_answer = _extract_structure_concept_cluster_from_docs(query, routed_docs or doc_dicts or [], max_docs=4)
            if not cluster_answer:
                return None, 0
            rescue_ok, rescue_reason, rescue_shaped = _assess_list_coherence(
                query,
                _preclean_list_answer_for_assessment(cluster_answer),
                strict_fast=False,
                local_support=list_local_support,
            )
            rescue_count = len([ln for ln in str(rescue_shaped or "").splitlines() if ln.strip()])
            S.logger.info("[STRUCTURE QUERY RESCUE] accepted=%s reason=%s items=%d", bool(rescue_ok), rescue_reason, rescue_count)
            if rescue_ok and rescue_shaped and rescue_count >= 2:
                return rescue_shaped, rescue_count
            return None, 0

        def _try_symbolic_list_lexical_rescue() -> tuple[str | None, int, dict | None, dict[str, Any]]:
            rescue_answer, rescue_count, rescued_doc, rescue_support, _rescue_reason = S._extract_symbolic_list_lexical_rescue_answer(query, routed_docs or doc_dicts or [])
            return rescue_answer, rescue_count, rescued_doc, rescue_support

        if q_list_local.startswith("what are ") and (not structure_query_mode) and (not _is_targeted_list_question(q_list_local)):
            plural_term = re.sub(r"^what are\s+", "", q_list_local).strip(" .?")
            plural_sentence, _plural_md = _best_term_explanation_from_docs(plural_term, routed_docs or doc_dicts or [])
            if plural_sentence:
                S.logger.info("[DEF FALLBACK MODE] activated entity=%s", plural_term)
                S.logger.info("[DEF FALLBACK ANSWER] %s", plural_sentence[:260])
                return _result(plural_sentence, used_llm=False, answer_type="definition_plural_explanation", items_count=0)
        extraction_blocks = 3 if list_section_confident else 4
        deterministic_list = _extract_list_from_context(query, list_context, max_candidate_blocks=extraction_blocks)
        if deterministic_list:
            det_ok, det_reason, det_shaped = _assess_list_coherence(query, _preclean_list_answer_for_assessment(deterministic_list), strict_fast=list_section_confident, local_support=list_local_support)
            S.logger.info("[LIST COHERENCE DEBUG] accepted=%s reason=%s", bool(det_ok), det_reason)
            S.logger.info("[FAST LIST GUARD] accepted=%s reason=%s", bool(det_ok), det_reason)
            if det_ok and det_shaped:
                S.logger.info("[LIST WINNER] mode=deterministic_context items=%s", len([ln for ln in det_shaped.splitlines() if ln.strip()]))
                return _result(det_shaped, used_llm=False, answer_type="list_deterministic_context", items_count=len([ln for ln in det_shaped.splitlines() if ln.strip()]))
            S.logger.info("[LIST REJECTED] reason=%s", det_reason)
            single_doc_best: str | None = None
            single_doc_count = 0
            for d_single in (routed_docs or doc_dicts or [])[:4]:
                single_ctx = str((d_single or {}).get("page_content") or (d_single or {}).get("text") or "")
                if not single_ctx.strip():
                    continue
                single_list = _extract_list_from_context(query, single_ctx, max_candidate_blocks=2)
                if not single_list:
                    continue
                single_ok, single_reason, single_shaped = _assess_list_coherence(query, _preclean_list_answer_for_assessment(single_list), strict_fast=False, local_support=_collect_local_window_support([d_single]))
                S.logger.info("[LIST SINGLE DOC DEBUG] accepted=%s reason=%s", bool(single_ok), single_reason)
                if not (single_ok and single_shaped):
                    continue
                item_count = len([ln for ln in single_shaped.splitlines() if ln.strip()])
                if item_count > single_doc_count:
                    single_doc_best = single_shaped
                    single_doc_count = item_count
            if single_doc_best and single_doc_count >= 2:
                S.logger.info("[LIST WINNER] mode=deterministic_single_doc items=%s", single_doc_count)
                return _result(single_doc_best, used_llm=False, answer_type="list_deterministic_context", items_count=single_doc_count)
        lexical_rescue_answer, lexical_rescue_count, lexical_rescue_doc, lexical_rescue_support = _try_symbolic_list_lexical_rescue()
        if lexical_rescue_answer and lexical_rescue_doc is not None:
            routed_docs = [lexical_rescue_doc]
            list_context = str((lexical_rescue_doc or {}).get("page_content") or (lexical_rescue_doc or {}).get("text") or "")
            list_local_support = dict(lexical_rescue_support or {})
            list_section_confident = True
            list_debug_selected_chunks = [dict((lexical_rescue_doc or {}).get("metadata") or {}).get("chunk_index")]
            list_debug_section_confidences = [round(float((lexical_rescue_support or {}).get("confidence", 0.0) or 0.0), 3)]
            S.logger.info("[LIST WINNER] mode=lexical_rescue items=%s", lexical_rescue_count)
            return _result(lexical_rescue_answer, used_llm=False, answer_type="list_lexical_rescue", items_count=lexical_rescue_count)
        structure_rescue_answer, structure_rescue_count = _try_structure_query_rescue()
        if structure_rescue_answer:
            S.logger.info("[LIST WINNER] mode=structure_query_rescue items=%s", structure_rescue_count)
            return _result(structure_rescue_answer, used_llm=False, answer_type="list_structure_rescue", items_count=structure_rescue_count)
        if not list_section_confident and answer_route != "list":
            S.logger.info("[LIST REJECTED] reason=weak_section_signal")
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="list_not_found", items_count=0)
        prefer_deterministic_list = bool(
            re.search(r"\bprinciples?\b", q_list_local)
            or "tell me about" in q_list_local
            or q_list_local.startswith("what are")
        )
        fast_list = None if prefer_deterministic_list else _extract_simple_list_from_docs(routed_docs or doc_dicts or [], query_text=query)
        if fast_list:
            fast_ok, fast_reason, fast_shaped = _assess_list_coherence(
                query,
                _preclean_list_answer_for_assessment(fast_list),
                strict_fast=True,
                local_support=list_local_support,
            )
            fast_items = [ln for ln in str(fast_shaped or "").splitlines() if ln.strip()]
            has_non_empty_items = len(fast_items) >= 2
            has_local_window = bool(len(list_debug_selected_chunks) >= 1)
            if list_section_confident and has_local_window and fast_ok and has_non_empty_items and fast_shaped:
                S.logger.info("[LIST WINNER] mode=fallback_fast_list_guarded items=%s", len(fast_items))
                return _result(fast_shaped, used_llm=False, answer_type="list_fast_simple", items_count=len(fast_items))
            structure_rescue_answer, structure_rescue_count = _try_structure_query_rescue()
            if structure_rescue_answer:
                S.logger.info("[LIST WINNER] mode=structure_query_rescue items=%s", structure_rescue_count)
                return _result(structure_rescue_answer, used_llm=False, answer_type="list_structure_rescue", items_count=structure_rescue_count)
            S.logger.info("[LIST REJECTED] reason=fallback_list_path_blocked coherence_reason=%s items=%s local_window=%s", fast_reason, len(fast_items), has_local_window)
            return _result(RAG_NO_MATCH_RESPONSE, used_llm=False, answer_type="list_not_found", items_count=0)

    if family == "explanatory_compare":
        q_over = re.sub(r"\s+", " ", str(query or "").strip().lower())
        topic_pure = _extract_topic_pure_overview_from_docs(query, routed_docs or doc_dicts or [])
        if topic_pure:
            return _result(topic_pure, used_llm=False, answer_type="overview_topic_pure", items_count=0)
        if not _is_force_overview_paragraph_query(query):
            fast_overview = _extract_simple_overview_from_docs(routed_docs or doc_dicts or [])
            if fast_overview:
                return _result(fast_overview, used_llm=False, answer_type="overview_fast_simple", items_count=0)

    items = extract_list_items(list_context) if family == "list_entity" else []

    weak_retrieval = _is_weak_retrieval_evidence(query, family, doc_dicts)
    allow_structured_attempt = bool(routed_docs or doc_dicts) and family in {"definition_entity", "definition_comparison", "list_entity", "explanatory_compare"}
    if weak_retrieval and not allow_structured_attempt:
        return {
            "intent": intent,
            "query_family": family,
            "answer": RAG_NO_MATCH_RESPONSE,
            "used_llm": False,
            "answer_type": "out_of_scope_gate_blocked",
            "extractor_items_count": len(items),
        }

    if llm_text is None:
        if family == "definition_entity":
            fast_def = _extract_simple_definition_sentence(query, doc_dicts or [])
            if fast_def:
                fast_def = _refine_concept_definition_answer(query, doc_dicts or [], fast_def)
                ql_local = re.sub(r"\s+", " ", str(query or "").strip().lower())
                if ql_local.startswith("what is") or ql_local.startswith("define"):
                    has_ent_local, ent_local = _extract_entity_from_definition_query(query)
                    ent_local_l = re.sub(r"\s+", " ", str(ent_local or "").strip().lower())
                    ent_local_tokens = [
                        t for t in re.findall(r"[a-z0-9]{2,}", ent_local_l)
                        if t not in {"the", "a", "an", "of", "and", "in", "to"}
                    ]
                    if has_ent_local and _s_definition_sentence(fast_def, ent_local_l, ent_local_tokens) <= 0:
                        alt_def = _extract_candidate_definition_sentence_from_docs(query, doc_dicts or [], max_docs=3)
                        if alt_def and _s_definition_sentence(alt_def, ent_local_l, ent_local_tokens) > 0:
                            fast_def = alt_def
                        else:
                            fast_def = None
                if not fast_def:
                    ql_local = re.sub(r"\s+", " ", str(query or "").strip().lower())
                    if ql_local.startswith("what is") or ql_local.startswith("define"):
                        rescue_def = _extract_best_scored_concept_sentence_from_docs(query, doc_dicts or [], max_docs=3)
                        if rescue_def:
                            fast_def = rescue_def
                if not fast_def:
                    rescue_specific = _specific_concept_not_found_rescue(query, doc_dicts or [])
                    if rescue_specific:
                        return {
                            "intent": intent,
                            "query_family": family,
                            "answer": rescue_specific,
                            "used_llm": False,
                            "answer_type": "definition_specific_concept_rescue",
                            "extractor_items_count": 0,
                        }
                    fallback_def = _definition_explanation_fallback(query, doc_dicts or [], _extract_entity_from_definition_query(query)[1])
                    if fallback_def:
                        return {
                            "intent": intent,
                            "query_family": family,
                            "answer": fallback_def,
                            "used_llm": False,
                            "answer_type": "definition_explanation_fallback",
                            "extractor_items_count": 0,
                        }
                    S.logger.info("[DEF REJECT WEAK] query=%s reason=no_strong_definition_sentence", query)
                    return {
                        "intent": intent,
                        "query_family": family,
                        "answer": RAG_NO_MATCH_RESPONSE,
                        "used_llm": False,
                        "answer_type": "definition_not_found_simple",
                        "extractor_items_count": 0,
                    }
                if not _passes_strict_definition_relevance_guard(query, fast_def):
                    fallback_def = _definition_explanation_fallback(query, doc_dicts or [], _extract_entity_from_definition_query(query)[1])
                    if fallback_def:
                        return {
                            "intent": intent,
                            "query_family": family,
                            "answer": fallback_def,
                            "used_llm": False,
                            "answer_type": "definition_explanation_fallback",
                            "extractor_items_count": 0,
                        }
                    return {
                        "intent": intent,
                        "query_family": family,
                        "answer": RAG_NO_MATCH_RESPONSE,
                        "used_llm": False,
                        "answer_type": "definition_not_found_strict_relevance",
                        "extractor_items_count": 0,
                    }
                if is_who_identity_query and (not is_who_attribution_query):
                    fast_def = _enrich_who_identity_answer(query, doc_dicts or [], fast_def)
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": fast_def,
                    "used_llm": False,
                    "answer_type": "definition_fast_simple",
                    "extractor_items_count": 0,
                }
            ql_local = re.sub(r"\s+", " ", str(query or "").strip().lower())
            if ql_local.startswith("what is") or ql_local.startswith("define"):
                rescue_def = _extract_best_scored_concept_sentence_from_docs(query, doc_dicts or [], max_docs=3)
                if rescue_def:
                    return {
                        "intent": intent,
                        "query_family": family,
                        "answer": rescue_def,
                        "used_llm": False,
                        "answer_type": "definition_fast_rescue_scored",
                        "extractor_items_count": 0,
                    }
                rescue_specific = _specific_concept_not_found_rescue(query, doc_dicts or [])
                if rescue_specific:
                    return {
                        "intent": intent,
                        "query_family": family,
                        "answer": rescue_specific,
                        "used_llm": False,
                        "answer_type": "definition_specific_concept_rescue",
                        "extractor_items_count": 0,
                    }
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "definition_not_found_simple",
                "extractor_items_count": 0,
            }

        if family == "list_structure":
            if not list_section_confident:
                S.logger.info("[LIST REJECTED] reason=weak_section_signal")
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": RAG_NO_MATCH_RESPONSE,
                    "used_llm": False,
                    "answer_type": "list_not_found",
                    "extractor_items_count": len(items),
                }
            deterministic_list = _extract_list_from_context(query, list_context, max_candidate_blocks=2)
            if deterministic_list:
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": deterministic_list,
                    "used_llm": False,
                    "answer_type": "list_extractor",
                    "extractor_items_count": len(items),
                }
            if len(items) >= 2:
                answer = "\n".join(f"- {item}" for item in items)
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": answer,
                    "used_llm": False,
                    "answer_type": "list_extractor",
                    "extractor_items_count": len(items),
                }
            if str(list_context or "").strip():
                S.logger.info("[LIST REJECTED] reason=extractor_failed")
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": RAG_NO_MATCH_RESPONSE,
                    "used_llm": False,
                    "answer_type": "list_not_found",
                    "extractor_items_count": len(items),
                }
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "list_not_found",
                "extractor_items_count": len(items),
            }

        if family == "definition_entity":
            definition_mode = _definition_mode_from_query(query)
            raw_text = definition_context
            definition_sentence = _extract_definition_sentence(
                raw_text,
                query=query,
                mode=definition_mode,
            )
            if definition_sentence:
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": " ".join([p.strip() for p in re.split(r"(?<=[.!?])\s+", definition_sentence) if p.strip()][:2]),
                    "used_llm": False,
                    "answer_type": "definition_extractor",
                    "extractor_items_count": 0,
                }
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "definition_not_found",
                "extractor_items_count": 0,
            }

        if family == "overview_chapter_compare":
            overview_answer = _extract_overview_chapter_compare_answer(query, (doc_dicts or [])[:3], overview_context)
            if overview_answer:
                term1, term2 = _compare_terms_from_query(query)
                if term1 and term2 and not _contains_compare_terms(overview_answer, term1, term2):
                    return {
                        "intent": intent,
                        "query_family": family,
                        "answer": RAG_NO_MATCH_RESPONSE,
                        "used_llm": False,
                        "answer_type": "overview_compare_missing_terms",
                        "extractor_items_count": len(items),
                    }
                if not _is_valid_overview_answer(overview_answer, query):
                    return {
                        "intent": intent,
                        "query_family": family,
                        "answer": RAG_NO_MATCH_RESPONSE,
                        "used_llm": False,
                        "answer_type": "overview_not_structured",
                        "extractor_items_count": len(items),
                    }
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": overview_answer,
                    "used_llm": False,
                    "answer_type": "overview_structure_extractor",
                    "extractor_items_count": len(items),
                }
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "overview_not_found",
                "extractor_items_count": len(items),
            }

        return {
            "intent": intent,
            "query_family": family,
            "answer": None,
            "used_llm": True,
            "answer_type": "llm_required",
            "extractor_items_count": len(items),
        }

    answer = (llm_text or "").strip()
    if family == "definition_entity":
        definition_mode = _definition_mode_from_query(query)
        raw_text = definition_context
        extracted_definition = _extract_definition_sentence(
            raw_text,
            query=query,
            mode=definition_mode,
        )
        if extracted_definition:
            return {
                "intent": intent,
                "query_family": family,
                "answer": " ".join([p.strip() for p in re.split(r"(?<=[.!?])\s+", extracted_definition) if p.strip()][:2]),
                "used_llm": False,
                "answer_type": "definition_extractor_override",
                "extractor_items_count": len(items),
            }
        return {
            "intent": intent,
            "query_family": family,
            "answer": RAG_NO_MATCH_RESPONSE,
            "used_llm": False,
            "answer_type": "definition_not_found",
            "extractor_items_count": len(items),
        }

    if family == "list_structure":
        if not list_section_confident:
            S.logger.info("[LIST FALLBACK] weak_section_signal=true action=not_found_after_llm")
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "list_not_found",
                "extractor_items_count": len(items),
            }
        deterministic_list = _extract_list_from_context(query, list_context, max_candidate_blocks=2)
        if deterministic_list:
            deterministic_list = _sanitize_list_answer_text(query, deterministic_list) or deterministic_list
            return {
                "intent": intent,
                "query_family": family,
                "answer": deterministic_list,
                "used_llm": False,
                "answer_type": "list_extractor_override",
                "extractor_items_count": len(items),
            }
        fallback_items = extract_list_items(list_context)
        if len(fallback_items) >= 3:
            answer = _sanitize_list_answer_text(query, "\n".join(f"- {item}" for item in fallback_items))
            if not answer:
                answer = None
        if answer:
            return {
                "intent": intent,
                "query_family": family,
                "answer": answer,
                "used_llm": False,
                "answer_type": "list_extractor",
                "extractor_items_count": len(fallback_items),
            }
        if str(list_context or "").strip():
            S.logger.info("[LIST REJECTED] reason=llm_fallback_blocked")
        return {
            "intent": intent,
            "query_family": family,
            "answer": RAG_NO_MATCH_RESPONSE,
            "used_llm": False,
            "answer_type": "list_not_found",
            "extractor_items_count": len(items),
        }

    if family == "overview_chapter_compare":
        overview_answer = _extract_overview_chapter_compare_answer(query, (doc_dicts or [])[:3], overview_context)
        if overview_answer:
            term1, term2 = _compare_terms_from_query(query)
            if term1 and term2 and not _contains_compare_terms(overview_answer, term1, term2):
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": RAG_NO_MATCH_RESPONSE,
                    "used_llm": False,
                    "answer_type": "overview_compare_missing_terms",
                    "extractor_items_count": len(items),
                }
            if not _is_valid_overview_answer(overview_answer, query):
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": RAG_NO_MATCH_RESPONSE,
                    "used_llm": False,
                    "answer_type": "overview_not_structured",
                    "extractor_items_count": len(items),
                }
            return {
                "intent": intent,
                "query_family": family,
                "answer": overview_answer,
                "used_llm": False,
                "answer_type": "overview_structure_extractor_override",
                "extractor_items_count": len(items),
            }
        return {
            "intent": intent,
            "query_family": family,
            "answer": RAG_NO_MATCH_RESPONSE,
            "used_llm": False,
            "answer_type": "overview_not_found_override",
            "extractor_items_count": len(items),
        }

    if _is_bad_output_text(answer):
        fallback_items = extract_list_items(list_context)
        if family == "list_structure" and len(fallback_items) >= 3:
            cleaned_fallback = _sanitize_list_answer_text(query, "\n".join(f"- {item}" for item in fallback_items))
            if cleaned_fallback:
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": cleaned_fallback,
                    "used_llm": False,
                    "answer_type": "blocked_bad_output_list_fallback",
                    "extractor_items_count": len(fallback_items),
                }
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "blocked_bad_output_list_fallback",
                "extractor_items_count": len(fallback_items),
            }
        raw_text = definition_context
        fallback_def = _extract_definition_sentence(
            raw_text,
            query=query,
            mode=_definition_mode_from_query(query),
        )
        if family == "definition_entity":
            if not fallback_def or not _passes_strict_definition_relevance_guard(query, fallback_def):
                fallback_def = _definition_explanation_fallback(query, doc_dicts or [], _extract_entity_from_definition_query(query)[1]) or RAG_NO_MATCH_RESPONSE
        else:
            fallback_def = fallback_def or RAG_NO_MATCH_RESPONSE
        return {
            "intent": intent,
            "query_family": family,
            "answer": fallback_def,
            "used_llm": False,
            "answer_type": "blocked_bad_output_definition_fallback",
            "extractor_items_count": len(fallback_items),
        }

    if family in {"out_of_scope_candidate", "general", "overview_chapter_compare"} and answer and answer != RAG_NO_MATCH_RESPONSE:
        grounded = _is_answer_grounded_in_docs(answer, doc_dicts, query_text=query)
        docs_count = len(doc_dicts or [])
        fallback_docs_count = len(S._select_generation_context_docs(query, doc_dicts or [], max_docs=3)) if S._is_llm_generation_query(query) else 0
        allow_generation_bypass = S._is_generation_bypass_query(query)
        if not grounded:
            if allow_generation_bypass and (docs_count > 0 or fallback_docs_count > 0):
                S.logger.info(
                    "[POST-GUARD CHECK] docs_count=%s grounded=%s decision=%s",
                    docs_count,
                    grounded,
                    "allow_generation_response",
                )
            else:
                S.logger.info(
                    "[POST-GUARD CHECK] docs_count=%s grounded=%s decision=%s",
                    docs_count,
                    grounded,
                    "not_found_no_docs_or_strict_mode",
                )
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": RAG_NO_MATCH_RESPONSE,
                    "used_llm": False,
                    "answer_type": "ungrounded_answer_blocked",
                    "extractor_items_count": len(items),
                }
        else:
            S.logger.info(
                "[POST-GUARD CHECK] docs_count=%s grounded=%s decision=%s",
                docs_count,
                grounded,
                "accept_grounded",
            )

    if family == "overview_chapter_compare" and answer and answer != RAG_NO_MATCH_RESPONSE:
        term1, term2 = _compare_terms_from_query(query)
        if term1 and term2 and not _contains_compare_terms(answer, term1, term2):
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "compare_answer_missing_terms",
                "extractor_items_count": len(items),
            }
        if not _is_valid_overview_answer(answer, query):
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "overview_answer_not_structured",
                "extractor_items_count": len(items),
            }

    if family == "out_of_scope_candidate" and answer != RAG_NO_MATCH_RESPONSE:
        if _is_weak_retrieval_evidence(query, family, doc_dicts):
            return {
                "intent": intent,
                "query_family": family,
                "answer": RAG_NO_MATCH_RESPONSE,
                "used_llm": False,
                "answer_type": "out_of_scope_candidate_blocked",
                "extractor_items_count": len(items),
            }

    q_low_final = re.sub(r"\s+", " ", str(query or "").strip().lower())
    if q_low_final.startswith("what is") or q_low_final.startswith("define"):
        if answer and answer != RAG_NO_MATCH_RESPONSE and not _passes_strict_definition_relevance_guard(query, answer):
            rescued = _definition_explanation_fallback(query, doc_dicts or [], _extract_entity_from_definition_query(query)[1])
            if rescued:
                return {
                    "intent": intent,
                    "query_family": family,
                    "answer": rescued,
                    "used_llm": False,
                    "answer_type": "definition_explanation_fallback",
                    "extractor_items_count": len(items),
                }

    return {
        "intent": intent,
        "query_family": family,
        "answer": answer,
        "used_llm": True,
        "answer_type": "llm",
        "extractor_items_count": len(items),
    }

def _extract_structured_list_from_context(context_chunks: List[str], query_text: str = "") -> Optional[List[str]]:
    if not context_chunks:
        return None

    bullet_re = re.compile(r"^\s*(?:[-•*]|\d+[.)]|[a-z][.)]|[ivxlcdm]+[.)])\s*(.+)$", re.IGNORECASE)
    numbered_inline_re = re.compile(r"(?:^|\s)\d+[.)]\s*([^\d\n][^\n]*?)(?=(?:\s\d+[.)]\s)|$)")
    list_clause_re = re.compile(r"\b(?:are|has|have|include|includes|consists\s+of|comprise|comprises|composed\s+of)\s*:?\s*([^\n]+)", re.IGNORECASE)
    stop_noise_re = re.compile(r"\b(?:copyright|all rights reserved|isbn|page\s*\d+|table\s*\d+|figure\s*\d+|chapter\s*\d+)\b", re.IGNORECASE)
    header_re = re.compile(r"^\s*(?:table|figure|fig\.?|chapter|unit|lesson|contents?)\b", re.IGNORECASE)

    def _clean_item(raw: str) -> str:
        item = re.sub(r"^\s*(?:[-•*]|\d+[.)]|[a-z][.)]|[ivxlcdm]+[.)])\s*", "", str(raw or ""), flags=re.IGNORECASE)
        item = re.sub(r"^\s*(?:the\s+)?(?:\w+\s+)?(?:items?|elements?)\s*[:\-–—]\s*", "", item, flags=re.IGNORECASE)
        item = re.sub(r"^\s*(?:\w+\s+)?components?\s*[:\-–—]\s*", "", item, flags=re.IGNORECASE)
        item = re.sub(r"\s+", " ", item).strip(" ,;:-–—.")
        item = re.sub(r"^\s*(?:first|second|third|fourth|fifth|next|then|finally)\s*[:\-]?\s*", "", item, flags=re.IGNORECASE)
        item = re.sub(r"\s*(?:©|copyright|all rights reserved)\b.*$", "", item, flags=re.IGNORECASE)
        item = re.sub(r"\s*\([^)]*(?:copyright|isbn|page\s*\d+)[^)]*\)\s*$", "", item, flags=re.IGNORECASE)
        item = re.sub(r"\s+", " ", item).strip(" ,;:-–—.")
        if not item:
            return ""
        if header_re.match(item):
            return ""
        if stop_noise_re.search(item):
            return ""
        if re.fullmatch(r"\d+(?:\.\d+)?", item):
            return ""
        if len(item.split()) < 1 or len(item.split()) > 18:
            return ""
        if len(item) < 3 or len(item) > 140:
            return ""
        if not re.search(r"[A-Za-z]", item):
            return ""
        return item

    candidates: List[str] = []
    for chunk in context_chunks:
        txt = str(chunk or "")
        if not txt.strip():
            continue

        lines = [ln.strip() for ln in txt.splitlines() if ln and ln.strip()]
        group: List[str] = []
        for ln in lines:
            ln_work = re.sub(r"\b(?:copyright|all rights reserved|isbn|page\s*\d+)\b.*$", "", ln, flags=re.IGNORECASE).strip()
            if not ln_work:
                continue

            m = bullet_re.match(ln_work)
            if m:
                cleaned = _clean_item(m.group(1))
                if cleaned:
                    candidates.append(cleaned)

            for n in numbered_inline_re.findall(ln_work):
                cleaned = _clean_item(n)
                if cleaned:
                    candidates.append(cleaned)

            clause = list_clause_re.search(ln_work)
            if clause:
                clause_text = re.split(r"[.!?]", clause.group(1), maxsplit=1)[0]
                clause_text = re.sub(r"\b(?:the\s+)?model\s+suggesting\s+that\s+an\s+attitude\s+has\s+", "", clause_text, flags=re.IGNORECASE)
                clause_text = re.sub(r"\b(?:there\s+are|there\s+is)\s+", "", clause_text, flags=re.IGNORECASE)
                parts = [p.strip() for p in re.split(r",|;|\band\b", clause_text) if p.strip()]
                if len(parts) >= 3:
                    for p in parts:
                        cleaned = _clean_item(p)
                        if cleaned:
                            candidates.append(cleaned)

            ln_compact = re.sub(r"\s+", " ", ln_work).strip()
            is_short_line = bool(ln_compact) and len(ln_compact) <= 90 and not re.search(r"[.!?]$", ln_compact)
            if is_short_line and (not header_re.match(ln_compact)) and (not stop_noise_re.search(ln_compact)):
                group.append(ln_compact)
            else:
                if len(group) >= 3:
                    for g in group:
                        cleaned = _clean_item(g)
                        if cleaned:
                            candidates.append(cleaned)
                group = []
        if len(group) >= 3:
            for g in group:
                cleaned = _clean_item(g)
                if cleaned:
                    candidates.append(cleaned)

        sents = [s.strip() for s in re.split(r"(?<=[.!?])\s+", txt) if s.strip()]
        prefix_buckets: Dict[str, List[str]] = defaultdict(list)
        for s in sents:
            if stop_noise_re.search(s):
                continue
            words = re.findall(r"[A-Za-z][A-Za-z\-']*", s)
            if len(words) < 4 or len(words) > 16:
                continue
            key = " ".join(w.lower() for w in words[:2])
            prefix_buckets[key].append(s)
        for bucket in prefix_buckets.values():
            if len(bucket) >= 3:
                for b in bucket:
                    cleaned = _clean_item(b)
                    if cleaned:
                        candidates.append(cleaned)

    deduped: List[str] = []
    seen: Set[str] = set()
    for c in candidates:
        norm = re.sub(r"[^a-z0-9]+", " ", c.lower()).strip()
        if not norm or norm in seen:
            continue
        seen.add(norm)
        deduped.append(c)

    return _validate_structured_list_items(deduped, query_text=query_text)

def _validate_structured_list_items(items: List[str], query_text: str = "") -> Optional[List[str]]:
    if not items:
        return None

    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    min_items = 2
    cleaned = [re.sub(r"\s+", " ", str(x or "")).strip(" ,;:-–—.") for x in items if str(x or "").strip()]
    cleaned = [x for x in cleaned if x]
    if len(cleaned) < min_items:
        return None

    noise_re = re.compile(r"\b(?:copyright|all rights reserved|isbn|chapter\s*\d+|table\s*\d+|figure\s*\d+|page\s*\d+|contents?)\b", re.IGNORECASE)
    cleaned = [x for x in cleaned if not noise_re.search(x)]
    if len(cleaned) < min_items:
        return None

    def _is_action_item(text: str) -> bool:
        low = text.lower()
        if low.endswith("ing"):
            return True
        return bool(re.match(r"^(?:define|identify|collect|gather|analy[sz]e|develop|test|draw|conclude|evaluate|implement|monitor|observe|describe|explain|predict|control)\b", low))

    action_count = sum(1 for it in cleaned if _is_action_item(it))
    noun_count = len(cleaned) - action_count
    if len(cleaned) >= 4 and min(action_count, noun_count) >= max(2, len(cleaned) // 2):
        return None

    if q and (re.search(r"\blist\b", q) or re.match(r"^\s*(?:what|which)\s+are\b", q) or re.match(r"^\s*how\b", q)):
        if action_count < min_items and len(cleaned) >= 3:
            noun_style_ok = len(cleaned) >= 4 and all(2 <= len(it.split()) <= 6 for it in cleaned)
            if not noun_style_ok:
                return None

    token_stop = {
        "the", "a", "an", "and", "or", "of", "to", "in", "on", "for", "with", "by", "from",
        "item", "items", "element", "elements", "point", "points",
    }
    token_sets: List[Set[str]] = []
    for item in cleaned:
        toks = {t for t in re.findall(r"[a-z0-9]{3,}", item.lower()) if t not in token_stop}
        if toks:
            token_sets.append(toks)
    if len(token_sets) >= 3:
        union = set().union(*token_sets)
        if len(union) > 45:
            return None

    out: List[str] = []
    seen_out: Set[str] = set()
    for item in cleaned:
        formatted = item[0].upper() + item[1:] if item else item
        norm = re.sub(r"[^a-z0-9]+", " ", formatted.lower()).strip()
        if not norm or norm in seen_out:
            continue
        seen_out.add(norm)
        out.append(formatted)

    if len(out) < min_items:
        return None
    return out[:12]

_MPC6_QUERY_STOP = {
    "what", "which", "who", "when", "where", "why", "how",
    "the", "this", "that", "these", "those", "their", "them",
    "is", "are", "was", "were", "be", "been", "being",
    "to", "of", "in", "on", "for", "and", "or", "with", "from",
    "a", "an", "as", "at", "by", "it", "its", "us", "we", "i",
    "do", "does", "did", "can", "could", "should", "would",
    "list", "name", "give", "mention", "identify", "describe", "explain",
    "tell", "about", "main", "major", "all", "some", "many", "into",
    "document", "chapter", "section",
}

_MPC6_SECTION_RE = re.compile(
    r"\b(\d+(?:\.\d+){1,3})\s+([A-Z][A-Za-z][A-Za-z0-9 ,&'\-/()]{2,90}?)\s*[:\-\u2013\u2014]\s",
)

_MPC6_CAPTION_RE = re.compile(
    r"\b((?:Figure|Fig\.?|Table)\s*\d+(?:\.\d+)?)\s*[:\-\u2013\u2014]\s*"
    r"([A-Z][A-Za-z0-9 ,&'\-/()]{2,90})",
    flags=re.IGNORECASE,
)

def _mpc6_query_focus_tokens(query_text: str) -> List[str]:
    q = re.sub(r"\s+", " ", str(query_text or "").strip().lower())
    out: List[str] = []
    seen: Set[str] = set()
    # Allow 2-character tokens (e.g. "ms") so short discriminating tokens are
    # not silently dropped from anchor scoring. Stop-words still filter the
    # common short tokens like "is", "of", "an", etc.
    for tok in re.findall(r"[a-z0-9]{2,}", q):
        if tok in _MPC6_QUERY_STOP or tok.isdigit():
            continue
        if tok in seen:
            continue
        seen.add(tok)
        out.append(tok)
    return out

def _slice_chunk_to_query_subsection(chunk_text: str, query_text: str) -> str:
    """Return a substring of ``chunk_text`` anchored at the inline subsection
    heading or figure/table caption whose title best matches the query focus
    tokens. The slice ends at the next anchor whose title does NOT overlap the
    query focus (i.e. a topic shift), or at the end of the chunk.

    If no qualifying anchor is found, ``chunk_text`` is returned unchanged.
    """
    text = str(chunk_text or "")
    if len(text) < 40:
        return text
    q_tokens = _mpc6_query_focus_tokens(query_text)
    if not q_tokens:
        return text

    anchors: List[tuple[int, int]] = []  # (start_pos, hits)
    for m in _MPC6_SECTION_RE.finditer(text):
        title_low = (m.group(2) or "").lower()
        hits = sum(1 for tok in q_tokens if re.search(rf"\b{re.escape(tok)}\b", title_low))
        anchors.append((m.start(), hits))
    for m in _MPC6_CAPTION_RE.finditer(text):
        title_low = (m.group(2) or "").lower()
        hits = sum(1 for tok in q_tokens if re.search(rf"\b{re.escape(tok)}\b", title_low))
        anchors.append((m.start(), hits))

    if not anchors:
        return text
    anchors.sort(key=lambda x: x[0])

    # Pick the highest-scoring anchor (earliest in tiebreak).
    best_idx = max(
        range(len(anchors)),
        key=lambda i: (anchors[i][1], -anchors[i][0]),
    )
    best_pos, best_hits = anchors[best_idx]

    # Discriminating-token coverage: require ≥2 focus tokens hit when the
    # query has ≥2 focus tokens; for single-token queries fall back to ≥1.
    needed = min(2, len(q_tokens)) if len(q_tokens) >= 1 else 1
    if best_hits < needed:
        return text

    end_pos = len(text)
    for pos, hits in anchors:
        if pos <= best_pos:
            continue
        if hits == 0:
            end_pos = pos
            break
        # Consecutive on-focus anchor: keep extending the slice.

    sliced = text[best_pos:end_pos].strip()
    if len(sliced) < 40:
        return text
    return sliced

def _explode_inline_ordered_enumerations(text: str) -> str:
    """When a single line contains a sequential ordered enumeration run
    (``A. ... B. ... C. ...`` or ``1. ... 2. ... 3. ...`` with at least three
    consecutive ascending markers starting at A/B or 1/2), insert a newline
    before each marker so per-line list extractors can match them.

    Pure structural — no domain content. Other markers (single isolated
    ``F.``, non-sequential, name initials like ``J. Clough``) are left
    untouched because they don't form an ascending run of length ≥3.
    """
    out = str(text or "")
    if not out:
        return out

    # 1) Single-letter run: A. B. C. ... or a) b) c) ...
    letter_matches = [
        (m.start(), m.group(1).lower())
        for m in re.finditer(r"(?:^|(?<=\s))([A-Za-z])[.)]\s", out)
    ]
    letter_cuts: Set[int] = set()
    if letter_matches:
        current: List[tuple[int, str]] = []
        prev_letter: Optional[str] = None
        runs: List[List[tuple[int, str]]] = []
        for pos, ltr in letter_matches:
            if prev_letter is not None and ord(ltr) == ord(prev_letter) + 1:
                current.append((pos, ltr))
            else:
                if len(current) >= 3 and current[0][1] in ("a", "b"):
                    runs.append(current)
                current = [(pos, ltr)]
            prev_letter = ltr
        if len(current) >= 3 and current[0][1] in ("a", "b"):
            runs.append(current)
        for run in runs:
            for pos, _ in run:
                letter_cuts.add(pos)

    # 2) Numeric run: 1. 2. 3. ...
    numeric_matches = [
        (m.start(), int(m.group(1)))
        for m in re.finditer(r"(?:^|(?<=\s))(\d{1,2})\.\s", out)
    ]
    numeric_cuts: Set[int] = set()
    if numeric_matches:
        current_n: List[tuple[int, int]] = []
        prev_n: Optional[int] = None
        runs_n: List[List[tuple[int, int]]] = []
        for pos, n in numeric_matches:
            if prev_n is not None and n == prev_n + 1:
                current_n.append((pos, n))
            else:
                if len(current_n) >= 3 and current_n[0][1] in (1, 2):
                    runs_n.append(current_n)
                current_n = [(pos, n)]
            prev_n = n
        if len(current_n) >= 3 and current_n[0][1] in (1, 2):
            runs_n.append(current_n)
        for run in runs_n:
            for pos, _ in run:
                numeric_cuts.add(pos)

    cuts = sorted(letter_cuts | numeric_cuts)
    if not cuts:
        return out

    parts: List[str] = []
    last = 0
    for c in cuts:
        if c <= last:
            continue
        parts.append(out[last:c])
        parts.append("\n")
        last = c
    parts.append(out[last:])
    return "".join(parts)

def _extract_list_from_context(query: str, context: str, max_candidate_blocks: int = 2) -> Union[str, None]:
    if not context:
        return None

    # MP-C6: anchor extraction to the matched subsection / caption when the
    # chunk text contains an inline structural anchor whose title overlaps the
    # query focus tokens. Then explode any inline ordered enumeration runs so
    # the per-line bullet detector can match them.
    sliced = _slice_chunk_to_query_subsection(context, query)
    _mpc6_anchored = bool(sliced and sliced != context)
    if _mpc6_anchored:
        context = sliced
        # Only explode inline ordered enumerations when slicing actually
        # anchored on a query-matching subsection. Running the exploder on
        # arbitrary chunks (e.g. front-matter / TOC) can fragment unrelated
        # numbered lines into spurious bullet candidates.
        context = _explode_inline_ordered_enumerations(context)

    ql = re.sub(r"\s+", " ", str(query or "").strip().lower())
    list_mode = bool(
        _is_targeted_list_question(ql)
        or re.match(r"^\s*(?:what|which)\s+are\b", ql)
        or (bool(re.search(r"\b(?:what|which|name|give|mention|identify)\b", ql)) and bool(re.search(r"\b[a-z]{4,}s\b", ql)))
    )
    if not list_mode:
        return None

    q_family_v2 = _classify_query_family_v2(query)
    strict_label_query_mode = bool(
        (
            re.match(r"^\s*(?:what|which)\s+are\b", ql)
            or re.match(r"^\s*(?:list|name|give|mention|identify)\b", ql)
        )
        and (not _is_goal_objective_list_query(query, q_family_v2))
    )
    stage_list_query_mode = bool(re.search(r"\bstages?\b", ql))
    strict_count_target = _list_query_count_target(query)

    exact_count_group = _extract_exact_count_structural_list_group(query, context)
    if exact_count_group:
        sanitized_exact = _sanitize_list_answer_text(query, "\n".join(f"- {item}" for item in exact_count_group))
        if sanitized_exact:
            return sanitized_exact

    context_chunks = [c for c in re.split(r"\n\s*\n+", str(context)) if str(c or "").strip()]
    structured_items = _extract_structured_list_from_context(context_chunks, query_text=query)
    if structured_items and len(structured_items) >= 2:
        sanitized_structured = _sanitize_list_answer_text(query, "\n".join(f"- {x}" for x in structured_items))
        if sanitized_structured:
            return sanitized_structured

    query_tokens_raw = [
        t for t in re.findall(r"[a-z0-9]{3,}", ql)
        if t not in {"what", "which", "are", "the", "and", "for", "with", "from", "list", "name", "give", "mention", "identify"}
    ]
    query_tokens: List[str] = []
    seen_query_tokens: Set[str] = set()
    for t in query_tokens_raw:
        for cand_tok in (t, _light_normalize_query_token(t)):
            cand_tok = str(cand_tok or "").strip().lower()
            if len(cand_tok) < 3 or cand_tok in seen_query_tokens:
                continue
            seen_query_tokens.add(cand_tok)
            query_tokens.append(cand_tok)
    year_re = re.compile(r"\b(1[0-9]{3}|20[0-9]{2})\b")
    # Accept alphabetic line starts so exploded inline enumerations are matched as bullets.
    bullet_num_re = re.compile(r"^\s*(?:[-•*�]|\d+[.)]|[A-Za-z][.)])\s*(.+)$")
    caption_re = re.compile(r"^\s*(?:figure|fig\.?|table)\b", flags=re.IGNORECASE)

    def _looks_like_heading(line: str) -> bool:
        s = (line or "").strip()
        if not s or bullet_num_re.match(s) or len(s) > 140:
            return False
        if s.endswith(":"):
            return True
        if re.match(r"^[A-Z][A-Za-z0-9\s\-,:]{3,120}$", s):
            return True
        return False

    def _normalize_item(raw: str) -> str:
        item = (raw or "").strip()
        item = re.sub(r"^\s*(?:[-•*�]|\d+[.)]|[A-Za-z][.)])\s*", "", item)
        item = re.sub(r"^\s*\d+\s*:\s*", "", item)
        item = re.sub(r"^\s*(?:first|second|third|fourth|fifth|then|next|finally)\s*[:\-]?\s*", "", item, flags=re.IGNORECASE)
        item = re.sub(r"^\s*(?:this\s+is|it\s+is|they\s+are|according\s+to|for\s+example|in\s+order\s+to|there\s+are|there\s+is)\s*[,:\-]?\s*", "", item, flags=re.IGNORECASE)
        if strict_label_query_mode and ":" in item:
            item = item.split(":", 1)[0].strip()
        item = re.sub(r"\s+(?:a|an|the)\s*$", "", item, flags=re.IGNORECASE)
        item = re.sub(r"\s+", " ", item).strip(" ,;:-–—.")
        return item

    def _is_meaningful_item(item: str) -> bool:
        if not item:
            return False
        low = item.lower()
        if year_re.search(item) or caption_re.match(item):
            return False
        if re.fullmatch(r"\d+(?:\.\d+)?", item):
            return False
        if len(item) < 4 or len(item) > 120:
            return False
        wc = len(item.split())
        if strict_label_query_mode:
            if wc < 1 or wc > (5 if strict_count_target is not None else 8):
                return False
        elif wc < 2 or wc > 12:
            # Allow uppercase single-word concept labels (e.g. "Prediction",
            # "Observation") that are >=4 chars — common in alpha-marked lists
            # (a), b), c) …) across any domain.  Generic: only casing + length.
            if wc == 1 and len(item) >= 4 and item[0].isupper():
                pass  # keep: single uppercase concept label
            else:
                return False
        if not re.search(r"[a-zA-Z]", item):
            return False
        if re.search(r"https?://|www\.|\.com\b", low):
            return False
        if re.search(r"\b(chapter|figure|table|contents?|index|objectives?)\b", low):
            return False
        if re.search(r"\b(?:and|or|to|of|for|with|by|in|on|at|from)\s*$", item, flags=re.IGNORECASE):
            return False
        return True

    def _extract_items_from_line(line: str) -> List[str]:
        out: List[str] = []
        ln = (line or "").strip()
        if not ln:
            return out

        line_low = ln.lower()
        line_anchor_hit = True
        if strict_label_query_mode and query_tokens:
            line_anchor_hit = any(_token_match_light(line_low, tok) for tok in query_tokens[:4])

        if strict_label_query_mode and line_anchor_hit and ("�" in ln or "•" in ln):
            for seg in [s.strip() for s in re.split(r"\s*[�•]\s*", ln) if s.strip()]:
                if len(seg) < 2:
                    continue
                out.append(seg)

        bullet = bullet_num_re.match(ln)
        if bullet:
            out.append(bullet.group(1).strip())

        if strict_label_query_mode and line_anchor_hit:
            colon_labels = re.findall(
                r"(?:^|[�•\-]\s*|\b)([A-Z][A-Za-z\-]+(?:\s+[A-Z][A-Za-z\-]+){0,3})\s*:\s*",
                ln,
            )
            out.extend([c.strip() for c in colon_labels if str(c or "").strip()])

            descriptor_labels = re.findall(
                r"\b([A-Z][A-Za-z\-]+(?:\s+[A-Z][A-Za-z\-]+){0,3})\s+(?:It|An|A|The)\s+(?:is|was|are|were|focused|focuses|concentrated|views|approach)\b",
                ln,
            )
            out.extend([c.strip() for c in descriptor_labels if str(c or "").strip()])

        if stage_list_query_mode:
            for m in re.finditer(r"\b((?!(?:stage|period)\b)[A-Za-z][A-Za-z\-']{2,}(?:\s+(?!(?:stage|period)\b)[A-Za-z][A-Za-z\-']{2,}){0,2}\s+(?:stage|period))\b", ln, flags=re.IGNORECASE):
                cand_stage = (m.group(1) or "").strip()
                if cand_stage:
                    out.append(cand_stage)

        inline_numbered = re.findall(r"(?:^|\s)\d+[.)]\s*([^\d\n][^\n]*?)(?=(?:\s\d+[.)]\s)|$)", ln)
        out.extend([p.strip(" ,;:-") for p in inline_numbered if p.strip()])

        # Letter-prefixed inline items: a) Item, b) Item, c) Item (common OCR pattern)
        inline_lettered = re.findall(r"(?:^|[\s,;])([a-z])\)\s*([^)\n]{2,60})(?=(?:[\s,;][a-z]\)\s)|$)", ln, flags=re.IGNORECASE)
        for _letter, payload in inline_lettered:
            cleaned_payload = payload.strip(" ,;:-")
            if cleaned_payload and len(cleaned_payload.split()) >= 1:
                out.append(cleaned_payload)


        listed_clause = re.search(r"\b(?:are|include|includes|consists\s+of|classified\s+as)\s*:\s*([^\n]+)", ln, flags=re.IGNORECASE)
        if listed_clause:
            parts = [p.strip() for p in re.split(r",|;|\band\b", listed_clause.group(1)) if p.strip()]
            if len(parts) >= 3:
                out.extend(parts)

        for tok in query_tokens[:3]:
            cue_re = re.search(rf"\b{re.escape(tok)}(?:es|s)?\b[^.\n]{{0,80}}\b(?:are|include|includes|consist\s+of|consists\s+of|classified\s+as)\b\s*[:\-]?\s*([^\n.]+)", ln, flags=re.IGNORECASE)
            if cue_re:
                tail = cue_re.group(1)
                parts = [p.strip() for p in re.split(r",|;|\band\b", tail) if p.strip()]
                if len(parts) >= 2:
                    out.extend(parts)

        for tok in query_tokens[:3]:
            phrase_pat = re.compile(
                rf"\b([A-Z][A-Za-z\-]+(?:\s+[A-Z][A-Za-z\-]+){{0,4}})\b\s+(?:is\s+|are\s+|was\s+|were\s+)?(?:an?\s+|the\s+)?\b{re.escape(tok)}(?:es|s)?\b",
                flags=re.IGNORECASE,
            )
            for m in phrase_pat.finditer(ln):
                cand = (m.group(1) or "").strip(" ,;:-")
                if cand:
                    out.append(cand)

        if (ln.count(',') >= 2 or ln.count(';') >= 2) and len(ln) < 400 and not re.search(r"\.\s", ln):
            parts = [p.strip() for p in re.split(r",|;|\band\b", ln) if p.strip()]
            if len(parts) >= 3:
                out.extend(parts)

        title_words = re.findall(r"\b[A-Z][a-z]{2,}\b", ln)
        if len(title_words) >= 4 and not re.search(r"[.!?;:]", ln):
            title_parts = [p.strip() for p in re.split(r"(?<=[a-z])\s+(?=[A-Z])", ln) if p.strip()]
            if len(title_parts) >= 3:
                out.extend(title_parts)

        ocr_payload = re.sub(r"^\s*(?:figure|fig\.?|table)\b[^:\n]{0,120}[:\-–—\s]*", "", ln, flags=re.IGNORECASE)
        if len(ocr_payload.split()) >= 6 and not re.search(r"\.\s", ocr_payload):
            ocr_parts = [p.strip() for p in re.split(r"(?<=[a-z])\s+(?=[A-Z])", ocr_payload) if p.strip()]
            if len(ocr_parts) >= 3:
                out.extend(ocr_parts)

        cleaned: List[str] = []
        for c in out:
            n = _normalize_item(c)
            if strict_label_query_mode and strict_count_target is not None:
                strict_reason = _strict_list_label_reject_reason(n)
                if strict_reason:
                    _log_list_quality_rejection(n, f"early_{strict_reason}")
                    continue
            if _is_meaningful_item(n):
                cleaned.append(n)
        return cleaned

    lines = [ln.strip() for ln in str(context).splitlines() if ln and ln.strip()]
    if not lines:
        return None

    blocks: List[Dict[str, Any]] = []
    current_heading = ""
    current_lines: List[str] = []
    for ln in lines:
        if _looks_like_heading(ln):
            if current_lines:
                blocks.append({"heading": current_heading, "lines": current_lines[:]})
                current_lines = []
            current_heading = ln
        else:
            current_lines.append(ln)
    if current_lines:
        blocks.append({"heading": current_heading, "lines": current_lines[:]})
    if not blocks:
        blocks = [{"heading": "", "lines": lines}]

    def _anchor_hits(block: Dict[str, Any]) -> int:
        hay = ((block.get("heading") or "") + " " + " ".join(block.get("lines") or [])[:1200]).lower()
        if not query_tokens:
            return 1
        return sum(1 for tok in query_tokens if re.search(rf"\b{re.escape(tok)}\b", hay))

    candidate_blocks = sorted(blocks, key=lambda b: _anchor_hits(b), reverse=True)
    max_blocks = max(1, min(4, int(max_candidate_blocks)))
    pooled_stage_items: List[str] = []

    def _dedupe_ordered(items: List[str]) -> List[str]:
        out: List[str] = []
        seen: Set[str] = set()
        for item in items:
            norm = re.sub(r"\s+", " ", item).strip().lower()
            if not norm or norm in seen:
                continue
            seen.add(norm)
            out.append(item)
        return out

    # Regex to detect alpha-marked lines: a) Item, b) Item, a. Item, b. Item
    _alpha_marker_re_ctx = re.compile(r"^\s*[a-z][.)]\s*\S", re.IGNORECASE)

    for block in candidate_blocks[:max_blocks]:
        if query_tokens and _anchor_hits(block) == 0:
            continue

        # Continuation merge: for alpha-list blocks, continuation connector
        # lines are merged into the preceding item before extraction.
        raw_block_lines = block.get("lines") or []
        _has_alpha_markers = any(_alpha_marker_re_ctx.match(ln) for ln in raw_block_lines)
        if _has_alpha_markers:
            _alpha_count = sum(1 for ln in raw_block_lines if _alpha_marker_re_ctx.match(ln))
            S.logger.info("[ALPHA LIST DETECTED] block_heading='%s' alpha_lines=%d total_lines=%d",
                        str(block.get("heading") or "")[:50], _alpha_count, len(raw_block_lines))
            merged_block_lines: List[str] = []
            for _ln in raw_block_lines:
                # Also merge when the previous line ends with a connector word.
                _prev_ends_connector = bool(
                    merged_block_lines
                    and re.search(
                        r"(?:\b(?:and|or|but|with)|&)\s*$",
                        merged_block_lines[-1],
                        re.IGNORECASE,
                    )
                )
                if (merged_block_lines
                        and not _alpha_marker_re_ctx.match(_ln)
                        and (
                            re.match(r"^\s*(?:and|or|but|with|to)\s+\S", _ln, re.IGNORECASE)
                            or re.match(r"^\s*&\s*\S", _ln)
                            or _prev_ends_connector
                        )):
                    merged_block_lines[-1] = merged_block_lines[-1].rstrip() + " " + _ln.strip()
                    S.logger.info("[LIST ITEM CONTINUATION MERGED] appended='%s'", _ln.strip()[:60])
                else:
                    merged_block_lines.append(_ln)
        else:
            merged_block_lines = raw_block_lines

        collected: List[str] = []
        for ln in merged_block_lines:
            collected.extend(_extract_items_from_line(ln))
        ordered = _dedupe_ordered(collected)
        if len(ordered) < 2:
            continue
        if stage_list_query_mode:
            pooled_stage_items.extend(ordered)
            continue
        sanitized = _sanitize_list_answer_text(query, "\n".join(f"- {item}" for item in ordered[:12]))
        if sanitized:
            return sanitized

    if stage_list_query_mode:
        merged_stage_items = _dedupe_ordered(pooled_stage_items)
        if len(merged_stage_items) >= 2:
            sanitized_stage = _sanitize_list_answer_text(query, "\n".join(f"- {item}" for item in merged_stage_items[:16]))
            if sanitized_stage:
                return sanitized_stage

    return None

def _validate_query_ui_equivalent(query: str) -> dict:
    """Diagnostic helper that exercises the SAME runtime decision path as the
    real WebSocket/UI flow (call_llm_streaming).

    Steps replicated:
      1. Query normalization (same as WS path)
      2. Retrieval via live_rag.search / _search_fast_minimal
      3. Active-source filtering
      4. Doc preparation (_prepare_rag_doc_dicts_shared)
      5. Heading boost and section reranking
      6. _shared_rag_final_answer_decision  (the internal shortcut)
      7. _enforce_runtime_answer_acceptance  (the runtime guard)
      8. _apply_not_found_ux                (postprocess / not-found UX)

    Returns a dict with:
      - query_original, query_normalized
      - retrieval_count, context_summary
      - internal_shortcut_result  (from step 6 alone)
      - ui_equivalent_result      (from steps 6+7+8, i.e. full path)
      - results_differ            (bool — True if shortcut ≠ UI path)

    This is for diagnostic purposes ONLY — not called in the production path.
    """
    import time as _t
    _t0 = _t.perf_counter()
    result: Dict[str, Any] = {
        "query_original": str(query or ""),
        "query_normalized": "",
        "retrieval_count": 0,
        "context_summary": "",
        "internal_shortcut_result": {},
        "ui_equivalent_result": {},
        "results_differ": False,
        "timing_ms": 0.0,
    }

    # --- Step 1: Query normalization (same as WS path) ---
    text = str(query or "").strip()
    if not text:
        result["ui_equivalent_result"] = {"answer": "I didn't catch that. Could you repeat?"}
        return result

    is_fact_query_early = _classify_query_family_v2(text) == "fact_entity"
    if not is_fact_query_early:
        normalized_query, corrected_concept = _normalize_definition_query_before_retrieval(text)
        if normalized_query and normalized_query.strip().lower() != text.strip().lower():
            S.logger.info("[VALIDATE] normalization: '%s' → '%s'", text[:80], normalized_query[:80])
            text = normalized_query
    result["query_normalized"] = text

    # --- Step 2: Retrieval (same as WS path) ---
    family = _classify_query_family(text)
    family_v2 = _classify_query_family_v2(text)
    if family_v2 == "fact_entity":
        top_k_req = FACT_MAX_TOP_K
    elif family_v2 == "list_entity" or family == "list_structure":
        top_k_req = 10
    elif family_v2 == "definition_comparison" or _is_definition_style_query(text):
        top_k_req = 12
    else:
        top_k_req = 6

    if family_v2 != "fact_entity" and _is_safe_definition_fast_path_query(text):
        relevant_docs = _search_fast_definition_minimal(text)
    else:
        relevant_docs = _search_fast_minimal(text, top_k=top_k_req)

    if not relevant_docs:
        relevant_docs = []

    # --- Step 3: Active-source filtering ---
    relevant_docs = S._filter_results_to_active_sources(relevant_docs)
    result["retrieval_count"] = len(relevant_docs)

    if not relevant_docs:
        not_found = _apply_not_found_ux(text, RAG_NO_MATCH_RESPONSE, [])
        result["internal_shortcut_result"] = {"answer": RAG_NO_MATCH_RESPONSE}
        result["ui_equivalent_result"] = {"answer": not_found}
        result["results_differ"] = (RAG_NO_MATCH_RESPONSE != not_found)
        result["timing_ms"] = (_t.perf_counter() - _t0) * 1000
        return result

    # Context summary for reporting
    context_snippets = []
    for d in relevant_docs[:3]:
        txt = str((d or {}).get("page_content") or (d or {}).get("text") or "")
        if txt:
            context_snippets.append(txt[:200].replace("\n", " "))
    result["context_summary"] = " | ".join(context_snippets)[:600]

    # --- Step 4: Doc preparation (same as WS path) ---
    doc_dicts = _prepare_rag_doc_dicts_shared(relevant_docs, text)

    # --- Step 5: Reranking (same as WS path — line 17857) ---
    # In the real WS path, reranking is applied ONLY for families NOT in this set:
    family_v2_current = _classify_query_family_v2(text)
    family_legacy_current = _classify_query_family(text)
    _rerank_excluded = {"definition_entity", "definition_comparison", "list_entity", "explanatory_compare"}
    if family_v2_current not in _rerank_excluded:
        doc_dicts = _rerank_docs_for_query_intent(text, doc_dicts)
        doc_dicts = _retrieve_with_section_bias(text, doc_dicts, top_k=min(max(6, len(doc_dicts)), 12))


    doc_dicts = sorted(doc_dicts, key=lambda x: x.get("score", 0), reverse=True)
    is_definition_query = (family_v2_current == "definition_comparison" or _is_definition_style_query(text)) and (_classify_query_family_v2(text) != "fact_entity")
    is_fact_query = _classify_query_family_v2(text) == "fact_entity"
    _is_list_family = (family_legacy_current == "list_structure" or family_v2_current == "list_entity")
    keep_n = 5 if (is_definition_query or is_fact_query or _is_list_family) else 3
    if family_legacy_current == "list_structure" or family_v2_current == "list_entity":
        keep_n = max(keep_n, 8)
    doc_dicts = doc_dicts[:keep_n]

    if not doc_dicts:
        not_found = _apply_not_found_ux(text, RAG_NO_MATCH_RESPONSE, [])
        result["internal_shortcut_result"] = {"answer": RAG_NO_MATCH_RESPONSE}
        result["ui_equivalent_result"] = {"answer": not_found}
        result["results_differ"] = (RAG_NO_MATCH_RESPONSE != not_found)
        result["timing_ms"] = (_t.perf_counter() - _t0) * 1000
        return result

    # --- Step 6: Internal shortcut (_shared_rag_final_answer_decision) ---
    shortcut_dec = _shared_rag_final_answer_decision(text, doc_dicts, llm_text=None)
    result["internal_shortcut_result"] = {
        "answer": str(shortcut_dec.get("answer") or ""),
        "answer_type": str(shortcut_dec.get("answer_type") or ""),
        "used_llm": bool(shortcut_dec.get("used_llm", False)),
        "source_mode": str(shortcut_dec.get("source_mode") or ""),
        "query_family": str(shortcut_dec.get("query_family") or ""),
    }

    # --- Step 7: Runtime guard (_enforce_runtime_answer_acceptance) ---
    enforced_dec = _enforce_runtime_answer_acceptance(text, dict(shortcut_dec), doc_dicts)

    # --- Step 8: Postprocess / not-found UX (_apply_not_found_ux) ---
    if not enforced_dec.get("used_llm", True):
        final_answer = _apply_not_found_ux(text, str(enforced_dec.get("answer") or RAG_NO_MATCH_RESPONSE), doc_dicts)
    else:
        final_answer = str(enforced_dec.get("answer") or RAG_NO_MATCH_RESPONSE)

    result["ui_equivalent_result"] = {
        "answer": final_answer,
        "answer_type": str(enforced_dec.get("answer_type") or ""),
        "used_llm": bool(enforced_dec.get("used_llm", False)),
        "source_mode": str(enforced_dec.get("source_mode") or ""),
    }

    # --- Compare ---
    shortcut_answer = str(result["internal_shortcut_result"].get("answer") or "").strip()
    ui_answer = str(result["ui_equivalent_result"].get("answer") or "").strip()
    result["results_differ"] = (shortcut_answer != ui_answer)
    if result["results_differ"]:
        S.logger.warning(
            "[VALIDATION MISMATCH] query='%s' shortcut='%s' ui='%s'",
            text[:80], shortcut_answer[:120], ui_answer[:120],
        )

    result["timing_ms"] = (_t.perf_counter() - _t0) * 1000
    S.logger.info(
        "[VALIDATE COMPLETE] query='%s' shortcut_type=%s ui_type=%s differ=%s timing=%.0fms",
        text[:80],
        result["internal_shortcut_result"].get("answer_type"),
        result["ui_equivalent_result"].get("answer_type"),
        result["results_differ"],
        result["timing_ms"],
    )
    return result

